INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (4133, 'The Devil Wears Prada', 350, 'tt0458352', '/gkh6Nt8DtY1XT4gQsyFq9XAVJlJ.jpg', 'The Devil Wears Prada', 'A young woman from the Midwest gets more than she bargained for when she moves to New York to become a writer and ends up as the assistant to the tyrannical, larger-than-life editor-in-chief of a major fashion magazine.', '/1LwW0W0Zyik00OmQPTnCUjmCh1C.jpg', '2006-06-29', 109, 'Meet Andy Sachs. A million girls would kill to have her job. She''s not one of them.', 'David Frankel', 0, 2, '2026-04-29 22:36:09', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (5225, 'Avatar: Fire and Ash', 83533, 'tt1757678', '/iN41Ccw4DctL8npfmYg1j5Tr1eb.jpg', 'Avatar: Fire and Ash', 'In the wake of the devastating war against the RDA and the loss of their eldest son, Jake Sully and Neytiri face a new threat on Pandora: the Ash People, a violent and power-hungry Na''vi tribe led by the ruthless Varang. Jake''s family must fight for their survival and the future of Pandora in a conflict that pushes them to their emotional and physical limits.', '/aabwWZWx6z1aYP4PX2ADvbDKktd.jpg', '2025-12-17', 198, 'The world of Pandora will change forever.', 'James Cameron', 1, 2, '2026-04-29 22:36:08', 0);
