INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (5282, 'Michael', 936075, 'tt11378946', '/xBT0oNq6rsTFv4SxG5uGRIEOrq6.jpg', 'Michael', 'The story of Michael Jackson, one of the most influential artists the world has ever known, and his life beyond the music. His journey from the discovery of his extraordinary talent as the lead of the Jackson Five, to the visionary artist whose creative ambition fueled a relentless pursuit to become the biggest entertainer in the world, highlighting both his life off-stage and some of the most iconic performances from his early solo career.', '/j57QWe3OoaXL9Idi9gLtsAybWLP.jpg', '2026-04-22', 128, 'Discover the making of a king.', 'Antoine Fuqua', 0, 0, '2026-04-29 22:36:08', 0);
