INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13900, 'Your Heart Will Be Broken', 1523145, NULL, '/1x9e0qWonw634NhIsRdvnneeqvN.jpg', 'Твоё сердце будет разбито', 'High school student Polina is saved from bullying at her new school and makes a deal with the main bully Bars: he must pretend to be her boyfriend and protect her, and she must do everything he says. During this game, the couple develops real feelings, but her family and classmates have reasons to separate the lovers.', '/7wIBfBl2gejt6xHxNSK0reVIm7E.jpg', '2026-03-26', 134, NULL, NULL, 0, 0, '2026-04-29 22:25:42', 0);
