INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13903, 'After Porn Ends 2', 440249, NULL, '/3Sq9c1Lxh75neQ2BC9thaTO74FZ.jpg', 'After Porn Ends 2', 'After Porn Ends 2 picks up where its predecessor left off and not only turns back the clock to meet the oldest living stars in adult film''s history, but goes in depth with some of Its most current retirees and juxtaposes their experiences in a life after porn. Delving deeper into society''s ongoing stigmas of race, misogyny, and the reality of decreasing opportunities for these former VHS box cover stars. For some, their careers in adult entertainment is accepted proudly and without regret. In fact, it seems to have proven to be the pathway to their current happiness and inner peace. For others, however, a career in porn has proven to be a conduit to certain despair as they struggle to find a way to bury their past and emerge with a new career or calling.', '/rfItXrtDGILwsCdmgVxX79phFuI.jpg', '2017-03-28', 90, NULL, NULL, 0, 0, '2026-04-29 22:25:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13904, 'Love and Magnets', 16423, NULL, '/8Ebtc10VNLnX3xAYgkk7Ao3NrNh.jpg', 'Les aimants', 'Back in Montréal after spending five years in Guatemala, Julie moves in with her elder sister, Jeanne, a chronic liar and woman of rather loose sexual morals... Disillusioned with love, Jeanne is nevertheless engaged to Noël. However, Jeanne and Noël lead separate lives, and only communicate by leaving each other messages on the fridge.Everything suddenly becomes very complicated. Jeanne compels Julie to take up with Noël so she can have a fling with a passionate musician. Noël, meanwhile, sets Julie up with Michel -- without Jeanne''s knowledge.  Julie mixes things up even further. Egged on by her friend Marie-Ève, she alters the contents of the messages on the fridge in an attempt to breathe new life into Jeanne and Noël''s relationship. Along the way, she also begins to fall for the seductive Michel. The tables are turned on everyone... In the game of love and truth, illusion leads to betrayal, but love conquers all.', '/bfrAPx5MlLlx5DmOAquiaLBJ1Io.jpg', '2004-10-01', 91, NULL, NULL, 0, 0, '2026-04-29 22:25:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13905, 'The Red Book Ritual: Gates of Hell', 1499885, NULL, '/mXeINZrLRKbIw51spnruegjmLBS.jpg', 'The Red Book Ritual: Gates of Hell', 'Robbie embarks on a dangerous quest to contact his deceased girlfriend through a ritual that summons the dead. He heads to an abandoned house with a group of young people to perform the "Red Book Ritual." But during the summoning, supernatural forces awaken. Now they must face ancient horrors to survive.', '/dOLRsvnjOB6rCx6olyRsMT92PxI.jpg', '2025-09-18', 0, NULL, NULL, 0, 0, '2026-04-29 22:25:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13906, 'Kranti', 545339, NULL, '/s8QGlg2rnVlYkUl4qBHatkZgnJs.jpg', 'Kranti', 'Inspector Abhay Pratap Singh is a young, honest and diligent police inspector, serving with Bombay Police, and comes from a respectable family, which consists of sister Anu; mom Sushma; and dad, Awadesh, who is also the Commissioner of Police. Abhay has long suspected Mahendra Pratap Rana of being a criminal don, who also has links with terrorists, but thus far has been unable to gather any material evidence for the police to lay charges. The Commissioner is unable to accept his son''s word, as Mahendra is well-known, influential, and wealthy. Abhay continues to pursue his investigation despite of warnings from his superiors, and is ultimately suspended from duty. Now even after suspension, Abhay has come to know that the life of Coloney Krishnakanth is threatened by Mahendra, and reaches out to his dad, who will not have anything to do with him anymore. It will upto Abhay to save the life of Krishnakanth, against all odds that are stacked up against him.', '/dH9jHruCCwPHEdNq6KY5iL6hdA4.jpg', '2002-03-27', 142, NULL, NULL, 0, 0, '2026-04-29 22:25:51', 0);
