INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13909, 'Brothers Under Fire', 1414413, NULL, '/6D2NsU3FIQVthPgjT6RAsX58qZ6.jpg', 'Brothers Under Fire', 'Captain Jordan Wright''s squadron on leave for a wedding in Mexico encounters a murderous cartel. As Jordan tries to lead survivors to safety, war erupts between his squad and the cartel, forcing him into a battle to save his men.', '/e5EKqk9V7N3w0WvYFhl6wSVrMp0.jpg', '2026-04-15', 99, 'He never planned to fight. But he refuses to fall.', NULL, 0, 0, '2026-04-29 22:26:00', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13910, 'TransSiberian', 6687, NULL, '/dpSrTZIWeI3u025LSUOjV9FHFvf.jpg', 'TransSiberian', 'A TransSiberian train journey from China to Moscow becomes a thrilling chase of deception and murder when an American couple encounters a mysterious pair of fellow travelers.', '/dhTOda5CLp9tEdDzQZiqBTdv5lR.jpg', '2008-01-18', 111, 'You can''t escape your lies.', NULL, 0, 0, '2026-04-29 22:26:02', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13911, 'A Breed Apart', 1303055, NULL, '/jrpLhYHxsE7XVZCtP8LZrfhlvIy.jpg', 'A Breed Apart', 'When Violet accepts an invitation to a private island with some of the world''s most famous social influencers, she expects a weekend of unrivaled viral opportunity. She soon becomes part of her own horrific reality show when the guests are pitted against each other to capture the island''s legendary man-eating dogs before they become victims of the monstrous canines.', '/6IiNUUV6H2W1wUc8e1w4GfuQCOE.jpg', '2025-05-16', 100, 'Like. Subscribe. Survive.', NULL, 0, 0, '2026-04-29 22:26:03', 0);
