INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13913, 'The Chumps', 979571, NULL, NULL, 'The Chumps', 'When the story begins, a newly married couple (Franklin Pangborn and Marjorie Beebe) board a train for their honeymoon. Soon they make friends with what they THINK is a nice couple...not realizing they are card sharps. They crooks are spotted on the train and are warned NOT to take advantage of other passengers...so they invite the couple to their home in order to fleece them. Does the plan go as the crooks planned?', NULL, '1930-07-16', 20, NULL, NULL, 0, 0, '2026-04-29 22:26:11', 0);
