INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13917, 'From Straight A''s to XXX', 441168, NULL, '/8gBOpyW6iTDGZJR93YuF3L7dDuI.jpg', 'From Straight A''s to XXX', 'When a change of circumstances leaves Miriam unable to pay her college tuition, she makes a surprising decision: to start performing in adult films, using the pseudonym Belle Knox. Miriam lies to her family and her friends at school, keeping her double life a secret. But soon rumours spread and Miriam becomes the subject of vicious online attacks and unwanted attention. Miriam fights back: she talks to the media, saying her new line of work empowers her as a feminist. But her confident stand has unintended consequences. Miriam is shunned by her conservative family and her colleagues in the adult film world. One impulsive decision has quickly spiralled out of control - and Miriam''s problems are just beginning.', '/kvcdaGcres9pGDwZfPN9jOKfZh.jpg', '2017-02-11', 87, 'Inspired by a true story', NULL, 0, 0, '2026-04-29 22:26:19', 0);
