INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13919, 'Exploits of a Young Don Juan', 81774, NULL, '/4cd9YihTHx1j8oRdlwEa1emKiAl.jpg', 'Les Exploits d''un jeune Don Juan', 'In 1914, sixteen year old Roger returned home from boarding school during vacation to find his puberty hit hard in a house filled with beautiful women. These women have previous engagements with other men who are away, and during this time, Roger impregnates them all, including his aunt and sister, then devises plans to cuckold the men.', '/xvtRgQIRegLjsjaIkKQbh0hk3Qy.jpg', '1986-11-04', 100, NULL, NULL, 0, 0, '2026-04-29 22:26:23', 0);
