INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13922, 'My Fault', 1010581, NULL, '/oz4U9eA6ilYf1tyiVuGmkftdLac.jpg', 'Culpa mía', 'Noah must leave her city, boyfriend, and friends to move into William Leister''s mansion, the flashy and wealthy husband of her mother Rafaela. As a proud and independent 17 year old, Noah resists living in a mansion surrounded by luxury. However, it is there where she meets Nick, her new stepbrother, and the clash of their strong personalities becomes evident from the very beginning.', '/w46Vw536HwNnEzOa7J24YH9DPRS.jpg', '2023-06-08', 116, 'Love can only survive in the shadow of secrets.', NULL, 0, 0, '2026-04-29 22:26:30', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13923, 'Broken Time', 1388696, NULL, NULL, 'Broken Time', 'Dereck, a quiet physicist from a small town, plans a trip with his girlfriend, Erica, across the state to meet her family. When the couple’s car suddenly stops working, they encounter strange phenomena from what appears to be the aftermath of a lab experiment--from Dereck’s lab--gone wrong. After encountering a reckless criminal with his hostage in tow, and a father searching for his family, the group of strangers search for answers and uncover dangerous truths about their world, time, and life itself.', NULL, '2024-11-09', 0, NULL, NULL, 0, 0, '2026-04-29 22:26:31', 0);
