INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13925, 'He Sees You When You''re Sleeping', 1371534, NULL, '/5UxASgNjx4vK91LJDWq90BTnRMQ.jpg', 'He Sees You When You''re Sleeping', 'Chester returns to the home of his estranged and hideously over-privileged family at Christmas, only to find an unknown killer disguised in a Santa outfit is stalking and killing family members one by one, in order to claim the huge family fortune. Which one of them is the killer?', '/z3eKq2GqVnqZCK0j1gnHQ8GbK7k.jpg', '2024-11-01', 83, NULL, NULL, 0, 0, '2026-04-29 22:26:35', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13926, 'Rocky Aur Rani Kii Prem Kahaani', 848116, NULL, '/61RYedFgX1K07xgVIvdJzukSR4g.jpg', 'रॉकी और रानी की प्रेम कहानी', 'Gym-freak brat Rocky falls in love with Rani, who comes from a well-educated Bengali family. Being from polar opposite worlds, the two decide to switch their families to adjust to each other''s cultures and backgrounds and to know if their marriage will survive. Rocky and Rani are trapped in a world where they are united by love but divided by families and the ultimate question is will they fit in?', '/vTQIqlxUkOuyf2UKhlM2OUaFGKz.jpg', '2023-07-28', 178, 'The power of family will decide the fate of love', NULL, 0, 0, '2026-04-29 22:26:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13927, 'After We Fell', 744275, NULL, '/mxdiaM2tsx8M6W3zLgiPwAkhQfq.jpg', 'After We Fell', 'Just as Tessa''s life begins to become unglued, nothing is what she thought it would be. Not her friends nor her family. The only person that she should be able to rely on is Hardin, who is furious when he discovers the massive secret that she''s been keeping. Before Tessa makes the biggest decision of her life, everything changes because of revelations about her family.', '/dU4HfnTEJDf9KvxGS9hgO7BVeju.jpg', '2021-09-01', 99, NULL, NULL, 0, 0, '2026-04-29 22:26:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13928, 'Sandra Gets a Job', 876284, NULL, '/lXPMXslBXFMkighMwNVHPZ6ubXc.jpg', 'Sandra saab tööd', 'Doctor of Physics Sandra suddenly loses her job. Finding a new job seems easy at first glance, but it turns into various tragicomic challenges. Endless job interviews bring the former researcher together with all sorts of situations and new personalities.', '/6KmB1ic38F4HnJq5isGpq1BQuGY.jpg', '2021-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13929, 'County Court', 887025, NULL, '/gzg1fXg9iVtd2zSUZP5ia98UnzQ.jpg', 'Maakohus', 'An absurdist court drama where a mother and a father, ex-spouses, fight over the custody of their 5-year old son. However, the whole process takes place in the middle of a grain field instead of the classic court room. On that field the courtroom has no boundaries much like the mother and father whose actual goal is to exact vengeance on each other with no regard to the means used, forgetting their child entirely.', '/2NizFQqZd7lG4Qh2WB9TAEeSkXe.jpg', '2021-11-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
