INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13931, 'Shop of Dreams', 46900, NULL, '/oQsDue5QXFRgeO93eelUHLE1akW.jpg', 'Stiilipidu', 'Three friends return from a vacation and discover that the TV studio they work for has gone bankrupt - so they decide to start their own costume renting business.', '/cTW6ntUEi4UumSZdnxA3orNkLYJ.jpg', '2005-04-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13932, 'Where the Heart Is', 670509, NULL, '/339hBhBoauVSFmRxdEKc9C6AakY.jpg', 'Talve', 'Arno Tali''s son Arnold returns to his homeland Paunvere, which ignites a passionate love triangle between Paunvere''s young Toots'', Kiir''s and Teele''s. Despite the restrictions of the occupation period, people party, have fun and fight, youthful bravado does not allow itself to be tamed even in dangerous times.', '/xbJJG5Zr1bK73DxL807ydDlWjbo.jpg', '2020-02-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13933, 'On the Water', 767655, NULL, '/isUq6OyixnCLo4KuzoJvAZ4zcWG.jpg', 'Vee peal', 'Andres is a sensitive teenager raised by his strict grandparents in a small bland Soviet Estonian town. He is being bullied at school and his only friends are the drunkards, whores, and thieves living next door.', '/wECFPcijmLVVUmm16BYq4DTKMw2.jpg', '2021-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13934, 'Love Is Blind', 227261, NULL, '/obz0VKPP0qyczjKpQVTPeStK7oW.jpg', 'Kertu', '30-year old Kertu has lived under her father''s power her whole life. Because of her gentle nature, she is thought by locals to be a little simple-minded. The young woman makes her first timid attempt to change something in her life - she send a postcard to Villu, a handsome but degenerate village drunk.', '/pkKYLe3NNrbO10POQZSRZSqOamV.jpg', '2013-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13935, 'The Vacationers', 964276, NULL, '/kgBQVIPwJkwZJEdbtnS8qSl5nHn.jpg', 'Suvitajad', 'Fisherman Ärni has decided to take vacationers for midsummer due to the poor catch of fish. The plan is not bad, but extremely troublesome guests arrive at his beautiful farm in Muhumaa: Mrs. Sohvia, her husband Johan, their son Junior and Sohvia''s beautiful sister Erna with her businessman cavalier Ivo. From first glance, it is clear that Ärni and his wife Laine will have a hard time with these vacationers.', '/wkYr7YYZ5JirkYjKzifQY60ndh.jpg', '2023-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13936, 'FRESH BLOOD: Own and Stranger', 758049, NULL, '/nh73VjZgDYbsUXjcxFStwY99kG9.jpg', 'VÄRSKE VERI: Oma ja võõras', 'Six fresh short films on the topic "Own and Stranger" from even more fresh Estonian directors.', '/xhYxCXNiP3qkqM0ME2j2NDFjbw.jpg', '2018-11-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13937, 'Strawberry Eaters', 541727, NULL, NULL, 'Maasikaõgijad', 'A fantasy film about two strawberry farmers whose field is destroyed by ravenous snails. The couple tries to start a new life in the city but when the woman announces they''re expecting a child, the paranoid man suspects that snails are behind that as well.', '/2YeYD8dL0npWFpcmvabQebsjrtU.jpg', '2018-05-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13938, 'Deliver Us', 1097150, NULL, '/s7JEziJOgV7HsQimPGXSrkwMVas.jpg', 'Deliver Us', 'When a nun in a remote convent claims immaculate conception, the Vatican sends a team of priests to investigate, concerned about an ancient prophecy that a woman will give birth to twin boys: one the Messiah, the other the Antichrist.', '/qOWZJgeEvH9ETqCFqxc6803l00H.jpg', '2023-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13939, 'Manslayer/Virgin/Shadow', 485335, NULL, '/inWlr67HFO1WOVxF9uMrqR0tlDz.jpg', 'Mehetapja/Süütu/Vari', 'The film consists of three chapters. The Manslayer takes place more than a hundred years ago. The leading character Maara is a young bride who is about to start her life in her new family. The Virgin, set in the spring of 1949, tells the story of a young woman called Elina, who has been deported from Ingria into Estonia during the previous war. The Shadow moves in the present, on the border of real life and fantasy. The main character, Luna Lee, has decided to flee from home. Is there anything besides emptiness somewhere? The film is led by the singularity of the leading character - Maara, Elina and Luna Lee are all played by the same actress.', '/hwv8Ju7UTRMmvhA6Bt6ViCdSQF1.jpg', '2017-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13940, 'The Polar Boy', 399097, NULL, '/uqR64SzJzZ0sLDwR7zcEDhjBW3z.jpg', 'Polaarpoiss', 'Mattias has a dream to become a photography student of the Berlin Arts Academy. On the journey of following his calling, his dream is constantly put to a test after Mattias falls in love with a beautiful free spirit Hanna. Trying to win her heart, Mattias feels the need to prove Hanna, that he can be just as adventurous and unpredictable as she is. Breaking the law together with Hanna, Mattias risks everything dear to him, not knowing yet, that Hanna''s bold acts are only the symptoms of bipolar disorder. In the moment of jelousy Mattias accidentally commits a crime that could put him behind bars for years. The only escape he sees is to get himself declared irresponsible. In order to achieve that Mattias decides to start faking the illness her gilfriend really has - bipolarity.', '/6cDePoWXI37490kW9xzxf0ndMsK.jpg', '2016-05-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13941, 'Fire Lily', 516558, NULL, '/2R5PSZNvDW9d5c0O4dvshSxIqvw.jpg', 'Tuliliilia', 'The mystical and thrilling drama asks what sort of reality can give our life meaning. The film tells the story of Pia (38), an ophthalmologist, whose marriage has recently ended because she was not able to have children. As she strives to move forward with her life, Pia learns the unknown but also finds her inner strength. Unexpectedly, her deepest wish to become a mother materializes, but not quite in the way she imagined it.', '/mNDEceHZzZBNkKYQiIEPJTF1nX6.jpg', '2018-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13942, '8 Views of Lake Biwa', 1040368, NULL, '/AekMp8wibrwFWgExYtIUDSMg7B7.jpg', 'Biwa järve 8 nägu', 'On the shimmering shores of Europe’s otherworldly edge, two teenage girls, Hanake and her best friend are discussing their first love interest while gazing out at yachts sailing to Kyoto. They whisper prayers and poems, the language of their longings. But the magic is fading in their isolated fishing village as they’re dealing with a recent disaster, with some indulging in erotic art, some in spiritual spells. It becomes clear that intimacy alone won’t help them process their loss.', '/zTV5R1cs34BrSc4618Rfd38qWol.jpg', '2024-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13943, 'Nightingale', 1199328, NULL, '/iOlNn5T2ddLaziPcO3CU2tdpFKn.jpg', 'Ööbik', 'Autumn 1944 in Tallinn, Estonia. German forces retreat as the Russian army settles in. Young soldier Aleksei is sent from the frontline to work in a prison filled with Estonian political prisoners.', '/26QBwusY1LrAjujNWed8aw4xJrU.jpg', '2023-11-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13944, 'Faulty Brides', 1053621, NULL, '/qp7mAUMtuXtbFOYX44uctLxVmxX.jpg', 'Vigased pruudid', 'The owner of the Lipuvere farm decides to marry his daughters off to wealthy suitors from the Mulgi Parish. However, the hearts of the girls already belong to local boys, with whom a plan is forged to get rid of the troublesome grooms.', '/cEifUFGunUxkM0jTVFmWKlEPMdL.jpg', '2023-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13945, 'Wishes from the Well', 1059237, NULL, NULL, 'Soovid kaevu põhjast', 'The story of a man caught between the gears of life, who has to find the missing pennies to buy medicine before the pharmacy closes. When begging doesn''t help, despair drives him to the bottom of the wishing well.', '/9N7VvsgYPzNY4upptxxkqNeHzOJ.jpg', '2022-12-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13946, 'Black Peter', 229805, NULL, '/exOIjwH4NgLrmGqis82aOOQt635.jpg', 'Must Peeter', 'Peter and his wife have dinner with friends in a restaurant. They have not quarreled for two weeks already. A new record could be in the making. But a trivial argument soon grows into a quarrel and the night brings weird games into their relationship.', '/oGfBhOFFNEAYQB0g0tMul0B3qvu.jpg', '2008-03-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13947, 'Skin of a Mandarin', 1064189, NULL, NULL, 'Puudutus', 'The film delicately follows 25-year-old Anna, whose mother has died suddenly. She wants to send her Orthodox mother on her last journey according to customs, but she runs into bureaucratic rules that do not allow Anna to dress her departed mother herself. This conflict brings her together with Maria, a 45-year-old funeral home worker, who in this story represents the hidden fears of death and grief on a deep emotional level.', '/iml7gm6EB4WkMEedqaRnKrsrBGa.jpg', '2023-11-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13948, 'Roukli', 357784, NULL, '/phAVJuGEQlWOZIkBqacLI7HesnH.jpg', 'Roukli', 'Two men on the run cause chaos in a small community that is on the brink of getting swallowed by war.', '/1NPWhPIiL00srPma3ni0TiBSiFR.jpg', '2015-09-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13949, 'Delusion', 416906, NULL, '/3sAjBAQTJcpEj9Lq9KnJwp3N43w.jpg', 'Teesklejad', 'After a heavy decision, Anna and Juhan are unable to move on with their lives. They take time off at their friends'' fancy summer house and once there, are forced to offer shelter to another couple caught in the storm. The couple assumes that the house belongs to Anna and Juhan and they do nothing to correct the mistake. Instead, they seize their new roles and start taking their mutual bitterness out on the strangers.', '/pAfKbWmfSgpu4xuLGbUkdZditMG.jpg', '2016-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13950, 'Portugal', 516565, NULL, '/4E2n3QsFNwzvNVcSzFUxkpMau1K.jpg', 'Portugal', 'Karina and Martin are in a pleasent relation where everyday life flows in an effortlessly accustomed way and no small misbehaviours can shake it’s rush. Life is good. Perhaps it’s this perfection and frequent patterns that make them finally pose a question – is everything to be expected in life?  This is a story about following the yearning of your soul. Longing for something other than the present and having the courage to be deliberately lost.', '/kLEnBAR1sDKOfIHOVrhCXjFOn3g.jpg', '2018-04-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13951, 'The Riddle of Jaan Niemand', 552393, NULL, '/aNtIQw3rYfoTUDhRxXFMR7uB7Qx.jpg', 'Põrgu Jaan', 'After ten years of war, plague and famine, the land is swept clean of people. The few remaining souls are scattered about, living in misery and lacking hope. An anxious silence hangs over the land. On one particularly starry night, two peasants find a stranger on the seashore.', '/vtagDZDf72NJK3MIaxCvkWAPR7L.jpg', '2018-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13952, 'Phantom Owl Forest', 560716, NULL, '/cMCWp4BvUVSVWiirSQhcLzxk5rv.jpg', 'Eia jõulud Tondikakul', 'A 10-year old girl''s Christmas plans take an unexpected turn after she is brought to a mysterious Estonian farm.', '/qx9cTMo1wQCu4YMsOthz7YisLK8.jpg', '2018-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13953, 'Rain', 744713, NULL, '/51Y8buHBShnG6p9ZUwumXURpiAV.jpg', 'Rain', 'The film follows 12-year-old Ats, whose older brother Rain unexpectedly returns to the family home in a small seaside town to face their authoritarian father Kalju and their mother, a woman on the verge of losing love. Ats is a witness to the clash between his father and brother, two stubborn men from different generations with radically different views of the world.', '/l6xm2a7KaYSdCzimXyN4mm5rJNo.jpg', '2020-09-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13954, 'Time Capsule', 769122, NULL, '/rqoAjR33M9BW9olf2R2NLifJLVW.jpg', 'Ajakapsel', 'Emeri comes across a map from her childhood - a map that marks the location of a time capsule buried 19 years earlier - and memories come rushing back.', '/mUUsvkxFEq0BxMYVTqkaZqLP37v.jpg', '2020-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
