INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13957, 'The Tree of Many Faces', 1280925, NULL, NULL, 'Mitme näoga puu', 'A Slavic folk tale unfurls when a lovelorn woman decides to sacrifice her soul for the heart of another.', NULL, '2023-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:39', 0);
