INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13959, 'The Chattering', 517559, NULL, '/zsWDQNzTrwH8lf29fH7RZsVISXg.jpg', 'The Chattering', 'Hundreds of gremlin-like mutant creatures from a melting glacier violently descend on a survivalist cabin in the mountains where an unsuspecting circle of high school seniors are celebrating their last weekend together before college.', '/ofverqCOehkTcfaUxo1k1P4tK7Q.jpg', '2017-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
