INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13961, 'Held', 1278127, NULL, NULL, 'Held', 'When Iris''s sister is taken hostage by a serial killer on the run, she is forced to make a decision between her own life and the life of her sister. The choice she makes affects the rest of her life.', '/v6zUy5ggZZnlCqp2hiSViITXrVB.jpg', '2015-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
