INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13963, 'Night Blind', 1278132, NULL, NULL, 'Night Blind', 'In the sleepy town of Clearwater, Sheriff Jack Carter tries to solve the murder of the local reverend but as he pursues the suspects, Jack struggles with the secrets he learns and confronts the monster he can become.', '/zRuitqIJlnNOxcTTaUQumjAJ01v.jpg', '2010-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13964, 'Takeo', 1278134, NULL, '/833daSOpYKIfHafrIHy0LIcRSSP.jpg', 'Takeo', 'A loving mother most protect her family from harm when a stranger terrorizes her home only to discover that the true villain of this story may be her husband.', '/z6UyHk24l7JVRcLWi4YSPAciDp7.jpg', '2010-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13965, 'Barbarella', 1034482, NULL, NULL, 'Barbarella', 'A remake of the 1968 classic, based on the comic books by Jean-Claude Forest. Barbarella, an astronaut from the 41st century, sets out to find and stop the evil scientist Durand Durand, whose Positronic Ray threatens to bring evil back into the galaxy.', '/kOIVwpDSlLQxJzuBXQFvqdIEYjd.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13966, 'Stolen from the Suburbs', 357525, NULL, '/2WxBFKk9QlGRP4L9NAl4n1cihyB.jpg', 'Stolen from the Suburbs', 'A single mother from the suburbs searches for her kidnapped daughter before human traffickers sell her on the international market.', '/2jU6kQzIo9IiT1NJMtp9aKTj8I9.jpg', '2015-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13967, 'Along Came the Devil', 409056, NULL, '/6tpvIOtArFdyd5oo3FbcWAVj0NN.jpg', 'Along Came the Devil', 'After a troubled childhood, Ashley searches for a connection, and unknowingly invites in a demonic force, which leaves her loved ones fighting for her soul.', '/tEiu83QxMMWWD8gWUtXR4piF1Iw.jpg', '2018-08-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13968, 'The Horde', 395797, NULL, '/rhATinMhgKwBxsuS5OcFaaCSuuB.jpg', 'The Horde', 'The film follows John Crenshaw as he accompanies his girlfriend and her students on a weekend nature-photography expedition deep into the woods. What should be an educational and fun-filled weekend turns into horror as the group is besieged by an unspeakable evil - a horde of hideously disfigured, mutated humans with an insatiable taste for blood. As things go from bad to worse, Crenshaw becomes their only hope if they are going to get out alive.', '/mHjXFWi5WnW2idcsOUC0zfAXvQd.jpg', '2016-05-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13969, 'The Martial Arts Kid', 316822, NULL, '/qYF25kMTTFK1wPacYdwJofmkWam.jpg', 'The Martial Arts Kid', 'When a troubled teen from Cleveland experiences bullying in Cocoa Beach, he soon learns Martial Arts to gain confidence and self-defense skills.', '/9MaPHFNj2ljX0Xk76eG0cjvN2dd.jpg', '2015-04-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13970, 'Cassidy Way', 384446, NULL, '/cbiiobXlsliG4x7KNMJV9yw6zLC.jpg', 'Cassidy Way', 'When a film student and her two friends go to Kern County to shoot a documentary, they stumble upon a mysterious family and learn why Pandora''s box should never have been opened.', '/4Q9fzRXgXmJQVWhRbIVqsTvoV2L.jpg', '2016-02-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13971, 'The Bling Ring', 116853, NULL, '/tOWjPR2PO8ujUhQxK4JPU0D0KmD.jpg', 'The Bling Ring', 'At the center of one of Hollywood''s most notorious burglary rings in 2009 was a group of average, middle-class teens from a quiet suburb. This is the behind-the-scenes story of how Nick, a shy, awkward boy, lured by the promise of popularity and acceptance, found himself following his glamorous, charismatic best friend Rachel into breaking into celebrities'' houses and robbing them of millions of dollars in clothes and jewelry.', '/x3WmMVULbz2IZ75J3n5wWaatRml.jpg', '2011-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13972, 'My Way', 1280463, NULL, '/iJXKkKYWspXejH32ZqmlmzSz9bO.jpg', 'My Way', 'My Way is more than a song, it''s a major score that has crossed the boundaries of eras and generations. An anthem that has become a part of ourselves and of music history. My Way is one of the most covered songs in the world, from Sid Vicious to Tom Jones, from Nina Simone to Pavarotti. Yet many people are unaware that it was conceived in France, by the pool of Claude François'' private hotel, in the summer of 1967, and that a succession of chance encounters and sleepless nights guided it across the Atlantic to the man who was to make it a legend. Like a biopic, this documentary recounts the birth of a myth and how a song entered the pantheon of pop culture.', '/8PZTdb1gj8b6BVo54yvITotF56z.jpg', '2024-05-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
