INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (13999, 'Wrath of Dracula', 1144028, NULL, '/lm2tnUSrtYjNrxl01ujzeLLzZ3M.jpg', 'Wrath of Dracula', 'The year is 1897. When her husband Jonathan disappears after travelling from England to Transylvania at the behest of the mysterious Count Dracula, Mina Harker journeys to Transylvania to find him. Upon her arrival, she finds a decimated village and one Van Helsing, who is hunting Count Dracula. Van Helsing begins training Mina in the art of vampire slaying, and the unlikely duo set off to rescue Jonathan from the Count and his brides and end Count Dracula’s reign of terror forever.', '/xsxOwoSaqh3EhXOXAvgdsg6y4Lw.jpg', '2023-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
