INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14001, 'Zombie Massacre', 153509, NULL, '/qsFQcYQV6shVoUMipW5mlBvHyvb.jpg', 'Zombie Massacre', 'A bacteriological weapon developed by the US Government to create a super soldier - spreads an epidemic in a quiet little town in the middle of Eastern Europe. All citizens have been turned into infected zombies. The plan is to bring an atomic bomb into the city''s nuclear plant to pretend a terrible accident occurred. No one has to know the truth. A team of mercenaries is hired to complete the mission. The battle is on. Hordes of monsters against the team. Who will survive?', '/iVAuzh1gMuqjCuLBaGajY4lAsgL.jpg', '2013-06-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14002, 'The Heroes of Halyard', 1160627, NULL, '/zmuTRTpBgCen2igqgcsjvGlLtKF.jpg', 'Хероји Халијарда', 'A story inspired by the largest single rescue mission of downed Allied airmen behind enemy lines in aviation history of all time, codenamed “The Halyard Mission”. This action took place in the summer of 1944. It was led by the Yugoslav Army in the Fatherland that was headed by General Dragoljub “Draža” Mihailović. It was at great cost and sacrifice that the Serbian people saved 508 American and other Allied countries’ airmen from certain death, sending them off to safety from the improvised airfield in the Serbian village of Pranjani, at the foot of Mt Suvobor.', '/20NRJyeBycwQUlhgCeH0QyDNgcZ.jpg', '2023-10-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14003, 'Artifacts of Fear', 1188278, NULL, '/qHwRjxH0tZ2yq5rJaKi3JZlNRIm.jpg', 'Artifacts of Fear', 'Enter a world of witches, murder, and mayhem in this anthology linked together by an infamous local antique store where things are not what they seem.', '/9qiMS1F8WxLFJOSzIF99zDhWNpT.jpg', '2023-09-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14004, 'The Shamrock Spitfire', 1200208, NULL, '/5mjyOjp4QU5GL1hsUJbVurXUKYI.jpg', 'The Shamrock Spitfire', 'The story of Irish fighter pilot Brendan "Paddy" Finucane, who at the age of just 21, became the youngest ever Wing Commander in the Royal Air Force, and one of its greatest and most celebrated fighter aces during World War Two.', '/AsSxBwz8ubOSneq3C2bBkqAHpz.jpg', '2024-02-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14005, 'Spring Lakes', 1224563, NULL, '/awI3WlmQp4GGBpOwJxMrHlhAXFN.jpg', 'Spring Lakes', 'When Marcus, a down and out struggling filmmaker goes on a search for his missing sister in Spring Lakes, he encounters strange and mysterious occurrences in the form of a Satanic Cult. Marcus must find his sister before, he too, becomes engulfed by the living forest and suffers the same fate as his sister, Shiela.', '/AmtMUKIOuWEjldNBG1TkHJgEppC.jpg', '2023-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14006, 'The Last Redemption', 1233243, NULL, '/yjqUa6yohr56Uep18W0zsgbMGtl.jpg', 'The Last Redemption', 'In a land of swords and sorcery, bandits break from their gang to protect a little girl, pitting them against their old friends and former leader who was once like a father to them.', '/xyKdcbzqX8pG17S4cLKURHlNlvN.jpg', '2025-01-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14007, 'The Somme: The First 24 Hours with Tony Robinson', 824973, NULL, '/9zZmIlwaxsdo95YvwyjUe2EImo9.jpg', 'The Somme: The First 24 Hours with Tony Robinson', 'Hosted by actor and historian Sir Tony Robinson, this one-off special tells the powerful and moving story of five men, all members of a unique volunteer army – the Sheffield City battalion – as it recounts the soldiers’ last days, leaving their homes and loved ones to go and serve alongside their friends and neighbours, completely unaware of what lay ahead of them. Central to the programme is the story of Private Frank Meakin, who recorded his unique personal testimony of the war. Frank and his friends could never have anticipated what they would experience, but 100 years on we know in detail, thanks to his diary – an account that shouldn’t have existed, because keeping one was forbidden for servicemen on active duty on the Western Front. Frank’s diary, which was smuggled back from the Front, reveals the intimate details and dramatic stories of one battalion – and one British city – in the words of one man.', '/cwFrgJhrijn3NI5b26zA2WXxLM4.jpg', '2016-07-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14008, 'Our Country', 1336851, NULL, '/aLnRyk4oFXByvmcHXCBDRgIheCk.jpg', 'Our Country', 'Scott is eager to make a good impression on John, his new girlfriend''s Dad, but whilst spending the evening at a pub with him and his friends, Scott is forced to confront some ugly home ''truths''.', '/igba8Re2Rf35VUUU8dNLWs8k3Ko.jpg', '2024-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
