INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14018, 'Wrath of the Crows', 207260, NULL, NULL, 'Wrath of the Crows', 'In a filthy, cramped prison, some inmates must submit to injustices perpetrated by the head of the guards and his tormentors. Above them all, however, is the Judge, whom no one has ever seen: feared by both inmates and guards, he imposes the laws to be obeyed. The prisoners know the rules to follow but remember nothing of their lives; they know only the evil they have done to get there. Almost out of nowhere, a new prisoner joins the company: Princess. She is a beautiful woman, covered only by a fur coat of raven feathers...', '/7YLPP6hB710nylgQXKkXYzvLYlz.jpg', '2013-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14019, 'Dragon Hidden in a Mysterious Hole', 1085542, NULL, '/9KPJktlPfUOcyn521LMWSqWmu4E.jpg', 'Detective Dee and Dragon Hidden Lair', 'A suspenseful detective movie directed by Guo Yulong and starring Zhu Zixiao. When the "ghost ship" entered Hong Kong, the boss wanted to close the case with "Water Bandit Rebellion" in order to protect Mingzhe''s safety, but Di Renjie faintly felt that something was wrong. The grand ceremony is just around the corner, and people in Chang''an are panic-stricken. The empress ordered Shen Ming, the head of the Dali Temple, to close the case within three days. Shen Ming had no choice but to put the pressure on Di Renjie to solve the case. Leng Jiyue, the chief of the water supervision department, also joined in, and met Duan Yan, an old acquaintance, on the "ghost ship" where the incident occurred. The three went to the "Xiacheng" of Chang''an Intelligence Center to obtain information. After exploring all the way, the two underground forces in Chang''an finally found the place where the secret is hidden--the cloud cave.', '/cKCyUsWRZPSdTrVTRwg4WpUAdNF.jpg', '2023-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14020, 'Tale of the Mural', 1092546, NULL, '/aytp6kAN7ynNMrkChXFee2hdZEI.jpg', '聊斋画壁', 'Zhu Xiao Lian, the most famous painter in Jiangnan, entered the world of the painting wall where demon spirits exist through an ancient temple mural. There, he meets the first woman who makes him want to draw a portrait, Wei Sheng. Unexpectedly, he set off the trap that was laid down by the bird demon. Unexpectedly, this breaks the bird demon plot. He falls in love with Wei Sheng as they fight the bird demon hand in hand. It turns out that Wei Sheng''s real identity is that of a Phoenix God, and the only way to defeat the bird demon is for him to die to help Wei Sheng gain nirvana.', '/vBBG0dtKF8Q1SRRumoeaGUELZ4v.jpg', '2023-02-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
