INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14025, 'The Demon Hunter', 928281, NULL, '/rK829tgwHJfV8EYPFBcHlUoQSsk.jpg', '降魔天师', 'Since the founding of the Yuan Dynasty, Emperor Zhao Yuwen of Yuan Yuan managed martial arts, quelled rebellions inside, and eradicated barbarians outside. The Huntian Supervisory Institute Si Zhengbai and Yitong accompanied Sun Duhu of the Duhufu of Xiyuan, and went to Xiyuan to investigate the locust plague and cholera that plagued the people. Bai Yitong. Bai Yitong observes the heavens, predicts the incision, establishes a calendar to solve problems, and solves strange cases every time, earning the emperor’s trust. But Bai Yitong was strict and inflexible, but the others could not say anything and just listen. Bai Yitong is idle except for his work, and his teacher, Sikong Chong, freely devotes himself to research at the inspectorate. Bai Yitong and Sun Duhu found a hole in a cave during the locust damage investigation, where they are indiscriminately attacked by locusts. Then, Bai Yitong returned to the city with his hands and reported this strange incident to His Majesty the Emper', '/dt4O1mRH4pbsTIQnnZ7AIatk2Pe.jpg', '2022-01-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14026, 'The Incredible Water Monster', 1127306, NULL, '/se5aDpgMHY4G9oRU5ydXDU4xN3i.jpg', '超能水怪', 'Su Liya (saw the news that a water monster appeared in Dianchi Lake while she was abroad. She vaguely felt that the water monster was inextricably linked to her missing father. In order to solve the mystery of her father''s disappearance, she came to a dangerous village alone. The local villagers built a resort here to attract investment and tried their best to prevent outsiders from investigating the water monster.  In order to protect the peace of the area, they used their cognition of high-dimensional space and the loopholes of time travel to fight wits and courage with the water monster and the greedy foreign evil forces. What is the connection between Su Liya''s father''s disappearance and the unknown creature?', '/xCyLjTJSVS25DvdRhsG9OMNQQT4.jpg', '2023-05-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
