INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14034, 'Peeper', 995462, NULL, NULL, '偷窺者', 'The nearly outdated actress An Qi has been in the entertainment industry for ten years but is not tepid. She and her agent Amy have a plan. The two carefully planned a hype event, and used Wang Hao, a fan who was too delusional about An Qi, to get rid of it after successfully hyping it up. From the exposure of the indecent video at the film conference, to An Qi''s move and arranging for Wang Hao to take care of her, all plans are going smoothly. Finally, one night, An Qi and her neighbors were attacked one after another, and the situation was serious. After the police took away Wang Hao who attacked An Qi, An Qi and Amy quarreled about whether to turn themselves in. Amy unexpectedly discovered that someone had been spying on An Qi, and that someone else was behind the attack on the neighbor.', '/cWlbPYUp2oYUdN5ajQap7wthDRa.jpg', '2016-06-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14035, 'The Light of Darkness', 270261, NULL, NULL, '黑暗之光', 'Hard to force young white ( Xu Huan ) investment failed to work frustrated , debt, felt whole life of darkness . Girlfriend A V ( Zhao Jing Yi decorated ) painstakingly exhortations , White did not listen , relying on alcohol numb . After a day in the bar street outside the white war hero rogue , picked up a strange goggles . Wearing goggles white home after going to sleep, but do not want a black front . When you wake up already in the middle of a TG party, became the suave rich handsome . A beautiful dress Saladin himself is moving out leering.', '/d0IVgnINtUoTrSfLeL0AIXkTzxL.jpg', '2014-04-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
