INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14038, 'Another World', 996131, NULL, NULL, '微天堂', 'Housewife Jingru suddenly found that people in her apartment were dying one after another! And her husband also had an abnormal phenomenon, and finally, her husband died strangely... Jingru was determined to find out, she pushed open the doors of the apartment... glutton... erotic maniac ...violent people...enjoying dark activities in those doors...but they don''t need to take any responsibility because they''re just playing games! An absolute virtual reality game "Micro Paradise"! The side effect of this game is that players can''t tell the difference between virtual and real! In the end, she was eroded by her own desires and happily committed suicide to reach the end of the game. Slowly, Jingru also got involved in the game, and just when she was trapped, a mysterious boy Gong Le appeared to rescue...they together Challenge the creator of the game, Zino, but can they defeat the perverted ultimate boss and escape from Micro Paradise...', '/jFUfUyLn9yTEtvmNFrCua2gCf8Z.jpg', '2016-04-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:40', 0);
