INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14086, 'On Our Merry Way', 90980, NULL, '/lFJjK1GG6GtClgygkwAuXUQu2Jc.jpg', 'On Our Merry Way', 'Oliver Pease gets a dose of courage from his wife Martha and tricks the editor of the paper (where he writes lost pet notices) into assigning him the day''s roving question. Martha suggests, "Has a little child ever changed your life?" Oliver gets answers from two slow-talking musicians, an actress whose roles usually feature a sarong, and an itinerant cardsharp. In each case the "little child" is hardly innocent: in the first, a local auto mechanic''s "baby" turns out to be fully developed as a woman and a musician; in the second, a spoiled child star learns kindness; in the third, the family of a lost brat doesn''t want him returned. And Oliver, what becomes of him?', '/r7F4aCepd6bF25XbY0UX8xCTEEc.jpg', '1948-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
