INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14095, 'The Clown', 1376171, NULL, NULL, 'The Clown', 'Severely injured after saving the son of Judge Jonathan Le Roy from a team of runaway horses circus clown, Piffle is taken to recover at the Le Roy home where he falls in love with the judge’s daughter, Millicent. She however loves another, Dick Ordway and is secretly carrying his child. When he is reported to have perished in the desert Piffle steps forward to save Millicent’s reputation by being husband and father. Millicent agrees but the judge insists Piffle leave the circus and become a banker. Piffle acquiesces but when Dick reappears many complications ensue.', '/62CplpcNGBN1fQBCpqBQzJb4zN.jpg', '1916-06-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14096, 'Bob Hope''s World of Comedy', 269294, NULL, NULL, 'Bob Hope''s World of Comedy', 'Bob''s favorite memories and funniest moments on TV  The biggest Stars! ... The biggest laughs!  On DVD for the first time, this special 90 minute collection proves that laughter is the universal language with a sidesplitting salute to slapstick, satire, sketch comedy and zingers. Featuring Bob''s funniest moments on television, this tribute includes a virtual who''s who of legendary entertainers like Bing Crosby, Jackie Gleason, Roy Rogers, Ingrid Bergman, Bob Newhart, Lucille Ball, Ann-Margret, Jack Benny, Angie Dickinson, Steve Allen, Johnny Carson, Danny Thomas, Don Rickles, Milton Berle, Redd Foxx, Dorothy Lamour, Frank Sinatra, John Wayne, Dyan Cannon, Debbie Reynolds, Lassie and more.', NULL, '1976-10-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14097, 'Suave Patria', 131978, NULL, '/sHQl9b9L78t7nQUqEvWtFfmmznT.jpg', 'Suave Patria', 'Oscar and Arthur are two actors without fortune who survive unemployment with a routine street, where one represents the thief and the other to the police. Thanks to this performance are "hired" by Mr. Mauricio Tavares to play a practical joke on dangerous Don Antonio Robledo, a senior executive who suffer a fictional kidnapping for later culminate in a surprise party.', '/cwNIOTZY30yBj64Uf6Q0wnXlapo.jpg', '2012-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14098, 'Pink Punch', 243672, NULL, '/7OyRJ8yn6tSO4dZ7echYkO0rnaU.jpg', 'Puños rosas', 'Jimmy Morales is a young fighter with a short career but with a promising future in the world of boxing. One night, after watching a movie, he witnesses a cold-blooded murder committed by Germán Corona, a known gangster of the neighborhood. Their eyes meet, Jimmy fears the worst, but the murderer runs away inexplicably. From that moment, a peculiar relationship between the boxer and gangster develop.', '/oIlv8HPqHPm8uHtjK3zcZwH23Nu.jpg', '2004-03-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14099, 'Pulling Strings', 219553, NULL, '/2Z0Pm7pLySHmaE16T5NINxcP7In.jpg', 'Amor a primera Visa', 'Rachel is an intelligent, modern-day woman constantly on the move. Primarily focused on her career as a diplomatic consul for the U.S. embassy, she''s literally lived her life on the move, globe-trotting from city to city. Currently working in Mexico City and set to leave for London, Rachel''s world turns upside down on the eve of her own goodbye party when she gets drunk and passes out on the street. Saved by Alejandro, a handsome Mariachi singer and single father, Rachel wakes up in his apartment with no recollection of how she got there. Nor does she remember that she rejected his visa the day before, which he desperately needs for his daughter. Romance unexpectedly blossoms between the two, but either sparks or fists will fly after she finds out his secret.', '/lCXpl44L4cd4SeZ3YeooPeGcd2r.jpg', '2013-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14100, 'The Wingwalker', 1183699, NULL, '/g7cIVHEdgADI3YjI4oCH6xk6vj2.jpg', 'Un Viaje Al Corazón', 'A young widower is deported as his daughter is scheduled for a heart transplant, this will lead him to orchestrate the boldest border crossing plan in history.', '/tROfq1PDlMAWAGKAdgaeweobsJ.jpg', '2024-10-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
