INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14121, 'Golden Dawn', 164011, NULL, '/wVfgfRgbSwAOlHTxfctI0fw86NH.jpg', 'Golden Dawn', 'Dawn, a young white girl who has been kidnapped in infancy and reared by Mooda, an African woman who operates a canteen in the German cantonment, meets and falls in love with Tom Allen, an English rubber planter who is a prisoner of war. Shep Keyes, who has joined the German troops, covets her but realizes he cannot possess her because she is betrothed to the tribal god, Mulunghu. On the eve of the ceremony, he learns of her love for Tom. Tom, meanwhile, is sent back to England, and when the English take the territory from the Germans, Shep tries to incite the natives, who are experiencing a drought, against Dawn because of her love of a mortal. Tom learns from Mooda that Dawn was stolen from a white trader and finds her seeking refuge in a convent. Shep arouses the natives, but Dawn declares her faith in the white man''s God, and a thunderstorm brings relief to the parched land, after which Tom claims her for his bride.', '/6sXMZAieQVmXegkWIilsvKiHSHm.jpg', '1930-06-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14122, 'Good Time Charley', 296787, NULL, NULL, 'Good Time Charley', 'Song-and-dance man Charles Edward Keene (Good Time Charley) is bereft when his wife, Elaine, dies as a result of a fall incurred trying to evade the advances of Hartwell, her manager. Years later, his daughter, Rosita, becomes an overnight sensation as a result of her cafe act under Hartwell''s management, and Charley is given a bit part in the show at her request.', '/wThKWFuBEYWhbhG1WsFetKJ8s7W.jpg', '1927-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
