INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14124, 'The Younger Generation', 204643, NULL, '/8Qz8S5AsiOOF5kvNW75dUSgj1JP.jpg', 'The Younger Generation', 'Soap-opera about a social-climbing Jewish man and his old-world parents who are heartbroken by his rejection of them. Young Morris Goldfish follows his immigrant father into business. His ruthless business practices cause him to become a big success, and he moves the family to Park Avenue. They go, but were happier back on the East Side. Morris is ashamed of this parents and his humble origins, but learns in the end that there is more to life than money.', '/jjdA2gKcL8CQAGLvnvNqDw3B39T.jpg', '1929-03-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
