INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14127, 'Twinkletoes', 408936, NULL, '/5F6Xk13soyM0icQk9gZ5jKme8I9.jpg', 'Twinkletoes', '"Twinkletoes" Minasi wants to be a great dancer like her deceased mother. Twink meets Chuck Lightfoot, a noted prizefighter, who falls in love with her at first sight. She tries to avoid falling in love with Chuck, whose wife, Cissie, is a drunken harridan and more than a little bit spiteful. Meanwhile, Twink has secured a job in a singing-dancing act in a Limehouse theater, under the auspices of Roseleaf, who has more than just a protective interest in the girl. The jealous Cissie discovers that Twink''s sign-painting father also has a night job as a burglar, and she turns him into the police. While a big success dancing on the stage, the arrest of her father has left her somewhat down in the dumps, and she decides to toss herself into the Thames. Possibly, the now-free Chuck, since Cissie has been killed in an accident, might come along and rescue her.', '/ju3I8jOB9zRCBKW4sApZDuUplUK.jpg', '1926-11-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14128, 'The Prude''s Fall', 437432, NULL, NULL, 'The Prude''s Fall', 'A French captain persuades a rich widow to become his mistress, but it is a scheme to test her love.', NULL, '1925-11-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14129, 'Her Wild Oat', 363800, NULL, '/xe5kkJ9dvgn7eN6prkkFjvRqQYE.jpg', 'Her Wild Oat', 'In this feature comedy, silent film star Colleen Moore plays a woman who owns a small lunch wagon and falls for a duke’s son, played by Larry Kent, who is pretending to be his own chauffeur. With her savings, she pursues him to a resort hotel, only to be mistaken for a duchess.  Preserved by the Academy Film Archive in partnership with Národní filmový archív in 2007.', '/jwn1UG1U1c8FRwuCIv02ao4He2X.jpg', '1927-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14130, 'Prisoners', 468188, NULL, '/xLMXuAsvSeiu0x4Uyh1nsnJ01YU.jpg', 'Prisoners', 'Prisoners was released as a part-talking, part-silent feature.  An Austrian showgirl working in a cabaret moonlights as a thief. When she is caught in the act, a young lawyer offers to defend her. Unfortunately, he loses the case, causing her to spend several months in jail. Fortunately, the two have fallen in love, and he promises to wait for her.', '/6edibjdPaeftyXTWfw5WbyNOZmG.jpg', '1929-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
