INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14132, 'The Brass Bottle', 492670, NULL, '/wfQmiutAtNfG7IgytTkspZluvVN.jpg', 'The Brass Bottle', 'Horace Ventimore, a young London architect, stumbles across an old brass bottle. When he picks it up a genie suddenly appears and promises Horace that he will grant every wish Horace wants in exchange for his freedom. Horace accepts the genie''s offer but finds out that things aren''t working out quite as well as he thought they would.', '/nUNDhGzBZO8pViIHG2PGhevQL5e.jpg', '1923-07-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
