INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14134, 'Oh Kay!', 541259, NULL, '/8ZgLxUN8LM4NTUhMLTbrsdFDN0v.jpg', 'Oh Kay!', 'On the eve of her wedding Lady Kay Rutfield runs off aboard her sloop. A storm carries her out to sea and she is rescued by a passing rumrunner bound for the Long Island Sound. Once they arrive in the States, Kay makes her escape and hides in the deserted mansion of Jimmy Winter. Jimmy is due to marry the following day. He comes home to the mansion unexpectedly, and finds Kay, who persuades him to let her pose for a night as his wife.', '/53jkdpovCqNMv4lyp3Ky8CJG8Me.jpg', '1928-08-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
