INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14140, 'Miss Hobbs', 684303, NULL, '/gt3JM6fY8ez8l81b9ujgbm3xk5Y.jpg', 'Miss Hobbs', 'She was a very modern young woman, was Miss Hobbs. Her ideas were about fifty years ahead of time. For one thing she hated men, thought them all brutes. But love has a way of smashing such an idea. Then she went in for barefoot dancing, futurist art and other advanced notions. Well, the upshot of it was the young man took upon himself to tame her, to make her a regular girl.', '/4w2C2vf3TEPJcAAS2Wwr8R0kjNR.jpg', '1920-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
