INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14142, 'The Scarlet Empress', 31527, NULL, '/v1lSv9nNeuAC1rmc5pEdR8keUOJ.jpg', 'The Scarlet Empress', 'During the 18th century, German noblewoman Sophia Frederica, who would later become Catherine the Great, travels to Moscow to marry the dimwitted Grand Duke Peter, the heir to the Russian throne. Their arranged marriage proves to be loveless, and Catherine takes many lovers, including the handsome Count Alexei, and bears a son. When the unstable Peter eventually ascends to the throne, Catherine plots to oust him from power.', '/lCoyv38br7T4hFPJF0OnfAGuzbp.jpg', '1934-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
