INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14151, 'The Hollow Child', 433419, NULL, '/9JD5I9MH1ZNsDfDiLX7ZHkGRDjC.jpg', 'The Hollow Child', 'Samantha has lived her whole life in different foster homes. Now living in a small town, she never feels like she quite fits in, even with her own current foster family who might adopt her, or the boy who follows her around doing her classwork. So, it’s perhaps natural that she doesn’t know what to do with a curious tagalong little sister named Olivia. One day, Sam callously ditches Olivia, who wanders off into the woods on her own and disappears.', '/lHeNY6zvR9yA2JWF9FrIOldsc2j.jpg', '2018-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:41', 0);
