INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14163, 'Song One', 244783, NULL, '/AckDhp2FYTD9AbhpDCk6HyrjNc8.jpg', 'Song One', 'Estranged from her family, Franny returns home when an accident leaves her brother comatose. Retracing his life as an aspiring musician, she tracks down his favorite musician, James Forester. Against the backdrop of Brooklyn’s music scene, Franny and James develop an unexpected relationship and face the realities of their lives.', '/a6dSJIEMxZFvQ7XJy4sf9fR0p7f.jpg', '2014-01-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
