INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14168, '10 Mountains 10 Years', 873936, NULL, NULL, '10 Mountains 10 Years', 'Chronicling the worldwide epic created by mountain climber Enzo Simone. 10 Mountains 10 Years follows his international team of mountain climbers as they scale 10 of the greatest peaks in the world to raise awareness and funds for Alzheimer''s and Parkinson''s Disease. Focusing on Mt. Kilimanjaro, the film tracks the greatest advances happening in the medical community alongside the team''s endurance at altitude. This is a story of hope and of common everyday people coming together to change this world and leave something better behind. A collaboration with the Leeza Gibbons Memory Foundation and the Focus On a Cure Foundation for Parkinson''s, proceeds from the film go towards medical research and caregiver programs.', '/spyttjnvaiBKKBndNlB3ieznqSI.jpg', '2010-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14169, 'Ocean''s Team 3.0', 1036013, NULL, NULL, 'Ocean''s Team 3.0', 'Director Gary Ross and participants from the previous extras discuss the challenge of casting a film where group chemistry is even more important than the individual performances.', '/50fABqkc1IInSqQcXmDjYPBoFTf.jpg', '2018-09-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14170, 'Seesaw Monster', 1045911, NULL, NULL, 'Seesaw Monster', NULL, '/lqjQkTj2qIJIAtlGhR8uVLeAbTJ.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14171, 'Yesteryear', 1323678, NULL, NULL, 'Yesteryear', 'Natalie seems to have the perfect life: a beautiful farmhouse on a working ranch, a handsome cowboy husband, six children, and eight million social media followers who adore her curated lifestyle. Behind the scenes, however, it’s a well-oiled machine of nannies, producers, and industrial-grade kitchen appliances. But when Natalie wakes up in a life that isn’t hers — transported back to 1805 — everything changes. Her home is no longer pristine, her husband is now a hardworking farmer, and her children are dirty and unruly. With no clue how she got there, and pregnant with her new ''husband’s'' child, Natalie must navigate the harsh realities of her new life, and figure out how to escape it.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14172, 'Elmo''s Christmas Countdown', 310524, NULL, '/dPUQNkqRCnOKItRGGQ3ucR0PI0u.jpg', 'Elmo''s Christmas Countdown', 'There''s a miracle on Sesame Street in this special holiday tale. Elmo, Abby Cadabby, and their new friend Stiller the Elf are going to count down to Christmas with the Christmas Counter-Downer. But all the counting boxes have gone missing and Christmas may never come again!', '/c3IO54d3mbubQEMyvj0d35ioemt.jpg', '2007-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14173, 'Valentino: The Last Emperor', 22774, NULL, '/lwx7W2NBoRLZeBPHYzZd3Y1G3tp.jpg', 'Valentino: The Last Emperor', 'Film which travels inside the singular world of one of Italy''s most famous fashion designers, Valentino Garavani, documenting the colourful and dramatic closing act of his celebrated career and capturing the end of an era in global fashion.  However, at the heart of the film is a love story - the unique relationship between Valentino and his business partner and companion of 50 years, Giancarlo Giammetti. Capturing intimate moments in the lives of two of Italy''s richest and most famous men, the film lifts the curtain on the final act of a nearly 50-year reign at the top of the glamorous and fiercely competitive world of fashion. (Storyville)', '/aQP33BMBuRrDQwOTSdTVHvmOVnv.jpg', '2008-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
