INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14176, 'The Last Thing He Wanted', 505225, NULL, '/cGUxPXVZF5n5P09dnlhWC8bLVp7.jpg', 'The Last Thing He Wanted', 'At the turning point of the Iran-Contra affair, Elena McMahon, a fearless investigative journalist covering the 1984 US presidential campaign, puts herself in danger when she abandons her assigned task in order to fulfill the last wish of her ailing father, a mysterious man whose past activities she barely knows.', '/4mDbGqi8mloDdxkviq13SKCfuFH.jpg', '2020-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14177, 'Inside ''Interstellar''', 529107, NULL, '/z7JUwll8F1BSVc8NjVGelW87mcU.jpg', 'Inside ''Interstellar''', 'Cast and crew of Christopher Nolan''s "Interstellar" discuss project origins, the film''s imagery, ambitions, incorporating IMAX footage, the human element within the film, arm shooting locations outside of Calgary, the set construction and design, working with real corn, mechanical characters, including backstory, design, the blend of practical and digital effects in bringing them to life, the differences in the characters, the human performances behind the characters, the creative process behind the film''s music, Icelandic locations, vehicle interiors, the processes of simulating the absence of gravity, the crucial end-film visuals and influence and inspiration for future generations', '/xWA7Bbo9VeahPcKCFYiC7NZXNoV.jpg', '2015-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14178, 'Les Misérables: The History of the World''s Greatest Story', 196241, NULL, '/sWvFdUzqPyLIm7IwsIB5Ea8T7RU.jpg', 'Les Misérables: The History of the World''s Greatest Story', 'From Victor Hugo`s classic French novel of the nineteenth century to Tom Hooper`s award winning blockbuster, Les Misérables has undergone one of the most successful transitions from book to stage to screen. In this new documentary, the scintillating journey of Hugo`s universal story is traced from book to stage to screen with contributions from those who have starred in and helped to create the entertainment phenomenon which has captured a place in everyone`s hearts. Helmed by entertainment and celebrity journalist Neil Sean, this insightful documentary traces the events of the Paris insurrection in 1832 and features excerpts from the restored 1978 Les Misérables lm starring Anthony Perkins alongside interviews with Frances Ruffelle, Hugh Jackman, Nick Jonas, Tom Hooper, Alfie Boe, Amanda Seyfried, Sir Cameron Mackintosh and Anne Hathaway.', '/eHYrgtxcE6DFJQrZScmVx42p1wI.jpg', '2013-04-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14179, 'PoliWood', 56822, NULL, '/olwhfqemuW8gWRZ7vqPO6bNBg63.jpg', 'PoliWood', 'An in-depth look at the Democratic and Republican national conventions held during the 2008 U.S. Presidential election year.', '/GTiCRXPY9K8PY3gQChwOItixDS.jpg', '2009-07-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
