INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14183, 'French Children Don''t Throw Food', 688081, NULL, NULL, 'French Children Don''t Throw Food', 'An American journalist who moves to Paris for her husband''s job and raises a family there. As she tries to figure out how to balance her family and career — and battle the feelings that she is failing at both — she observes her French neighbors and friends to uncover the secrets behind parenting astonishingly well-behaved French children. She learns, however, that everyone, no matter how perfect they might appear, has their own problems.', '/vxmasHk5oW8f2P6ucNQiD2kOxaW.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14184, 'Sesame Street: Elmo''s Playdate', 693617, NULL, '/ixVNMfBNUYxcz11DDoFyzVWbq9U.jpg', 'Sesame Street: Elmo''s Playdate', 'Part of Sesame Workshop''s "Caring for Each Other" Initiative, Sesame Street: Elmo''s Playdate offers families a moment of joy and connection in challenging times.', '/iPgYAtcujldVjltuVJqrsdY5gvs.jpg', '2020-04-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14185, 'Ending the Knight', 703363, NULL, '/xogFZVEkGazbvx3NaZXK0SWauZi.jpg', 'Ending the Knight', 'A comprehensive look into how Director Christopher Nolan and his production team made "The Dark Knight Rises" the epic conclusion to the Dark Knight legend. These cover stunts and action, production/vehicle design, various effects, photography and shooting IMAX, sets and locations, sound design and music, story/character areas, cast and performances, and some general thoughts about the series.', '/8B5qQ1t9uw97a61oXnRV8u5Nmjf.jpg', '2012-12-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14186, 'The Happy Days of Garry Marshall', 705088, NULL, '/o5FCfPVjYiQzP2tgFmW5XJcViUa.jpg', 'The Happy Days of Garry Marshall', 'In a heartfelt tribute to Hollywood legend Garry Marshall, his family and friends share their favorite memories of the creative genius behind some of the most memorable series in television history.', '/sKPAaxa4LYuIC59LzpnrPUklS7j.jpg', '2020-05-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
