INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14188, 'Armageddon Time', 615952, NULL, '/pqCfTRzYzojsyHvKtS6mHfC7Wc7.jpg', 'Armageddon Time', 'In 1980, Queens, New York, a young Jewish boy befriends a rebellious African-American classmate to the disapproval of his privileged family and begins to reckon with growing up in a world of inequality and prejudice.', '/wMK717aDWhboXOiVbZ9sLBqLmKh.jpg', '2022-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14189, 'A Place in Time', 725409, NULL, NULL, 'A Place in Time', 'The film takes a look at the daily lives of people in more than two dozen countries around the world during the course of a week. In the film, celebrity friends of Jolie visit orphanages, refugee camps and other areas of concern in an effort to raise awareness and encourage cultural understanding. It is an experimental documentary that seeks to capture both the diversity of life around the globe and the similarities of the human spirit by filming in many places in the world at precisely the same moment.', '/jOmvPb4zEOOvDgTEXBcLwK5XOlm.jpg', '2007-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
