INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14197, 'Untitled FBI Wedding Sting Film', 1401726, NULL, NULL, 'Untitled FBI Wedding Sting Film', 'A mismatched partner of two undercover FBI agents with radically different styles is forced to pretend to cohabitate. Initially, they detest one another. By the end they learn to respect each other as the case winds to a close.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14198, 'Alone at Dawn', 1500229, NULL, NULL, 'Alone at Dawn', 'Following the true story of U.S. Air Force Combat Controller John Chapman and his fight to the death to save his fellow soldiers during the 2002 Battle of Takur Ghar in Afghanistan. Years later, an intelligence officer works to prove his valor, leading an investigation that would ultimately secure Chapman the Medal of Honor.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14199, 'An SNL Thanksgiving', 1587298, NULL, '/pxNsv663FJ2xd1LnzEIIKRS5Mn1.jpg', 'An SNL Thanksgiving', 'Hope you''ve got an appetite for a buffet of Thanksgiving-themed SNL sketches from the past 50 years, from musical tributes to commercial parodies to dinners that go horribly, hilariously wrong to cat adoption events filled with sexual tension. Don''t miss A Saturday Night Live Thanksgiving, which compiles two hours of the best SNL sketches about and inspired by the holiday.', '/xf9aejUaUvFPL1vPTQ1EccNN2kP.jpg', '2024-11-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
