INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14202, 'The Devil Wears Prada 2 Red Carpet World Premiere', 1673568, NULL, '/Af907x5h9W1wVis8XrSd7ynTWuy.jpg', 'The Devil Wears Prada 2 Red Carpet World Premiere', 'Get ready for couture, cameras, and cast moments as Disney+ and Hulu livestream the The Devil Wears Prada 2 world premiere from New York City’s Lincoln Center. Streaming live to subscribers worldwide, the event offers a rare, front‑row view as it unfolds in America’s fashion capital. From red carpet arrivals to behind‑the‑scenes interviews, it’s an inside look at one of the most glamorous nights of the year, and the perfect kickoff to the film’s theatrical debut.', '/grTJpqC5pfGfjWmrgBVvPHYMq5K.jpg', '2026-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14203, 'Get Smart''s Bruce and Lloyd Out of Control', 15531, NULL, '/fKhzA76gT3cl56XrQ5oSnFwZxJX.jpg', 'Get Smart''s Bruce and Lloyd Out of Control', 'Bumbling R&D inventors Bruce and Lloyd get out of the lab and into the field as they search to locate their latest invention - which has somehow gone missing. When you''re used to spending your day inventing the most cutting edge spy equipment known to man, adapting the stealth and guile needed to become a true secret agent doesn''t come naturally. Unfortunately the invisibility cloak that the pair recently collaborated on has disappeared, and in order to ensure that it doesn''t fall into the hands of KAOS they will have to master the skills of a true spy. But how exactly does one find an object that''s invisible to begin with? As the search gets underway, these brainy inventors are given an eye-opening crash course in high-level espionage.', '/trazfJKPyhC6PVSFnzHmegYzw4i.jpg', '2008-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14204, 'Angels in Exile', 1080614, NULL, NULL, 'Angels in Exile', 'Two homeless children attempt to escape the dangerous streets of Durban, South Africa.', '/Xw0N5dYxBQgdwcX4nc6RuUrI6c.jpg', '2016-05-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14205, 'The Life and Death of Peter Sellers', 10609, NULL, '/lD6JhXP1MGeRNdkdTpid1ClfiIS.jpg', 'The Life and Death of Peter Sellers', 'The turbulent personal and professional life of actor Peter Sellers (1925-1980), from his beginnings as a comic performer on BBC Radio to his huge success as one of the greatest film comedians of all time; an obsessive artist so dedicated to his work that neglected his loved ones and sacrificed part of his own personality to convincingly create that of his many memorable characters.', '/eZHnSd73L5v5FDZdBpGhQPLUZGW.jpg', '2004-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14206, 'Sweet November', 1921, NULL, '/6KfQTuw4X3LQN11sDA18eYy9HJY.jpg', 'Sweet November', 'Nelson is a man devoted to his advertising career in San Francisco. One day, while taking a driving test at the DMV, he meets Sara. She is very different from the other women in his life. Nelson causes her to miss out on taking the test and later that day she tracks him down. One thing leads to another and Nelson ends up living with her through a November that will change his life forever.', '/3biEHZSBSYqSkawU2sQyNbLcjgE.jpg', '2001-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14207, '15 Minutes', 2749, NULL, '/lxIpa7wIoeXw6hJksNHZnQ8kPVa.jpg', '15 Minutes', 'When Eastern European criminals Oleg and Emil come to New York City to pick up their share of a heist score, Oleg steals a video camera and starts filming their activities, both legal and illegal. When they learn how the American media circus can make a remorseless killer look like the victim and make them rich, they target media-savvy NYPD Homicide Detective Eddie Flemming and media-naive FDNY Fire Marshal Jordy Warsaw, the cops investigating their murder and torching of their former criminal partner, filming everything to sell to the local tabloid TV show "Top Story."', '/ycF4oMuaj9VPiQk8xXaN8LFhSbV.jpg', '2001-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14208, 'The Curse of the Jade Scorpion', 2779, NULL, '/vq4vYFV0TWCCovAFLcdZLCo4Qud.jpg', 'The Curse of the Jade Scorpion', 'CW Briggs is a veteran insurance investigator, with many successes. Betty Ann Fitzgerald is a new employee in the company he works for, with the task of reorganizing the office. They don''t like each other - or at least that''s what they think. During a night out with the rest of the office employees, they go to watch Voltan, a magician who secretly hypnotizes both of them.', '/mfvWefUp09oaLLxb8KhsvUYi7mX.jpg', '2001-08-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14209, 'The Astronaut''s Wife', 2900, NULL, '/c77Aq23NdM8UAzlH5GuniJBuCPd.jpg', 'The Astronaut''s Wife', 'When astronaut Spencer Armacost returns to Earth after a mission that nearly cost him his life, he decides to take a desk job in order to see his beautiful wife, Jillian, more often. Gradually, Jillian notices that Spencer''s personality seems to have changed, but her concerns fade when she discovers that she''s pregnant. As Jillian grows closer to becoming a mother, her suspicions about Spencer return. Why does it seem as if he''s a different person?', '/54RGJ6INW9ERG8IaalmMKbbDgwH.jpg', '1999-08-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14210, 'Waking Up in Reno', 21118, NULL, '/8Be8hMBJuBujQmYjwLxaaPEgne4.jpg', 'Waking Up in Reno', 'Candy and Lonnie Earl are just crazy about each other. The problem: she''s married to Roy and he''s married to Darlene. So far it''s been a secret affair. But that''s about to change, because this foursome is driving cross-country and headed for some big surprises.', '/wXLmDc7KoaXqglHsqgJ2Zh2YFRx.jpg', '2002-12-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14211, '2 Days in the Valley', 9401, NULL, '/7JmTlybgcuEH6uuOIOk96Bupj4Z.jpg', '2 Days in the Valley', 'In a sleepy bedroom community of LA''s San Fernando Valley, the murder of a professional athlete by two hit men sets into motion a chain of events that puts the mundane lives of a dozen residents on a collision course. This clever tale tells the story of two hit men, a mistress, a nurse, a vindictive ex-wife, a wealthy art dealer and his lovelorn assistant, a suicidal writer and his dog, and a bitter cop and his partner.', '/dKmOINYPpg2W8SMRicnFdusqk1x.jpg', '1996-09-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14212, 'Battle in Seattle', 13177, NULL, '/vLUqy3lVMvtdOMwa5ToIxlXa3cJ.jpg', 'Battle in Seattle', 'Thousands of activists arrive in Seattle, Washington in masses to protest the WTO Ministerial Conference of 1999 (World Trade Organization). Although it began as a peaceful protest with a goal of stopping the WTO talks, it escalated into a full-scale riot and eventually, a State of Emergency that pitted protesters against the Seattle Police Department and the National Guard.', '/jO8tKM4mCMXpLVd5GnmlfJByghF.jpg', '2007-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14213, 'Sleepwalking', 14349, NULL, '/gHZujwfeAgQtug2HPFyzWizcOu0.jpg', 'Sleepwalking', 'When her boyfriend is arrested for marijuana possession, Joleen Reedy and her 11-year-old daughter, Tara, take refuge with Joleen''s aimless brother, James. Joleen soon runs off with a truck driver, and James is unable to meet his responsibilities. After Child Protective Services takes possession of Tara, James abducts her from a foster home, and the two travel from California to Utah, where his abusive father lives.', '/sQ2YMtrzHBEVNW6fGwd45DzmHOG.jpg', '2008-03-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14214, 'Trial and Error', 17770, NULL, '/hqn2GTCYk1qbUKM0oVtkdPRsSlF.jpg', 'Trial and Error', 'When lawyer Charlie is sent to a small Nevada town to file a continuance request for a client, his actor friend Richard turns up to throw a surprise bachelor party celebrating his upcoming marriage to the boss''s daughter. When Charlie is too hung-over to make it to court for the hearing, Richard fills in, inadvertently committing felony fraud, and Charlie is left with no choice but to coach the clueless Richard through the whole trial.', '/menUTMx04eYe8EYKhJnGYA4gK6Q.jpg', '1997-05-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14215, 'Carol Burnett: 90 Years of Laughter + Love', 1111889, NULL, '/ndOa8B63Jh3pkbGDTF1gbw38gr2.jpg', 'Carol Burnett: 90 Years of Laughter + Love', 'Paying tribute to a beloved national icon for her birthday, NBC celebrates Carol Burnett’s illustrious career with a star-studded event featuring an A-list lineup of musical performances and special guests who come together to share their love for one of the most cherished comediennes in television history.', '/2MKglxLcNgKE7GFxWD7k3ZReOuQ.jpg', '2023-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14216, 'Head in the Clouds', 18804, NULL, '/30TFieICaZPeAggwGF9S5GQeoFa.jpg', 'Head in the Clouds', 'Gilda Bessé shares her Paris apartment with an Irish schoolteacher, Guy Malyon, and Mia, a refugee from Spain. As the world drifts toward war, Gilda defiantly pursues her hedonistic lifestyle and her burgeoning career as a photographer. But Guy and Mia feel impelled to join the fight against fascism, and the three friends are separated.', '/7hife90EykgFaJ6KPY1DX8y7DVD.jpg', '2004-04-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14217, 'Young Adult', 57157, NULL, '/wwcsaGDLBoYbPk5mBCaTIljLiCs.jpg', 'Young Adult', 'A divorced writer from the Midwest returns to her hometown to reconnect with an old flame, who''s now married with a family.', '/4tGMz5xUs9sk8X9B28G6UalHK1d.jpg', '2011-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
