INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14226, 'Nelson Mandela Redrawn', 373068, NULL, NULL, 'Nelson Mandela Redrawn', 'This fascinating documentary unfolds in reverse telling the story of Mandela from the old man to the rural child. With contributions from storytellers from every corner of the globe, we gain a unique insight into why Mandela was so loved and revered. Mandela''s unique way of handling the challenges of life range from his relationship with the British Royals and the attempted suicide of a South African rugby hero, to epic political strategies that clinched a World Cup, and single-handedly averted civil war. Beyond the media hype was the political genius who could manipulate the press, inspire awe in celebrities, politicians and superstars alike and managed to shape a country from inside a prison cell. For the first time, his genius as a political strategist is laid bare and we discover the seminal moments that transformed a man into a hero.', '/iYPAKMefwKa8wZIqTdi4YzQoC8o.jpg', '2014-07-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
