INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14233, 'Captured on Film: The True Story of Marion Davies', 334025, NULL, '/NBWcXW7mBh9GFkE4xnWyyWdhrn.jpg', 'Captured on Film: The True Story of Marion Davies', 'Blonde, beautiful and talented, Marion Davies was the first and funniest screwball comedienne. As star of two of the best comedies ever made, Show People and The Patsy, she combined zany slapstick and exuberant mimicry. Glamorous, witty and kind, both on screen and off, Davies was also famous for her 35-year-long love affair with William Randolph Hearst.', '/5GZx21fr5JRNtJ09jV9nMHcTldg.jpg', '2001-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
