INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14238, 'It’s a Mad Max World', 1504199, NULL, '/4RbRlbD7sxFjkJGEXOBNj0pFpE0.jpg', 'L''apocalypse selon Mad Max', 'Emerging from the depths of the film industry, the Mad Max saga became an instant cult classic after the release of the first film in 1979. These five critically acclaimed films have continued to captivate audiences. They shaped the identity of Australian cinema, launched a movie star – Mel Gibson – and propelled George Miller as one of the greatest directors of his generation. Above all, Mad Max has left an indelible mark on our collective unconscious, redefining our vision of the apocalypse and human civilization. This documentary tells the story of this phenomenon, from the small production of the first film to the monumental later installments, drawing on interviews and rare archives.', '/aL6JGWMt0Op6OLSS1TZJZVmhJNf.jpg', '2025-06-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:42', 0);
