INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14241, 'Schoolmistress 4', 877221, NULL, '/qjauZVPlB3IbID9Uylq1oCgcdbw.jpg', '여선생 4', 'Min-woo solves his sexual partner Yu-ri''s financial troubles, and Sam-su-ha hires Yu-ri as Min-seok''s tutor on the condition that he keeps his relationship a secret from Min-seok for the sake of his younger brother Min-seok''s math grades.  Min-seok gets excited when Yuri, who looks sexy his age, starts tutoring him, and he dreams of having sex that night.  Meanwhile, Yuri doubts that Min-woo is dating another woman, but when she learns her door code while attending tutoring, she sneaks into Min-woo''s room late at night to confirm. Yuri, delighted to see Min-woo sleeping in her room without having an affair, wakes up sleeping Min-woo and gives her a special service.', '/eaGJkVVSKaR1hquJ2MXH7muqohj.jpg', '2021-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14242, 'New Female Employee', 884053, NULL, '/90R6Ya7TMNWBwVq03tsouRCENzA.jpg', '신입 여사원', 'Na-young, a job-seeking student, receives a letter of acceptance from a venture company, Log M, and calls for joy. Bonus 400%! Even the friendly smile of CEO Hoonnam. The only job assigned to Na-young is managing the power of the company server or making coffee. Na-young, a new employee who did not want to lose the good fortune that had come so much, became a member of the company by enduring the sexual harassment of the lesbian team leader Mi-ran. She appeals to her sexy side and follows her to the reception desk for success... What is the true identity of Jun-seo, a young venture capitalist, and the shocking identity of Rogue M?', '/p4skRsi88kiI5qiziJ9KzOxT8sW.jpg', '2020-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14243, 'Suspicious Massage Shop', 1106320, NULL, '/h3tJQ1Zox75JcDG0YwaPx9Bzbtl.jpg', '수상한마사지샵', 'Unlimited service until the body and mind of female customers are satisfied! Special service for women opened~ Bong-seok, who runs a massage shop, is worried because his business is not going well. Employee Hae-soo proposes to change the business to a harmful female-only massage shop in Gangnam, but when they change to a female-only massage shop and promote it, female customers begin to come by word of mouth. Bong-seok and Hae-soo work together to secure regular customers and increase sales. We provide a special service that will heal the village, but female customers Sora and Seongae, who are satisfied with the special service, continue to come as regulars, and Bongseok’s massage shop spreads rumors around and makes a lot of money every day. Seok’s body and mind are getting more and more exhausted… Will the special service, a popular menu item at Bongseok’s massage shop, continue to gain popularity?​', '/7Vo6mZdAUWhUo6SUH9R5J3k0lQh.jpg', '2021-11-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
