INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14245, 'Madam''s Golf Lesson', 934246, NULL, '/65JoGLRe6kbYUegGf6QyOt5mjpb.jpg', '사모님 골프 개인교습', 'Ahn-ha Moo-in''s chaebol wife, Mi-yeong, changed her housekeeper and golf teacher. Mi-yeong''s golf instructor, Dong-won, feels sorry for the new maid Ok-jeong who is working at Mi-yeong''s house, and offers to get revenge on Mi-yeong. Even Mi-yeong''s husband, Il-ryong, who cares more about kind Ok-jeong. What will happen to Mi-yeong and Ok-jeong?', '/vaNB68cS06sOour5wfIu9YhiJvY.jpg', '2021-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14246, 'Blood Type B, Wet and Hot Sister-in-law', 854662, NULL, NULL, 'B형 물 많고 화끈한 처제', 'Min Soo''s younger brother Kyung Soo says he goes to sleep at Min Soo and Young Hee''s house as usual. Due to Young Hee who is busy on business trip and Min Soo who went out for work Kyung Soo while being in the house alone suddenly meets Young Hee''s younger sister Ga Hee, who suggests having a beer to resolve the awkward situation between the two of them. Ga Hee, who was drinking beer with Kyung Soo, gets drunk and somehow has sex with Kyung Soo. In fact, Ga Hee came when Min Soo was alone to seduce her brother-in-law.', '/mpg2Rsht6kFa5UwNDqLpl2n3RFf.jpg', '2020-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14247, 'Dangerous Younger Cousin', 938086, NULL, '/mG6idJ78OCxdqn3AccqqeuJ9Nph.jpg', '위험한 사촌동생', 'Hyang-gi hates her mother who only likes men and doesn''t take care of herself. She brings a man to her house to sleep over so her mom will find her crooked. To correct Hyang-gi, she asked Do-hwan, Hyang-gi’s cousin, to live with her at home for a while. Hyang-gi and Do-hwan, who were reunited as adults, grew very attracted to each other. Chae-kyeong, Do-hwan''s girlfriend, finds out about it. After revealing the truth in front of everyone, Hyang-gi and Do-hwan are on the verge of breaking up.', '/pwdWFhhdfzNFCUnlZsiz2MfWv37.jpg', '2021-11-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14248, 'Advanced Prostitute', 829959, NULL, NULL, '고급창녀', 'Yeon-su had a hard time getting into music school, but she has to continue her college life alone and work part-time, so she can''t continue her studies properly. A performance in a short skirt, determined to give up to the professor in charge. But a professor in charge is not blinking an eye. Having lost hope, Yeon-ju tries to give up her life, but dreams of an elegant life due to the sudden luck.', '/4s5C9ssz5m5o9TT3PFalfuJEsfC.jpg', '2021-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
