INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14298, 'Pakshikalkk Parayanullath', 1150273, NULL, NULL, 'പക്ഷികള്‍ക്ക് പറയാനുളളത്', 'Meenakshi a thirteen-year-old girl, her father Mohamed Jahan and her mother Indulekha who live in there marooned worlds. Jahan is a taxidermist. He tries to freeze the flight of birds, reflecting his view of life affecting relationships. His world is like a box of eerie memories frozen in taxi -dermal mounts, glass jars and bead eyes. Indulekha, who had an emotional paralytic stroke, is bedridden. Life goes on disconnected in the huge ancestral house of dark shades. Fighting the forced solitude, the teenager created a magical world of happiness around her. On a fateful day, confused and drunk, Jahan during his usual charade of expressing his unrequited love towards Indulekha mistakenly advances towards Meenakshi. That dark act throws the splintered lives into a moral vortex. It takes her to an abysmal plunge to loss of her pictorial passion of life.', NULL, '2020-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:43', 0);
