INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14305, 'Vivement Truffaut', 4033, NULL, NULL, 'Vivement Truffaut', 'A tribute to the late, great French director Francois Truffaut, this documentary was undoubtedly named after his last movie, Vivement Dimanche!, released in 1983. Included in this overview of Truffaut''s contribution to filmmaking are clips from 14 of his movies arranged according to the themes he favored. These include childhood, literature, the cinema itself, romance, marriage, and death.', '/aWYe58XwzNe45p1qRjEhGHbAbou.jpg', '1985-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
