INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14309, 'An Old Fashioned Thanksgiving', 24364, NULL, '/yTRBLtdNko7kdZe8l5ZHTUIZN1O.jpg', 'An Old Fashioned Thanksgiving', 'Recently widowed Mary Bassett and her three children have hit difficult times on their farm. Suddenly, Mary’s wealthy and estranged mother Isabella comes to visit upon receiving a devious letter from the eldest daughter. Mary resents her mother’s attempts to help them out of their financial difficulties. In the end, more than money will be needed to heal deep wounds and rampant scarlet fever.', '/t6TU4fKsJs5bxnpSNUKEZQUGmKl.jpg', '2008-11-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
