INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14311, 'Save the Last Dance 2', 9817, NULL, '/9GIxfO9LDxEYfxUfFvBt38PMeT2.jpg', 'Save the Last Dance 2', 'Sara joins Julliard in New York to fulfill her and her mother''s dream of becoming the Prima ballerina of the school. She befriends her roommates, Zoe and Miles, who teach hip-hop classes. She has ballet classes with the rigid and famous Monique Delacroix that she idolizes - Monique requires full commitment, discipline and hard work from her students. When Miles, who is a composer, invites Sara to help him compose the music for the dance choreography Sara''s passion for hip-hop is sparked and she also falls in love with Miles. When she is assigned to perform Giselle in an important event, she feels divided between the technique of the ballet and the creative work offered by Miles.', '/wc9Ymn4p7hdjZdKwgtfGGlStFTV.jpg', '2006-10-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14312, 'The Mephisto Waltz', 40158, NULL, '/tM2iPPkWHEJDjx1ox4xxCzHpK3K.jpg', 'The Mephisto Waltz', 'A frustrated pianist himself, music journalist Myles Clarkson is thrilled to interview virtuoso Duncan Ely. Duncan, however, is terminally ill and not much interested in Myles until noticing that Myles'' hands are ideally suited for piano. Suddenly, he can''t get enough of his new friend, and Myles'' wife, Paula, becomes suspicious of Duncan''s intentions. Her suspicions grow when Duncan dies and Myles mysteriously becomes a virtuoso overnight.', '/h2zyPibxcUtvcL9Fxxsh1RRkW49.jpg', '1971-04-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14313, 'Who Is Killing the Great Chefs of Europe?', 42216, NULL, '/pxguvoO28L6VGNZ5NgpPZA6WLNo.jpg', 'Who Is Killing the Great Chefs of Europe?', 'Mystery abounds when it is discovered that, one by one, the greatest chefs in Europe are being killed. The intriguing part of the murders is that each chef is killed in the same manner that their own special dish is prepared in. Food critics and the (many) self-proclaimed greatest chefs in Europe demand the mystery be solved.', '/N98Pdb4hdNqZsYO5bBXXb897RS.jpg', '1978-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
