INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14315, 'The Knack... and How to Get It', 42744, NULL, '/8Rf6qaHRZkq0tN5wd4xh8ezSJa8.jpg', 'The Knack... and How to Get It', 'A nebbish schoolteacher begs his smooth (and misogynistic) pal to teach him ''the knack'' – how to score with women. Serendipitously, the men meet up with a new girl in town, as well as a friendly lunatic who can’t help but paint things white.', '/xO2dJcCISY6lujaU4Qew3RzSErJ.jpg', '1965-06-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
