INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14318, 'The Fine Art of Love: Mine Ha-Ha', 61950, NULL, '/drdr5FaY6JTviWF2qup5QHZRYV8.jpg', 'The Fine Art of Love: Mine Ha-Ha', 'A group of young girls are brought up in a college within dark forests and gloomy lakes. Young Hidalla and her friends Irene, Vera, Blanka, Melusine and Rain are brought up in an isolated world: the girls don''t know anything about live outside the college''s high walls. At the age of 16, some of them start asking questions about their origins, their parents and the true purposes of the Headmistresses strict rules. When two of them disappear mysteriously, the initial fairytale atmosphere grows more and more eerie...', '/ks5PovbKHXukfaUNGSNmGNKorRo.jpg', '2005-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
