INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14320, 'Belmondo, il était une fois le beau monde', 918640, NULL, '/qqyZlQpaS5sNsypIIxUm2G0VWkk.jpg', 'Belmondo, il était une fois le beau monde', 'A profile of Jean-Paul Belmondo by his peers. Besides appearing in over eighty films, the actor also delighted audiences with his dangerous stunts, his laughter, his jokes, and his refreshing ease and impertinence. Cultivating the art of the counterpunch, he spanned half a century of French cinema.', '/cW8ZtgvmxM1I2n5sAZENnexiXPv.jpg', '2011-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
