INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14324, 'End of the Game', 72494, NULL, '/8GzX5egahS7tdo7gjIUROtRQFt9.jpg', 'Der Richter und sein Henker', 'Hans Baerlach is a Swiss police detective who has dedicated much of his career to pursuing powerful and allegedly murderous businessman Richard Gastmann. Though Baerlach''s partner meets his demise while investigating Gastmann, his replacement, Walter Tschanz, is undaunted. Meanwhile, the lovely Anna Crawley becomes involved in the case, which proceeds to take many twists and turns.', '/aq5SwVQ37piQwRYVLBr1lARa4cR.jpg', '1978-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14325, 'The Thief Who Came to Dinner', 92299, NULL, '/qfvCotaLIdme6DBWAhDSAnupFz8.jpg', 'The Thief Who Came to Dinner', 'A computer programmer decides to become a thief. And when he starts making waves, an insurance investigator hounds him. He also meets a woman who becomes his accomplice.', '/2sopwAOdBOzrQ5kcBdZrC1Y9FnS.jpg', '1973-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
