INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14327, 'Let the Devil Wear Black', 57679, NULL, '/vDE07ea5Nhr7YlJD9bgDQyidg6K.jpg', 'Let the Devil Wear Black', 'A man comes face-to-face with personal treachery after suspecting that his father may have been murdered.', '/sWasEjoBfAFF9hgw5RLBsTmcBAy.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14328, 'The Sunday Woman', 57310, NULL, '/54upLqnMOkkmsh8KC1WirJrar0B.jpg', 'La donna della domenica', 'Police commissioner Santamaria is investigating the murder of the ambiguous architect Mr. Garrone. The investigations soon drive him into the Torino''s high society. Santamaria suspect Anna Carla and at the same time falls in love for her. Lello is the lover of Massimo, Anna Carla’s gay friend. He is following another direction in order to find out the truth, and his results are confusing the Policeman. But another murder happens...', '/jb2Ocf9vNJUoM4JoISUIkxtGEDK.jpg', '1975-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14329, 'The Survivors Club', 95745, NULL, NULL, 'The Survivors Club', 'After being raped by a serial killer, Jillian Hayes, Carol Rosen and Meg Pesaturo found "The Survivors Club", and they use the press to force the police and justice to arrest the rapist. Eddie Como is arrested, based on DNA evidences, and while going to court for trial, he is murdered by a sniper and the three women switch position from victims to suspects. Detective Roan Griffin, who is traumatized by the brutal murder of his beloved wife by the manipulative killer David Price, joins the investigation with detective Fitz Fitzpatrick trying to solve the case.', '/bFv1Ysq7pikxrV0wfR1mkqQzdUj.jpg', '2004-03-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14330, 'Britannic', 59709, NULL, '/KlYRORotYilG7XL2kPsHImDeBO.jpg', 'Britannic', 'It was the sister ship of the infamous Titanic... and its final destiny was the same. Experience the true untold story of Britannic, a tumultuous, epic voyage of human passion, courage and betrayal aboard an ill-fated ocean liner bound for a shattering demise. With the world at war, an undercover British agent (Amanda Ryan), embarks the Britannic in search of a German spy believed to be on board to sabotage the ship. Posing as a governess, the undercover agent finds herself falling in love with the ship''s chaplain (Edward Atterton). In a stunning discovery, the lovers suddenly find themselves enemies of war. And when a massive explosion deals a deathblow to the ship, their battle becomes one for their own survival. With a dynamic, international cast and a story line that hosts a chilling tale of espionage, politics and romance, Britannic brings one of history''s most devastating events to riveting, new life.', '/dzjEdjrRNAe6gIYcQFm0lKAby6Q.jpg', '2000-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14331, 'The First Time', 86767, NULL, '/4xKbjYeSOVI2rxYehFhmKllv42a.jpg', 'The First Time', 'With the coming of summer, three high school buddies--Kenny Leeds, Mike Decker, and Tommy Kingsley--anticipate their initiation into the pleasures of manhood. But Kenny is separated from his friends and sent to stay with his grandparents in Buffalo while his father, a widowed salesman, leaves on a business trip with his secretary-fiancée. Bored and alone in a strange city, Kenny writes his two friends letters about his adventures at "Rosie''s," a fictitious brothel across the Canadian border in Niagara Falls. His lie quickly backfires.', '/9xWaCHJxxcJnYE2khi5yuPvvvT9.jpg', '1969-06-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14332, 'Swing', 58912, NULL, NULL, 'Swing', 'Anthony is caught between dreams of being a musician and pleasing his father and fiance. Encouraged by his great uncle, Anthony finds inspiration from a mysterious older woman in an other worldly night club, who teaches him to find happiness through swing dancing.', '/7NL9xAmDhJHr7b9Kkl8uG7XTiUb.jpg', '2003-10-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14333, 'Believe in Me', 86948, NULL, NULL, 'Believe in Me', 'Remy is a medical student who has a flair for making his patients comfortable. His genuine concern for the patients in his charge marks him as a hot prospect in his internship program. Pamela works at a children''s book publishing company. The two meet via Pamela''s brother, who is also Remy''s good friend. They fall in love and get an apartment in the East Village of New York. Soon after, the couple begins to indulge in speed and barbiturates. They become heavily addicted. Remy is thrown out of medical school and Pamela quits her job. Remy soon finds himself in debt with the local dealer, Stutter, who introduces his customer to heroin as a revenge for his late bill. Pamela faces the prospect of getting sober at her brother''s clinic, but must leave behind a destitute Remy in order to do it.', '/o0wAn3fSrjykk2OPX6fWpgS2jhK.jpg', '1971-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14334, 'Sex & Mrs. X', 87309, NULL, NULL, 'Sex & Mrs. X', 'Joanna is a woman secure in the knowledge of who she is: a perfect wife, a successful magazine journalist and a woman who''s just celebrated her 10th wedding anniversary with her husband, Dale. But when Dale suddenly leaves her for another woman, Joanna''s world collapses. Her self-esteem shattered, Joanna questions her attractiveness as a woman and her value as a human being. How did this happen to her? Follow Joanna as she escapes to Paris and learns the many secrets of seduction under the tutelage of Madame Simone. Slowly, empowered by her newfound knowledge and self-confidence, Joanna comes to understand her true self-worth.', '/4CdjW5LuZwe5jgIUPKVNFN1hTXA.jpg', '2000-04-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14335, 'The Maid', 100080, NULL, '/6Ag7ApojKZOwwauL5TMt2132gB1.jpg', 'The Maid', 'A man goes off to Paris to start his new job at a bank. When he falls in love with a beautiful woman, he decides to work as her maid -- until he discovers she not only is his boss, but his colleague at the bank.', '/vjLtYULEUDKzfEQZ4HbAHjPLiC1.jpg', '1991-08-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14336, 'Nick Nolte: No Exit', 104156, NULL, '/xDybJmLWILGEztrq5y6oLr3XDsy.jpg', 'Nick Nolte: No Exit', 'A frank and unconventional view of the life and work of actor Nick Nolte.', '/sXVK9zH0f36q38LkotBqLOwCBaa.jpg', '2008-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14337, 'High Season', 121893, NULL, '/bZfdj1do9tYdKLFPj8jysaAK2tC.jpg', 'High Season', 'On the isle of Rhodes, Katherine, an expatriate English photographer, lives with her daughter. A young local wants to encourage tourism, so he commissions a sculpture of the Unknown Tourist for the town square; the sculptor he brings to Rhodes is Kate''s ex-husband. Also there to see Kate is Sharp, an aging antiquarian and her dear friend. He has something important to tell her. As Kate, her ex, and Sharp sort out things that go back years, two English tourists bumble about, one thinking he''s fallen in love with Kate, his wife thinking she''s found her own lover. A rare vase, a spy, old friendships, the statue''s unveiling, and off-hand English sorting-out play into the resolution.', '/b3KqJglV3ADqJ6WrmOTFiqaB7j.jpg', '1987-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14338, 'Loren & Rose', 946112, NULL, '/yqMcA2DRgnVd81q5IdXd2d7pSn7.jpg', 'Loren & Rose', 'The appetizer is an introduction, the dessert is a farewell in this story of an indelible bond forged between a promising young filmmaker and an iconic actress.', '/u0cQOMFyK9IZoQMWAXRGTZbiu1s.jpg', '2022-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
