INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14347, 'Rossini! Rossini!', 191306, NULL, '/psd3Fh7MeXe1tfxoVW5FdfoU53F.jpg', 'Rossini! Rossini!', 'An funny, witty and bright biopic by the master of italian comedy Mario Monicelli about the famed italian composer Gioacchino Rossini, here portrayed in a wonderful way by famed actor and later director Sergio Castellitto.', '/wz22pjZGEyQS3EWV5OmTFHS90Ki.jpg', '1991-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14348, '2 Jacks', 191698, NULL, '/udP7rKbmRln0TYeaL49y2EcOByM.jpg', '2 Jacks', 'Jack Hussar is a legendary Hollywood director, whose persona commands respect and adoration from his fans. Can his son, Jack Jr. maintain his legacy?', '/zC4pmYNBjSu9aO5ErJyGtjSGcT9.jpg', '2012-08-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14349, 'East & West: Paradises Lost', 570584, NULL, NULL, 'Est et Ouest, les paradis perdus', 'In this quasi-semi-documentary, a Russian angel leads viewers in a quest to discover what, if anything, remains of the great, utopian "American Dream" now that the so-called "Worker''s Paradise" dream of Russia has passed completely into oblivion. Along the way, real celebrities and working members the film community in Hollywood are interviewed, and a number of "types" are impersonated by actors. Some of the celebrities interviewed include Jacqueline Bisset, Zsa Zsa Gabor, and screenwriter Jonathan Lawton (the Pretty Woman script writer).', '/8UcowMCIHHrUXDTRxjbfA7H6vVk.jpg', '1993-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14350, 'Together?', 194801, NULL, NULL, 'Amo non amo', 'Louise has left her husband, launched a career as a dress designer, and together with her son moved in with Giovanni, a lawyer. Despite the emancipated exterior, she still encounters the same problems — a son who demands her attention, a dominating lover, and jealousy.', '/1YioHc609e58r5PurKQtFhJ3BaP.jpg', '1979-12-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14351, 'Welcome to New York', 197696, NULL, '/xRa23mJjSidsGtz9JpxKtQK4hhu.jpg', 'Welcome to New York', 'Mr. Devereaux is a powerful man. A man who handles billions of dollars every day. A man who controls the economic fate of nations. A man driven by a frenzied and unbridled sexual hunger. A man who dreamed of saving the world and who cannot save himself. A terrified man. A lost man.', '/wxpCdLp3SHUDBQ0xOeZDuDnFxYm.jpg', '2014-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14352, 'Secret World', 211816, NULL, '/gVAZVPwhRKYQvj4j2MWjBzurf7h.jpg', 'La Promesse', 'Wendy is the British guest of a French couple and the daughter of the man who saved the host''s life during World War II. Living with the couple is their 20-year-old son and a 12-year-old nephew whose parents were killed in an automobile accident. The father and son both try to seduce the attractive guest. The young boy retreats into his own world and dreams of being taken back to Britain by Wendy in this romantic drama. The mother spends her time bleaching her hair and is seemingly uninterested in anything that goes on with her family at the beachfront villa. Meanwhile, Wendy and the younger boy develop a fondness for each other, while his aunt and uncle fail to understand his needs.', '/bUCYfcFfQFFWDubWwlZymPUBwVV.jpg', '1969-07-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14353, 'Anna Karenina', 220343, NULL, '/yKtCtFKrWqldiYp7fOhzcWShx3i.jpg', 'Anna Karenina', 'In Imperial Russia, Anna, wife of the officer Karenin, goes to Moscow to visit her brother. On the way, she meets charming cavalry officer Vronsky, to whom she''s immediately attracted. But in St. Petersburg’s high society, a relationship like this could destroy a woman’s reputation.', '/tYFtgpDmf38flrI5lTT4SLtNwKr.jpg', '1985-03-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14354, 'End of Summer', 250613, NULL, NULL, 'End of Summer', 'An unmarried aristocrat (Jacqueline Bisset) resists the advances of the adventurous man (Peter Weller) whom she actually desires, causing him to turn his attentions to her new ward (Amy Locane) and a young maid (Karen Dwyer).', '/qD0dmJjDIIPcb4iX9hd09nL48b4.jpg', '1997-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14355, 'Secrets', 223150, NULL, '/sPkXsKhjDdmAWuQiHZAYTGN6vnd.jpg', 'Secrets', 'A woman''s unfulfilling marriage leads her into a passionate affair with a wealthy extramarital lover.', '/uXspJS7sXWRl8NYGgYzqm1BCOH.jpg', '1971-09-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14356, 'The House of Jade', 239492, NULL, '/jL5nAaKzxVqqsBNXvKowf12e0oj.jpg', 'La Maison de Jade', 'During a ceremony in an orthodox church in Paris, a 40-year-old writer and journalist is seduced by a young man, whom with she will live an extraordinary story of love and passion that will drive them to madness.', '/gSXjQrYD0o2G0qmwtyDElcKenz3.jpg', '1988-11-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14357, 'Rosamunde Pilcher: September', 219894, NULL, '/ndHUDvNi8Dk7Q1nexVLU2TlUDqy.jpg', 'Rosamunde Pilcher: September', 'Verena Steynton is holding a party for her daughter. All the aristocratic families of Strathcroy in the Scottish Highlands are attending, with all their guilty secrets...', '/eRGUoiGryKx2E2BfPs32dT5pVjn.jpg', '1996-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14358, 'Observations Under the Volcano', 992841, NULL, NULL, 'Observations Under the Volcano', 'Documentary on the making of the movie Under the Volcano.', '/4MqAnjsh1tJZ7WSScoMUxkce2hq.jpg', '1984-07-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14359, 'New Year''s Day', 262914, NULL, NULL, 'New Year''s Day', 'Two 17-year-old boys mark the new year by doing twelve dangerous but exciting tasks set for them by their friends.', '/gjnsEaJKL2zcjISaUOxJMXM8QTQ.jpg', '2001-11-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14360, 'Once You Meet a Stranger', 264769, NULL, NULL, 'Once You Meet a Stranger', 'This television remake of Alfred Hitchcock''s "Strangers on a Train" (1951) follows the same story, but has changed the genders of the lead characters from male to female. Sheila Gaines is a former child star whose first husband is unwilling to give her a divorce. A chance meeting with Margo Anthony on a train leads to a conversation where the mentally unstable Margo, who hates her mother, suggests that they swap murders, so as to solve their problems. Although she thinks nothing of the conversation, Sheila''s life takes a surprising turn when her husband is murdered by Margo. Now Margo wants Sheila to do her part of "the deal." With the police on her tail and Margo constantly in her face, Sheila must find a way out of this tangled web.', '/uZwa0Ye52VwUmgSS45H9k2uMAL9.jpg', '1996-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14361, 'The Sweet Ride', 280134, NULL, NULL, 'The Sweet Ride', 'AA tennis bum (Tony Franciosa) and his Malibu Beach buddies hang out with a TV actress (Jacqueline Bisset) headed for trouble.', '/ak2RTfCXsKyPZ7kV6KGDZ9G3iM9.jpg', '1968-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14362, 'Mary Woronov: Cult Queen', 1212210, NULL, NULL, 'Mary Woronov: Cult Queen', 'The documentary explores the enigma of actress and artist Mary Woronov and chronicles her colorful career trajectory as a ground breaking female performer starting from her work with Andy Warhol to Roger Corman, that sealed her reputation as a "Cult Queen".', '/1PZZBTd2kgVl8vwBgLdH8sCHVWG.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14363, 'Witch Hunt', 268788, NULL, NULL, 'Witch Hunt', 'An infant girl named Hannah is abducted by her grandmother Barbara Thomas. Hannah''s father David Overton, convinced that Barbara is the head of a coven of witches, inaugurates a desperate nationwide search for his missing daughter. However, David may have a sinister agenda of his own, as indicated by the fact that his wife recently died under mysterious circumstances.', '/pq98iZgCqq8gMiamWqdeAFQlBkI.jpg', '1999-05-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14364, 'Notes from Under the Volcano', 420654, NULL, NULL, 'Notes from Under the Volcano', 'A behind-the-scenes documentary on the making of John Huston''s "Under the Volcano" (1984).', '/h68sVzqYTwPKGlHxVRbAbF4uxWn.jpg', '1984-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14365, 'Choices', 329221, NULL, NULL, 'Choices', 'A 19 year old girl suddenly finds herself pregnant. Not wanting to face motherhood or dealing with the consequences of a child, she contemplates an abortion without the knowledge of her boyfriend. However, her father, a retired 62 year old judge discovers her situation and is strongly opposed to abortion in principle. However, he soon finds he has to re-examine his own beliefs as his younger 38 year old second wife suddenly announces she is also pregnant. The two, when first married, agreed that there would be no additional children. This accidental pregnancy is unacceptable to the older man who cannot see him being involved in a young child''s life. In the end, all three must make choices.', '/pGEtbtbdw55grfCRDfASLHJ0FHH.jpg', '1986-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14366, 'People Who Love Each Other', 329716, NULL, '/3ljlh9VMfIZWC8qH5SjE8nuMnDJ.jpg', 'Les gens qui s''aiment', 'Jean-Francois and Angie have known each other for 25 years and have been lovers on and off for most of that time. After two marriages (one ending in divorce, the other with her husband''s death) and two children, the free-spirited Angie has returned to Jean-Francois, only to announce after a year of living together that she''s leaving him to open a antique business in the United States. Jean-Francois regrets Angie''s decision, but also knows her well enough to know there''s little he can do to change her mind. Five years later, Jean-Francois has become friends with Angie''s daughter Winnie, who now lives in Paris and has fallen in love with Laurent, a carefree artist who lives in a studio given to him by his father. However, after sleeping with Laurent, Winnie is convinced he can''t be trusted and keeps him at a distance. Over the next few years, Laurent keeps running into Winnie, and Angie periodically arrives at Jean-Francois'' doorstep only to leave again shortly after.', '/7KktC2fPmDFOiPUSF2W8HHhZgmC.jpg', '2000-07-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14367, '''Bullitt'': Steve McQueen''s Commitment to Reality', 331248, NULL, NULL, '''Bullitt'': Steve McQueen''s Commitment to Reality', 'A behind the scenes look at the making of the movie Bullitt with a strong focus on the attention to details taken. It features some of the preparations made before shooting began, but is mostly focused on the onsite filming locations which brings a strong amount of reality to the film as the title suggests.', '/aEcqkVlYl5nIJ9neXpDFe6SfXCb.jpg', '1998-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14368, 'CrimeBroker', 288277, NULL, '/dyCimm2Le2AaGU7CMSSSKwoFfGd.jpg', 'CrimeBroker', 'High court judge Holly McPhee devises blueprints for criminal operations and offers them for sale to the crime world. Her scrupulous operation falls apart when she takes part in a multi-million dollar  bank robbery and becomes an accessory to murder.', '/fZH0ufXkBTUWhZZUWk8p5W0HhQ7.jpg', '1993-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14369, 'Night of 100 Stars II', 830514, NULL, NULL, 'Night of 100 Stars II', 'This special is the second "Night of 100 Stars" to benefit The Actors Fund of America. Edited from a seven-hour live entertainment marathon that was taped February 17, 1985, at New York''s Radio City Music Hall, this sequel to the 1982 "Night of 100 Stars" special features 288 celebrities.', '/mQtYzJUViK66XTKJki3CQf5sRKj.jpg', '1985-03-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14370, 'Cezanne in Provence', 276941, NULL, NULL, 'Cezanne in Provence', 'Explore the life and art of post-impressionist painter Paul Cézanne in this PBS documentary shot on location in Provence, France, and at Washington, D.C.''s National Gallery of Art. Art critics and historians examine the influence of the French landscape on Cézanne''s work. Visit some of the sites depicted in his works, such as Montagne Sainte-Victoire and Atelier des Lauves, and marvel at his masterful use of light, color and perspective.  Narrated by Jacqueline Bisset.', '/u3n7lEdj6YnnQvCxGMQbOOvmZI1.jpg', '2006-07-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14371, 'Fascination', 71547, NULL, '/2jwJtiw4lZ55iPftK6Opy1kUNoK.jpg', 'Fascination', 'Young Scott Doherty (Adam Garcia) gets suspicious when his mother (Jacqueline Bisset) plans to wed Oliver Vance (Stuart Wilson) soon after her husband''s untimely death. Scott investigates with Oliver''s pretty daughter, Kelly (Alice Evans), who shared Scott''s doubts about the upcoming nuptials. Along the way, he falls in love with Kelly, but a fatal explosion turns Scott''s life upside down - and the evidence points to him as the murderer. Has he been framed?', '/h9IsB1pv6U7H4bEUiKG92VXlNrn.jpg', '2004-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14372, 'Александр Годунов. Побег за смертью', 1277652, NULL, NULL, 'Александр Годунов. Побег за смертью', NULL, NULL, '2023-06-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14373, 'America''s Prince: The John F. Kennedy Jr. Story', 278967, NULL, NULL, 'America''s Prince: The John F. Kennedy Jr. Story', 'A look inside the life of John F. Kennedy Jr.', '/ja63BNkxkPIQxVtV8LKcdAwiJvO.jpg', '2003-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14374, 'Sharon Tate: Murdered Innocence', 375033, NULL, '/jpKcZiemcaUYOllVi9tk8n9qEDL.jpg', 'Sharon Tate: Murdered Innocence', 'Sharon Tate is a rising young star before her life ends in a shocking murder.', '/fBZjQ8BdVrJRIubenEPBWuDWOcl.jpg', '2002-10-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14375, 'BRATS', 999621, NULL, '/iJ27WaIy8xyrwAyHCYiJJNFq3Hy.jpg', 'BRATS', 'In the 1980s, Andrew McCarthy was part of a young generation of actors who were set to take over Hollywood after a string of successful teen movies. However, when the New York magazine cover story in 1985 dubs them the Brat Pack, stars in the making suddenly find themselves losing control over the trajectory of their careers. Now, almost forty years later, McCarthy looks to reconnect with peers and co-stars so that together they can reflect on their respective legacies.', '/8kXKxkFo1KC0pwvjbaKg4ruXG6J.jpg', '2024-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14376, 'Summer Solstice', 281709, NULL, NULL, 'Summer Solstice', 'Summer Solstice is a collection of love stories about, and for, people of all different ages and generations. Each character''s tale connects, weaving in and out of the others, mirroring and countering them so that, as the long hot summer draws to its close, each is forced to examine their lives and decide to whom their loyalties lie or else risk loosing everything they hold so dear.', '/3crVvLSGKH5TkOGuK14vk2Cn3p4.jpg', '2005-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14377, 'The Last Film Festival', 412532, NULL, '/g3EkfmFd2rsZ7tfwc7VD9WhxLn3.jpg', 'The Last Film Festival', 'Dennis Hopper plays Nick Twain, a Hollywood Producer whose latest film is rejected by every film festival in the world except one- in Ohio. Nick will do anything to get his film distributed, including manipulating his dysfunctional cast into attending the festival. Hollywood egos and small town politics inevitably collide.', '/jUC5u21rwSUKeHJEBXQPfUhGwO6.jpg', '2016-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14378, 'Peter and John', 415263, NULL, NULL, 'Peter and John', 'A town doctor’s jealousy over his younger brother’s mysterious inheritance is compounded when they both fall for the same woman.', '/a1RxXzzaDZidxRXKTgAgISqB075.jpg', '2015-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14379, 'Electric Blue 004', 416411, NULL, NULL, 'Electric Blue 004', 'Britain''s top-selling adult video cassette continues its unchallenged supremacy! This entry features numerous centerfolds, male-to-female sensation Amanda Lear, a tour of Nevada''s Mustang Ranch, three beauties having fun in a pool, nude wives, nude celebrities (Jacqueline Bissett and Jayne Mansfield) and power boat thrills and spills.', '/du1ZuEwzhf5QfvIv24LONZybufQ.jpg', '1980-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14380, 'Scenes from the Class Struggle in Beverly Hills', 60276, NULL, '/u8oJq3FQQWk4rycIXpNYCKYRJo.jpg', 'Scenes from the Class Struggle in Beverly Hills', 'A wealthy Beverly Hills resident who has just become a widow, Clare Lipkin temporarily takes on her friend Lisabeth as a house guest. As the two women deal with their upper-class woes, Clare''s driver, Frank, and Lisabeth''s servant, Juan, make a wager to see who can be the first to seduce the other''s boss.', '/4Q8yE7ijikNXWItWnAJkjt9yWvn.jpg', '1989-06-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14381, 'Stand Up and Be Counted', 421229, NULL, NULL, 'Stand Up and Be Counted', 'Sheila is a newspaper reporter who returns to her home town in order to write an article about the progress of the liberation of the women. Arriving at the town she is very surprised to see that her sister and also her mother agree very much with the feministic arguments.', '/aiJWLBQLXkAq55L6AZtoqZQhHbs.jpg', '1972-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
