INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14393, 'Forbidden', 433107, NULL, '/qqkS1SDB5yd5RmWs9eH2T0WxYFy.jpg', 'Forbidden', 'In Berlin in the early 1940s, romance is forbidden between the young countess who is studying veterinary medicine and a young man she meets at the home of a former professor. But they fall in love. She gets involved in helping Jews escape from the Nazis. All get out of Berlin except the young man. There is a room in her apartment where he can''t be seen through the windows and a chest converted into a sofa where she and her brothers played hide-and-seek as children. This real life hide-and-seek game has high stakes. The movie is said to be based on a true story.', '/bleLq1OWoCotyrs3mce77petuuT.jpg', '1984-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
