INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14401, 'The Lodger', 783572, NULL, '/oQHqyM14Nq4FtXYtXjcl1DoHFQw.jpg', 'Messe basse', 'Julie just started university in Bordeaux. She moves into the house of Elizabeth, an old widow who lends her a room in exchange for her help with daily chores. There’s one condition: acting as if Victor, Elizabeth’s dead husband, was still alive. But soon, Julie starts feeling his presence… and an inescapable and dangerous love triangle begins.', '/35iyoI248BJ4s1j7lxzI0hU1C1c.jpg', '2021-08-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
