INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14410, 'Belmondo: The Incorrigible', 1021162, NULL, '/b4nMcTpMiHUnz22bHPhdFIlcqqx.jpg', 'Belmondo l''incorrigible', 'Charismatic and resourceful, seducer and daredevil, Jean-Paul Belmondo has always played his roles as he lived, at a thousand miles an hour. He had only one passion: to entertain the public with his smile, his naturalness, his energy, his stunts. But contrary to appearances, his destiny was full of pitfalls. This film lifts the veil on a founding childhood that allowed him to overcome many obstacles throughout his life thanks to the tutelary figures of his father and mother. Told from the inside with the help of his autobiography, interviews and unpublished archives, this epic story traces the career of this turbulent young actor who launched the New Wave in Breathless before becoming the popular Bebel, an indestructible and provocative vigilante. From film to film, this documentary paints an intimate portrait of a man who built himself up to reach the top: his triumphs but also his trials, his doubts, his secrets, his angers, his clowning, his disappointments or his personal dramas.', '/b1LDBZDOTG9wfYmZZQUy4dSRySe.jpg', '2022-09-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14411, 'Sol y sombra', 1626117, NULL, NULL, 'Sol y sombra', 'Carmela is almost sixteen. She has just lost her mother and is suddenly sent to a boarding high school in Montpellier, the city of her paternal grandparents, after having spent her entire life in Spain. When the holidays arrive, she travels to Seville to see Luis again—an elderly Romani cantaor, her mother’s former partner and her lifelong accomplice. These reunions, the screening of a film they were never able to finish eight years earlier, and the upheavals of a minority which, in the age of technology, longs to integrate, abruptly sacrificing all the specific traits that had tirelessly shaped it until then, will entail—beyond the mourning of childhood—the realization of a paradise forever lost.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14412, 'Morceaux de Cannes', 847138, NULL, NULL, 'Morceaux de Cannes', 'We thought we''d seen, read, and heard everything there was to see about the Cannes Film Festival, from the glitz and gossip to the scandals and censorship. And yet, Emmanuel Barnault''s "Morceaux de Cannes" (Pieces of Cannes), by this leading expert on Italian and French cinema, convinces us otherwise. The third largest event in the world (after the Olympic Games and the FIFA World Cup) reveals its secrets only sparingly, as this film attests. The result of passionate research in the INA archives, these 52 minutes, without interviews or voice-over narration, string together rare and sometimes previously unseen footage. Taken together, they tell a surprising, original, and heartwarming story of the Festival. On the beach, on a street corner, in a restaurant, or in the privacy of a hotel room, these forgotten archives summon the greatest filmmakers, actors, and actresses of the last seventy years, from Jean Cocteau to David Lynch, for an anthology of the Festival''s history.', '/as5HrR2xYEko9jY1QQHwKfJImy6.jpg', '2021-07-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14413, 'The WASPS: Taking Flight', 1669887, NULL, '/4NOmtTfzQ4aFIVeKAJTLmdVNRWY.jpg', 'The WASPS: Taking Flight', 'Nadine Ramsey was one of 1,102 young women who answered the call to defend lives and liberty during WWII. The film is a profile in courage of the women who selflessly cleared the flight path for today''s female combat and commercial aviators yet were not recognized or compensated as members of the armed forces. They came from all walks of life to join the experimental WASP program, a once in a lifetime opportunity to enter what had been an exclusively male bastion.', '/z5Oj6KRHqO8vXs3EdaUTcg1mxpZ.jpg', '2026-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14414, 'The Ex-Wife of My Life', 40173, NULL, '/w76Mi4Kqvl0kuKPvACB7JgY4dCt.jpg', 'L''Ex-femme de ma vie', 'Six years after their split, a woman attempts to get her ex-husband back by unusual means.', '/uENzbPoVyWVM6CYDOxMHfI2BT8t.jpg', '2004-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
