INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14418, 'The Crimson Rivers', 60670, NULL, '/1Kzrk49o1oX15yqjWVuGPAEnjgd.jpg', 'Les Rivières pourpres', 'Two French policemen, one investigating a grisly murder at a remote mountain college, the other working on the desecration of a young girl''s grave by skinheads, are brought together by the clues from their respective cases. Soon after they start working together, more murders are committed, and the pair begin to discover just what dark secrets are behind the killings.', '/npvDhiKkpQBuTaQ8cbWRT2iEfkE.jpg', '2000-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14419, 'Les Grandes Bouches', 72282, NULL, '/c4ktAc89NC1AwYlXobg0EibvJgH.jpg', 'Les Grandes Bouches', 'This is a suspense drama about Esther, Lamar, and Zed, three friends who live together. Tired of having financial problems, they decide to hit it big somehow. They visit Armand, a former ''Godfather'' who has now retired. They soon realize that, in contrast to their world of easy living with few responsibilities, Armand''s world belongs to the underground with its own code of behavior. Their involvement in that world brings them face to face with events they had never imagined before.', '/8BfMa1gRk4wkCbHvApkHUpxErAD.jpg', '1999-02-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14420, 'Tell Me Yes...', 74606, NULL, '/e8QFz2buz8VbXXj4RSXonSUXd4H.jpg', 'Dis-moi oui...', 'Handsome pediatric doctor feels unfulfilled, until his affection for a 12-year-old opens him to a romantic view of the world. When she falls ill, he must get closer to her, and a conflict of interests and ethics arise. His medical reputation is at stake.', '/mrnGPW4bDOEbJLIZcphAfHYYQtZ.jpg', '1995-04-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14421, 'Men, Women: A User''s Manual', 76390, NULL, '/mH1reW0EGDgYLjC8xhwb74BjLoy.jpg', 'Hommes, femmes : Mode d''emploi', 'Benoit Blanc loves living, he loves women, he loves daring. He is a famous businessman who suffers from stomach-ache. Fabiolini, a would-be actor, is a policeman and he too suffers from the same sickness. The two man face suffering in opposite ways: Benoit Blanc is optimistic while Fabiolini, always unsure of himself, is persuaded he is seriously ill. The two men meet by chance while doing a gastroscopy and become friends. After having known their real different conditions, they will change and will understand better their lives. Around them, other people, women and men, will see their lives changed, by chance, by love or solely by the life stream.', '/5cbsWJB790lWB99w33MiAGCSMYb.jpg', '1996-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
