INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14423, 'Love in the Strangest Way', 139874, NULL, '/bHfOWxg9w23JhL89NNvEo4IdHpk.jpg', 'Elles n''oublient jamais', 'Successful Julien sees his family off on holiday and at once becomes drawn into a risky relationship with Angela, whom he spies outside the cafe opposite his office. When he later finds she is to become his son''s new nanny he rightly starts to worry there is more to the relationship than he bargained for.', '/c8wzzCBtjvxZxNmVSM8PwUrSSzB.jpg', '1994-04-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
