INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14428, 'Toujours possible', 1313168, NULL, '/lk10DY1qyUXmZVkjnVLG9gCxfG3.jpg', 'Toujours possible', 'At 55, Gabrielle, a brilliant scientist who has just been laid off, decides to take her life back into her own hands: she wants to have a child! Her mother, Rose—eccentric and kind-hearted—enthusiastically gets involved in helping her find the “perfect sperm.” That’s when Gaby meets Pierre, 58, a charming man in crisis, and Max, 26, his son, who’s searching for a father rather than a pal. Between desire, taboos, and pretenses, each finds themselves confronted with their own contradictions. A tender, sharp, and deeply human comedy. Because, in the end, everything is always possible.', '/qwklLRMLoCq6StEcLkTjmX1fdoM.jpg', '2025-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14429, 'Everyone''s Life', 437399, NULL, '/yVDuzbhH8hm0oO29gEB5Uz9quFp.jpg', 'Chacun sa vie', 'Before being judges, attorneys, or jury members, they are first of all men and women at a crossroads in their lives, with their dreams and their secrets, their hopes and their limitations, all beneath the same sun, each with their own dark side. In a lovely provincial town, during a jazz festival, life will juggle with their destinies.', '/pvTvo9V6CMVCgOYmdqXFV8vTYxb.jpg', '2017-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
