INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14432, 'The Nest', 22156, NULL, '/uCdHAMknWaR4PbSRlCqAcrN95f3.jpg', 'Nid de guêpes', 'Laborie is a high-flying officer in the French special forces. Her mission is to escort Abedin Nexhep, a godfather of the Albanian mafia. Charged with heading a wide-reaching prostitution network, this formidable criminal is due to stand trial before a European court. During the transfer, killers hired by Nexhep set up an ambush to free their boss but Laborie and her men manage to escape...', '/5mamCUxm8jaFVeMH7DFgrSticd5.jpg', '2002-03-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
