INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14435, 'A Monkey''s Tale', 37949, NULL, '/oG24VU7BdJnw8YeXYvp0bcQzzjU.jpg', 'Le Château des singes', 'Kom is from a tribe of monkeys who live in a canopy. He rejects elders'' authority as well as the superstition that the lower world would be inhabited by demons. But he accidentally falls from the trees…', '/s4pYSLnGHXUyiTs0HNmpUJMYVKv.jpg', '1999-06-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14436, 'Le Cavalier des nuages', 800042, NULL, NULL, 'Le Cavalier des nuages', 'Luc Farraud, a journalist and former hostage in Lebanon, lives alone in the wilderness. But his tranquility is disrupted by the arrival of Joss, a young cop, and Melka, a beautiful gypsy car thief.', '/mWB5Y9uXf8L0VSIcZ7J3Hheytyv.jpg', '1995-12-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
