INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14438, 'Haters', 825252, NULL, '/sBoDAR1v3Xc7mU7NEPLgA1hnWt9.jpg', 'Haters', 'Internet humor star Thomas the Lama gets out of hand in a video. He becomes the target of all haters and his life falls apart. To win back his girlfriend and his audience, he decides to go meet his 10 biggest detractors to see if they can say, face to face, what they write on his page - Each meeting promises to be epic.', '/hw6E3XV4Q0eYuLWiVLXR8FxPmJ6.jpg', '2021-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14439, 'Sous les pieds des femmes', 534293, NULL, NULL, 'Sous les pieds des femmes', 'This romantic, political drama is about the reunion of an Algerian woman who abandoned her lover 35 years earlier to live in France, and the lover who chose to stay in Algeria and fight the French colonials.', '/zHLNpLRZY09kkZhsNxLl8qtD9c3.jpg', '1997-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
