INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14442, 'Diary of a Young Comic', 341514, NULL, NULL, 'Diary of a Young Comic', 'A time capsule of the L.A. comedy scene in the 1970s, "Diary of a Young Comic" casts Richard Lewis as a fictionalized version of himself - a young New York comic who comes out to Los Angeles to seek his fame and fortune.', '/bnHlCtCbJ5GkO4jrmvsN0wXEqAw.jpg', '1979-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
