INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14444, 'Mixed Blood', 86458, NULL, '/kX0Keyjs1DcNQ1Z5qEwUSz9c3Gs.jpg', 'Mixed Blood', 'On the mean streets of New York City, a dog-eat-dog mentality reigns among the destitute citizens. In one of the many abandoned buildings in the neighborhood of Alphabet City lives the Brazilian Rita La Punta, along with her delinquent son, Thiago, and a gang of Hispanic teens charged with selling heroin and cocaine. When Rita and her young gang members get involved in a minor turf war, the violence escalates out of control, touching everyone and sparing no one.', '/3WIt6TJevoFhP4AzOthL1f6C94i.jpg', '1984-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14445, 'Down Twisted', 88253, NULL, '/lntCWM6sFQSFG5vSDvVxu4taekl.jpg', 'Down Twisted', 'A naive, good-hearted Los Angeles waitress does not think twice about helping her troubled roommate. Unfortunately, her help lands her in Central America fleeing for her life with a grungy mercenary.', '/7Dwpo0WuOceN1faGSbzC3EMIsxq.jpg', '1987-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14446, 'Alien from L.A.', 31397, NULL, '/rwD8N3wvfxcDBborM1BCZ6AiExZ.jpg', 'Alien from L.A.', 'When her archaeologist father disappears on an expedition, Wanda sets out to look for him. What she finds is a secret underground world, where no one believes in life on the surface and where she and her father are taken for spies.', '/Al8v2ASozhufxTiA7HVL7GAxi3y.jpg', '1988-02-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14447, 'Strangers Kiss', 119880, NULL, '/jDdkda0tPIOZWB7MtDBt0sVx4HS.jpg', 'Strangers Kiss', 'Hollywood. 1955. Faced with two inexperienced actors, a film director encourages the leading lady and leading man to fall in love in real life so as to provide the heat needed for the inner film''s romance, which enrages the actress'' possessive gangster boyfriend, who happens to be the film''s financier.', '/2nAk00NTvQIIZ3MwIw44JaMJ2hw.jpg', '1983-09-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14448, 'Eagle Shadow Fist', 21537, NULL, '/s4LEUGP03RVY4ctR0CBYIuX7UML.jpg', '顶天立地', 'Historical movie set during the Japanese occupation of China during WWII. Jackie Chan is one of the good guys but has nothing much more than a supporting role.', '/xOxoM1mr6ePsOMXDdv5zBHkjZsn.jpg', '1973-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
