INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14450, 'New Police Story 2', 1100119, NULL, NULL, '新警察故事2', 'After his release from prison, Joe Kwan wants retribution and uses the media to degrade the police, which hurts the reputation of Inspector Cheng Siu-Fung and Chief Superintendent Chan Kwok-Wing.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14451, 'Jackie Chan: My Stunts', 40863, NULL, '/vj433os6uMy1YCG6xdrtO3EmYjW.jpg', '成龍的特技', 'Jackie Chan: My Stunts shows some of the tricks of the trade that Jackie and his stunt team utilize to perform their stunts. This is not an endless gag reel of stunts gone wrong, but an in depth look at how timing and camera placement can make or break a shot. Jackie will show you what is done to enhance fights and protect the stuntmen from getting injured. Of course, if the character you are portraying is wearing shorts and a tank top, you just have to get hurt!', '/eLT6kuZ4bQpUaFJ6OKH2YMvaUet.jpg', '1999-03-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14452, 'How Bruce Lee Changed the World', 40572, NULL, '/h4lqGVzWwBnK55QhPPfxtPAAggA.jpg', 'How Bruce Lee Changed the World', 'More than just a biography, this film explores Bruce Lee''s global impact to see how he has influenced all areas of popular culture including fitness, cinema, music, sport, dance, video games and philosophy. A journey across the United States, Asia and Europe, takes Shannon Lee on a trip back to her father''s roots in Hong Kong and China. With unique access to the family''s photographic archive, home movies and all material owned by the Bruce Lee Foundation.', '/7Ogaw7mCHBPocOzYCl0Rc6UAAc3.jpg', '2009-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14453, 'Snake & Crane Arts of Shaolin', 35170, NULL, '/6lByUNEwyjZIYGUsG6Cqp5JMWJv.jpg', '蛇鶴八步', 'Jackie Chan stars as the young warrior Hsu Yiu Fong. Hsu has been entrusted with the book of the "Art of the Snake and Crane," after the mysterious disappearance of the eight Shaolin Masters who had written it. He must fight off numerous clans who are all attempting to steal the book from him, to find out the true reason for the disappearance of the Shaolin Masters.', '/r4okXfWfTdnZESaEkBeFnAJrTmI.jpg', '1978-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
