INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14463, 'The Invincible Fighter: The Jackie Chan Story', 1123344, NULL, NULL, '天下无敌', 'The setting is Hong Kong and the hero of the film is Jackie Chan. This documentary chronicles the life and entertainment career of the star of Hong Kong action films. Archival photographs and the personal recollections of family and friends paint a portrait of the private life of the film star. Clips from movies, such as Top Fighter and Rush Hour, as well as the television series Jackie Chan''s Adventures show the martial artist''s prowess and skill. Interviews with Chanand his colleagues give viewers an inside look at how some of the stunts are set up and carried out, as they put the action in action films.', '/pZ1C7QIspPCYD66ixkKi8hbO9m7.jpg', '1996-06-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
