INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14469, 'The Golden Lion', 107840, NULL, '/hhWAkMG2Ny3qdHjXTjpPs69j8Ce.jpg', 'Jin mao shi wang', 'Director Ho Meng-hua is one of Shaw Studio''s most versatile directors. He''s helmed romances, mysteries, award-winning dramas, contemporary action films, historical costume dramas, fantasies, and, finally, popular swordplay movies. The title character in this one is a chivalrous thief who raises the jealous ire of the rival Red Shirt Gang. There''s plenty of action in this adventure, which sweeps from the plains to the mountains ... to the sound of slashing swords.', '/yDhyIfEfUmabNv0UATQR9nxMfKH.jpg', '1975-12-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14470, 'The Black Tavern', 86275, NULL, '/5OYxEDIKVk3GxDkfaLvRpXGGbMI.jpg', '黑店', 'A rumor has spread that a retiring corrupt official is traveling with a box filled with all kinds of valuables, and is going to make a stop at a remote inn. And multiple criminal martial artists planning to rob him descend on the tavern.', '/ySjUQjYTX8Me1r6eDCfKuqfZBZr.jpg', '1972-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
