INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14474, 'Robin Williams: Laugh Until You Cry', 1212471, NULL, '/26WBdpUvbrOrfqYxO17xavhiCX2.jpg', 'Robin Williams: Laugh Until You Cry', 'Robin Williams. The comic genius with an electric mind, with a range of talent that left us breathless. The one who amazed and kept us entertained until the very end, and whose sole purpose in life was to make people laugh. Living life to the fullest, he went from one memorable film role to the other. But behind the upbeat, frenzied facade of Robin Williams was a sensitive and vulnerable man, deeply plagued by depression and haunted by his demons. Few comedians have ever been as beloved as Robin Williams. His story is full of tragic moments. It inspires us to look past the mask of those people who seem to have a perfect life. His legacy, reaching way beyond his body of work, lives on. We look back at the journey and tragic loss of a unique comic legend...and one of the greatest comedians of all time.', '/nnNmRLcAeugdaBvVaZHv31xm3tJ.jpg', '2022-03-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14475, 'Fire Dragon', 351719, NULL, NULL, 'ลุยละว๊ะ! เฉินหลง 9มังกรคาบแก้ว ภาค2', 'A Team of Prisoners, famous thieves and great fighters are assembled by a shadowy government agency to steal a top-secret file.  Their destination the island of the Women Warriors! Suddenly, they find themselves in a deadly trap-if they succeed with their mission.  Will they uncover an even bigger secret? Prime-time Jackie!', '/4JuRNKiNdP4ZO6WI3x3llmCoENN.jpg', '1983-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
