INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14478, 'Top Fighter', 50151, NULL, NULL, 'Top Fighter', 'Welcome to the world of the martial arts. A voyage for the times of the martial arts cinema, from the beginning in China in the 6th Century A.C. by a Buddhist monk, Bodhidharma, until the actual time and the influence in the world, with interviews to actors and historians, and a review to the most important movies of all times and to the most famous action movies actors. A magnificent jewel of this genre what nobody wouldn''t lose.', '/7ox6gdXTuyJi0sQCBP1VFCJCg8r.jpg', '1995-06-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14479, 'The Blade Spares None', 74266, NULL, '/dVDAsTsx3aRd9JDMPsuaIYMbWF2.jpg', '刀不留人', 'Ho Li-Chun, a pretty but ruthless swordswoman, and three challengers are participating in an open tournament at Prince Kuei''s Palace. A knight, Chen Jo-Yu, is defeated in the tournament. He flees and later returns with knight Tang Ching-Yun who wields a strange sword. They get trapped but Ho deliberately sets both free after seeing Tang''s weapon which she recognizes as the same weapon once used by Sun Tien-Chen, a foe of the Ho family. She decides to investigate. She finds out Prince Kuei actually is Sun, who killed the real prince years ago and assumed his identity. Ho joins forces with Chen and Tang. The trio slays Sun in a desperate confrontation at the palace.', '/qk9b4belX71BbShSlh1mu3xP93Q.jpg', '1971-04-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
