INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14483, 'Masters of the Martial Arts Presented by Wesley Snipes', 165343, NULL, NULL, 'Masters of the Martial Arts Presented by Wesley Snipes', 'Special honoring the grand masters of the martial arts with guest stars from film and television, music performances, live demonstrations, competitions and tributes to Jackie Chan, Bennie "The Jet" Urquidez, Cynthia Rothrock, Billy Blanks, Ernie Reyes Sr., and Shaka Zulu.', '/71ybAjosGUER1a1IqZEO74CraEm.jpg', '1998-08-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14484, 'The Art of Action: Martial Arts in the Movies', 118483, NULL, '/3TLr3NyVwonTEXnIZa9UlUg7C68.jpg', 'The Art of Action: Martial Arts in the Movies', 'Hosted by Samuel L. Jackson, this in-depth documentary offers viewers a behind-the-scenes look at the history of the martial arts film -- from the genre''s rebellious beginnings to high-flying modern epics. Jackson takes you through the best moments of 100 movies, including Charlie''s Angels and Oscar winner Crouching Tiger, Hidden Dragon. Interviews with martial arts film veterans Sammo Hung, John Woo and Ang Lee round out the video.', '/6iAptuGwI1q64tsAgiaQ9tVxMTj.jpg', '2002-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
