INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14488, 'A Kid from Tibet', 50154, NULL, NULL, '西藏小子', 'As the evil sect known as the Black Section of Esoteric Buddhism wreaks havoc on Tibet, a young monk named Wong La (Biao Yuen) is sent to Hong Kong to recover a sacred urn that holds the power to defeat the enemies. Wong soon meets and safeguards a gorgeous woman (Michelle Reis) connected to the urn''s protector, while the leader of the Black Section learns of Wong''s plan and pursues the urn for himself in this martial arts thriller.', '/9bVHHXTFD9UES7AUf6MeL2aLyqE.jpg', '1992-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
