INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14495, 'Lady of Steel', 107899, NULL, '/kVHAS71fxdXzNjypnYc836I22Vb.jpg', '荒江女俠', 'A young swordswoman named Fang Ying-qi (Cheng Pei-Pei) sets out to join a gathering of the martial world’s leading warriors under the banner of Lord Xia (Fang Mien) and the Flying Dragon Clan. Their mission is to organize the defense of their country against invading Jin forces. Fang also intends to avenge the murder of her parents 20 years past by bandit leader Han Shi-xiong (Huang Chung-hsin). Han has since taken on a new, false identity as a reputable member of the Flying Dragon Clan while secretly working with the Jin to bring down the resistance. Han uses cunning and a network of criminal fighters in an attempt to assassinate Fang, and when that fails, to frame her as a traitor. Once his true identity and intentions are revealed, a determined Fang must rely on her deadly sword skills and assistance from a clever beggar clan leader (Yueh Hua) to stop Han and restore her reputation.', '/sEo0WMrTNe6rSzzmOGuwg0YKXW1.jpg', '1970-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
