INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14502, 'Village of Tigers', 187473, NULL, NULL, '惡虎村', 'The Village of Tigers is known as the home of all evil doers throughout the land, ruled by their leader, Lord Hu Jiao. When the famed swordsman known as the Sword of the Southern Sky, Luo Hong-Xun ends up in said village, he will teach the bandits a lesson.', '/xtBQ2Uofc85PGprPfkl4KgW4sCI.jpg', '1974-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
