INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14506, 'The Legend of Silk Boy', 307466, NULL, NULL, '世博總動員: 世博冠軍湖絲仔', 'An ambitious little boy who stumbles into a magical world filled with fun, laughter, adventure, danger, and the most amazing and colorful characters you''ve ever seen. Along his journey, Silk Boy discovers the history of his country and becomes a hero by fighting against the evil Filthington IV who will stop at nothing to obtain all of the riches of the world, especially the control of the rarest silk on earth made by the beautiful Goddess of Silk.', '/e1xQblpHG6jVSthc7RVPZ4KR77a.jpg', '2010-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
