INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14509, 'The Life of Bruce Lee', 167679, NULL, NULL, 'The Life of Bruce Lee', 'Documentary about martial arts actor Bruce Lee, from his birth in 1940 till his death in 1973, with interviews with his fellow actors and family. Dedicated to his son, Brandon.', '/dXCuW2urSFcNAxLtxhwxqQePZUB.jpg', '1994-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14510, 'Jackie Chan - From Stuntman to Superstar', 468299, NULL, NULL, 'Jackie Chan - From Stuntman to Superstar', 'Jackie Chan - From Stuntman to Superstar is a documentary on Jackie Chan.', '/iVRYqQeud5Qonn2CPFMkqkGBEPS.jpg', '1996-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14511, 'The Path of the Dragon', 167675, NULL, NULL, 'The Path of the Dragon', 'Produced and directed by Walt Missingham who, in 1983, became the first non-Chinese to practice Kung Fu at the Shaolin Temple, this authoritative and informative programme uses rarely seen archive footage to trace both the history of martial arts and the phenomenal impact Bruce Lee had on this culture. Narrated by Lee''s daughter, Shannon Lee Keasler.', '/v226fUcRti1KmkfbpFPTNdAH0wH.jpg', '1998-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14512, 'Eastern Heroes: The Video Magazine - Volume 1', 493203, NULL, NULL, 'Eastern Heroes: The Video Magazine - Volume 1', 'Eastern Heroes: The Video Magazine - Volume 1 is a Documentary on Hong Kong cinema.', '/aewFVSvTTBcMyGLzgfePScUL5ye.jpg', '1995-07-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14513, 'Jackie Chan''s Global Friendship Tour', 493226, NULL, NULL, 'Jackie Chan''s Global Friendship Tour', 'Jackie Chan''s Global Friendship Tour is a Jackie Chan Documentary', '/6oYj2niQFO3wgH7762eP50e7Dp0.jpg', '2006-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14514, 'Augustin, King of Kung-Fu', 64919, NULL, '/6XK8F0lbgExpQmjEeXdAmJORpx9.jpg', 'Augustin, roi du kung-fu', 'The solitary and largely self-contained Augustin (Jean-Chretien Sibertin Blanc), on obscure young actor of bit-parts and advertisements, has but one ambition - to play the lead role in a Kung Fu epic. But hours of Kung Fu practice alone in his room are not enough. Augustin knows he must pack up and start a new life in China... or at least that part of China within bicycling distance: Chinatown in south-east Paris. There he meets Ling (Maggie Cheung), a young Chinese woman who practices ocupuncture, and little by little, Ling''s needles awaken emotions in Augustin that his virginal body had never dreamed of. Where will this lead him? To Kung Fu stardom, maybe not, but to another destiny, a quirky but logical continuation of the same dream.', '/tKzm2brQ1mO7gkRtIbQodBSAljh.jpg', '1999-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14515, 'A Century of Light and Shadow', 514927, NULL, NULL, 'A Century of Light and Shadow', 'Revisit 100 years of Chinese cinema through the RTHK TV program A Century of Light and Shadow. Aired in 2005, this interesting and informative documentary traces the development of the Chinese film industry from the pioneering years to contemporary times. From the volley between Mandarin and Cantonese films to the rise of the New Wave, this program touches on all the major trends and developments that have helped define Chinese cinema and explores different genres and representative figures and films. From actors to directors, over 200 film industry names, including Jackie Chan, John Woo, Sammo Hung, Connie Chan, Andrew Lau, Peter Chan, and Lau Ching Wan, appear in the program, bringing their intimate knowledge of the industry and providing insight about what lies ahead for Chinese cinema.', '/ic2yCZ6jdziwjG0arHzkzN5Fcmf.jpg', '2005-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14516, 'Hong Kong Superstars', 515737, NULL, NULL, 'Hong Kong Superstars', 'Hong Kong Superstars is a documentary', '/111XsXPuG5mfL6QzZFOywXq9zGW.jpg', '2001-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14517, 'Bruce Lee: The Legend Lives On', 167684, NULL, NULL, 'Bruce Lee: The Legend Lives On', 'This insightful documentary takes an in-depth look at the life of Bruce Lee, and the physical and mental practices he employed on his way to becoming the most popular martial arts star in the world. Utilizing footage of Lee both practicing and teaching Jeet Kune Do, as well as interview footage with the people who both knew and worked with Lee--including James Coburn, Bob Wall, Van Williams, Brandon Lee, and more--THE LEGEND LIVES ON is a comprehensive examination and celebration of a true artist.', '/2jbCyoSCJpUadaLNvxXbjK25XTu.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14518, 'Jackie Chan Adventures: The Search for the Talismans', 311494, NULL, NULL, 'Jackie Chan Adventures: The Search for the Talismans', 'Amateur archeologist, undercover agent and world-famous action hero Jackie Chan has his hands full when his 11-year-old niece Jade -- who''s a chip off the old block -- arrives in San Francisco to live with her uncle. Meanwhile, Jackie''s accidental discovery of a coveted ancient Chinese talisman has an evil criminal enterprise known as the Dark Hand, led by the villainous Valmont, chasing after him.', '/zkBHxQBkebgPhsdeckyKobsJIAZ.jpg', '2001-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14519, 'The Moment: Fifty Years of Golden Horse', 383944, NULL, NULL, '我們的那時．此刻', 'In 2013, the Golden Horse Film Festival celebrated its 50th anniversary. The ministry of Culture commissioned director Yang Li-chou to make a documentary about the history of Golden Horse. What is unique to this film is that it''s not an ode to celebrities but about the role cinema plays in ordinary people''s lives. It''s a love letter to cinema, filmmakers and audiences.', '/rIiFfZNJRTPxkQcywNNFXFAnz7I.jpg', '2016-03-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14520, 'Iron Fists and Kung Fu Kicks', 600014, NULL, '/wtHejZOVkAZtZ8L8o1g3KNE56xJ.jpg', 'Iron Fists and Kung Fu Kicks', 'The fantastic story of how an ancient martial art, Chinese kung fu, conquered the world through the hundreds of films that were produced in Hong Kong over the decades, transformed Western action cinema and inspired the birth of cultural movements such as blaxploitation, hip hop music, parkour and Wakaliwood cinema.', '/1t0SsQqmfYVuD3MBCIB4muGllAP.jpg', '2019-08-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
