INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14537, 'Jackie Chan: Building an Icon', 860578, NULL, '/tyPojL6AL8mdVlpwvVvO5SJFyTJ.jpg', 'Jackie Chan - Humour, gloire et kung-fu', 'Jackie Chan is a true icon of Asian and Chinese culture. Over a 45-year-long career, he has carved a niche for himself as an actor, stuntman, director, and screenwriter, but also singer and formidable businessman. After starring in almost 200 films, Jackie Chan has reconciled fans of genre film and Hollywood blockbusters, whilst bridging the gap between Asian and Western cinema.  Through film excerpts, archive footage and images, and an offbeat approach inspired by the visual codes of the golden age of kung fu films, this documentary will take a look back at the creation of a popular hero who has come to be an icon for China, and for the entire Asian continent.', '/bSSGZLWKWt4RAf68mMgjUMfZIRw.jpg', '2021-08-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:44', 0);
