INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14545, 'Molester Diary: A Man Who Kept Stroking Ass', 927589, NULL, NULL, '尻を撫でまわしつづけた男　痴漢日記', 'A manga artist stumbles into the sleazy world of perverts who stalk trains looking for women to molest. He discovers quickly that he is very much one of them and even finds love along the way. The first in the alarmingly long-running Molester Diary series.', '/iJL6OF6aEE0aBxj1kPgZFIk7370.jpg', '1995-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14546, 'Heisei Zankeiden: Battered Slash!', 934933, NULL, NULL, '平成 残 侠伝 ぶった斬れ !', 'A man who was trapped by a gangster who was taken over by a sneaky means of life, such as a gangster and a gangster who disappeared from the screen with the era of his work. With the trampled step-in-law and streaks as shields, the last princes of Heisei who sought a place to die at the end show a fierce way of life!', '/eFBMifeQM5syTvitCsPiqjCqEQt.jpg', '1996-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14547, 'Jingi 29: Gokudo Corpse Robbery', 976108, NULL, NULL, '仁義２９ 極道死体強奪', 'Former sand group member Kasahara attacked the Akamatsu group''s office and robbed cash. Kasahara, who was driven by the Akamatsu group and lost his escape, asks Hitoshi for help. Jin, who judged that he was an act that deviated from Jinyoshi, refused to rescue Kasahara. Kasahara, who was in a difficult situation, attempted suicide, and Jin was forced to shoot Kasahara and deliver the stolen money to the Akamatsu group. However, a few days later, Kim and Kasahara''s corpse disappeared, and the suspicion was struck by Jin.', '/5FkkT3Z21E5DNooDesX2NCsSg4J.jpg', '2001-09-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14548, 'Apartment Wife ''98: Dangerous Ecstasy', 1069489, NULL, NULL, '団地妻''98 危険なエクスタシー', 'Yuki had a casual affair with a man she met at the scene of a suicide by jumping. Yuki got married and moved to a huge housing complex. Her life, which seemed to pass peacefully, cracked one day. Saito, the man from the sealed past, appears. Yuki, who is satisfied with her husband, is also embraced by Saito. And her neighbor who looks into the figure, and even her husband who has an affair...', '/3JTVbrsosukbD6MED8QonOxPqyi.jpg', '1998-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
