INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14550, 'Female Teacher Diary: Forbidden Sex', 670435, NULL, '/pNE7sm5kvMR8A3sKFaJNA78KkgS.jpg', '女教師日記 禁じられた性', 'The film depicts the relationship between a beautiful teacher and a male teacher, popular among female students, an excellent student who tells the teacher about his feelings using an answering machine, and a high school student who bets on whether she can have a relationship with a male teacher. This is the debut full-length work by Hideo Nakata.', '/wD7Xtfd91hfl66pMDWp1i8dVyX0.jpg', '1995-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14551, 'Shin Yurizoku 3', 1241151, NULL, NULL, '新・百合族３', 'Satomi Yamamoto, a librarian at Keishin Girls'' High School who lives with her homeroom teacher Ayako, is in love with Ryoko Sawaki, who always comes to the library at the same time. Satomi unexpectedly has an opportunity to exchange voices with her. She gives Ryoko a card asking her to buy a book, saying that she had it herself, but she wanted everyone to read it as well. "What kind of book is it?" she asked, and she answered that it was about a love story between girls. Satomi immediately bought the book and was stunned by the book''s depiction of intense sex. Ayako then introduced her transfer student, Suzuko Sakurai, to Satomi as her new roommate. When it turns out that Suzuko was actually the original author of the book, Satomi''s heart suddenly becomes flustered. Moreover, the novel is written based on fact...', '/i6fKSr0n55LCaVCTRYZPdI5ZT8Y.jpg', '1995-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14552, 'Tokyo Decameron', 348961, NULL, '/qe2DAo9msvjtarbEL7s4NHVvSNK.jpg', '東京デカメロン', 'Exploitation diva Kei Mizutani movie stars within this omnibus flick featuring three reports of madness and sensuality. The first part, entitled "Two Women known as Mariko," paints an image of a younger comely lass named Mariko, whom, because of to a strange series of occasions during her youth, finds by herself the slave of another girl coincidentally also named Mariko. Into the 2nd yarn, five ladies endeavor to a remote cottage. Yet maybe not very long after, the quintet occur upon a corpse. Plus in the final portion, entitled "The guy within the Pillory," a young dancer looks for the dastardly villain that drove her sister to suicide', '/f9K0Hc0B5nMRZ701jKU2UWXEXPR.jpg', '1996-07-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14553, 'Dochinpira 15: Twisted Desires', 1069480, NULL, NULL, 'どチンピラ15 歪んだ欲望', 'The 15th in a live-action adaptation of the manga of the same name by Makio Hara and Tetsumi Doko. Jin has hooked up with a beautiful woman, Kaori, but is surprised to learn that the person he''s making him orgasm with is his older sister, Tomoko. Tomoko suffers from multiple personality disorder because of the shock of seeing her former lover killed in front of her eyes.', '/1JBv9F7YdhbQDV47H9gO8xEBqL3.jpg', '1996-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14554, 'Suspicious Married Woman Telekura Report', 1069497, NULL, '/ko93ZKqJgGiVJg0o7XEWZiG7zVn.jpg', 'あやしい人妻　テレクラ・リポート', 'Sawaki, who used to be a socially active reportage writer, is now unemployed. The job that came to Sawaki was that of a telekura report. Now that his wife Naomi is pregnant, he has no choice but to take on any job. The editor-in-chief asks for a report that targets the naked private life of a married woman. At first, Sawaki was bewildered by the unknown world, but...', '/iZRJqnsItYZ8fYX3wLchqkBfCor.jpg', '1996-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14555, 'Darkest Hour', 460045, NULL, NULL, '丑刻二参ル', 'One cold midnight, Kenji was riding on a bicycle on trail in the woods...running away from his own life. When he saw a lady casting "Ushikoku" spell in the woods, a sleepless night begins. To cast ''Ushikoku'' spell, the one must nail a doll down to a tree in the midnight shrine. If the spellcaster be seen castiing spell, he or she must kill the witness to complete the spell... On the way running away from the lady through the midnight city, he finds out that no one helps him, his old friends, police, nobody. And soon, everyone starts chasing him, being a part of the spell. Kenji decides to fight. Not for his life, but for his girl with sickness inside her.', '/crWdK1vDuxZoaZ2dxkTB2d0czF8.jpg', '2015-11-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14556, 'Labyrinth', 466991, NULL, NULL, '迷宮', 'Three students, Hoshino, Tachibana and Keiko travel to an ancient and mysterious Chinese city in search of a potion that gives eternal youth. But once they arrive, Hoshino is attacked by a half-invisible creature that separates him from his friends...', '/nIZSg8kVmOcm37JSVZWv9NhlpLH.jpg', '1996-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14557, 'Peanuts', 279246, NULL, NULL, 'ピイナッツ 落華星', 'Two mysterious tough guys infuriate a local gang after helping an elderly grocery store owner with his debts by robbing a yakuza organised gambling den.', '/kztxfZatsQeqfrvU3zKWxzcVfGa.jpg', '1996-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14558, 'Family Court Probation Officer, Akira Yamanobo', 525411, NULL, NULL, '家裁調査官 山ノ坊晃', 'Tokyo Family Court judicial research official Akira Yamanobo is in charge of Tetsuo and Ayano Katase''s divorce arbitration. Ayano, the wife, who works for a boutique company, insists her husband is involved with another woman. Supported by her employer Kotomi Saegusa, the company president, she demands a divorce as soon as possible. On the other hand, her husband Tetsuo, a trading professional, denies having a relationship with a woman. He says he will not agree to the divorce and does not plan to let his only son Kenta go, so the arbitration continues. According to Akira''s investigation, Ayano gave birth to Kenta as a single mother five years ago when she was working as a hospital clerk, making him Tetsuo''s stepson. Tetsuo loves Kenta as his own child, so Akira doesn''t understand why Ayano is so insistent on getting a divorce. However, Tetsuo''s insistence on not giving up custody of his stepson Kenta is also very unusual.', NULL, '2016-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14559, 'Gigolo', 630336, NULL, NULL, '濡れ事師', 'Daisuke is a regular businessman who is looked down upon by his family and colleagues at work. But that job is only a cover for his real job as an agent who gets paid to extract top secret information from his targets by using his sexual technique to please women. One day, he unwillingly gets involved in a murder case....', '/vNHEWTN95YQHHLTJzAHBmroInJv.jpg', '1995-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
