INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14563, 'Female Teacher Diary 3: Hidden Sex', 631318, NULL, '/3ABnMR20ZvrvFY4AFkoZq5Jfoj8.jpg', '女教師日記3 秘められた性', 'When she takes off her teacher clothes, her womanhood breaks...  Satoko, a new teacher, is frightened by the hungry gazes of frustrated male students, and is bullied every day by delinquent students such as Hinata Masaaki. Unable to resist, she just lets things happen, and her only emotional solace is through computer communications. As she becomes addicted to lewd sex with the people she is communicating with, a shocking event befalls her...', '/iG2OcU7azeRrtD2xoZznvQaDiTb.jpg', '1997-06-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
