INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14565, 'Shin Mahjong Horoki 2', 1524378, NULL, NULL, '新・麻雀放浪記2', 'After a 20-year hiatus, the legendary mahjong master Boya Tetsu returns to the world of competition. However, he becomes entangled in the troubles of a young man named Hiyokko, who was the catalyst for his comeback, leading to a showdown with the mysterious woman Hanae. The intense mahjong battle ignites Boya Tetsu''s competitive spirit...', '/vhNHCs6uvgUEtkIOXbSJz38tvsf.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14566, 'Apartment Wife ''98: Dangerous Affair', 1559197, NULL, NULL, '団地妻’98 危険な情事', 'Voyeurism, eavesdropping, stalking, and sexual assault. Yuki, a newlywed living in a housing complex, finds her daily life gradually corrupted by abnormal sexuality... What kind of sex hell does this married woman fall into?! Yuki''s past. A chance encounter with a man she met at the scene of a suicide attempt. After getting married, Yuki sealed that day away in her body and moved to a huge housing complex. However, the man from that time, Saito, appears and Yuki is embraced once again. Saito strangles Yuki. Yuki feels an abnormal excitement in the ecstasy of heading towards "death". But there was a man watching them. In exchange for a recording tape, Yuki is forced to undress and descends into a life of sex and degeneracy...', '/AcLqlO9VY4lAXWlNuH0cSLaLHF0.jpg', '1997-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14567, 'Jungle Crow', 1606952, NULL, NULL, 'ジャングルクロウ！', 'The capital, Tokyo, had fallen into ruin as a crime-ridden metropolis, day and night, a city where violent offenders roamed the streets. And within that darkness lived a man who had become legend. Known only as ‘Crow,’ he survives in the underworld, hunting down the heads of criminals listed for special police bounty rewards.  Journalist Shizuka Matori tracks Crow, determined to uncover the shadows that flicker behind him and the greater conspiracy hiding in the dark. But this city—where the underground powers of Japan, South Korea, and China stand in a fragile stalemate—is overflowing with hidden dangers…', '/mW50m9X1XpEreL0zIzUhJb2DhtF.jpg', '2010-03-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
