INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14570, 'The Man Who Loved Women', 1421, NULL, '/n2lLL7epkunVFtAYiHLDScvvx9l.jpg', 'L''Homme qui aimait les femmes', 'At Bertrand Morane''s burial there are many of the women that the 40-year-old engineer loved. In flashback Bertrand''s life and love affairs are told by himself while writing an autobiographical novel.', '/qAbqXoN6ucpN8jvHOxZOzwyP8pE.jpg', '1977-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
