INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14573, 'I Married a Shadow', 4227, NULL, '/7QuZpCp2E9Rm39HZwZTdUZI7fMC.jpg', 'J''ai épousé une ombre', 'After a train accident, a woman survives and is mistaken for an other woman she just met on a train before the accident.', '/e1fHOMHDUZEHHC54GjXzcj58oeM.jpg', '1983-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14574, 'The Flower of Evil', 10930, NULL, '/osPfgq5zKWZrkXxb6rMvWzwyt8J.jpg', 'La Fleur du mal', 'Three generations of a wealthy Bordeaux family are caught in the crossfire when Anne decides to run for mayor, thanks to a political pamphlet that revives an old murder scandal.', '/kbOV3t9rQMkLaARTkb4DumTdJdw.jpg', '2003-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
