INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14576, 'The Green Room', 8070, NULL, '/vTG5rpUcNGl28iKsf6Pd3G312pp.jpg', 'La Chambre verte', 'A widower maintains a memorial room filled with his late wife''s belongings. When fire destroys it, he transforms a chapel into a new shrine to preserve her memory.', '/8D2Oty3FpihcNoNowuYbzOaXKsv.jpg', '1978-04-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14577, 'Sous le soleil de Pialat', 869954, NULL, '/x17y9CVoOHY3lxBgtBTwcecioWj.jpg', 'Sous le soleil de Pialat', 'In just ten films, Maurice Pialat painfully rose to the top of the cinema, draining into his legend a mad demand for truth as much as memorable fury to achieve it. With "L''Enfance nue", his first feature film at the age of 43, the filmmaker immediately made his mark, this "art of making things authentic", according to Chabrol. But throughout an unclassifiable filmography in the form of an autobiography, from a break-up to his fatherhood in wonder, through the agony of his mother, the filmmaker does not get rid of the feeling of being misunderstood, despite international recognition.', '/lfILgYLG3iipjJ046YLImiSPVA7.jpg', '2021-10-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14578, 'Le soir où j''ai reçu le César 2022', 1091152, NULL, '/fSO09vPqJlcVcCvQgazpzCytZIc.jpg', 'Le soir où j''ai reçu le César 2022', 'Receiving a César is a defining moment in an actress’s or actor’s career. Eleven actresses and actors take part in a mirror exercise and, years later, revisit the footage of the ceremony where they were honored. They rediscover the emotion, the laughter, and sometimes the regrets of that unforgettable moment.', '/qBcpnb1mlQkPoKh4z92xHq21Ki6.jpg', '2022-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14579, 'Strange Affair', 12266, NULL, '/ettXOIDHXdqnTa92JDt9RAbVEym.jpg', 'Une étrange affaire', 'A young Parisian advertising executive becomes so captivated by the unsettling charm of his mysterious new employer that he eventually abandons his family and friends, viewing it a privilege to let the ubiquitous employer take over his home, his life, his desire. Only his wife remains suspicious, recognizing both the pathos and the evil in the man’s soul-stealing power.', '/nf6OzJJQnTMD71yhvhkvldEkkab.jpg', '1981-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14580, 'The Young Lieutenant', 12455, NULL, '/gNlJjYsfOYj7X7jGx9uW1nkzn40.jpg', 'Le Petit Lieutenant', 'A rookie policeman from provincial Le Havre volunteers for the high pressure Parisian homicide bureau and is assigned to a middle-aged woman detective.', '/eIjrRfBacqZ1XbGbwbHtYVauBHj.jpg', '2005-08-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14581, 'The Price to Pay', 13045, NULL, '/65ts1lojgafFFsfIJIybb5IGzsA.jpg', 'Le Prix à payer', 'Jean-Pierre, a wealthy businessman, is lonely. He still desires his wife but she only seems interested in shopping and the beauty salon. Tired of lunching alone every day, one day he decides to invite his chauffeur to join him, and a relationship quickly develops as the two find they have much in common. Are they just cash machines for their wives? Don''t they deserve some love in return? Jean-Pierre confiscates his wife''s credit card, but things don''t turn out exactly the way he''d hoped...', '/AbFKuolhEAVcLOgx4iPXlpf4aZn.jpg', '2007-04-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14582, 'Venus Beauty Institute', 33491, NULL, '/5bM4eG1c3hSsyb7aBpmeKzF9htS.jpg', 'Vénus beauté (institut)', 'Aging beautician Angèle, already wounded by a long-ago romance, gets awkwardly dumped at a train station. Witnessing how she turns around a humiliating situation, younger sculptor Antoine becomes so smitten that he breaks up with his fiancée and sets out to win Angèle''s heart. Meanwhile, Angèle attempts to quash the budding romance of her young co-worker, Marie, and a much older widowed client, despite their obvious rapport.', '/nQIv4yTGmjk3ZLnK9CWUiIu66R1.jpg', '1999-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14583, 'Michou d''Auber', 14650, NULL, '/5eqzEQ2PyclVUxeZuhwlpyUOPTR.jpg', 'Michou d''Auber', 'Set in France during the struggle for Algerian independence, Messaoud''s mother is terminally ill and his father, needing to work long hours in the factory, can''t look after him, so decides to put him and his older brother Abdel in foster care. Sent to the countryside, Abdel has to work on a farm, but Messaoud is taken in by a childless woman, who conceals his Arab origins from her fiercely Gaullist ex-army husband. Re-named Michel/Michou, and with his hair comically dyed blond, the young boy quickly steals the hearts of both foster-parents, and eventually is instrumental in saving their troubled marriage.', '/jsJf0DhTmfOVHJ9AMvhVPieG1yI.jpg', '2007-02-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14584, 'Tomorrow''s Another Day', 15329, NULL, '/dzvA3E27k51YGVU8mKydVhIoDtS.jpg', 'Ça ira mieux demain', 'A group of Parisians frets over the minutiae of life in the course of one week.', '/3WbRApGaCpeTXbxxGcYG29n7MDi.jpg', '2000-11-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14585, 'A French Gigolo', 15460, NULL, '/vxQxIAQ9ErYO17crT9bm2qIwLcV.jpg', 'Cliente', 'Marco leads a double life. As Marco, he is a construction worker but rich ladies craving sexual excitation know him as Patrick. As Marco he is married to Fanny, an ambitious young woman who has opened her own hairdressing salon in partnership with her friend Rosalie. Marco/Patrick is not a male prostitute at heart: in fact he does the job in order to support his wife''s business. Which doesn''t prevent Judith, an elegant tele-shopping presenter who buys his services, from falling in love with him. But when Fanny learns what Marco does and with whom, she first gets mad but soon starts interfering in their affair.', '/7VXfz9WqmAqWqW25O5G9YM1yXb6.jpg', '2008-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14586, 'Paparazzi', 62134, NULL, '/sQGQYylQ1qKEej8Sy7wHlYcYcf9.jpg', 'Paparazzi', 'Franck shows up in a gossip magazine photo behind a brawling TV star at a football match.', '/xVQVOMqyCdJGujMbz0lKmBYHEf2.jpg', '1998-04-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14587, 'Les Enfoirés - Les Enfoirés en chœur de 1985 à aujourd''hui', 371443, NULL, NULL, 'Les Enfoirés - Les Enfoirés en chœur de 1985 à aujourd''hui', NULL, '/t5yGRHGRC84duZ6hY2ToNqQVUeH.jpg', '2014-12-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14588, 'Solemn Communion', 198517, NULL, '/2oQCrrEijzG1oHERQ8ClhszUpcl.jpg', 'La Communion solennelle', 'In this complex chronicle of the evolution of a provincial family''s life, the story follows three generations of at least two neighboring families from the 1890s to the 1970s. In one of many related tales, a man who was engaged to the older daughter of a farmer elopes with the younger one. After many years and the birth of five children, the man leaves his wife and family for the bright lights of the city but continues turning up from time to time, until he is finally taken into the home of one of his sons when he is a quite old man. The complex interactions of the legitimate and illegitimate children of a womanizing miner give rise to yet another set of related stories.', '/82LbdB4WX0lO5J5IVNvhCrxiVLo.jpg', '1977-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14589, 'Nicole Garcia, actrice-cinéaste', 1112565, NULL, NULL, 'Nicole Garcia, actrice-cinéaste', 'Stage actress turned film actress and director, Nicole Garcia has worked with the greatest French directors. Mysterious, singular, elegant, she has become a major figure in French cinema, but in her forties, she wanted to tell her own stories.  She took a big risk when she was being offered fewer roles as an actress and became a film director.', '/39mUuIdcC4E6Ell334ZxRPmAOLK.jpg', '2023-04-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14590, 'France Boutique', 64207, NULL, '/w3Zp0wrCY6C5w2PgSa6oPf8h9k9.jpg', 'France Boutique', 'Francois Cluzet and Karin Viard are the couple behind a French shopping channel whose business and marriage are both drifting towards the rocks, with Nathalie Baye as a smiling Rottweiller out to steal their business by conning them into offering a duff product, the ''Fear Eliminator,'' and picking up the network for pennies in the ensuing financial fallout.', '/kSMwpIPGmFVrY1m1Q1jWxJbpT1f.jpg', '2003-10-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14591, 'Feelings', 18461, NULL, '/kezMULHihevYWIRTQqHsKzZXPMn.jpg', 'Les Sentiments', 'Two seemingly happily married French couples are forced to contend with a number of issues.', '/AnC4jgDCyoOZwVzA70bXQ3Uvz7x.jpg', '2003-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14592, 'An Affair of Love', 46991, NULL, '/uBcGJXygtbLm67jw50yvd43f1UH.jpg', 'Une liaison pornographique', 'A man and a woman meet to fulfill her sexual fantasy.', '/6VcPf4jOrlKcB4CDNZUHc36loSm.jpg', '1999-09-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14593, 'The Red Shade', 67553, NULL, '/nbwINFMStLN9SgdlWKtIAUAKtBf.jpg', 'L''Ombre rouge', 'The time is the 1930s and two Soviet spies (both Frenchmen by nationality) have been helping Communist factions during the Civil War in Spain. It is the time of Stalin''s iron rule in the USSR, and the two agents are suddenly called to Moscow by the KGB. Knowing that they are in trouble for no fault of their own, fear drives one of them to suicide while the other gets his lover and her child and begins a run for his life, knowing that the KGB will never let him go free.', '/wLl5mSHR7YHs0Q7e2N0Rxy7jrbj.jpg', '1981-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14594, 'Beautiful Lies', 51072, NULL, '/d187LYnwu7KzyPKgaQRnSWKrIbq.jpg', 'De vrais mensonges', 'A hairdresser forwards a passionate love letter to her widowed mother.', '/s59yijelLaTRB17L9WTwY0UOn6l.jpg', '2010-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14595, 'A Week''s Vacation', 71586, NULL, '/ajDUkQbaMLopIX3YRtSg02swTuf.jpg', 'Une semaine de vacances', 'On the verge of an emotional collapse, schoolteacher Laurence takes a week off from work to figure out her life. She reconnects with friends and family and wrestles with everything from whether she should continue her job to whether she should have a child with her boyfriend.', '/lJThC4TqiXhR9nFyk6zhQorwB3a.jpg', '1980-06-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14596, 'Detective', 52710, NULL, '/yw2JsmZnK27Ak31aAxQHqP2KmO3.jpg', 'Détective', 'Emile Chenal and his wife, Françoise, leaned on boxing manager Jim Fox Warner to cough up the considerable sum of money that he owes them, with both the police and the mob circling the situation. In the same hotel, Inspector Neveu looks into a murder that took place years before, and his storyline overlaps with the arc of the Chenals.', '/5olbP0zwKKYMPW2ZZSFNfLYcFHl.jpg', '1985-08-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14597, 'Rat Race', 51437, NULL, '/oOEXHGn2yRAZY8yO2Tit0ZaZuvI.jpg', 'Je vais craquer !!!', 'Young dynamic executive, married and father of two children, Jérôme Ozendron dreams of writing and escaping a life he considers mediocre. The meeting with a former comrade, who had become an actor, brought him into contact with the world of cinema. He meets, Natacha, a cover girl, for whom he is ready to give up, wife and children. Then he becomes the lover of Lilianne, a marginal who persecutes and pursues him. He quit his job to devote himself to writing a novel. But nothing goes as he wants.', '/aemu6pB04w9Ul7YbvwZ2xeYUpsz.jpg', '1980-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14598, 'Visage', 53520, NULL, '/6FCmPG9knRVSsEdws6s2Aw0CcTv.jpg', 'Visage', 'Hsiao-Kang, a Taiwanese film director, travels to the Louvre in Paris, France, to shoot a film that explores the Salomé myth.', '/xBlH9ZrGWcwifYg4ygNXnQiMsKn.jpg', '2009-10-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14599, 'Fill ''er Up with Super', 76410, NULL, '/5GEEs46HGDsSxycvhagLuzol34M.jpg', 'Le Plein de super', 'When a young auto salesman is forced to give up a vacation with his wife in order to drive a big American car to its new owner who lives on the Riviera, he makes the best of things. First, he gets and old friend to ride along with him. Then, the two of them are joined by another pair of men who want to ride south.', '/jGiF3i4V4XsiellWB5LgWtSBgrM.jpg', '1976-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14600, 'Together''s a Crowd', 53980, NULL, '/oBYc38ic1xxkYYX88pQwMPzncrK.jpg', 'Ensemble c''est trop', 'Imagine, if you will, a somewhat contented married woman finding out her husband''s infidelity during the celebration of a birthday party. That is what happens to Marie-France, when her husband, Henri, pulls out panties from his pocket to be used as a handkerchief. Marie-France becomes furious, storming out of the house. His son, Sebastian and his wife, Clementine, a struggling couple, decide to take Marie-France to their tiny apartment, something they feel it is a temporary arrangement. Little did they know what they were getting into...', '/OGkzl0rvx6s88n5OtSj7pkbWat.jpg', '2010-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14601, 'Absolutely Fabulous', 75118, NULL, '/fFklgaA69EQovQzNkOp0TAwoIdD.jpg', 'Absolument fabuleux', 'Middle-aged best friends Eddie and Patsy live in an endless haze of drugged, drunken selfishness. The duo leave no impulse unenacted and no lust unsated — be it for sex or the latest in designer clothing. Waking up from a night of drunken debauchery, the two dip right into a feast of champagne and caviar, much to the irritation of Eddie''s elegant mother and her resentful daughter. As Eddie stretches an appalling pair of leopard-print leotards (complete with matching shoes, purse, and hat) over her massive rear end, she and Patsy learn of a handsome young rollerblading delivery boy who quickly becomes the object of their lust.', '/uwbTExTl2bAhey2bUJewq1Kedza.jpg', '2001-08-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14602, 'Barnie''s Minor Annoyances', 56625, NULL, '/qzYeWgYPZNALHXqYlyoK8n3m7kh.jpg', 'Barnie et ses petites contrariétés', 'Barnie lives in Calais but works in London. Everyday, he takes the Eurostar to go to his office. Although he is married to Lucie, Barnie has two lovers in London: Margot, a young and fresh advertising executive, and Mark, a hot 35 years old auctioneer. Everything could work out fine like that, until Margot, Mark and Lucie separately offer Barnie the same birthday present: a return ticket to Venice on the Orient-Express, and on the same dates. What will Barnie do? Who will he choose to go with? After thinking that going with Lucie could actually save his marriage, problems are not over: Margot and Mark both show up at Barnie and Lucie''s house, pretending to be a couple, and asking Barnie for some explanations. Which he obviously can''t give...', '/AirxwUaEklmhVMnTtId6U0583Am.jpg', '2001-02-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14603, 'The Mouth Agape', 93672, NULL, '/24izo7vjdYhCA2LUlMELN5EChst.jpg', 'La Gueule ouverte', 'Monique is dying of cancer, lying in bed in the apartment above the store her family owns. Her philandering husband carries on with life, her son remains aloof, and her daughter-in-law wonders if she is witnessing her own decline. They all struggle to express, or feel, their love for one another.', '/lOdKDFF6RhlbVKiLJNIxHoNPD8S.jpg', '1974-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14604, 'To Mathieu', 57728, NULL, '/7Gcd1RyUUX5VZOFJeAkdw6EbFkb.jpg', 'Selon Matthieu', 'Matthieu and Eric are two brothers who work at the same factory as their father in Normandy. When his father is dismissed for smoking on the factory floor, Matthieu is incensed and tries to have him reinstated, in vain. His brother has just got married and, with a child and mortgage on the way, is reluctant to stir up trouble...', '/rRByWOHJIOMoWAV7Ek3y7wPthWl.jpg', '2001-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14605, 'The Slap', 76198, NULL, '/mFEkMTRjknsXbRJVQTnvg9uv2zo.jpg', 'La Gifle', 'A Parisian teacher loses his cool when his teenage daughter tells him she plans to drop out of school and move in with her boyfriend.', '/jV7ZW36smhVjjRWoBhFDIEBqqiT.jpg', '1974-10-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14606, 'My Son', 76268, NULL, '/wgAJEPePFXdE7TjBWH0o8PPiYUd.jpg', 'Mon fils à Moi', 'Julien and his mum care for each other very much. But Julien has committed a deadly sin: he is growing into a teenager! Worse, he has found himself a girlfriend of his age. "Mummy" is not going to tolerate such an ignominy. Julien is HER baby and will remain HERS for ever, encouraged in her "crusade" by her bovine husband and barely thwarted by the more courageous interventions of Suzanne, Julien''s sympathetic big sister.', '/sNcmkD0aowU3yD9TF5v2duoHPdx.jpg', '2006-03-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14607, 'One Stays, the Other Leaves', 59565, NULL, '/z6X3nUz1ZmbkRImUpvRcUMF9j7m.jpg', 'L''un reste, l''autre part', 'A story about two couples, longtime friends in which both husbands engage in long-term affairs and, as the title says, ultimately one remains with his wife and one makes a new life with another woman.', '/ifkKLivTgs3TdygZL1LqRn4g9BH.jpg', '2005-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14608, 'Our Story', 58619, NULL, '/sOgXX1rsw01UeDN808d9T2F9XBZ.jpg', 'Notre histoire', 'Robert Avranche, a middle-aged, alcoholic garage owner, is sitting on a train, reflecting on the emptiness of his life. An attractive young woman, Donatienne, suddenly enters the compartment and offers to make love to him. Robert accepts but, when the woman leaves the train afterwards, he decides to follow her...', '/vhceLoMLFlyqd53NaEduPGazQ1g.jpg', '1984-05-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14609, 'C''est La Vie', 77672, NULL, '/y05Y9zyVcJqEMhXAN7hKm4JyL9O.jpg', 'La Baule-les-Pins', 'A story is about young teenage girl, with sister and brothers, a pleasant uncle and aunt, an annoying nanny, a young boy interested in kissing her, a close relationship with the imaginary addressee of her daily diary and her parents'' disintegrating marriage - all this in a rented house in a summer resort.', '/AjxFVDmOWFbHDmIP93waiFYBBbO.jpg', '1990-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14610, 'Off and Running', 58943, NULL, '/udkwQy662jn5DcvP6aXP4oIUNPI.jpg', 'Passe passe', 'A missed highway exit leads Darry Marzouki, an unemployed magician, to cross paths with Irène Montier Duval, a wealthy woman carrying a Hermès bag full of cash. Out of love, she acted as an intermediary in an arms deal between a French minister and Korea. When the deal was exposed, the minister tried to pin the blame on her. On the run, she offers to pay Darry to drive her to Geneva in his BMW.  The problem? The BMW isn’t his—he impulsively stole it from his hot-tempered brother-in-law, who’s out for blood. Unable to accept Irène’s offer, Darry pretends to be an activist heading to a summit in Locarno. Irène, eager for a change, plays along.  They have little in common but spend three unforgettable days together—while being chased by Koreans, French intelligence, a minister, and the furious brother-in-law. In the end, one finds love, the other freedom.', '/lkv0vO6c5Qlf3TT8xkuiSfE9UCp.jpg', '2008-04-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14611, 'Enfants de salaud', 77872, NULL, NULL, 'Enfants de salaud', 'Sylvette, a sassy waitress, Sandro, a macho guy, Sophie, a shy bourgeoisie, and Susan, an American actress, do not know each other and do not have much in common. However, they all have the same father, a scammer named Julius.', '/kj7leE46xJjceqRym41ijZHkSng.jpg', '1996-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14612, 'I''ve Been Waiting So Long', 78692, NULL, '/lN72ZEq6f558m4QGkfF42JxDftq.jpg', 'Une vie à t''attendre', 'A married Frenchwoman living in Brazil returns to her native country to visit her ailing elderly mother. There, she ends up rekindling a love affair with a man whom she hadn''t seen in twelve years.', '/nawQTnQ1BfFswTldkVqBu8yamNB.jpg', '2004-03-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14613, 'Small World', 59112, NULL, '/c6JEc0Ia4lSm30FrfHmS2NNtBSk.jpg', 'Je n''ai rien oublié', 'Conrad Lang, a handyman in a rich family - he has been raised like a brother with Thomas, who has the same age -, accidentally puts fire to the big holiday house he keeps. He returns to the town he grew up in, to the family home, where Philippe, Thomas''s son, and Simone are getting married. Conrad''s frequent memory loss and behavioural problems rapidly reveal a neurological disease (Alzheimer''s is suggested by doctor Cohen when he examens Elvira) which leads Elvira, Thomas''s stepmother, to install Conrad in a guesthouse on the property, with the help of a nurse. When Conrad looses more and more his landmarks in present and past, memories of his youth come back to surface. They intrigue Simone, since these memories do not entirely fit together with the official family history...', '/tfNRiVFQ39hLheSlGrlmyhBXtTY.jpg', '2010-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14614, 'La Californie', 79034, NULL, NULL, 'La Californie', 'Mirko and Stefan, Serbian refugees, move to the French Riviera. There they meet Maguy who lives in a luxurious mansion up the hill above Cannes with an odd group of friends.', '/bTPcibZ37nLlHjsOA2hrBwtWOVd.jpg', '2006-05-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14615, 'La Balance', 86404, NULL, '/A1ZHzJIskmiigtgvadHaoBYkJ1g.jpg', 'La Balance', 'A Paris police detective plays rough with a prostitute and her pimp/lover, whom he wants as an informant.', '/zQ5OfelytoqlK5o7hPAtgISkJQa.jpg', '1982-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14616, 'Honeymoon', 89736, NULL, NULL, 'Lune de miel', 'A Frenchwoman in Manhattan, in danger of being deported because of her relationship with a recently arrested drug offender, enters into a marriage of convenience with a stranger that is arranged through an agency. But even though the two are not supposed to even meet, her new husband starts taking his faux wedding vows entirely too seriously.', '/pO2eCgU4m4gFEAEqPWXy0EQ9vP5.jpg', '1985-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14617, 'Laurence Anyways', 110160, NULL, '/lNUP9ymEHolzjLIHyoAkpHRQZxq.jpg', 'Laurence Anyways', 'The story of an impossible love between a woman named Fred and a transgender woman named Laurence who reveals her inner desire to become her true self.', '/d8BpJ9qOQE7VFFqaV1XDdGfMsP7.jpg', '2012-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14618, 'L''Inconnu', 950250, NULL, NULL, 'L''Inconnu', 'The descent into hell begins for Edouard, a disillusioned marginal, when he loses his job, and his wife leaves with his son. His meeting with a mysterious stranger, who claims to work for the secret services, leads him to commit the irreparable. Was it a trap or just a symptom of his madness? There is doubt...', '/6FWP45M0sNG6JNGfLwqiBRdz92i.jpg', '1973-12-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14619, 'Every Man for Himself', 113479, NULL, '/p8NHG9uNXn7MSrknNk0LbBjJxQc.jpg', 'Sauve qui peut (la vie)', 'A look at the sexual and professional lives of three people — a television director, his ex-girlfriend, and a sex worker.', '/hA69SHZQ3jixYq2wykoTlH2VgjI.jpg', '1980-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14620, 'Marie-Octobre', 145249, NULL, '/dDilG86m7x7quOAPR43gDC0376z.jpg', 'Marie-Octobre', 'After the Liberation of France during the World War II, ten former Resistant fighters meet again during a dinner organized by Marie-Octobre...', '/n5DHIUW9ypzyBstwEyHypWy8M0q.jpg', '2008-10-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14621, 'Mensonge', 164025, NULL, '/9XQCEF2GIso8jqLVX8ceVBv8Nxw.jpg', 'Mensonge', 'Emma has been happily married to Charles, a hardworking journalist, for over ten years. They have a son, and are considering having another child when she learns that she is both pregnant and HIV-positive at a time when Charles is away. As Emma has never used drugs or slept around, and has never had a blood transfusion, there can only be one source for her infection: her absent husband. Shocked to the core by this turn of events, she goes through his things and finds an address book with the names of many women in it. Determined to discover what has been going on, she begins contacting every name in the book. She continues her investigations even after her husband, whom she confronts over this, returns.', '/yfPnKkBdTgGo7mqJYcBVCeBWmVN.jpg', '1993-05-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14622, 'Queens of the Ring', 202215, NULL, '/x03CGbRA29WqmtxDcGBUFS71bZo.jpg', 'Les reines du ring', 'More than anything, 30-year-old Rose longs to be reunited with Mickaël, her estranged 11-year-old son who has been placed with a foster family and blames his mother for their long separation. When she discovers that Mickaël is crazy about wrestling, Rose thinks she''s found a way to melt the ice: she''ll put together a tag team with three girlfriends from the store where all four work as checkout girls...', '/tattcNlGtbIcK7iQguVED1j6sMJ.jpg', '2013-07-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14623, 'Mother Valley', 967549, NULL, '/8zIL0AAu0XnsxRetFxplglLXici.jpg', 'La Nuit du verre d’eau', 'In 1958, while revolution is rumbling in Beirut, three sisters spend their holidays in an isolated village of Lebanese mountains: rebellious Nada, romantic Eva, and the eldest Layla, a good woman, beloved by everyone. But the war threatens and the sudden entrance of two French summer vacationers leads Layla to revolt against patriarchal society.', '/a8M4MimsldfdSyxNnys194CMDFO.jpg', '2023-06-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14624, 'Beware of My Love', 172973, NULL, NULL, 'Si je t''aime, prends garde à toi', 'Muriel, a writer nearing 50 whose older lover won''t live with her in Paris, meets a man on a train - Samuel, an Arab. He''s attracted to her and pursues her, dropping in, asserting himself. She''s willing to connect. He''s passionate, then boorish, then jealous and possessive. He seems fixed on "Who''s the strongest?," while she wants respect and trust. She''s self-possessed as well as sexually charged, willing to laugh, and alternately firm and forgiving. He has little money, no immigration papers, few prospects, and a gambling jag. What does each want, and why does she stick with it? Is this colonial strife, war between the sexes, or a love story?', '/ebMAYFXpb8xVb31uSOgMnv1qpKb.jpg', '1998-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14625, 'The Machine', 197537, NULL, '/ypcCh1fFMy9UaXV0PQdWENfqpEy.jpg', 'La Machine', 'This deftly made French psychological thriller terrifies with its exploration of an experiment gone horribly wrong. Dr. Marc Lacroix, a psychiatrist specializing in brain functions, is obsessed with the link between mind and spirit. To find his link he studies the criminally insane. He builds a secret machine, known only to his mistress Marianne, in which he hopes to exchange minds between humans. He simultaneously wants to help the mentally ill recover, and he wants to experience their madness. He chooses the psychotic killer, Zyto, a man who stabbed at least three women, for his experiment. The initial experiment is successful and the two exchange minds. But trouble ensues when Zyto refuses to reverse the switch. There is little Marc can do when Zyto takes over Marc''s life, and more ominously his wife and child whom are unknowingly in mortal danger. Marc, encased in Zyto''s body, is returned to the asylum. Will Marc''s wife recognize the danger? Will Zyto kill again?', '/8w1Szh5ZueTtD4Rcg4E5AxNCezT.jpg', '1994-05-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14626, 'Alibi.com 2', 967585, NULL, '/isihZ8cM9nr5JGNn8yU9l7yYxN3.jpg', 'Alibi.com 2', 'After closing his agency Alibi.com and promising Flo that he would never lie to her again, Greg''s new life became quiet, too quiet... Not for long! When he decides to propose to Flo, Greg is up against the wall and has to introduce his family. But with his crooked father and his ex-charm actress mother, this could ruin his future union. He has no choice but to reopen his agency with his former accomplices for an ultimate Alibi and to find more presentable fake parents.', '/u2IgcRl1q5iDoag5xBYR4q51gJW.jpg', '2023-01-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14627, 'Every Other Weekend', 213917, NULL, '/wdaGFYhjzpp4UFudVXofftHuOvI.jpg', 'Un week-end sur deux', 'Camille, a mercurial César-winning actress, has seen better times. Estranged from her husband, she''s with her children only every other weekend. It''s her weekend, but her agent has booked her to MC a Rotary club dinner in Vichy. She takes them with her, and when her husband learns this, he demands to pick them up at once. She bolts in a rented car to the seaside, trying to improve her relations with the children, especially the precocious and distant Vincent. He loves astronomy. A rare meteor shower is due in a few days, so she suggests they go to a plateau in Spain hoping to see it. He agrees, but the relationship remains difficult, and her husband is on their trail.', '/gnFCn8qaZzADt57XFmMrKo6FAZ1.jpg', '1990-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14628, 'Rive droite, rive gauche', 211923, NULL, '/o4cURc2ysIbmlDWd54uALhxvHvR.jpg', 'Rive droite, rive gauche', 'Longtime friends Guarrigue and Sénanques own a successful law practice in Paris. The dreaded businessman Pervillard is one of their clients. One night, Sénanques, who is in an unhappy relationship, meets Sacha. For her sake, he causes a political scandal involving Pervillard and puts himself in danger.', '/wwvvohYdwpNxOnP3JLsSMGxb4Vv.jpg', '1984-10-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14629, 'Godard by Godard', 1122965, NULL, '/51uIx1VkBwsNVWsJetqE7cA1Vav.jpg', 'Godard par Godard', 'Godard by Godard is an archival self-portrait of Jean-Luc Godard. It retraces the unique and unheard-of path, made up of sudden detours and dramatic returns, of a filmmaker who never looks back on his past, never makes the same film twice, and tirelessly pursues his research, in a truly inexhaustible diversity of inspiration. Through Godard’s words, his gaze and his work, the film tells the story of a life of cinema; that of a man who will always demand a lot of himself and his art, to the point of merging with it.', '/bT3dDMz11CwtF8IdakwG0ILpyYu.jpg', '2023-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14630, 'No Harm Intended', 224887, NULL, '/gVlEs2V40CT2PP0CW9Bnbe8hr1a.jpg', 'En toute innocence', 'When Catherine is caught with her illicit lover by her father-in-law Paul, the concerned father leaves to tell his son Thomas about the incident. Paul is injured in an auto accident and returns home in a wheelchair unable to speak. Catherine''s guilt weighs heavily on her as she hopes to never let Thomas know she was unfaithful. She panics and seeks a way to eliminate Paul in this psychological thriller.', '/jFQW6IlE87vjYtHX5iWiAa7MyNb.jpg', '1988-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14631, 'Soirée Pyjama', 1180778, NULL, '/s1au6F4PaXMcDDEnUDbujIC5LoF.jpg', 'Soirée Pyjama', 'To celebrate 2019, Barthès & Dedienne are hosting a sleepover with some friends.', '/dOqbtbMgqRy6lkDsexE4ok2BRTU.jpg', '2019-01-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14632, 'The Honeymoon Trip', 453628, NULL, '/t9UlRlMWgP5yFsc90Ld2q8JAvGR.jpg', 'Le Voyage de noces', 'Paul and Sarah form a happy couple with no problems. But when Sarah sees Paul wrapped in the arms of a young woman her peaceful happiness collapses. She in turn takes a lover. Paul realizes that he''s losing his wife and proposes a second honeymoon in Morocco...', '/j1GEh37EoFugWmjAApAoFRPTCzv.jpg', '1976-04-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14633, 'Faustine and the Beautiful Summer', 259903, NULL, '/3eEspSl5YOeAJsFNMN6ypRyt6Eq.jpg', 'Faustine et le Bel Été', 'Faustine suffers the wounds of first love. During a summer when she is staying with her grandmother, she comes to know the nearby neighbors. Two brothers live in the large house. One is divorced and one has recently remarried, both of them live there with their teenaged and adult children. Though the boys of the household are drawn to Faustine, she grows ever more smitten with the divorced older man...', '/bIomX5LwnsmcZkXtUWRfWxrfQaG.jpg', '1972-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14634, 'Engagements of the Heart', 267079, NULL, NULL, 'De guerre lasse', 'Alice is the widow of a Jewish surgeon who helps the former diplomat Jerome smuggle Jews out of Austria to save them from the Nazis. The duo recruits Charles, a shoe manufacturer whose uncle is a Nazi sympathizer in the Vichy government. Charles and Alice become lovers when they are picked up in Paris by Nazi soldiers on a curfew violation.', '/w6lQBfjcgdm6I17vdZC9ltAuny1.jpg', '1987-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14635, 'Lou!', 294463, NULL, '/maKP1cgu7yZr6ZZ793u7GSHReXS.jpg', 'Lou ! Journal infime', 'Lou, a creative and dreamy 12-year-old girl, lives alone with her mother in an orange building with tons of little balconies that give access to the roof. Mina has been her best friend since kindergarten, and Lou has been in love with Tristan, one of her neighbors, since elementary school. Her mother has relinquished her own personal happiness of late so as to devote herself to her daughter, but their little bubble bursts when Mom meets a man and Lou at last dares speak to Tristan.', '/k9BiIFPSwzgSeKcc95LSLWHD6CM.jpg', '2014-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14636, 'Beethoven''s Nephew', 42043, NULL, '/cqhBGxe8duwKCSrJbxFHemF4ft4.jpg', 'Le Neveu de Beethoven', 'The plot centers around old Beethoven''s fixation on the welfare of his nephew, for whom he fought a lengthy custody battle against his brother''s former wife. Beethoven thought she was a bad influence on the boy. Sadly, the nephew isn''t receptive to Beethoven''s "overtures", and resents his boorish uncle''s efforts on his behalf. The nephew is a complete nonentity, lacking in both interest and talent. He seems to wish only to be left alone.', '/D7fEBBQKw55ANU0rwQOklacPel.jpg', '1985-09-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14637, 'SK1', 307103, NULL, '/epZEeCqidRtSBCerlsKW4ZeuMeD.jpg', 'L''Affaire SK1', 'The hunt, capture and trial of Guy Georges, one of France''s most notorious serial killers.', '/h4IU1VPMj2g4WkeiF1Nm8dFxCBM.jpg', '2015-01-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14638, 'Xavier Dolan: Bound to Impossible', 594120, NULL, NULL, 'Xavier Dolan: à l''impossible je suis tenu', 'Actors Anne Dorval, Suzanne Clément, Monia Chokri, Gaspard Ulliel, Vincent Cassel, Niels Schneider and Melvil Poupaud discuss working with the young Canadian director Xavier Dolan, who has conquered the hearts of both cinema lovers and prestigious festival juries with his films. To French actress Nathalie Baye, he seems very experienced despite his young age, while Cannes Director Thierry Frémaux says he may be insolent, but everyone agrees he is passionate, creative, a perfectionist and... in a hurry.', '/pdseRIjlGKqO2wThv84YYYYbrv8.jpg', '2016-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14639, 'It''s Only the End of the World', 338189, NULL, '/rsQBqWu6QgAnJmRnpbZu0rC5C7V.jpg', 'Juste la fin du monde', 'Louis, a terminally ill writer, returns home after a long absence to tell his family that he is dying.', '/riWa3WZrO3n8lLWuaEVMgaqAZGn.jpg', '2016-09-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14640, 'Un jour, la fête', 533699, NULL, NULL, 'Un jour, la fête', 'Michel returns from a trip. He meets up with his friends from the H.L.M. housing estate. Together, they have set up a meeting place. The developer has the place demolished. Furious, instead of rebelling, the friends organize a party in the housing estate. The party gets off to a good start, but a tragic event interrupts it...', '/bNmPxLuqkzwr09QRk42suN9y1NC.jpg', '1975-02-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14641, 'Bacri, comme un air de famille', 927095, NULL, '/9yiHd3vTWdEz5FMicpjau9gk6pj.jpg', 'Bacri, comme un air de famille', 'Jean-Pierre Bacri was never happy about anything. But beyond the caricature of the grumpy man, from his apprenticeship years to his death in January 2021, this film tells the story of this quintessential Frenchman: a man turned towards others, an actor by accident, a moralist by vocation, who was left unaffected by flattery and false honors by success, and ready for all kinds of anger when it was necessary to speak out against injustice and stupidity. The film tells the story of how Jean-Pierre Bacri''s life changed several times: from Algeria to France when he was eleven years old in 1962; from bank clerk to apprentice theater actor; from Pieds-noirs film star to screenwriter for Alain Resnais; and from Cannes playboy to Agnès Jaoui''s mad lover, the most decisive encounter for his life as well as for his work', '/jtgb4Au21wy5cUmf3I9CVo6Yzc2.jpg', '2022-01-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14642, 'Monsieur Papa', 355333, NULL, '/4cHrGzcNmTWlfIKh8u7XsbPIUW5.jpg', 'Monsieur Papa', 'In this family comedy, Papa has no end of trouble getting his young son to accept his new girlfriend.', '/bMHcbpznA2yluPc7CGnD28rP2nK.jpg', '1977-08-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14643, 'Esquisse d''une jeune femme sens dessus dessous', 1060936, NULL, NULL, 'Esquisse d''une jeune femme sens dessus dessous', NULL, NULL, '1975-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14644, 'The Assistant', 358206, NULL, '/7vJB5o8mVxffpu3CsiwAmAME5kZ.jpg', 'La Volante', 'With his wife in labor, father-to-be Thomas (Malik Zidi) speeds to the hospital, and in the process, accidentally kills a young man on the road. That death sets into motion events that will change everyone’s lives forever, including the young man’s mother Marie-France (Nathalie Baye), who cannot recover from the trauma. Nine years later, Marie-France takes a job as Thomas’s secretary without him knowing about her connection to his past. As Marie-France’s maternal rage reaches tragic proportions, she insinuates herself into his life, his work and his family in this classic thriller à la Hitchcock.', '/lRX31QALsr5CKkXZOYW5SzKEoAZ.jpg', '2015-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14645, 'François Truffaut: The Man Who Loved Cinema - The Wild Child', 386097, NULL, NULL, 'François Truffaut: The Man Who Loved Cinema - The Wild Child', 'A fascinating glimpse into Truffaut’s creative process and how his life informed his art, told from the perspectives of those who knew him best.', '/LumoHEqqcL0t5BzASv3FA2gctt.jpg', '1996-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14646, 'Godard Cinema', 1005409, NULL, '/kcDyzBiXrcpLaVpFVGvRgT7gcxk.jpg', 'Godard, seul le cinéma', 'Jean-Luc Godard is synonymous with cinema. With the release of Breathless in 1960, he established himself overnight as a cinematic rebel and symbol for the era''s progressive and anti-war youth. Sixty-two years and 140 films later, Godard is among the most renowned artists of all time, taught in every film school yet still shrouded in mystery. One of the founders of the French New Wave, political agitator, revolutionary misanthrope, film theorist and critic, the list of his descriptors goes on and on. Godard Cinema offers an opportunity for film lovers to look back at his career and the subjects and themes that obsessed him, while paying tribute to the ineffable essence of the most revered French director of all time.', '/cz5DGkSyAfoe31AY5yV855Lx2zR.jpg', '2023-06-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14647, 'François Truffaut: The Man Who Loved Cinema - Love & Death', 386098, NULL, NULL, 'François Truffaut: The Man Who Loved Cinema - Love & Death', 'A fascinating glimpse into Truffaut’s creative process and how his life informed his art, told from the perspectives of those who knew him best.', '/po0LVJg50pKI6Mzu80CWxPQYtAb.jpg', '1996-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14648, 'Sheila, toutes ces vies-là', 1071146, NULL, '/q9rD0K9E1zU8HjlqHEkxRlQTmRA.jpg', 'Sheila, toutes ces vies-là', 'The portrait of a woman who remembers. Sheila tells the story of Sheila, without concessions or evasions. Her childhood, her parents, her beginnings, the rumors, her love affairs, her marriage, her son, her successes, her farewells, her return, her mourning. The journey of an extraordinary popular icon who never stopped fighting. The courage of an artist who never gives up. "Sheila, toutes ces vies-là" is also a journey through time. 60 years of pop music, punctuated by numerous archives, personal films, timeless hits and illustrations by Marc-Antoine Coulon. But also 60 years of fashion, through a legendary wardrobe (her TV show outfits) that Sheila invites us to rediscover.', '/tNng0G9dK34Nlapb628I3vrCc78.jpg', '2022-12-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14649, 'Short Memory', 164246, NULL, '/qDdjhFmfwsQuaZiRvFMp2IE8Tp0.jpg', 'La Mémoire courte', 'In this thriller, a UNESCO translator stumbles across a group which is hiding and supporting Nazis and facilitating their travel around the world. She had been given an assignment to study the work of a writer who recently had died, and the conspiracy is revealed in materials he left behind. She comes upon a young man who is going through the writer''s papers, and she immediately assumes he must be one of the conspirators. However, he soon convinces her of his innocence in that regard, and the two together begin a search for the ringleader.', '/hryRflGY457W0jakA4HD0ilS54r.jpg', '1982-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14650, 'Préjudice', 363007, NULL, '/1sAFIeMhrOPaqEw4FVoxR6jhcNA.jpg', 'Préjudice', 'A challenging psychological drama where the carefully nurtured harmony of a family is shattered one lovely summer evening. Cédric, who is generally shut away in a world of his own, doesn''t react very well to the happy news of his sister’s pregnancy.', '/ra2brYfSnyQrILKkjkITdsSJQsZ.jpg', '2015-10-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14651, 'The Man Inside', 382223, NULL, NULL, 'The Man Inside', 'Gunter Wallraff is a journalist seeking to expose the unethical journalism practiced by The Standard, a very popular and powerful German newspaper. He goes undercover, using forged identity papers and at great personal risk, to join their staff. Once there, he sees how they don''t just report the news, but manufacture it to suit the personal political agenda of the paper''s leaders.', '/hDf3MWoGVKmeGKcspKy9oxR5l7n.jpg', '1990-10-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14652, 'Les contes sauvages', 388299, NULL, NULL, 'Les contes sauvages', 'A tribute to Frédéric Rossif, the most legendary animal director in cinema, a long animal poem, a walk-exploration through the most secret regions of a little-known continent, the former USSR.', '/reJrKxUOHQqLQy4ioglHqi8ZbaN.jpg', '1993-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14653, 'Alibi.com', 398929, NULL, '/vK5JKdAAeQpz5vbKeyy07XcSGdd.jpg', 'Alibi.com', 'Greg founded a company called Alibi.com that creates any type of alibi. With his associate, Augustin, and Medhi his new employee, they devise unstoppable stratagems and stagings to cover their clients. But meeting Flo, a pretty blonde who hates men who lie, will complicate Greg''s life, which begins by hiding the true nature of his activity. During the presentation to parents, Greg understands that Gérard, the father of Flo, is also one of their clients.', '/8K5dvcXq7Lq2qiE9nkjF1Dht60R.jpg', '2017-02-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14654, 'Moka', 408024, NULL, '/177pdnlXfnyb44JYjJSuEMMcMfO.jpg', 'Moka', 'Diane Kramer is led by one obsession: to find the driver of the mocha color Mercedes which hit her son and devastated her life. With a few belongings, some money and a gun, she goes to Evian, where she''s learned the driver lives.', '/3Ru4aUDCSexnLzz73s1PL40qZui.jpg', '2016-08-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14655, 'The Guardians', 427347, NULL, '/1qM06sCm429nDgzCi4frKB9f5oW.jpg', 'Les Gardiennes', 'In this ensemble drama set in rural France, the women of the Paridier farm are left to run it by themselves while their men are off fighting in World War I. But things become complicated with the arrival of American troops.', '/7nkfTsQrlyVh6r2Jik5hl86OLhz.jpg', '2017-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14656, 'François Truffaut, une autobiographie', 429105, NULL, NULL, 'François Truffaut, une autobiographie', 'A documentary tracing the career of filmmaker François Truffaut through the testimony of collaborators and admirers.', '/mvgo4NTYumDGDdAU2rZXEiKTwND.jpg', '2004-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14657, 'Médée', 450460, NULL, NULL, 'Médée', 'A lonely mother and her son go to the opera where a performance of Cherubini’s opera Medea is given. It is the mother’s birthday and she wanted to surprise her son by inviting him to the opera. But, the son’s plan were different and he is quite upset about it. His mother tries to break the silent barrier behind which he hides. A semblance of discussion begins, not without humour. Tension is present but, as the performance goes on, both find themselves astounded, captured, alone in the opera house.', '/oyb3VtmfqsgH25YCfcI8orIFDYa.jpg', '2017-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14658, 'Hitler in Hollywood', 473621, NULL, '/5xKmt7y8TgiUjRKuvasoKAhAdCb.jpg', 'HH, Hitler à Hollywood', 'A bio-doc about Micheline Presle changes into a thrilling investigation of the long hidden truth about European cinema. This mockumentary thriller uncovers Hollywood''s unsuspected plot against the European motion picture industry. Numerous directors and stars appear in the film, making it a choice morsel for all film lovers.', '/8gvpdZKfj3NYeIoZfwl2ayP9ZME.jpg', '2011-05-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14659, 'Food of Love', 501498, NULL, '/r9OKD40hBdDPQI5yo8MsmhB2C4M.jpg', 'Food of Love', 'A group of ex-university students reunite to perform a Shakespeare play in a quaint English village.', '/x1Xlduh0PI8K8MnvXI5cmnI7VNQ.jpg', '1997-10-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14660, 'God''s Offices', 8901, NULL, '/jQ6Yyp1I2KVRpXv3COwyLvsBqkb.jpg', 'Les Bureaux de Dieu', 'A realist dramedy about dedicated social workers who devote their long shifts to helping pregnant women.', '/2WXWVf94h6TlnInTWsPTCgycLPr.jpg', '2008-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14661, 'Mon Premier Amour', 265578, NULL, NULL, 'Mon Premier Amour', 'This sentimental drama is the story of the relationship between a lovely mother and her 20-year-old son who never really knew her. When he learns that she is dying of leukemia, he tries to get to know her. By the end of the film, the two have reconciled and she dies feeling at peace.', '/vIF32pPIToTLbsP5G7BIlpiv5WA.jpg', '1978-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14662, 'Scénario de ''Sauve qui peut la vie''', 230893, NULL, NULL, 'Quelques remarques sur la réalisation et la production du film ''Sauve qui peut (la vie)''', 'Jean-Luc Godard proposes a diary of his creative process. Looking at photos of three actors, Jacques Dutronc, Isabelle Huppert, and Miou-Miou, who were previously cast to play in "Sauve qui peut (la vie)," Godard speaks about great image makers: Dreyer and Wim Wenders, the painters Edward Hopper and Pierre Bonnard.', '/5mq8b3U3XSiJPOTajMiiCuw8vlK.jpg', '1979-04-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14663, 'François Truffaut: Stolen Portraits', 128743, NULL, NULL, 'François Truffaut: Portraits volés', 'Twenty-six people - including two daughters, an ex-wife, his last lover, actors, fellow directors and writers, a neighbor, and boyhood friends - talk about François Truffaut. They discuss his attitudes toward wealth, his early writings about cinema, the undercurrent of violence in his films and his personality, the way he used and altered events in his life when making films, his search for a father (both artistic and biological), his relationship with his mother, the scenes in his films that cause a squirm of embarrassment, and his ultimate mysticism. Clips from a dozen of his films are included.', '/5XLdflYRN0dltzuYB7CgO8ge6Tn.jpg', '1993-05-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14664, 'The Great Restaurant', 298885, NULL, '/k6MWjhEQ8Yk58ZxPpeiHrUxv9Ka.jpg', 'Le Grand Restaurant', 'Fragments of the lives of the customers of a great restaurant and the inconvenience of its manager.', '/63ZOq85lRkY76J32IHzmi6fUbqc.jpg', '2010-02-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14665, 'My Best Part', 661229, NULL, '/3XVkTNJcPACMIGxA1fK8y59a4xJ.jpg', 'Garçon chiffon', 'Jérémie, a young man reaching a breaking point on all fronts, decides to leave behind Paris and return to Limosin, to the home of his intrusive mother.', '/uG2tIGzwIxYcBOexgZxApdebooi.jpg', '2020-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14666, 'Les Enfoirés 1996 - La Soirée des Enfoirés', 569618, NULL, '/yemH2HKoONbrL1W1kikU9vFypnv.jpg', 'Les Enfoirés 1996 - La Soirée des Enfoirés', NULL, '/tDYGqEbcmXIfYbbX0eWUN4WWhmQ.jpg', '1996-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14667, 'Massacre Play', 417934, NULL, '/j8mLUWYkw3pcInTqgSAflqbWj6O.jpg', 'Gioco al massacro', 'Estranged childhood friends, both passionate filmmakers, find themselves on divergent paths: one an acclaimed Oscar winner, the other struggling in TV. Accusations of plagiarism further strain their relationship as one''s success is built on the other''s stolen ideas.', '/gOUhGXpiGs746tigdzGWOTe6611.jpg', '1989-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14668, 'Haute Couture', 719463, NULL, '/lRFAjHmx5foEU89AaTxj7Ppjvr2.jpg', 'Haute couture', 'Esther is at the end of her career as Head Seamstress at Dior Avenue Montaigne workshop. One day, she gets her handbag stolen in the metro by a 20 years old girl, Jade. Instead of calling the police she decides to take care of Jade. She sees in her the opportunity to pass on her skills, the craft of dressmaking, her only wealth. In the frenetic world of Haute Couture, Esther will give Jade la beauté du geste, a way to reach beyond herself.', '/srN0iA97EfjZReGlGyDNcDh8ZPs.jpg', '2021-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14669, 'Mado', 3424, NULL, '/wkgwj78yAtwrp8tnzYpYChTFDkc.jpg', 'Mado', 'A middle-aged businessman faces bankruptcy after his partner''s suicide and a rival''s unscrupulous offer to buy his company. Determined to avoid the trap, he finds an unexpected solution through a prostitute.', '/J7DbJx6h7cxGcshkJOKag4eq8y.jpg', '1976-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14670, 'Him', 752070, NULL, '/qC3jmpKjt0cXkLiDv9YaGae899y.jpg', 'Lui', 'Lacking inspiration, a composer isolates himself at a desolate house, on a small island, in Brittany. There he finds an old piano and receives visits from people who won''t let him rest.', '/73hv4MR4LZSWD2nM0qfjG7Z2rvD.jpg', '2021-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14671, 'Bon vent Claude Goretta', 655893, NULL, NULL, 'Bon vent Claude Goretta', 'Claude Goretta directed “L''invitation” in 1973. For filmmaker Lionel Baier, born in 1975, it is like a “travelling companion”, to adapt Serge Daney’s expression. He feels it is definitive proof that a Swiss can be deeply Chekhovian. The young filmmaker goes to Geneva to ask his elder how he achieved the whoosh of water effect in the film, why attention to detail matters so much, and how to film great actors such as François Simon. This encounter with Claude Goretta – but also with Isabelle Huppert, Nathalie Baye, Michel Robin and Frédérique Meininger – leads one of the greatest of Swiss filmmakers to open up about his work.', '/9DDutqZnarHbuXbbbehDEHaZHFD.jpg', '2011-08-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14672, 'Voyage à travers un film (Sauve qui peut (la vie))', 780397, NULL, NULL, 'Voyage à travers un film (Sauve qui peut (la vie))', 'A televisual journey guided by Jean-Luc Godard inside his film Sauve qui peut (la vie), incorporating filmed conversations between him and Isabelle Huppert and the film critic Christian Defaye.', '/ouvi2BrFcfqDQUJYYMWmL3Dzki.jpg', '1981-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14673, 'Acteur', 799872, NULL, NULL, 'Acteur', 'A look at the world of acting: is it possible to go from the shadows to the limelight without losing one''s soul?', NULL, '2007-03-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14674, 'The Voice', 534102, NULL, NULL, 'La Voix', 'The tale of two lovers spending time in Rome when, suddenly, in a restaurant, the man believes he recognizes the voice of a woman he once loved... remembrances and dreams of past love ensue.', '/vJFkLXx6WwPDGuyPHglpYRd0Sbs.jpg', '1992-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14675, 'Conversation avec Nathalie Baye', 848749, NULL, '/uSv5izlexxkxDNZGyV5M5e7ZCcC.jpg', 'Conversation avec Nathalie Baye', 'Xavier Beauvois'' documentary-style filming techniques, her collaboration with François Truffaut, Xavier Dolan''s masterful tone... Nathalie Baye looks back on her roles in "Le petit lieutenant," "La chambre verte," and "Juste la fin du monde" as they are broadcast on ARTE. A conversation hosted by Olivier Père (Managing Director of ARTE France Cinéma).', '/9wg5kmcpp5vdpzcSwkHcPwQYYU2.jpg', '2021-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14676, 'La provinciale', 263581, NULL, '/rfBddJYqGM6js8CNclavi6jdVcr.jpg', 'La provinciale', 'When Christine, young and out of work, arrives in Paris without money, a job or support, vulnerable and ignorant of the rules of the game, she seems to be an easy victim. But she is determined not to let herself be destroyed.', '/NUOs4TlDHDkHpOdHPe57hD3wp4.jpg', '1981-01-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14677, 'A Day in the Life of French Cinema', 1359804, NULL, '/8xWKWFeH7c7eIfcARJYmcsf8ylT.jpg', 'Un jour dans la vie du cinéma français', 'Documentary showing one day of work of over 90 actors and filmmakers from French cinema on the same day. On 27 March 2002, 27 teams filmed actors, directors, producers and technicians at work, from Hawaii to Paris and from New York to Lisbon.', '/aIDpejRH0TkNQNz7hJ0EJKErnW2.jpg', '2002-05-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14678, 'Madame Sourdis', 1378008, NULL, NULL, 'Madame Sourdis', 'Adèle lives in the shadow of her husband, Ferdinand, a painter. After her father''s death, they leave the provinces for Paris. She refines his paintings and comforts him. Thanks to her brushstrokes, Ferdinand discovers fame and success. And love in all this? Sacrificed on the altar of creation...', '/mL7mKRX084bEjGHXTEkcAMsO8N4.jpg', '1979-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14679, 'Jean-Pierre Léaud: The Child of Cinema', 1320481, NULL, '/r1MWp0ENzCuyzyXXQrKKkboOGOC.jpg', 'Le Cinéma de Jean-Pierre Léaud', 'A portrait of the legendary actor Jean-Pierre Léaud, icon of the French New Wave and closely linked to the work of François Truffaut and Jean-Luc Goddard.', '/u8jEWJGIVN48XZAd3LVPE3CyQN7.jpg', '2024-09-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14680, 'Sauve la vie (qui peut)', 384468, NULL, '/4rxurC0kJftE2ZsDBXSJjwNslXb.jpg', 'Sauve la vie (qui peut)', 'Godard experimental film with montages combining "Sauve qui peut (la vie)" and other films by other filmmakers.', '/eCTampcyrghM4GJM8lH3lkiCyID.jpg', '1981-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14681, 'From Time to Time', 1556306, NULL, '/gfeTzj8BrTRyU7wJBZPN9hWjXEl.jpg', 'Un voyage dans le temps', 'In the Visionarium, the Timekeeper is a robot testing a new time machine. Because of the potential dangers, he sends his assistant, the robot 9-Eyes, into the machine. The test works and she travels through all eras. Arriving in the nineteenth century, it was discovered by the author Jules Verne who grabbed it. Wanting to bring her back to the present, the Timkeeper also takes the author who decides to travel through our time.', '/m24A5XBW6qzv4e175dHQ8FeVS1x.jpg', '1992-04-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
