INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14687, 'I Love You Like Crazy', 399270, NULL, NULL, 'I Love You Like Crazy', 'Dan is crazy. He''s schizophrenic, he has delusions that he''s a rock star, and he''s haunted by the voice of a controlling band manager who doesn''t actually exist. When he gets thrown in the psych ward again, he meets Melody, a feisty punk girl who teaches him how to love. Like crazy.', '/caz8Iwn5duycvcWNc0j5T0CQ0Xy.jpg', '2011-06-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
