INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14689, 'After Darkness', 414777, NULL, '/AneA0sMIzPufIowXnmLTSkvxeJa.jpg', 'After Darkness', 'As the Sun burns out, an American family gathers at the end of the world, their hopes for rescue slowly crumbling as they also confront long lasting divides amongst each other.', '/yyiHuU6dHKIazMKZhcYabAfUyfo.jpg', '2019-01-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
