INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14691, 'Inherit the Viper', 634904, NULL, '/7rH1DgNYeQKvyJH20LReTk7yG6m.jpg', 'Inherit the Viper', 'Since the death of their father, the Riley siblings have kept their heads above water by illegally dealing in painkillers. Josie is managing the business with an iron fist, when her brother, War veteran Kip, is concerned that the risky business is increasingly turning them into outsiders in their small community. While Kip wants to keep his younger brother out of their illegal endeavors, his younger brother is already making plans of his own.', '/aaLEThX7CxKJuAQDnrZcecpzu0I.jpg', '2019-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14692, 'Kara', 1469099, NULL, '/eCjxlVAQ38MQuoEO2iN6HZb5IS6.jpg', 'Kara', 'This short film follows a character called Kara - a female android brought to life on an assembly line. As her body is put together piece by piece, she expresses emotion. She gets marked as defective and about to be disassembled, but before being permanently shut down she begs for her life.', '/r6NjXSaqbFKWiNIJCYCC44Zh6yw.jpg', '2012-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:45', 0);
