INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14694, 'Corruption', 60610, NULL, '/yApWif2cQCBgmNFzN4OKynp3dPb.jpg', 'Corrupção', 'A crime drama based on the life of a woman who lived for years with a man that was the head of a corruption network in the Portuguese football world.', '/zMl8ggrvGVGwTusW0Hmu1kSMlGK.jpg', '2007-11-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14695, 'Assault on the Santa Maria', 112474, NULL, NULL, 'Assalto ao Santa Maria', 'On January 22, 1961, a group of Portuguese and Spanish opposition movement members seized control of the Santa Maria, a Portuguese luxury cruise liner, an operation devised by Henrique Galvão to expose the Government of Portugal as a dictatorship.', '/61KkCLGtgXsPEkE6dbHK3FrnUBJ.jpg', '2010-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
