INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14697, 'The Mystery of Sintra', 173928, NULL, '/9MCgbxWvq0y1wFAu1vGVKHfCPKN.jpg', 'O Mistério da Estrada de Sintra', 'Summer of 1870. Two writers, Eça de Queiroz and Ramalho Ortigão, decide to write a four-handed whodunit for the daily "Diário de Notícias". Could it be that the story they wrote as fiction is based on a real case? This question fuels the conflict between the two writers and drives them to a nearly fatal duel. Lisbon is in commotion. One crime follows another in a story in which love is stronger than tradition. Everything happens at frenzied pace, as in a game.', '/3zbXphRRh3VBtoskMzRwYRQtbEU.jpg', '2007-05-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14698, 'Skin', 242536, NULL, '/ehLwcV3YeQHdgNt09ectDZxZiCR.jpg', 'Pele', 'Pele is a film about a young mulatto woman that in spite of being rich, beautiful and intelligent, feels discriminated because of the colour of her skin. The entire plot is in the early 70''s, when Portugal had a dictatorial government, ultramarine territories and lots of racism in its society… Issues like racism, female condition and the spoilt lives of the high-society are the main themes of this movie', '/lRdcT8ZT0XjjEowm6BSLPP6oVks.jpg', '2006-05-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14699, 'Sei lá', 251829, NULL, '/A3U9FxFzur0C166QM55vK8Flmqc.jpg', 'Sei lá', 'Madalena is 30 years old and is abandoned by the love of her life a mysterious Spaniard named Ricardo. With the support of her best friends she tries to forget him, and find true love.', '/i3clehWQ1exfbDTF2tYv6B1abwG.jpg', '2014-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14700, 'Disquiet', 151433, NULL, '/uH7er5EHJWX8chr1nERqYVNlVRT.jpg', 'O Filme do Desassossego', 'Lisbon, today. In a room of a house at Douradores Street, a man invents dreams and theorizes about them. The essence of the dreams itself becomes physical, palpable, visible. The text itself materializes in its musicality. And, in front of our eyes, this music can be felt with the ears, brain and heart. It spreads itself in the street where the man lives, in the city that he loves above all and over the entire world.', '/whNK0oLwa2rp9K13BNXu4ZLkmah.jpg', '2010-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14701, 'Dead Man''s Memories', 134887, NULL, NULL, 'Der Gläserne Blick', 'A policeman lunching with his daughter is present when a dead body washes up on shore. He investigates, leading him down a twisted and muddled path of nefarious connections reflecting, somewhat, his own life.', '/ttlNczNccKtAU81nOalDUSCACZp.jpg', '2003-07-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14702, 'Soldier Millions', 513343, NULL, '/y0jBSKfIEnob6sBdRTD8B3rLuq8.jpg', 'Soldado Milhões', 'A Portuguese soldier, who got stranded from his team during the La Lys battle, struggles by himself through dozens of German offensives so he can guarantee the safety of his companions.', '/9qhnUiUOspdg3TWh7uTB4PZ7ZkF.jpg', '2018-04-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14703, 'O Inimigo Sem Rosto', 512426, NULL, NULL, 'O Inimigo Sem Rosto', 'A plot that surrounds police officers, politicians and consultants who crudely demonstrate the lines apparently hidden of the political system and public institutions.', '/FIzLj83vksgVGZPjRC9Mxkub9S.jpg', '2010-08-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14704, 'Jacinta', 449393, NULL, '/5dWFe49m70vk1HoKqmGfoeDzMws.jpg', 'Jacinta', 'The story of Jacinta, one of the three children involved in the Marian apparition reported in 1917 at Cova da Iria, in Fátima, Portugal.', '/wvbfi9372DePH3Gp0a3hPyflFlG.jpg', '2017-04-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14705, 'True and Tender is the North', 105699, NULL, '/gUfKraGpUbjoTQHHW1IwUsS0C9S.jpg', 'A Corte do Norte', 'Adaptation of a 1987 novel by Agustina Bessa Luis, a multi-generation exploration of a wealthy family with a mysterious past and a house on the island of Madeira.', '/lvzyXRNve5K2QXwXq6AR8gAGfUw.jpg', '2008-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14706, 'The Mutants', 80098, NULL, '/dRrMLAZG8RgAV2aiPrLqAPciBB5.jpg', 'Os Mutantes', 'Three homeless teenage rejects struggle to survive together. Of them, Andreia is pregnant, while Pedro and Ricardo hustle, steal and are exploited by a pornographer.', '/rav4Yd9zcRhYkjNhTK75q15WnlM.jpg', '1998-11-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14707, 'Antonio, a boy in Lisbon', 431535, NULL, NULL, 'António, Um Rapaz de Lisboa', 'A boy in Lisbon, in this Lisbon in permanent renovation.', '/ySQgHzGt11Npy7QNxxDE9yRD6k5.jpg', '2002-01-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14708, 'Camarate', 50230, NULL, '/gaVOAGPq2LRvwmtUI6dLiBpnql3.jpg', 'Camarate', 'In 1980, a small plane carrying the Prime Minister, the Defense Minister and six others crashed during takeoff in Camarate, Portugal, killing all on board. The police investigation decided it was an accident caused by pilot error. But controversy raged for twenty years, and the Parliament investigated it no less than six times. Finally, in 2000, in response to a suit by the families of the survivors, the High Court had to decide whether to open a criminal investigation, or close the case forever.', '/vOq1L7X1rsJ6R0PvP7eoOhtZe7V.jpg', '2001-04-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14709, 'Uma Vida Toda Empatada', 790043, NULL, NULL, 'Uma Vida Toda Empatada', 'An adaptation of the short story with the same name by Portuguese writer Mário de Carvalho.', '/g25r6Xzb33t6b9kmL8WEwzbB5ZL.jpg', '2021-02-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14710, 'O Conto do Nadador', 1357500, NULL, '/2vLkV45gt5zlvbMrb8h1IN9bBl9.jpg', 'O Conto do Nadador', 'A story from a time when mystery made all the difference and where the most subtle sense of observation reigns supreme. It all begins with the death of the Swimmer, discovered at the edge of the cliff. But to this day, it is not known who fired the fatal shot, despite a thorough investigation by the Judicial Police, with special attention given to three girls—two sisters and a friend—who are there on vacation. But the doubt remains, and the inspector who conducted the investigation wonders, because the three seemingly naive teenagers leave the inspector with the conviction that, between their statements and their father''s assertive maturity, it will be difficult to prove what his instinct tells him.', '/wevd0lVB7eEhCwjBuooxj65AVbD.jpg', '2024-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14711, 'A Família Ventura', 1408252, NULL, '/yKfF8QLigeia4QfCVtnKqp4ZeMo.jpg', 'A Família Ventura', NULL, '/5oAReUgSfeIrWNw6xZfcE2siKP1.jpg', '2017-12-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14712, 'Inequality for All', 159008, NULL, '/2X2jnuBmTa4q34Eutv50r9Uk1FK.jpg', 'Inequality for All', 'Based on Reich''s 2010 book Aftershock: The Next Economy and America''s Future, the film examines widening income inequality in the United States.  U.S. Labor Secretary Robert Reich tries to raise awareness of the country''s widening economic gap. He publicly argued about the issue for decades, and producing a film of his viewpoints was a "final frontier" for him. In addition to being a social issue documentary, Inequality for All is also partially a biopic regarding Reich''s early life and his time as Secretary of Labor under Bill Clinton''s presidency. Warren Buffett and Nick Hanauer, two entrepreneurs and investors in the top 1%, are interviewed in the film, supporting Reich''s belief in an economy that benefits all citizens, including those of the middle and lower classes.', '/yGWDqQlRzIcvna4YoEYw1cZ7rmn.jpg', '2013-01-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14713, 'The Borking of America', 1260057, NULL, NULL, 'The Borking of America', '"Meet Robert Bork. I worked for him. I respected him. I liked him. I also blame him for some profound and lasting harm to our society. Here''s why."', NULL, '2024-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14714, 'Busting the “Paid What You’re Worth” Myth', 1271544, NULL, NULL, 'Busting the “Paid What You’re Worth” Myth', '"Let’s set the record straight: Workers are not ''paid what they’re worth.''  "This is a myth peddled by the rich to exploit workers and hoard unconscionable wealth.  "It’s designed to make us think that nothing can be done to change what people are paid.  "Don’t fall for it."', NULL, '2023-06-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14715, 'This One Thing Would Increase Wages By $300 Billion', 1271546, NULL, NULL, 'This One Thing Would Increase Wages By $300 Billion', '"Non-competes are a trap.  "They block workers from seeking out higher wages or better conditions.  "Meanwhile, they sabotage the economy by depriving growing businesses of needed talent.  "They serve one thing only: corporate monopolies who want to kill off their competition."', NULL, '2023-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14716, 'Is It Inflation? Or Is It Greedflation?', 1273626, NULL, NULL, 'Is It Inflation? Or Is It Greedflation?', '"The next time you hear someone blame inflation on stimulus checks that Americans got four years ago or workers finally getting much-needed pay bumps, kindly remind them that corporate profits are at a 70-year-high. Hello?"', NULL, '2024-04-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14717, 'Love & Taxes', 336323, NULL, '/bmifSE3twN1uYcz1oNjKSCHmt2R.jpg', 'Love & Taxes', 'Love &amp; Taxes is a riveting comic tale of seven years of tax avoidance. Following the possibly real-life exploits of Josh Kornbluth, an autobiographical monologist, Love &amp; Taxes is a comedy that blends solo performance and scripted scenes to bring the subjective reality of the storyteller hilariously to life. A tale of procrastination, making movies and growing up, Love &amp; Taxes is a middle-aged coming-of-age story that is also, quite possibly, the first ever pro-tax romantic comedy.', '/kJwYUePVOA503HXMpa2Y4XHCGJv.jpg', '2015-07-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14718, 'Saving Capitalism', 483010, NULL, '/2eyFqpycQQzU08CEq1cDAy2JGEK.jpg', 'Saving Capitalism', 'Former Secretary of Labor Robert Reich meets with Americans from all walks of life as he chronicles a seismic shift in the nation''s economy.', '/klxZFkVYV0bmOdeLI8YQ8GcE26m.jpg', '2017-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14719, 'A Dangerous Idea', 550986, NULL, '/lv0DS72wRaePWxtl1QBWSgF1cDa.jpg', 'A Dangerous Idea', 'A dangerous idea has threatened the American Dream from the beginning - the belief that some groups and individuals are inherently superior to others and more deserving of fundamental rights. Such biological determinism provided an excuse for some of America''s most shameful history. And now it''s back. This documentary reveals how biologically determined politics has disenfranchised women and people of color, provided a rationale for state sanctioned crimes committed against America''s most vulnerable citizens, and now gains new traction under the Trump administration.', '/mV3NLk4tEY0rxVyvPrTBHvGVCV0.jpg', '2016-12-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14720, 'Fired!', 37299, NULL, '/rien0JIthKGopmZjSmWID9gUHCC.jpg', 'Fired!', 'When actress Annabelle Gurwitch was fired from a play by Woody Allen, she wondered how she would cope with being downsized by a cultural icon. Turning to friends in show business, she was assured she was not alone. Everyone she knew, from her rabbi to her gynaecologist, had their own account of getting the boot. Featuring interviews with comedians, economists and regular working folks, and drawing on her hugely popular book, Fired! is a humorous look at downsizing in America.', '/dWLzkKIkR8MMVTqKvfLFaKDP9ly.jpg', '2007-06-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14721, 'Landslide: A Portrait of President Herbert Hoover', 184565, NULL, NULL, 'Landslide: A Portrait of President Herbert Hoover', 'Documentary about personal life of Herbert Hoover''s and his governmental career, profiles the former head of state''s political philosophy, memorable election campaigns, Great Depression policies and more. Through interviews with scholars such as David Kennedy, Robert Reich and Tim Egan, this biography sheds new light on the underappreciated president''s difficult tenure and enduring legacy.', '/uSi3gYTD5TojLigRpyj61UBVKkY.jpg', '2009-10-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14722, 'The Last Class', 1471937, NULL, '/hV0yd5eAF69Cnt0G6pkVb9AKgYJ.jpg', 'The Last Class', 'American political economist, professor, author, and social media sensation Robert Reich teaches his final "Wealth and Poverty" class to 1,000 students at UC Berkeley, ending a 40-year career that reached 40,000 students. One thousand fill the biggest lecture hall on the UC Berkeley campus, the last class to receive Reich''s wisdom and exhortations not to accept that the world has to stay the way it is. His belief in the next generation''s ability to take on the fight is inspiring.', '/xoX69VuEJ5H51dqC3nKQbiZNQd0.jpg', '2025-06-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
