INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14724, 'National Theatre Live: The Last of the Haussmans', 141677, NULL, '/jGYtjoxOEiU3DjWmKpnO0333aWE.jpg', 'National Theatre Live: The Last of the Haussmans', 'Anarchic, feisty but growing old, high society drop-out Judy Haussman remains in spirit with the Ashrams of the 1960s while holding court in her dilapidated Art Deco house on the Devon coast. After an operation, she''s joined by wayward offspring Nick and Libby, sharp-eyed granddaughter Summer, local doctor Peter, and Daniel, a troubled teenager who makes use of the family''s crumbling swimming pool. Together they share a few sweltering months in this chaotic world of all-day drinking, infatuations, long-held resentments, free love and failure.', '/vhzH5QqnT9RaRbJNEde6n2zVN7R.jpg', '2012-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14725, 'Come Home', 931633, NULL, '/zzpkUrEqe9YJeQ7LcKTyM3ehd1C.jpg', 'Come Home', 'During the holiday season, Angie, a pack''s mother, gets stranded by a blizzard and winds up backstage at the variety show studio. She then gets a chance to connect with her family even if she can''t physically make it back to the house.', '/yIwVPBD8w1HoJ9hVidzjQx0oEx2.jpg', '2021-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
