INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14728, 'Testament of Youth', 284689, NULL, '/jD0mmfqPRpvJUaPdpLl1vMj38CA.jpg', 'Testament of Youth', 'Testament of Youth is a powerful story of love, war and remembrance, based on the First World War memoir by Vera Brittain, which has become the classic testimony of that war from a woman’s point of view. A searing journey from youthful hopes and dreams to the edge of despair and back again, it’s a film about young love, the futility of war and how to make sense of the darkest times.', '/a6kFsaDCulCLfYHmKLDKTYaddM4.jpg', '2015-01-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:46', 0);
