INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14760, 'I Want Someone to Eat Cheese With', 13066, NULL, '/7Q0hbVTeCqbbF3IrYSrFnvXThlT.jpg', 'I Want Someone to Eat Cheese With', 'Life has its downs for James, living with his mom in Chicago at 39, an aging performer at Second City, eating and weighing too much. A woman he''s been dating drops him, as does his agent, her brother. James turns down roles in local TV, roles that make him sad. Someone''s remaking his favorite movie, "Marty," a role he''d love, but he doesn''t even get an audition.', '/4zVqWaiC9Y2GJSmuJjMDRlYv4ae.jpg', '2006-04-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
