INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14765, 'I Think We''re Alone Now', 451877, NULL, '/ipaCW3O6vFcZKfh1FLPeV4vArxI.jpg', 'I Think We''re Alone Now', 'After a catastrophe destroys most of humanity, recluse Del lives in his small, empty town, content with the utopia he has methodically created for himself, until an interloper, young Grace, disrupts his solitude.', '/9sNsmC8FKgr4hTfnGCS49WY20k4.jpg', '2018-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
