INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14767, 'The Roads Not Taken', 567714, NULL, '/3khLsessoSDOpA5hkBo6JeVamk2.jpg', 'The Roads Not Taken', 'The film follows 24 hours in the life of father and daughter Leo and Molly, as they weave their way around New York City, until their ordinary but stressful day takes on a hallucinatory and epic quality.', '/7GtX3NDh8S8ImqtTp4Ww02SXh4B.jpg', '2020-03-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14768, 'Camp! The Movie', 601825, NULL, '/bAN0FtH5hTmGwkhiAQxp327cdsm.jpg', 'Camp! The Movie', 'At the Met Gala 2019, Lady Gaga, Cardi B, Kim Kardashian West, Kylie Jenner, Kendall Jenner, Celine Dion, Gigi Hadid, Bella Hadid, Harry Styles, Bette Midler, Hailey Bieber, Jared Leto, Gwen Stefani, Lizzo and more of your favorite celebrities helped stage a camp film classic in the halls of the Met Museum, and you have to see it to believe it!', '/2X5cxfFaBNXUUK7GN3NVS0nXo0U.jpg', '2019-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
