INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14771, 'Sigur Rós: Valtari Film Experiment', 183613, NULL, NULL, 'Sigur Rós: Valtari Film Experiment', 'Sigur Rós have given a dozen film makers the same modest budget and asked them to create whatever comes into their head when they listen to songs from the band''s album Valtari. The idea is to bypass the usual artistic approval process and allow people utmost creative freedom. These 16 films are the result. Sad, funny, beautiful and, occasionally, plain bewildering, they represent just some of the available emotional responses to this most contemplative album.', '/xXK2lTH5lXwfGkrfNPPxxo3dLKu.jpg', '2013-03-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14772, 'Penn & Teller: Try This at Home', 709664, NULL, '/oWs2YPmlRsaNi0jLgDpdrh2Wh39.jpg', 'Penn & Teller: Try This at Home', 'A special for these unique times. Filmed entirely at the homes of Penn & Teller and their friends around the world, Penn & Teller: Try This at Home showcases new magic Penn & Teller and their magician friends have developed at home and teaches viewers how to do an array of tricks themselves while being joined by celebrity guests including Elle and Dakota Fanning, Michael Carbonaro and Shin Lim.', '/4CV1Ez7yHwg48k3TJI2shLW3z5e.jpg', '2020-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
