INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14774, 'That Click', 715922, NULL, NULL, 'That Click', 'A man at the cutting edge of fashion, photojournalism and portraiture, photographer to the stars Douglas Kirkland has portrayed over sixty years of pop culture. This fascinating feature takes a closer look into the career of one of the most important photographers of the last century. His subjects, who are some of the biggest stars of Hollywood and the fashion world, provide testimonials.', '/qP0tngP2EyPqKVqZKwhM3QhVCFI.jpg', '2019-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14775, 'Making Somewhere', 756497, NULL, NULL, 'Making Somewhere', 'Like the movie, this behind the scenes takes a more artistic turn. It lingers on and around filmmakers as the discuss the movie.', NULL, '2011-04-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14776, 'Common Ground: Under Construction Notes', 1389971, NULL, NULL, 'Common Ground: Under Construction Notes', 'The making of Alejandro González Iñárritu’s Babel is chronicled through an observational approach that captures the creative and logistical challenges of filming a deeply interconnected narrative across four continents. Directed by Carlos Armella and Pedro González-Rubio, the documentary reveals Iñárritu’s commitment to authenticity and cultural sensitivity, from collaborating with local actors and communities to meticulously recreating environments. Through behind-the-scenes footage and the director’s reflective commentary, it delves into themes of human connection, the boundaries we hold within ourselves, and the visceral nature of communication, offering profound insights into the philosophy behind the acclaimed film.', '/yGyFN93iF1shzrZPkz894QRJfl6.jpg', '2007-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14777, 'On the Red Carpet Presents: "A Complete Unknown"', 1452230, NULL, '/szIP8CgTZC9sX1K1VXJA04joVoF.jpg', 'On the Red Carpet Presents: "A Complete Unknown"', 'A behind the scenes look at the making of "A Complete Unknown" featuring interviews with the cast and filmmakers.', '/pDR0MqZvhpb7Onu2Y6Vqfn5jNX0.jpg', '2025-01-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14778, 'Elle Fanning''s Fan Fantasy', 1565429, NULL, NULL, 'Elle Fanning''s Fan Fantasy', 'Vogue''s original short film on Elle Fanning - fanning the rock, fawn, fan mail, fawn etc.', NULL, '2017-05-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
