INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14781, 'The Tailor of Panama', 2575, NULL, '/zKctuZIWdni1QxTEt4SsNyysdxW.jpg', 'The Tailor of Panama', 'A British spy is banished to Panama after having an affair with an ambassador''s mistress. Once there he makes connection with a local tailor with a nefarious past and connections to all of the top political and gangster figures in Panama. The tailor also has a wife, who works for the Panamanian president and a huge debt. The mission is to learn what the President intends to do with the Canal.', '/na80ysnoCvoxwGTMWCWYvnmaDlz.jpg', '2001-02-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14782, 'Laws of Attraction', 11141, NULL, '/ktvFYpvolLOzUzWV7tXt6Mz0jwH.jpg', 'Laws of Attraction', 'Amidst a sea of litigation, two New York City divorce lawyers find love.', '/6aqR0xwmK0mPOIVShDlT88Vo5W0.jpg', '2004-04-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14783, 'The Fourth Protocol', 4918, NULL, '/48wk2XbofCCX5SJbgX1aF8jJUVa.jpg', 'The Fourth Protocol', 'Led by Kim Philby, Plan Aurora is a plan that breaches the top-secret Fourth Protocol and turns the fears that shaped it into a living nightmare. A crack Soviet agent, placed under cover in a quiet English country town, begins to assemble a nuclear bomb, whilst an MI5 agent attempts to prevent its detonation.', '/qh4JMlyWKttjTUvARdEfqpuvqP0.jpg', '1987-03-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14784, 'Death Train', 20435, NULL, '/k8TExBK5ePvo18DNgd2zZSrfnyV.jpg', 'Death Train', 'When a renegade Russian general sends a nuclear bomb hurtling toward the Middle East aboard a hijacked train, special agents are dispatched to disarm the deadly device.  Ten tons of steel and one ounce of hot plutonium are now riding roughshod through Europe.  With time running out, the agents launch a desperate, bullet-packed assault on a deadly moving target piloted by a cold-blooded mercenary.', '/zC0MftjGSMUuHFFzZnHnaYWC4gf.jpg', '1993-04-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14785, 'Robinson Crusoe', 11210, NULL, '/ynpag8C3nhpPrHIghrKH6kKXOSO.jpg', 'Robinson Crusoe', 'Robinson Crusoe flees Britain on a ship after killing his friend over the love of Mary. A fierce ocean storm wrecks his ship and leaves him stranded by himself on an uncharted island. Left to fend for himself, Crusoe seeks out a tentative survival on the island, until he meets Friday, a tribesman whom he saves from being sacrificed. Initially, Crusoe is thrilled to finally have a friend, but he has to defend himself against the tribe who uses the island to sacrifice tribesman to their gods. During time their relationship changes from master-slave to a mutual respected friendship despite their difference in culture and religion.', '/93uRPzVpf4ZVjDfswmpsrAmBS4w.jpg', '1997-06-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14786, 'Evelyn', 21868, NULL, '/q3P6P6yVij3i16B4F0sotx8IOzB.jpg', 'Evelyn', 'Desmond Doyle is devastated when his wife abandons their family on the day after Christmas. His unemployment, and the fact that there is no woman in the house to care for the children—Evelyn, Dermot and Maurice—make it clear to the authorities this is an untenable situation. The Catholic Church and the Irish courts decide to put the Doyle children into Church-run orphanages.', '/kGsCpJcJj9JDsSLQRlfukNuZJgq.jpg', '2002-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14787, 'The Ghost Writer', 11439, NULL, '/dXWJ3cNNx3BOk124s7VT5xrklTI.jpg', 'The Ghost Writer', 'A writer stumbles upon a long-hidden secret when he agrees to help former British Prime Minister Adam Lang complete his memoirs on a remote island after the politician''s assistant drowns in a mysterious accident.', '/rK7m2Ba0ieXa37NaAmrx4dfRvvM.jpg', '2010-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14788, 'Married Life', 8060, NULL, '/fvIj8fo9j6DifyMWopHevGVhFUQ.jpg', 'Married Life', 'A very gentle middle-aged man is married, but when he falls in love with another woman, he decides that to divorce his wife would humiliate her too much – so instead he decides to kill her.', '/AdJKmRh3AKX5CVCdwdw1dNTqEJ8.jpg', '2008-03-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14789, 'The Greatest', 32395, NULL, '/fQehemJNDIKfGcmTnvm5SqQ7kgr.jpg', 'The Greatest', 'Teenagers Rose and Bennett were in love, and then a car crash claimed Bennett''s life. He left behind a grieving mother, father and younger brother, and Rose was left all alone. She has no family to turn to for support, so when she finds out she''s pregnant, she winds up at the Brewer''s door. She needs their help, and although they can''t quite admit it, they each need her so they can begin to heal.', '/7dNynUNdYSxeOpuJJNv3Fyk54NA.jpg', '2009-02-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14790, 'The Matador', 9515, NULL, '/jBxIfffFWY69oAx6CLQtKZ3xtYO.jpg', 'The Matador', 'The life of Danny Wright, a salesman forever on the road, veers into dangerous and surreal territory when he wanders into a Mexican bar and meets a mysterious stranger, Julian, who''s very likely a hit man. Their meeting sets off a chain of events that will change their lives forever, as Wright is suddenly thrust into a far-from-mundane existence that he takes to surprisingly well … once he gets acclimated to it.', '/oJnlAGmrhsg4QrlVKGgP91J6WPu.jpg', '2005-05-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14791, 'Live Wire', 12629, NULL, '/5kFSjZNYSng3YrXgencT6iINItv.jpg', 'Live Wire', 'Danny O''Neill is a bomb disposal expert assigned to a case where terrorists have developed an "invisible" liquid explosive which is activated within the human body.', '/xQbj9KgXqw9yjZfDO99jFyw1pzg.jpg', '1992-09-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14792, 'Murder 101', 27494, NULL, '/fqZxzpo1pd7tHbgTGPbYGxNEZ8u.jpg', 'Murder 101', 'Charles Lattimore, an author of a book about a famous murder trial, arranges to meet with one of his students one night. When the student is found murdered and Lattimore has no alibi, he suspects he is being framed by the subject of his book.', '/zkimtYPutlDe4y3rKpER2NFBD1p.jpg', '1991-03-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14793, 'Seraphim Falls', 13249, NULL, '/kPNnBitz7R2A5XzFT9NanVQGoVQ.jpg', 'Seraphim Falls', 'The Civil War has ended, but Colonel Morsman Carver is on one final mission – to kill Gideon, no matter what it takes. Launched by a gunshot and propelled by rage, the relentless pursuit takes the two men through frigid snow-capped mountains and arid deserts, far from the comforts and codes of civilisation, into the bloodiest recesses of their own souls.', '/3WCcrCYq9mCyFGLpgx2IwhpURTe.jpg', '2007-01-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14794, 'Butterfly on a Wheel', 13250, NULL, '/7al64Hp3RPaMNB5AWTdFH7RggnG.jpg', 'Butterfly on a Wheel', 'A sociopathic kidnapper methodically pushes a desperate pair of parents to their absolute breaking point.', '/qcjjYcMaaSKD2C8xn0hy6o6yj2L.jpg', '2007-07-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14795, 'Nomads', 26725, NULL, '/f0aKdbxNRcUX4YrTSN3s06w8fMz.jpg', 'Nomads', 'One night, in a Los Angeles hospital, Dr. Flax attends to a seriously injured man who, apparently crazed, whispers mysterious and disconcerting words in French into her ear.', '/rqPl4jsFmBvl2odkYHtUeTqBCjT.jpg', '1986-03-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14796, 'The Spirit of Grey Owl', 1097909, NULL, NULL, 'The Spirit of Grey Owl', 'Delves into the incredible story of the Englishman Archie Belaney who came to Canada and lived the life of an Ojibwa. He went on to become Canada’s best-known personality as an author and conservationist.', '/9Xbb6yxWN8LVrg9AN9sTrvn1ysq.jpg', '2000-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14797, 'The Match', 41160, NULL, NULL, 'The Match', 'Romantic comedy set against the story of a grudge football match between two pubs. The prize for the winner of the centenary match is the the closure of their opponent''s bar. The Match was mainly filmed around Straiton in Ayrshire.', '/h7sS80bAgJrPm31eKHNV5JqzdEL.jpg', '1999-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14798, 'Grey Owl', 41807, NULL, '/vyxQ6wrpRjqwdIhZJJPQca0UuQX.jpg', 'Grey Owl', 'Archie Grey Owl is a trapper in Canada in the early 1930s when a young Iroquois woman from town asks him to teach her Indian ways. They live in the woods, where she is appalled at how trapped animals die. She adopts two orphaned beaver kits and helps Archie see his way to stop trapping. Instead, he works as a guide, a naturalist writer, and then the Canadian government hires him to save the beaver in a conserve by Lake Ajawaan in Prince Albert National Park. He writes a biography, which brings him attention in Canada and invitations to lecture in England. Before he leaves, he and Anahareo (Pony) marry. In England, his secret is revealed. Will Anahareo continue to love him?', '/zreBHtHVAkH8Z2EdAAje1pFuF2p.jpg', '1999-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14799, 'The Deceivers', 41968, NULL, '/tRyR9eI9yTJ3eOgjIUyHVpBzk9f.jpg', 'The Deceivers', 'India, 1825: the country lives in mortal fear of cult members known as the “Deceivers." They commit robbery and ritualistic murder. Appalled by their activities, an English military man, Captain William Savage, conceives a hazardous plot to stop them. In disguise, he plans to himself become a “Deceiver” and infiltrate their numbers. Ever present in Savage’s adventures is a sense of dread; he is in constant fear of betrayal and vengeance and also undergoes a disturbing psychological transformation as he experiences the cult’s blood lust firsthand.', '/dwno7eKJbzNZ2prc5wI1istvnyj.jpg', '1988-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14800, 'Love Affair', 43742, NULL, '/aqun4YtcepdCBOHkhO16gIwtZxb.jpg', 'Love Affair', 'Ex-football star Mike Gambril meets Terry McKay on a flight to Sydney, which is forced to land on a small atoll. They become romantic on board a ship sent to take them to a larger island. They agree to meet in New York three months later to see if the attraction is real. One shows up but the other doesn''t. However, a chance meeting brings them together again.', '/uPEh48HZN9qqewkF2Hsi9BD6oz7.jpg', '1994-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14801, 'The James Bond Story', 44650, NULL, '/xIzw0rE6tWCgK3eGPqnyvFP15V9.jpg', 'The James Bond Story', 'Bond... James Bond! Perhaps the greatest fictional cinema icon ever. He first appeared on the big screen in 1962 in Dr. No and has remained the most powerful action hero ever since. The secret to his success is his adaptability. No matter what tight spots he finds himself in, he always appears to be suave, sophisticated and cool. This is the full story -- from the creation of the character, the men who played him, all the toys, and all the women. Everything you wanted to know about James Bond... and more.', '/wG1iksqapNCNNZuIneHuF6j9Sg0.jpg', '1999-10-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14802, 'Night Watch', 38651, NULL, '/8r51eVEjtqAQvpHfbFHXcedRB8r.jpg', 'Night Watch', 'UN agents Mike Graham and Sabrina Carver are sent by their director Nick Caldwell to investigate the theft of Rembrandt''s painting, "The Night Watch". The trail takes them from Amsterdam to Hong Kong and involves them in not only art theft and forgery, but the high-tech schemes of Martin Schraeder and his Korean cohort Mao Yixin', '/6B3RWyjuiMcug49aw65h0F6wjDQ.jpg', '1995-10-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14803, 'Salvation Boulevard', 51995, NULL, '/apMLieYY9z6tgBHLbCA7wsuar02.jpg', 'Salvation Boulevard', 'Set in the world of mega-churches in which a former Deadhead-turned-born-again-Christian finds himself on the run from fundamentalist members of his mega-church who will do anything to protect their larger-than-life pastor.', '/q8kPPcpPUGhdAOP5LYHDMKZBXYP.jpg', '2011-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14804, 'I Don''t Know How She Does It', 70868, NULL, '/f2WjZXaEAp8eAxCFiRCbfbu84U2.jpg', 'I Don''t Know How She Does It', 'As an employee at a Boston-based financial firm, Kate Reddy struggles daily to balance the demands of her high-powered career with the needs of her husband, Richard, and their two children. When she gets an account that requires frequent trips to New York and her husband gets a new job, Kate finds herself spread even thinner. Complicating Kate''s life even more is her new business associate Jack Abelhammer, who throws temptation into the mix.', '/eUQfE21WB0qKfUx6yUAhmsCWTmX.jpg', '2011-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14805, 'Jane''s Journey', 82686, NULL, '/72FSJzxJKEcTS8q7A1ZAbfoKv0i.jpg', 'Jane''s Journey', 'It would be hard to name anyone who has had more of an impact in the realm of animal research and wildlife conservation than Jane Goodall, whose 45 year study of wild chimpanzees in Africa is legendary. In Jane''s Journey, we travel with her across several continents, from her childhood home in England, to the Gombe National Park in Tanzania where she began her groundbreaking research and where she still returns every year to enjoy the company of the chimpanzees that made her famous. Featuring a wide range of interviews and spectacular footage from her own private collection, Jane''s Journey is an inspiring portrait of the private person behind the world-famous icon.', '/ig1inzD7qY0Oq30inhVVX5p2ert.jpg', '2011-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14806, 'The Heist', 54535, NULL, '/dJsXwveQjyRvSuAknufMe5S1DjZ.jpg', 'The Heist', 'Ex-con Neal Skinner seeks revenge against track owner Ebbet Berens for framing him in an emerald smuggling deal.', '/aLmAG96GVFAK47xw4oci8b4Y8YI.jpg', '1989-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14807, 'Thomas & Friends: The Great Discovery', 93458, NULL, '/qolzFHbR6iMrWcY9r3DTxoMeaqq.jpg', 'Thomas & Friends: The Great Discovery', 'Thomas the Tank Engine™ stars in an all-new movie guest starring Pierce Brosnan as the narrator! Sodor Day is coming and all the engines are busy preparing. When Thomas gets lost in the mountains, he discovers the old town of Great Waterton! Soon the whole island is buzzing with the news of Thomas'' discovery and restoring the town in time for the big day. Join the fun and meet a new engine friend named Stanley!', '/1ThzDIhr8PnjS6aOFH9LycgXbdr.jpg', '2008-07-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14808, 'The Nephew', 78784, NULL, '/q0KhhLSbxoJTlV2o79NtXZgYW8c.jpg', 'The Nephew', 'Twenty years ago, Tony Egan''s sister went to America. Nobody ever heard of her again. But now, the message of her death arrives in her town of birth. Only days later, her only son Chad arrives, too. Obviously, his mother took a black husband. Soon, Chad falls for Aislin, who has a bit of a crush on him too. But there is an old conflict going on between her father and Chad''s uncle. This conflict resurfaces and begins to draw circles, wider and wider.', '/iN3hezUBdYs2RL2nnePtrSWBYNt.jpg', '1998-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14809, 'Mister Johnson', 123772, NULL, '/4o7TR3cXROgKBeN3ulras4pATDz.jpg', 'Mister Johnson', 'In 1923 British Colonial Nigeria, Mister Johnson is an oddity -- an educated black man who doesn''t really fit in with the natives or the British. He works for the local British magistrate, and considers himself English, though he has never been to England. He is always scheming, trying to get ahead, which lands him in a lot of hot water.', '/pkvaIlFJOw4CKm7820Rhw7t9xUJ.jpg', '1991-03-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14810, 'A Long Way Down', 141043, NULL, '/cA2lXcl4rVKsRltJwVYRqpSqvhq.jpg', 'A Long Way Down', 'Four lost souls—a disgraced TV presenter, a foul-mouthed teen, an isolated single mother, and a failed musician—decide to end their lives on the same night, New Year''s Eve. When this disillusioned quartet of strangers meet unintentionally at the same suicide hotspot, a London high-rise with the well-earned nickname Topper''s Tower, they mutually agree to call off their plans for six weeks, forming an unconventional, dysfunctional family. They become media sensations as the Topper House Four and search together for reasons to keep on living.', '/ibtYPDUQXKK2CIYzMEWgt1VNMlP.jpg', '2014-03-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14811, 'Love Is All You Need', 126250, NULL, '/wlNvuEelOmUZpAbCuAn7kEADpps.jpg', 'Den skaldede frisør', 'Ida, a Danish hairdresser who has lost her hair to cancer, returns home from the hospital one day to find her husband is cheating on her. She decides to travel to Italy on her own for her daughter''s wedding, but discovers on arriving that the wedding gathering will present its own challenges.', '/nKeCYHHG8LCv2RuOpgS8jkRyihT.jpg', '2012-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14812, 'Everything or Nothing', 135921, NULL, '/hAeZVtiKlNoqFD9JACtbal9fcIS.jpg', 'Everything or Nothing', 'The story of three men with a shared dream: James Bond franchise producers Albert R. Broccoli and Harry Saltzman, and Bond creator and author Ian Fleming. It’s the thrilling and inspiring narrative behind the longest running film franchise in cinema history, which began in 1962.', '/j7ibOc2uYDZbIr7T0aaFMdIi6Ud.jpg', '2012-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14813, 'Don''t Talk to Strangers', 189492, NULL, '/odaPaWoSZyTlp3wnet82EtBGC50.jpg', 'Don''t Talk to Strangers', 'After Jane''s first marriage collapses, she and her new husband Patrick Brody attempt to build a new life and move to a new state. However, her ex-husband follows them with a view to revenge.', '/drYzDNODySjuKlokeiP7M0g4e7E.jpg', '1994-08-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14814, 'The Love Punch', 209249, NULL, '/5YnUQ5oRXjQcxuqwn76NoIxwRV2.jpg', 'The Love Punch', 'Retirement at last! Middle-aged and divorced, company owner Richard Jones is looking forward to a worry-free existence as he arrives at his office on his last day of work. Much to his dismay, he discovers that the management buyout of his company was fraudulent. The company is now bankrupt and the employee pension fund — including his own — has been embezzled. Enlisting the help of his ex-wife Kate, Richard sets out to track down the shady businessman behind the fraud.', '/iaJZm5z38RUi9czHxaiayN1OMAe.jpg', '2014-01-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14815, 'Victim of Love', 214318, NULL, '/mDj1b6JKIPw5IH4ucBgLyJyD207.jpg', 'Victim of Love', 'Therapist Tess falls for widowed professor Paul, who''s having an affair with Carla, one of her patients. Tess turns a dangerous page when she uncovers that Paul is not only the root of Carla''s emotional turmoil, he also murdered his wife in order to be with Carla.', '/2k0WF7qhxbR4YXodQaxVfZc73j.jpg', '1991-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14816, 'Getting Close to the Show', 951158, NULL, '/5fSoQkVE2QJazatbofe8MBzVXc1.jpg', 'Getting Close to the Show', 'Documentary on the making of ''Dante''s Peak'' (1997).', '/wk019sSQNtrDBlTZTQq41IeaQVo.jpg', '1998-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14817, 'Some Kind of Beautiful', 253344, NULL, '/fisrVuzjLMFsQP9VZbjMlwGF4Yr.jpg', 'Some Kind of Beautiful', 'By day, Richard Haig is a successful and well-respected English professor at renowned Trinity College in Cambridge.  By night, Richard indulges his own romantic fantasies with a steady stream of beautiful undergraduates.  But Richard has grown tired of the  game and is looking for something more meaningful and lasting.  So when Kate, Richard’s tanned, athletic, 25-year-old American girlfriend tells him that she is pregnant, Richard is thrilled.  He looks forward to having a family of his own,  being a father his children could be proud of, not some sex-fueled bobcat.  There is only one problem.  Richard’s not in love with Kate.  Richard is in love with Kate’s sister, Olivia. He had been in love with her ever since he first saw her.', '/ubuc8fRcT0I5lF4Q5P5lnyrZJJg.jpg', '2015-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14818, 'Completing the Golden Mile: The Making of The World''s End', 240972, NULL, NULL, 'Completing the Golden Mile: The Making of The World''s End', 'A documentary about the making of The World''s End. It is very thorough, hitting on virtually every aspect of the film''s production.', '/lwjB3xj4zyq0oVE37EsAXOpDb1H.jpg', '2013-11-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14819, 'In Search of James Bond with Jonathan Ross', 264022, NULL, NULL, 'In Search of James Bond with Jonathan Ross', 'Jonathan Ross delves into the world of James Bond and meets with new and former cast members who reveal humorous stories and anecdotes in a series of interviews. All the 5 Bonds at the time are featured, though only Lazenby (reflecting in the usual frank, self criticizing manner), Moore and Brosnan granted an interview. Connery and Dalton are featured through some unused footage from LWT''s 30 years of James Bond program. The ever faithful Desmond Llewelyn turns up in character as well as some other less related peeps like Christopher Lee, Paul McCartney and the ultimate playboy: Hugh Hefner -- who all give an interesting perspective on the worlds most famous spy.', '/d416YCqX42GzWaX6uzRe8iCnGtd.jpg', '1995-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14820, 'Murphy''s Stroke', 273552, NULL, NULL, 'Murphy''s Stroke', 'The horse Gay Future is at the centre of an Irish betting syndicate in 1974 which saw trainer Antony Collins present a poor performing horse at his stables. The betting stakes were subsequently raised, before the real horse was entered in the race.', '/f2TkT3C74iO7KETT2hEAx5bIDub.jpg', '1980-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14821, 'The Broken Chain', 287726, NULL, '/oUr7y5CLeO3xlK7cbbUtuOWSU0R.jpg', 'The Broken Chain', 'The true story of Iroquois warrior Thayendanegea participating in the French and Indian War and the American Revolutionary War.', '/uDsvEhM37f5XquZiGBWTa9KKvgB.jpg', '1993-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14822, 'Deep Blue', 11019, NULL, '/rtdGOcCW1vJYxk6uxk2VUV4Z0Q3.jpg', 'Deep Blue', 'Deep Blue is a major documentary feature film shot by the BBC Natural History Unit. An epic cinematic rollercoaster ride for all ages, Deep Blue uses amazing footage to tell us the story of our oceans and the life they support.', '/lzKirFeKspU0PktaX5BfdhSofcT.jpg', '2003-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
