INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14833, 'Giant', 1078581, NULL, '/53Ey8CIdc9jeS7fB4TCyxQTCjm6.jpg', 'Giant', 'Follows Prince Naseem Hamed from his humble beginnings on the tough working-class streets of Sheffield and his discovery by Ingle, himself a steel industry worker turned boxing trainer. Their unlikely partnership, Naz’s unorthodox style, cocky persona, and sheer dominance in the ring propelled them to the top of boxing’s elite and unprecedented levels of global superstardom, all in the face of the rampant Islamophobia and racism of ’80s and 90’s Britain.', '/1KKmUdFulYDVSV31nQt9LVm3Oue.jpg', '2026-01-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
