INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14836, 'American Ballet Theatre: The Dream', 313483, NULL, '/rZIkn9weknzwQyWhZz5JcyYeDJu.jpg', 'American Ballet Theatre: The Dream', 'Choreographed by Frederick Ashton in honor of William Shakespeare''s 400th birthday, this magical production -- based on the Bard''s play "A Midsummer Night''s Dream" -- features Felix Mendelssohn''s famed score and sublime sets that add to the charm. Ethan Stiefel delivers an impressive performance as the lordly Oberon, Alessandra Ferri shines as fairy queen Titania, and Herman Cornejo is pitch-perfect as the impish Puck.', '/4L2JAifqbGmTLkRzMaKgkZ7cW87.jpg', '2004-04-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
