INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14848, 'The Grand Finale', 70852, NULL, '/86gAxESpJgoaidaP6nHJgSjc90r.jpg', 'The Grand Finale', 'The 2006 FIFA World Cup was the 18th FIFA World Cup, the quadrennial international football world championship tournament. It was held from 9 June to 9 July 2006 in Germany, which won the right to host the event in July 2000. Teams representing 198 national football associations from all six populated continents participated in the qualification process which began in September 2003. Thirty-one teams qualified from this process, along with the host nation, Germany, for the finals tournament.  Italy won the tournament, claiming their fourth World Cup title. They defeated France 5–3 in a penalty shootout in the final, after extra time had finished in a 1–1 draw. Germany defeated Portugal 3–1 to finish third.', '/bVUFajoiJLp5kqeiXkthaz4ysRE.jpg', '2006-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14849, 'The Pig on the Hill', 545926, NULL, NULL, 'The Pig on the Hill', 'When Pig''s free-spirited and energetic new neighbour Duck plunges himself into Pig''s quiet, orderly life, Pig learns that having friends is what he has been missing all along.', '/dsMyEtoWgNuIcaPCuGrhItLxhIV.jpg', '2018-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14850, 'False Positive', 591634, NULL, '/8FHQFJGCuIuSQ8hC7Iyrd8fPdy7.jpg', 'False Positive', 'After months of trying and failing to get pregnant, Lucy and Adrian finally find their dream fertility doctor in the illustrious Dr. Hindle. But after becoming pregnant with a healthy baby girl, Lucy begins to notice something sinister through Hindle''s gleaming charm, and she sets out to uncover the unsettling truth about him.', '/3HSov8EW2fI3oQbUJxOvnf684ej.jpg', '2021-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14851, 'Whaledreamers', 43078, NULL, NULL, 'Whaledreamers', '"Whaledreamers" - the title alone evokes hypnotic visions of these most magnificent and ancient creatures. This visually stunning film offers an incredible glimpse into a rarely seen and scarcely understood tribal culture whose entire story of creation revolves around whales and has endured for centuries. The film passionately explores the connection between the subtle elegance of these “mothers of the sea” and ancient civilizations around the world whose culture and very existence is based on whales. Intertwining incredible underwater footage with ancient legend, whaledreamers examines the complex past and the possibly dire future of human civilization. Told with moving optimism and spiritual strength, it is a clarion call encouraging humanity’s reconnection to the profound beauty of the natural world and is an appeal to embrace all living beings thereby creating the unity and peace which the Earth itself can bring.', '/64SOV0PcRKIBQmHSQjbRy0d8zO1.jpg', '2006-06-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14852, 'The Goldfinger Phenomenon', 685315, NULL, NULL, 'The Goldfinger Phenomenon', 'A look at the marketing, advertising and merchandising of the James Bond movie Goldfinger (1964) including trailers, interviews, TV spots and rare promotional films.', '/eay4F0hMR1Zfe9k3OmWxwvqDCyf.jpg', '1995-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
