INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14856, 'Riverdance: The Animated Adventure', 756403, NULL, '/qqthj8EUL4QKlDBoMcPqeWvi6Ya.jpg', 'Riverdance: The Animated Adventure', 'A young Irish boy named Keegan and Spanish girl named Moya journey into a magical world of the Megaloceros Giganteus who teach them to appreciate Riverdance as a celebration of life. Based on the stage show phenomenon of the same name and featuring Bill Whelan’s multi-platinum Grammy Award-winning music.', '/i6TRDlVuuEXMyLSlIkDd8YhBN0r.jpg', '2021-05-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14857, 'Good Fortune', 437636, NULL, NULL, 'Good Fortune', 'GOOD FORTUNE is the rags to riches tale of conscious capitalism pioneer John Paul DeJoria. Born with nothing, at times homeless on the streets of LA, “JP” spent his early adulthood in and out of motorcycle gangs only to wheel and deal his way to the top of a vast hair and tequila empire. A modern day Robin Hood, JP’s motto is “Success unshared is failure.” The son of immigrants, JP defies the stereotype of ''the 1%'' and is the poster boy of the triple bottom line – people, planet and profit. A success story full of ups and downs, GOOD FORTUNE is the portrait of an extraordinary business man.', '/216XZMA0hrYdVVDLKtu1IQfE55.jpg', '2016-09-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14858, 'The Last Rifleman', 763144, NULL, '/aRTiGPgzE1S2F8IercFUmR19kxP.jpg', 'The Last Rifleman', 'A WWII veteran escapes his care home in Northern Ireland and embarks on an arduous but inspirational journey to France to attend the 75th anniversary of the D-Day landings, finding the courage to face the ghosts of his past.', '/co1GhkWdgt2J0LRTEJjHntkMrj3.jpg', '2023-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
