INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14867, 'Highly Classified: The World of 007', 423101, NULL, NULL, 'Highly Classified: The World of 007', 'His world is full of glamour, mystery and intrigue and now you get to be a part of it! Let gadget wizard Q (Desmond Llewelyn) be your guide to the ubiquitous lifestyle and thrilling adventures of the world''s most notorious secret agent. The undercover team will take you behind-the-scenes as they infiltrate the highly classified worlds of the man everyone knows as Bond -- James Bond. Hosted by Desmond Llewelyn who plays Secret Service gadget master Q. Boasts rare behind-the-scenes footage of spectacular stunts and explosive action sequences. Reveals the special effects magic behind the remotely-driven BMW, the rooftop motorcycle chase and death-defying skysrcaper jump. Interviews with Tomorrow Never Dies'' director Roger Spottiswoode and stars Pierce Brosnan, Jonathan Pryce, Michelle Yeoh, Teri Hatcher and Judi Dench.', '/kfE7hRnSvmZLFSZmDpKCYwtTotK.jpg', '1998-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
