INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14875, 'Cliffhanger', 1120556, NULL, '/pzGOeQL5UAgjz64kb7WxfglFbf1.jpg', 'Cliffhanger', 'During a weekend trip with a billionaire''s son, seasoned mountaineer Ray Cooper and his daughter Sydney are targeted by a gang of kidnappers. Ray’s other daughter Naomi, still haunted by a past climbing accident, witnesses the attack and escapes. To save her family, she must confront her fears and fight for survival.', '/92cL0rfm6eK6cUU8UciorsX0Fpg.jpg', '2026-08-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
