INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14877, 'Playing to Survive: Von Cramm vs. Hitler', 1337095, NULL, '/mZvApVWqE87PMmmaKiXqEgkGAY6.jpg', 'Playing to Survive: Von Cramm vs. Hitler', 'An untold story of a unique demonstration of bravery. It’s a love letter to Gottfried von Cramm, one of the forgotten tennis heroes of the 20th century, whose career and fame was shunned early on due to the rising rampant homophobia that prevailed after the Roaring Twenties — along with Adolf Hitler’s hidden agenda for the sports star.', '/ozCP2BE3r7SsNpQGXyArKHuVKWy.jpg', '2024-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
