INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14883, 'Easy Living', 80364, NULL, '/nh6IvmqGkQE5Vxz4Sqb2Zbnconl.jpg', 'Easy Living', 'J.B. Ball, a rich financier, gets fed up with his free-spending family. He takes his wife''s just-bought (very expensive) sable coat and throws it out the window, it lands on poor hard-working girl Mary Smith. But it isn''t so easy to just give away something so valuable, as he soon learns.', '/jAiagfGw23B79vmgHmNTKL7K7IT.jpg', '1937-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
