INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14885, 'Free Love', 565403, NULL, '/4wfVH6ITLHE368fBMkDu2JRvjra.jpg', 'Free Love', 'A wife''s psychiatrist tells her that she is being dominated by her husband. Her solution is to divorce him.', '/nXQag9de6YgRDQW4Km1onxv7xk2.jpg', '1930-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14886, 'Morals', 286226, NULL, '/vFmX8ABz1DuonMy5nsRUcYYplhu.jpg', 'Morals', 'Reared in a Turkish harem and threatened with marriage to a man she does not love, Carlotta escapes to London with an English adventurer. When he is killed, she is left destitute and attaches herself to Sir Marcus Ordeyne and begs his protection. He takes her home out of pity, and her charm and innocence cause him to fall in love with her. When he plans to marry her, Judith Mainwaring, who looks upon Carlotta as a rival, tells her he merely pities her and is marrying her to avoid a scandal. Carlotta runs away with Pasquale, a friend of Sir Marcus, though she loves her guardian. Later, Mrs. Mainwaring meets Carlotta in Paris and tells the girl the truth--that Sir Marcus is searching for her. Realizing his love for her, Carlotta is reunited with her benefactor.', '/AvisPnpOHEo2bpuSSByKnHKg3LI.jpg', '1921-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14887, 'Charlie Chan at the Race Track', 33387, NULL, '/yaNzyH7LFbNoBJlFgixwQRwOtBC.jpg', 'Charlie Chan at the Race Track', 'When a friend of Charlie''s is found kicked to death by his own race horse on board a Honolulu-bound liner, the detective discovers foul play and uncovers an international gambling ring.', '/n02zNAllSZq7KpEKTRTUtKV1955.jpg', '1936-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14888, 'Subway Express', 600455, NULL, '/wEYPXxtz6GM7Sw5yvfYxsfEpVw8.jpg', 'Subway Express', 'Inspector Killany of the New York City police department is called in to investigate the murder of a subway passenger and the usual-and-unusual suspects climb on and off at each stop.', '/eQqh5SSZPSuHZI5ymRVMvTlYM36.jpg', '1931-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14889, 'The Amazing Dr. Clitterhouse', 17885, NULL, '/8aPNj1OK7rSY33RZk4T2jBKCw7D.jpg', 'The Amazing Dr. Clitterhouse', 'A wealthy society doctor decides to research the medical aspects of criminal behaviour by becoming one himself. He joins a gang of thieves and proceeds to wrest leadership of the gang away from its extremely resentful leader.', '/7fPKRTXMbDMER4UG1FP4mr09Lll.jpg', '1938-07-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14890, 'The Greeks Had a Word for Them', 36783, NULL, '/hhCk02dAYqUSgEQEvOFlgc3mJRU.jpg', 'The Greeks Had a Word for Them', 'A trio of money-hungry women rent a luxurious penthouse, spending their dough on drink and debonair clothing, backbiting and catfighting as they steal each other''s boyfriends.', '/gPyCVzofmPg4wNOpPppiwCbX7ih.jpg', '1932-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14891, 'Queen Kelly', 42638, NULL, '/iS4APOsILdMylXr8UL7V101mHBx.jpg', 'Queen Kelly', 'In Kronberg, Ruritania, the planned wedding of Queen Regina and Prince Wolfram is disrupted when the prince falls in love with Patricia Kelly, a beautiful orphan at the convent. The prince kidnaps Patricia and takes her to the palace, but the queen drives her out. After a botched suicide attempt, Patricia unwillingly allows her scurrilous aunt to marry her off to a decrepit scoundrel. Undaunted, Wolfram follows Patricia to her new home in East Africa.', '/86kEZyMwfYZIxO28EHqmoBYPqN.jpg', '1929-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14892, 'Crazy to Marry', 335459, NULL, '/j9IULmQcyuioduGh8bOZkDSCjYa.jpg', 'Crazy to Marry', 'A doctor who believes he can cure criminals takes on a big challenge.', '/iHnkiQlgz3HiWwWvwFDkKeQlmtQ.jpg', '1921-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14893, 'The House of Mirth', 630051, NULL, NULL, 'The House of Mirth', 'Wharton creates a portrait of a stunning beauty who, though raised and educated to marry well both socially and economically, is reaching her 29th year, an age when her youthful blush is drawing to a close and her marital prospects are becoming ever more limited. The House of Mirth traces Lily''s slow two-year social descent from privilege to a tragically lonely existence on the margins of society.', '/dUfLx89dW4CfOaT7NRjOrJr6RIe.jpg', '1918-08-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14894, 'Parlor, Bedroom and Bath', 53571, NULL, '/tn9qzTCtXt1MlgvIdAcPStS13kT.jpg', 'Parlor, Bedroom and Bath', 'Jeffrey Haywood wants to marry to Virginia Embrey. However, Virginia refused to marry unless her older sister, the hard-to-please Angelica gets married first. Angelica, in turn, finds every man she knows too dull and predictable, and for this reason prefers to stay single. Jeff then tries to make Angelica interested in the mild-mannered and timid Reggie Irving passing him off as a notorious playboy to intrigue her. He asks his friend Polly to teach Reggie "how to treat a woman right", but he turns to be a disastrous learner.', '/y6vmo8pJjRBoByhdtIIJ7S10cvv.jpg', '1931-02-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14895, 'Being Respectable', 594971, NULL, '/85XOlWGRx287fDkRMcVFmWuAHJ.jpg', 'Being Respectable', 'Wealthy young Charles Carpenter is pressured by his family to marry Suzanne, even though he is really in love with young "flapper" Valerie. He gives in to his family''s pressure, however, and marries Suzanne, after which Valerie leaves town. Years later, after Charles and Suzanne have had a child, Valerie comes back to town and Charles realizes he is still in love with her, and she with him. Complications ensue.', '/8Q8aQIduJRf9fjKKK8uJ2Cpd3Ke.jpg', '1924-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14896, 'The Dawn Patrol', 46688, NULL, '/bbTVFFCIywOuyBWHwDoES2DvgU1.jpg', 'The Dawn Patrol', 'In 1915 France, Major Brand commands the 39th Squadron of the Royal Flying Corps. The young airmen go up in bullet-riddled "crates" and the casualty rate is appalling, but Brand can''t make the "brass hats" at headquarters see reason. Insubordinate air ace Captain Courtney is another thorn in Brand''s side...but finds the smile wiped from his face when he rises to command the squadron himself. Everyone keeps a stiff upper lip.', '/ncrQ21mjMTznDZDTmAcT3j5berB.jpg', '1938-12-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14897, 'Sioux Blood', 925462, NULL, NULL, 'Sioux Blood', 'One of John Waters'' two Tim McCoy westerns made with MGM in the last years of the silent era. A print is preserved at the George Eastman House in New York but it hasn''t been made available to the public and there don''t seem to be any plans for it.', '/vvU8OD9zLIowjOKEczKM3qZW62t.jpg', '1929-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14898, 'A Man Four-Square', 927530, NULL, NULL, 'A Man Four-Square', 'A Man Four-Square is a screen version of William McLeod Raine''s popular tale of a rancher who finds himself falsely accused of murder while attempting to help a friend in need.', '/1EWyEfioyGayfbdvfnffKlEQfYg.jpg', '1926-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14899, 'Three Smart Boys', 219462, NULL, '/rjc77CXUEAMkgcnoPJyPXmrhRyE.jpg', 'Three Smart Boys', 'When they overhear Miss Witherspoon, the school superintendent, say that nothing short of an epidemic will allow the school to be closed for a week, the Our Gang conspire to fake illness.', '/iTR4rf1NdkDYbtl97Ob90ZAElqj.jpg', '1937-05-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14900, 'Broadway Bill', 77198, NULL, '/nMzwClZuT1cYtppGuwB8XTciNLB.jpg', 'Broadway Bill', 'Tycoon J.L. Higgins controls his whole family, but one of his sons-in-law, Dan Brooks, and his daughter Alice are fed up with that. Brooks quits his job as manager of J.L.''s paper box factory and devotes his life to his racing horse Broadway Bill, but his bankroll is thin and the luck is against him. He is arrested because of $150 he owes somebody for horse food, but suddenly a planned fraud by somebody else seems to offer him a chance...', '/dDWQjYnnxNTsU99mpjr4CRPOry7.jpg', '1934-11-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14901, 'The Haunted House', 595631, NULL, '/5RisrIv67BbkuY9K8f9rtBxVoZP.jpg', 'The Haunted House', 'Four heirs to a family fortune are summoned to appear at the family estate for the reading of the will, where they meet the estate''s staff, which includes a nurse, a crazed doctor, and a sinister handyman.', '/a4np8B1Pq2zDpWyZgQZHrmxWj7n.jpg', '1928-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
