INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14903, 'Inspiration', 30632, NULL, '/bLP1saBBCWjEaAP2yDsgiSpD2MW.jpg', 'Inspiration', 'Yvonne is a beautiful model who loves frequenting the Parisian bohemian life, because she loves hobnobbing with artists.', '/lmdBc19g6RfR0grRibo8hORF2WY.jpg', '1931-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14904, 'Manslaughter', 166472, NULL, '/wYaoX4uso84Rjlmuc5871PkGOO3.jpg', 'Manslaughter', 'Society-girl thrillseeker Lydia''s fun comes to an end when she accidentally causes the death of motorcycle policeman.', '/xWyKsjzkexx0UrOWWLAeXMh8WeL.jpg', '1922-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14905, 'Criminal Lawyer', 240331, NULL, '/e0AN5l5eL1cp0FROKDAaBaDVYnX.jpg', 'Criminal Lawyer', 'Barry Brandon, a criminal lawyer, visits the night club of Denny Larkin, his primary client, with Betty Walker, a spoiled society girl. The police raid the club and Brandon pleads that the whole group is guilty, just to get even with Larkin for a rebuke. On the same night in court, Madge Carter is on trial for disorderly conduct, and Brandon volunteers to defend her, and proves the case against her if a frame-up. Finding that she is penniless, Brandon hires her as his secretary, and falls in love with her. Brandon is appointed district attorney and has ambitions of becoming the state governor. Having dinner at Betty''s home, she maneuvers him, while he is drunk, into marrying her. Later, Madge is a witness when Larkin shoots down a fellow gangster. By threatening Brandon''s life, he forces her to commit perjury at his trial, and say he fired in self-defense. Brandon, the prosecuting attorney (who has had his marriage to Betty annulled) knows she is lying but doesn''t know why.', '/cxrgWN7jakOxohCzUOFBZviUDrt.jpg', '1937-01-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14906, 'The Firefly', 43866, NULL, '/lc2gIwZreFmG9jz2X37paiTzqG6.jpg', 'The Firefly', 'Nina Maria Azara is the beautiful and alluring singing spy for Spain during the Napoleonic Wars. Her mission is to seduce French officers, in order for them to reveal Napoleon''s intentions toward Spain. She is sent to Bayonne, France to gather military secrets. Prior to this, she meets Don Diego while performing at a club. Unknown to her, Don Diego is actually Captain Andre, who is sent to Spain to spy on her. While in France, Nina discovers Diego''s true identity, only after she has fallen in love with him. Nina Maria outwits her potential captors, returns to Spain and goes into hiding. Napoleon''s troops invade Spain, resulting in Nina''s capture. In a strange twist of fate, Nina and Captain Andre are reunited, but the 2 nations are now at war...', '/gFJmgckbeKQ6emmxkVBLx2weaZm.jpg', '1937-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14907, 'The Emperor''s Candlesticks', 53853, NULL, '/767cpIPM78S9ioHyPmDoVzNqaFF.jpg', 'The Emperor''s Candlesticks', 'Spies on opposite sides fall in love in pre-revolutionary Russia.', '/geUo8IaO67Gw2lq5DI5RjLcj49b.jpg', '1937-07-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14908, 'Ruggles of Red Gap', 919480, NULL, '/fGlo5jIqgRS4UbBfHaSoplwmCxd.jpg', 'Ruggles of Red Gap', 'An English valet brought to the American west assimilates into the American way of life.', '/i9VI8CGK9vv4atDbRhDYGkD83Jw.jpg', '1923-10-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14909, 'The Vanishing Shadow', 181164, NULL, '/tqIYCnC0UiCI7PemwDdl9TkKcXG.jpg', 'The Vanishing Shadow', 'A 12-episode serial in which a son avenges the death of his father at the hands of corrupt politicians. He develops a wide variety of complex devices in his crusade . . . ray guns, robots and a ''vanishing belt.''', '/aljqB1O1wg9CetTSprOXIHKsak8.jpg', '1934-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14910, 'Win That Girl', 963033, NULL, '/x7xlmdaAYjUGJjVnXWAEacctfXn.jpg', 'Win That Girl', 'A gridiron rivalry between two colleges is entering its third generation, and the Norton family (father and grandfather were members of teams defeated by rival squads captained by members of the Brawn family) rears Johnny Norton, 3d, to be a star football player. The lad is underweight, however, and initially shows a talent only for drop kicking. During the big game, Johnny is substituted for another player and leads his team to victory, winning for himself the love of Gloria Havens.', '/6iR8lPyereiIN1hXzVbaqRmluEh.jpg', '1928-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14911, 'Fight for Your Lady', 242468, NULL, '/4mGJeqIgXmUG3NzU9yXpT5JdOns.jpg', 'Fight for Your Lady', 'Wrestling trainer puts himself in charge of a singer''s love life when the singer is jilted by a rich girl.', '/Aod16CFuTm6Ty3kgQne0WhgxmzU.jpg', '1937-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14912, 'Rhythm in the Clouds', 190787, NULL, '/zRzHGNCBd1x7WivQld3SYTd09eb.jpg', 'Rhythm in the Clouds', 'Judy Walker is a poor songwriter who, through mistaken identity, gets her songs played on the radio.', '/3skHdGEEYnqJqPICpEsbIFLsFbr.jpg', '1937-06-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14913, 'The Second Floor Mystery', 171629, NULL, '/5wAmV7csdEHV95ZTsshinaB4ly0.jpg', 'The Second Floor Mystery', 'In this mystery, a man and woman have been corresponding through a "personal" column under the names Lord Strawberries and Lady Grapefruit. When the man''s neighbor is found dead upstairs, he and the lady are the prime suspects of a police inspector, who has his own very good reason for blaming them.', '/3cbM8WdNXWXefdchTbJmQtzyhgv.jpg', '1930-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14914, 'One Rainy Afternoon', 206119, NULL, '/8BOoMB4biJz4Em0ZIBl14y0ywE.jpg', 'One Rainy Afternoon', 'Suave French actor Philippe Martin provokes a scandal when, in a darkened theater, he mistakes young Monique for his mistress, Yvonne, and tries to kiss her. Charged with assault, the quick-thinking Philippe claims it''s French tradition to do as he did, and is let go. To his surprise, Philippe learns that Monique has paid his fine. As the tabloids exploit the situation, Monique dates Philippe, until a photo appears of him kissing Yvonne.', '/57eB4CC6Ru3MOEIMkLaMAhkHUaW.jpg', '1936-05-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14915, 'He Was Her Man', 207083, NULL, '/kasdanXyD7EV4dV5YHvMmcppaG.jpg', 'He Was Her Man', 'A safecracker goes straight after doing a stretch for a bum rap. He agrees to do one last job for his "pals". He then flees from killers with a San Francisco fisherman''s fiancee.', '/1crNmJfvqaZJDJGY4kl07pDiKT2.jpg', '1934-06-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14916, 'The Poor Rich', 198243, NULL, '/2NqzFYTwQ8YDtEt6QyDnywIPKgK.jpg', 'The Poor Rich', 'Albert Stuyvesant Spottiswood and his cousin Harriet Winthrop Spottiswood arrive separately at their long abandoned and very much run down family manor, each unaware that the other is going to be there, and since both have become penniless, they are forced to move into the dilapidated house. When Albert receives a letter from old acquaintances Lord and Lady Fetherstone advising the Spottiswoods of their impending visit to the manor, the cousins are at wit''s end as to how to exercise non-existent skills required to make the old house acceptable for guest reception.', '/roSCm31stFEEX7N4IuAHm6lTnOx.jpg', '1934-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14917, 'The Wedding March', 42537, NULL, '/9ser9RnKEFh8XL1Q6S7b2nJH31B.jpg', 'The Wedding March', 'Against the backdrop of Vienna''s hidebound caste system, aristocrat and army officer Nicki is attracted to peasant Mitzi, although he knows it cannot last. Acquiescing to familial pressure, he ultimately gives her up to marry the more socially acceptable – albeit crippled – heiress Cecelia. Mitzi, for her part, is heartbroken and must resign herself to marrying churlish butcher Schani Eberle.', '/ej61Px6QKN1lTbkU9b1kqEHnWEW.jpg', '1928-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14918, 'The Girl Downstairs', 211691, NULL, '/lslvuKTUDs0SvmpxnDDPCw2dG34.jpg', 'The Girl Downstairs', 'A wealthy playboy surreptitiously romances a scullery maid to gain access to her mistress with whom he is in love, but doesn''t count on the maid falling in love with him.', '/hacLJyc5GY5C3CiHk8KvZPXrNRC.jpg', '1938-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14919, 'The 9th Guest', 179254, NULL, '/fQO8VM1ZoEUQXkJDhtarbTJ7dDV.jpg', 'The 9th Guest', 'Eight people are invited by an unsigned telegram to a penthouse apartment,  where they find themselves locked in and greeted by their unknown host''s voice via the radio, who explains that before the night is over each one will be die unless they manage to outwit the ninth guest, Death.', '/p8kkihcGPK6xdqpCUsQvaiVPhKA.jpg', '1934-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14920, 'Back Page', 222251, NULL, '/qc8hhKdVyIjqWYrfU6Qn2lIllG2.jpg', 'Back Page', 'A former New York reporter (Peggy Shannon) is hired as editor of a failing, small town newspaper in California.', '/zrj89S7gfo6pNBIONLTzwllCtHP.jpg', '1933-11-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
