INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14922, 'A Bankrupt Honeymoon', 233633, NULL, NULL, 'A Bankrupt Honeymoon', 'A Bankrupt Honeymoon is a 1926 American silent comedy film starring Harold Goodwin and featuring Oliver Hardy.', NULL, '1926-02-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14923, 'My Love Came Back', 232625, NULL, '/7O9GlpTyw1qQ8QV8taJL04lDmh1.jpg', 'My Love Came Back', 'Amelia is a gifted violinist who is in danger of quitting the Brissac Academy of Music. Julius arranges to have a scholarship given to her through his employee Tony so that Julius can escort Amelia to every musical event in the city. The trouble begins when he cannot meet her one night and Tony goes in his place. Tony believes that Julius and Amelia are a couple and then son Paul thinks that Tony and Amelia are a couple as he is sending her the money. The worst part is that Amelia might leave classical music for swing music with classmates Dusty, Joy and the band.', '/kynhluonP3AkHXQPM7RPM0sceu5.jpg', '1940-07-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14924, 'Broken Dreams', 223406, NULL, '/logRbrLNPiNFtFPFHfTdMvnHhYY.jpg', 'Broken Dreams', 'Medical intern Robert Morley is distraught after his wife dies in childbirth. He''s resentful of his new son and wants nothing to do with him. He leaves the child with his aunt and uncle and heads off to Europe to pursue his medical studies. Morley returns to his hometown six years later, now a successful doctor and engaged to be married to a beautiful socialite. He also feels differently about the boy and attempts to gain custody from his aunt and uncle.', '/rr90XP8lLlJ9DxfLSe0Ei3q3prl.jpg', '1933-10-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14925, 'The Strategy of Ann', 789134, NULL, NULL, 'The Strategy of Ann', 'A Short comedy starring Mabel Normand. The film is considered lost.', NULL, '1911-07-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14926, 'Oh Darling!', 992408, NULL, NULL, 'Oh Darling!', 'At a small hotel, Judith Barrett and Norman Peck are eloping; John Litel and Addie MacPhail are quarreling because of his constant jealousy; and Eva Thacher and Al Thompson are tracking down their eloping daughter. It''s a constant barrage of slamming doors and such trapping of the stage farce.', NULL, '1930-02-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14927, 'By Divine Right', 1198785, NULL, NULL, 'By Divine Right', 'Mildred, a young stenographer, seeks protection at the mission run by Austin Farrol, known as "The Prince," when her employer, Trent, an unscrupulous politician, attempts to seduce her. Mildred begins to work at the mission and falls in love with Farrol. Farrol is accused of arson when a fire started by Trent destroys the mission. However, he escapes when the train he rides crashes. Farrol assumes a disguise, and gets a position in Trent''s household. During a party, Trent''s child falls from a window and is believed to be permanently crippled, but Farrol, with "divine power," is able to cure her. A lost film.', '/lbHhZsbowJYgoguV7GdJtSujOjn.jpg', '1924-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14928, 'Let ''em Have It', 200787, NULL, '/5t1Vg5r92Aolc5cMSwNqflcqns1.jpg', 'Let ''em Have It', 'Let ''Em Have It is a 1935 gangster film. It was also known as The Legion of Valour and False Faces. An FBI agent tracks down a gang leader.', '/gjooqZ2V1VoNvvo4pxFGuCBqseO.jpg', '1935-05-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14929, 'Breakfast for Two', 83240, NULL, '/94XikBlAUQOwAqHW5C56akC0TlV.jpg', 'Breakfast for Two', 'After a night on the town, Jonathan Blair wakes to find that Texan Valentine Ransome has escorted him home. Valentine is attracted to Jonathan and sets out first to reform him, and his family''s near-bankrupt shipping company, and then to marry him. In her way is Jonathan''s fiancée, actress Carol Wallace.', '/amtKYOhdWh0jxQtRJdciPZOrwvg.jpg', '1937-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14930, 'Reducing', 260525, NULL, '/8vx22MnrC5QiElq0Y1GI1MKt06U.jpg', 'Reducing', 'Culture shock bombards a woman and her family when they leave their hick town to help her sister out in her big-city beauty parlor.', '/2bP8MeQ8faeliExIUlubzcYWvNY.jpg', '1931-01-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14931, 'The Ragged Princess', 1010534, NULL, NULL, 'The Ragged Princess', 'After running away from an orphanage, young Alicia Jones disguises herself as a boy and gets a job on a farm. She falls in love with Harry Deigan, a farmhand who knows her secret, but when the farm''s owner finds out, he fires her. Alicia is forced to return to the city, where she meets up with a wealthy man who adopts her. He turns out to be Thomas Deigan, the half-brother of Alice''s love Harry Deigan. Harry finds out that Thomas is his half-brother, but also finds out something that could change his, Thomas'' and Alicia''s lives forever.', '/dErrsXMPBwWYB19MsQgxycf0zEY.jpg', '1916-10-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14932, 'Magnificent Obsession', 47920, NULL, '/aWG6Cfu2Sl2fBaStUMB0wlg31je.jpg', 'Magnificent Obsession', 'A playboy tries to redeem himself after his careless behavior causes a great man''s death.', '/zcBLLMeKUjW1igNGwQ71njzB0Iz.jpg', '1935-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14933, 'His Captive Woman', 295972, NULL, NULL, 'His Captive Woman', 'Cabaret dancer Anna Janssen kills her sugardaddy and escapes to a South Seas island on the yacht of a wealthy admirer. Stolid, conscientious Tom McCarthy, a New York detective, is sent after Anna and arrests her, chartering a steamer to bring her back to the United States. The steamer sinks, and Anna and Tom are stranded on a small island. They fall in love, and Tom''s influence brings about a benign change in Anna''s character. They are rescued, however, and Anna is placed on trial for her life. Tom takes the stand in her defense and informs the judge of Anna''s conversion in the solitude of the island. The judge instructs Tom to marry Anna and then sentences them to life--on the island where they found happiness together.', '/odiqOGmrrtAZYu14Ib4AKbGmEYR.jpg', '1929-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14934, 'Midnight Madness', 257341, NULL, NULL, 'Midnight Madness', 'In Midnight Madness millionaire diamond miner Michael Bream (Clive Brook) discovers that the woman he’s marrying — funfair shooting-gallery hostess Norma Forbes — is a gold digger. So Bream decides to teach her a lesson, and forces her to live with him in the remote African outback where, eventually, she realizes her true affections.', '/skzUoYSIoQtZsGDpluatQCx0NxM.jpg', '1928-03-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
