INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14936, 'Follow Thru', 156347, NULL, '/rBWxQKyVlxSsXwKGuQGQPjXGcdk.jpg', 'Follow Thru', 'Lora Moore, the club champion, loses a golf match to a woman from another golf club. Then Jerry Downs, a handsome golf pro, and his goofy friend, Jack Martin, show up. Lora takes him on as her golf teacher to work on her putt. She falls for him, but so do several other women. Meanwhile Angie Howard, Lora''s friend, chases after Jack. A lot of silliness ensues.', '/ightSmqeBPCV4e4EenOI1UgRAgw.jpg', '1930-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14937, 'The Bishop Murder Case', 61546, NULL, '/19Yug55d355dIpwYrUxVuMXdX95.jpg', 'The Bishop Murder Case', 'The murders start with the body of Robin. He is found with a arrow through the heart, but Vance deduces that the body was placed and not found where he was killed. The note found dealing with the murder was part of a nursery rhyme and signed by ''Bishop''. The only witness may have been Mrs. Drukker and Adolph, but they are not talking. As the murders progress, each one is accompanied by a nursery rhyme. It is up to Philo Vance to unravel the clues and unmask the identity of the murderer ''Bishop''.', '/lNueCH8pzU8alf1c9hXlZiwYUV0.jpg', '1929-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
