INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14957, 'Redemption', 206247, NULL, '/nyyl3Fxg5Ly2zZJLJnJJwzYLWtg.jpg', 'Redemption', 'In Russia in the early 1900s, Fedya, a handsome, self-indulgent womanizer, falls in love with and marries Lisa, his friend Victor''s fiancée. Fedya quickly tires of domestic life and resumes his profligate ways, drinking and gambling away his family''s fortune. Lisa refuses to leave him despite his deplorable ways, so he takes drastic measures to ensure that she will no longer be harmed by his actions and reputation.', '/wPvt1LpzKhwCJP0pO6tt4ubnOPg.jpg', '1930-04-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
