INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14960, 'Playboy of Paris', 266385, NULL, '/ndMWk2zfAMlgdJs30lHf63AfJ7X.jpg', 'Playboy of Paris', 'Yvonne, daughter of Philibert, a Paris cafe owner, is in love with dreamy, blundering Albert, a waiter, though he pays little attention to her. Philibert plans to marry his daughter to a wealthy Parisian, but upon learning that Albert is to come into a large inheritance, he conspires to place him under a longterm contract, confident that he willingly will pay a forfeit to break it.', '/4lyojY8Perk2vE6Ec7yvEOiL9NO.jpg', '1930-10-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
