INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14963, 'The Sun Never Sets', 235042, NULL, '/ewuFlHcb3Gr2xneRbduUdVQgkq6.jpg', 'The Sun Never Sets', 'The Randolph family have a tradition of working in the British colonial service. Clive comes home from a mission in the Gold Coast of Africa accompanied by his wife Helen. He discovers his younger brother John, is not keen on following in his footsteps. John is then persuaded to try colonial service by his grandfather. He is accompanied by Clive who has been sent to investigate the source of a series of radio broadcasts that are sewing unrest throughout the world. These may be linked to Hugo Zurof, a man plotting to rule the world.', '/hIEFYe9v64BnkLetqwBZ0GPz0ma.jpg', '1939-05-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
