INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14973, 'Fast and Furious', 169822, NULL, '/nTh7GgGH4dA4lZapoXlQFAFduYq.jpg', 'Fast and Furious', 'Joel & Garda Sloan, a husband and wife detective team, who also sell rare books in New York, take a vacation to Seaside City. At Seaside, Joel''s pal, Mike Stevens is managing and preparing for their beauty pageant. Joel is made one of the judges plus he has invested $5,000 in it, to Garda''s dismay. Eric Bartell, promoter, arrives to dupe Stevens. When Ed Connors, New York racketeer arrives, Bartell is mysteriously murdered. Joel and Garda set out to investigate the murder.', '/rdQrh59Gq0DX8OmoQeECUtBkoH5.jpg', '1939-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14974, 'Arsène Lupin Returns', 127812, NULL, '/2F57WhHhzZYKqg8LsfWbcz4C8zu.jpg', 'Arsène Lupin Returns', 'A woman and a man vying for a woman''s affection: the usual love trio? Not quite so since the belle in question is Lorraine de Grissac, a very wealthy and alluring society woman, while one of the two rivals is none other than Arsène Lupin, the notorious jewel thief everybody thought dead, now living under the assumed name of René Farrand. As for the other suitor he is an American, a former F.B.I. sleuth turned private eye by the name of Steve Emerson. Steve not only suspects Farrand of being Lupin but when someone attempts to steal a precious emerald necklace from Lorraine''s uncle, Count de Brissac, he is persuaded Lupin is the culprit. Is Emerson right or wrong? Which of the two men will win over Lorraine''s heart?', '/3yHqgzR5uUQ7IUf1pGzsufn47g6.jpg', '1938-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14975, 'The Preview Murder Mystery', 251271, NULL, '/rhZFWdnmpywRXqkLbxpuOV1qiSe.jpg', 'The Preview Murder Mystery', 'Someone is murdering the cast and crew of a new Hollywood movie, and the leading lady may be next. As a police detective locks down the lot and refuses to let anyone leave, the studio’s publicity head and his secretary attempt to solve the murders themselves.', '/8Zb5DHeiXb8TBZZG7remCOByGy5.jpg', '1936-02-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
