INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14981, 'The Body Disappears', 99673, NULL, '/dxbVA0wJPTiM4bXkOx21ht0AiHu.jpg', 'The Body Disappears', 'Wealthy scion Peter DeHaven, about to marry socialite Christine Lunceford, wakes up after bachelor party revelry to find he''s been turned invisible by eccentric college professor Reginald Shotesbury. An unbelievable series of events is revealed by several witnesses testifying in a "mystery trial" to determine the reason for DeHaven''s "disappearance".', '/mlHuoLQrQouiiEOb8Z6CjOStMCZ.jpg', '1941-11-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14982, 'A Dangerous Affair', 337442, NULL, '/2B9iB9fyDfkRDDLBDlsyDLTsa5P.jpg', 'A Dangerous Affair', 'Holt plays police lieutenant McHenry, while Graves is his friendly rival, crime reporter Wally Cook. After the two men verbally duel over a variety of details, they hunker down to business, that of solving the murder of a lawyer who was in the midst of reading a will to a motley collection of heirs.', '/mJE9jRu6Ic35IHERPKXL55AS9hu.jpg', '1931-09-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
