INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14984, 'The Blackbird', 111302, NULL, '/lOq8hYyOST1IlAxVpQAMffr4F3c.jpg', 'The Blackbird', 'Two thieves, the Blackbird and West End Bertie, fall in love with the same girl, a French nightclub performer named Fifi. Each man tries to outdo the other to win her heart.', '/idRhSavLX2sAECg4mEqK6ru4sau.jpg', '1926-02-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14985, 'Show People', 31404, NULL, '/lIO8ZVTVRemo4gQMsvMzdNh86Eb.jpg', 'Show People', 'Hollywood hopeful Peggy Pepper arrives at a major studio, from Georgia, to become a great dramatic star. Things don''t go entirely according to plan.', '/kMf0YYCNMqUbS9cTJBTCWcvsXEn.jpg', '1928-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14986, 'Shanghaied Love', 600468, NULL, NULL, 'Shanghaied Love', 'Captain Angus Swope (Noab Beery), known as The Black Yankee, skipper of the Golden Bough, treats his crew shamefully and he treats women no better, as evidenced by his handling of a woman he has abducted, together with her baby daughter, Mary (Sally Blaine), from seaman Newman (Willard Robertson). When the woman dies as a result of his cruelty, he brings up Mary as his own daughter.', '/t7MjUhQfSjS0ZYL5sZONzhdjVf5.jpg', '1931-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14987, 'The Matinee Idol', 75429, NULL, '/obsfV8tTKi6aBi7WfV3YQuT7Ual.jpg', 'The Matinee Idol', 'The famous matinee idol and blackface comedian, Don Wilson, heads out of town to escape adulation. There, calling himself Harry Mann, he accidentally joins a traveling acting troupe, and falls in love with Ginger Bolivar, who runs the troupe and stars in their Civil War melodrama. Don''s producer sees the play, and thinks it''s a comic masterpiece, and just what Don''s Broadway show needs. But when Ginger finds out she''s been played for a fool, will she forgive Don?  Preserved by the Academy Film Archive in partnership with Sony Pictures Entertainment, Inc. in 1997.', '/oJ07uptDt7N79st0cqUnzmaq7xL.jpg', '1928-03-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14988, 'Birds of Prey', 407684, NULL, '/eclKwml0ZbCLRHhz2dOwZl8wLel.jpg', 'Birds of Prey', 'Helen Wayne and Archie Crossley, two clever pickpockets, rob J. Hamilton Smith, a well-known metropolitan banker, and he is later recognized by one of their gang as a former prisonmate; they demand a price for their silence, and he is forced to accede.', '/aKg1SC3ImkDNWCTwggNSD19phZ9.jpg', '1927-03-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14989, 'Invisible Enemy', 410757, NULL, '/28VrBNAJIkQGAdVrBSh81Vpgsid.jpg', 'Invisible Enemy', 'Jeffrey Clavering is hired in London by The Great Eastern Oil Corporation to go to Paris to prevent unscrupulous industrialist Nikolai Kamarov from gaining control of their oil fields and turning them over to a foreign power.', '/xacy5OlIo3Xgwd3VlJcB1oCIUg4.jpg', '1938-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14990, 'No Time for Comedy', 132928, NULL, '/1B9lkqsOFgsyr22M8oGGOA0YdNQ.jpg', 'No Time for Comedy', 'An aspiring playwright finds himself an overnight Broadway success.', '/ovaAAdww9ht6DXqXIkQSAv3qDpM.jpg', '1940-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14991, 'The Honeymoon', 912596, NULL, '/k4J2FlWbgBZZEorfVCsDEAU8emf.jpg', 'The Honeymoon', 'The  honeymoon of Prince Nicki in the Alps, and the wedding of Mitzi and Schani. Mitzi still loves Nicki, and jealous Schani decides once again to kill the prince. Schani shoots at Nicki, but Cecilia throws herself in front of Nicki. Schani becomes a fugitive and goes into hiding. Nicki and Mitzi meet one last time, where Mitzi tells Nicki that she will go to a convent. Nicki goes off to war, where he is killed. Sequel to von Stroheim''s The Wedding March released only in Europe. The only known copy was destroyed in a fire at the Cinémathèque Française in 1959.', '/6rdIjft0x8pqIVKkllVN80yayeO.jpg', '1929-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14992, 'The March Hare', 766508, NULL, NULL, 'The March Hare', 'Lizbeth Palmer is known as "The March Hare" among her friends, and the daughter of a Los Angeles millionaire, comes to New York with a chaperon to visit her aunt. After betting the chaperon that she can live on 75c for an entire week, she assumes the part of a flower girl in a restaurant and there makes a hit with young millionaire Tod Rollins, who invites her to his home.', '/vNSrSvAMt0X3Nn2njRzD0lD9MJ.jpg', '1921-06-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14993, 'The Outside Woman', 1326199, NULL, NULL, 'The Outside Woman', 'Thinking it is a worthless trinket, Dorothy trades her husband’s prized Aztec idol to a street peddler in exchange for a beautiful silk shawl. She soon discovers the idol is actually an extremely valuable artifact. Desperate to retrieve it before her husband notices, she learns that it has already been purchased by their neighbor, an artist named Cambridge. Dorothy enters Cambridge’s apartment to recover the idol secretly. Her efforts lead to a series of comedic misunderstandings and frantic situations as she tries to protect her marriage and her husband''s property.', '/b3B9DE5MpWinfO7r7O1RPJ7GfDk.jpg', '1921-02-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14994, 'Anybody''s Woman', 352654, NULL, '/8SEpLWUDQq6pdi2qen2n7WBXpM3.jpg', 'Anybody''s Woman', 'A lawyer, left by his wife, gets drunk and marries a chorus girl, or so he learns the morning after.', '/5pavh7Byt2fwC9w3RiacM4nLH23.jpg', '1930-08-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14995, 'Massacre', 178348, NULL, '/r296eyKJ7ANGM8ldhmO8NqVZdZV.jpg', 'Massacre', 'Upon the death of his father, who was the tribal chieftain, Joe Thunder Horse returns to the reservation of his youth, only to discover that his people are dying of various diseases and are being systematically cheated of their possessions and basic rights by crooked Indian agents. He heads to Washington in hopes of righting these wrongs, only to experience prejudice and hatred all along the way.', '/4BD0r0sDLeaD9cYLJTAVQ3S6gQV.jpg', '1934-01-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14996, 'Sporting Blood', 246874, NULL, '/z5pCSyYkdQiG5YuHK8r68cDjXP0.jpg', 'Sporting Blood', 'A horse with great potential is reluctantly sold by the breeder and by chance passes through multiple hands who do not treat him well.', '/uFf9AMyhsHq5JCyuGDZcL4y4jBu.jpg', '1931-08-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14997, 'Tangled Destinies', 156372, NULL, '/3JTxbpiPAKmCQgtKFev6CPbp0GB.jpg', 'Tangled Destinies', 'An airliner makes a forced landing at night in the desert. The passengers and crew take refuge in a nearby deserted house. Soon some of the passengers are found murdered, and one of the passengers reveals himself to be a detective who was guarding one of the murdered passengers, who was carrying a bag of diamonds--which is now missing. The detective must find out which of the passengers is the killer.', '/svWfBO5YtfQyNYPPYnfa4THe3VB.jpg', '1932-10-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14998, 'Corruption', 164304, NULL, '/r0tdp7JyOBYfDnY7NJDm1gwboei.jpg', 'Corruption', 'A young lawyer is elected mayor of the city and promises to rid it of the corruption it''s famous for. The problem is that most of the corruption he''s vowed to eliminate is caused by the crooked political machine that helped elect him.', '/lF7wV0wG6l7TwBXw1ZghfsB9izU.jpg', '1933-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (14999, 'Our Daily Bread', 126136, NULL, '/v21vRUTcv0nhbfUdKehTKI3Lspq.jpg', 'Our Daily Bread', 'John and Mary Sims are city-dwellers hit hard by the financial fist of The Depression. Driven by bravery (and sheer desperation) they flee to the country and, with the help of other workers, set up a farming community - a socialist mini-society. The newborn community suffers many hardships - drought, vicious raccoons and the long arm of the law - but ultimately pull together to reach a bread-based Utopia.', '/xbJ3osnuxaKckhhG7e6DFUF2I03.jpg', '1934-10-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15000, 'Outcast Lady', 177415, NULL, '/x2whk1z26Si3A1Wjfqtk9VYGFQ8.jpg', 'Outcast Lady', 'A woman''s dubious past proves to be a stumbling block when she becomes engaged to marry.', '/Ad4IiPiAatsz1aSL5BygUEMA737.jpg', '1934-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15001, 'Sinner Take All', 155532, NULL, '/dtkfNq67WQk9jAhZG2dySqSyU8r.jpg', 'Sinner Take All', 'A young lawyer is determined to identify who is murdering members of a wealthy New York publishing family.', '/nUVeOgvrZuR1CJCRKTpsMAxDX7Y.jpg', '1936-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15002, 'Changing of the Guard', 440644, NULL, NULL, 'Changing of the Guard', 'On New Year''s Eve, a girl is told a story by her grandfather about his days in a military regiment; then, the girl dreams she''s at the Changing of the Guard ceremony at Buckingham Palace.', NULL, '1936-06-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15003, 'Painting the Town', 438663, NULL, '/5jEBhe7TTU3HtwjoWdqZzIDvcYx.jpg', 'Painting the Town', 'Glenn Tryon and Patsy Ruth Miller, headed the cast of Universal''s Painting the Town. In his first starring role, Tryon is cast as bucolic inventor Hector Whitmore, who falls for flirtatious city gal Patsy Deveau (Miller). Misinterpreting her fluttering eyelashes as a sign of true and lasting love, Hector follows Patsy to New York, much to the dismay of the girl''s wealthy fiance.', NULL, '1927-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15004, 'Thundering Tenors', 444477, NULL, '/2V0PfSsp2lw0DreRFDvX5Ku4KQR.jpg', 'Thundering Tenors', 'Charley is invited to a high class party, where he feels ill at ease and has no idea how to act, yet he wants to impress his young lady.', '/ujB4JHTKBwpvpXGVBtB94eqyQlV.jpg', '1931-02-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15005, 'The Monster Walks', 95560, NULL, '/5XGobuLZa1FjbGHpzz8QTWqSv9z.jpg', 'The Monster Walks', 'Ruth Earlton has come home to her ancestral mansion to claim her inheritance.  Accompanied by her boyfriend, she discovers that her father died suddenly under suspicious circumstances.  Now it''s her turn, as her deranged and relentless uncle targets her for death with the help of his wife and son, plus a very unhappy ape.', '/c2MEDsZHT2zYCTXnYbsL2JyfWKO.jpg', '1932-02-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15006, 'The Phantom of the Air', 162788, NULL, '/ycogat2jVquZwcRJ4EA2KaDS8CV.jpg', 'The Phantom of the Air', 'An adventure serial presented in 12 chapters. Inventor Thomas Edmunds uses a super plane, ''The Phantom,'' to protect his new anti-gravity invention, the Contragrav, from theft.', '/3VMSGD3MvUqNV2WAkYfugsdLnNq.jpg', '1933-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15007, 'My Best Girl', 73969, NULL, '/5qmVGP7BPZUQ3Sjyoz78qub8lHX.jpg', 'My Best Girl', 'Joe Merrill, son of the millionaire owner of a chain of 5 and 10 cent stores, poses as Joe Grant, and takes a job in the stockroom of one of his father''s stores, to prove that he can be a success without his father''s influence. There he meets stockroom girl Maggie Johnson, and they fall in love. This causes problems, because Mrs. Merrill had planned for her son to marry Millicent Rogers, a high society girl.', '/30K2vL1L4TnTmAlZQj3ArUxHdgj.jpg', '1927-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15008, 'Dangerously They Live', 71433, NULL, '/brrp8p83cDUI68XEas3vjwv6UPS.jpg', 'Dangerously They Live', 'A New York City doctor tries to rescue a young woman from Nazi agents.', '/xXvxWDwDaVvfZzP4W1Fy7vxKjHu.jpg', '1941-12-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15009, 'The Washington Masquerade', 246876, NULL, '/muejPA4IznRTjObZNFD22I9iA5a.jpg', 'The Washington Masquerade', 'An honest, talented and well respected attorney defeats a corrupt incumbent U.S. Senator. After a very good start he has to face the subtle temptations and innocent looking traps of Washington.', '/wQwJ2R6bTXdbaCZUywYIXbjnWFS.jpg', '1932-07-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15010, 'Zudora', 174098, NULL, NULL, 'Zudora', 'Zudora, not knowing she''s an heiress to a $20 million fortune, lives with her uncle, a mystic and detective, who covets her inheritance. She wants to marry John Storm but her uncle is against it. However, the uncle makes a bargain; if Zudora can solve the next twenty mysteries brought to him, she can marry as she chooses. Episodes 1,2 and 8, plus another unidentified chapter, survive. The rest is believed to be lost.', '/gH3gJcDP9WBtbOn53QE6j9Ry3ms.jpg', '1914-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15011, 'Uncle''s Namesakes', 191912, NULL, NULL, 'Uncle''s Namesakes', 'An American family in need of some money decides to pull a little innocent scam on a wealthy English relative.', '/8NOGdoOrWTFm5Y1cxJDFVa8Fgxv.jpg', '1913-12-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15012, 'Merry-Go-Round', 114324, NULL, '/sw2d908d2n8eg35TRzDCDlvtDJh.jpg', 'Merry-Go-Round', 'A nobleman posing as a necktie salesman falls in love with the daughter of a circus puppeteer, although he''s already wed to the daughter of his country''s war minister.', '/tI0ZgiwUJ9yRu24IPaocsBeMf99.jpg', '1923-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15013, 'Little Orphan Annie', 108666, NULL, '/zAzXNpSHQaynCVjqg4YQGbtQ0vw.jpg', 'Little Orphan Annie', 'Millionaire Daddy Warbucks goes bust in the Great Depression and is forced to abandon his adopted daughter, Annie.  While he''s out west working on another fortune, Annie finds an orphaned boy on the streets and helps him find a home.', '/baPt81o6DU8nym1vhfqLX4CyRoD.jpg', '1932-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15014, 'Why Men Leave Home', 509648, NULL, '/9cwhQmt9bcC99aouMHrYwZqf75T.jpg', 'Why Men Leave Home', 'John and Irene Emerson''s marriage begins well enough, but it is not long before John becomes less attentive. Feeling neglected, Irene spends more time with her girl friends, and John, consequently, falls prey to the vamping wiles of his secretary, Jean Ralston. When John comes home from the theater smelling of Jean''s perfume, Irene procures a divorce; John then marries Jean.', '/e793ivkyNOhj7z6oSArTlJTUY2P.jpg', '1924-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15015, 'Children of Pleasure', 261720, NULL, '/hoI3L1zKvj1IsxTHuR9Tu3s9J5j.jpg', 'Children of Pleasure', 'A successful songwriter, dazzled by high society, falls for a society girl who is just playing around.', '/jjuYbTjQ60oPC5tVA2PkK311Q0p.jpg', '1930-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15016, 'A Slave of Fashion', 511605, NULL, '/5LZxiWPHw9mP3jZw4i0ibzjvu95.jpg', 'A Slave of Fashion', 'Katherine Emerson, an Iowa girl hungry for the good things in life, leaves her small hometown and sets out for New York. En route, she is involved in a train wreck in which another woman is killed. Katherine finds the woman''s purse and, among its contents, discovers an invitation for the woman to spend 6 months in an unoccupied luxury apartment in Manhattan. Katherine seizes this opportunity and sets up housekeeping in the elegant suite, living well and dressing in the newest fashions.', '/9MzJkNZny8n7wNiBafl2cYr5vKL.jpg', '1925-08-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15017, 'Saturday''s Millions', 513322, NULL, '/4vfExzGlzLb1ke3RkfwMcUI5lbn.jpg', 'Saturday''s Millions', 'Jim Fowler is Western University''s football hero and is constantly besieged by reporters. Jim''s father Ezra comes to visit him and becomes reacquainted with an old Western football chum, Mr. Chandler, who happens to be the father of Jim''s girlfriend Joan. Jim keeps his roommate, Andy, busy by sending him to collect money on their laundry concessions business, even though Andy is desperately trying to meet his girlfriend Thelma, who has just come for a visit. When the coach tells Chandler and Fowler that Jim is nervous and erratic, Chandler invites Jim to spend the night before the big game at his home.', '/yyDzC4RfDmtfWHOVLXbHic7plD9.jpg', '1933-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15018, 'The Merry Widow', 53230, NULL, '/gITA1IgbVz4qBOWDD54E8rSIK2m.jpg', 'The Merry Widow', 'Prince Danilo falls in love with dancer Sally O''Hara. However, his uncle, King Nikita I of Monteblanco, forbids the marriage due to her being a commoner. Thinking she''s been jilted by her prince, Sally marries lecherous old Baron Sadoja, whose wealth has kept the kingdom afloat. When he suddenly dies, Sally must be wooed all over again by Danilo.', '/7cicZpacvh3MINqNorntTl8xdOY.jpg', '1926-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15019, 'The Phantom of Paris', 95862, NULL, '/jDBInktFzyTbirZHA7y5bQ7wkU2.jpg', 'The Phantom of Paris', 'Chéri-Bibi is a world class escape artist, but he cannot escape the false murder charge that is placed on him.', '/mbSSvn5LDaFUHHGlbyLAxVNSwux.jpg', '1931-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
