INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15021, 'The Little Giant', 27991, NULL, '/33hTF4n2Y7XeEVXLxhQ3nElwNM1.jpg', 'The Little Giant', 'Prohibition is ending so bootlegger Bugs Ahearn decides to crack California society. He leases a house from down-on-her-luck Ruth and hires her as social secretary. He rescues Polly Cass from a horsefall and goes home to meet her dad who sells him some phony stock certificates. When he learns about this he sends to Chicago for mob help.', '/n7YHYu2JO0zBCEsBW8lKRBvpTgr.jpg', '1933-05-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
