INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15024, 'The Littlest Diplomat', 234249, NULL, NULL, 'The Littlest Diplomat', 'Young Sybil visits her grandfather, a British Colonel stationed at a garrison in India, and she helps negotiate a diplomatic truce between him and the local natives.', '/x8qgDdDLcxR3IavdPtGh6xeTnxd.jpg', '1937-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
