INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15026, 'My Official Wife', 548929, NULL, '/6wsSnRNAiKEtJYnh79Cl4QNoOCG.jpg', 'My Official Wife', 'A glittering drama of Imperial Russia in the days before the Revolution and the reckless life of the aristocracy in the days of the Czar, featuring gorgeous gowns, beautiful women and spectacular settings.', '/2VvirkWm0dM8Rc0wiQQV6N3hLFu.jpg', '1926-10-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
