INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15028, 'The Bill of Rights', 562487, NULL, NULL, 'The Bill of Rights', 'This short subject is a lavish costumed color production which dramatizes the birth of the American Bill of Rights. It depicts leading political figures of the American Revolution and the despotic British colonial rule which led to the creation of the Bill of Rights.', '/sOqRF8jCisFwbTBmTsYxp8qk9sq.jpg', '1939-08-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15029, 'Red-Headed Woman', 77966, NULL, '/cBsgEJhxaR1hGOOWR68A6sWXAMs.jpg', 'Red-Headed Woman', 'Lil works for the Legendre Company and causes Bill to divorce Irene and marry her. She has an affair with businessman Gaerste and uses him to force society to pay attention to her.', '/3Iv5sY7qWljRFEHQ3qsgRetIboC.jpg', '1932-06-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15030, 'What Every Woman Knows', 234939, NULL, '/E5OcBHn8QpEl0uoVI9jWf9Emqw.jpg', 'What Every Woman Knows', 'Aspiring young Scottish politician John Shand enters into an unusual agreement with the wealthy Wylie family -- if they fund his education, he must marry their daughter, Maggie. Staying true to his word, John weds Maggie and begins a successful career, thanks largely to his savvy wife. The couple''s relationship is placed in jeopardy when John faces temptation in the form of the lovely aristocrat Lady Sybil Tenterden.', '/4SQHFGu4IqxkoPqhkwh10Qi9Ayp.jpg', '1934-10-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15031, 'The Rage of Paris', 43856, NULL, '/jI8CqKSbhN9TlRlgdXulWpf2EhA.jpg', 'The Rage of Paris', 'Nicole has no job and is several weeks behind with her rent. Her solution to her problems is to try and snare a rich husband. Enlisting the help of her friend Gloria and the maitre''d at a ritzy New York City hotel, the trio plot to have Gloria catch the eye of Bill Duncan, a millionaire staying at the hotel. The plan works and the two quickly become engaged. Nicole''s plan may be thwarted by Bill''s friend, Jim Trevor, who''s met Nicole before and sees through her plot.', '/lkcecPOr93hqwgjJpFAjY68RWsr.jpg', '1938-06-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15032, 'A Huntress of Men', 600669, NULL, NULL, 'A Huntress of Men', 'Upon hearing about a woman dubbed The Huntress because of her wild attention craving ways, Fleming Harcourt decides he can domesticate her and they marry. He takes her to settle down in a mining town, however she soon becomes bored and returns to the city and her lavish parties with plenty of adoring male admirers. Fleming decides to make her jealous by flirting with other women. When the Huntress hears the rumors of his affairs, she soon realizes her one true love is Fleming, and they are happily reunited.', '/eYyJJotSDn1NDq59pK2LkWv1tJc.jpg', '1916-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15033, 'Hard to Get', 247602, NULL, '/jXrr1JXvenV7dyOnEotCPFlhKHW.jpg', 'Hard to Get', 'When spoiled young heiress Maggie Richards tries to charge some gasoline at an auto camp run by Bill Davis, he makes her work out her bill by making beds. Resolving to get even, she pretends to have forgiven him, and sends him to her father to get financing for a plan Bill has. What happens next was not part of her original revenge plan.', '/siQWTquMOdjObxcKU5VqJkMudxD.jpg', '1938-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15034, 'Along Came Youth', 626045, NULL, '/ahCgIRpiVMoYYj1X4qzrHR5s3J4.jpg', 'Along Came Youth', 'Broke and stranded in England, American sportsman Larry Brooks and his pal Ambrose take on increasingly odd jobs to remain in proximity to the aristocratic lady that Larry would woo.', '/p32WFS4Fqoy3FYpDPongkcrLvG0.jpg', '1930-12-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15035, 'Only Yesterday', 116671, NULL, '/joIVesTXptwoIMhEBbuKgjwtqDW.jpg', 'Only Yesterday', 'On the back of the Wall Street Crash of 1929, a young businessman is about to commit suicide. With a note to his wife scribbled down and a gun in his hand, he notices an envelope addressed to him on his desk. As he begins to read, we''re taken back to World War One and his meeting with a young woman named Mary Lane.', '/rJUDRGnwuRiqYNOjHvl72TwGnTv.jpg', '1933-11-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15036, 'Letty Lynton', 162064, NULL, '/a7yqMDdDXNL2KjXznswNRkWeNhI.jpg', 'Letty Lynton', 'Socialite Letty Lynton is returning to New York, abandoning one-time lover Emile Renaul in South America, when she strikes up a shipboard romance with Jerry Darrow. Renault is waiting for her in New York and will not leave her alone, so she poisons him. When detectives take her to the D.A.s office, Jerry cooks up an alibi.', '/1Sx9mRtdzW3M61134h72NjWHiJ4.jpg', '1932-04-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15037, 'The Voice of Bugle Ann', 182899, NULL, '/r48qqyVcoo0FmjaMkc5oBo7MHNL.jpg', 'The Voice of Bugle Ann', 'A Missouri farmer''s (Lionel Barrymore) son (Eric Linden) loves the daughter (Maureen O''Sullivan) of a neighbor who has killed the farmer''s foxhound.', '/iTccA7ssYJtdRmvbfn4EyZHeVT3.jpg', '1936-02-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15038, 'Doughboys', 104557, NULL, '/tTG9fJJ8GhMZClb6StkDhH13oQ3.jpg', 'Doughboys', 'Elmer, rich society loafer, falls for Mary, but she''ll have nothing to do with him until (mistakenly thinking that he''s hiring a new chauffeur) he accidentally volunteers for the army. Luckily, Mary''s signed up to entertain the troops. Unluckily, Elmer''s sergeant likes Mary, too. And worst of all, they''re all about to ship out for France.', '/7VFMmjs1nzzwesPlGwPN7ppIl8q.jpg', '1930-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15039, 'The Wrong Road', 217917, NULL, NULL, 'The Wrong Road', 'A young married couple whose plans for their life together haven''t turned out as expected decide to rob the bank where the husband works of $100,000, then hide the money in a safe place and return for it after they serve out their sentences. All goes according to plan until they get out of prison, when they find that they''re being trailed by an insurance investigator and the husband''s old cellmate, who has decided that he wants a cut of the money.', '/QsoPpK5Pzu6eASwLRhKBLp6K19.jpg', '1937-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15040, 'Bulldog Drummond''s Revenge', 140472, NULL, '/823D4jfr0ehkrzPGjtPf0dLzUmc.jpg', 'Bulldog Drummond''s Revenge', 'Captain Drummond is travelling to Switzerland to marry his girlfriend. However, when a cargo containing dangerous explosives goes missing from its place, Drummond is forced to delay his plans.', '/2MApfgh43g93IDWD8o1SkfqyPJQ.jpg', '1937-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15041, 'Anna Karenina', 70881, NULL, '/3T8piadXjpmUf37D3XtjmHzhpGq.jpg', 'Anna Karenina', 'In Imperial Russia, Anna, wife of the officer Karenin, goes to Moscow to visit her brother. On the way, she meets charming cavalry officer Vronsky, to whom she''s immediately attracted. But in St. Petersburg’s high society, a relationship like this could destroy a woman’s reputation.', '/39bSsAvMGOgN8I5lt2rOQgAXsj7.jpg', '1935-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15042, 'She Had to Eat', 352788, NULL, '/dik4VjhAOiTlQFEIFeLg0UjocNW.jpg', 'She Had to Eat', 'An Arizona gas station owner faces comic adventures after traveling with an eccentric millionaire to New City, where he meets up with a small-time con woman and is repeatedly mistaken for a gangster.', '/9AWSR1OIGe9ta6Ve6UZb6rFEfxE.jpg', '1937-07-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15043, 'You Never Know Women', 288606, NULL, '/v0gr9Cgls3CVQmkuwYa6zC1WYRU.jpg', 'You Never Know Women', 'On her way to the theater, Vera, star of a Russian vaudeville troupe, is rescued from a falling girder by Eugene Foster, a wealthy broker who persists in his efforts to win the girl. Foster engages the troupe to perform at his home, and Vera, stunned by a fall, awakens to find Foster pleading his love, while Norodin, her partner who loves her, sees them embrace. Norodin, who performs an underwater stunt, asks Vera not to be present for his act and causes her to believe him dead; heartbroken, Vera tells Foster of her mistake; and enraged, he attempts to seize her. The magician appears, pins Foster to the wall with knives, and advises him to leave before the last blade is thrown.', '/ayLwDOXkdhLruFnBjclzPCbX2kT.jpg', '1926-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15044, 'The 13th Juror', 679170, NULL, '/sl2429AMJPhZsvXnQT8DX83Ny0F.jpg', 'The 13th Juror', 'A 1927 American mystery film directed by Edward Laemmle and written by Charles Logue and Walter Anthony. It is based on the 1908 play Counsel for the Defense by Henry Irving Dodge. Richard Marsden is a long-time friend of Henry Desmond, a powerful and successful attorney. The district attorney plan to break Desmond by having George Quinn infer that Marsden''s wife is having an affair with the lawyer.', '/1IhSXdi0uATiUjOcRjxu8giFYCX.jpg', '1927-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15045, 'Bullets for O''Hara', 146919, NULL, '/f5UThbao4SQ9MzJwizqSz5cdcu2.jpg', 'Bullets for O''Hara', 'A detective courts a gangster''s ex-wife to lure him into a trap.', '/3v18Ukj4pfElRhaN8zoIvSNvoFt.jpg', '1941-07-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15046, 'Everybody''s Hobby', 218597, NULL, '/rlRo8XFy6wmvKMPdsimU3GCYDuO.jpg', 'Everybody''s Hobby', 'A hobby-mad family makes their obsessions pay off.', '/j9fLyBLW40fGmERQDvslUg5GdmE.jpg', '1939-08-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15047, 'The Dictator', 699362, NULL, '/NhZphz1474yQ0OuwMQ98VOU5yT.jpg', 'The Dictator', 'A silent romantic adventure melodrama (from the play and novel by Richard Harding) about a womanizer who follows a beautiful Hispanic woman to her home country and his adventures there.  He ends up helping her father become dictator of the entire country, and is rewarded with marriage to her and he is named Minister of Finance!', '/lWZMn3qNYhlPk6pcx8aAt6uQQwP.jpg', '1922-06-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15048, 'The Million Dollar Mystery', 285226, NULL, '/pA1GcBjKgq8yoMRFeeMVjtq7T4V.jpg', 'The Million Dollar Mystery', 'This twenty-three episode serial told the story of a secret society called The Black Hundred and its attempts to gain control of a lost million dollars.', '/9usEwvPANatb47jqXvQHASWtPsL.jpg', '1914-01-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15049, 'Maid of Salem', 56557, NULL, '/og9Q4jxEcGbT8ENdToLEKkmI4YZ.jpg', 'Maid of Salem', 'When a young woman named Barbara Clarke has an affair with adventurer Roger Coverman, it causes a scandal in the Puritanical town of Salem, Massachusetts. After a meddling girl arouses their suspicions, the town''s elders accuse Barbara of being a witch. She is tried, convicted of sorcery and sentenced to death. As the townspeople prepare to burn Barbara at the stake, Roger tries desperately to save the woman he loves.', '/2T16eAg4ByqkzWAMvoQcufP03pw.jpg', '1937-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15050, 'Trouble for Two', 188249, NULL, '/lYpkUbqmtD1adINWyQXHZZVOy3a.jpg', 'Trouble for Two', 'A decadent prince unhappy over an impending arranged marriage, looking for a good time in London discovers the existence of a secret society called The Suicide Club, and so he seeks to become a member.', '/jRil7KfZZbWsW5iXZ6btI92WoWW.jpg', '1936-05-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15051, 'Crime and Punishment', 708323, NULL, NULL, 'Crime and Punishment', 'Former student Raskolnikov is pushed to murder when struggling to pay the rent on his apartment. When the murder is being investigated by the police, Raskolnikov struggles between trying to hide his guilt and the pressure to confess.', '/1fJqOi18vDjMiQ9Nu2unkNLyaHy.jpg', '1917-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15052, 'Forsaking All Others', 150249, NULL, '/uLVbI1FDyvEG8B6SffrOHtjfT1h.jpg', 'Forsaking All Others', 'A socialite only realises that her friend is in love with her when she falls for the wrong man.', '/jPt57JYNjSqKHQPMMRtVal8B2AU.jpg', '1934-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15053, 'Invisible Stripes', 80196, NULL, '/9CsOxigYZWZ9heb3GfCo5kWZxCI.jpg', 'Invisible Stripes', 'A gangster is unable to go straight after returning home from prison.', '/88U6ZWmIUWnxQvVPQzE3RJ2fOXY.jpg', '1939-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15054, 'Many Happy Returns', 471686, NULL, '/8XPKifHivkkZcsyTQKN6xpCinxe.jpg', 'Many Happy Returns', 'Gracie Allen assumes the "management" of the shop owned by her papa Horatio Allen, turning it into a radio station and then an aviary---with the usual Gracie Allen logic---while distracted Papa is trying to get younger daughter, beauty contest winner Florence, married before she can head to Hollywood and get into the movies.', '/fAIxmWIecplI0ZrRrvESmeghNNu.jpg', '1934-06-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15055, 'Temptation and the Man', 610007, NULL, NULL, 'Temptation and the Man', 'Jim Crosby, the product of a broken home, becomes a gangster and goes to prison. Meanwhile, Ann Payton, an heiress, converts a saloon into a mission. She is engaged to her father''s secretary, Temple Vaughn, a gambler. Jim is released from prison and seeks shelter at the mission. Temple becomes indebted to gambler Phil Johnson and is forced to arrange a crooked poker game involving some of his wealthy friends. Jim overhears the plot and, realizing that Temple is Ann''s fiancé, robs the poker game and puts a check Temple forged into Temple''s own pocket.', '/exNiJocIpDAw8kfRUutwSROUv52.jpg', '1916-07-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15056, 'So This Is Marriage?', 771174, NULL, '/fuZ85ZjQpOGo7jxz03byGqnXVPh.jpg', 'So This Is Marriage?', 'After five years of marriage, Beth and Peter Marsh''s life together is a series of rows and reconciliations. Beth is frivolous and extravagant; Peter is domineering and ambitious and has difficulty paying the bills. Daniel Rankin, who lives in the same apartment building, becomes attracted to Beth and arranges with the Marsh chauffeur to have her car break down, allowing him to offer assistance and gracefully introduce himself; Rankin later invites her to a dance. Resenting Rankin''s attentions to his wife, Peter forbids her to go. However, Beth accompanies Rankin to spite her husband, and Rankin proposes that she divorce Peter and become his wife. A lost film.', '/moB4twPqYTPS2zMyXmxBVRJzg9e.jpg', '1924-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15057, 'Man-Made Women', 771183, NULL, NULL, 'Man-Made Women', 'The man who loved her showed her how to hold the man she loved. A novel picture story packed with drama, thrills and laughs.', '/yHSEB4rhCCY6E2bbTDY8ZVIsIpX.jpg', '1928-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15058, 'Comet Over Broadway', 95968, NULL, '/cMVAteiciGyJ2xNiQVVCiWsU1Ud.jpg', 'Comet Over Broadway', 'A rising stage star''s ambition causes trouble.', '/9auXRZfbLC8mDDQtOlTd88IqsFI.jpg', '1938-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15059, 'The Path of Happiness', 609394, NULL, NULL, 'The Path of Happiness', 'Sick of life in the city after his fiancée deserts him, Merrill Day goes to the country for a rest with his sister and niece. There he meets Joan, who has lived in the hills for her whole life, and they quickly begin a romance. Grekko, however, a hunchback who has loved Joan for years, convinces her that Merrill''s sister is really Merrill''s wife.', '/1Z1mcd65T1xuPr4gzdvwKuWY2nO.jpg', '1916-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15060, 'Robin Hood', 848339, NULL, '/tHlqoNohaE31tiUjqOIkQjPP8Ce.jpg', 'Robin Hood', 'Robin Hood and his followers aid the poor and oppressed from their hideout in Sherwood Forest, pursued by the Sheriff of Nottingham.', '/8sJuZD0YMigdLEXBU8YyQ6uBlZu.jpg', '1913-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15061, 'Second Childhood', 202053, NULL, '/1QijZa4Iin2Z21sJyrLNDfLxTel.jpg', 'Second Childhood', 'A lonely, rich, hypochondriac is celebrating her 65th birthday in the same manner in which she observes the other 364 days of the year by complaining, berating her servants, taking her pills and grumping about everything around her, including the sunshine. A toy airplane comes flying through an open window and breaks a vase, and when its owner, Spanky, comes in search of it he is informed he will have to pay seventy-five cents for the broken vase. Spanly has never seen six-bit, much less having it in his pants, so he offers his and his friend''s help in cleaning up the yard in exchange. Before the kids are through, they''ve given the old lady a new outlook on life.', '/5KEWk1qngCiBtEBnxOIIcOVpbqc.jpg', '1936-04-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15062, 'The Long Trail', 1378325, NULL, NULL, 'The Long Trail', NULL, '/ldrUXUOQWhQK3TTJQSClcAEVdHg.jpg', '1917-07-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15063, 'My Own United States', 1384651, NULL, NULL, 'My Own United States', 'When his son is reluctant to fight for democracy Philip Nolan II shares with him the secret he has long held, the treason of the first Philip Nolan "The Man Without a Country." He explains how the elder Nolan played into the hands of Aaron Burr; how Thomas Jefferson was elected president over Burr; how Alexander Hamilton prevented the conscienceless Burr becoming governor of New York; the duel between Hamilton and Burr; how Philip Nolan was later arrested on his wedding night for aiding Burr, who had conspired to start a rival government in the south to wage war against the United States, and how he was later banished from the United States for saying "Damn the United States! I wish I might never hear its name again," and how Philip Nolan died kissing the flag of the country he had execrated. Understanding how important freedom is the younger Nolan rushes to enlist.', '/t2UPMNrLxSfvk13tyq0MEWDbtfN.jpg', '1918-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15064, 'The Man Inside', 609392, NULL, NULL, 'The Man Inside', 'Years after Barry Thornton disappears from Panama while under suspicion of stealing American defense plans for the canal, his daughter Eleanor, now the ward of Barry''s twin brother Dana, is still obsessed with the mystery. Senator Carew informs her that he has solved it, but he is murdered before he can give her the details.', '/9NWvUvblSP8hhyvMIkFHeNq2WCi.jpg', '1916-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15065, 'Mills of the Gods', 268309, NULL, '/l5voyfMcKlbvxloFb5l12NWh24b.jpg', 'Mills of the Gods', 'Fay Wray plays Jean Hastings, the wealthy and spoiled scion of a factory-owning family led by her irrepressible grandmother. Sparks fly when Jean meets Jim Devlin, the labor leader who’s spearheading a tense worker’s strike against the factory. After circumstances force Jean and Jim to spend a night together in his cabin, she begins questioning her family’s ruthless tactics. This hard-to-see Columbia film by British director Roy William Neill not only features Wray as a brunette but also includes an explosive depiction of labor strife. (Block Cinema)', '/uynUXzhNmsxnRn6tSEAtlVLxv5f.jpg', '1934-12-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15066, 'I''ll Fix It', 595889, NULL, '/pKcpzuWumVASFyRgO1cSbmJPIvH.jpg', 'I''ll Fix It', 'A power-broker ward-heeler, Bill Grimes, wields more power than the elected politicians and has no problem in getting matters-of-the-city handled in which ever way is best for his needs. But when he tries to fix his adored kid brother''s place on the school football team, he meets his match in school-teacher Anne Barry.', '/1vbksZ3gNwosxUEh55sVZPOk9Lk.jpg', '1934-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15067, 'Little Miss Happiness', 1400821, NULL, NULL, 'Little Miss Happiness', 'Unable to tolerate city life, Sadie Barker leaves her husband Max and with her baby, returns to her birth village; afraid to tell her father that she plans to raise a baby without a father, she pretends that she is still childless and asks Lucy White to look after the infant for a few months. Lucy quickly agrees; hoping to preserve Sadie''s secret, she claims that the child is really her own, and even conceals the truth from her sweetheart, Dave Allen. Risking the condemnation of the community, which has already ostracized Lucy for having a baby out of wedlock, Dave decides to stand by his sweetheart. He marries her after Max and Sadie are reunited and take back their child.', '/e0hP76lPl1cu9eHtfLc7a5mfvjz.jpg', '1916-08-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15068, 'Caprice of the Mountains', 1400825, NULL, NULL, 'Caprice of the Mountains', 'Wealthy playboy Jack Edmunds spends some time in a small mountain town, where he makes the acquaintance of local girl Caprtice Talbert and invites her to his apartment. When Caprice''s father finds out about it--although nothing happened--he forces the two to marry, and the newlyweds move to Jack''s home in the city. Tensions arise between the two as Jack is still resentful over the "shotgun wedding" and Caprice finds that she can''t bear living in the big city and wants to return home.', NULL, '1916-07-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15069, 'The Notorious Sophie Lang', 528616, NULL, '/ktfs281fyTmfYDpfe9JZ4ElsYGT.jpg', 'The Notorious Sophie Lang', 'After an extended stay in England, Sophie Lang returns to America. She is beautiful, sophisticated--and a notorious jewel thief. A New York police detective who''s been trying to nail her finally comes up with what seems a foolproof scheme--to catch her off guard by having her fall for a handsome and suave jewel thief who happens to be in the U.S. traveling under an assumed name.', '/iW5dW6P6XwlHWzjfCAsh2q0ueSf.jpg', '1934-07-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15070, 'God''s Witness', 1404655, NULL, NULL, 'God''s Witness', 'A story is told of a woman who, disinherited after a scandal, later needs expensive surgery. Her father, General Darrington, initially refuses her plea for money, so she sends her daughter, Beryl, to him. The General dies from a falling andiron, Beryl is arrested, and a will favors a lawyer named Lennox. Beryl''s brother, Bertie, arrives and provides exculpatory testimony supported by Lennox, who appears with a lightning-imprinted photograph. The siblings eventually discover love between Beryl and Lennox.', NULL, '1915-05-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15071, 'Dance, Fools, Dance', 154515, NULL, '/adR7ehgGwnGLNTbqLb28PdgOHAr.jpg', 'Dance, Fools, Dance', 'When misfortune hits hard on the Jordan family of Chicago''s upper class, Bonnie Jordan, a dazzling and witty girl, finds a job as an aspiring reporter; however, her naive younger brother Rodney takes a twisted path and gets involved with the wrong people.', '/dwieBi0VsQpGnKLMOomldAWgipR.jpg', '1931-02-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15072, 'A Man''s World', 1420024, NULL, NULL, 'A Man''s World', 'The story of a girl who rebelled against the "double standard" of morals, and demanded that women should have as much right to expect virtue in the man they are going to marry as a man expects of a woman.', '/3nJ6qRB6WxTUTwGYweVtgn7PEdw.jpg', '1918-06-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15073, 'You Can''t Get Away with Murder', 87612, NULL, '/epseta9NxR0dyBbqTdGgEnW0Rgi.jpg', 'You Can''t Get Away with Murder', 'Johnnie learns crime from petty thug Frank Wilson. When Wilson kills a pawnbroker with a gun stolen from Johnnie''s sister Madge''s fiance Fred Burke, Fred goes to Sing Sing''s death house. Wilson uses all the pressure can to keep Johnnie silent, even after he and Johnnie themselves wind up in the big house.', '/9AqCXB4RksSsU0hk8QpGGyW4qe.jpg', '1939-03-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15074, 'Speak Easily', 43131, NULL, '/zQpmMt7wdQre1IT5DreQaK9rvDN.jpg', 'Speak Easily', 'A professor gets mixed up with chorus girls in a Broadway musical.', '/pWVjJr90gKkt50omskSlT3t0Emy.jpg', '1932-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15075, 'Omens and Oracles', 1464831, NULL, NULL, 'Omens and Oracles', 'Housemaid Belinda finds a pin on the doorstep, taking it as a sign of good luck, just before a young man arrives looking for a room. The landlady, Ophelia, falls for the boarder at first sight. A policeman finds a fortune-teller''s card, which Belinda takes to Ophelia. The two women visit Madam Miriam, who tells Ophelia a young blond man will fall in love with her. Both Ophelia and Belinda assume this refers to their new boarder, Sidney. Sidney, short on cash, tries to stay in Ophelia''s good graces by taking her out for ice cream. While they are out, Belinda searches his room and finds a photograph of Sidney''s wife, who is none other than the fortune-teller, Madam Miriam. Belinda is shocked by the discovery, revealing that the "omens and oracles" that fueled Ophelia''s romantic hopes were part of a deception orchestrated by the boarder and his wife.', NULL, '1913-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15076, 'Food for Scandal', 1470485, NULL, NULL, 'Food for Scandal', 'June Arbuthnot tries to make her bored husband jealous by feigning a scandal with another man, which ultimately backfires when the ruse becomes too believable.', '/7Z2NYSavwBHfGig57qpTEpMIOxd.jpg', '1920-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15077, 'Monte Carlo', 105067, NULL, '/dqrOCjOXZKFsiEIobIOIyRHlWmw.jpg', 'Monte Carlo', 'A countess fleeing her husband mistakes a count for her hairdresser at a Monte Carlo casino.', '/eKw9l71pSV2lQpUsfK1pV3KJKaX.jpg', '1930-08-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15078, 'The Devil''s Circus', 189622, NULL, '/2Ht3GufLzv1Nfmq2x61hcHolI2t.jpg', 'The Devil''s Circus', 'In 1913, Carl is released from prison, where he served a sentence for stealing. Spurned by his circumstance, Carl rejects God and resumes his fast life of crime. Before long, his fate intersects with that of Mary, a devout orphan, prompting a romance and a reevaluation.', '/z0UFCPhF7v3fVbpfn8ftw4MXYz8.jpg', '1926-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15079, 'Nobody''s Bride', 618821, NULL, NULL, 'Nobody''s Bride', 'Jimmy Nevins--once wealthy and now engaged to Doris Standish--is reduced to poverty and jilted by her when he is befriended by Mary Butler, the leader of a gang of crooks.', '/bFC91V5FbbTrpTgZIuwyTTsyjXz.jpg', '1923-04-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15080, 'The Casino Murder Case', 87881, NULL, '/7Fd0KzzoTPJBZPNjVjdm3RwMM1i.jpg', 'The Casino Murder Case', 'After socialite Lynn Llewellyn receives an anonymous threat, he is poisoned at his uncle''s casino, and although he recovers, his wife is murdered by the same killer.', '/psMxJHNMj2xP6msln8l9QGaTy4l.jpg', '1935-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15081, 'Is Matrimony a Failure?', 1587332, NULL, NULL, 'Is Matrimony a Failure?', 'Mr. and Mrs. Amos Saxby''s silver wedding anniversary is interrupted by the surprise elopement of their daughter Margaret with bank clerk Arthur Haviland. Law student Dudley King, and rival suitor for Margaret, announces that the marriage-license clerk is on vacation and that the license obtained by the elopers is invalid; he wires the proprietor of the lodge where the couple plan to spend their honeymoon, and Arthur and his wife indignantly return home.', '/tWTs5WmFdu40u9a6zf9Wsm7vsQm.jpg', '1922-04-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15082, 'An Amateur Devil', 1590515, NULL, NULL, 'An Amateur Devil', 'Carver Endicott, a young sophisticate, is rejected by his fiancée for being too foppish and dull. When she feigns an interest in his father, Carver attempts to disgrace his family name by working as a farmhand and later as a busboy in a hotel. However, the newspapers only praise him for his self-sacrificing principles; and finding that he cannot bring shame to the family through menial labor, he takes up with a notorious actress. But when this maneuver also fails, he returns to his former fiancée, who has no further complaint about his being an inexperienced dullard.', '/4W837GFeGhkZYqe9pU9beeHTSAB.jpg', '1920-12-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15083, 'The Wild Party', 619119, NULL, NULL, 'The Wild Party', 'Leslie Adams, secretary to the city editor of a newspaper, persuades him to let her write up a society affair. Her efforts result in a libel suit against the paper, and Leslie is told to prove her story or join the ranks of the unemployed.', '/caCZE4ZxYwFjhOm63lkT95fKX96.jpg', '1923-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15084, 'The Mystery Club', 701950, NULL, NULL, 'The Mystery Club', 'The Mystery Club, an organization of millionaires, draws up an agreement at the instigation of Cranahan, wagering that crimes can be committed without detection by the police; Inspector Burke serves as arbiter. A forfeiture of $25,000 is set, and the members draw secret lots to decide who is to be the criminal. When Burke himself is reported murdered, the members agree to cancel the agreement but cannot find the document.', '/cXPXwlNSCXdF6REfDttmEsXHNmq.jpg', '1926-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15085, 'The Lion and the Lamb', 600450, NULL, NULL, 'The Lion and the Lamb', 'Directed by George B. Seitz. With Walter Byron, Carmel Myers, Raymond Hatton, Montagu Love.', '/uVmEJAn41EA08WqbhYDLZ0m1dNw.jpg', '1931-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15086, 'The Deemster', 1605755, NULL, NULL, 'The Deemster', 'Daniel Mylrea is the son of the Bishop of Man, the baron of the Isle of Man, whose temporal power is higher even than that of the Deemster, or governor. The Bishop desires Dan to become a minister, but he prefers to be a fisherman. The Deemster of Man has a son and a daughter, Mona and Ewan. Dan and Mona are in love. She consents to marry him when he can obtain her father''s consent. Ewan, her brother, decides to become a clergyman, even in the face of his father''s insistence that he take up business as a vocation. The Deemster opposes Dan''s suit for Mona''s hand because he has fallen from his high estate as the son of the Bishop by becoming a fisherman.', '/bxiyYuVho1EhzqYRLUYI9KPGggt.jpg', '1917-04-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15087, 'Wife vs. Secretary', 38721, NULL, '/x5PiKsCxqweRo3bAoNeWZgCrSlv.jpg', 'Wife vs. Secretary', 'Linda, the wife of a publishing executive, suspects that her husband Van’s relationship with his attractive secretary Whitey is more than professional.', '/ufPxYmsDDGNUv2qbAtZhXr5m4rU.jpg', '1936-02-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15088, 'One Wonderful Night', 618699, NULL, NULL, 'One Wonderful Night', 'John Curtis discovers that Jean de Curtois, whose assault he has witnessed, was married a few hours earlier to Hermione Fane so that she might escape marriage to Count de Mauriat and retain her fortune.', NULL, '1922-12-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15089, 'The Woman Who Dared', 1660878, NULL, NULL, 'The Woman Who Dared', 'A young woman inherits a textile plant, and finds that she''s expected to pay protection money to gangsters who have their own men among the plant''s employees.', '/vBqlLOuSiKlIc67sCSTP6J8ikD8.jpg', '1933-04-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15090, 'The Social Buccaneer', 1673838, NULL, NULL, 'The Social Buccaneer', 'John "Jack" Norton, before the war a society playboy and fop, returns from the trenches of World War One a two fisted American who finds his father, Raymond Norton, in jail, charged with theft of funds from the bank in which he was the president. The money, placed there by the American authorities for the Kingdom of Thorwald, and Princess Elise, is on the way to collect it. John lets his father think he is still the playboy he was before the war, but secretly dons his old ''Doughboy" uniform and sets out after the gang that framed his father.', '/cfH48Qt61etvRXEKLLd2f5AXRel.jpg', '1923-01-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:47', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15091, 'In Good Company', 1901, NULL, '/ukShYvWPLrGBFdy1CvnKXR79oRV.jpg', 'In Good Company', 'Dan Foreman is a seasoned advertisement sales executive at a high-ranking publication when a corporate takeover results in him being placed under naive supervisor Carter Duryea, who is half his age. Matters are made worse when Dan''s new supervisor becomes romantically involved with his daughter an 18 year-old college student Alex.', '/5H3fbU4NlHPbLf3MUFZwPdmD3nS.jpg', '2004-12-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15092, 'If Lucy Fell', 10324, NULL, '/9OM746UZPI8PJxafovfNgR7IlVK.jpg', 'If Lucy Fell', 'Joe and Lucy are roommates and best friends. Lucy, whose love life is embarrassingly dull, convinces Joe, who is infatuated with a neighbor he''s never met, that if they don''t have stable romances within a month, they must jump off the Brooklyn Bridge.', '/l3Bwmjdon6JBDzJUA3ZSdMZZ7lI.jpg', '1996-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15093, 'The Spirit', 8285, NULL, '/xqgSXgSIkTvyU9vfUcBOd6GYflJ.jpg', 'The Spirit', 'A Rookie cop named Denny Colt returns from the beyond as The Spirit, a hero whose mission is to fight against the bad forces from the shadows of Central City.  The Octopus, who kills anyone unfortunate enough to see his face, has other plans; he is going to wipe out the entire city.', '/g9qawfzR3LWRC8r8YZ9w2yaQi5W.jpg', '2008-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15094, 'Just Cause', 9061, NULL, '/i9opFwOh2DvFyjy8uQXC17UEUzL.jpg', 'Just Cause', 'A Harvard professor is lured back into the courtroom after twenty-five years to take the case of a young black man condemned to death for the horrific murder of a child.', '/hbkS4UpgHcGhLlGy9YCX4WIJ4lu.jpg', '1995-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15095, 'The Nanny Diaries', 12435, NULL, '/oMInxu0s7JzmXDJ9QfKAM0um2v4.jpg', 'The Nanny Diaries', 'A college graduate goes to work as a nanny for a rich New York family. Ensconced in their home, she has to juggle their dysfunction, a new romance, and the spoiled brat in her charge.', '/8hX6rcxnCidaqegPCyeFm9PODBn.jpg', '2007-08-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15096, 'A Love Song for Bobby Long', 9953, NULL, '/8KOtoiqtNNMBR2STj9ZDWeEoTpx.jpg', 'A Love Song for Bobby Long', 'A headstrong young woman returns to New Orleans after the death of her estranged mother.', '/7HoqdnUpIcK1CnFDNNONPZ9PBoi.jpg', '2004-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15097, 'The Perfect Score', 13505, NULL, '/6I9r2ZTp2ZtNjD4hYD62UHF0fDn.jpg', 'The Perfect Score', 'Six high school seniors decide to break into the Princeton Testing Center so they can steal the answers to their upcoming SAT tests and all get perfect scores.', '/xflTliVBvCztaLzTJx9luHnSqwD.jpg', '2004-01-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15098, 'Fall', 37567, NULL, '/mjEc4llir1d3SGqaxVjTMXrbvKB.jpg', 'Fall', 'For Michael Shiver, life as an easy-going cab driver in New York suddenly changes when he picks up supermodel Sarah Easton and falls head over heels in love. But Sarah has more than just passion on her mind; she also has a husband and a glamorous lifestyle that she can''t seem to leave behind. Torn between her feelings for Michael and the security of her marriage, Sarah is forced to make a realistic decision about the sacrifices that must be made to be truly and totally in love.', '/4nRzyiVckWoqE9Vpm35yZTrfkJM.jpg', '1997-06-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
