INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15102, 'Marvel Studios Assembled: The Making of Hawkeye', 936643, NULL, '/cOyxcD7YUZPriEhyCEbkJlY9kQg.jpg', 'Marvel Studios Assembled: The Making of Hawkeye', 'Join the likes of Jeremy Renner, Hailee Steinfeld, Florence Pugh, and Vincent D’Onofrio as they reveal how Marvel Studios’ “Hawkeye” was conceived and created. Witness firsthand what it took to pull off the show’s pulse-pounding action set pieces, and discover how iconic characters from the pages of Marvel Comics such as Kate Bishop were adapted and brought to life for the six-episode series.', '/pQOLNPHe4rwXl3RpKNa0VWjYNLR.jpg', '2022-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
