INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15106, 'Catching Fire: The Story of Anita Pallenberg', 1122602, NULL, '/gGcmm8N3oMdJTEVyj3aHBfpyKPe.jpg', 'Catching Fire: The Story of Anita Pallenberg', 'An exploration of the life of Anita Pallenberg, European actress and rock ’n’ roll muse. Told in Anita’s own words, from her unpublished memoir, and in the words of her family, this bittersweet film is a never-seen-before look at life with The Rolling Stones.', '/mO41UPBGnb5kOKmiaXaeVPMzLyT.jpg', '2024-05-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15107, 'Escape from the World''s Most Dangerous Place', 1201346, NULL, '/8nLeBBamxuEGnYNzzCK3hMbWDrz.jpg', 'Escape from the World''s Most Dangerous Place', 'Successful model Samira Hashi makes an emotional return to Somalia, one of the most dangerous places in the world and the place she was born. Civil war broke out in 1991, 10 days after Samira''s birth, but two years later her family managed to flee the country and she grew up in the UK.Now, as Samira and the war both turn 21, she''s going back for the first time to visit the people and places she left behind. The contrast with her safe and glamorous life in London could not be starker as she experiences firsthand the war''s effect on a generation of young people growing up in conflict.', '/7vL3SBHbZzL4AbfAuEmqjCawgBs.jpg', '2012-04-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15108, 'Deep Down', 280409, NULL, '/e6wMWkfMSINfMzoHycLDpFJYdkn.jpg', 'Deep Down', 'Deep Down redraws a descent into hell of a stripper called America, lost in the very depths of the U.S, taken away by a devastating love-story.', '/8FHwX3beVvRJQsEa2yLhp7vy5bQ.jpg', '2014-07-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15109, 'Drive-Thru Records: Vol. 1', 310012, NULL, NULL, 'Drive-Thru Records: Vol. 1', 'Some of the most successful underground punk bands are showcased in this compilation from indie punk label Drive-Thru Records. The video features over three hours of videos from Drive-Thru''s stable, including Allister, Fenix TX, Home Grown, The Movielife, New Found Glory, RX Bandits, Something Corporate and The Starting Line; plus concert footage, interviews and home videos from many bands including Senses Fail, Steel Train and The Early November.', '/wfcwtU3rxYpR9icmc8U3KTCenfc.jpg', '2002-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15110, 'Her: Love in the Modern Age', 250853, NULL, '/zUvCR8biVVMHT65myMVuJ9ueer3.jpg', 'Her: Love in the Modern Age', 'Her: Love In The Modern Age chronicles reactions to Spike Jonze''s Oscar-nominated film, "Her." The documentary, directed by Lance Bangs, features stories and reflections from writers, musicians, actors and contemporary culture experts, including Olivia Wilde, James Murphy and Bret Easton Ellis, on the film "Her," and their thoughts on love in the modern age.', '/yq4j7uBuNXKUlti2726PEnqu2Wb.jpg', '2014-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15111, 'Marvel: 75 Years, from Pulp to Pop!', 299969, NULL, '/69rb6VKOEqpuJ88MkKXLaSd71Va.jpg', 'Marvel: 75 Years, from Pulp to Pop!', 'In celebration of the publisher''s 75th anniversary, the hour-long special will take a detailed look at the company''s journey from fledgling comics publisher to multi-media juggernaut. Hosted by Emily VanCamp (S.H.I.E.L.D. Agent Sharon Carter), the documentary-style feature will include interviews with comic book icons, pop culture authorities, and Hollywood stars.  The special also promises an "extraordinary peek into Marvel''s future!" Might Marvel release the first official footage from next year''s Avengers: Age of Ultron or Ant-Man? If they do, you''ll know about it here.', '/biud0bsRfQryGBfcTXN2ep6ODwM.jpg', '2014-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15112, 'Penglai', 1026725, NULL, '/kjW02tDDomjoVymI3634THXO15q.jpg', 'Penglai', 'A young fisherman, dissatisfied with his life, embarks on a quest to find the mythological island of Penglai. Shipwrecked in a storm, he is rescued by a mysterious woman who seems to have otherworldly powers. He comes to believe that she is the manifestation of the divine Buddha. She leaves, promising to return, only then does the fisherman ultimately come to a shattering realization.', '/ftBCIMluF0tV83ALCMvbVTO5Huq.jpg', '2022-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
