INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15114, 'Featherwood', 1243035, NULL, NULL, 'Featherwood', 'Carol Blevins, a heroin addict and “Aryan Princess featherwood” (property of a gang member), became one of the FBI’s most important informants during an epic, six-year investigation into the murderous neo-Nazi crime and drug syndicate known as the Aryan Brotherhood of Texas. Blevins, who lived with the gang, memorized details, pre-empted murders, interrupted robberies, and helped convict 13 members of the group. However, her harrowing journey left her with significant physical and mental scars and she lives under constant threat of reprisal by the ABT.', '/yVHJ9NTnclFw3SX80EQ2ZikbDtC.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
