INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15139, 'Bert Stern - Original Madman', 94026, NULL, '/pLrVfnhf0N6l2z0qD081xofydGt.jpg', 'Bert Stern - Original Madman', 'The untold and intimate life story of one of the greatest American photographers of all time, Bert Stern. After working alongside Stanley Kubrick at Look Magazine, Stern became an original Madison Avenue ''mad man'', his images helping to create modern advertising. Ground-breaking photos of Elizabeth Taylor and Richard Burton, Marilyn Monroe and Twiggy, coupled with his astonishing success in advertising, minted Stern as a celebrity in his own right.', '/uF8uAzu8aMQwAGFOPNhLeFzsOhh.jpg', '2011-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15140, 'Get Over It', 10050, NULL, '/saQxwnIr4ftRmFpJeV9DQI1lsWd.jpg', 'Get Over It', 'When Berke Landers, a popular high school basketball star, gets dumped by his life-long girlfriend, Allison, he soon begins to lose it. But with the help of his best friend Felix''s sister Kelly, he follows his ex into the school''s spring musical. Thus ensues a love triangle loosely based upon Shakespeare''s "A Midsummer Night''s Dream", where Berke is only to find himself getting over Allison and beginning to fall for Kelly.', '/hS1jjzTe4P8GMWGnvca7HIndPEX.jpg', '2001-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15141, 'American Psycho II: All American Girl', 10726, NULL, '/bck1APsiyOtEniGLsFO0Gu8QtUU.jpg', 'American Psycho II: All American Girl', 'Rachel is a criminology student hoping to land a position as a teacher''s assistant for professor Robert Starkman. She''s sure this position will pave the way to an FBI career, and she''s willing to do anything to obtain it -- including killing her classmates. The school psychiatrist, Dr. Daniels, becomes aware that Rachel is insane, but Rachel is skilled at her dangerous game of death and identity theft.', '/mYBvrIV78mckZGdT5gpHtXOKVc2.jpg', '2002-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
