INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15143, 'Krippendorf''s Tribe', 31220, NULL, '/7VzXNGpSnrvs4s1I9M00aQBRLH1.jpg', 'Krippendorf''s Tribe', 'After squandering his grant money, despondent and recently widowed anthropologist James Krippendorf must produce hard evidence of the existence of a heretofore undiscovered New Guinea tribe. Grass skirts, makeup, and staged rituals transform his three troubled children into the Shelmikedmu, a primitive culture whose habits enthrall scholars. But when a spiteful rival threatens to blow the whistle on Krippendorf''s ruse, he gets into the act as well.', '/5mmGI4O1gWYrwpPQ22hgHu9PkIv.jpg', '1998-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15144, 'Extract', 12569, NULL, '/vSUz6gjbK0x9LfaDxZcIKk84Dxs.jpg', 'Extract', 'The owner of a factory that produces flavor extracts, Joel Reynold seems to have it all, but really doesn''t. What''s missing is sexual attention from his wife, Suzie. Joel hatches a convoluted plan to get Suzie to cheat on him, thereby clearing the way for Joel to have an affair with Cindy, an employee. But what Joel doesn''t know is that Cindy is a sociopathic con artist, and a freak workplace accident clears the way for her to ruin Joel forever.', '/cjen0vxjybwItQPH3NNCJuME2MY.jpg', '2009-09-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15145, 'Goodrich', 1088096, NULL, '/1jXebnKdnb580YOzGuyhuujSGbc.jpg', 'Goodrich', 'Andy Goodrich''s life is upended when his wife enters a rehab program, leaving him on his own with their young kids. Goodrich leans on his daughter from his first marriage, Grace, as he ultimately evolves into the father Grace never had.', '/silxnsoelZ0qXp4Bm2spBY949iP.jpg', '2024-10-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
