INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15148, 'After Sex', 17097, NULL, '/6IcKXawCxDd6QZ8CfQHamp3qFDO.jpg', 'After Sex', 'Sex is a background to examine intimacy and vulnerability. Looks at the complexity of modern day relationships told through eight separate couples. Through dialogue and compromising situations, the film takes us from the beginning of a relationship to the aftermath of one, and examines every stage in between seeing humor within the drama, heartache and confusion of it all.', '/4n41P5CKHFFkQ3s8VJieNmqUkn7.jpg', '2007-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
