INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15163, 'A Very Special Family Guy Freakin'' Christmas', 572202, NULL, '/scL9FjharQl3Ew5CVgLFOTyoeCj.jpg', 'A Very Special Family Guy Freakin'' Christmas', 'The holidays are approaching, and who better to play Jesus in the town nativity scene than Stewie? Plus, Peter gives the family''s gifts to charity, Brian sets the house on fire, and Stewie demands plutonium from Santa. Then, rejoice with a bonus gift--this never-before-released-on-DVD episode of "American Dad"! Stan will just die if he can''t find the perfect Christmas tree. Watch Stan die! And maybe come back to life. Deck the halls with all these outrageous yuletide yucks!', '/uUNqRwHk9vNgisejGqpAtGwbohR.jpg', '2001-12-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15164, 'Family Guy Presents: Stewie Kills Lois and Lois Kills Stewie', 572204, NULL, NULL, 'Family Guy Presents: Stewie Kills Lois and Lois Kills Stewie', 'You can learn a lot from a maniacal baby genius bent on a world of domination, but we kinda hope you don''t. In the shockingly hilarious 100th episode of Family Guy, Stewie makes good on his threat to do away with "vile woman" he calls Lois.', '/vsZpFUNTEAawtI2kA0hgsG4DbHT.jpg', '2009-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15165, 'Breaking News in Yuba County', 556867, NULL, '/dLJs1CprSFK2o1QtI0jgoH9yypC.jpg', 'Breaking News in Yuba County', 'An overlooked pencil-pusher catches her husband in bed with another woman, the shock of which causes him to die of a heart attack. So she buries his body and takes advantage of the growing celebrity status that comes from having a missing husband. But she quickly finds herself in over her head, dodging cops and criminals, all while trying to keep the truth from her sister, a local news anchor who’s desperate for a story.', '/pMyCYtgfBmMisX3RFc5eH6zIV5Y.jpg', '2021-01-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
