INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15178, 'Peter, Peter, Pumpkin Cheater', 1682554, NULL, '/35ahwYIiRFjqEuHvUL1EpEFOxne.jpg', 'Peter, Peter, Pumpkin Cheater', 'In the 2024 Family Guy Halloween special, Peter becomes a human pumpkin to help Joe finally win Quahog''s Great Pumpkin Contest. Meanwhile Stewie brings Rupert to life, and Rupert immediately resolves to kill Brian.', '/aIvQ5nuZvBFLot9kf88pwMDCW5c.jpg', '2024-10-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
