INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15180, 'Lions for Lambs', 4515, NULL, '/tfE55NmC3tF2U0DtZkAYKvUHn5k.jpg', 'Lions for Lambs', 'Three stories told simultaneously in ninety minutes of real time: a Republican Senator who''s a presidential hopeful gives an hour-long interview to a skeptical television reporter, detailing a strategy for victory in Afghanistan; two special forces ambushed on an Afghani ridge await rescue as Taliban forces close in; a poli-sci professor at a California college invites a student to re-engage.', '/tpwq5AHgj13uBE06B07xWqWQV5i.jpg', '2007-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15181, 'Losin'' It', 33676, NULL, '/rBVattNnNKvml4ecK9nLn5UcjnI.jpg', 'Losin'' It', 'In 1965, four Los Angeles school friends -- Woody, Dave, Spider and Wendell -- go on a series of misadventures when they head to Tijuana, Mexico, for a night of cruisin'', causing trouble, and to lose their virginity.', '/7BQP8GzBW4ZZxqcc5tDH68yNeAI.jpg', '1983-04-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15182, 'All the Right Moves', 18172, NULL, '/5OAgCNzFS1dgIQ9jtAlbn2v4dvV.jpg', 'All the Right Moves', 'Sensitive study of a headstrong high school football star who dreams of getting out of his small Western Pennsylvania steel town with a football scholarship. His equally ambitious coach aims at a college position, resulting in a clash which could crush the player''s dreams.', '/y8OSutSNEi84ROcqyV7Tu7p8xYg.jpg', '1983-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15183, 'Tom Cruise: The Last Movie Star', 1133142, NULL, '/vcAPhgU9V443XUW3uR2mR3zOuAq.jpg', 'Tom Cruise: The Last Movie Star', 'Tom Cruise - actor, producer, daredevil. The face of Hollywood in the 1980s, after a mid-career meltdown, his future looked in doubt. But through a single-minded commitment to entertaining audiences worldwide, he has risked life and limb and fought his way back to the very top. In an entertainment world dominated by superheroes and fantasy franchises, he stands alone… the last movie star.', '/eykwtACYOMMJdTO40vh70BpreUv.jpg', '2023-07-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15184, 'Tom Cruise: Lights, Camera, Action', 1209264, NULL, '/9arVJmRD203r2FiMS9bXToDgndZ.jpg', 'Tom Cruise: Lights, Camera, Action', 'Having just turned 60, Tom Cruise is still one of the leading names in Hollywood. A prolific actor with a career spanning over 40 years, he is continually building a giant legacy within the film industry. His ability seems to know no limits.', '/g1KqHRrvWbET4fMuV2pH00eFePB.jpg', '2022-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
