INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15186, 'Spielberg', 467062, NULL, '/fHM3ChEYaoAEcCCpRokQzN2DBYy.jpg', 'Spielberg', 'A documentary on the life and career of one of the most influential film directors of all time, Steven Spielberg.', '/2AAvIR2PHoxNITgLDOkXXlWLlua.jpg', '2017-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15187, 'Close Up', 1113682, NULL, NULL, 'Close Up', 'More than 150 silent short films about singers, actors and directors captured during Press Conferences in Cannes, Venice and Berlin, between 1993 and 2002. Presented the first time in 2012 (ten years after the last shooting) in Napoli Film Festival and in 2013 at the Art Institute of California in Santa Ana. An anthropological experiment on the facial expressions of famous people showing the human being aspect. All original footage from Mel Gibson to Peter Jackson, from George Lucas to Catherine Deneuve, from Michael Douglas to Giancarlo Giannini and many others.', '/76Wud5jsFJDMpBoRVzwluMZeaa.jpg', '2012-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15188, 'Space Station 3D', 18221, NULL, '/kfyLvdWaXlvXWSvKGYjA1JFxsAl.jpg', 'Space Station 3D', 'Some 220 miles above Earth lies the International Space Station, a one-of-a-kind outer space laboratory that 16 nations came together to build. Get a behind-the-scenes look at the making of this extraordinary structure in this spectacular IMAX film. Viewers will blast off from Florida''s Kennedy Space Center and the Baikonur Cosmodrome in Russia for this incredible journey -- IMAX''s first-ever space film. Tom Cruise narrates.', '/3WTMYkXYd1p9ObrrZmxBc179mUr.jpg', '2002-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15189, 'Tom Cruise: An Eternal Youth', 765522, NULL, '/9mOXEpXUyzTtmgamjC2jGk3SdNN.jpg', 'Tom Cruise: An Eternal Youth', 'After 40 years, Tom Cruise continues to push the envelope in film. Exposing one''s heart to the world through their work is not only risky business, as far as Cruise is concerned, it is the only way to achieve an end that feels complete.', '/MQwWS1iBzUkpyjNFV8Je6dFoIU.jpg', '2020-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15190, 'Winning: The Racing Life of Paul Newman', 291537, NULL, '/rn1BZEmmNUKXEt5x4R8jMy3dkrW.jpg', 'Winning: The Racing Life of Paul Newman', 'The world knows Paul Newman as an Academy Award winning actor with a fifty-plus year career as one of the most prolific and revered actors in American Cinema. He was also well known for his philanthropy; Newman''s Own has given more than four hundred and thirty million dollars to charities around the world. Yet few know the gasoline-fueled passion that became so important in this complex, multifaceted man''s makeup. Newman’s deep-seated passion for racing was so intense it nearly sidelined his acting career. His racing career spanned thirty-five years; Newman won four national championships as a driver and eight championships as an owner. Not bad for a guy who didn''t even start racing until he was forty-seven years old.', '/hsTxEODkmcHvVhR9junDH8I43dt.jpg', '2015-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15191, 'Stanley Kubrick: A Life in Pictures', 30416, NULL, '/2Rx61lWWkxR0jeaBi0H0CJQm35b.jpg', 'Stanley Kubrick: A Life in Pictures', 'With commentary from Hollywood stars, outtakes from his movies and footage from his youth, this documentary looks at Stanley Kubrick''s life and films. Director Jan Harlan, Kubrick''s brother-in-law and sometime collaborator, interviews heavyweights like Jack Nicholson, Woody Allen and Sydney Pollack, who explain the influence of Kubrick classics like "Dr. Strangelove" and "2001: A Space Odyssey," and how he absorbed visual clues from disposable culture such as television commercials.', '/yGrzFNyc9ztyAJejneh9734Y9Uj.jpg', '2001-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15192, 'Nicole Kidman: Eyes Wide Open', 975388, NULL, '/q65vDp87n3826snyjMMSmixJiuy.jpg', 'Nicole Kidman : les yeux grand ouverts', 'Nicole Kidman has worked with a host of top directors in a varied career including Gus Van Sant, Jane Campion, Stanley Kubrick, Lars von Trier and Sofia Coppola. A portrait of a fascinatingly ambivalent actress who shines in Hollywood blockbusters as well as auteur cinema, determined to explore, role after role, the female condition.', '/kNQFovCREAXi0QNiGCScohGI5aZ.jpg', '2023-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15193, 'Mission: Improbable', 149044, NULL, '/rdC9hf7qoyZo9rerPhbI0HBdSGd.jpg', 'Mission: Improbable', 'A behind the scenes look at the stunt work of "Mission: Impossible 2", told through one stunt man who looks like a certain superstar, who''s got his looks, but certainly not his smarts.', '/aJJqTX3aRGcuJCzR8NFOfqN2WhM.jpg', '2001-06-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15194, 'Hitting It Hard', 705078, NULL, NULL, 'Hitting It Hard', 'The press tour to promote the film Vanilla Sky (2001) does quite a number on its stars. We see how tired an actor can get after answering the same questions over and over again at various press junkets and premieres.', '/gDQUqhfjiBXC6WO1YlvVgQdsrTU.jpg', '2002-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15195, 'James Corden''s Top Gun Training with Tom Cruise', 984430, NULL, '/rqlO5TfhIBetwnaUoxebrF178WZ.jpg', 'James Corden''s Top Gun Training with Tom Cruise', 'When "Top Gun: Maverick" star Tom Cruise calls you up to hang out for the day, you say yes. And for James Corden, that meant having Tom pilot you in two different fighter planes, pushing the limits of gravity and James''s stomach.', '/e2EILRtu7b6qu4TuwU7BpyHop68.jpg', '2022-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15196, 'The Final: Attack on Wembley', 1263766, NULL, '/ao6UU1y1fctSgcRg818W9DiBYJ0.jpg', 'The Final: Attack on Wembley', 'As England reach the final of the Euros at last, 6,000 ticketless football fans storm Wembley stadium, leaving destruction in their wake.', '/6XQ1WAbqhBMrEB1UAEiB8Hpy5Ge.jpg', '2024-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15197, 'Junket Whore', 833818, NULL, NULL, 'Junket Whore', 'A documentary film that explores the relationship between publicists and journalists in Hollywood.', '/nOjIGu6IWWs91fFOTcfzdPYNtBD.jpg', '1998-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15198, 'Broadsword', 1321757, NULL, NULL, 'Broadsword', 'A Special Operations Executive (S.O.E.) mission in World War II goes badly and leaves a Royal Marine Captain stranded in France as the sole survivor. Against all odds, he must complete his mission amidst the chaos of war.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15199, 'Paris 2024 Olympic Closing Ceremony', 1322488, NULL, '/4zeKxGtxRX2Sk1vEH8Sm67DXY4G.jpg', 'Cérémonie de clôture des Jeux Olympiques de Paris 2024', 'Like an indelible memory, this Olympic closing ceremony will be marked by audacity, fraternity and emotion. In the heart of the Stade de France, athletes from all over the world will represent their countries one last time in an incredible moment of celebration and sharing. With their eyes riveted to the flame, the emotion will be immense as we close the great Olympic book of Paris 2024.', '/5Kb7DTk4cxo8rlr7bhcOPZFNzHW.jpg', '2024-08-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15200, 'City of Night: The Making of ''Collateral''', 565663, NULL, '/y8WTq81DcttzMvy9Opzq2ZAo1uy.jpg', 'City of Night: The Making of ''Collateral''', 'This documentary chronicles the making of the film Collateral (2004). We get to see Tom Cruise and Jamie Foxx training for their roles, as well as Jada Pinket Smith''s Audition. Michael Mann also informs us on his preparation for the film, as well as some more behind-the-scenes looks at the 17 special camera-ready taxis and the taxi crash.', '/1oFFFrbgU5mqCC4eRap4B1iid6p.jpg', '2004-12-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15201, 'Danger Zone: The Making of Top Gun', 1022047, NULL, '/r0OGNs8auphBzrUK4ZkdSyHSZGy.jpg', 'Danger Zone: The Making of Top Gun', 'A comprehensive 6-part documentary on the making of "Top Gun" featuring all-new interviews with the cast and crew. Available on Disc 2 of the "Top Gun" 2-Disc Special Collector''s Edition DVD.', '/fhjM1vsPfjIzHsIC2GE1w5RcfCP.jpg', '2004-05-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15202, 'Staying Gold: A Look Back at ''The Outsiders''', 554405, NULL, NULL, 'Staying Gold: A Look Back at ''The Outsiders''', 'Join director Francis Coppola and his remarkable cast as they reminisce about their experiences shooting "The Outsiders" in 1982 in Tulsa, Oklahoma.', '/ykiF7zSFsxO0DmGMiLgJLmKbYhG.jpg', '2005-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15203, 'Time Out: The Truth About HIV, AIDS and You', 298339, NULL, NULL, 'Time Out: The Truth About HIV, AIDS and You', 'Join stars Paula Abdul, Luke Perry, Sinbad, Pauly Shore, Jaleel White and many, many more as they take an entertaining, music-filled and honest look at HIV and AIDS.  You''ll get all the latest facts, important dos and don''ts, and you''ll meet some wonderful people.  Co-hosts Arsenio Hall and Earvin "Magic" Johnson even hit the court for a little one-on-one, and then take "time out" for an informative heart-to-heart!  For people who already know about HIV and AIDS, and for those who don''t, TIME OUT is a video you can''t afford to miss.', '/u78t56yghgd4v1ieNBrEbQbLF2F.jpg', '1992-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
