INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15215, 'Boo-Yah: A Portrait of Stuart Scott', 1595856, NULL, '/yAfkQJOc2W7G8P28Hs5QG5PyJ7C.jpg', 'Boo-Yah: A Portrait of Stuart Scott', '"Boo-Yah" traces Stuart''s journey from local television in North Carolina to becoming one of ESPN''s most influential voices. At a time when hip-hop and popular culture were often marginalized in mainstream media and few Black anchors held national prominence, Stuart brought both unapologetically to "SportsCenter," blending sharp analysis, pop culture and swagger in a way that spoke to a new generation of fans.', '/w7V3lOur4lCYKZV8np53atCM2t.jpg', '2025-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15216, 'Kubrick by Kubrick', 689705, NULL, '/pe2kAmZr2OghIIC12SYW1gx8qn0.jpg', 'Kubrick by Kubrick', 'American filmmaker Stanley Kubrick (1928–1999), one of the greatest in history, but also one of the most reserved, gave few interviews throughout his long career, and none of them were filmed. A first-person journey through his life and work, based on a recorded conversation with French film critic Michel Climent.', '/hgmWmo2xBghbWXKK8YpJHSR8n1x.jpg', '2020-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
