INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15218, 'My Scientology Movie', 359871, NULL, '/dqoPH4sRFhBASjrmqgPOasA1ztT.jpg', 'My Scientology Movie', 'After being denied access to the Church of Scientology''s headquarters, documentarian Louis Theroux teams up with ex-Scientology official Marty Rathbun to stage re-enactments of alleged abuses within the organization. Theroux soon discovers that the church is watching his every move.', '/mTAZFb79cum6bfU41C96DwMCp6Y.jpg', '2016-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15219, 'Commitment to Life', 965251, NULL, '/3AvizCJowiM1iBklLnO8YDwnHE2.jpg', 'Commitment to Life', 'Against a rich Hollywood backdrop, "Commitment to Life" documents the true story of the fight against HIV/AIDS in Los Angeles - and how an intrepid group of people living with HIV/AIDS, doctors, movie stars, studio moguls and activists changed the course of the epidemic.', '/2GBQLto8W33Tc1CMEpL8Zk1KEYD.jpg', '2023-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15220, 'Johnny & Clyde', 857553, NULL, '/5S6502vFWcJCu8jyAEBXgT8nDxo.jpg', 'Johnny & Clyde', 'Johnny and Clyde are two serial killers who are madly in love and on an endless crime spree. Alana (Megan Fox) is the confident and cunning owner of a prosperous casino that generates tens of millions of dollars each year. Johnny and Clyde decide to assemble a ragtag group of criminals and misfits to steal from Alana''s casino and pull off the heist of the century. Unfortunately for Johnny and Clyde''s crew, Alana has a deadly weapon at her disposal – the monstrous slasher spirit known as Bakwas.', '/cdfdR90WYCTQmYoQ0aDRZP8I2IL.jpg', '2023-03-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15221, 'Confessions of a Teenage Drama Queen', 11132, NULL, '/z5r8XnWFWTD0shvIlR9yCn85Lna.jpg', 'Confessions of a Teenage Drama Queen', 'After moving to New Jersey, Lola bags a coveted role in a school play, which earns her the wrath of Carla, the most popular girl in school, who will do anything to ruin Lola''s life.', '/nQA9Ozh9ftLQyJvuKy6sl5zSlH2.jpg', '2004-02-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:48', 0);
