INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15251, 'The Hideout', 29951, NULL, '/oBMLqKvdWoF9UayRz8uAry0r0Zy.jpg', 'Il nascondiglio', 'A mystery-thriller about an Italian woman who moves to Davenport to open a restaurant. After her husband commits suicide, she spends fifteen years recovering at a Minnesota mental hospital. When she builds herself up enough to begin another restaurant, she discovers that a murder took place there fifty years earlier. She decides to investigate and finds a secret plot.', '/5C2D5HH9aJzIOdQZXpqQcTPSVul.jpg', '2007-11-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
