INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15254, 'Sirley', 660599, NULL, '/yjpR3p1gapGAUv9eICwg1GUeRiF.jpg', 'Maledetta primavera', 'Nina is 13 years old and has an incredibly messy family. She finds herself catapulted from the center of Rome in a suburban neighborhood: grey high-rises, boys on scooters and a funny grandmother who spends all of her time gambling on cards. A sudden encounter upsets everything, like a storm: she is 13 years old, lives in the opposite building, and dances the Lambada. Her name is Sirley, she comes from French Guiana and has an ambitious dream: to interpret the Madonna in the neighborhood procession. Between the two an intense, very strong bond is created. Their friendship will lead Nina to finally lose control, and to discover her place not only in the world, but in the heart of her family.', '/ojJBnLgY6JNKW0PiUNUZcMb4obK.jpg', '2021-06-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15255, 'The Healer', 1351701, NULL, '/s6XTzVtjDWsV4wJNhbEc0peVJDC.jpg', 'La bocca dell''anima', 'In the shadowed aftermath of the Second World War, Giovanni Velasques returns to his quaint hometown nestled in the breathtaking landscapes of Sicily’s mountains, bearing the scars of war inside and out. Haunted by wartime traumas, Giovanni’s tumultuous spirit finds solace in the wisdom of an elderly lady who unveils his extraordinary gift: the ability to harness the spirit of a departed soul and heal the tormented. But as Giovanni’s reputation as a healer grows, he finds himself on a collision course with two formidable adversaries: the church and the mafia. Torn between his mystical calling and societal pressures, he’s pushed into a corner of isolation, forcing him to forsake his magical calling and embrace the expected life of a family man and farmer. But will that sacred soul, worshipped like a god, truly be lost to oblivion?', '/f3IzihKL9rPpFAIMY37jMaGH3q0.jpg', '2024-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
