INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15280, 'The Murder Man', 27998, NULL, '/jZ9KWu4iSMmK7gZMjkteG3pWHMK.jpg', 'The Murder Man', 'Steve Grey, reporter for the Daily Star, has a habit of scooping all the other papers in town. When Henry Mander is investigated for the murder of his shady business partner, Grey is one step ahead of the police to the extent that he often dictates his story in advance of its actual occurrence. He leads the police through an ''open and shut'' case resulting in Mander being tried, convicted and sentenced to death. Columnist Mary Shannon is in love with Steve but she sees him struggle greatly with his last story before Mander''s execution. When she starts typing out the story from his recorded dictation, she realizes why.', '/jjoBHLSJsNml7mcl5lGr1CvYFjs.jpg', '1935-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
