INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15285, 'Midnight Faces', 189547, NULL, '/AR4R9QvcHEzpi1jPGa7KbFl2fz.jpg', 'Midnight Faces', 'A young man inherits a mansion in a Florida swamp from an uncle he never knew he had. When he, his assistant and the estate''s executor arrive at the house, the audience catches sight of someone crawling in the window, though the house is supposed to be unoccupied. As the house staff begins to arrive they sense a strange presence in the house, and when a young woman no one knows runs into the house to escape a knife-wielding psycho, the occupants realize they may be in danger from both outside and inside the house.', '/cvDgs4Ns7aKqNm1vgTraAVgr8Pw.jpg', '1926-03-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
