INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15299, 'Too Hot to Handle', 33028, NULL, '/qMdIbpdTCcNdt2IwXCFRCIlw6CT.jpg', 'Too Hot to Handle', 'While in Shanghai reporting on the Sino-Japanese war, Chris Hunter, a shrewd news reporter, meets pilot Alma Harding. She does not trust him, but he manages to hire her as his assistant. During an adventurous expedition through the jungles of South America, her opinion of him begins to change.', '/bdfmUhmuWT0QJllnIJcoJ0aCVuB.jpg', '1938-09-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
