INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15302, 'Turn It Up', 9995, NULL, '/9h90ga8OYzcHAVHCuwRuFYQQNm.jpg', 'Turn It Up', 'Trying to bootstrap his way out of Brooklyn''s mean streets is Diamond, a rap musician. With his long-time pal Gage acting as his manager, he''s trying to lay down a demo tape with cut-rate studio time. To pay the bills, he and Gage run drugs for "Mr. B." Inside a week, Diamond''s beloved mother dies suddenly, his father appears after an absence of 12 years and wants a relationship, and his girlfriend Kia tells him she''s pregnant, asking him if he''s ready to be a father. Gage steals $100,000 in a multiple-felony robbery so that Diamond can record a full album, not knowing it''s Mr. B''s money he''s taken. B wants his money, Diamond wants his music, Tia wants an answer.', '/1LqMTyQJnI7IfeDjjGRcDh1vv0r.jpg', '2000-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15303, 'Truth In 24', 16900, NULL, '/boET2fgExdaOfojez5VKQqAoKAs.jpg', 'Truth In 24', 'It''s 24 hours of pure exhilaration, complete exhaustion, and it''s not for the faint of heart or the ill-prepared. It is the legendary 24 Hours of Le Mans. But before you win it, you have to master finishing it. This film chronicles the dedication, the determination and the spirit required to not just survive 3,000 grueling miles, but to be in a position to win one of the greatest races in history.', '/wLiHPyV6yUhBWUL3iX0TZMMkSQg.jpg', '2008-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15304, 'Inferno: The Making of ''The Expendables''', 145308, NULL, '/cdW045qbUjbvPIUxsXdsArcXs8K.jpg', 'Inferno: The Making of ''The Expendables''', 'Sylvester Stallone''s 90-minute video diary, covering the making of "The Expendables".', '/ejMVMjjd7XPjfLDmf78vV3VNoYt.jpg', '2010-11-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15305, 'Direct Your Own Damn Movie!', 165000, NULL, NULL, 'Direct Your Own Damn Movie!', 'Legendary director Lloyd Kaufman, President of Troma Entertainment and Creator of the Toxic Avenger, reveals 40 years worth of maverick cinematic know-how in Direct Your Own Damn Movie! Lloyd offers you the magic key to operating outside the film studio system as well as providing you with the roadmap to script writing, pre-production, casting, managing your set, post-production and the secrets of selling you movie!', '/76InRyePJcjLIbfTs51ToPThrzQ.jpg', '2009-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15306, 'Red Desert Nights: Making Ghosts of Mars', 1048938, NULL, NULL, 'Red Desert Nights: Making Ghosts of Mars', 'Documentary about the making of John Carpenter''s sci-fi horror movie, Ghosts of Mars.', '/57aEOQ2VHPMfXQqDOVbtYgPBByE.jpg', '2001-12-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15307, 'Making ''Snatch''', 357659, NULL, NULL, 'Making ''Snatch''', 'The making of Guy Ritchie''s ''Snatch''.', '/hDpAqVdBVAjRepOHGn1EngI8FSH.jpg', '2001-07-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15308, 'Truth In 24 II: Every Second Counts', 111192, NULL, '/xO21Nwgzu3ssa9L5zhTWCxGcSE9.jpg', 'Truth In 24 II: Every Second Counts', 'The film TRUTH IN 24 II documents the tenth and arguably most emotional triumph of the brand with the four rings at this sports car classic. After two Audi R18 TDI cars have retired following spectacular accidents, the remaining Audi fights a dramatic battle for overall victory with the three Peugeot 908 cars which the Audi trio ultimately decides in its favor with a narrow margin of 13 seconds. The film captures the entire drama of the fourth-narrowest running of the Le Mans 24 Hours with intimate insights into the team of Audi Sport and breath-taking pictures.', '/7sycIw5sg6zqHzdI8DColwDjTdI.jpg', '2012-03-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15309, 'Jean-Claude Van Damme: Karate King', 1103705, NULL, '/AcLne9m4VRaGzXK0Lrp4Ll0fB1r.jpg', 'Jean-Claude Van Damme, coup sur coup', 'An American low-budget action film celebrated an unexpected worldwide success in 1988: "Bloodsport". With its, the world of film fans and martial arts cinema discovered a new idol: Jean-Claude Van Damme. In the 1970s there was Bruce Lee, but at the end of the 1980s a Belgian won the day. Van Damme was a karate master and had unparalleled strength and flexibility. For ten years he was one of Hollywood''s hottest action stars. But excessive overconfidence and drugs bring him down again. At home in Europe he becomes a laughing stock on talk shows. Only with "JCVD" does he manage to get back on his feet, playing his character with perspective and self-irony, but without ever giving up the reputation that his action films brought him and which has been a cult for several generations. The highs and lows of his eventful life are told through archive footage and contributions from people close to the popular Belgian actor.', '/1UrweOtMOmXGuYWIpz56sOtjDGA.jpg', '2023-03-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15310, 'Fast & Furious 6', 82992, NULL, '/xDp29MSWa7O3ROC13r6dPTFnREJ.jpg', 'Fast & Furious 6', 'Hobbs has Dominic and Brian reassemble their crew to take down a team of mercenaries; Dominic unexpectedly gets sidetracked with facing his presumed deceased girlfriend, Letty.', '/3EXOOkhSmJQ9DisNmIjZ8Xi633I.jpg', '2013-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15311, 'Thai Boxing: A Fighting Chance', 1441316, NULL, NULL, 'Thai Boxing: A Fighting Chance', 'Three fighters pursue their dreams in the world of muay thai. Sam Sheridan, a 27-year-old Harvard graduate, travels to Thailand to train under a legendary champion. Gong-Prai Sorjintana, a 13-year-old boy, fights to earn money for his education. Boon-Term Kitmuti, a 29-year-old mother, defies tradition to enter the ring despite her husband''s disapproval. As they prepare for their toughest battles, their journeys reveal the challenges, sacrifices, and passion behind the sport.', '/7f2a3MD8ThFiLUyp4weyhRCcGyK.jpg', '2002-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
