INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15314, 'John Doe', 1683034, NULL, NULL, 'John Doe', 'A man has no memory, no past, and no name — and only one face he can’t forget: Eliza. As fragments of his identity return, he discovers he was trained for a mission still in motion and is being hunted by the very people who sent him. With enemies closing in, John must choose between finishing what he started… or protecting the one thing that makes him feel human: love.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:49', 0);
