INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15318, 'Counting to 1000', 1210838, NULL, '/yKj7L9uamSz4W5mZ3TsUwGpmD5J.jpg', 'Counting to 1000', 'Detective Callow explores the gray area between good and evil while investigating a botched home invasion by low-level criminal Donny and his ruthless crew. As he interrogates Donny, they unravel the twisted motives behind what should have been a simple job.', '/sT4lgN3o4JWOc04etV0KLs3p5Oa.jpg', '2016-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
