INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15320, 'How It Ends', 776559, NULL, '/xhV3CYYyiGeY58FT5YwC9RzXNKy.jpg', 'How It Ends', 'Liza scores an invite to one last wild party before the world ends. But making it there won''t be easy, as her car has been stolen, and the clock is ticking on her plan to tie up loose ends with friends and family. Accompanied by her younger self, Liza embarks on a hilarious journey across Los Angeles, running into an eclectic cast of characters.', '/h4FQ8H77z6rIY82HzR5wgOYoxCA.jpg', '2021-07-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
