INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15322, 'Elden Ring', 1485839, NULL, NULL, 'Elden Ring', 'A live-action adaptation of the dark fantasy video game, taking place in the war-torn world of the Lands Between, which was once united by the Elden Ring.', '/3ApvUAl0aw6TKKLkJH3IrEzPpIf.jpg', '2028-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15323, 'Iron Bridge Kung-Fu', 875024, NULL, NULL, '莽漢鬥老千', 'Iron Bridge Monkey is 10th generation of O Mei section, in order to protect the national treasure – Jade Watermelon, he lives at Tien Ho town secretly and disguises as a time announcer. General Chang intends to find it and sell to a foreigner. When his real identity is exposed, he has to run away. Who will finally get the Jade Watermelon remains a puzzle…', NULL, '1979-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15324, 'Dance of the Drunk Mantis', 49642, NULL, '/9G8MM6gylR68Q64tbGPcFaKWCB5.jpg', 'Nan bei zui quan', 'A year after training young Jackie Chan in the Drunken Fist, Sam the Seed discovers he has a son, Foggy. He tries to train Foggy but to no avail. Foggy is then trained in Drunken Fist from his uncle as he must face his father''s rival, Rubber Legs, another Drunken Fist master who combines it with Mantis Fist to create a deadly style.', '/jNOdUZHi7MKhFTq88ZIRqSGrQD3.jpg', '1979-06-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15325, 'Sleeping Fist', 71598, NULL, '/1ikxT4tfA1B7RFWARuwxio9cq5c.jpg', '睡拳怪招', 'A plainclothes policeman, Chin Tai Ba, is seriously wounded in a fight with some ruffians but is helped to safety by a young wiseguy, Cub. Here he is taught the art of Sleeping Fist by Cub''s master Chung Yiu, and the trio march to the Shang Wei martial arts school to take revenge on the thugs. However, in a last desperate attempt to get even, the gang call on Eagle Claw master Kao to sort out the snoozers.', '/eg8c2IDOtV2lyuxhPDw5NzAKfKg.jpg', '1979-05-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15326, 'The Story of the Drunken Master', 52882, NULL, '/wfrf33etzWhDm2WuzOiyPeDQ6ug.jpg', '醉俠蘇乞兒', 'Beggar So is trying to keep his two star students, brother and sister team Cheong and Gam Fa, in line and well-trained. But So''s old enemy Grasshopper Bill Chan and his brother Cougar cause trouble. Bill helps young Kai to be pledged in marriage to Gam Fa against her wishes, but actually plans to have her for himself.', '/d6NkO7BLkGQUpAIVkdkM2qOMHwv.jpg', '1979-07-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15327, 'Blind Fist of Bruce', 54321, NULL, '/9SHjf2XPJIydLvOwzQNFjVr91qz.jpg', '盲拳鬼手', 'The incomparable martial arts expert, Bruce Li, stars as a wealthy hero who defends his village from the assaults of ill-wishers.', '/ntsKI4znP2qorsHHdsEV0WpsIX4.jpg', '1979-07-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15328, 'The Mystery of Chess Boxing', 54503, NULL, '/3pS9Epuztiggpcez0rzHcbs1JkS.jpg', '雙馬連環', 'Evil Chun Shan uses chess boxing and a five-element ninja style to terrorize the martial arts world until he is challenged in a series of battles, then destroyed.', '/wF8FQKNI1LZ5UQBXhgAvAqEDfUl.jpg', '1979-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15329, 'Dragon Swamp', 75699, NULL, '/vYBfjpTZCfYhwR8MLMnEaAAMUL.jpg', '毒龍潭', 'After being implicated in the theft of the Jade Dragon Sword, Fan Ying (Cheng Pei-pei) is banished to the Dragon Swamp for 20 years. Now, 20 years later, the sword has been stolen again, and the members of Lingshan Clan are sent out to find the culprit. Among those is Qing-Erh (Cheng Pei-pei again), who meets a wandering swordsman (Yueh Hua) searching for the long lost Fan Ying. Together they decide to enlist the help of the Dragon Swamp Master in their respective searches.', '/uLC8dc360BXQXNvOnxn3H58K7cq.jpg', '1969-03-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15330, 'The Chivalrous Whip', 943688, NULL, NULL, '神鞭俠', 'Doctor and whip-wielding Hero Chai Tin-sum travels to an isolated village where he finds the population dying of the plague while being oppressed by the Ku family and their fortress. The family has cutoff the supply of fresh water to the village causing calamity. Chai must find a way to defeat the Ku family and restore water or the village will die.', '/7ycqFAcMKNx5sJIXmAAg0XHjzKT.jpg', '1968-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15331, 'Drunken Arts and Crippled Fist', 128651, NULL, '/oMbYun3hIO1KpieNMIRQh6gU7ym.jpg', '怪拳小子', 'At the age of eight years old, Shao is sent to train under the notorious drunkard "Crippled Fist Master". Shao returns home after ten long years of training, to find himself dealing with local criminals and gangsters.', '/4fCFDFdLCm0qiszBVXXL5ZbPc8T.jpg', '1979-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15332, 'The Silent Swordsman', 198303, NULL, '/dzwEkLPOpb1BbCCnAV91rt44Eys.jpg', '儒俠', 'A young swordsman is tasked to lead a patriotic secret society to fight a traitorous general who conspired with the enemy to invade their country. In due course, he meets two pretty sisters from a rural tribe and is caught between the affections of the two girls...', '/ak7QjLhCJmIYx5RYmW8UR6KHkrW.jpg', '1967-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15333, 'The Nine-Finger Devil', 1174383, NULL, NULL, '九指怪魔', 'HK horror crime thriller.', NULL, '1955-06-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15334, 'Lady Robin Hood', 489041, NULL, NULL, '女羅賓漢', 'A sick king instructs his loyal minister Luo Zhengqing to guide and install the crown prince as king after his death. However, the minister of the army, Situ Yangming, makes a grab for power after the King''s death and incarcerates the crown prince. Luo''s daughter disguises herself as the male bandit Robin Hood, robbing government offices to help the poor. Meanwhile, Situ orders captain of the imperial guards, Zhang Zhonggeng, to kill the crown prince. Zhang is a loyalist and conspires with Lady Robin Hood to save the crown prince. When Situ discovers that the prince has escaped, he falsifies the late King''s will and has himself crowned as king. However, the female Robin Hood has stolen the original will. The female Robin Hood kills Situ and installs the crown prince as the ruler.', '/aOxNcGmNbsufZV6CfEWNzCpmQyL.jpg', '1947-10-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15335, 'The Dragon Lives Again', 84275, NULL, '/mPRC7OAQq4lQZlwQ13msQpH4th.jpg', '李三腳威震地獄門', 'Everyone''s favorite martial artist ""Bruce"" winds up fighting for his life and soul in hell against an evil Warlord intent on making him mincemeat - and he has recruited some of the 1970s most iconic B-movie characters to help dispatch the great one. But when that won''t do the trick, he uses monsters, mummies and beautiful women to get the little dragon at any cost.', '/vEtx6bQv3UTk8SWTJCwX18AXBdN.jpg', '1977-03-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15336, 'The Knight of Knights', 183783, NULL, NULL, '文素臣', 'Six heroes are killed while investigating rampant lawlessness at Zhaoqing Temple where villains are posing as monks. The dead heroes’ senior brother Su-chen and his two apprentices pose as scholars in order to infiltrate the temple. When the life of the Emperor’s Inspector and his daughter are threatened, the trio leaps into battle as government troops prepare to storm the temple.', '/nkfA6PSILpiYRGw3xuB2xTTQkiS.jpg', '1966-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15337, 'The White Crane Hero', 1021585, NULL, NULL, '白鶴英雄傳', NULL, NULL, '1956-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15338, 'Jin ou', 1220797, NULL, NULL, 'Jin ou', 'Gangster Li Yibiao''s jewelry was suspected to have been stolen by Gu Daqiang. Biao asked Jin Zhenyu to cooperate with him to get the jewelry back. During this period, Yu discovered that the mysterious woman Jin Ou was also looking for jewelry, and the two agreed to cooperate. Hou Yu learns that Biao set up a trap for him and Qiang to kill each other, and Ou and Qiang confront Biao. The jewelry originally belonged to Ou''s deceased brother, so Yu lets Ou take it back.', '/j8b7v3WfU6Tj1e8qNFfbciX0zpJ.jpg', '1967-06-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15339, 'The Murder Case at Club 99', 993967, NULL, NULL, '九九大血案', 'Club 99 is not just a hideout for triad gangsters, but also a haven for smuggling jewelleries from robbery. When detective Law is investigating a jewellery heist, he is ambushed by the men from Dog Stone (Sek Yin-tsi) who is the owner of Club 99. Then, Law''s daughter Fong (Law Yim-hing) helps her father to be undercover and disguises herself as a dancer in the club and gambler Lung (Lam Kau) is also an informant for the police force. While Dog Stone is cunning enough to discover their identities, there are in fact more undercover agents in the club...Influenced by Hollywood''s semi-documentary style, the film has a detailed yet complex portrayal of human nature－undercover anxieties, domineering gangsters and moral ambiguity. With its realistic chasing and action sequences, the film is nonetheless a very entertaining piece of cinema.', NULL, '1956-07-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15340, 'The Young Rebel', 206452, NULL, NULL, '後生', 'When Ti Lung and David Chiang left Shaw Brothers, they returned a year later after learning directing and defied their former studio heroics making films with social leanings. Directed by Ti, The Young Rebel is one such film. Fatherless as a child, Hsiang (Chiang) supports his mother. When gangsters kill his mother, he kills in revenge. Unlike his swordplay heroes, Hsiang admits guilt, expresses sorrow and is imprisoned', '/mVHpNX7EiF8yehQ96XT7JtK0r5m.jpg', '1975-02-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15341, 'Wong Fei-hung: The Whip That Smacks the Candle', 202509, NULL, NULL, '黃飛鴻鞭風滅燭', 'Martial artist Wong is confronted by other masters. After he returns to his disciples, he vents his anger during a fierce fight.', NULL, '1949-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15342, 'The World of Drunken Master', 67023, NULL, '/2npQJ4UcfJoZXXQU8Uur2pHWLjR.jpg', '酒仙十八跌', 'Chan Hui Lau stars in this vintage martial arts film as Chang, the owner of a winery and master of Drunken Boxing, a deadly kung fu technique that, as the name implies, requires its practitioner to be drunk. His relatively peaceful life is interrupted when he catches two boys (Li Yi Min and Jack Long) stealing grapes from his vineyards and puts them to work for him. Over time, he teaches them the art of Drunken Boxing. When the two boys get into a fight with some local toughs, they provoke the wrath of Yeh Hu (Lung Fei), Chang''s enemy.', '/6lpnzOR69N35YVaySrfYUUFpkUo.jpg', '1979-11-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15343, 'A Sword and Nine Rings, Part Two', 1240245, NULL, NULL, '追魂太極鏢', 'Lee Kap-lan, whose parents are slaughtered by the underling of the Qing court, Yan Sheung-kong, is rescued from the carnage by Leopard-faced Magic Nun. Nun imparts martial artistry to Lee, who will kill the old enmity when she grows into womanhood. Yan and his half-brother Luk Sun are assigned to capture the survivor. Fong-ping comes under the attack of an assassin dispatched by Sun when Butterfly comes to his help. Recruited to the Yan den, Ying Tin-lung summons the knights-errant of the martial world to the court. Lee infiltrates the congregation and has her eyes fixed upon Sun and strikes him with the Soul-snatching Tai Chi Dart which has mistakenly wounded Fong-ping. Butterfly puts Lee into a drug-induced coma to obtain the antidote to treat Fong-ping. Ying seizes the chance to capture the women. Fong-ping sustains another injury to rescue the hostages. Nun arrives in time and seizes the Lee family heirloom. Lee avenges her parents'' death.', NULL, '1961-06-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15344, 'Drunken Master Strikes Back', 116042, NULL, '/xqwRGTsdnaYSitigxHlgPgtGg7R.jpg', '怪拳怪招怪師傅', 'Two fools learn kung fu from an old master of iron back style. But after getting a beating from the town''s hardman they seek out the service of the drunken master to help improve their kung fu skills.', '/3nZJ6SEQwRNj7SpGH8QQjpwOxAR.jpg', '1978-08-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15345, 'The Devil and Her Magic Needles, Part One', 1254617, NULL, NULL, '白骨離魂針', 'Yiu But-fan marries on the day his father Yan-kit retires as a distinguished swordsman when Yan-kit''s nemesis ''Ghostly Mother Blue Flower'' Chiu Choi-wan and her foster son Lai Chun-wah gatecrash the party, striking dead the elder and But-fan''s wife with the White-bone Soul-thrashing needles. Having pledged his alliance to the anguished son, Taoist Tranquil of Emei vows to eradicate the menace at Mid-Autumn Festival when his junior disciple Kau Suet-mui is challenged to a duel with Chiu. Kau''s fellow disciples Hung Tin-bo and Chuk Yuk-heung follow the orders of their master to roam the martial world and tumble into a bandit lair. Extricated from danger by the Taoist, the duo join hands with the passer-by Yiu to thwart Lai''s assault on Kau by sorcery, again aided by the Taoist. Yiu, Kau and her peers head back to the Kau Fortress where a martial contest is being held to select a prospective groom for the daughter. Kau overwhelms Lai in the ring but concedes defeat to Chiu.', NULL, '1964-01-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15346, 'The Devil and Her Magic Needles, Part Two', 1254621, NULL, NULL, '白骨離魂針下集大結局', '''Ghostly Mother Blue Flower'' Chiu Choi-wan has abducted a group of virgin boys and girls for the nourishment of her mind and soul. Alarmed by the abduction, Yiu But-fan, Kau Suet-mui and Hung Tin-bo make a night raid on the Hanshan Temple to release the children and set a torch to the bandit lair. Fuming over the arson, Chiu casts a spell on Kau, who kills the father of Chuk Yuk-heung in her cross-dressing persona as Yiu. Confronted by the angry Chuk clansmen at the Chuk Fortress, Yiu tries futilely to defend his innocence. Believing that Chiu has masterminded the framed murder, the fugitive infiltrates the White-bone Yinyang Cave where he finds himself attacked by Kau and Chiu. Demon-vanquishing Magic Monk, Chuk and Hung helped Yiu wrestle Chiu, who fled. Kau is nursed back to health by the monk and joins the fellowship in their quest to annihilate the demon. With all her venomous needles forfeited to the monk, Chiu gets her comeuppance, slain by Chuk''s flying dagger.', NULL, '1964-01-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15347, 'Mad Mad Kung Fu', 86851, NULL, '/fQjNX9wbik5npNvYz5gJQF1v9qH.jpg', '怪招軟皮蛇', 'This old school martial arts comedy involves the search for the elusive “Bamboo Stick,” an aged kung fu master played by Simon Yuen, who kills a local crime boss’s son after taking the place of the son’s forced bride on the wedding night.', '/xENP69HHGEBkoahXSpN0LAjPQ90.jpg', '1979-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15348, 'Crystal Fist', 128911, NULL, '/4UiVsPaCTRKc4b9S8c4DicSxnuy.jpg', '奇招', 'A young man vows revenge against the killers of his father. To do this, he must train with his father''s teacher who teaches him the "Shadow Claw", a deadly combination of the eagle claw and shadow fist.', '/bvvlj1AQoQ19iCEIj38o3cAVOM1.jpg', '1979-06-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15349, 'Shaolin Martial Arts', 64360, NULL, '/owbCzjkSPheXnTZzzUfAjO51TfE.jpg', '洪拳與詠春', 'After the destruction of the Shaolin Temple, the Chings are in control and send their best students to wipe out all of the remaining Shaolin practioners. They almost succeed, but two students escape. They learn various Kung Fu styles from different teachers to combat the Ching''s two kung fu fighters.', '/i0YKxuP5bFXrMp7bSQyWyYqh4RO.jpg', '1974-08-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15350, 'The Warlord', 187901, NULL, '/t3ArFrmZrgXzsMZit77qzlBHrMM.jpg', '大軍閥', 'No list of the screen''s comic geniuses would be complete without Michael Hui Kwun-man. He created a hilarious and lovable comic persona that was both uniquely Asian but also universally beloved. This, his first film, not only showcased his incomparable sense of humor but revolutionized Hong Kong comedy. Evoking Chaplin, he plays a warlord in early 20th Century China, but makes the role his own with both laughs and some of the sexiest ladies on the Shaw Brothers lot.', '/zGDtUPC34d6cuw85XzonpqV0OQW.jpg', '1972-08-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15351, 'Deadly Snail vs. Kung Fu Killers', 276090, NULL, NULL, '天螺大破五行陣', 'The epic magical battle between fairies rages on as young martial artist Cheung risks his life to rescue the Sky Mussel Fairy. No good deed goes unpunished, however, and for his daring but foolish antics, Cheung is cast out of his uncle''s safe home. Now, Cheung wanders a perilous world of gods and demons. Only his fighting skills can keep him safe.', '/xJTTEY72SJNFVjSaCO3XVmCD6RB.jpg', '1977-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15352, 'Secret Book', 1296309, NULL, NULL, '仙鶴神針', 'Find the secret book', NULL, '1961-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15353, 'Karate from Shaolin Temple', 395694, NULL, '/xciL4Dyfw4fpptYMBZkVNRadenH.jpg', '少林寺拳法　ムサシ香港に現わる', 'The Japanese karate master Muhashi spent some time in Hong Kong studying various Shaolin martial arts styles. Soon the narcotics brigade calls in his help to combat a powerful drug and prostitution syndicate.', '/w7CMyrA9PQr5BFz3tQpod9dHxL4.jpg', '1976-11-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15354, 'Kung Fu Master Named Drunk Cat', 404481, NULL, '/35TpwBhTIgs0nToTAqJmR666YAi.jpg', '醉猫师傅', 'Given a jar of sweets by a beautiful air-hostess, Chan finds that each one contains a diamond (diamonds belonging to a ruthless smuggling gang). Chan finds out the hard way that when there’s no place to hide and nowhere left to run, a fight to the finish is the only way out!', '/s1OL5RJsqHfxvDdvWm6dv3lFMvt.jpg', '1978-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15355, 'Operation Hong Kong', 254406, NULL, '/qykuI3zHJ8ZpXIo58ry1M41wmY4.jpg', 'Weiße Fracht für Hongkong', 'A suave gangster tries to get away from his boss with a suitcase full of heroin. Two pilots and lots of beautiful women get involved in the affair. Soon blood begins to flow.', '/sofR4nU72HxSOcOUsJYmZwQ8OqH.jpg', '1964-03-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15356, 'Hong Kong Hot Harbor', 254124, NULL, '/6zJ6n81E1vQ2fsSUK2TBfMLHwQ8.jpg', 'Heisser Hafen Hongkong', 'German journalist Peter Holberg arrives in Hong Kong and, by accident, he is carrying a microfilm that was destined to local gang lord, Marek. Peter is helped by another German journalist, Joan Kent, and falls in love with a night-club dancer, Colette. Colette is actually working for Marek, but betrays the gang for love - at the ultimate cost to her. The HK Police will intervene just in time to prevent Peter from further losses.', '/rs2tchhtfRnQu3AwJvn7hwnklH6.jpg', '1962-05-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15357, 'The Kiss of Death', 107893, NULL, '/fw1xeQVgpPWNfpk5cxqrslCTJTp.jpg', '毒女', 'One night a textile worker is sexually assaulted by five deviants. The young lady tries to cope with the aftermath of this dramatic event but her life is ruined. Like a shattered vase, the pieces can be put back together but it''ll never be the same. Cheng get''s a job as a bar girl. She meets the club''s owner who was a former kung-fu fighter until he was crippled. Cheng uses her position as a B-girl to go after the losers who raped her, She soon learns from a sleazy doctor that she has contracted a dark V.D. called Viet-Nam Rose. Crushed, she begs Lo Lieh to teach her kung-fu. At first he refuses until he learns her secret. Furious, Lo Lieh teaches her his deadly fight techniques (such as a groin crunching blow).', '/s0Rm6rprOlEtbcSrw72ZbebXLHK.jpg', '1973-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15358, 'Against Rascals with Kung-Fu', 145830, NULL, '/coVdajl2CvVmPFxaak1yiV5X1vg.jpg', 'Lao tou quan tou da man tou', 'A old ill-humored White Crane master teaches his martial art to a young loner. Soon they must battle side by side against the cruel Snake style master and his predatory followers.', '/iUotATpZHkBxj4PVXF9Ly4pS5Tw.jpg', '1980-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
