INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15368, 'Iron Bones', 478884, NULL, NULL, '鐵骨傳', 'Iron Bones, about a young lad that learns a secret Tai Chi type of style called the Wind Palm, where you can kill with chi blows. Sure, it''s a little crazy, but the acting is a big cut above most martial arts movies and the sword fights are pretty good. And Sam the Seed shows up, sans wig, as a dirtbag Shaolin monk after the book. Han Ying Chieh, the big boss, is one of the thugs in the background.', '/3qyKBzpHnfrfGF54omJDlfVmJT5.jpg', '1969-01-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15369, 'The Association', 298458, NULL, '/tZlM05PFh7q8Y1zJiXFSA9I1Ns2.jpg', 'Yan ku shen tan', 'Plain-clothes detective Wang is the best in his trade. One day he stumbles across a young girl''s body who apparently is died of abortion. Wang investigates the guilty abortionist who leads Wang to a secret organization called "The Welfare Association". Actually it is an international prostitution racket. Wang sneaks into the association. When he is about to arrest the association''s organizer, a girl, Lei, whose sister''s death cause by the secret society, saves Wang in certain death. Wang arrests the organizer but has set her free from headquarter. Wang and Lei get together in getting the commander dismissed.', '/n89BOS1iMgxC5yU7R2CYebSFLFW.jpg', '1974-11-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15370, 'The Witch', 483386, NULL, NULL, '碧眼魔女', 'Hong Kong martial arts / horror.', '/1tPsqNEgEd3tCtQ9IAuHetfSQup.jpg', '1967-04-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15371, 'The Black Centipede', 482265, NULL, NULL, '黑蜈蚣', 'Enter the dragon villain, Shek Kin, is the Leader of the Black Centipede clan, a ruthless gang who terrorize the good people of Fuzhou, Walter Tso and Connie Chan are taught some tricks from---old Sam the Seed himself on how to bring down the Black Centipede clan.', '/p2n9NenhewxBuLsqTnh8wOcyben.jpg', '1963-04-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15372, 'Heroes of the East', 40980, NULL, '/gfULDSNKtqvWN315mufsRFSpe3Y.jpg', '中華丈夫', 'When a series of martial misunderstandings spirals into an international incident,  a Chinese martial arts student struggling to relate to his new Japanese wife is forced to take on seven of Japan''s most powerful martial arts masters, each an expert in a different discipline, ranging from karate to samurai to ninjitsu.', '/h06JtkvCkOChzcm13O8DYVwmspP.jpg', '1978-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15373, 'Red Dragon', 196531, NULL, '/y4Yspi1DaLg7GevSxq8gUsYp2zC.jpg', 'Das Geheimnis der drei Dschunken', 'An FBI agent goes to Hong Kong to short-circuit a smuggler of electrical parts to the communists.', '/A5op86U0i5S1zwepa4JllO2GsDk.jpg', '1965-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15374, 'The Buddhist Fist', 61039, NULL, '/64h5I54oZ1gHSDchzme9tjcFjVK.jpg', '佛掌羅漢拳', 'Two orphans raised by monks are taught divine secrets of kung fu. As adults, one chooses the path of the monks while the other opts for the outside world. Aspiring barber and experienced kung-fu fighter Shang learns that his childhood friend, Siu Ming, has been framed for murder by an unknown villain.When Shang begins looking into the crime, he soon finds himself the target of an assassination attempt. They reunite to find their missing godfather and seek vengeance on his kidnappers. Who is behind all these crimes, and can Shang stop them?', '/xR0mBnDeH6iENFhZ7TVTglFnD49.jpg', '1980-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15375, 'The Sword and the Lute', 100943, NULL, '/xkEEkBYjNq2RNGqfyC7rwWq21Ie.jpg', '琴劍恩仇', 'The adventures of a young married swordfighting couple, Lianzhu and Gui Wu, and the swordfighting members of their different clans.', '/eoI8h3XyoeHJQ72nFWDuPTRQdiV.jpg', '1967-04-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15376, 'The Fragrant Sword', 451770, NULL, NULL, '一劍香', 'The Fragrant Sword is a Hong Kong Martial Arts movie starring Stanley Fung. Yu Lap-chung has been executed for the murders of martial alliance members when the black-clad assailant to blame is still roaming free. Apprehended by the murder threats to the helmsman of Emei and Xueshan, Golden-clad Ambassador of the alliance solicits help from the security escort master Wai To, Yu in disguise spared from execution by his master who had a rapist stand in his place. The fake scholar ingratiates himself with Ai Ching-yee, daughter of the Mulberry Pillar Fortress helmsman Ai Pak-chuen and exposes the father''s conspiracy with his sworn brother to rule the martial world by dispatching Ching-yee''s senior disciple Sze-hung Ying to commit atrocities against the martial alliance. Yu cajoles Ching-yee into assisting in Sze-hung''s capture and with the culprit handed over to the alliance, the young lovers wander away.', '/rx5uAdUDbpQNwQRVTje84UWokf3.jpg', '1969-01-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15377, 'The Snowflake Sword (Part 1)', 577170, NULL, '/2NgyDimSluY8fb23RwusdKGczsr.jpg', '雪花神劍(上集)', 'The Blood Pool Map re-emerges in Jiang-hu, and all good and evil sects hunt for Fang Zhaonan, who is said to carry it. For his part, he simply hopes to trade it to the herbalist Lu Xuan for medicine he needs to free his sister, but fate has other plans.', '/oVpMrdhoBieSl09mTK6PEMSYXnN.jpg', '1964-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15378, 'Little Mad Guy', 579181, NULL, NULL, '潮州笑汉', 'Slapstick humor and over the top martial arts action highlight this madcap adventure tale of a simpleton who fights for the people.', '/3snN0VP1sHGfVEv1M0rknGzhhAf.jpg', '1982-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15379, 'The Goddess of Mercy', 350941, NULL, '/VINixjY5KwTxPVoWWfV1dNaTXB.jpg', '觀世音', 'With her elegant classic persona, Li Li-hua was the ideal performer for period aristocratic and imperial roles. The Goddess Of Mercy is a good example of her strong empathy and noble presence. The youngest daughter of a brutal king, the princess openly disapproves of the floggings and cruel treatment her royal family heaps on the peasants. As a result, the heartless king turns on his own daughter forcing her into exile.', '/exheMlvcfzvwwaB3NLujWLbrTRo.jpg', '1967-03-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15380, 'An Old Kung Fu Master', 46479, NULL, '/gO2C2IVCNSdOC17ot0U6sWBbHdi.jpg', '一老一少一根钉', 'A movie starring Simon Yuen Siu-Tin as a Kung Fu master.', '/z178DlVITgnC2YmWEbLWz0Yt6I2.jpg', '1981-05-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15381, 'Martial Arts', 115325, NULL, NULL, '絕招', 'Chen is forced by his father to leave their home as evil plotters plan his death. On his journey he kills a man in hand-to-hand combat and then decides to find and help the man''s family.  When Chen arrives, he meets the dead man''s two pretty daughters, now under the control of an evil war lord and his cruel gang. One by one, Chen takes them down until the big tournament, when he is forced to fight several skilled killers in a variety of martial arts styles. After winning the tournament, Chen takes on the big war lord himself in a fight to the death!', '/c0ihBRaJjw5dG3GXWkUdqai8io.jpg', '1974-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15382, 'The All-powerful Flute: Part 2', 678854, NULL, NULL, '蕭聲震武林(下集)', 'Yuan Xiao is chased by the panther head monster, and starts a fierce fight. Wang Gunlong and Min Tianhu take the opportunity to capture the flute.', NULL, '1965-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15383, 'How Liang Hongyu''s War Drum Caused the Jin Army to Retreat', 747500, NULL, NULL, '梁紅玉擊鼓退金兵', 'The Song Dynasty is in danger after being invaded by Jin soldiers. The geisha Liang Hongyu encourages her lover Han Shizhong to join the army and fight against Jin Zhong''s superior, Wei Liangchen.', '/aNoRUa8SC78kDjgJvnAY7mgkZiU.jpg', '1956-08-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15384, 'Jackie Chan - Invincible Fighter', 415965, NULL, NULL, '成龙 - 龙威天下', 'Invincible Fighter is a documentary on Jackie Chan', '/hstkzLXWXBsUOYfoPgMhscH7SSt.jpg', '1995-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15385, 'The Six Directions of Boxing', 277446, NULL, NULL, '六合八法', 'Capt. Ai, a small-town policeman, receives orders to apprehend a gang of gunrunners and find their hidden stockpile of weapons. Enlisting the help of his girlfriend''s father—who happens to be a retired kung fu master—the captain takes on both the criminals and a few corrupt officials sent in for good measure.', '/4JWDpNPhQgemirw8oQA3R5J2Dsv.jpg', '1980-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15386, 'Wong Fei-Hung Goes to a Birthday Party at Guanshan', 839157, NULL, NULL, '黃飛鴻官山大賀壽', 'Wong Fei-Hung Goes to a Birthday Party at Guanshan is a Wong Fei-Hung movie starring Kwan Tak-Hing.', '/4CauWZE0UvrVeerYm3ZCB7R8k7f.jpg', '1956-10-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15387, 'The Killing Flag (Part 1)', 839317, NULL, NULL, '奪魂旗(上集)', 'The master of the Soul-Snatching Banner has re-emerged in jiang hu to cause chaos and disruption. He leaves his mark - the killing flag - to show where he will strike next. The younger generation of swordsmen and women seek him out to end his rampage but each end up badly injured and dispirited. Part one of two.', '/hkLarTVghZHkgEFzRypA5YxY186.jpg', '1963-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15388, 'Spy No. 13', 841784, NULL, NULL, '十三號情報員', 'During World War II, spy Wu Lai-sheung is instructed by her superior Fan Yeung-shan to murder spy number 13 Cheung Chi-ping. While Wu establishes a relationship with Sakei, the assistant general of the Japanese army, she also gets acquainted with Cheung. Cheung and Wu fall in love. Wu recommends Cheung to become Sakei''s driver. Cheung pretends to court the Japanese spy Siu-kuen, but Siu-kuen arranges to kill the spies contacting with him. Cheung has seen through Kuen''s identity for long. When Kuen is going to kill Wu, Cheung kills Kuen, Fan compels Wu to kill Cheung. Wu follows the instruction to murder Cheung. After the murder, Wu disappears. After the war, Fan discovers Wu ends up in asylum. When he visits Wu, he tells her of Cheung''s innocence. This breaks Wu''s heart. Cheung turns out to have seen through Wu''s identity for a long time and pretended to have been killed to cover up his identity and facilitate his work. With the truth known and the war ended, Cheung and Wu married.', NULL, '1964-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15389, 'The Story of Wong Ang the Heroine', 860031, NULL, NULL, '女飛俠黃鶯巧破鑽石黨', 'The Diamond Gang commits a robbery. The leader Chiu Yee-kong wants to keep the booty and this arouses the suspicion of gang member Tai-wai. The police does not have a clue and thus invite Wong Ngung, Heung Ad and Wu Ngar for help. Kong is in accomplice with his third concubine. They order someone to steal the diamond and leave Wong''s symbol. Wai turns his attention on Wong. Wong, Ad and Wu are not afraid of Wai and they throw him out. They sneak in Kong''s apartment to investigate. Kong''s second concubine is mad at Kong for neglecting her. She tells Wong the truth but gets killed. Kong''s people surround Wong, Ad and Wu. Each of the three faces their enemy.  Ad is tortured by Wai. Wong and Wu arrive in time and save her. One of Kong''s people tells Wai the truth. Wai immediately attacks Kong. Wong, Ad, Wu and the police arrive at Kong''s headquarter to arrest the gangsters. Wai is arrested but Kong has escaped. The diamonds are found. The inspector makes Wong, Ad and Wu as partners.', NULL, '1960-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15390, 'How Oriole the Heroine Solved the Case of the Three Dead Bodies', 860045, NULL, NULL, '女俠黃鶯夜破三屍案', 'The three heroines, Wong Ang, Wu Nga, and Heung At expose a murder case involving three dead bodies found in an old temple. Unbeknown to the trio, they''ve fallen in a trap laid by gangster Hui Pui-shing, who desires to avenge his brother''s death by eliminating the women. With the cooperation of Hui''s righteous subordinate, the police arrest Hui for smuggling tobacco and seizes their forged banknotes.', '/fqvZXI1T7yMZo3OUC9idaNDbuPn.jpg', '1959-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
