INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15400, 'The Six-fingered Lord of the Lute (Part Two)', 1472458, NULL, NULL, '六指琴魔(下集)', 'The Martial World is in disarray as each faction accuses the other and the mysterious Six Fingered Lord of the Lute uses the chaos for his own benefit. Meanwhile Yuet-Wah penetrates the castle of Hell with the help of young Ghost Slave (Nancy Sit), to rescue Lui Lun (Connie Chan).', '/5WX2ErIciQ2Fnrr0ND9zZcr8Tmi.jpg', '1965-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
