INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15404, 'Return of the Crazy Bumpkins', 187679, NULL, NULL, '阿牛出獄記', 'The sequel to John Lo Mar and Chang Yang''s original film finds the naive village immigrant, Ah Niu (Yeh Feng) leaving jail to work and live with his crooked Uncle Chou (Wang Sha) again. But now, his girlfriend Ah Hua (Ai Ti) has become the wife of an abusive husband. As with the bittersweet original, Ah Niu -- with his kind heart but simple mind -- gets caught in various rackets and silly situations.', '/sCRtPsWVffeygMOgaiMjBrDZfRk.jpg', '1975-05-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
