INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15432, 'Fear the Night', 1143190, NULL, '/2gmaQoioyg0nmYEMBlSjBovLcUy.jpg', 'Fear the Night', 'During a bachelorette party in a secluded California farmhouse, masked intruders launch a brutal attack, forcing eight women to fight for survival. Led by Tess, a troubled military veteran, they unite to defend themselves throughout a harrowing night.', '/oAWpvlroYbHbkaeKwlL3XlVRnyG.jpg', '2023-07-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
