INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15434, 'All of Them', 1367665, NULL, '/evMxZPC98YCtYEzsBfDuDNdZeUq.jpg', 'All of Them', 'When Cora stops by to check on her elderly mother, she discovers her in the bathtub, dressed for a party and refusing to budge. Familiar with her mother’s dramatic antics, Cora attempts to reason with her, only to find herself drawn into a deeper confrontation that reveals the vulnerabilities hidden beneath her mother’s irascible facade, forcing Cora to confront painful truths.', '/2QFUYnIECM1nDMyUUMS4y0I2exy.jpg', '2024-07-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
