INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15438, 'Oxalis', 636372, NULL, '/dhOdZWhyC1K4Rx6WvgRQNb60h2J.jpg', 'Oxalis', 'A father’s perverse strategy for identifying his son''s killer involves a nightmarish scientific experiment whose consequences are felt for generations to come.', '/xMWaMPYzNEnq2cRLrbos2HWsYVt.jpg', '2018-02-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15439, 'The Long Way Home', 361297, NULL, '/fbLZ7wQzzLgcXiVrvuIsTmtfZZk.jpg', '서부전선', 'Nam-bok, a middle-aged South Korean farmer is conscripted and assigned a mission to deliver a classified military document that may decide the fate of the war. After losing it while under attack from the enemy, he then faces a teenage North Korean soldier named Yeong-gwang who happens to acquire the secret document on his way to the North.', '/wT2TvLsB3n76TLZAOJv84nSsjHH.jpg', '2015-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15440, 'The Bros', 485442, NULL, '/wOpEQo2AXLShL8r5XJIK9MSkvGd.jpg', '부라더', 'Reunited in their hometown for their father''s funeral, two self-interested brothers meet a peculiar woman who shares a huge secret about their family.', '/ztpRiRGlPyaDd2vS5UjCpgcSoQX.jpg', '2017-11-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15441, 'Sleeping Beauty', 108008, NULL, '/fbZ2Sg8jyVQzakgVYAO53cUPg6p.jpg', '슬리핑 뷰티', 'Do-yeon, a 6th grade elementary school student, meets her cousin Sang-jun at her grandmother''s funeral. On the last day of the funeral Do-yeon and Sang-jun go into an empty classroom near the funeral. There they have their first sexual experience.  Lee Rae, a single women in her 50''s, lives with her father who suffers from Alzheimer''s. She raises ducks, but recently got rid of them because of Avian Influenza. Her father''s physical and mental health has also worsened. He even asks Lee Rae to touch him inappropriately.  17 year old Su-Jin was smuggled into the country by professional brokers. She was adopted into a family that lives in a countryside farm. On her first day at the farm she was raped by her stepfather. They also share the same bedroom. Su-Jin is continuously accosted by her stepfather. Su-jin sole source of comfort is the grandson, who sympathizes with Su-jJn and her plight. He is a victim of physical abuse from the stepfather. Su-Jin then becomes pregnant.', '/gELGtWCTEEr15GWthNA3BwNhDNT.jpg', '2008-10-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15442, 'The Weird Missing Case of Mr. J', 56606, NULL, '/13TeCpISt6ffvNytN93ft372yVH.jpg', '정승필 실종사건', 'On the day of the hundreds billion dollar contract deal just ahead, Jung suddenly disappears after he leaves for a convenient store. Inspector Kim who is desperate to get an exclusive crime case in the hope of drawing media attention finds out that Jung had many jealous colleagues and starts to investigate the case focusing on embezzlement and kidnapping. On the other hand, inspector Park finds out that Jung’s fiancee Mi-sun, a sales manager at the insurance company, has recently took out a life insurance policy on Jung’s life and points her as a suspect. The more investigation goes further the more case gets mysterious and things start to get out of control as a missing case develops to an assault, a kidnapping and finally to a murder.', '/1tZKsrm5dAkWgmdr8Rorc8NnGDi.jpg', '2009-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15443, 'Death Bell 2', 52414, NULL, '/qd6QhU1nHK2eSvYVKYvQrx5GVJR.jpg', '고사 두 번째 이야기: 교생실습', 'A class of students stays at school for a camp in an elite study group to finesse theirs and the school''s grades. Upon the first night, the swimming coach is found murdered. As the students try to figure out what happens, a voice informs them that if they don''t figure the murder out, students will begin dying in quick succession.', '/6E3XPxhorO0sLIa0jeX3zDD3PXI.jpg', '2010-07-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15444, 'Cry Cry', 510637, NULL, NULL, 'Cry Cry', 'Eunjung and Qri star as a pair of delinquent thieves who wind up in a huge mess when the bag they lifted from a club turns out to have been stuffed with drugs. A flashback sequence reveals that Qri originally was Jiyeon, but after a run-in with a couple of gangsters, they mauled her face and she ends up with plastic surgery leaving her looking like Qri, and unrecognizable to the man played by Cha Seung Won, whom she once loved.', '/6yW9kedWDMWhZ9IwQN9SnmuHgYI.jpg', '2011-11-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15445, 'T-ARA - Cry Cry & Lovey-Dovey', 1396235, NULL, '/fuut5c1k1jnJLMKSrsYWFyIkmMa.jpg', 'T-ARA - Cry Cry & Lovey-Dovey', NULL, '/mPOZt0G9CjHx5ZIab5hMafe17Ns.jpg', '2012-04-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15446, 'The Generals', 1618952, NULL, NULL, '보통사람들', 'Roh Tae-woo is a figure who publicly presents himself as an ''ordinary man'' while maneuvering behind the scenes beside dictator Chun Doo-hwan, who wields absolute authority. Surrounded by allies, rivals, and functionaries with their own agendas, Roh navigates a dense network of relationships in his bid to claim the top seat for himself.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15447, 'Attack of the Hollywood Clichés!', 877657, NULL, '/9xc1xRBUgSDSQeWQ1oCFFz8gISN.jpg', 'Attack of the Hollywood Clichés!', 'One-man armies, meet-cutes, casual strolls away from huge explosions — stars and industry insiders toast and roast these cinematic chestnuts and more.', '/fmI1oIAwXjfX8LcZYT8Rs2rZe2R.jpg', '2021-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
