INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15449, 'Inside Christopher Nolan''s Oppenheimer', 1152711, NULL, '/ollv1D9AWpRuZldA54k3kZ1M19f.jpg', 'Inside Christopher Nolan''s Oppenheimer', 'A look behind the scenes of Christopher Nolan''s film "Oppenheimer" about an American scientist and his role in the development of the atomic bomb.', '/p3mB2IFZAhFlBPwlNbv2ouzwxx0.jpg', '2023-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15450, 'The Falling', 294741, NULL, '/pvn9CqsQFIzK4j1rrgQcpV3T6UJ.jpg', 'The Falling', 'England, 1969. The fascinating Abbie and the troubled Lydia are great friends. After an unexpected tragedy occurs in the strict girls'' school they attend, a mysterious epidemic of fainting breaks out that threatens the mental sanity and beliefs of the tormented people involved, both teachers and students.', '/hjlU6vSDD5fdJenWhUKE5l672rb.jpg', '2015-04-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15451, 'The Pack', 1041577, NULL, NULL, 'The Pack', 'A group of documentarians brave the remote wilderness of Alaska in an effort to save a nearly extinct species of wolves. When the crew is brought back together at a prestigious awards ceremony, tensions flare as a deadly truth threatens to unravel their work. The team lived through the harsh elements of the wild but will a secret they share survive the night?', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
