INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15460, 'The Maid', 776864, NULL, NULL, 'The Maid', 'Set at the Regency Grand Hotel, where Molly the maid leaves every room perfect and pristine, while getting to know each guest’s dirty secrets. A Clue-like, locked-room whodunnit, The Maid explores Molly’s descent into the murderous underbelly of her gilded workplace, while telling a timely story about the strengths of our differences.', '/bDB0ahqUBJKH6F60A7ZbsaxoW1F.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
