INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15465, 'American Gigolo', 2768, NULL, '/tnbEY8Kn0mPyMfkxONYePWP5RUa.jpg', 'American Gigolo', 'Julian makes a lucrative living as an escort to older women in the Los Angeles area. He begins a relationship with Michelle, a local politician''s wife, without expecting any pay. One of his clients is murdered and Detective Sunday begins pumping him for details on his different clients, something he is reluctant to do considering the nature of his work. Julian begins to suspect he''s being framed. Meanwhile Michelle begins to fall in love with him.', '/igXGCwti23PHOjLKQX6eGIGzQiJ.jpg', '1980-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15466, 'Time Out', 418717, NULL, NULL, 'Time Out', 'Drama about a young Dane who has traveled to America to find the father he can hardly remember. In New Mexico he gets to know the daughter of a political-religious fanatic who runs a "survival school". The young Dane is interested in the girl and admits to school. Later, however, there will be a violent showdown with the fanatic. But was this man, in fact, his father?', '/wgmg8uw9df0ZmTqGF2mfSxtb76g.jpg', '1988-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
