INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15468, 'Cutter''s Way', 31593, NULL, '/g8wlcoLYzxOgukkLasp4G8NkpP5.jpg', 'Cutter''s Way', 'Alex Cutter is a boozy, belligerent and deeply cynical Vietnam veteran whose encounter with a landmine during the war has left him minus an eye, a leg and an arm. When his drifter playboy friend Richard Bone is falsely accused of murder, Cutter sets out for revenge in his own inimitable style.', '/7IhITThoRNFmJe3fwwx1q6h6k5L.jpg', '1981-03-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15469, 'Quintet', 45169, NULL, '/4gIrc2OGZJgloQadWdS427rPJ6Q.jpg', 'Quintet', 'During a future ice age, dying humanity occupies its remaining time by playing a board game called Quintet. For one small group, this obsession is not enough. They play the game with living pieces, and only the winner survives.', '/kjAzxXZzzoixPca518dwKRnJ0Km.jpg', '1979-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15470, 'A Wedding', 45695, NULL, '/jZDD1orkxLkTBllVqV8IboeDi3v.jpg', 'A Wedding', 'Muffin''s wedding to Dino Corelli is to be a big affair. Except the ageing priest isn''t too sure of the ceremony, only the families actually turn up as the Corelli Italian connection is suspect, security guards watch the gifts rather over-zealously, and Dino''s grandma expires in bed just as the reception starts. Could be quite an occasion.', '/u7cs5RMLbnA6a0u87ychiyHdxbV.jpg', '1978-08-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15471, 'Kærlighedens melodi', 47267, NULL, '/sWuytHyWwcR7ykAIZJGzfRCKXOq.jpg', 'Kærlighedens melodi', 'Nina and Frederik were the big names in international showbiz in the 1950s with their rousing calypso rhythms. That''s why "Kærlighedens Melodi" (The Melody of Love) was bound to be a hit when the young, beautiful couple teamed up with the legendary, wonderful "Satchmo," Louis Armstrong, from the world of jazz. Musical interests vary widely in the affluent neighborhood of Hellerup. At the Schmidt wine merchant''s, son Peter has only one interest: jazz. At the Supreme Court lawyer''s house next door, Mozart is on the program. But his daughters like both jazz and Peter! Even though their fathers are suing each other, the two young people still find each other. And Louis helps when he plays "The Formula for Love."', '/tYTTxYvvCKnv6NZNieq68IMKZPi.jpg', '1959-08-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15472, 'Jungle Warriors', 86509, NULL, '/sb9nrpUDDS7EXeEx5RIMFTuVrJb.jpg', 'Jungle Fever', 'A group of models fly into the jungle of some South American country to look for a photo location. Their plane is shot down and they are captured by a drug baron''s private army. At the same time, the Mafia''s representative arrive to negotiate future collaboration.', '/cLRpfSFOiQTqAgFlGa9wTArkKaL.jpg', '1984-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15473, 'Verdens rigeste pige', 56887, NULL, '/57RR0h5415RTIRoTV7GQhxq8Kum.jpg', 'Verdens rigeste pige', 'One dark night, a ravishing young girl flees from a convent boarding school in Switzerland. She is Lisa Hoffmann, daughter of a wealthy Danish-American oil magnate from Brazil, and she is running away with her sweetheart, the calypso singer Jacque. There is a huge uproar in newspapers around the world, and even more so when it turns out that the two young people are performing in cabarets around Europe''s capital cities.', '/rpAEvJLU2eKOnjCWVD2umT1EmH5.jpg', '1958-07-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15474, 'Cloud Dancer', 244829, NULL, '/eKC6Y9JEPgA4Lec10jQoJ0AIBZ9.jpg', 'Cloud Dancer', 'An aerobatic pilot comes to terms with his work, his photographer ex-lover and a brash newcomer.', '/4kyfSslhPPE6bh6kmFEVuuScr4b.jpg', '1980-05-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
