INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15477, 'Second Serve', 137445, NULL, NULL, 'Second Serve', 'Fact-based story about tennis pro Renee Richards, whose player status was challenged in 1976 when it was revealed that she was a trans woman. Flashback to 1964 before she was out as trans, a successful New York doctor with a great lifestyle, a flashy girl friend, and a secret life. Her psychiatrist mother refuses to deal with her and sends her to a colleague who diagnoses with a psychotic gender confusion, which he says can be unlearned. After a failed marriage and parenthood, she comes out as trans, with a new life in California.', '/8KsySdmTQL9dT5YrFFwGud1qtUA.jpg', '1986-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15478, 'O.C. and Stiggs', 27464, NULL, '/sN5ZbXF3Uq7RpVyDMJ84ev5xxhI.jpg', 'O.C. and Stiggs', 'O.C. and Stiggs aren''t your average unhappy teenagers. They not only despise their suburban surroundings, but they also plot against it. They seek revenge against the upper-middle-class Schwab family, who embody all they detest: excess.', '/68JG3eNZD6KrGF03Jg0WM0iPll8.jpg', '1987-07-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
