INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15480, 'F for Fake', 43003, NULL, '/kwwuAQpPvewf4voKVMN98KcXEPM.jpg', 'Vérités et Mensonges', 'Documents the lives of infamous fakers Elmyr de Hory and Clifford Irving. De Hory, who later committed suicide to avoid more prison time, made his name by selling forged works of art by painters like Picasso and Matisse. Irving was infamous for writing a fake autobiography of Howard Hughes. Welles moves between documentary and fiction as he examines the fundamental elements of fraud and the people who commit fraud at the expense of others.', '/fVeIDxS73CrosoeVOaefQuCUGZg.jpg', '1973-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
