INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15482, 'Dragnet', 10023, NULL, '/qbe8WKCS0FpsuIjGR928QK3jn6z.jpg', 'Dragnet', 'LAPD Sgt. Joe Friday -- the equally straight-laced nephew of the famous police sergeant of the same name -- is paired up with a young, freewheeling detective named Pep Streebeck. After investigating some strange robberies at the local zoo and the theft of a stockpile of pornographic magazines, they uncover cult activity in the heart of the city and are hot on the case to figure out who''s behind it all.', '/77H17YDeHoJCHebpfGF1rY3Dfof.jpg', '1987-06-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15483, 'Joe Versus the Volcano', 2565, NULL, '/qZ8t05qidOjhSSsaByxxpu6CKOH.jpg', 'Joe Versus the Volcano', 'Hypochondriac Joe Banks finds out he has six months to live, quits his dead end job, musters the courage to ask his co-worker out on a date, and is then hired to jump into a volcano by a mysterious visitor.', '/fwjMUuDZUxedfsUpVQKQN8cYfzB.jpg', '1990-03-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
