INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15485, 'Magnificent Desolation: Walking on the Moon', 30172, NULL, '/bDFx0wBA95uic77C1KT81pDzu51.jpg', 'Magnificent Desolation: Walking on the Moon', 'Twelve men who belong to one of the world''s most exclusive fraternities -- people who''ve walked on the surface of the moon -- are paid homage in this documentary. Using newsreel footage, rare NASA photographs, and digitally animated re-creations, Magnificent Desolation: Walking on the Moon examines the Apollo missions between 1969 and 1972 which put astronauts on the moon.', '/r37asMhJd2iX030bxFl4l66c6za.jpg', '2005-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15486, 'Radio Flyer', 20763, NULL, '/qupyOOes39BBlCtgvH77vgGVpA1.jpg', 'Radio Flyer', 'A father reminisces about his childhood when he and his younger brother moved to a new town with their mother, her new husband and their dog, Shane. When the younger brother is subjected to physical abuse at the hands of their brutal stepfather, Mike decides to convert their toy trolley, the "Radio Flyer", into a plane to fly him to safety.', '/nQjCKrwWYH6ES0HrnkLkPXnOEp0.jpg', '1992-02-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15487, 'Shooting War', 5707, NULL, NULL, 'Shooting War', 'A remarkable film that takes a special look at the first war to be truly reported and recorded by one of the more unsung heroes of World War II: the combat photographer. Through the unflinching eye of their camera''s lenses, these courageous soldiers continually risked their lives in their brave attempts to capture history.', '/81XtyZfL5WFPJXVLUUQP9PQP6Hl.jpg', '2000-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15488, 'A Night at the Academy Museum', 885058, NULL, NULL, 'A Night at the Academy Museum', 'Exclusive look at the movies'' 120-year history as well as an insight into the largest institution in the U.S. dedicated to the arts, sciences and artists of moviemaking.', '/2ANOppd40Q2qScqULGIduMwulSZ.jpg', '2021-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
