INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15505, 'The Extraordinary Voyage', 87061, NULL, '/3K4R0CZ81JhfpGsvJiRWysG1sD0.jpg', 'Le Voyage extraordinaire', 'An account of the extraordinary life of film pioneer Georges Méliès (1861-1938) and the amazing story of the copy in color of his masterpiece A Trip to the Moon (1902), unexpectedly found in Spain and restored thanks to the heroic efforts of a group of true cinema lovers.', '/37dXuUl9Jv6NXFihaLsWbiYVBdv.jpg', '2011-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15506, 'Horatio''s Drive: America''s First Road Trip', 121100, NULL, '/hWjRmjNx5vJQjipHomHeQ3iwXYi.jpg', 'Horatio''s Drive: America''s First Road Trip', 'In the spring of 1903, on a whim and a fifty-dollar bet, Dr. Horatio Nelson Jackson set off from San Francisco in a 20-horsepower Winton touring car hoping to become the first person to cross the United States in the new-fangled "horseless carriage." Most people doubted that the automobile had much of a future. Jackson''s trip would prove them wrong.', '/iglGxGhlo2ul2ciXXxDAHg3lv3x.jpg', '2003-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15507, 'Lost Moon: The Triumph of Apollo 13', 141498, NULL, NULL, 'Lost Moon: The Triumph of Apollo 13', 'The making of the motion picture "Apollo 13", as well as the story of the space mission it details. Featuring interviews with director Ron Howard, astronaut Jim Lovell, his wife Marilyn Lovell, producer Brian Grazer, executive producer Todd Hallowell, visual effects supervisor Robert Legato, lead digital compositor Mark Forker, astronauts Fred Haise and Dave Scott, Apollo 13 flight director Gerald Griffin, command module systems controller Sy Lieberglot, Apollo 13 flight dynamics officer Jerry Bostick, mission control director Gene Krantz, Tom Kelly of Grumman, NASA mission operations director Christopher Kraft, daughters Susan Lovell Williams and Margaret Haise, command systems module controller John Aaron, and actors Tom Hanks, Bill Paxton, Kevin Bacon, Gary Sinise, Kathleen Quinlan, and Ed Harris.', '/sLARsRcHS9x6kp85eJcw0BhMSt1.jpg', '1996-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15508, 'Inventing David Geffen', 127850, NULL, NULL, 'Inventing David Geffen', 'Notoriously press and camera-shy, David Geffen reveals himself for the first time in this unflinching portrait of a complex and compelling man. His far-reaching influence - as an agent and manager, record industry mogul, Hollywood and Broadway producer, and billionaire philanthropist - has helped shape American popular culture for the past four decades. This documentary offers a rare insight into the world of the man responsible for launching the early successes of Joni Mitchell, Tom Cruise, and Guns N’ Roses; co-founded DreamWorks; produced Cats and Dreamgirls;  and is one of the largest contributors to the fight against AIDS. (SBS AU)  Geffen narrates his unorthodox rise from working class Brooklyn boy to billionaire entertainment power broker in extensive interviews.  American Masters explores the highs and the lows in Geffen’s professional and personal life through more than 50 new interviews with his friends, colleagues and clients, as well as other media luminaries. (PBS)', '/eNJFdM0trGlwThfH6iLrg8QDLan.jpg', '2012-11-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15509, 'Partysaurus Rex', 130925, NULL, '/sRPMsLAygtI3GlZS8fLERQrzIvk.jpg', 'Partysaurus Rex', 'When Rex finds himself left behind in the bathroom, he puts his limbs to use by getting a bath going for a bunch of new toy friends.', '/7Y7NBliUme8KFqBh4MvQ1NOSDNW.jpg', '2012-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
