INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15511, 'Who Killed the Electric Car?', 13508, NULL, '/vb4BE2jdiUR6lCumcFGA0MZxEZE.jpg', 'Who Killed the Electric Car?', 'In 1996, electric cars began to appear on roads all over California. They were quiet and fast, produced no exhaust, and ran without gasoline... Ten years later, these cars were destroyed.', '/uMamC9o5zNU9wn8fyuAo2gUCMiD.jpg', '2006-08-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15512, 'Killing Lincoln', 170039, NULL, '/8t2wI3IZVWucJaULiYLlWTrQ6bS.jpg', 'Killing Lincoln', 'April 14, 1865. One gunshot. One assassin hell-bent on killing a tyrant, as he charged the 16th President of the United States. And in one moment, our nation was forever changed. This is the most dramatic and resonant crime in American history—the true story of the killing of Abraham Lincoln.', '/zqlOXMsJ0sSyForOe93BSfNW3Pi.jpg', '2013-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15513, 'Tom Hanks: The Nomad', 1128918, NULL, '/9ySIJ6EWmFs4rW4L9C9C4Xn85eC.jpg', 'Tom Hanks: The Nomad', 'From humble beginnings to an aspiring thespian to acting as some of the world''s most iconic and notable characters. He has picked up a reputation as ''America''s Nice Guy'', ''The Everyman'' and a nomad of the arts. But we all know him... as Tom Hanks.', '/dacx3E91IFXQ66fJLIhTVGSSxDw.jpg', '2023-05-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
