INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15515, 'Radioman', 103733, NULL, '/gJsVRVo4IHpZG7cSviGZJGXLBs5.jpg', 'Radioman', 'The extraordinary story of ''Radioman'',  a New York film set mascot who overcame homelessness and alcoholism to become a fixture of the New York film industry, with over 100 small parts to his name.', '/9nNitB9nKGaPusEgSx0UfLD0g6C.jpg', '2012-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15516, 'Toy Story of Terror!', 213121, NULL, '/hrjLiSuPPj4rPPn13Aj9sgAzw.jpg', 'Toy Story of Terror!', 'What starts out as a fun road trip for the Toy Story gang takes an unexpected turn for the worse when the trip detours to a roadside motel. After one of the toys goes missing, the others find themselves caught up in a mysterious sequence of events that must be solved before they all suffer the same fate in this Toy Story of Terror.', '/oPBEnNP4Fg4gv9c0KBhchmtoG4H.jpg', '2013-10-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15517, 'Through the Eyes of Forrest Gump', 237353, NULL, NULL, 'Through the Eyes of Forrest Gump', 'A look behind the scenes of Robert Zemeckis'' 1994 Oscar-winning film, ''Forrest Gump''.', '/dfjLE1HjdR9XhEpN04elCGUOJfA.jpg', '1994-07-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15518, 'Beyond Infinity: Buzz and the Journey to Lightyear', 979163, NULL, '/mBJ995JUssgh2hhm4JxNj8hyVVM.jpg', 'Beyond Infinity: Buzz and the Journey to Lightyear', 'Explore the evolution of Buzz Lightyear from toy to human in the making of Pixar’s Lightyear. Dive into the origin and cultural impact of everyone’s favorite Space Ranger, the art of designing a new “human Buzz,” and the challenges faced by the Lightyear crew along the way.', '/mnp0INIjyWt4AziWmTHgPk9IFoE.jpg', '2022-06-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15519, 'Halftime', 962192, NULL, '/sVUj3GZ6qWCyaVyu4PpMlyYQbxd.jpg', 'Halftime', 'Global superstar Jennifer Lopez reflects on her multifaceted career and the pressure of life in the spotlight in this intimate documentary.', '/jUVglxBw7KSkcVEhvfJs1eipPnk.jpg', '2022-06-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15520, 'Exclusively Elvis: A Special Edition of 20/20', 989517, NULL, '/tE8iAcc2k8nDM0fkMHpYekxag93.jpg', 'Exclusively Elvis: A Special Edition of 20/20', 'Inside the making of "Elvis," the cinematic drama starring Austin Butler as Elvis Presley and Tom Hanks as Presley''s manager, Col. Tom Parker, interviews with Presley''s surviving family, who reflect on the 45 years since his death, Baz Luhrmann.', '/jHz0l4H3fKrZO9L5CIQuDFjCb1T.jpg', '2022-06-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15521, 'Waking Sleeping Beauty', 47813, NULL, '/1x8qZSDzqFFth4ijstLEwzHLUOQ.jpg', 'Waking Sleeping Beauty', 'By the mid-1980s, the fabled animation studios of Walt Disney had fallen on hard times. The artists were polarized between newcomers hungry to innovate and old timers not yet ready to relinquish control. These conditions produced a series of box-office flops and pessimistic forecasts: maybe the best days of animation were over. Maybe the public didn''t care. Only a miracle or a magic spell could produce a happy ending. Waking Sleeping Beauty is no fairy tale. It''s the true story of how Disney regained its magic with a staggering output of hits - "Little Mermaid," "Beauty and the Beast ," "Aladdin," "The Lion King," and more - over a 10-year period.', '/hywGLq5tMOuKwXfOhYUzoqNNAnU.jpg', '2009-09-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15522, 'Who Needs Sleep?', 208238, NULL, NULL, 'Who Needs Sleep?', 'A documentary that highlights the deadly combination of sleep deprivation and long days of work, focusing on the American film industry.', '/auGiMgC8cI3LUj8TIoxmIbAdxbY.jpg', '2006-01-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15523, 'A Timeless Call', 1198548, NULL, NULL, 'A Timeless Call', 'A short tribute to American military veterans, made for the 2008 Democratic National Convention. It honors the service and sacrifice of U.S. troops and their families, and premiered on August 27, 2008, at the Pepsi Center in Denver, Colorado.', '/eSIJDlKvMt1OllOCBqfZ0bmRqqQ.jpg', '2008-08-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15524, 'The Pixar Story', 15302, NULL, '/jbdvzJvNu0swWURJp71Fxwd54Fm.jpg', 'The Pixar Story', 'A look at the first years of Pixar Animation Studios - from the success of "Toy Story" and Pixar''s promotion of talented people, to the building of its East Bay campus, the company''s relationship with Disney, and its remarkable initial string of eight hits. The contributions of John Lasseter, Ed Catmull and Steve Jobs are profiled. The decline of two-dimensional animation is chronicled as three-dimensional animation rises. Hard work and creativity seem to share the screen in equal proportions.', '/vhK51wJybwZTRCPVUOkGpSI4auN.jpg', '2007-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15525, 'Die Tom Hanks Story', 1116589, NULL, NULL, 'Die Tom Hanks Story', NULL, NULL, '2021-07-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15526, 'Ithaca', 305642, NULL, '/pY9vGDtO6PKMZHvth3FCQkncgUW.jpg', 'Ithaca', 'In a small town in California''s San Joaquin Valley, 14-year-old Homer Macauley is determined to be the best and fastest bicycle telegraph messenger anyone has ever seen. His older brother has gone to war, leaving Homer to look after his widowed mother, his older sister and his 4-year-old brother, Ulysses. And so it is that as spring turns to summer, 1942, Homer Macauley delivers messages of love, hope, pain... and death... to the good people of Ithaca. And Homer Macauley will grapple with one message that will change him forever - from a boy into a man. Based on Pulitzer Prize-winning author William Saroyan''s 1943 novel, The Human Comedy, ITHACA is the quintessential wartime tale of the Home Front. It is a coming-of-age story about the exuberance of youth, the sweetness of life, the sting of death and the modesty and sheer goodness that lives in each and every one of us.', '/oCyNJbfZ7kQVhRyOlNcJhlsizLb.jpg', '2015-10-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15527, 'Disney 100: A Century of Dreams – A Special Edition of 20/20', 1221257, NULL, '/9iFlqEIa044ZMnjZhd1fvW8fb9k.jpg', 'Disney 100: A Century of Dreams – A Special Edition of 20/20', 'Commemorating the 100th anniversary of the entertainment company with interviews, rare footage and photos, and never-before-heard stories from those who built the Disney legend; a look inside Disney''s newest attraction.', '/gZupK8CHNte7I1OPDSjreK5MhcW.jpg', '2023-12-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15528, 'All In', 298859, NULL, NULL, 'All In', 'A behind-the-scenes look at the team and event that made history.  The DVD chronicles the Rider''s incredible run to the 101st Grey Cup Championship game and their historic victory on home soil.  This 70 minute feature takes you behind the scenes of the Roughrider''s 2013 season, the Grey Cup Championship Game, the Grey Cup Festival and the aftermath of one of the greatest moments in Roughrider history.  Insightful interviews get you up close and personal with General Manager Brendan Taman, Head Coach Corey Chamblin, broadcasters, event crews and the players that made it all happen.', NULL, '2014-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15529, 'Misery Loves Comedy', 316067, NULL, '/dJTUyaWhtNN0HTshnFN4VKaFxLt.jpg', 'Misery Loves Comedy', 'Do you have to be miserable to be funny? More than sixty comedians—including stand-ups, writers, actors, and directors from the US, Canada, and abroad—take on this question, sharing anecdotes and insights with lively enthusiasm.', '/wjYla0vnZ3HtzAS6JxINNrZ3wY5.jpg', '2015-01-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
