INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15539, 'Live 8', 42348, NULL, '/gm2BF7nEaypNTz8lXXAGgXaOn0S.jpg', 'Live 8', 'On 2 July 2005 an estimated 3 billion people came together in the fight against extreme poverty. LIVE 8 - 10 concerts featuring over 1000 musicians from across the globe - asked people not for their money, but for their voice.', '/joFzIENnJHDLesiktLETN3VNutO.jpg', '2005-11-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
