INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15543, 'Boatlift', 374164, NULL, '/qR4S4CKCAG8z1JlsBJx2yf0fPEP.jpg', 'Boatlift', 'From the midst of 9/11, one of the darkest moments in American history, comes this inspiring and relatively unknown story. When the twin towers fell, hundreds of thousands of people ran to the water''s edge. They soon realized that Manhattan is, indeed, an island. And that they were trapped. Within moments, an armada of every vessel that could get to the city''s seawall spontaneously organized. Dashing into the teeth of danger, hundreds of boats pulled together and, without any formal planning, military or otherwise, they pulled off an ad-hoc sea evacuation that became the largest in history. Their story of courage and resolve reminds us of the powerful spirit that rose among us, on that fateful day. Narrated by Tom Hanks. Directed by Eddie Rosenstein.', '/CL5DxOFJ0hwW2DWTVlq2pJD90D.jpg', '2011-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15544, 'Mike Nichols: An American Master', 380994, NULL, NULL, 'Mike Nichols: An American Master', 'With charm and wit, Nichols discusses his life and 50-year career as a performer and director.', '/wOMSIJeIt3LunhwSeSF7LO2JuPe.jpg', '2016-01-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
