INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15547, 'Defying the Nazis: The Sharps'' War', 252451, NULL, '/n77OxYu5POTaHiCKxkdAX9ko5zZ.jpg', 'Defying the Nazis: The Sharps'' War', 'Join an American couple’s courageous mission in 1939 to help refugees escape Nazi-occupied Europe. Over the course of two years, the pair will risk their lives so that hundreds can live in freedom.', '/cnMQERaTKOZZTwT4YmbPd52qzId.jpg', '2016-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
