INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15549, 'And the Oscar Goes To...', 253639, NULL, '/guSb6lfH0lLYJQ9QSQn60jeBMKz.jpg', 'And the Oscar Goes To...', 'The story of the gold-plated statuette that became the film industry''s most coveted prize, AND THE OSCAR GOES TO... traces the history of the Academy itself, which began in 1927 when Louis B. Mayer, then head of MGM, led other prominent members of the industry in forming this professional honorary organization. Two years later the Academy began bestowing awards, which were nicknamed "Oscar," and quickly came to represent the pinnacle of cinematic achievement.', '/rRL4xf3Z6kgLUyb5vbGKErlzP4h.jpg', '2014-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15550, 'The Harryhausen Chronicles', 43714, NULL, '/ljQmSctjYjGOvFWioPHKd2zN6mK.jpg', 'The Harryhausen Chronicles', 'As an actor, director and producer, Ray Harryhausen has been a vibrant figure in Hollywood, working on everything from family films to mind-bending sci-fi. But his true genius lay in the creation of special effects for movies such as Mighty Joe Young and It Came from Outer Space. Narrated by Leonard Nimoy and featuring appearances by George Lucas and Ray Bradbury, this film documents Harryhausen''s remarkable life''s work.', '/xP4CR20quD3iNi0qKxyhpjs0YNr.jpg', '1997-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
