INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15552, 'Saturday Night Live: 15th Anniversary', 454330, NULL, NULL, 'Saturday Night Live: 15th Anniversary', 'A TV special celebrating the 15th anniversary of Saturday Night Live. Before a celebrity audience, many of the former cast members and guest hosts return to perform their signature monologues and present a look back at some of the best comedy skits and musical numbers of the past 15 years.', '/m7HxQu1CC82mYCTiabOdOja91Iw.jpg', '1989-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15553, 'Walking the Mile: The Making of The Green Mile', 456703, NULL, '/z1uRO9B7Gqp9ZELapLdX80Ivtwv.jpg', 'Walking the Mile: The Making of The Green Mile', 'Frank Darabont explains how this new project was introduced thru a phone call from Stephen King as "another prison tale" if he was interested to make it, the answer was not, King expose his concept idea in few words, however Frank asking to Stephen send the script to him firstly, when the first tale was finished and sent to Darabont, after reading such odd story, asking for more, so King replied "You must wait as anybody else", receiving later all other tales Frank wrote a screenplay on 8 weeks, so come up "the Green Mile"', NULL, '2000-06-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15554, 'The Story Behind ''Toy Story''', 464729, NULL, '/8jELoQY7JosQaGOtLmlVHJzUzeq.jpg', 'The Story Behind ''Toy Story''', 'The documentary short of Toy Story of why and how the feature length blockbuster sleeper movie became a success and helps to boost Pixar''s popularity of making one of the few animation movie production companies in the world today, especially in North America.', '/ul7sy0m9GPifIgMaEXX8ivENqHP.jpg', '1996-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15555, 'The David S. Pumpkins Halloween Special', 478639, NULL, NULL, 'The David S. Pumpkins Halloween Special', 'Set in a small suburban town on All Hallows'' Eve, the special centers on David Pumpkins and his skeleton sidekicks who show a young boy and his sister the true meaning of Halloween, answering none of their questions along the way.', '/3uoVw6eGWi3ek9c0DYP4r0O6AkX.jpg', '2017-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15556, 'Can''t Buy Me Lunch: Another Look at The Rutles', 32694, NULL, NULL, 'Can''t Buy Me Lunch: Another Look at The Rutles', 'Twenty-three years after the release of the original Beatles mockumentary, ''The Rutles: All You Need Is Cash'', famous artists, actors and musicians speak out on how The Rutles influenced them.', '/maUbhufh8qw44vg2rYnQcozpd2l.jpg', '2003-08-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15557, 'Catch Me If You Can: Behind the Camera', 459682, NULL, NULL, 'Catch Me If You Can: Behind the Camera', 'A behind-the-scenes look at the making of Stephen Spielberg''s "Catch Me If You Can."', '/dW0ufGS32gimuicgzvf7P0YTSHf.jpg', '2003-05-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15558, 'Rebels of Oakland: The A''s, The Raiders, The ''70s', 224355, NULL, NULL, 'Rebels of Oakland: The A''s, The Raiders, The ''70s', '"As soon as you hear the title to this new one, you know exactly what it''s about and why it''s likely to be good, especially if you were a sports fan growing up in the 1970s. Even to good boys all the way across the country in New Hampshire, the authority-flouting baseball A''s and football Raiders were magical. Not only did they win championships, they did it amid clubhouse brawls, feuds with an owner and a general embrace of the 1960s aesthetic.  Filmmakers Rick Bernstein and Ross Greenburg tell the stories of these turbulent, talented teams and show how they perfectly fit their city. Oakland was blue collar and home to hardcore hard-core 1960s rebellion, exemplified by the Black Panthers. Oakland, especially, was not San Francisco, the effete, world-class city across the bay."', '/rc9ovrusS56WpuR79BaYksmEEhq.jpg', '2003-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15559, 'The Universal Story', 471198, NULL, NULL, 'The Universal Story', 'Richard Dreyfuss hosts a celebration of the 80 year history of Universal Studios. Founded as IMP by Carl Leammle to oppose Edison''s Motion Picture Tust, it soon grew under the leadership of 21 year old production head Irving Thalberg with classic silents from artists like John Ford, Erich Von Stroheim, and Lon Chaney and prospered further in the Sound Era under the leadership of Carl Leammle Jr. with such classics as "All Quiet on The Western Front," "Showboat," and the studio''s signature monster franchises, "Frankenstein" and "Dracula."', '/QmEOPgTZ9hELnWSmfzelaqAriU.jpg', '1996-04-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15560, 'The Mayo Clinic', 550600, NULL, '/zOpB3aAL935XXxvdA1wjUuHFn5C.jpg', 'The Mayo Clinic', 'The Mayo Clinic tells the story of a unique medical institution that has been called a "Medical Mecca," the "Supreme Court of Medicine," and the "place for hope where there is no hope." The Mayo Clinic began in 1883 as an unlikely partnership between the Sisters of Saint Francis and a country doctor named William Worrall Mayo after a devastating tornado in rural Minnesota. Since then, it has grown into an organization that treats more than a million patients a year from all 50 states and 150 countries. Dr. Mayo had a simple philosophy he imparted to his sons Will and Charlie: "the needs of the patient come first." They wouldn''t treat diseases...they would treat people. In a world where healthcare delivery is typically fragmented among individual specialties, the Mayo Clinic practices a multi-specialty, team-based approach that has, from its beginnings, created a culture that thrives on collaboration.', '/r5Axef30grCmdyN3UR8eftSB4fo.jpg', '2018-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15561, 'Quincy', 504561, NULL, '/8McBKWoQOQZfeIGQl23g0TJ6jto.jpg', 'Quincy', 'An intimate look into the life of icon Quincy Jones. A unique force in music and popular culture for 70 years, Jones has transcended racial and cultural boundaries; his story is inextricably woven into the fabric of America.  Jones came to prominence in the 1950s as a jazz arranger and conductor before working on pop music and film scores. He moved easily between musical genres, producing major pop hits of the early 1960s  and serving as an arranger and conductor for several collaborations in the same time period.', '/yYtY9CRLyz4dXqTOiimdMF7Nt4e.jpg', '2018-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15562, 'The Last Mile', 567649, NULL, '/mU7A8sM6TFC5MuFxl2i0rLbEHLk.jpg', 'The Last Mile', 'It''s been 25 years since “Philadelphia” premiered, and since then, we''ve come a long way in the fight to end AIDS. In partnership with Coca Cola and RED, "The Last Mile" explores how far we''ve come.', '/fp3mOjFJ55HhHVULBMs5oqtzWk2.jpg', '2018-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15563, 'Beyond All Boundaries', 574379, NULL, '/6NXM452S865MhGx3WiNIYyc2bLa.jpg', 'Beyond All Boundaries', 'A visual, 4-D experience of the battles of World War II featuring stories, archival footage and advanced special effects.', '/8TcXwhS8HbXLXC1hadEvesf8wwb.jpg', '2009-11-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15564, 'The Dave Clark Five and Beyond: Glad All Over', 325450, NULL, '/xUgWf8zeBbirS9YVIFDY3Dp6VEk.jpg', 'The Dave Clark Five and Beyond: Glad All Over', 'The Dave Clark Five started the rock n roll British invasion that changed the world, having already knocked The Beatles out of the #1 position in the UK. Watch newly-filmed interviews with Tom Hanks, Paul McCartney, Elton John, Bruce Springsteen, Stevie Wonder, Dionne Warwick and many more, as they share their memories of how the music of the 60s and the cultural revolution of 1964 changed their lives forever. Bonus disc includes 2 hours of extra interview scenes and rare archival footage, including never-before-seen star performances and alternate performances from The DC5 ! Featuring 4 hours of star-studded performances in total!', '/jNTueLKnIavVd1hUNO2c55wnWfF.jpg', '2014-05-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15565, 'The 25th Anniversary Rock and Roll Hall of Fame Concerts', 31107, NULL, '/hFeW14oNRU0hKiILAUKZVrilFBg.jpg', 'The 25th Anniversary Rock and Roll Hall of Fame Concerts', 'On October 29th and 30th, 2009, rock ''n'' roll royalty held court at Madison Square Garden for what have been called ''the best concerts ever,'' and ''where rock ''n'' roll history was made.'' The concerts featured a who''s who of rock ''n'' roll from the ''50s to the ''90s and included artists performing together in unprecedented combinations that will most likely never be witnessed again. ''The 25th Anniversary Rock and Roll Hall of Fame Anniversary Concerts'' included sets by Crosby, Stills & Nash; Stevie Wonder; Paul Simon; Simon & Garfunkel; Aretha Franklin; Metallica; U2; Jeff Beck and Bruce Springsteen & the E-Street Band. Joining this iconic line up on stage were special guests including: Jerry Lee Lewis, Bonnie Raitt, Jackson Browne, Smokey Robinson, B.B. King, Annie Lennox, Lou Reed, John Fogerty, Mick Jagger, Fergie and others. A 4-hour special of the concerts aired on HBO to high ratings, and was seen by tens of millions. Now this historic event is available on DVD.', '/yvVW8X56vjGWEP7zLJyLWK19mk8.jpg', '2009-11-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15566, 'People Like Us: Making ''Philadelphia''', 606078, NULL, NULL, 'People Like Us: Making ''Philadelphia''', '10 years after the release of "Philadelphia," director Jonathan Demme, Tom Hanks, Denzel Washington and others discuss about the making of that film and it''s important legacy through the years of being the first mainstream Hollywood film about dealing with the topic of Aids, revealing its impact on culture and society. Cast and crew talk about the inception of the project, the making of it and curious stories about one of the greatest hits of 1993.', '/f729hoffrFAOuTkhymgi0b4hszW.jpg', '2004-07-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15567, 'Vault of Horror I', 473544, NULL, NULL, 'Vault of Horror I', 'A compilation of three episodes from the Tales from the Crypt series ("Carrion Death", "None but the lonely heart" and "Abra Cadaver") with some famous cast and directors.', '/jrCnvkXgEe5xH7pVg6eFK05efuZ.jpg', '1994-07-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15568, 'Beyond Boundaries: The Harvey Weinstein Scandal', 558912, NULL, '/bFzBbSphXMpv3DH01Vdg9IKs5N4.jpg', 'Beyond Boundaries: The Harvey Weinstein Scandal', 'Examine the rise and fall of Hollywood media mogul Harvey Weinstein following the scandal in 2017. Learn from exclusive interviews with those who knew him in the industry, and a discussion of the start of the #MeToo movement.', '/3RttUhiOHu1qFkmvYPdJOo1PJk5.jpg', '2018-08-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15569, 'Making a ''Splash''', 698229, NULL, NULL, 'Making a ''Splash''', 'Retrospective documentary on the making of the hit comedy Splash (1984).', '/tqTBRER4JqHu4mjCvPA9VEcUnFP.jpg', '2004-03-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15570, 'We Are One: The Obama Inaugural Celebration at the Lincoln Memorial', 705899, NULL, '/leUVJPZbA8rZIkcn33y46LGMPv2.jpg', 'We Are One: The Obama Inaugural Celebration at the Lincoln Memorial', 'A public celebration of the inauguration of Barack Obama as the 44th President of the United States of America at the Lincoln Memorial and the National Mall in Washington D.C., on January 18, 2009.', '/aqFHftRn2gRe5psczpv37J0Aqsi.jpg', '2009-01-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15571, 'Pennis from Heaven', 712062, NULL, '/6rmc43jaxcztIGEeAq2zBIQGQ8L.jpg', 'Pennis from Heaven', 'Wherever he goes, Dennis Pennis (Paul Kaye) leaves a trail of embarrassment in his wake. From London to the Venice Film Festival and on to Hollywood, no-one is spared, no star is too big to escape verbal abuse. Victims include Steve Martin, Pierce Brosnan, Don Johnson, Jim Carrey, Richard Gere, Sharon Stone, Sandra Bullock, Charlie Sheen, Cindy Crawford, Demi Moore and Arnold Schwarzennegger. If you''re a star, beware! Pennis is out to get you. This release includes previously released Very Important Pennis, Anyone For Pennis? and RIP - Too Rude to Live.', '/c1HiJwCJy8OMdrJCmzSD8Wiz89c.jpg', '2005-03-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15572, 'The Road We''ve Traveled', 720203, NULL, NULL, 'The Road We''ve Traveled', 'A short documentary on the first term of President Barack Obama''s administration.', '/bgkB00OM00xOQLiCwqVYMwM2JIg.jpg', '2012-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15573, 'Saturday Night Live: 25th Anniversary Special', 269535, NULL, '/cNlPJE40kkEOmD28lKE98NMXEGa.jpg', 'Saturday Night Live: 25th Anniversary Special', 'A TV special celebrating the 25th anniversary of Saturday Night Live. Before a celebrity audience, many of the former cast members and guest hosts return to perform their signature monologues and present a look back at some of the best comedy skits and musical numbers of the past two and a half decades.', '/iloU9d27LBYLH5AaWtkSsSoqFtC.jpg', '1999-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15574, 'Celebrating America', 785930, NULL, '/t4OhMwOgQnBPmT9zYSytYJGeFCN.jpg', 'Celebrating America', 'Inauguration Day special showcasing the American people’s resilience, heroism, and unified commitment to coming together as a nation to heal and rebuild.', '/bor7aoKx0TvaRjqiGcal4Traaj.jpg', '2021-01-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
