INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15576, 'Rescued from the Closet', 838219, NULL, NULL, 'Rescued from the Closet', 'Rescued from the Closet is a 2001 documentary consisting of interviews originally recorded for the 1995 film The Celluloid Closet. It explores the history and impact of LGBT representation in cinema, providing insights into the portrayal and evolution of LGBT characters and themes within the film industry.', '/h3PZfCQ0t91plYx8p63ugpRxd5o.jpg', '2001-05-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15577, 'Concert for George', 28236, NULL, '/lTTOed6NeyEaMzgItVWnNrF2yFN.jpg', 'Concert for George', 'As a memorial to George Harrison on the first anniversary of his passing, The Concert for George was held at the Royal Albert Hall in London on 29 November 2002 . Organized by Harrison''s widow, Olivia, and son, Dhani, and arranged under the musical direction of Eric Clapton and Jeff Lynne. A benefit for Harrison''s Material World Charitable Foundation, the all-star concert took place on the day of the first anniversary of his death. Proceeds from the film also went to the Material World Charitable Foundation. The film was shot using discreet cameras from over twelve locations.', '/mpz7cVFuwC9QnNMb2SjZOqzCJUx.jpg', '2003-10-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15578, 'The Making of ''Band of Brothers''', 1335757, NULL, '/1gfpdg2H3m5Ju7f8oePNdLeXt58.jpg', 'The Making of ''Band of Brothers''', 'Interviews made of the various actors and cast members that provide the knowledge and production skills and sets required to make the film a success.', '/u9C6q5DXJRxmkEt81FaRVuhgzfF.jpg', '2001-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15579, 'How to Rig an Election: The Racist History of the 1876 Presidential Contest', 1098569, NULL, NULL, 'How to Rig an Election: The Racist History of the 1876 Presidential Contest', 'The most hotly contested presidential election in U.S. history did not take place in 2020, or even 2000. It took place 11 years after the Civil War and ended in a backroom deal with devastating consequences still felt to this day.', '/8ztdnmwdrjYJXglAwaQJqByTkiB.jpg', '2023-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15580, 'Passport to the Universe', 1439830, NULL, NULL, 'Passport to the Universe', 'The breathtaking Passport to the Universe reveals the wonders of our universe in a way never before possible in a planetarium.  The presentation treats the audiences to realistic close-up views of starfields and planets, taking them on an exhilarating flight through a virtual re-creation of our universe, into the Orion Nebula, out of our Galaxy, and deep into intergalactic space.  Narrated by Tom Hanks.', '/nKOphUkverrWyWb0JRmvl6LK57M.jpg', '2005-04-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15581, 'Making That Thing You Do', 1453188, NULL, NULL, 'Making That Thing You Do', 'Behind the scenes of That Thing You Do!', '/3vM9OQKTBrrfOMFdAUFZzBAEcVO.jpg', '2007-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15582, 'Greyhound 2', 1051002, NULL, NULL, 'Greyhound 2', 'Captain Krause and the Greyhound crew, from the beaches of Normandy to the Pacific Ocean, help turn the tide of the war.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15583, 'Clint Eastwood : la légende', 1486770, NULL, '/oa9Rqm0yrmMASI0IEJAlk2F4DD8.jpg', 'Clint Eastwood : la légende', 'Clint Eastwood made his mark on cinema by abandoning violent action films to turn his attention, behind the camera, to more substantial productions that were praised by critics.', NULL, '2025-05-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15584, 'Bigger Than Life - The Making of Elvis', 1507351, NULL, '/hjFdTL33rUMXsLwZLuj5g2gfQLw.jpg', 'Bigger Than Life - The Making of Elvis', 'Documentary about the making of the 2022 biopic Elvis', '/bpIkfA6OpLxHZ614xC5ltpaKgoq.jpg', '2022-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15585, 'A Case of the Cold War: Bridge of Spies', 1374644, NULL, NULL, 'A Case of the Cold War: Bridge of Spies', 'The piece opens with Steven Spielberg''s family history with the real life events and follows with cast and crew examining the politics and history of the time, the screenplay''s inspirations, espionage and intelligence gathering of the era, the story''s relevance today, character attributes, and the Francis Gary Powers and Frederic Pryor stories and their depictions in the film.', '/hNfTgfjw50Ym4Z94JDQgJirduNS.jpg', '2016-02-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15586, 'John Candy: I Like Me', 1492608, NULL, '/rSuqSerMzqMtgX7fX50Hl55ficF.jpg', 'John Candy: I Like Me', 'Those who knew iconic funnyman John Candy best share his story, in their own words, through never-before-seen archival footage, imagery, and interviews.', '/mNEJdx9WSXeyMmkuQfTeY4zouNx.jpg', '2025-09-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
