INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15589, 'Saturday Night Live in the ''90s: Pop Culture Nation', 337559, NULL, NULL, 'Saturday Night Live in the ''90s: Pop Culture Nation', 'A retrospective of "Saturday Night Live" during the 1990''s. Includes interviews with the cast and crew as well as hosts. Features memorable sketches and behind the scenes dynamics.', '/tpbl95fpMgADYda7OHIXwKVNWvj.jpg', '2007-05-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15590, 'What is an Ocean… Reconnecting the Cast and Crew of Cloud Atlas', 1601090, NULL, NULL, 'What is an Ocean… Reconnecting the Cast and Crew of Cloud Atlas', 'A unique feature-length retrospective documentary bringing together the directors, author David Mitchell, and key cast and crew - including Tom Hanks, Hugh Grant, and Susan Sarandon - to share new reflections and untold stories from the making of Cloud Atlas. The film celebrates the artistry, collaboration, and enduring impact of the Wachowskis and Tom Tykwer''s visionary production.', '/tw7aQ17lYfZ7Vmi7lNaWIPW0V9F.jpg', '2025-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15591, 'Lincoln in the Bardo', 1599454, NULL, NULL, 'Lincoln in the Bardo', 'In 1862, a grieving Abraham Lincoln visits his son Willie''s grave, sparking a supernatural moment where ghosts in the "bardo" must help the boy move on before he is trapped forever.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:51', 0);
