INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15617, 'Bereavement', 55890, NULL, '/fmPfRSDkdegZ6HHN9yKkHCPwMLQ.jpg', 'Bereavement', 'In 1989, six year old Martin Bristoll was kidnapped from his backyard swing in Minersville Pennsylvania. Graham Sutter, a psychotic recluse, kept Martin imprisoned on his derelict pig farm, forcing him to witness and participate in unspeakable horrors. Chosen at random, his victim''s screams were drowned out by the rural countryside. For five years, Martin''s whereabouts have remained a mystery, until 17 year old Allison Miller comes to live with her Uncle, Jonathan. While exploring her new surroundings, Allison discovers things aren''t quite right at the farmhouse down the road. Her curiosity disturbs a hornet''s nest of evil and despair that once torn open, can never be closed.', '/5Zd0NzvT3x8EhuE5lYMJz5ShcH1.jpg', '2010-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
