INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15620, 'I Wish You All the Best', 1022888, NULL, '/q2w64nBl0F8oBwWGtbcKy9u9JIw.jpg', 'I Wish You All the Best', 'A non-binary teen is kicked out of their North Carolina home after coming out to their ultra-religious parents. As a result, they move in with their estranged sister and her husband. Though the two are welcoming, they continue to struggle with anxiety further exacerbated by their parents'' rejection. As such, they try to keep a low profile at school. However, after they meet a proudly bisexual classmate, their life begins to look a little more hopeful.', '/zJAxxNoyzwFC9Q8OLMj1r2zlcDc.jpg', '2025-11-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
