INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15623, 'Couples Weekend', 1257868, NULL, '/vzAcTHSYy9cMwuZ73OrxwbqX5bB.jpg', 'Couples Weekend', 'What happens when a tree falls in the woods and someone does hear it? Two couples are forced to deal with such a question — and their lives in general — when a New Year''s Eve trip to the woods unearths simmering feelings and the secrets they carry threaten to break their seemingly perfect relationships.', '/69Gf2J4XwskFHbx3ETIarQFazIx.jpg', '2026-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15624, 'We Have Always Lived in the Castle', 411144, NULL, '/wm5QhKgitszib5KjaWeNK6yAgoj.jpg', 'We Have Always Lived in the Castle', 'In Shirleyville, Vermont, during the sixties, sisters Merricat and Constance, along with their ailing uncle Julian, confined to a wheelchair, live isolated in a big mansion located on the hill overlooking the town, tormented by the memories of a family tragedy occurred six years ago. The arrival of cousin Charles will threaten the fragile equilibrium of their minds, haunted by madness, fear and superstition.', '/ejp1MQSlekBjH3bBJrBlWItpmQW.jpg', '2019-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
