INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15629, 'Can You Keep a Secret?', 537739, NULL, '/mpHUz9wz3C5MNWcVVHPYOJ6bbqi.jpg', 'Can You Keep a Secret?', 'Emma Corrigan, a girl with a few secrets, thinks she’s about to die on a turbulent plane ride. She spills them all to the handsome stranger sitting next to her. At least, she thought he was a stranger. But then, her company’s young and elusive CEO, arrives at the office. It’s him. And he knows every single humiliating detail about her.', '/uNWk5HZfVBHpARcV1z9cwUAbtpF.jpg', '2019-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15630, 'Lost Transmissions', 535987, NULL, '/SFWJpeYVbex65zEC4Wol5zrXRu.jpg', 'Lost Transmissions', 'When an acclaimed music producer goes off his medication for schizophrenia, his friends chase him though the LA music scene to help commit him to a psychiatric hospital, revealing the troubling inadequacies of the mental health care system.', '/8pqvbXqkruyyt1u4TWUtxZw59et.jpg', '2020-03-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15631, 'We Summon the Darkness', 546724, NULL, '/9ZSAFg56HlCsn6OrOhLjxOAzprc.jpg', 'We Summon the Darkness', 'Three best friends attending a heavy-metal show cross paths with sadistic killers after they travel to a secluded country home for an after party.', '/g5hx5kepkzUFm1czj1MZse1klX4.jpg', '2020-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15632, 'Airborne', 603624, NULL, NULL, 'Airborne', 'After a deadly disease breaks out onboard a Sydney-bound flight from Los Angeles, a flight attendant struggling with the recent death of her mother is forced to summon inner strength she never knew existed.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
