INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15634, 'Die in a Gunfight', 481879, NULL, '/zJIyrAt24I48Kz26ffu8dFpB6UQ.jpg', 'Die in a Gunfight', 'Mary and Ben are the star-crossed black sheep of two powerful families engaged in a centuries-long feud. When the pair reignite a romance after many years apart, their forbidden love draws a motley assortment of schemers and killers into their orbit, and as fists and bullets fly, it becomes clear that violent delights will have violent ends.', '/byXLJZq5vfveYdAWaC4uMtojsWj.jpg', '2021-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15635, 'Faces Without Eyes', 626884, NULL, NULL, 'Faces Without Eyes', 'Doc and Iris''s date night takes a turn for the worse when Doc''s disturbing plans for Iris emerge.', '/98E5HLsTxm4gedJ2g8BFct1SFBM.jpg', '2015-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15636, '1 Night in San Diego', 664051, NULL, '/fncQYY6Et7CCIjCClOz82CPvCrv.jpg', '1 Night in San Diego', 'Two life long friends, Hannah, a former reality starlet, and her conscious cuddling best friend, Brooklyn, road trip to San Diego to meet a high school crush and attend Comic Con. When things don''t go as planned, their trip turns into a night of chaos, debauchery, and ultimately tests the deepest bonds of their friendship.', '/mnvFf0u6FC5MmYeKSc9TTKOcuTz.jpg', '2020-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15637, 'Superman: Man of Tomorrow', 618354, NULL, '/bazlsLkNuhy3IuhviepqvlMm2hV.jpg', 'Superman: Man of Tomorrow', 'It’s the dawn of a new age of heroes, and Metropolis has just met its first. But as Daily Planet intern Clark Kent – working alongside reporter Lois Lane – secretly wields his alien powers of flight, super-strength and x-ray vision in the battle for good, there’s even greater trouble on the horizon.', '/n9GtiJiBETVFayQy7YnVdF9AucU.jpg', '2020-08-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15638, 'Songbird', 721625, NULL, '/aqm0i13UOmow0K30gB1hrNYpJca.jpg', 'Songbird', 'During a pandemic lockdown, Nico, a young man with rare immunity, must overcome martial law, murderous vigilantes and a powerful family to reunite with his love, Sara.', '/pm7pstYup0ZHpImjT0k6YyxGVkX.jpg', '2020-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15639, 'The Hottest State', 18586, NULL, '/nAoDRZ7ESMhfVmQW3VTtISWnmFX.jpg', 'The Hottest State', 'A young actor from Texas tries to make it in New York while struggling in his relationship with a beautiful singer/songwriter.', '/pJvnZRzOaK0aevbLgESfmI05mSu.jpg', '2007-06-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15640, 'Hershey', 1461490, NULL, NULL, 'Hershey', 'The story behind one of the most famous chocolate companies in the world.', '/4iuKFMlFPCjIvL4j0GFwPZvpvfR.jpg', '2026-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15641, 'Inground', 1537430, NULL, NULL, 'Inground', 'A recently divorced father attempts to reconnect with his young son by building a swimming pool in his backyard that they can both enjoy over the course of a long, hot summer. What begins as an exciting project turns into a terrifying nightmare.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15642, 'Estrellados', 1079096, NULL, NULL, 'Estrellados', 'A matinée idol and a bumbling manager fight for the love of a would-be starlet. Estrellados is the Spanish version of Free and Easy (1930) with Hispanic/Spanish-speaking actors.', '/828fFCM9v4orMaLHUIcpzk3KDOk.jpg', '1930-07-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15643, 'Free and Easy', 42811, NULL, '/62lMzht2Y6gfyTt6hv7mOzPD9my.jpg', 'Free and Easy', 'Gopher City Kansas hosts a beauty contest. The winner, Elvira Plunkett, and her mother go to Hollywood. The Chamber of Commerce also provides Elvira with an agent, Gopher City''s own Elmer J. Butz. Elmer likes Elvira and the shy Elvira likes him, but Mrs. Plunkett, a formidable woman, has little use for hapless Elmer. On the train west, they meet movie star Larry Mitchell, who takes a shine to Elvira and helps her meet MGM directors once they get to Tinsel Town. Elmer, meanwhile, wants to help Elvira with her career and he also wants to be her man. Movie stardom does come to the Gopher City entourage, but to whom is a surprise. And who will win the lovely Elvira''s hand?', '/31UrsNkQOBNgaGkE7FF8oD6ONU.jpg', '1930-03-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15644, 'A Racing Romeo', 1107248, NULL, '/1jYgNTEhcZQW0UsSDf5VShRtl0t.jpg', 'A Racing Romeo', 'When Red Walden loses out in the annual town motor race, Aunt Hattie Wayne and her niece Sally advise him to pay more attention to his garage.', '/vjMA12wnfHFEVEuo5nygoGAHq6S.jpg', '1927-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15645, 'The Whole Town''s Talking', 722917, NULL, '/loRcFwDJiwtHZX43E1OvAiYFqPh.jpg', 'The Whole Town''s Talking', 'Chester Binney, a wounded war veteran, erroneously believes he is carrying a silver plate in his head and must avoid all excitement. He returns to his hometown, and there his former employer, George Simmons, attempts to arrange a match between Chester (who is to inherit a fortune) and his daughter Ethel. Ethel, however, finds Chester unexciting as a lover; and to enliven the affair, the father invents a lurid past for the boy by displaying a signed photograph of Rita Renault, a famous movie star. Rita, accompanied by her jealous husband, Jack Shields, arrives in the town for a personal appearance. By chance, Jack discovers the photograph of Rita, presumably the property of Chester, and when he sees his wife kissing Chester, a running fight ensues.', '/36fHyvdsuM5EFTzhqn209zjnw87.jpg', '1926-12-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15646, 'Wanderer of the Wasteland', 110836, NULL, '/qcMRKa0X3v9L0pJy4kWyXtnS95C.jpg', 'Wanderer of the Wasteland', 'Adam Larey becomes a fugitive from justice when he escapes after being blamed for a crime he did not commit. He wanders into the desert wastelands and joins an outlaw gang who prey on gold prospectors. Years later, he meets his wife and her gold-prospecting father as they have come there seeking their fortune, and not knowing the danger of the treacherous desert wastes, the poisoned-water holes and the outlaw bands of marauders who roam the desert in search of the gold found by others. He comes to their aid and, eventually, manges to clear his name of the false charge against him.', '/Amca8gVrJZn48OvrTvyrIEELx88.jpg', '1935-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15647, 'The March of Time', 920677, NULL, '/hm8xK2RYEyxV2TrRueZSL0x2aEF.jpg', 'The March of Time', 'Unfinished pre-Code era film consisting of three sections with past performers from the stage and the vaudeville circuit, then-present-day performers and up-and-coming performers.  Musical excerpts were later used in Broadway to Hollywood (1933), Nertsery Rhymes (1933), and Roast-Beef and Movies (1934). "The Lock Step" was later used in That''s Entertainment! III (1994)', '/j9w70AcWEIvuYowPULs2GNIHeLI.jpg', '1930-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15648, 'Proud Flesh', 184875, NULL, '/mFs3NsAgchuBsDsSGLlpx15TsG3.jpg', 'Proud Flesh', 'The snooty Fernanda decides to leave Spain to visit her uncle in San Francisco in order to escape the attentions of the dandy, amorous Don Diego, but he follows her. She is rescued from a wild taxi ride by a passerby who owns a huge plumbing company. Believing him to be a common plumber, she snubs him, but he pursues her and a romantic rivalry is born.', '/xqHQYNRdjIu6jIHkdgjhCYn0Rat.jpg', '1925-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15649, 'My Bag o'' Tricks', 207828, NULL, NULL, 'My Bag o'' Tricks', 'A vaudeville act. Trixie Friganza performs first a story and then a song. For the story, she wears a wide-brimmed had and a matching diaphanous shawl. She tells of a visit to a friend who has a five-year old son. The mother tells Trixie a tale of stepping out on her husband, and to conceal the story from the boy, spells out key words. By the story''s end, mom is in for a surprise and Trixie has a moral for us. Then, the hat and shawl come off, a base fiddle comes out, and Trixie sings us a comic song about her first two husbands.', '/oFpVh80K6fOfGimdtizp9MPbTBf.jpg', '1929-01-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15650, 'Almost a Lady', 208042, NULL, NULL, 'Almost a Lady', 'Marcia, a pretty young girl, goes to work as a model for a lecherous dress-shop owner. She resists his advances, despite his giving her expensive gifts. One day Mrs. Reilly, a prominent society woman and a customer of the shop, invites Marcia to a party she''s throwing. Marcia winds up impersonating a famous writer in order to impress a "duke" for Mrs. Reilly, who doesn''t know the "duke" isn''t really a duke. Complications ensue.', '/hxmqWzaAN3P1i40nMR4XNJtvko1.jpg', '1926-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15651, 'How to Undress in Front of Your Husband', 232527, NULL, NULL, 'How to Undress in Front of Your Husband', 'A "Peeping Tom" likes to look through windows at women undressing. We see him as he sneaks a peek at two subjects. The first, a woman dressed in lingerie, is young, shapely and attractive. The second, to be charitable, isn''t. That doesn''t stop him, and the viewer, from getting an eyeful.', '/gXDZL5f2shoZlFpqh15ee45aRVm.jpg', '1937-06-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15652, 'Silks and Saddles', 470226, NULL, '/vDnAI7PHZH56tvz2V7jmW5iQz2s.jpg', 'Silks and Saddles', 'College student Jimmy Shaw inherits a racehorse, named Lightning Lad, and sells stock to fellow students in order to obtain funds for racing the horse. Lightning Lad wins very race he is entered in. Marion Braddock, a spoiled rich girl who owns a racing stable offers to buy Lightning Lad, but Jimmy refuses to sell. The day of the big handicap-race arrives and Jimmy and his fellow stockholders are on their way to the track. But a group of gamblers, betting on Lightning Lad to lose, have some skullduggery plans to ensure Lightning Lad does not win the race.', '/bHIVc9ZraaxAn3y0JpX0ruVAiaW.jpg', '1936-12-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15653, 'Myrt and Marge', 183881, NULL, '/98LnQcdy3X4sL2iPwemdQLW6sTj.jpg', 'Myrt and Marge', 'Myrt has a show chock full of talented performers that deserves to be on Broadway, but can''t raise the necessary money. Jackson, a lecherous "producer", provides the money in order to get his hands on the show''s pretty young star, Marge. Myrt teams up with Marge''s boyfriend to try to thwart the randy producer and get the show to Broadway.', '/5QwpkZF2eLgi44SqfRKtOF57UZs.jpg', '1933-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15654, 'The Road to Yesterday', 184511, NULL, '/73jYzqP6FhVxtGVorOq7RFAkWBl.jpg', 'The Road to Yesterday', 'Malena''s apparent frigidity toward her husband Kenneth is a result of injustice done in an earlier incarnation when he was a knight and she was a gypsy headed for burning at the stake. This becomes evident when their unconscious minds travel back from a train wreck in the American plains to Elizabethan England.', '/48157u5dfqIvBlQJYWx801ohrGF.jpg', '1925-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15655, 'The Unholy Three', 27504, NULL, '/l7MNAXrIiJ2MbQ6MpxVGEMsxJuE.jpg', 'The Unholy Three', 'A trio of former sideshow performers double as the "Unholy Three" in a scam to nab some shiny rocks.', '/4NLoePBFJX8O0yCwBbhrqhHFXFp.jpg', '1930-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15656, 'Monte Carlo', 1054855, NULL, NULL, 'Monte Carlo', 'Three girls from a small town win a trip to Monte Carlo. The trip was sponsored by their local newspaper, which sends along its ace reporter Bancroft as their "chaperone".', '/5XKftphbbxoXdWqrhc91bHPOOy7.jpg', '1926-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15657, 'The Charmer', 395386, NULL, '/A9rDDrXuUatJWDXBzQgNRrHDb2H.jpg', 'The Charmer', 'A wild dancer in a cheap Seville cafe, Mariposa is taken to New York by Señor Sprott, a prominent theatrical producer. Billed as "The Charmer," Mariposa becomes the toast of two continents. Among her most ardent admirers are Ralph Bayne, a millionaire playboy, and his chauffeur, Dan Murray, both of whom first met her in Spain. Madly in love with Bayne, Mrs. Sedgwick invites Mariposa and her mother to a weekend party in a deliberate attempt to humiliate the beautiful dancer. Bayne quickly realizes that Mariposa is out of place in high society, and, determining to make her his mistress, takes her home with him. Mrs. Sedgwick unexpectedly arrives at Bayne''s swank suite ( followed by her suspicious husband), and Mariposa protects the society woman''s reputation at the cost of her own.', '/92jCez8AW76MmG0i1cqzmakYkH5.jpg', '1925-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15658, 'Strong and Willing', 454981, NULL, NULL, 'Strong and Willing', 'Trixie does ''Rosie O''Kerry'' in different voices and does a few nationality skits to the same tune.', '/Az3Cc2ZuSj6q9PhqD3d2HWjgDS.jpg', '1930-06-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15659, 'If I Had My Way', 74214, NULL, '/4TR2nanKdkI36lvAPcz4q7FB83V.jpg', 'If I Had My Way', 'Construction worker Buzz Blackwell becomes the guardian of 12-year-old Pat Johnson after one of his buddies, her father, is killed. Buzz and Pat, along with their chum Axel Swensen, head to New York to look for the girl''s uncle. The trio soon unexpectedly become owners of a tired restaurant.', '/ocJpYH0Ou2fKhCo34zIlRMRJghC.jpg', '1940-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15660, 'Gentlemen Prefer Blondes', 423172, NULL, NULL, 'Gentlemen Prefer Blondes', 'Gold digging blonde Lorelei and her brunette friend Dorothy are searching for rich husbands. This film is believed lost.', '/cHEwe7YmRDLy4fWoGFryHjYWuHb.jpg', '1928-01-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15661, 'Borrowed Finery', 1360365, NULL, NULL, 'Borrowed Finery', 'Dress model Sheila Conroy loses her job after ruining a gown she borrowed from her employer. Harlan, a criminal posing as a government agent, offers Sheila work as his assistant. She accepts for the sake of her brother-in-law, Billy, who embezzled money from his firm and is in danger of discovery. Her assignment is to obtain the necessary "evidence" on Mrs. Bordon, a wealthy widow who smuggled a valuable jewel into the country. Channing Maynard, a real government agent, reveals the truth to Sheila, and after they bring Harlan to justice, Channing takes Sheila for his bride.', NULL, '1925-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
