INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15663, 'Thanks for the Buggy Ride', 1642616, NULL, NULL, 'Thanks for the Buggy Ride', 'Jenny, a dance instructor, accidentally meets Joe Hall, a song promoter who escorts her home. She gives him a song idea by saying "Thanks for the Buggy Ride".', '/lniGnmWKJC7nXeRO8k6EfhWPVux.jpg', '1928-04-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:52', 0);
