INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15666, 'Bill & Ted''s Bogus Journey', 1649, NULL, '/4PMSgLOzPFgyzARQBhhX4vS9oOW.jpg', 'Bill & Ted''s Bogus Journey', 'Amiable slackers Bill and Ted are once again roped into a fantastical adventure when De Nomolos, a villain from the future, sends evil robot duplicates of the two lads to terminate and replace them. The robot doubles actually succeed in killing Bill and Ted, but the two are determined to escape the afterlife, challenging the Grim Reaper to a series of games in order to return to the land of the living.', '/tldtDfLnPFOtTWp758EmIP2Hbz5.jpg', '1991-07-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
