INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15668, 'I Love You to Death', 3101, NULL, '/joBJxmTxjQNN9q14UoCMkTBiIMH.jpg', 'I Love You to Death', 'Joey Boca is the owner of a pizza parlour, and has been married to Rosalie for years. When Rosalie discovers that Joey is a womanizer and has been cheating on her for a long time, she goes to extreme lengths to punish him.', '/8LdWJLUfEa5JeUJ7SljJQMIJikZ.jpg', '1990-04-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15669, 'The Watcher', 10685, NULL, '/dtFS7DS64umOHK6PcfabXtDaf2w.jpg', 'The Watcher', 'FBI agent Joel Campbell, burnt-out and shell-shocked after years spent chasing serial killers, flees L.A. to begin a new life for himself in Chicago. But five months later, Joel''s best laid plans are abruptly cut short when his new hometown becomes the setting for some particularly gruesome murders--murders that could only have been committed by one man: David Allen Griffin. One of Joel''s most elusive and cunning nemeses, Griffin has followed his former pursuer to Chicago in order to play a sadistic game of cat and mouse. Taunting Joel with photographs of his intended victims and leaving his crime scenes meticulously free of clues in order to keep the police at bay, Griffin derives as much pleasure out of watching Joel react to every movement as watching his victims die. But when Griffin moves into Joel''s inner circle, Joel must quickly find some way to stop him before someone close to him becomes the next one to die.', '/hsMvndtd3KPAvJ3q7zKZuNSB1R3.jpg', '2000-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
