INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15671, 'River''s Edge', 21309, NULL, '/A4nFhxBKmT2Zlyojmq6VUhlTPJG.jpg', 'River''s Edge', 'A group of high-school friends must come to terms with the fact that one of them, Samson, killed another, Jamie. Faced with the brutality of death, each must decide whether to turn their friend in to the police, or to help him escape the consequences of his dreadful deed.', '/bT68aKa9d7zDF7Z8MaskbWBRqzb.jpg', '1986-10-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
