INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15673, 'Babes in Toyland', 26984, NULL, '/lBGWicMFQCbmTakVPbYZ9AHUkFL.jpg', 'Babes in Toyland', '11-year-old Lisa has no time for toys; she''s too busy taking care of her siblings and cooking for her mother. During the Christmas Eve blizzard, Lisa travels to Toyland in Wizard of Oz-like fashion and arrives just in time for a wedding. Young Mary Contrary is about to marry mean, old Barnaby Barnacle, despite the fact that she loves Jack Be Nimble. Lisa tries to stop this terrible wedding and, together with her new friends, discovers that Barnaby wants to take over Toyland. Lisa, Mary, Jack, and Georgie Porgie ask the Toymaster for help, but he can''t help them as long as Lisa doesn''t truly believe in toys.', '/mTg72oYoK18oV1uuuZGW2JI752x.jpg', '1986-12-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15674, 'Feeling Minnesota', 12656, NULL, '/pWQccERGRrNRJTEK9cOLV8M4Efx.jpg', 'Feeling Minnesota', 'Sam Clayton''s marriage to ex-stripper Freddie comes about when she''s strong-armed into the match by Red, a club proprietor who once did her a favor. But Freddie falls in love with Jjaks, Sam''s brother, and the pair tries to escape the situation together. It isn''t long before both Sam and Red catch up with them, resulting in threats against the two of them -- although tension also starts to build between Sam and Red.', '/fCJ5eUZw6mGS53spQxGUu7rzFm1.jpg', '1996-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
