INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15676, 'The Last Time I Committed Suicide', 34941, NULL, '/Hx5VuyfXN9AVHnzeKmhMFaPINq.jpg', 'The Last Time I Committed Suicide', 'Neal Cassady is living the beat life during the 1940s, working at The Tire Yard and philandering around town. However, he has visions of a happy life with kids and a white picket fence. When his girlfried, Joan, tries to kill herself he gets scared and runs away. But when Joan reappears will he take the chance at that happiness, or will he turn his back on it?', '/5AM1oDIlsWBBLYecetUAHOWv9dW.jpg', '1997-06-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
