INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15679, 'Tune in Tomorrow...', 41927, NULL, '/ltuTwhowD0Z7UVUcc4rZL615csD.jpg', 'Tune in Tomorrow...', 'Martin works at the local radio station, which just hired a new scriptwriter with a reputation for great drama, Pedro Carmichael. Martin’s aunt Julia, not related by blood, returns home after many years away and Martin falls for her. Once Pedro finds out about this romance, he starts incorporating details of it into the script of his daily drama series. Soon, Martin and Julia are not only hearing about their fictional selves over the radio, but about what they are going to do next.', '/cMabi4aTi9mYs29tFS5Bh2DSEPi.jpg', '1990-10-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15680, 'Flying', 62768, NULL, '/5jdcMKI5KXxwjxaEjiRy9Cgxx7s.jpg', 'Flying', 'Robin and her father have a car accident. Her father dies. Robin is badly injured and cannot compete in gymnastics tournaments anymore. She lives with her mother and bad step-father. Robin is accepted to the school athlethics team but is not accepted by some other girls, so she works out at a friends house. Eventually Robin and her team compete in the national scholastic meet.', '/ppcoRM6wNT92N2bLkX91YTOLZ8E.jpg', '1986-05-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
