INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15684, 'The Great Warming', 49917, NULL, NULL, 'The Great Warming', 'We are living at the dawn of a new epoch. Year by year, degree by degree, Earth is growing warmer... a legacy of the Industrial Revolution, population growth, and our addiction to technology, speed and power. Just as other generations spoke of a Great Plague and a Great Depression, our children will be compelled to endure The Great Warming - and find a way to conquer its consequences. Filmed in eight countries on four continents, endorsed by dozens of the world''s leading scientists, this is the most factually accurate, visually stunning and wide-ranging production ever mounted about this complex, fascinating subject.', '/j3e0YaGwR7TnJsmcaJFHwRL0EdF.jpg', '2006-11-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15685, 'Permanent Record', 51321, NULL, '/disE4kPp6jkIR8MJhVsdYuKyv3q.jpg', 'Permanent Record', 'David Sinclair seems to have everything going for him: he''s smart, musically talented, and very successful. To top off his senior year in high school, his band is trying to get a recording session. Therefore, David''s suicide leaves everyone, especially his best friend and bandmate, Chris, with a lot of questions.', '/AsoyWPJwtuRJuHyMhXpcsK0XrbX.jpg', '1988-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15686, 'Henry''s Crime', 53172, NULL, '/eLTdgR6f4MrnqAA42NDVGHp7xXd.jpg', 'Henry''s Crime', 'An aimless man is sent to prison for a crime he did not commit, an ex-con targets the same bank he was sent away for robbing.', '/1i1sDWOZecbUZ4Yp9DG5UiTBBRl.jpg', '2010-01-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15687, 'Side by Side', 110354, NULL, '/AkuDVdvopWHr2Vw3IBmfhlPk8Bx.jpg', 'Side by Side', 'Since the invention of cinema, the standard format for recording moving images has been film. Over the past two decades, a new form of digital filmmaking has emerged, creating a groundbreaking evolution in the medium. Keanu Reeves explores the development of cinema and the impact of digital filmmaking via in-depth interviews with Hollywood masters, such as James Cameron, David Fincher, David Lynch, Christopher Nolan, Martin Scorsese, George Lucas, Steven Soderbergh, and many more.', '/qeeQ7rfTAXNYh4EqqdolFLkNwKM.jpg', '2012-08-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
