INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15700, 'Deep Web', 321769, NULL, '/ayfUwTMNSYcra3IfYhP4Et8iRPb.jpg', 'Deep Web', 'Deep Web gives the inside story of one of the most important and riveting digital crime sagas of the century -- the arrest of Ross William Ulbricht, the 30-year-old entrepreneur convicted of being ''Dread Pirate Roberts,'' creator and operator of online black market Silk Road. As the only film with exclusive access to the Ulbricht family, Deep Web explores how the brightest minds and thought leaders behind the Deep Web and Bitcoin are now caught in the crosshairs of the battle for control of a future inextricably linked to technology, with our digital rights hanging in the balance.', '/sk6KzLhpWizGBrEt04qyzUqmSkn.jpg', '2015-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
