INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15777, 'Love, Antosha', 565276, NULL, '/3G0xVewAccMul25pPQxbmfOIS4J.jpg', 'Love, Antosha', 'From a prolific career in film and television, Anton Yelchin left an indelible legacy as an actor. Through his journals and other writings, his photography, the original music he wrote, and interviews with his family, friends, and colleagues, this film looks not just at Anton''s impressive career, but at a broader portrait of the man.', '/AntNP1sX7qKBT7hSYM4248RKMaL.jpg', '2019-08-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15778, 'The Making of ''Split''', 685564, NULL, NULL, 'The Making of ''Split''', 'A piece in which Shyamalan discusses his growth as a person and a filmmaker, how the film reflects his growth, casting, script secrecy, characters, the film''s style, influences (namely It Follows), locations and set design, and budget.', '/u5B29EdugGRKgvbUsS5oUsjodfE.jpg', '2017-04-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
