INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15780, 'Creating The Queen''s Gambit', 784047, NULL, '/4aTonMQCSEgu5PV3n3xRaNMZmG1.jpg', 'Creating The Queen''s Gambit', 'A fascinating character. Exquisite sets. A wig for every era. The stars, creators and crew reveal how the hit series about a chess prodigy came to life.', '/gKxPyeItCrOscP8On4y5sG3WY9A.jpg', '2021-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15781, 'Nighthawk: Maison Margiela Artisanal 2024', 1363999, NULL, '/oqByBsXLV97iCVSJBGHWusntgtH.jpg', 'Nighthawk', 'A film based on an original concept by John Galliano and directed by Sasha Kasiuha. Founded in the proposition that opened the 2024 Artisanal Show in January 2024 – “Would you like to take a walk with me, offline?” – the cinematic experience elucidates and elaborates the haute couture collection for posterity. In a fast-paced culture, it serves as an articulated desire to be present in the moment, and in the memory; values key to Maison Margiela.', '/3Mj82nblHWchHGmkcnKm0pfei9i.jpg', '2024-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15782, 'Dinner and Diatribes', 1529200, NULL, NULL, 'Dinner and Diatribes', 'The final single off the apocalyptic Wasteland, Baby, Hozier described "Dinner & Diatribes" as being about "the crushing tedium of social obligations" and "that feeling of relief when leaving any tedious social engagement," and that energy is clearly on display in the song. The narrator wants nothing to do with the club they are at with their partner and craves a chance to get away and indulge in much more intimate and decadent choices.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
