INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15784, 'Untitled Joni Mitchell Biopic', 1133874, NULL, NULL, 'Untitled Joni Mitchell Biopic', 'Described as an unconventional biopic, ''akin to an autobiography'', telling the story of Joni Mitchell''s life from her point of view, while also offering her view on the world.', '/9uqjNXCPpebwDWPfrVNWv5lxFO8.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15785, 'Mad Max and the Genius of George Miller', 1545263, NULL, '/fHJ48xLsULqwqA5PuRm1m4I76Yy.jpg', 'Mad Max and the Genius of George Miller', 'The improbable story of how one 1970s Australian film grew into the country’s biggest ever cultural export, and the intertwined story of its creator, George Miller, his singular cinematic vision and how it set him on an unlikely journey from outback Queensland to the pinnacle of Hollywood success.', NULL, '2025-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15786, 'Her Dior', 1615380, NULL, '/zjiXtCCiNpaZXT03twg2QCrCFqd.jpg', 'Her Dior', 'In celebration of International Women''s Day, the House reveals "Her Dior", a documentary by ‪Loïc Prigent‬ chronicling Maria Grazia Chiuri''s radical collaborations with renowned female figures since becoming Dior''s Creative Director for womenswear in 2016. The film charts her journey from Rome to the global stage, distilling the essence of these poignant artistic exchanges in a single word: sisterhood.', '/aAjd0D6GtAYqfIfHW8nW0Qd4Ius.jpg', '2025-03-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15787, 'Bulaklak ng Maynila', 233780, NULL, '/dJHoNHJJrSP1zvlrLbSP8AJYUPw.jpg', 'Bulaklak ng Maynila', 'A woman who falls under the sway of a crime boss plots to bring him down after a horrible betrayal in this drama from the Philippines. Azun (Elizabeth Oropesa) is a wife and mother living in a dangerous neighborhood in Manila, where she peddles goods on the street. Azun''s husband Roque (Bembol Roco) becomes involved in a burglary that goes awry, leading to a lengthy jail sentence. With few options, and needing safety and support, Azun becomes involved with Timo (Christopher De Leon), leader of a local crime syndicate. But Timo''s protection does not extend to Azun''s teenage daughter Ada (Angelu De Leon); Timo rapes Ada, then forces her to leave her boyfriend (Jomari Yllana) and start dancing in his strip club. When Azun learns what Timo has done to Ada, she makes plans to get her revenge.', '/1oHLcMXrQlDG0wBnwS9HhdxFoSK.jpg', '1999-12-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:53', 0);
