INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15844, 'Bolero', 37335, NULL, '/uLSQy99Tk5Ux3EeCpcvAwPs6f5H.jpg', 'Les uns et les autres', 'The film follows four families, with different nationalities (French, German, Russian and American) but with the same passion for music, from the 1930s to the 1960s. The various story lines cross each other time and again in different places and times, with their own theme scores that evolve as time passes. The main event in the film is the Second World War, which throws the stories of the four musical families together and mixes their fates. Although all characters are fictional, many of them are loosely based on historical musical icons (Édith Piaf, Josephine Baker, Herbert von Karajan, Glenn Miller, Rudolf Nureyev, etc.) The Boléro dance sequence at the end brings all the threads together.', '/6FUXOIU9pa835mNRD4bG4MKzdrx.jpg', '1981-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
