INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15850, 'Irreconcilable Differences', 47874, NULL, '/c08CoaUvRGgJLgiRtN9Idc8H06L.jpg', 'Irreconcilable Differences', 'Alternating between the past and the present, a precocious little girl sues her selfish, career-driven parents for emancipation, surprising them both.', '/jBr9FR2pUpjOERgxljxaNtpIj9c.jpg', '1984-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15851, 'Intersection', 46717, NULL, '/x2vTCtMdjCTGffHKSZ6r78UQWsC.jpg', 'Intersection', 'During a car accident, Vincent Eastman watches his whole life flash before his eyes, and he doesn''t like what he sees. While maintaining the semblance of a marriage with his wife, Sally, Vincent has been carrying on with a mistress, Olivia. She''s everything Sally isn''t -- warm, passionate, carefree. So why can''t he choose between the two, especially when his indecision is taking its toll on his daughter?', '/xRMbpD2WRxpVcU6Vvws32GkMxin.jpg', '1994-01-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15852, 'He Said, She Said', 17956, NULL, '/1y43OB6R4vfBKEuVpGxyFENMAqh.jpg', 'He Said, She Said', 'Womanising, right-wing Dan Hanson and quiet, liberal Lorie Bryer work for the Baltimore Sun. Rivals for the job of new writer of a vacant column, the paper ends up instead printing their very different opinions alongside each other, which leads to a similarly combative local TV show. At the same time their initial indifference to each other looks like it may evolve into something more romantic.', '/5uYv11zTTa83WMWwI3B6EOZtI0Z.jpg', '1991-02-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
