INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15855, 'Big Guns Talk: The Story of the Western', 927607, NULL, NULL, 'Big Guns Talk: The Story of the Western', 'Interviews and film clips re-create the glorious history of the American western.', '/3SfMyEi0N1A7spttIGdmDGn4fgO.jpg', '1997-07-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15856, 'Simpatico', 50116, NULL, '/lAH6sXpb9pnyhOQHk5Z1TWwwNIx.jpg', 'Simpatico', 'As youths in Azusa, Vinnie, Carter, and Rosie pull off a racing scam, substituting winners for plodders and winning big bucks on long odds. When an official uncovers the scam, they set him up for blackmail. Jump ahead twenty years, Carter and Rosie are married, successful racers in Kentucky about to sell their prize stallion, Simpatico. Vinnie is a drunk in Pomona. Vinnie decides to make a play for Rosie, lures Carter to California, steals his wallet and heads for Kentucky with the original blackmail material. Carter begs Vinnie''s friend, a grocery clerk named Cecilia, to follow Vinnie and get the stuff back that he has in a box. Will she succeed?', '/p6JglpvM6ERbZAYEW31gwvNprVZ.jpg', '1999-09-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15857, 'Diary of a Hitman', 50185, NULL, '/ro2MhbNxhijplYSkgeN5RU1zoUY.jpg', 'Diary of a Hitman', 'A veteran hitman, Dekker is ready to call it quits and leave the profession. His final job, however, proves to be trickier than expected when a sadistic man recruits the assassin to kill his wife, Jain, and their baby, but he can’t bring himself to do the job, complicating all of their lives.', '/rF4Qz69ConQqoedsAtiv38O7UX0.jpg', '1991-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15858, 'A Different Loyalty', 19180, NULL, '/bHAqlUjH3ZjoUevtS4vAJL72IxZ.jpg', 'A Different Loyalty', 'In January 1963, British journalist Leo Cauffield suddenly disappears from his home in Beirut. His wife Sally knew that he was working part-time for British intelligence, but was not prepared to be told by the British embassy that they suspect he has defected to Communist Russia. As his wife puts together the pieces of the mysterious jigsaw of the past, tracking her passionate relationship with her husband and his history as former head of MI6’s counter-espionage section, her relentless search for the truth takes her to London, New York and finally Moscow.', '/fbJwFcXT6tvIVHMzXmN7FnJgQxW.jpg', '2004-11-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15859, 'Streets of Blood', 19727, NULL, '/rc2U9zz3hNLnb8jcgpUGRwDFdRB.jpg', 'Streets of Blood', 'A police officer''s partner has died during Hurricane Katrina, but he later discovers that his partner may have been murdered. An investigation follows, taking the officer and his new partner into the depths of the criminal underworld.', '/UBLsks7CwsWqYil8PAkzOJauq8.jpg', '2009-05-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15860, 'Beyond the Stars', 92331, NULL, '/3mvSLJWHp3Ws2IM6LW4aMk5SV78.jpg', 'Beyond the Stars', 'Teenager Eric, the son of a computer scientist who worked for the Apollo mission which sent the first human to the moon, is determined to become an astronaut himself one day, and befriends Paul Andrews, the first man on the moon. Paul is avoided by other astronauts nowadays, because he was very rude and rebuffing when he returned from space. Only slowly Eric learns, that he discovered something during his excursion on the moon, that he keeps as a secret.', '/hfOnqwPoXJHeFAap69LfmW5KZCa.jpg', '1989-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
