INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15862, 'Largo Winch II', 57331, NULL, '/cb1EgHUV2OW988cEunXm7Px4OhT.jpg', 'Largo Winch II', 'Propelled to the head of the W Group after the death of his adoptive father, Largo Winch decides, to everyone''s surprise, to sell it, and use the proceeds to create an ambitious humanitarian foundation. But on the very same day, he finds himself accused of crimes against humanity by a mysterious witness. To prove his innocence, Largo will have to retrace the steps of his past life, in the heart of the Burmese jungle.', '/cS7v9W2OeOQFkTWA9PbeTrXoCEy.jpg', '2011-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15863, 'Tears in the Rain', 77631, NULL, '/e4VSWCZwqLW8AlN1xffeEcVi8NJ.jpg', 'Tears in the Rain', 'When Casey Cantrell''s mother died, her last wish was that her daughter would give a letter to Lord Richard Bredon, living in the UK. When Casey arrives in London, Lord Bredon denies ever having known her mother.', '/pEAsKBif5VwGOPcxjcHWmgunfiC.jpg', '1988-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
