INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15865, 'No Subtitles Necessary: Laszlo & Vilmos', 91967, NULL, NULL, 'No Subtitles Necessary: Laszlo & Vilmos', 'The artistry, triumph and lifelong friendship of the great cinematographers Laszlo Kovacs and Vilmos Zsigmond. With film school equipment, they shoot the Soviet crackdown of the 1956 Hungarian Revolution. As refugees they struggle in Hollywood, finally breaking into the mainstream with their pivotal contribution to the "American New Wave."', '/s4BgpSIHqNdUetA7cxhaXj1wDuc.jpg', '2009-01-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
