INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15867, 'Calendar Girl Murders', 159324, NULL, '/uwPQ1PcyjgJS57KJ7tFzXxMij90.jpg', 'Calendar Girl Murders', 'During the launch party of a nude calendar, one of the models is thrown to her death by a black gloved killer. When the killer begins to strike again, going in the order of the calendar itself, a hard nosed cop realizes that he needs to solve the mystery, or risk all of the models ending up in the morgue!', '/k38XxckhivAEftg8t8jIlZrrp2J.jpg', '1984-04-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15868, 'Harlow: The Blonde Bombshell', 166352, NULL, '/4K7PYRGlAgoVrmbwa7SuYiBNe2O.jpg', 'Harlow: The Blonde Bombshell', 'Actress Sharon Stone hosts this documentary about the life and career of 1930s sex symbol Jean Harlow. Included are clips from many of her films, photos and stories about her life before she became a movie star, and accounts of her troubled personal life, including a domineering mother, the failure of her three marriages and the suicide of her second husband.', '/cWaB9YNciyIRGgjQQTubbPZqhM0.jpg', '1993-02-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
