INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15880, 'The American Tetralogy', 1022059, NULL, '/5Ejlncjb1Bl4oavVvQfUqGVse5W.jpg', 'The American Tetralogy', 'Entirely made in California, the film brings together 30 American and European actors in an epic which crosses the mythical territories of that cinematic land from Zabriskie Point to Mulholland Drive. California is revisited through the movie memories incarnated by the very presence of famous actors and actresses. "The American Tetralogy" is a way of staging reality which questions the fictional nature of the movies.', '/uQzlyn5lS6IWiRh4cc8FV2WT6s8.jpg', '2012-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15881, 'Mon Clown', 1038901, NULL, NULL, 'Mon Clown', 'Documentary from French TV channel Canal+ about Marion Cotillard''s road to the Oscar for her performance as French singer Édith Piaf in the 2007 film ''La Vie en Rose'', also featuring behind-the-scenes footage from the film.', '/Tiiat9lZD3ZRjoj9EbGefEBLBw.jpg', '2008-03-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
