INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15884, 'Not Just Another Affair', 245438, NULL, '/9R9mNa50DZxZN3fr4wkPYh54pLO.jpg', 'Not Just Another Affair', 'A lady marine biologist, determined to save herself until marriage, meets a handsome attorney who is not used to being rejected sexually, and it becomes a battle of wills as to who will emerge the winner.', '/bqggaIoRR5g6R5jyNELlJy5mQS1.jpg', '1982-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15885, 'Jiminy Glick in Lalawood', 67445, NULL, '/5LEz0AsrcsQUWBEBtnGAW3s0PsY.jpg', 'Jiminy Glick in Lalawood', 'Hungry for an A-list interview that could launch him into the gossip rag stratosphere, Jiminy Glick, a small-time journalist with big aspirations and an even bigger appetite, drags his wife and kids across the country to the star-studded Toronto Film Festival. But in between the nonstop parties and all-you-can-eat buffets, Glick soon finds himself in the middle of an outrageously scandalous mystery that becomes the celebrity scoop of the decade!', '/xggAb26HJ64LTx7SYIn58nIM1b0.jpg', '2005-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15886, 'Faye', 1280483, NULL, '/hWdo4fYvvPr6jPOPJwxebBCeE0j.jpg', 'Faye', 'Through honest reflection, complemented by insight from colleagues and friends, Faye Dunaway contextualizes her life and filmography, laying bare her struggles with mental health while confronting the double standards she was subjected to as a woman in Hollywood.', '/dpeUP8kX4mjDqqQXmByv6OKXTs0.jpg', '2024-05-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15887, 'The Cold Open', 1282503, NULL, NULL, 'The Cold Open', 'Aubrey Plaza leads a satanic cult of actresses in a sacrificial offering to preserve the integral values of independent cinema.', '/avSlTGpkCr1fXdUNxcjnMnu3SYN.jpg', '2019-02-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15888, 'Mothers and Daughters', 109453, NULL, '/3t1ntXTE8G50j9uiKsgYhKjDY3D.jpg', 'Mothers and Daughters', 'Interwoven stories of what it is to be a mom seen through the lens of photographer Rigby Gray.', '/tTu3xPJOIV4s6ZzNwjvcwGytMla.jpg', '2016-05-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15889, 'Life on the Line', 398289, NULL, '/YIpBRJLhKa9doO3vjoUTndNlUB.jpg', 'Life on the Line', 'As a huge electrical storm sweeps towards Texas, lineman Beau Ginner is haunted by memories of his brother''s death by lightning years earlier. Since that tragic day, he has raised his niece Bailey and risen to foreman of a lineman team. However, there is friction when Bailey''s on-off boyfriend Duncan joins the crew, while another new recruit is hiding PTSD symptoms. Beau and his team are soon putting their lives at risk in a race to replace miles of power cables to keep the electrical grid running before the deadly lightning storm strikes. Based on a true story; this film is a tribute to the heroes who risk it all to keep us safe.', '/uGGJJxcS1UA5hvZvQW0fOnn46tZ.jpg', '2016-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15890, 'Making Casino', 1302438, NULL, '/1Avnr6IdXxyVdv7jO9H5wtXtBpe.jpg', 'Making Casino', 'A four-part making-of documentary about Scorcese’s 1995 Vegas crime epic Casino featured in physical media releases and split into sections on the Story, the Cast and Characters, the Look and After the Filming.', '/inKRp2hCZ6DjBoqlMZYeyIeTQUM.jpg', '2007-05-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15891, 'Cannes Uncut', 1139231, NULL, '/eynmkL1vjUgC1KXc3GabpZfpF5z.jpg', 'Cannes Uncut', 'Looks at the glamour, red carpets, movies, craziness, stunts, deals, parties and personalities that have been part of the Cannes Film Festival over eight decades, as well as looking to the future.', '/xazzsETUj9OMgr1hmjuBrogr2UC.jpg', '2023-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15892, 'Running Wild', 430406, NULL, '/p8fKTEXw3PDvKSnrFTmyMWmRQXF.jpg', 'Running Wild', 'Stella Davis is a widow who saves her ranch by working with convicts to rehabilitate a herd of wild horses that wandered on to her property. Stella must fight prejudice, greed, bureaucracy and vanity (including her own) to finally understand that there is no better remedy to misfortune than helping another living creature.', '/v5K2odrXNvbZLYl7gFB9WCimN8S.jpg', '2017-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15893, 'Off the Menu: The Last Days of Chasen''s', 85984, NULL, NULL, 'Off the Menu: The Last Days of Chasen''s', 'In 1995, Chasen''s closed its doors after 60 years of serving chili to movie stars and visiting dignitaries, Presidents and the Pope. During its two final weeks, Chasen regulars (actors and producers), staff, and management sat for interviews. There''s an Oscar party for 1500, footage and photos of famous diners, and time with Tommy Gallagher, the ebullient head waiter until retirement in 1994, his son Patrick, catering head Raymond Bilbool, general manager Ronnie Clint, hat check girl Val Schwab, ladies'' room attendant Onetta Johnson, and foreign- born waiters, including Jaime. When he started in 1970, like other Latins, he wasn''t allowed out of the kitchen. It''s a family farewell.', '/4QSZ1oUfQQvgUcDUlAhJACEGDhw.jpg', '1998-06-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15894, 'Badlands 2005', 455975, NULL, NULL, 'Badlands 2005', 'In 1995, a severe drought forced Americans to flee the West for the cities. Water became more precious than gold. Now in 2005, settlers are coming back, meeting new challenges, and age-old adversaries. A U.S. Marshal and his cyborg partner patrol the American West. A hard-as-nails female boss heads two U.S. Marshals (one human, one bionic) in Badlands 2005, a concept where the near future sees water as a more precious commodity than gold. The West of America has been deserted after droughts a decade earlier, and now a re-population program is underway.', '/mOFhuiF5RzDFTv7sIkxKsJcFF0o.jpg', '1988-08-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15895, 'All I Wish', 462723, NULL, '/kdBqrEl2CIBLZdKTNtlwtRnHeAy.jpg', 'All I Wish', 'A woman struggles to escape the clutches of her overbearing, co-dependent mother, while gradually falling for a sexy, sophisticated attorney.', '/4Cm7htvkYRB4M04LzEAIgKoS0n9.jpg', '2018-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15896, 'Mindfulness: Be Happy Now', 470456, NULL, '/zrrqcCt5kisyYenMZOwIomHdFBT.jpg', 'Mindfulness: Be Happy Now', 'Mindfulness is the art of simply being present.  From Oprah to Phil Jackson to Anderson Cooper, it''s an art practiced by some of the world''s most successful people.  Brought to the west by Zen Buddhist Monk Thich Nhat Hanh, who was once nominated for a Nobel Peace Prize by Dr. Martin Luther King Jr., mindfulness has recently gained mainstream popularity in both the media and in mental health treatment.  This film features insights from Deepak Chopra, Thich Nhat Hanh, Sharon Stone, Oliver Stone, Cesar Milan, and many more. Watch it and learn how to embrace mindfulness in your own life!', '/veDWIDkVH1zSU2xMtWycLxwfkYF.jpg', '2015-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15897, 'Into the Night: Portraits of Life and Death', 484864, NULL, '/uLyl3zOtdcaQj69qVeJmJHCsBPq.jpg', 'Into the Night: Portraits of Life and Death', 'We don’t know how. We don’t know when. But death comes for us all. To be human is to wrestle with this truth and with the great unanswered question: How do we live with death in our eye? We can deny, we can rail, we can challenge, we can accept. What is our story, and will it sustain us at the end? “Into the Night: Portraits of Life and Death,” a two-hour documentary, features men and women of uncommon eloquence and intelligence who are grappling with these questions. For them death is no longer an abstraction far off in the future, it is real. They come from all walks of life, all ages, dying and healthy, believers and unbelievers, well known and obscure. These are people who have been shocked into mortality and are forever changed. They have stories to tell, and we can listen and learn from them.', '/apSog1ttB94v3MBuurFqFuasIb5.jpg', '2017-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15898, 'La Traversée du désir', 488210, NULL, NULL, 'La Traversée du désir', 'What was your first desire? What did you long for most? Arielle Dombasle put these questions to a wide circle of famous people.', '/5vefbKVyld9eRG7IZYi3CrmJcUx.jpg', '2009-03-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15899, 'What About Love', 476928, NULL, '/h91JC9H67NxSs5HWyCQ1hjBvV9S.jpg', 'What About Love', 'Two young lovers change the lives of their parents forever when the parents learn from the joyful experience of their kids, and allow themselves to again find their love.', '/jGVpMWEemYCSa2p9OSCMsaBXY98.jpg', '2024-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15900, 'Jewel''s Catch One', 413165, NULL, '/kI3qCdBGFqGu2NfCeUSO514y7lD.jpg', 'Jewel''s Catch One', 'With four strikes against her (black, female, poor and a lesbian), our trailblazer, Jewel Thais-Williams, helped changed laws, save lives and influence communities across Los Angeles, California as she opened her legendary nightclub''s door for 42 years.', '/9TTRQN30RBJYGNuQR4uBntlDAFg.jpg', '2017-01-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15901, 'Cannes: All Access', 471208, NULL, NULL, 'Bienvenue à Cannes', 'From its simple beginnings in 1939 in a sleepy beach town in the south of France, the prestigious Cannes Film Festival has become the must-attend red carpet event of the year. Filmmaker Richard Schickel''s fascinating documentary captures the glitz and glamour of the festival''s incredible 60-year run with archival footage and unforgettable moments. Hollywood''s biggest names including Clint Eastwood, Martin Scorsese, Sharon Stone and Harvey Weinstein talk about the politics, madness, and thrills of competing for one of the industry''s highest honors - the coveted Palme d''Or - and what it''s like to be at the most fabulous festival by the sea.', '/1Pyh7zxHPFNPBbXxOEKuj0nO178.jpg', '2007-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15902, 'The Good, The Bad, and the Beautiful', 551448, NULL, NULL, 'The Good, The Bad, and the Beautiful', 'A documentary reflecting on women in film and the entertainment industry through the ages led and hosted by some of its most beloved female icons.', '/nl5PGgetUTdADk1gO12BPXb7wtB.jpg', '1996-03-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15903, 'This Changes Everything', 541577, NULL, '/3bMVNEBXfMgduNjKG1lzzOwh1ah.jpg', 'This Changes Everything', 'An investigative look and analysis of gender disparity in Hollywood, featuring accounts from well-known actors, executives and artists in the Industry.', '/xoSQcN74mTx2cCgX29OC4YuQ4er.jpg', '2019-07-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15904, 'Harry Benson: Shoot First', 407803, NULL, '/b8sxF22ZF9Pz6TSG3GocTAXPhFF.jpg', 'Harry Benson: Shoot First', 'What we know today about many famous musicians, politicians, and actresses is due to the famous work of photographer Harry Benson. He captured vibrant and intimate photos of the most famous band in history;The Beatles. His extensive portfolio grew to include iconic photos of Muhammad Ali, Michael Jackson, and Dr. Martin Luther King. His wide-ranging work has appeared in publications including Life, Vanity Fair and The New Yorker. Benson, now 86, is still taking photos and has no intentions of stopping.', '/y2bcZFgfT8QWZr6GuRiWbLPYWxQ.jpg', '2016-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15905, 'Hollywood''s Greatest Villains', 597151, NULL, NULL, 'Hollywood''s Greatest Villains', 'Villains have always been with us. In a war-plagued world, brutality and corruption embody our darkest fears--all that is selfish and wicked in the human soul. And they also happen to be great box-office draw as we see in this fascinating, terrifying look at some of the most evil--and best-loved--characters ever created--from Dracula to Darth Vader to Hannibal Lecter. Featuring interviews with actors like Sharon Stone (Basic Instinct) and directors such as George Lucas (Star Wars), John Carpenter (Halloween), this riveting, insightful film exploration takes viewers through more than 100 years of screen evil, including clips from the master of suspense, Alfred Hitchcock. Shiver through our comprehensive gallery of rogues in a bone-chilling homage to the men and women who haunt our darkest dreams...and fulfill our most secret desires?', '/1X1JrnQpShcuNMs3AmsusNpppka.jpg', '2005-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15906, 'Forever Hollywood', 599031, NULL, NULL, 'Forever Hollywood', 'Noted Hollywood stars and directors talk about the history and evolution of the film industry in Los Angeles.', '/pl09MM3C2gLcdMn8D9vICEhusKo.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15907, 'Rolling Thunder Revue: A Bob Dylan Story by Martin Scorsese', 574638, NULL, '/4MYtYsSGzQUUYQqHGWBNeEkT91s.jpg', 'Rolling Thunder Revue: A Bob Dylan Story by Martin Scorsese', 'Part documentary, part concert film, part fever dream, this film captures the troubled spirit of America in 1975 and the joyous music that Dylan performed during the fall of that year.', '/ixxELBgYj9OH8hz0XCrcZOJpIx9.jpg', '2019-06-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15908, 'House of Cardin', 617736, NULL, '/4SZ8EEWvc7K0X6JxXyV9QE4KYWr.jpg', 'House of Cardin', 'The life and design of Pierre Cardin, including exclusive access to his archives and unprecedented interviews from Mr. Cardin.', '/w71p6atMHJNcsvYnHqcHA0IqKxs.jpg', '2019-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15909, 'Beauty', 667642, NULL, '/hZTU9xlOl1pyZxCDM6mDCLZqZcy.jpg', 'Beauty', 'A young singer on the brink of a promising career finds herself torn between a domineering family, industry pressures and her love for her girlfriend.', '/yjAXHyMz0JZzYiQP7q1fT5kXLif.jpg', '2022-06-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15910, 'Here Today', 711475, NULL, '/a8Bbbpqi6sd58Nr4BzbMQa8VFPp.jpg', 'Here Today', 'Veteran comedy writer Charlie Berns, who is slowly but surely losing his grip on reality, befriends a talented young New York street singer Emma Payge. Together, they form an unlikely yet hilarious and touching friendship that kicks the generation gap aside and redefines the meaning of love and trust.', '/xp64qD0V9SRE3jU6sEtQufAzYRk.jpg', '2021-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15911, 'CyberWorld', 251278, NULL, '/6ZEvjFypBjlqZoUbY11twcd6YAR.jpg', 'CyberWorld', 'A collaboration of computer-animated films which features new characters and old friends from the award-winning Fox network television series, "The Simpsons" and Dreamworks'' feature film "Antz" The saucy, synthetic hostess, Phig, takes the viewers through Cyberworld 3D, a futuristic gallery of wild adventure and spectacular images. Trouble arrives in the form of three unwelcomed guests named Buzzed, Wired and Frazzled who are inadvertently destroying the environment''s foundation, forcing Phig into a hilarious battle to save herself and Cyberworld 3D from total annihilation!', '/uWv23YVkwa0BLHW3YA2bhfEJxgB.jpg', '2000-10-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15912, 'Treasury of Children''s Stories', 773515, NULL, NULL, 'Treasury of Children''s Stories', 'A trio of stars read stories for kids.', NULL, '1996-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
