INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15915, 'Stone', 666906, NULL, NULL, 'Stone', 'A radical ''found-footage'' remake of Diabolique (1996), a remake of the French suspense thriller Les diaboliques (1955). He puts the spotlight back on Sharon Stone, a forgotten film goddess, and perhaps the last real film diva?', '/lpHygQYicwkT6C2BsS0xhuAWy1u.jpg', '2020-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15916, 'The Please Watch the Jon Lovitz Special, Live!', 825678, NULL, '/hI3su9eAijtbArbVCaEd0zPK7d6.jpg', 'The Please Watch the Jon Lovitz Special, Live!', 'A half-hour parody special in the style of Playhouse 90, starring comedian and SNL veteran Jon Lovitz.', '/1FaMbyzVFs3htk7PMyjDEX8zWqd.jpg', '1992-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15917, 'Sharon Stone: Survival Instinct', 1336835, NULL, '/kn8I7tZTMMYOpHjrDZZhV4ooUYR.jpg', 'Sharon Stone, l''instinct de survie', '30 years after Basic Instinct, Sharon Stone is still stigmatized for her role as a sexual psychopath. But the Oscar nominee has always fought against domination. She embodies the independent woman of the 21st century, who refuses to be invisibilized and a "passive" object, subjected only to the male gaze.', '/uzRCOzRskJwQLLlktQq0XQwe8vX.jpg', '2024-08-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15918, 'In Memoriam', 1358448, NULL, NULL, 'In Memoriam', 'A veteran Hollywood actor becomes obsessed with securing a spot in the Oscars’ “In Memoriam” montage after he receives a terminal cancer diagnosis. This leads to a heartfelt journey of self-exploration as well as ego, humility, and legacy.', '/m4RJbZax1UwzmW6WZyDJ1EP1CfW.jpg', '2026-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15919, 'The Battle of Amfar', 186279, NULL, '/qnRQil6wfAtPLMAH4Zd6JOx1pIP.jpg', 'The Battle of Amfar', 'When AIDS struck in the early 1980s, a scientist and a movie star did not have to respond - but they did. Dr. Mathilde Krim and Elizabeth Taylor joined forces to create amfAR, the Foundation for AIDS Research. The fight against HIV has never been the same. The Perfect Host reveals how two powerful and very different women came together, and what their combined efforts achieved. With passion and wit, Taylor wielded celebrity as a weapon against government indifference while Krim''s commitment to science ensured support for the most promising research areas. Today, the only man cured of AIDS can thank research championed by Mathilde Krim. Visually dazzling and emotionally compelling, this story offers a surprising perspective on the still ongoing fight against AIDS.', '/cdPswia1JkVcCxDbXvJXtYkC3Lk.jpg', '2013-01-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15920, 'Scorsese''s Women', 1413222, NULL, NULL, 'Scorsese''s Women', 'Five amazing actresses who have starred in Martin Scorsese''s films come together in imaginary cinematic scenarios. Each leading lady has her own mysterious narrative-and so does each photograph.', '/uAQaIJmKphSJKz4ZpRSKiGHmNRi.jpg', '2014-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15921, 'The Trainer', 956057, NULL, '/Af4Q5zXIffaWLY9puJI7YAKUhuB.jpg', 'The Trainer', 'Jack Flex is broke, buff, and wildly delusional—but he’s got a dream: to sell his absurd invention, the Heavy Hat, on his mom’s favorite shopping channel. When a desperate producer gives him a shot, Jack’s web of lies—celebrity clients, Hollywood fame—starts to unravel. With just one week to turn fiction into fact, he sprints through L.A. in a chaotic quest for credibility, hope, and a shot at stardom.', '/pi9sCv9qTKZtBpPweEk4cdlUov7.jpg', '2024-10-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15922, 'Babies', 1537546, NULL, NULL, 'Babies', 'Struggling with the decision of whether or not to bring a child into the world, Annie and her husband Aaron become instant co-parents when their newly-divorced friend moves into their home with her 4-year-old. An ensemble comedy drama about the journey to parenthood... or not.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15923, 'Hollywood: No Sex, Please!', 702565, NULL, '/9Xhgq4eY4Kq52zVixFmK0Uy75mO.jpg', 'Hollywood: No Sex, Please!', 'Deep rooted religious beliefs seemingly going back to the Pilgrim Fathers'' puritanism dominate a society which is entertained by violence to no end on a daily basis. If it is true that American movies reflect American society, the United States have yet another severe problem: a lack of open sexuality and eroticism.', '/seJCFkWBrIAlnet05zO2Q8CJFlY.jpg', '2018-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15924, 'Celebrity Naked Ambition', 1614826, NULL, '/7pCwq93QXMtANzUJQupb9Avsh2O.jpg', 'Celebrity Naked Ambition', 'Documentary looking at how nudity has been used in the movies, sometimes shrewdly and other times without thought.', '/fHEBPK5Tk3YIZkJyVT12yQvq5ja.jpg', '2003-07-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15925, 'Speed the Plow', 1630679, NULL, NULL, 'Speed the Plow', 'At American Prestige Studios, junior executive Bob Grant is appointed to a head of production role. Grant is emotionally and philosophically unsuited to a job overseeing the production of schlock, but is aided, or impeded, by a studio time server, Charlie Fox; an office temp, Karen; and crazed movie star Gemma Speed.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15926, 'Jews and Buddhism: Belief Amended, Faith Revealed', 1640439, NULL, NULL, 'Jews and Buddhism: Belief Amended, Faith Revealed', 'This film examines the dramatic surge of interest among American Jews in the spiritual teachings of Buddhism. Jews, who make up 2% of the population, account  for some 30% of non-Asian American Buddhists. Many of them are among the leading expositors and scholars of Buddhism in America. In practice, traditional  Jewish ritual and liturgy are being modified in synagogues and among individuals seeking to incorporate the teachings of Buddhism into their spiritual lives.', NULL, '1999-07-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15927, 'Becoming Marilyn', 1011403, NULL, '/iKG9yKOjkAI5tC5I5sgU4T7qcje.jpg', 'Devenir Marilyn', 'The story of how Norma Jeane Mortenson became Marilyn Monroe (1926-62), a lucid path of self-discovery, from anonymity to stardom: the painful birth of a myth.', '/u2DcsCdev5ihVPKeuFEwtBabtsV.jpg', '2022-07-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15928, 'Casa de remolienda', 286082, NULL, NULL, 'Casa de remolienda', 'Concerned about the future of her three children, a widow takes them to the city with the purpose of getting them married.', '/3wiNsLOkh7IK3QWmv06rfyI3W3j.jpg', '2007-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15929, 'Kiltro', 26481, NULL, NULL, 'Kiltro', 'Street tough Zamir has been in love with Kim ever since he rescued her from rapists, but the only way that he can express his affection is to attack any man who shows interest in her. Kim tolerates Zamir''s infatuation, but keeps him at arm''s length. When Max Kalba arrives in town to take vengeance on Kim''s father, Zamir attempts to rescue her once again.', '/55dSTVl28buCnjaSorzDoJbkZf1.jpg', '2006-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15930, 'El vuelo del poeta', 705525, NULL, NULL, 'El vuelo del poeta', 'The life story of Chilean poet Vicente Huidobro who leaves his wife and children in Chile and flees to Paris in order to devote himself to poetry.', NULL, '2009-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15931, 'Rendition', 5125, NULL, '/hVgbeqLYbbrT23pryiR0Oz009CM.jpg', 'Rendition', 'When an Egyptian terrorism suspect "disappears" on a flight from Africa to Washington DC, his American wife and a CIA analyst find themselves caught up in a struggle to secure his release from a secret detention facility somewhere outside the US.', '/uW8gNhIJkNabd0AIafWqFRxB8Os.jpg', '2007-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15932, 'Moonlight Mile', 31005, NULL, '/53f29bdN46K7UT17OCYQ0sBZBdm.jpg', 'Moonlight Mile', 'As he copes with the death of his fiancee along with her parents, a young man must figure out what he wants out of life.', '/jKDnCPUkL4QsgeqKCtyNMPL2XUU.jpg', '2002-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15933, 'Proof', 9777, NULL, '/7WW1qhOdDzYWmjmhIwVt8lc9FCJ.jpg', 'Proof', 'Catherine is a woman in her late twenties who is strongly devoted to her father, Robert, a brilliant and well-known mathematician whose grip on reality is beginning to slip away. As Robert descends into madness, Catherine begins to wonder if she may have inherited her father''s mental illness along with his mathematical genius.', '/h5z4JWhaPYMMXhYzwuK7SUgjmMm.jpg', '2005-09-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15934, 'The Good Girl', 9962, NULL, '/hVJpiirgqfgsW82QVsea5s6I5gy.jpg', 'The Good Girl', 'A discount store clerk strikes up an affair with a stock boy who considers himself the incarnation of Holden Caulfield.', '/jpRumFobwgPzxj5YH33Wswnxdam.jpg', '2002-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15935, 'Lucid Dreams: The Making of Enemy', 1111185, NULL, NULL, 'Lucid Dreams: The Making of Enemy', 'The cast and crew of ''Enemy'' guide the audience through the making of the film and the possible meanings behind its enigmatic imagery.', '/dX3c5PgphiBktDEYf6P7tHlVI8a.jpg', '2014-06-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15936, 'Heath Ledger: A Tribute', 789323, NULL, NULL, 'Heath Ledger: A Tribute', 'On January 22, 2008, the entertainment world was rocked by news that one of its brightest young stars had unexpectedly died. This film is a commemorative special dedicated to the life and works of this complex and unique talent who died before his time.', '/x1eJojaMe9N0y0qg5yRRWEjYJxa.jpg', '2009-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15937, 'Highway', 18808, NULL, '/8cwxKDaTK0i4XC3UAm3h284bsIT.jpg', 'Highway', 'Jack is caught with the wife of his employer, a Vegas thug. The thug sends goons after Jack, who convinces his best friend, Pilot, to flee with him. Pilot insists that they head for Seattle, but doesn''t tell Jack why. The goons learn from Pilot''s drug source where the youths are headed, and they follow, hell bent on breaking Jack''s feet. On the road, Jack and Pilot give a ride to Cassie, a distressed young woman. She and Jack hit it off. They pick up an aging stoner headed to Seattle for Kurt Cobain''s memorial, and they help a circus sideshow family. Why is Pilot so set on Seattle, will the goons catch Jack, and is there any way the friends'' competing needs can be resolved?', '/jttL1E4eCQn7tHBbYlUkMz865Q4.jpg', '2002-03-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15938, 'Lovely & Amazing', 50035, NULL, '/k61yNqKbQjokBZh2bvmXjieuSnH.jpg', 'Lovely & Amazing', 'An intimate family portrait of four hapless but resilient women and the bittersweet lessons they learn in keeping up with the hectic demands of their individual neuroses. Each of the women seeks redemption in her own haphazard way, but whatever salvation they find is illusory and short-lived.', '/4HZ7Y7N4KHapO5ylOY8BePQYC5X.jpg', '2002-08-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15939, 'Deus ex Machina: The Philosophy of ''Donnie Darko''', 441636, NULL, NULL, 'Deus ex Machina: The Philosophy of ''Donnie Darko''', 'The feature-length documentary about the making of the cult film favourite, "Donnie Darko".', '/oIXYsUMMvKBZoqN7iHmtPFTWuJS.jpg', '2016-12-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15940, 'Accidental Love', 316002, NULL, '/rFoRdUFIHQhWRX9ZXK79uilOSWO.jpg', 'Accidental Love', 'A small town waitress gets a nail accidentally lodged in her head causing unpredictable behavior that leads her to Washington, DC.  Sparks fly when she meets a clueless young senator who takes up her cause - but what happens when love interferes with what you stand for?', '/znPsDmQVKW0BuBnaErIAPo49X3i.jpg', '2015-02-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15941, 'Road House 2', 1290379, NULL, NULL, 'Road House 2', 'The sequel to the 2024 reboot. Plot TBA.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15942, '12-12-12 | The Concert for Sandy Relief', 149922, NULL, '/2AINW4lU49rKz3Jld2JkvXoa2E9.jpg', '12-12-12 | The Concert for Sandy Relief', '“12-12-12” was a fundraising concert to aid the victims of Hurricane Sandy, it took place on December 12, 2012 at Madison Square Garden. The concert featured Bon Jovi, Eric Clapton, Dave Grohl, Billy Joel, Alicia Keys, Chris Martin (featuring Michael Stipe), The Rolling Stones, Bruce Springsteen & the E Street Band, Eddie Vedder, Roger Waters, Kanye West, The Who, Paul McCartney (featuring Nirvana) as well as other artists.', '/mMmU4hFipk3Ekc6M4Py6YF1yZuz.jpg', '2012-12-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15943, 'Wildlife', 417812, NULL, '/nrzKvKLEOYWFEi3iWefST8EKgga.jpg', 'Wildlife', '14-year-old Joe is the only child of Jeanette and Jerry — a housewife and a golf pro — in a small town in 1960s Montana. Nearby, an uncontrolled forest fire rages close to the Canadian border, and when Jerry loses his job (and his sense of purpose) he decides to join the cause of fighting the fire, leaving his wife and son to fend for themselves.', '/hQSUwjSSRtWCA5EBoY22gGzaE8Y.jpg', '2018-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15944, 'Moonlight Mile: A Journey to Screen', 939822, NULL, '/p2LhgbEnAnGyf7FPSUKK7oW11Iu.jpg', 'Moonlight Mile: A Journey to Screen', 'Showing the journey to the creation of the film Moonlight Mile.', '/2VLOu3rRxtDjy5o2b6UJHBRpz7S.jpg', '2003-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15945, 'Jake Gyllenhaal Challenges the Winner of the Nobel Peace Prize', 265648, NULL, NULL, 'Jake Gyllenhaal Challenges the Winner of the Nobel Peace Prize', 'A remixed narrative that combines two Jake Gyllenhaal films (Donnie Darko and Jarhead) with news footage of former President Barack Obama.', '/395Xzxm0CJyKnEDzBY3GLmd37F6.jpg', '2010-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15946, 'A Dangerous Woman', 108021, NULL, '/1aTT2UJEaN1KWJp8priMxsGsDnT.jpg', 'A Dangerous Woman', 'Martha Horgan is a withdrawn, mentally disabled woman who lives with her aunt, Frances. One of Martha''s unusual traits is that she doesn''t lie, a quality that leads to her getting fired from a dry-cleaning shop thanks to the actions of the shifty Getso. Conflict seems to follow Martha, since she also becomes romantically involved with local fix-it man, Mackey, who is sleeping with Frances as well.', '/wsRHmHgio3w5nR5W2brn5VQ2oe4.jpg', '1993-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15947, 'Homegrown', 17133, NULL, '/i72JysXqxwdDX7vgZDQwsAbI3QK.jpg', 'Homegrown', 'Three laborers on a Northern California marijuana plantation become increasingly paranoid when they learn that their boss has been murdered. They know enough to run, taking with them enough of the crop to pay them for services rendered. Hooking up with go-between Lucy in the next town, they plot their next move.', '/feQeYHriKLCjzkUEjg4D81ggyYs.jpg', '1998-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15948, 'The Man Who Walked Between the Towers', 256787, NULL, '/ph7LtaoJ2WBO62sIAxIaoKIT13x.jpg', 'The Man Who Walked Between the Towers', 'One of the most exciting and memorable stories in the history of the World Trade Towers is that of Philippe Petit, a French man who walked a tightrope between the massive monuments in 1974. Narrated by Oscar nominee Jake Gyllenhaal, this is an animated adaptation of the lyrical Caldecott Award-winning book by Mordecai Gerstein. Directed and animated by Michael Sporn, with music by Michael Bacon (of the Bacon Brothers).', '/xK9NfoxGbEdhulAZOQN9y4Ckyqr.jpg', '2005-04-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15949, 'Josh & S.A.M.', 48706, NULL, '/eXHznh4SCFOAaU92Ix23rBnzKEG.jpg', 'Josh & S.A.M.', 'Josh and Sam are two brothers facing change, their mother is about to marry a French accountant and the kids are sent to go live with their father in Florida. Meanwhile, Josh tells Sam that he is a "S.A.M." that is going to be sent to Africa to fight in a war and that Canada is a safe haven for any S.A.M. unwilling to fight. Will Josh & S.A.M. make it to Canada or will they wish they should have never left home?', '/dWggqpyiZzhvpIyef5ZPB4Lsscu.jpg', '1993-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15950, 'Abby Singer', 499117, NULL, NULL, 'Abby Singer', 'Chronicles the life of Curtis Clemins, who is torn between the love of his life and accomplishing his dream. When hitting rock bottom during the Sundance Film Festival, Clemins'' calls upon his old college chum, Kevin Prouse, giving the now drunken acting instructor in the throes of a divorce, the only clue that will salvage Clemins'' rapidly deteriorating life.', '/wfWSRcQRmEw3u5myacurSf57M8x.jpg', '2003-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15951, 'John Mulaney & The Sack Lunch Bunch', 650073, NULL, '/9O4qARYvsuCVTtw8ybLIQNTywTO.jpg', 'John Mulaney & The Sack Lunch Bunch', 'John Mulaney and his kid pals tackle existential topics for all ages with catchy songs, comedy sketches and special guests in a nostalgic variety special.', '/rP8knLNDHN6VlUi89nWuqaWUdoo.jpg', '2019-12-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15952, 'One Night Only: The Best of Broadway', 775038, NULL, '/9HPsegHGqRY76HtLECqJHrLNU8E.jpg', 'One Night Only: The Best of Broadway', 'Tina Fey is set to host One Night Only: The Best of Broadway, an unforgettable night of music celebrating the incredible and resilient Broadway community and featuring songs from the Great Bright Way’s top productions. The two-hour special is set to air Thursday, December 10, at 8 pm ET/PT on NBC and benefits Broadway Cares.  Several of Broadway’s best shows will take over the streets of New York City with special performances from the casts of Ain’t Too Proud – The Life and Times of the Temptations, Chicago, Diana: The Musical, Jagged Little Pill, Jersey Boys, Mean Girls, Rent and an appearance by the cast of Harry Potter and the Cursed Child. The night will also showcase special sneak peaks at Broadway shows coming in 2021.', '/fEVlD42aMtK39kLujvboUG21xy0.jpg', '2020-12-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
