INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15958, 'Time to Dance', 1427145, NULL, '/mlmNLHc4Y8dBx0YEJY6PT1CnlU5.jpg', 'Time to Dance', 'A serial killer played by Jake Gyllenhaal travels through the hippest parties on a killing spree of Dalston hipsters. Gyllenhaal masters the role of unsuspecting dark-eyed psycho as he pumps iron and gums drugs preparing for his next beautifully fashionable victim. Transforming a music video into magnificently dramatic cinema, director Daniel Wolfe has captured contemporary London in a shockingly addictive modern slasher.', '/mdedDUDxJk1GNXZURt11f6azQDC.jpg', '2012-04-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
