INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15961, 'Raoul Wallenberg: Missing Inaction', 1563656, NULL, '/m5Fsa4sOTvFmwnIKSSlDVDkQcy4.jpg', 'Raoul Wallenberg: Missing Inaction', 'Raoul Wallenberg was the scion of Sweden''s wealthiest dynasty, a diplomat and hero who saved more than 100,000 Jews from the Holocaust in an undercover American-financed mission within Nazi occupied Budapest. But in the final hours of WWII, Raoul was arrested by the "liberating" Soviet Red Army, sent to Moscow and vanished into Russian KGB prison system, never to be seen again. The question still haunts the world: what happened to Raoul Wallenberg?', '/afNY1zBNbnkNF4ZLydLNxYlTNxt.jpg', '2025-09-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
