INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15972, 'Browncoats Unite: Firefly 10th Anniversary Special', 143216, NULL, '/qZXIloRloLaqugztl5JAYdp69lQ.jpg', 'Browncoats Unite: Firefly 10th Anniversary Special', 'Science Channel reunites Joss Whedon, Nathan Fillion and the entire renegade crew of the Serenity for the first time ever to provide the complete oral history on the franchise that continues to explode in popularity — despite meeting its end a decade ago. The 60-minute special includes secrets from the set, exclusive cast interviews, and footage from this year''s colossal Comic-Con panel that dominated the pop culture conversation.', '/2lkSVoeoK7xbIn7DF9Ok5wZ0vib.jpg', '2012-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:56', 0);
