INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15988, 'Johnny Handsome', 505, NULL, '/3rJ0EjEh1nlXY8TlA2f26jlCoom.jpg', 'Johnny Handsome', 'A career criminal who has been deformed since birth is given a new face by a kindly doctor and paroled from prison. It appears that he has gone straight, but he is really planning his revenge on the man who killed his mentor and sent him to prison.', '/ec0fMt4CwtWJ0VxeJr9nnhdS867.jpg', '1989-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15989, 'Sniff', 872137, NULL, NULL, 'Sniff', 'A retired detective is pulled back into the action by his former partner, they uncover a hidden underworld of sex, drugs and murder in the wealthy community controlled by kingpin Harvey Stride, and his femme fatale enforcer.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15990, 'The Contract', 1441, NULL, '/btd9VPSfnVh0pHZqbiUJLsOkBDf.jpg', 'The Contract', 'Attempting to recover from a recent family trauma by escaping into the woods for a peaceful hiking trip, an ex-lawman and his young son stumble across a dangerous contract killer.', '/sU2yzV3T1LetBdQPAeBRDb4YwLo.jpg', '2006-04-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15991, 'Under Suspicion', 10562, NULL, '/yedYIJC9lg5V3eGXQJlDNGJxTB5.jpg', 'Under Suspicion', 'A lawyer is asked to come to the police station to clear up a few loose ends in his witness report of a foul murder. "This will only take ten minutes", they say, but it turns out to be one loose end after another, and the ten minutes he is away from his speech become longer and longer.', '/2snkCKKthT5S8Ua0aMZkeaXkmBi.jpg', '2000-08-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15992, '10 Items or Less', 2357, NULL, '/uXFmUOVUvw2coUYSCQu3Z4AnKCd.jpg', '10 Items or Less', 'An actor who is considering the role of a supermarket manager arrives at a grocery store on the outskirts of Los Angeles to do some field research. He subsequently becomes stranded, without a car or cell phone, and accepts a ride home with Scarlet, a cashier who is about to interview for a new job. The actor rediscovers the essence of his craft while helping Scarlet gain the confidence she needs to change her life.', '/2MBxFTeRe4m7DC49PmIkMXMjMEO.jpg', '2006-09-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15993, 'Nurse Betty', 10480, NULL, '/8ZquU1oL90wNowQeXaXx7xPk7vZ.jpg', 'Nurse Betty', 'What happens when a person decides that life is merely a state of mind? If you''re Betty, a small-town waitress and soap opera fan from Fair Oaks, Kansas, you refuse to believe that you can''t be with the love of your life just because he doesn''t really exist. After all, life is no excuse for not living. Traumatized by a savage event, Betty enters into a fugue state that allows -- even encourages -- her to keep functioning... in a kind of alternate reality.', '/1OCHR9z9k7go669AsShOkTj4CFb.jpg', '2000-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15994, 'Levity', 21052, NULL, '/x0eVAQeg2XplCx8MQlvhtejtVag.jpg', 'Levity', 'Manuel Jordan is a man who is free after serving 23 years for killing a teenager during an attempted robbery. After nearly two decades of staring at his victim''s face on a newspaper clipping in his cell, the newly paroled man seeks redemption. Instead, redemption—in the form of a mysterious minister and two needy women— finds him.', '/pLmF3LChsgxkF6dCBN0aHJR91Gu.jpg', '2003-03-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15995, 'Follow the Drinking Gourd', 357320, NULL, '/uSjN8pW2KxGhSlNzolxOmuWITdf.jpg', 'Follow the Drinking Gourd', 'Based on the traditional American folksong, this compelling tale recounts the daring adventures of one family''s escape from slavery via the Underground Railroad. This touching story captures all the drama of a perilous flight to freedom. Narrated by Morgan Freeman.', '/iVZ8SQ9e4bnweMInfDdQ59uhKmx.jpg', '1990-09-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15996, 'Teachers', 31601, NULL, '/tFgZqPvW1XBnjBaizxuPfmydOcn.jpg', 'Teachers', 'A teacher reconnects with an old student who is now an attorney representing a family who is suing the school for graduating their son who still cannot read or write.  Amid the daily chaos of teaching in an inner city school, Alex Jurel tries to decide if he will lie at his deposition to protect the school or tell the truth and risk throwing away his career.', '/foWZXdAeNtMubNrjYqSni6iDuVp.jpg', '1984-10-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15997, 'The Maiden Heist', 24271, NULL, '/ihURVgowKHaXGBsl8ltglt4numm.jpg', 'The Maiden Heist', 'A comedy centered on three museum security guards who devise a plan to steal back the artworks to which they have become attached after they are transferred to another museum.', '/vrp0dqlp74A02YaUiwNpLElgTR0.jpg', '2009-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15998, 'Eyewitness', 31679, NULL, '/84hrHsxKSTY16nQl5KRMQ9GVvx2.jpg', 'Eyewitness', 'NYC custodian Daryll Deever is a big fan of local news reporter Tony Sokolow, so he is intrigued when she shows up to cover a story at his workplace. There''s been a murder in the office building, and Tony suspects that Daryll may have insight into the crime, a notion that he furthers to stay close to her. However, when those behind the killing begin to think that he really knows something, they target the pair to keep their secrets hidden.', '/dxMbBWegmjtPfZNmw6HHJjgZkQt.jpg', '1981-02-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (15999, 'The Hunting of the President', 26254, NULL, NULL, 'The Hunting of the President', 'Previously unreleased material outlines the campaign against Bill Clinton''s presidency, from his days in Arkansas up to his impeachment trial.', '/2BcSbP8gjmCsCnugxPAM7dAmhUd.jpg', '2004-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16000, 'Shelter from the Storm: A Concert for the Gulf Coast', 949439, NULL, '/mqeV7XUR9NtqqHD9uLRoj0YPwKO.jpg', 'Shelter from the Storm: A Concert for the Gulf Coast', 'A one-hour, commercial-free benefit concert television special that aired simulcast worldwide on September 9, 2005, at 8 pm ET/CT live.', '/fapVrp46shZouhHtcYmxutARsfM.jpg', '2005-09-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16001, 'The Big Bounce', 12634, NULL, '/3ERk0cT9GIfxv6ULs2XZV3wgvEU.jpg', 'The Big Bounce', 'A small-time con artist and a Hawaiian real estate developer''s mischievous, enterprising mistress team up for a potential $200,000 score.', '/l6tzLXXGubnC6TbFgg8acfcvGRO.jpg', '2004-01-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16002, 'The People Speak', 34158, NULL, '/v1LF8Qedjc6GjRP6xjK6875hVhF.jpg', 'The People Speak', 'A look at America''s struggles with war, class, race and women''s rights. based on Howard Zinn''s "A People''s History of the United States."', '/bRGRNm0NCwKKI0kamQUYQWR8cXR.jpg', '2009-12-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16003, 'The Power of One', 13823, NULL, '/obRnxaCL74Wp2z3nqufIBnbfP95.jpg', 'The Power of One', 'PK, an English orphan terrorized for his family''s political beliefs in Africa, turns to his only friend, a kindly world-wise prisoner, Geel Piet. Geel teaches him how to box with the motto “fight with your fists and lead with your heart”. As he grows to manhood, PK uses these words to take on the system and the injustices he sees around him - and finds that one person really can make a difference.', '/k7RIsoUQb0F1X8mb3YvPr7F8ot5.jpg', '1992-03-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16004, 'Death of a Prophet', 42141, NULL, '/d7voks94AQLo2SUIrG3Ti5HYFZm.jpg', 'Death of a Prophet', 'After breaking ties with the Nation of Islam, Malcolm X became a man marked for death...and it was just a matter of time before his enemies closed in. Despite death threats and intimidation, Malcolm marched on - continuing to spread the word of equality and brotherhood right up until the moment of his brutal and untimely assassination. Highlighted by newsreel footage and interviews, this is the story of the last twenty-four hours of Malcolm X. Featuring the music of jazz percussionist Max Roach.', '/sGDfnH99iQ3X4qweXRVXK0d5SJU.jpg', '1981-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16005, 'Clean and Sober', 14441, NULL, '/awVbKi9qebgdC8IjZ77ruvciY2x.jpg', 'Clean and Sober', 'Hotshot real estate salesman Daryl has a bad cocaine habit. After embezzling his company''s money, he wakes up next to a girl who overdosed. To hide from the police, he checks into a rehabilitation program guaranteeing anonymity. Under the mentorship of counselor Craig, Daryl accepts that he has a substance abuse problem. As he falls in love with fellow patient Charlie, Daryl begins committing to a newly sober life.', '/cU2VrB1SbKg3WypvK2Z0u1jLQEK.jpg', '1988-08-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16006, 'Feast of Love', 14313, NULL, '/krC37EnKGPLTa1MMEVpi45wicDc.jpg', 'Feast of Love', 'A meditation on love and its various incarnations, set within a community of friends in Oregon. It is described as an exploration of the magical, mysterious and sometimes painful incarnations of love.', '/6Uyl94M1Yi8U0o6GddMRqAfa466.jpg', '2007-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16007, 'Thick as Thieves', 14979, NULL, '/de49MfZzcVWpBl84NJGxmwc9PgZ.jpg', 'Thick as Thieves', 'A master thief recruits a notorious thief to help him steal two famous Faberge eggs from an impenetrable vault in an effort to pull off one final job and repay his debt to the Russian mob.', '/4TOJiqayrIZQGtmmGjM3d7lp5gM.jpg', '2009-01-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16008, 'Prom Night in Mississippi', 61896, NULL, '/vHJjDcjfj95ouMSI50H7pH4wnQw.jpg', 'Prom Night in Mississippi', 'A high school in a small-town in Mississippi prepares for its first integrated senior prom.', '/sdfKAfREemylAY7Xyb0JoNRkWoY.jpg', '2009-01-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16009, 'Dolphin Tale', 62837, NULL, '/y0GUZoM63hT4HTKyUbQbsaP8yIT.jpg', 'Dolphin Tale', 'A sea of animal rescuers — and a lonely boy in need of a friend – nurse an injured dolphin back to health after it loses its tail in a trap.', '/af2SRFllNW26WFG84AfTv3xLT5t.jpg', '2011-09-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16010, 'Guilty by Association', 38292, NULL, '/lzZRFwaIx6u4K9jbyINfNTRplOp.jpg', 'Guilty by Association', 'There is no honor without truth. When gang wars spin out of control in downtown Washington D.C., one man steps onto the battlefirld to hunt down a ruthless killer. A young man has been released from prison and is determined to build a new life for himself. Unfortunately, without any prospects in sight, he gets lured back into the only world he knows....crime. He gets in touch with his former best friend who has since "made it big" as a drug dealer during his time in prison. But what starts out as a partnership which promises to get them both out of the projects, soon turns rotten as money comes between the two. As loyalties are divided, anger and violence erupt... destroying anyone who gets in the way. Innocent victims get caught in the crossfire and its up to one man, Police Lieutenet Redding (Morgan Freeman) to take matters into his own hands and stop the needless deaths before it''s too late.', '/4MpeaVbZk7nirk9Jbf2pSB2cRVT.jpg', '2003-07-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16011, 'That Was Then... This Is Now', 64945, NULL, '/dBs5MsoH2RGvBzeSN6GfwhxYBw0.jpg', 'That Was Then... This Is Now', 'A delinquent teenager''s only link to society is the attachment he feels towards an older brother-figure. When the older boy starts spending time with a new girlfriend, the teenager begins to feel even more alienated, and gets involved with drugs and the police.', '/9uXl1EtvGo9qBPdtsJqwEcuckAZ.jpg', '1985-11-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16012, 'Betty White: A Celebration', 921890, NULL, '/awelvzPr81PanE2pRUUeNvcJC1U.jpg', 'Betty White: A Celebration', 'A documentary focusing on the life of actress and comedian Betty White.', '/eVkeP8Cc2p6afVBTw2y1ETiQjqx.jpg', '2022-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16013, 'Moll Flanders', 18989, NULL, '/m6Si2vwNCorETZape82t6iuxTj3.jpg', 'Moll Flanders', 'The daughter of a thief, young Moll is placed in the care of a nunnery after the execution of her mother. However, the actions of an abusive priest lead Moll to rebel as a teenager, escaping to the dangerous streets of London. Further misfortunes drive her to accept a job as a prostitute from the conniving Mrs. Allworthy. It is there that Moll first meets Hibble, who is working as Allworthy''s servant but takes a special interest in the young woman''s well-being. With his help, she retains hope for the future, ultimately falling in love with an unconventional artist who promises the possibility of romantic happiness.', '/lHVpzsvjLU7qSCB8UWFqIAavSRu.jpg', '1996-06-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16014, 'Born to Be Wild', 50081, NULL, '/lGfrl0eF189HifRGYPumrGUAqkt.jpg', 'Born to Be Wild', 'Born to Be Wild observes various orphaned jungle animals and their day-to-day behavioural interactions with the individuals who rescue them and raise them to adulthood. The film unfurls in two separate geographic spheres. Half of it takes place in the rain forests of Borneo, where celebrated primatologist Dr. Birute Galdikas assists baby orangutans; the other half takes place on the arid savannahs of Kenya, where zoologist Dame Daphne Sheldrick works with baby elephant calves.', '/78qdFtASdnBSOiqSvazDgxGcQHk.jpg', '2011-04-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16015, 'Resting Place', 71741, NULL, '/3Ui0oiDP0gwdivzy02pcmQriHMq.jpg', 'Resting Place', 'A television movie set in Rockville, Georgia, in 1972. Major Kendall Laird, a Survival Assistance Officer, arrives in this sleepy little town with the body of Lieutenant Dwyte Johnson, a Vietnam war hero. It''s Laird''s job to help Johnson''s parents bury their son. But since the dead hero was black, his parents are turned away by the white racists who maintain the town''s "all-white" cemetery.', '/dv0wGog8xcdJQ8wN2ADuNOXj1he.jpg', '1986-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16016, 'The Minute You Wake Up Dead', 934641, NULL, '/kg1nZdetR4cmosDieXJ2D2zhmj0.jpg', 'The Minute You Wake Up Dead', 'A stockbroker in a small southern town gets embroiled in an insurance scam with a next-door neighbor that leads to multiple murders when a host of other people want in on the plot. Sheriff Thurmond Fowler, the by-the-book town sheriff for over four decades, works earnestly to try and unravel the town’s mystery and winds up getting more than he bargained for.', '/pUPwTbnAqfm95BZjNBnMMf39ChT.jpg', '2022-11-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16017, 'Harry & Son', 91767, NULL, '/nIWyiZD1fYXytFoLzcM5GWoTiE0.jpg', 'Harry & Son', 'Widower Harry Keach is a construction worker who was raised to appreciate the importance of working for a living. He takes a dim view of his sensitive son Howard''s lackadaisical lifestyle and has a strained relationship with his daughter Nina as he does not approve of her husband. When Harry is fired from his job, his life changes drastically as he is made to focus on the relationships around him.', '/kl9yUlWRBEyXNGIXav1WIRBy5te.jpg', '1984-03-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16018, 'The Blues Live On! The Delta Blues Museum', 935916, NULL, NULL, 'The Blues Live On! The Delta Blues Museum', 'Located in an old depot in Clarksdale, Mississippi, where Muddy Waters boarded the train to carry the Blues to the world, this small museum tells the powerful story of the origins of the Delta Blues and its ultimate transformation into Rock-n-Roll. Interviews include actor and native son, Morgan Freeman and blues artists Charlie Musselwhite and “Super Chikan” Johnson. Featured are Muddy Waters’ sharecropper cabin; Sonny Boy Williamson’s harmonicas; B.B. King’s guitar, “Lucille;” and the annual Sunflower River Blues festival, which brings together rising talents and established stars of America’s most enduring music.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16019, '761st Tank Battalion: The Original Black Panthers', 1134108, NULL, '/2J9RRT5PFoWr09qYVmu5t8QeQfG.jpg', '761st Tank Battalion: The Original Black Panthers', 'The riveting story of the first all-Black tank battalion to fight in US military history. Under General George Patten''s command, the 761st fought heroically throughout WWII and were the furthest east of all US troops in the European theater of war.', '/1lGtS2Bu01Kx0U4wnNz5sYBxfMB.jpg', '2023-08-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16020, 'Betty White''s 90th Birthday: A Tribute to America''s Golden Girl', 85088, NULL, NULL, 'Betty White''s 90th Birthday: A Tribute to America''s Golden Girl', 'A special Betty White''s 90th Birthday Party aired on NBC a day before the star''s birthday on January 16, 2012. The show featured appearances of many stars with whom White has worked over the years', NULL, '2012-01-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16021, 'Paradise Highway', 939979, NULL, '/vC0tDDqSDY0ApO5qyzyGcGSM8jp.jpg', 'Paradise Highway', 'A truck driver has been forced to smuggle illicit cargo to save her brother from a deadly prison gang. With FBI operatives hot on her trail, Sally''s conscience is challenged when the final package turns out to be a teenage girl.', '/2ahZgaFAbWoKMfJHhmhZDrdStgD.jpg', '2022-07-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16022, 'Marie: A True Story', 87400, NULL, '/wK16A2JRPvhQ0COMBcLND0B2rE4.jpg', 'Marie: A True Story', 'In 1978 Tennessee, a single mother and political appointee risks her career and her life to blow the whistle on rampant corruption in the penal system.', '/ulZH8aa972yRBDnbbt07LCvHjDd.jpg', '1985-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16023, 'Breaking the Taboo', 79893, NULL, '/jVmx9xKDEBUZbDP9cQT8zu221Bg.jpg', 'Quebrando o Tabu', 'Narrated by Morgan Freeman, this groundbreaking new documentary uncovers the UN sanctioned war on drugs, charting its origins and its devastating impact on countries like the USA, Colombia and Russia. Featuring prominent statesmen including Presidents Clinton and Carter, the film follows The Global Commission on Drug Policy on a mission to break the political taboo and expose the biggest failure of global policy in the last 50 years', '/vOpX1BZwvyrQ0ZpijcXHLvVfRAr.jpg', '2011-06-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16024, 'The Magic of Belle Isle', 101731, NULL, '/fM4TVNg27IBCYAz8FUiLefWck1p.jpg', 'The Magic of Belle Isle', 'In an effort to tap into his original talent, a wheelchair-bound author moves to a rural town, where he befriends a single mother and her three kids, who help reignite his passion for writing.', '/imoZLjmCnfG4f69Dq0f2Zsr9XOR.jpg', '2012-07-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16025, 'Panama Canal in 3D a Land Divided a World United', 1144811, NULL, NULL, 'Panama Canal in 3D a Land Divided a World United', 'Through the magic of 3D and IMAX cameras, audiences everywhere can take a mind-blowing trip through one of the seven wonders of the modern world in PANAMA CANAL 3D: A LAND DIVIDED A WORLD UNITED, revealing not only its vast scope, but plunging down into the locks and mechanical operations, boarding the giants sailing the Canal, gliding airborne over the entire country, the Panama railway, exploring by native canoe, discovering the unexpected tropical rain forest beauty and wildlife. The film sweeps from the days when Conquistadores struggled through a water-soaked quagmire to the 19th-Century French canal-digging debacle to the American engineering achievement that revolutionized shipping and tropical medicine. It''s also about the visionary present, documenting efforts by Panama to expand the 100-year-old waterway to accommodate post-panamax ships. It concludes with a fusion of old and new Panama, its skyscrapers, its culture, a rising economic nerve of Central America.', '/w0yfBubQLWftLLkGlMBgYSSvRxG.jpg', '2019-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16026, 'Clinton and Nadine', 104535, NULL, '/cMdVVErJQ21ebj01yRp2Bgn7AGO.jpg', 'Clinton and Nadine', 'Eager to find his brother''s murderer, Clinton enlists the aid of Nadine, an expensive call girl. Together they get sucked into a plot to smuggle guns to the Contra forces in Nicaragua.', '/xmvMrYbrcslR7t1lQJ9fLi1MbVI.jpg', '1988-05-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16027, 'Inside the White House', 126286, NULL, NULL, 'Inside the White House', 'Featuring behind-the-scenes footage and unprecedented access to its hallowed halls, this program from National Geographic takes viewers on an in-depth tour of 1600 Pennsylvania Avenue -- the White House. Interviews with presidents and first ladies offer a revealing look at what goes into running that famous household, and White House employees give viewers a taste of the preparations involved in hosting a state dinner.', '/6cMLac59ByzH4npXXcbBUJTeNoD.jpg', '1996-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16028, 'The True Story of Glory Continues', 150346, NULL, NULL, 'The True Story of Glory Continues', 'Morgan Freeman narrates this documentary that explores the 54th Massachusetts regiment that is the basis of the motion picture, "Glory".', '/iTmTEBxEeWvs6RGDHpDlnXBO3T8.jpg', '1991-06-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16029, 'The Eastwood Factor', 155060, NULL, '/4RsHxjR55EPgJUZ6ETFnA1Wv9u9.jpg', 'The Eastwood Factor', 'For 35 years Clint Eastwood has called Warner Bros. home. In The Eastwood Factor, film historian Richard Schickel ventures beyond Eastwood’s tough, iconic screen personas to reveal the easygoing and thoughtful man behind the magic. Morgan Freeman narrates this insightful profile that features memorable film clips and visits to movie locations, the Warner Bros. lot and Eastwood’s hometown Carmel where, with humor, candor and intelligence, Eastwood illuminates the craft behind his legendary work on both sides of the camera to create a rare experience that is pure, unadulterated Clint.', '/ok7Hjh5O5ynfnYv4Z498MNDqVk7.jpg', '2010-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16030, 'The Execution of Raymond Graham', 153076, NULL, '/fcjuh9nc8t5hDDUHT8V8LCX2y5W.jpg', 'The Execution of Raymond Graham', 'A young man, convicted of the murder of a clerk, who has been on death row for five years and now awaits his execution while his family desperately seek a reprieve.', '/oCpa6WATfhkRnrPcMjzk7tvG4Hf.jpg', '1985-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
