INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16032, 'The Little Bedroom', 1158401, NULL, NULL, 'The Little Bedroom', 'Follows Edmond, a man recovering in a facility after taking a bad fall. He finds out that his son has sold his apartment, so he leaves with a nurse to her home so that he can reclaim his autonomy.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
