INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16035, 'JFK: A President Betrayed', 238827, NULL, '/9dBvYUtQrHL7JXmWW0hNZWIkaET.jpg', 'JFK: A President Betrayed', 'Narrated by Academy Award winner Morgan Freeman, "JFK: A President Betrayed" uncovers new evidence that reveals how JFK embarked on secret back channel peace efforts with Nikita Khrushchev and Fidel Castro and was determined to get out of Vietnam despite intense opposition inside his own government.', '/mPa2jhPTEbSy4ra3AjykWDmOm56.jpg', '2013-11-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
