INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16048, 'Echoes ''Cross the Tracks', 420786, NULL, '/qnBbod6AJfaBDV8vNsFX9ixcITY.jpg', 'Echoes ''Cross the Tracks', 'A powerful documentary starring Morgan Freeman about the genesis of The Blues in the South and the music spreading around the world. Morgan Freeman shares his story of his experience of growing up in Clarksdale, Mississippi and his love for the Blues.', '/kEnQF3aaEAI6b1NJMlh8yKTVEcM.jpg', '2012-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16049, 'My Dead Friend Zoe', 1128505, NULL, '/umx11EgTkJJNe8a5TrhLrNOgN9t.jpg', 'My Dead Friend Zoe', 'Merit, a U.S. Army veteran suffering from PTSD, is repeatedly tortured by visions of her deceased friend and company buddy Zoe. After her Afghanistan service in 2016, she attends group therapy until Dale, her grandfather and former Lieutenant Colonel, is recently diagnosed with Alzheimer''s. Merit steps up to his aide, and discovers more about herself and her family, while also gaining the courage to put her metaphorical demons to rest.', '/bRoDBpwGU5UW03hQMExN2l92Q93.jpg', '2024-03-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16050, 'Laddie: The Man Behind the Movies', 322525, NULL, NULL, 'Laddie: The Man Behind the Movies', 'Profile of the producer and former studio head of 20th Century Fox in the 1970s, Alan Ladd Jr.', '/in4tn7sdKX2sqTQ9yfVmuMV9yHu.jpg', '2017-11-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16051, 'The Editor and The Dragon: Horace Carter Fights the Klan', 244910, NULL, NULL, 'The Editor and The Dragon: Horace Carter Fights the Klan', 'In 1953, Horace Carter earned a Pulitzer Prize for Meritorious Public Service for his reporting on the Ku Klux Klan.  Carter persevered in the face of death threats, including those against his family, and used the editorial authority of North Carolina''s TABOR CITY TRIBUNE to protest the Klan''s racist rhetoric and vigilantism.  Carter''s bold reporting and the unwavering integrity of his editorials helped lead to the first federal intervention in the south during that era and to the arrest and conviction of nearly 100 klansmen.', NULL, '2013-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16052, 'Momentum', 346808, NULL, '/7nYZxYAb1vkLd1a5i7qDcH5kBsK.jpg', 'Momentum', 'When Alex, an infiltration expert with a secret past, accidentally reveals her identity during what should have been a routine heist, she quickly finds herself mixed up in a government conspiracy and entangled in a deadly game of cat-and-mouse with a master assassin and his team of killers.  Armed with her own set of lethal skills, Alex looks to exact revenge for her murdered friends while uncovering the truth.', '/49bPrxvgwUqEtvOfvTe3x92hEFV.jpg', '2015-10-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16053, 'Le frontiere dell''Astronomia - EP-7 Vite aliene nel cosmo', 347587, NULL, NULL, 'Le frontiere dell''Astronomia - EP-7 Vite aliene nel cosmo', NULL, NULL, '2012-03-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16054, 'The President''s Photographer: Fifty Years Inside the Oval Office', 205989, NULL, NULL, 'The President''s Photographer: Fifty Years Inside the Oval Office', 'The documentary covers fifty years inside The White House.', '/zm26GaEWfXkrBsLDOdLTXJ9QCPb.jpg', '2010-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16055, 'Eastwood Directs: The Untold Story', 198228, NULL, '/wRxtG8beg2RC45wKOju6uiJVASL.jpg', 'Eastwood Directs: The Untold Story', 'With a focus on Clint Eastwood''s career as a director, this documentary features movie clips, behind-the-scenes footage, interviews with people with whom he has worked, as well as comments from Clint Eastwood himself.', '/9TxY2YiQk8kAC2VP2H1u1y4wNRQ.jpg', '2013-04-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16056, 'Clint Eastwood: Out of the Shadows', 295560, NULL, NULL, 'Clint Eastwood: Out of the Shadows', 'Hollywood careers are full of make-or-break moments. For Clint Eastwood, one such moment came when studio powers agreed to let him make his directing debut. That story and others comprise this portrait of the famed Hollywood icon. His career is explored via an array of film clips, interviews and more.', '/ogcXMdPhmT22HaNGRAePvosuIET.jpg', '2000-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16057, 'Clint Eastwood: The Last Legend', 1039896, NULL, '/tOXDvsaPPYkkSzNYfgDugrXCvlG.jpg', 'Clint Eastwood, la dernière légende', 'The portrait of the last cowboy Hollywood legend dives into the 65 years of an extraordinary career in Hollywood, highlighted iconic films like The Good, the Bad and the Ugly, as well as Million Dollar Baby, Mystic River and Gran Torino all the way to Cry Macho in 2021. It is no small task to cover more than 60 years of cinema history, especially when it is trying to surveyed with such breadth and diversity: TV star, international star, controversial icon, contested director, filmmaker with a capital F, Eastwood has been through it all, experienced it all, and it is first of all this romantic trajectory, this true American pastoral that the documentary wants to tell with all the passion it possibly can.', '/xG5sdTh9a2QDqyhOkbSDPrBsBv3.jpg', '2022-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16058, 'Clint Eastwood''s West', 558595, NULL, NULL, 'Clint Eastwood''s West', 'An entertaining look at Clint Eastwood''s storied career as a Western icon and filmmaker, featuring interviews with Clint Eastwood, Morgan Freeman, Kevin Costner, Frank Darabont, John Lee Hancock and many more.', NULL, '2011-07-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
