INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16061, 'Sidney', 961722, NULL, '/orEVSaVSRNElwjB7GZI3vsOKMS9.jpg', 'Sidney', 'This revealing documentary honors the legendary Sidney Poitier—iconic actor, filmmaker, and civil rights activist. Featuring interviews with Denzel Washington, Spike Lee, Halle Berry, and more.', '/cVdkjqmIipF2DCvDwt16BRv7e9o.jpg', '2022-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16062, 'Where Were You When the Lights Went Out?', 42687, NULL, '/jlIjiG6hAH2oBLFr2UQ5TeFmTro.jpg', 'Where Were You When the Lights Went Out?', 'When the Great Northeast Blackout of 1965 hit, millions of people were left in the dark, including Waldo Zane, a New York executive in the process of stealing a fortune from his company, and two people whose paths he''s destined to cross, Broadway actress Margaret Garrison and her husband, Peter.', '/iuYNfNNgvqyeT6dkAWdGRXhTdUE.jpg', '1968-06-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16063, 'Scandalize My Name: Stories from the Blacklist', 386089, NULL, NULL, 'Scandalize My Name: Stories from the Blacklist', 'A look at the confluence of the Red Scare, McCarthyism, and blacklists with the post-war activism by African Americans seeking more and better roles on radio, television, and stage. It begins in Harlem, measures the impact of Paul Robeson and the campaign to bring him down, looks at the role of HUAC, J. Edgar Hoover and of journalists such as Ed Sullivan, and ends with a tribute to Canada Lee. Throughout are interviews with men and women who were there, including Dick Campbell of the Rose McLendon Players and Fredrick O''Neal of the American Negro Theatre. In the 1940s and 1950s, anti-Communism was one more tool to maintain Jim Crow and to keep down African-Americans.', '/4TrBSVSSKI8xU87hUZOQz2f41Xg.jpg', '1998-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16064, 'Declaration of Independence', 387385, NULL, NULL, 'Declaration of Independence', 'Famous actors and actresses read the Declaration of Independence of the United States.', '/mOb4iKKSIP5UVgEH8QuaEsKAnId.jpg', '2003-06-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16065, 'Just Getting Started', 398177, NULL, '/a7pM4QWQxMMa9ifuCPPzp9UGZHv.jpg', 'Just Getting Started', 'Duke Diver is living the high life as the freewheeling manager of a luxurious resort in Palm Springs, Calif. He soon faces competition from Leo, a former military man who likes the same woman that Duke is interested in. When Diver''s past suddenly catches up with him, he must put aside his differences and reluctantly team up with Leo to stop whoever is trying to kill him.', '/vtfYt7vi0cdzRCD7iUMTg3PPSoi.jpg', '2017-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16066, 'The C Word', 403579, NULL, '/bNMAq0Gy7Kh0i4dtRl6tK1cnCan.jpg', 'The C Word', 'Cancer: Few words are more feared. But in her sharply researched, deftly humorous message of hope, survivor Meghan O’Hara changes the way we think about this terrifying disease, showing that it’s time to stop being afraid of cancer and time to make cancer afraid of us. Following her diagnosis, O’Hara met neurologist Dr. David Servan-Schreiber, who was diagnosed with brain cancer while doing cancer research. Together they explore daily Western behaviors that are linked to 70% of cancer deaths: smoking, processed foods, stress, contaminants, and lack of exercise. Narrated and executive produced by Morgan Freeman, “The C Word” is an unflinching look at our complacency with cancer culture, the vibrant cast of characters who are changing the game, and the tools we already have to beat the dreaded scourge of our time.', '/efcs94CjzuFjpn4zK2E8KYFyir0.jpg', '2016-07-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16067, 'The Earth Day Special', 405806, NULL, '/wtLw69A3lUkFGePgfUQUxnjLGkL.jpg', 'The Earth Day Special', 'The Earth Day Special is a television special revolving around Earth Day that aired on ABC on April 22, 1990. Sponsored by Time Warner, the special featured an all-star cast addressing concerns about global warming, deforestation, and other environmental ills.', '/kV8VKQCwciY2lwTbM2e8R3BxfjA.jpg', '1990-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
