INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16069, 'The Gospel at Colonus', 1323866, NULL, '/p3fq95JstAVGeJiKKmFRpvsOzyP.jpg', 'The Gospel at Colonus', 'An African-American musical version of Sophocles''s tragedy, Oedipus at Colonus. In 1985 PBS televised the original Brooklyn Academy of Music production, as presented by the American Music Theater Festival at the Annenberg Center in Philadelphia, as part of the Great Performances series.', '/zleoiTloeaW56ck3bOsBH4FFFSu.jpg', '1985-11-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
