INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16071, 'Odysseus Returns', 1339213, NULL, '/hx5emjLnPjiAAMtY1UBMQXYi8UO.jpg', 'Odysseus Returns', 'Archaeologists have searched Ithaca for the home of King Odysseus for centuries. So, when politician Makis Metaxas discovers the king''s tomb. The story of his discovery quickly spreads, but controversy surrounds the case.', '/2gog03SJ418zhljQ3nAjmfGM1aT.jpg', '2024-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
