INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16073, 'The Words That Built America', 464655, NULL, '/oeFNndgqfIB9uRUkROzbyLvfLR8.jpg', 'The Words That Built America', 'In recognition of the 4th of July, several celebrities and politicians of differing ideologies join to read the historic documents which laid the foundation for the United States of America.', '/pk7TYOGbtIHeVLSmmsfSgAKp75Z.jpg', '2017-07-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16074, 'A Raisin in the Sun', 25781, NULL, '/9hfOwUrWDAauq3eaTZuQ6EmkJCu.jpg', 'A Raisin in the Sun', 'Dreams can make a life worth living, but they can also be dashed by bad decisions. This is the crossroads whare the Younger family find themselves when their father passes away and leaves them with $10,000 in life insurance money. Should they buy a new home for the family? Perhaps a liquor store? While no choice is easy, life on the South Side of Chicago in the 1950s is even harder.', '/pUoE6wFKPTm9fWy0Qio38OqUDFG.jpg', '2008-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
