INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16076, 'Where the Water Meets the Sky', 477595, NULL, NULL, 'Where the Water Meets the Sky', 'Narrated by Academy Award winning actor, Morgan Freeman, Where the Water Meets the Sky tells the inspiring story of a group of women from a remote town in northern Zambia who are given a unique opportunity: To learn how to make a film, on a subject of their choosing. In one of poorest regions of the country, where women rarely have the chance to speak out, a courageous group of twenty-three women produce a film about an issue that has affected them all, but few will discuss: the plight of young women, orphaned by AIDS. Inspired by the strength of Penelop, a young woman who agrees to share her story on film, the group becomes a force for change, showing how a single story can unite an entire community.', '/xdX05JS3gsVjqht5lYZhrz9NVb1.jpg', '2008-06-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16077, 'The Poison Rose', 529983, NULL, '/cXpkDrZWK8amdYXzf24LH67Vftn.jpg', 'The Poison Rose', 'A down-on-his-luck PI is hired by his old flame to investigate a murder. But while the case at first appears routine, it slowly reveals itself to be a complex interwoven web of crimes, suspects and dead bodies.', '/gSzyUmg719TgAxarFZYWjLLMqvS.jpg', '2019-05-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
