INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16079, 'Shawshank: The Redeeming Feature', 546312, NULL, '/u6hgtSIzW8nDKKWmun9JDhZz2fp.jpg', 'Shawshank: The Redeeming Feature', 'Film critic and presenter Mark Kermode explores the fascination and praise audiences, fans and critics have behind the classic The Shawshank Redemption (1994) and how its importance grew higher over the years despite being an overlooked film when it was released and not getting any Oscars victories when it was nominated as one of the Best Pictures of the Year.', '/b7DGM74MRfiLqEveVKwh0jnQ8zX.jpg', '2001-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16080, 'The Best of The Tony Awards: The Plays', 312639, NULL, NULL, 'The Best of The Tony Awards: The Plays', 'The Great White Way comes into your living room via this disc of rare performances from some of Broadway''s brightest luminaries. Culled from clips from the Tony Awards shows, this unique collection features acting powerhouses James Earl Jones, Annette Bening, Joan Allen, Joe Mantegna, Gary Sinise and Maggie Smith, among others, performing works by such playwrights as August Wilson, David Mamet, Wendy Wasserstein and more.', '/pqn9Vtk7OWxhmA3fALM6I1aRgRS.jpg', '2006-05-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16081, 'Partners of the Heart', 613562, NULL, NULL, 'Partners of the Heart', 'Recounts the extraordinary segregation-era partnership between two surgeons--one black and one white--who defied the medical establishment and changed the course of cardiac surgery.', '/ozOxllMeSQ8wtVPKpQynE4aW8i7.jpg', '2002-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16082, 'Brian Banks', 535845, NULL, '/fuSOcHaahBSr8y00ZSQzqgvGpHn.jpg', 'Brian Banks', 'An All-American football player''s dreams to play in the NFL are halted when he is falsely accused of rape and sent to prison.', '/4MnCFcFHYAEMG4NBTUKvjhf5AhU.jpg', '2019-08-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16083, 'The Comeback Trail', 650783, NULL, '/611tmWkvhAXsaltcX3h4hSVcYfG.jpg', 'The Comeback Trail', 'Two movie producers who owe money to the mob set up their aging movie star for an insurance scam to try and save themselves. But they wind up getting more than they ever imagined.', '/ublJIJbc2NZ30ptXj4O2d2apo1t.jpg', '2020-11-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
