INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16086, 'Eastwood & Co.: Making ''Unforgiven''', 692293, NULL, '/tkU7h8ub1elfTsBIL6ck8Lj7rCj.jpg', 'Eastwood & Co.: Making ''Unforgiven''', 'Behind the scenes of Unforgiven (1992)', '/tclevvIQxMIf8GAViwVn1N5uBdU.jpg', '2002-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16087, 'The Electric Company''s Greatest Hits & Bits', 701660, NULL, '/cNH14A5DhwVMjFVtKwXrrvWapc6.jpg', 'The Electric Company''s Greatest Hits & Bits', 'When "The Electric Company" made its television debut in October 1971, it was instantly clear that it would fulfill its mission of helping struggling and reluctant readers. With a ground-breaking and diverse cast, clever writing, innovative direction, and an original visual and musical style, the show was so effective that by the end of its first season, nearly a quarter of all US schools were using the show in the classroom. Generations of young people learned to read from the series, making it one of the most important and enduring shows in American television history. "The Electric Company''s Greatest Hits and Bits" is a clip-filled celebration featuring many of the series'' most popular segments (with Bill Cosby, Morgan Freeman, Rita Moreno and the rest of the multi-talented Electric Company cast), and includes new interviews with cast members Jim Boyd, Judy Graubart, Skip Hinnant, Tom Lehrer, Rita Moreno, and Joan Rivers, as well as with series creator Joan Ganz Cooney.', '/AcglRG2XeRffEIPhwuyQ5Xr9tgJ.jpg', '2006-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16088, 'The Disney Family Singalong - Volume II', 702920, NULL, '/lwwnoNDP7xEP2xypd0knp6zY8Cg.jpg', 'The Disney Family Singalong - Volume II', 'Ryan Seacrest hosts the second Disney Family Singalong featuring celebrities and their families as they take on their favorite Disney tunes from their homes. Special guests include John Legend, Christina Aguilera, Shakira, and Katy Perry.', '/uOYIKG0RfK6iWGQQXXY2vEHA7gI.jpg', '2020-05-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16089, 'The 16th Man', 54737, NULL, '/59Ff8lDOVbmOr9DnWVuIYviKQlR.jpg', 'The 16th Man', 'Rugby Union has long been viewed in South Africa as a game for the white population, and the country’s success in the sport has been a true source of Afrikaner pride. When the 50-year-old policies and entrenched injustices of apartheid were finally overthrown in 1994, Nelson Mandela’s new government began rebuilding a nation badly in need of racial unity. So the world was watching when South Africa played host to the 1995 Rugby World Cup. Though they had only one non-white player, the South African Springboks gained supporters of all colors as they made an improbable run into the final match where they beat the heavily favored New Zealand team. When Mandela himself marched to the center of the pitch cloaked in a Springbok jersey and shook hands with the captain of the South African team, two nations became one. Oscar winner Morgan Freeman and director Cliff Bestall will tell the emotional story of that cornerstone moment and what it meant to South Africa’s healing process.', '/hQPwbCjWEDuzf7PCQwnaHDbJroT.jpg', '2010-05-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16090, 'Into Nature''s Wild', 735814, NULL, NULL, 'Into Nature''s Wild', 'From the wilds of Alaska and the lush coastline of Oregon, to the ancient canyons of the Southwest and the rolling hills of the Appalachian Trail, Into Nature’s Wild is a non-stop ride via kayak, train, bike, hot air balloon and more that explores the transformational allure of wild places and the human connection we all share with the natural world.', '/aBH9lOiSGiAwaKhWyzrIFhXz1U2.jpg', '2020-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16091, 'Meeting the Beatles in India', 741204, NULL, '/umAKhkVwU94gj9Tiu4H10237R63.jpg', 'Meeting the Beatles in India', 'Filmmaker Paul Saltzman retraces his journey of 50 years ago when he spent a life-changing time with the Beatles at the Maharishi Mahesh Yogi''s ashram on the banks of the Ganges River. In 1968, he discovered his own soul, learned meditation, which changed his life, and hung out with John, Paul, George and Ringo. Fifty years later, he finds "Bungalow Bill" in Hawaii; connects with David Lynch about his own inner journey; as well as preeminent Beatles historian, Mark Lewisohn; Academy Award nominated film composer, Laurence Rosenthal; and Pattie and Jenny Boyd. And much of this is due to Saltzman''s own daughter, Devyani, reminding him that he had put away and forgotten these remarkably intimate photographs of that time in 1968.', '/lckvWRHLW0ckMfEwZynwICZ1Zde.jpg', '2020-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16092, 'Who Says I Can''t Ride a Rainbow!', 774426, NULL, NULL, 'Who Says I Can''t Ride a Rainbow!', 'Barney owns the last working farm in Manhattan. For various reasons, city officials have decided to close it down. A special event is planned to raise awareness and money to keep it running.', '/ywFSCtijjxZahmHsjy8F9ld31iK.jpg', '1971-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16093, 'Rita Moreno: Just a Girl Who Decided to Go for It', 776526, NULL, '/qXZN7uyIfcNkyEO7lBHycN3n33Z.jpg', 'Rita Moreno: Just a Girl Who Decided to Go for It', 'Rita Moreno defied both her humble upbringing and relentless racism to become one of a select group who have won an Emmy, Grammy, Oscar and Tony Award. Over a seventy year career, she has paved the way for Hispanic-American performers by refusing to be pigeonholed into one-dimensional stereotypes.', '/gWZsBiQtmxN94hXdXfo0PfMMJzT.jpg', '2021-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16094, 'A Man Called Adam', 151043, NULL, '/nrALjYHjdYEsV4qBULc3SG8SXLa.jpg', 'A Man Called Adam', 'A famous jazz trumpeter finds himself unable to cope with the problems of everyday life.', '/lQQnlbhgFRCBmtuh1Lq42oBE1im.jpg', '1966-03-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16095, 'JFK & LBJ: A Time for Greatness', 694747, NULL, NULL, 'JFK & LBJ: A Time for Greatness', 'How U.S. President Lyndon B. Johnson used his political prowess to make the Civil Rights Act of 1964 and the Voting Rights Act of 1965 happen. The story is told using rarely-seen footage, interviews and secret White House tapes.', '/cwtQw6zgqwQkwMx4Ug5cQiqlzQx.jpg', '2015-08-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16096, 'Vanquish', 804435, NULL, '/mYM8x2Atv4MaLulaV0KVJWI1Djv.jpg', 'Vanquish', 'Victoria is a young mother trying to put her dark past as a Russian drug courier behind her, but retired cop Damon forces Victoria to do his bidding by holding her daughter hostage. Now, Victoria must use guns, guts and a motorcycle to take out a series of violent gangsters—or she may never see her child again.', '/AoWY1gkcNzabh229Icboa1Ff0BM.jpg', '2021-04-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
