INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16098, 'Hate to See You Go', 838773, NULL, NULL, 'Hate to See You Go', 'The story of Sonny Bell, an aging Chicago Blues musician, who refuses to retire and defiantly hits the road with his band for one last long-shot to keep doing the only thing that makes them all feel truly alive--play Blues. The story is inspired by Stone''s experiences touring and playing harmonica with many of blues music''s most revered artists.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
