INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16102, 'CLINT', 1374855, NULL, '/7na8RRD7FJJoVEzIPgySmFZqFPC.jpg', 'CLINT', 'CLINT is the inspirational story of the early life of film legend and icon Clint Eastwood. We follow young Clint from age 20 when he received his draft notice to fight in the Korean War, through boot camp and military service, up to the point where we discover the unexpected chain of events that motivated him to move to Los Angeles and pursue a career in acting, which led to the extraordinary life of a Legend.', '/fXoM875Zuf676xX3Aiw0zbbsu4i.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
