INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16112, 'Greasy Rider', 309481, NULL, '/oswyKLnT5zLs6bUJ2cCkQJrymxa.jpg', 'Greasy Rider', 'Filmmakers Joey Carey and J.J. Beck pack up their vegetable oil-powered 1981 Mercedes-Benz and set off on a cross-country road trip to explore the world of biodiesel fuel and vegetable oil conversion in this engaging documentary. In addition to appearances by Noam Chomsky, Morgan Freeman, Tommy Chong and Yoko Ono, the film also features interviews with representatives from vegetable oil-conversion companies such as Greasecar and Frybrid.', '/eOFFK1caENHw1oEE1dmBOIfDFbc.jpg', '2006-10-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
