INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16116, 'Playing by Heart', 825, NULL, '/31hKau6i2AqCUHubvl82f111jgo.jpg', 'Playing by Heart', 'In a vibrant tapestry of love and longing, nine interconnected souls navigate romance and heartbreak in L.A., where passions collide and truths unfold, revealing that the heart''s desires often lead us where we least expect.', '/3neHR1oPnC0OpcYhLn0TEdSHoEp.jpg', '1998-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16117, 'A Mighty Heart', 1988, NULL, '/zjVE6yJE3UvQbBTB6QbiN3fK52m.jpg', 'A Mighty Heart', 'Based on Mariane Pearl''s account of the terrifying and unforgettable story of her husband, Wall Street Journal reporter Danny Pearl''s life and death.', '/z5f7KPg8vqqYXtaF0wUkSWryDIg.jpg', '2007-06-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16118, 'Without Evidence', 23476, NULL, '/bBPsblWmfNDAW8eC5f6zyQB5wa.jpg', 'Without Evidence', 'It is based on the true story of Michael Francke, who was the Head of Corrections for the state of Oregon before being murdered. Just before his murder, Francke visits his brother and informs him of a drug ring involving his prison colleagues. When Michael is killed, his brother begins his own investigation into the murder, leading him to more lies and deceit.', '/ngwlWUKxPSY3Y68mL3FShFAoa3r.jpg', '1995-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16119, 'Mojave Moon', 24275, NULL, '/p98VRomVosbv0xc5UIpM7HNvrQx.jpg', 'Mojave Moon', 'Al McCord is hanging out at his favourite restaurant when he meets an attractive young woman (Ellie) who is looking for a ride from the city out into the Mojave Desert, where her mother lives. Little does he know that while Ellie is falling in love with him, he is falling for her mother (Julie), despite the nearby presence of Julie''s boyfriend who seems likely to go berzerk at any moment. Even more strange, hilarious events follow and it''s up to Al to find some explanation. His life may never again be the same.', '/mUGMYmA11ZFnPqOJ4GdnZa2q6FU.jpg', '1996-11-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16120, 'Playing God', 12628, NULL, '/gHqEy16wIeGEfoCdROYaTpCcPUb.jpg', 'Playing God', 'Stripped of his medical license after performing an operation while high on amphetamines, famed LA surgeon Dr Eugene Sands abandons his former life only to find himself crossing paths with Raymond Blossom, an infamous counterfeiter. Employed as a "gun-shot doctor" when Raymond''s associates cannot risk visiting a hospital, Eugene is lured deep into the criminal world and becomes entangled with his boss''s girlfriend.', '/faYRZjtBMNygM7spt72yrs72hC8.jpg', '1997-10-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16121, 'Beyond Borders', 9839, NULL, '/pqGon4dlyUXKb33zcBQN4HCdC6l.jpg', 'Beyond Borders', 'Sarah Jordan, an American living in London in 1984, is married to the son of a wealthy British industrialist. She encounters Nick Callahan, a renegade doctor, whose impassioned plea for help to support his relief efforts in war-torn Africa moves her deeply. As a result, Sarah embarks upon a journey of discovery that leads to danger, heartbreak and romance in the far corners of the world.', '/j7Upm2AtGuTzCs2Asq0GyBIMAxX.jpg', '2003-10-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16122, 'George Wallace', 61445, NULL, '/cbnEsD0O6qpFoJyUhTzvfuZw8i8.jpg', 'George Wallace', 'George Wallace is a 1997 television film starring Gary Sinise as George Wallace, the former Governor of Alabama. It was directed by John Frankenheimer, who won an Emmy award for it; Sinise and Mare Winningham also won Emmies for their performances. The film was based on the 1996 biography Wallace : The Classic Portrait of Alabama Governor George Wallace by Marshall Frady, who also co-wrote the teleplay. Frankenheimer''s film was highly praised by critics: in addition to the Emmy awards, it received the Golden Globe for Best Miniseries/Motion Picture made for TV. Angelina Jolie also received a Golden Globe for her performance as Wallace''s second wife, Cornelia.', '/AeCijWmx9B1rZSBozFRuDFup3wI.jpg', '1997-08-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16123, 'Hell''s Kitchen', 37900, NULL, NULL, 'Hell''s Kitchen', 'Newly released from jail, an ex-gang member asks a former contender to teach him to box.', '/4O5qyaUbVBJGe4Gt95RpKS2yyrl.jpg', '1998-09-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16124, 'Cyborg 2', 16437, NULL, '/wyF3MzxcLZyJnEYZsp6XdPvpsdc.jpg', 'Cyborg 2', 'In the year 2074, the cybernetics market is dominated by two rival companies: USA''s Pinwheel Robotics and Japan''s Kobayashi Electronics. Cyborgs are commonplace, used for anything from soldiers to prostitutes. Casella Reese is a prototype cyborg developed for corporate espionage and assassination. She is filled with a liquid explosive called Glass Shadow. Pinwheel plans to eliminate the entire Kobayashi board of directors by using Casella', '/hYNJ4KNMVaVgR5JAqC5qlgbJEmJ.jpg', '1993-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16125, 'The Fever', 64192, NULL, '/aS1luXDYEhAVtKNqc5YnlOql8hc.jpg', 'The Fever', 'Tells the story of a woman who gets involved in politics with no previous contact with world events.', '/fXLee26yjmFAZG3ZEZwZ8eTcPJ7.jpg', '2007-06-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16126, 'Life or Something Like It', 16643, NULL, '/AwkaTlvHAc5qQksrXg982CWMkYJ.jpg', 'Life or Something Like It', 'A reporter Lanie Kerrigan interviews a psychic homeless man for a fluff piece about a football game''s score. Instead he tells her that her life has no meaning and is going to end in just a few days, which sparks her to action, trying to change the pattern of her life...', '/b9lUSfCjv8jjNRSsmk65HEV1Pv3.jpg', '2002-04-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
