INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16130, 'Love Is All There Is', 55058, NULL, '/gWLEQEFElvjpQX0IXJRmAOa4xha.jpg', 'Love Is All There Is', 'The Malacicis, a hard-working Italian family recently immigrated from Florence, open a fancy restaurant in the Bronx, N.Y., drawing the ire of another clan. Mike and Sadie Capomezzo, equally hard-working Sicilian caterers from the area, find they cannot stand Piero  and Maria Malacici. But things get complicated when the Malacicis'' daughter, Gina, and the Capomezzos'' son, Rosario, fall in love.', '/tXaewq2LMjTJmZLTuKEM6LJhBo2.jpg', '1996-05-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16131, 'Marvel Studios Assembled: The Making of Eternals', 939356, NULL, '/imkqp2S4ZXEGczb59ciF6IYVwnW.jpg', 'Marvel Studios Assembled: The Making of Eternals', 'Join director Chloe Zhao and the Cast of Eternals as they recount their experiences during the making of Marvel Studios’ most ambitious film to date. Discover how the ensemble cast felt stepping into their roles, filming in remote locations, and creating bonds that would help to create the on-screen relationships that span over 7,000 years.', '/fBJ5ZjFJ6IHQWz90SsW80PizVlF.jpg', '2022-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
