INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16133, 'Lara Croft: Lethal and Loaded', 182600, NULL, '/9J9Jk5Hh0OUjI2UDS5Y8EHnDzFS.jpg', 'Lara Croft: Lethal and Loaded', 'Lara Croft is the fearless pioneer of "girl power." She''s the empress of the digital age, and the star of the wildly successful computer game and movie Tomb Raider.  Now, for the first time, this fascinating program explores the unique phenomenon of Lara Croft and tells an amazing tale of ingenuity and success. It reveals how Core Design invented Lara Croft and catapulted her into mainstream contemporary culture, making her the most successful cyber character to cross over into global marketing, advertising, and of course, Hollywood.  This is the amazing story of cyber tomb raider Lara Croft, and it is a “must see” for all of her fans.', '/fhl8oe6aiqaITD2jtNAAz4KbxQ3.jpg', '2001-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16134, 'Why Are We Creative?', 540003, NULL, '/iA2pIUBoFEcTmSlhRY3hkX9RJnB.jpg', 'Why Are We Creative?', 'A 30 years odyssey: the world''s most intriguing artists and thinkers from the fields of visual art, music, filmmaking, acting, literature, philosophy, politics, business and science, are asked the same question: "Why are you creative?"', '/hD7HPBmdH67J2zHsBSzFHbETDhE.jpg', '2018-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16135, 'Valencia: The Movie/S', 253157, NULL, '/oWCHceB0zCAhgJv1ZpVzfKofuAe.jpg', 'Valencia: The Movie/S', 'Valencia is a collaboration between a national community of queer filmmakers to adapt the underground classic memoir into a kaleidoscopic vision of San Francisco''s Mission District in the early 90s during the rise of a punk lesbian diaspora told through the experiences of Michelle, a single rootless twenty-something searching for sex and love, drugs and adventure.', '/nS4DgyzGca5pDHhn0kftDakJDHc.jpg', '2013-06-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16136, 'Broken: The Incredible Story of Brangelina', 988627, NULL, '/bTpN5igwH8tMm5WwMcJz2nItD5b.jpg', 'Broken: The Incredible Story of Brangelina', 'Bestselling author and award-winning filmmaker Ian Halperin lifts the lid on Brangelina - the couple, the brand and the breakup. Featuring exclusive revelations and anecdotes from behind the scenes, Broken: The Incredible Story of Brangelina explores the relationship of one of the most fascinating, powerful and enigmatic couples in the entertainment business.', '/hI0fQitHDpsOKBfLx8S05Wuc9l5.jpg', '2018-06-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16137, 'Lookin'' to Get Out', 47878, NULL, '/9E3V82RIeSqdvhRkxFt3n7Vts1r.jpg', 'Lookin'' to Get Out', 'Two gamblers must leave New York City after one loses a lot of money. Doing what all gamblers in trouble would do, they hurry to the gambling capital Las Vegas to turn their luck around.', '/tcfuDnWoGBFqdqDRoJrfj21jAhu.jpg', '1982-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16138, 'By the Sea', 314385, NULL, '/u67FvSAhGmHsJFb2uU9y43q5XVv.jpg', 'By the Sea', 'Set in France during the mid-1970s, Vanessa, a former dancer, and her husband Roland, an American writer, travel the country together. They seem to be growing apart, but when they linger in one quiet, seaside town they begin to draw close to some of its more vibrant inhabitants, such as a local bar/café-keeper and a hotel owner.', '/oEyeG4UyAQvYIJiFpUV57Q3PTDp.jpg', '2015-11-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
