INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16140, 'The Queen''s Green Planet', 519864, NULL, '/3nWNxulwJoMRlp1Tv5srDeRFKMg.jpg', 'The Queen''s Green Planet', 'Featuring a unique conversation between The Queen and Sir David Attenborough as they walked in the garden at Buckingham Palace last summer, a landmark documentary will explore the ambition of a remarkable new initiative - a vast network of native forests across Britain and the Commonwealth, protected forever in The Queen''s name.', '/pjyPrbPgrzzRtaz7BxGSTXCK54k.jpg', '2018-04-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16141, 'Balkan Spirit', 482768, NULL, NULL, 'Balkan Spirit', 'Filmmaker Hermann Vaske explores the creative Balkan world in the hopes of understanding the meaning of "Balkan spirit".', '/oA3XFtOE2jbeXCXz2zAd1d4wpPz.jpg', '2013-04-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16142, 'Confessions of an Action Star', 45833, NULL, '/mhZexPA8kpjBcairnWkjnQ3AJqJ.jpg', 'Confessions of an Action Star', 'A ''mockumentary'' on the rise and fall of Chip and Dales dancer turned martial arts action star, Francis Allen Sledgewick, AKA Frank Sledge. When fame and fortune caused Frank to lose his sense of what''s truly important, he realized he''d have to get in touch with his roots, if there''s ever going to be a comeback.', '/uw6Jixhh36TQhzOWuvrF9d6kbHC.jpg', '2005-01-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16143, 'Every Note Played', 752017, NULL, NULL, 'Every Note Played', 'A world-renowned concert pianist and composer on the verge of creating his magnum opus. When he receives a life-changing diagnosis, his estranged ex-wife takes up the cross of caring for him, and he is forced to balance reconciling his failed relationships with redefining his pursuit of greatness.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16144, 'Indiana Jones: The Search for the Lost Golden Age', 827007, NULL, '/ofRUyIddC3iE7hXGETqPAMUqy3P.jpg', 'Indiana Jones : à la recherche de l''âge d''or perdu', 'Hawaii, May 1977. After the success of Star Wars, George Lucas and Steven Spielberg meet to find a new project to work on together, the former as producer, the latter as director. The story of how the charismatic archaeologist Indiana Jones was born and how his first adventure, released in 1981, triumphed at box offices around the world.', '/r3iQkvEU50t87oiKq6seLJFZMgF.jpg', '2021-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16145, 'The Keyboard Cowboys: A Look Back at Hackers', 606061, NULL, NULL, 'The Keyboard Cowboys: A Look Back at Hackers', 'Brand-new interviews with director Iain Softley, cast members Fisher Stevens, Matthew Lillard and Penn Jillette, costume designer Roger Burton, visual effects artist Peter Chiang, and more!', '/aebl0Zp2Y6EmM2SksM40vD3zqJl.jpg', '2015-08-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16146, 'Sesame Street: 50 Years of Sunny Days', 810397, NULL, '/bFa10udi6t18rGUHPI4IDrvO0xi.jpg', 'Sesame Street: 50 Years of Sunny Days', 'For more than a half-century, Sesame Street has addressed and explained diversity, equity, and inclusion around the globe by using the universal tools of music, empathy and celebrity. Sesame Street: 50 Years of Sunny Days reflects upon the efforts that have earned the show respect and qualification around the globe. The special also chronicles the creation and introduction of a Black family of Sesame Street Muppets, Wes and Elijah Walker, a father-and-son duo who are at the heart of Sesame Workshop’s new racial justice initiative Coming Together.', '/3S2HHxdyWxdIxyysbCkgtyMCRmw.jpg', '2021-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16147, 'The True Story Of Angelina Jolie', 1361644, NULL, NULL, 'The True Story Of Angelina Jolie', 'From award-winning actress to dedicated humanitarian, Angelina Jolie''s life serves as an inspiration to many. Explore the remarkable journey of this extraordinary woman.', NULL, '2020-07-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16148, 'Anxious People', 1474678, NULL, NULL, 'Anxious People', 'On the day before Christmas Eve, investment banker Zara begrudgingly finds herself mingling with a group of strangers at an open house. When a reluctant bank robber inadvertently takes the group hostage, chaos and oversharing ensues, secrets are revealed and literally nothing goes according to plan', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16149, 'Bee Wild', 1487072, NULL, NULL, 'Bee Wild', 'Bee Wild is an inspirational, upbeat, and poetic documentary that explores the foundational role that bees play in sustaining humanity, the reasons for their sharp population decline and how we can regenerate bees worldwide so they are once again part of a thriving ecosystem. Because we are losing 1 billion pollinators annually, the film will focus on the urgent nature of both bees and other insects that pollinate our food and emphasize ways that viewers can get involved in restoring, regenerating and nurturing this largely unseen world.', '/jWmAgQmUWMNezYhUyb32zn2llzK.jpg', '2026-02-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16150, 'Brad Pitt & Jennifer Aniston: Hollywood''s Couple of the Year', 923893, NULL, NULL, 'Brad Pitt & Jennifer Aniston: Hollywood''s Couple of the Year', 'This documentary explores the sequence of events that led A-listers Brad Pitt and Jennifer Aniston to one another, and recounts their relationship in the international spotlight.', NULL, '2000-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
