INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16153, 'Angelina Jolie: Skin Deep', 836896, NULL, NULL, 'Angelina Jolie: Skin Deep', 'The stunning Oscar-winning actress has transcended traditional expectations to become a humanitarian, activist, and renowned director.', NULL, '2011-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16154, 'The Initiative', 1529282, NULL, NULL, 'The Initiative', 'A rogue master spy named Bright works outside the lines, when a new agent named Charlie joins Bright’s team. He soon finds himself in situations where he isn’t sure whether his new boss is trying to kill him or simply is willing to do whatever is necessary to protect the free world.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16155, 'Sunny', 500901, NULL, NULL, 'Sunny', 'Wealthy and glamorous Sunny radiates polished perfection, but beneath her sparkling society smile, Sunny is a drug kingpin, mob mistress and devoted single mother, who has an adrenaline-fueled 24 hours to clean up and get out of town before the local mob boss discovers her dysfunctional family''s devastating secret.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16156, 'Most Outrageous Celebrity Splits', 1629246, NULL, NULL, 'Most Outrageous Celebrity Splits', 'Fame and fortune rarely translate to happily ever after. Whether Princess Diana and King Charles'' issues hidden behind palace walls or Johnny Depp and Amber Heard''s past exploded on national TV, dive into Hollywood''s most iconic breakups.', '/ybXtBCg1DvlB5csXst8SuVbf1LP.jpg', '2024-07-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16157, 'Mon Guerlain: Notes of a Woman', 1652577, NULL, NULL, 'Mon Guerlain: Notes of a Woman', 'Mon Guerlain, the house''s new fragrance, is a tribute to today''s femininity - a strong, free and sensual femininity, inspired by Angelina Jolie. Mon Guerlain is characterized by the freshness of Lavender Carla, an exceptional variety cultivated in Provence, which contrasts with the voluptuousness of the Sambac jasmine from India and the Australian Album Sandalwood, associated with the sensual Vanilla Tahitensis of Papua New Guinea.', '/rRMuzXkieF8yzwaUYdVkWbqs9aN.jpg', '2017-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16158, 'Muppet Treasure Island', 10874, NULL, '/3RfNxQhvseerf9dNlo1dmL09RLr.jpg', 'Muppet Treasure Island', 'After telling the story of Flint''s last journey to young Jim Hawkins, Billy Bones has a heart attack and dies just as Jim and his friends are attacked by pirates. The gang escapes into the town where they hire out a boat and crew to find the hidden treasure, which was revealed by Bones before he died. On their voyage across the seas, they soon find out that not everyone on board can be trusted.', '/k4KW2CUkzDKaCy4H4cS02cO8gvV.jpg', '1996-02-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16159, 'Four Dogs Playing Poker', 20445, NULL, '/msQroAI9XORkT5YH7JCSGBxgp70.jpg', 'Four Dogs Playing Poker', 'With the help of their mentor Felix, a group of the best friends and first-time thieves steal a valuable statuette for a ruthless black market art dealer. After the amateurs botch the delivery of the objet d''art, the dealer kills Felix and forces the remaining four to "find" $1 million within a week''s time or face certain death.', '/6v4Cx2uf3S1UvBvAhKv2kAMz4hq.jpg', '2000-06-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16160, 'Rugrats Go Wild', 20694, NULL, '/7jhCBakn96BcRpjQfFyMZdnrKEY.jpg', 'Rugrats Go Wild', 'When the Rugrats find themselves stranded on a deserted island, they meet the Thornberrys, a family who agrees to help them escape.', '/hpVpXRNY2IsU0xvfXtYOxu0QDwc.jpg', '2003-06-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
