INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16162, 'The Worst Witch', 24054, NULL, '/aaPPyLUQC1KkYjEPLqc8jBImZY5.jpg', 'The Worst Witch', 'Mildred is one of the young girls at a prestigious witch academy. She can''t seem to do anything right and is picked on by classmates and teachers. The headmistress of the school, Miss Cackle, has an evil twin sister who plans to destroy the school. Can Mildred foil the plan before the Grand Wizard comes to the Academy for a Halloween celebration you''ll never forget?!!', '/ph6U11FTmfxFlkl32riyAyytqgZ.jpg', '1986-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
