INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16175, 'McHale''s Navy', 14908, NULL, '/uTp1WgfD43U6g4iP44VcoKQcm1H.jpg', 'McHale''s Navy', 'Retired Lieutenant Commander Quinton McHale spends his days puttering around the Caribbean in the old PT-73 selling homebrew, ice cream, and swimsuit calendars. He''s brought out of retirement when his old nemesis turned the second best terrorist in the world, Major Vladikov, takes over the island of San Moreno and starts building a nuclear launch silo on it. With help from his old crew and hindrances from Captain Wallace B. Binghampton, who sank a cruise liner a while back, McHale tries to put Vladikov out of business.', '/tg9qzqF349j526pNZnjPB4p2UED.jpg', '1997-04-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16176, 'Wolf Girl', 43749, NULL, '/4pvrACQMFjLcMW6agd4LnH0j4tH.jpg', 'Wolf Girl', 'Tara Talbot is afflicted with the rare genetic condition hypertrichosis: she is covered head to toe in hair. She lives her life in Harley Dune''s Travelling Freak Show, on display as the ''Terrifying Wolf Girl'', but underneath she is just a teenage girl who longs to be normal.', '/tpfV3n3UIXPz0sw3IUgX6dHD9q7.jpg', '2001-09-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16177, 'Daisy-Head Mayzie', 52457, NULL, NULL, 'Daisy-Head Mayzie', 'Daisy-Head Mayzie wakes up one morning to find a daisy has sprouted from the top of her head. Facing her classmates'' taunts and her parents'' dismay, Mayzie triumphs at last with the hard-won knowledge that love is more important than fame!', '/usaxjWWjoR5jQco4gaXFVnWJR9F.jpg', '1995-02-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16178, 'Bailey''s Billion$', 44900, NULL, '/fEKdIqPhdkCG1pwVkkN1mldpB7F.jpg', 'Bailey''s Billion$', 'Sweet and savvy talking golden retriever, Bailey, is one doggone lucky pooch when his devoted owner, Constance Pennington, leaves him her entire billion-dollar fortune. Bailey is lucky, that is, until he becomes the target of an elaborately-designed dognap scheme hatched by Constance''s nasty nephew Caspar and his money-hungry wife Dolores. The despicable duo''s wicked plan is to ultimately gain custody of the canine so they can get their greedy paws on his inheritance. Unfortunately for them, there''s a thing or two they don''t know about Bailey. Not only does he have great street smarts, he has great pals too. Bailey''s loyal guardian Ted, kind-hearted animal advocate Marge, her daughter Sam, and a clever border collie named Tessa set out on a hilarious madcap adventure to free their four-legged friend and put the nasty dognappers out of business-for good!', '/XnA0Aswod1EvM29weR5xcFjgsq.jpg', '2005-08-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16179, 'Rugrats in Paris: The Movie', 16340, NULL, '/4JbPQv5OiEhDypNFlF6jCvhdzWq.jpg', 'Rugrats in Paris: The Movie', 'A group of rambunctious toddlers travel a trip to Paris. As they journey from the Eiffel Tower to Notre Dame, they learn new lessons about trust, loyalty and love.', '/grIL8mvfLznaWsv7EEEPhCpkH81.jpg', '2000-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16180, 'A Christmas Carol', 47257, NULL, '/aHtF8OmxDE2JKFbRTs5rL9dDNJm.jpg', 'A Christmas Carol', 'Miser Ebenezer Scrooge is awakened on Christmas Eve by spirits who reveal to him his own miserable existence, what opportunities he wasted in his youth, his current cruelties, and the dire fate that awaits him if he does not change his ways. Scrooge is faced with his own story of growing bitterness and meanness, and must decide what his own future will hold: death or redemption.', '/s0dYgcUTxX1GmJ0AZwGBrViGo1D.jpg', '1997-12-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16181, 'Roger Waters: The Wall - Live in Berlin', 47271, NULL, '/ysCNJw3VeTf7WWtZfBBZf2O6SyQ.jpg', 'Roger Waters: The Wall - Live in Berlin', 'A global television broadcast of the event in which former Pink Floyd leader singer and composer Roger Waters led an all-star cast in a mammoth benefit performance of his acclaimed concept album, The Wall. Set in Berlin, Germany less than a year after the destruction of the hated Berlin Wall, Waters was accompanied by disparate talents such as Cyndi Lauper, James Galway, Joni Mitchell and Albert Finney in the classic dark musical tale of a rock star''s descent into madness and back.', '/djjobmdz3bUUL641d1pLgBevK02.jpg', '1990-07-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16182, 'Get Bruce!', 68426, NULL, '/grv7UOZiHeGu9tRoPsJAlv515jD.jpg', 'Get Bruce!', 'Affectionate tribute to Bruce Vilanch, who writes material for celebrities who make public appearances, from Oscar hosts and award recipients to Presidents. We meet his mom and see photos of his childhood; in Chicago, he writes for the Tribune and then heads West. Whoopi Goldberg, Billy Crystal, Robin Williams, and Bette Midler talk with him and to the camera about working with Bruce, and we also watch Bruce help others prepare for Liz Taylor''s 60th, Bill Clinton''s 50th, and an AIDS awards banquet where the hirsute, rotund Vilanch lets his emotions show.', '/f1uXB5YuDmaadM6wq5qTAIiK6Sr.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16183, 'Oliver Twist', 49483, NULL, '/dyDjr0hXqHiaMWn19PcRLIDy0sD.jpg', 'Oliver Twist', 'When 9-year-old orphan Oliver Twist dares to ask his cruel taskmaster, Mr. Bumble, for a second serving of gruel, he''s hired out as an apprentice. Escaping that dismal fate, young Oliver falls in with the street urchin known as the Artful Dodger and his criminal mentor, Fagin. When kindly Mr. Brownlow takes Oliver in, Fagin''s evil henchman Bill Sikes plots to kidnap the boy.', '/jRJmVqsRtfWqQsDRDkD0Vtyo8Za.jpg', '1982-03-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16184, 'Little Miss Christmas', 80085, NULL, NULL, 'Little Miss Christmas', 'It s almost Christmas Even for Eloise, the Plaza s most famous six-year old. She and her friends have decided to put on a holiday show like no other! With different traditions from many cultures, it is sure to be the best show the Plaza has ever seen. Chaos abounds, at the last minute as Mr. Salamone must cancel the show. Will Eloise be able to find a way to keep the arrive for the party? The kids scramble to find a way to save their show and in the end learn the true spirit of the season is having the people you love all happy and together. There s holiday fund for everyone in this hilarious adventure starring the talented voice of Lynn Redgrave as nanny and Tim Curry as Mr. Salamone!', '/nrrsW3CLM34ku6M8zTKSMhMn8K0.jpg', '2006-12-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16185, 'King on Screen', 1013651, NULL, '/h4JWVX5ts2Li56zjV74SPIfgMDG.jpg', 'King on Screen', '1976, Brian de Palma directs Carrie, the first novel by Stephen King. Since, more than 50 directors adapted the master of horror''s books, in more than 80 films and series, making him now, the most adapted author still alive in the world.', '/8IxzBsnEPafpk4JTz4yoHJcpFZm.jpg', '2023-08-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16186, 'A Turtle''s Tale: Sammy''s Adventures', 49953, NULL, '/oobepzwlUcuWD8QPyLJ30DVQJqI.jpg', 'A Turtle''s Tale: Sammy''s Adventures', 'Born on a Baja, California beach in 1959, new hatchling Sammy races across the beach to the ocean while avoiding being caught by seagulls and crabs. Thus begins Sammy''s incredible fifty-year ocean journey where he overcomes obstacles, both natural and man-made, while trying to fulfill his dream of travelling around the world. Along the way he meets his best friend, a fellow turtle named Ray, and never forgets about Shelly, a turtle he saved that first day on the beach and the one he''s always loved.', '/jYz1FQjspxQCUCMXuB4ihnH9Y03.jpg', '2010-08-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16187, 'Burke & Hare', 50204, NULL, '/lmglBJjuzAqdvmvVomX69AXHYNk.jpg', 'Burke & Hare', 'Two 19th-century opportunists become serial killers so that they can maintain their profitable business supplying cadavers to an anatomist.', '/3VY3gKHPc9dRq8FshSXWbXtgD9B.jpg', '2010-10-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16188, 'Ribbit', 256690, NULL, '/etcOaTO8BDLx3VHdfhWE1g7ys3l.jpg', 'Ribbit', 'A frog who hates water and jumping in wishes that he could be like the other animals in the Amazon rainforest.', '/vKHPzB0LqFJkf8TqLrhZEmoQIfr.jpg', '2014-09-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16189, 'Bartok the Magnificent', 19594, NULL, '/71MV737vocwbM55qKIv5kn838y3.jpg', 'Bartok the Magnificent', 'Albino bat Bartok – former sidekick to the wicked Grigori Rasputin – ventures to prove his true worth on a new quest to defeat the legendary Russian witch Baba Yaga.', '/r243zEE7lTd8E6WwbtEGgu5dOs.jpg', '1999-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
