INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16192, 'Super Nova', 931690, NULL, '/sKb5iS3KvNm1HvRvQTJZ5lxwhGb.jpg', 'Super Nova', 'As things settle down on the Lexx, the crew realizes Kai needs a constant supply of proto-blood to continue to function in the real world. Stanley and the others undertake a desperate mission to Kai''s wrecked home world in search of a way to extend Kai''s existence.', '/bRSUwzeCkj2Fgiqwpy4AcX4fU8a.jpg', '1997-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16193, 'The Pebble and the Penguin', 54648, NULL, '/9AJNEWmprXEIRhMdWFirYn1egbZ.jpg', 'The Pebble and the Penguin', 'A bashful bachelor penguin named Hubie, who''s partial to a pretty female named Marina. Ancient penguin ritual dictates that males present a pebble to their intended, then mate for life. Hubie finds a spiffy stone, but before he can bestow it on Marina, dastardly rival Drake tosses him into the churning sea, and Hubie gets swept away.', '/aWi36nNbyMw51yGN0tTSOrOLu6L.jpg', '1995-04-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16194, 'Pass the Ammo', 92383, NULL, '/pY2H1xZfTQibY9IWuvRBHmnkjGT.jpg', 'Pass the Ammo', 'A corrupt television preacher and his congregation are held hostage by a woman, her lover, and her two cousins in an attempt to avenge the theft of her inheritance. A quirky look at the dishonesty of the televangelist industry.', '/ypoc2ng2HAhPouGDL0MijBpev3z.jpg', '1988-03-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16195, 'Times Square', 76411, NULL, '/ebcXU5CBC0IVz6txTxG3jVmCsHc.jpg', 'Times Square', 'When a 13-year-old girl befriends a defiant antisocial child of the streets, the mismatched runaways set off to the Big Apple to find their own adventure.', '/zkZtDpfOfUVz0tFWRrkPp6W2iPd.jpg', '1980-10-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16196, 'I, Crocodile', 939124, NULL, NULL, 'I, Crocodile', 'An Egyptian crocodile lives happily in his new home in Paris, until a chef tries to turn him into dinner. The crocodile escapes through the sewers and lives to tell about his newest menu delight - people!', '/oBe4rvGnCWQDadJmMFAf7hiTCI6.jpg', '2002-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16197, 'Three Men in a Boat', 78329, NULL, '/ykjVUvNPi2Ce4afvIK876J7nAX0.jpg', 'Three Men in a Boat', 'One hot June day, three friends decide there is nothing they would like to do more than to get away from London. A boating holiday with lots of fresh air and exercise would be just the very thing, or so their doctors tell them. So, after debating the merits of hotel or camp beds and what to pack, they set off on their voyage - a trip up the Thames from Henley to Oxford - but very quickly find themselves ill-equipped for the trials of riverbank life.', '/oG7Yawt8Gnz8fksOtdbcEgkuqsI.jpg', '1975-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16198, 'Rocky Horror 45: The Movie', 946250, NULL, NULL, 'Rocky Horror 45: The Movie', 'Underground filmmaker Manny Velazquez dives into the immortal history and legacy of The Rocky Horror Picture Show and its lesser known sequel Shock Treatment with a collection of interviews, convention footage and more.', '/8AOb8WuJAvM21WNO3eLmL17s8g9.jpg', '2021-05-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16199, 'Schmoedipus', 141215, NULL, '/mJMaYqO8uiRkwXi8NTj02OLy3GD.jpg', 'Schmoedipus', 'Glen, a complete stranger, appears at the door of Elizabeth Carter, a middle-aged woman, and claims to be the illegitimate son she gave away at birth.', '/ejU1AL6DZC1yUTWpTBLNFUGbN2l.jpg', '1974-06-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16200, 'What About Dick?', 143295, NULL, '/g3pix5tYyR0h3u2leZVbVEjXFzl.jpg', 'What About Dick?', 'The movie begins with the birth of a sex toy invented in Shagistan in 1898 by Deepak Rushdie Obi Ben Kingsley, and tells the story of the subsequent decline of the British Empire as seen through the eyes of a Piano. The Piano narrates the tale of Dick; his two cousins: Emma, an emotionally stunted English girl; her kleptomaniac sister Helena and their dipsomaniac Aunt Maggie who all live together in a large, rambling, Edwardian novel.  When the Reverend Whoopsie discovers a piano on a beach, a plot is set afoot that can be solved only by a private Dick, the incomprehensible Scottish sleuth Inspector McGuffin, who with the aid of Sergeant Ken Russell finally reveals the identity of the Houndsditch Mutilator.', '/bK553z1Mu3Dh6PdbG61gvfZ18J7.jpg', '2012-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16201, 'Gingerclown', 129385, NULL, '/tW8Lm5KWAUjTvU6eqentNwnx6S3.jpg', 'Gingerclown', '1983: A group of high school students are having a great time near Hollywood Hills at the weekend when they bump into the Loser from their school, Sam, who''s just on his way home. Sam would do anything in order to get Jenny''s attention, one of prettiest girls in school. Unfortunately she''s also the girlfriend of the school''s bully, Biff, the quarterback of the football team. Biff and his buddies are keen to take Sam to the old abandoned amusement park to make him prove his courage as part of their initiation ceremony. They involve Jenny in their cruel game as the grand prize of the competition. Sam accepts the challenge, but the girl wouldn''t let him go in by himself; she follows him into the amusement park and a night they''ll never forget.', '/upuQ9fqbKnyJ8QB11p2pAHvTng4.jpg', '2013-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16202, 'Jimmy Neutron: Operation: Rescue Jet Fusion', 959629, NULL, NULL, 'Jimmy Neutron: Operation: Rescue Jet Fusion', 'Jimmy is enlisted as a spy by the Big Top Secret Organization. His mission: find and rescue Agent X - who turns out to be Jimmy''s movie hero, Jet Fusion.', '/wEHyknqqr6xm9e4a7y1ymqApv9m.jpg', '2003-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16203, 'The Outback', 136405, NULL, '/ocOWqV5xFxrvUE3Hk2ZNZsTwDax.jpg', 'The Outback', 'Being teased for his color, Johnny the white koala joins a traveling carnival with Hamish, a Tasmanian devil, and Higgens, a photographer monkey as talent agents. On the way through the Australian outback desert, the trailer they are in comes loose and crashes. Johnny must live up to the hero status Hamish presents him as while the outback locals try to rescue a kidnapped koala from Bog, a giant crocodile and his dingo lackeys.', '/tcc5ZqiQLhBVK6Mr6hOJOhjIEvC.jpg', '2012-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16204, 'The Ploughman''s Lunch', 160103, NULL, '/uCO5AIYD2xKR8jEaRzN0i87XK0B.jpg', 'The Ploughman''s Lunch', 'As the UK begins its military engagement in the Falklands, a BBC news journalist attempts to climb up from his working-class roots, at any cost, lying to those around him to get what he wants, only to discover  that he is the recipient of a deception far more clever than his own.', '/xi7fht5jEvyRdBaF0cilxGt1vDb.jpg', '1983-05-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16205, 'The Easter Story', 178913, NULL, '/rQTb4g92CTrzqpSFPd75zDxxRAZ.jpg', 'The Easter Story', 'The Greatest Adventure: Stories from the Bible is a television series produced by Hanna-Barbera that tells of three young adventurers—Derek, Margo, and ''their nomad friend'' Moki—who travel back in time to watch biblical events take place in the past. This segment of the story tells about the time the time travelers encounter Mark as he is gathering material to write the Gospel of Mark. He informs them of the events surrounding the Garden of Gethsemene, Jesus'' numerous trials before Annas, Caiaphas, Herod, and Pilate, as well as the Crucifixion and Resurrection. He finishes by telling them of the Ascension.', '/eilh304RBtZIgNBQKCxtR33gCVt.jpg', '1990-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16206, 'Strange Frame', 205392, NULL, '/poP7B207rbxL9q3zDquQfOE3re5.jpg', 'Strange Frame', '28th century, 200 years after the Great Earth Exodus. Naia, a feisty, young singer/songwriter, falls in love with the beautiful saxophonist Parker in Ganymede, one of Jupiter''s moons. The two form a band - and now they have to not only make it as musicians but also to fight for their freedom. Dramatically rendered in rich, hand drawn animation, Strange Frame brings us into a world of space pirates, indentured slaves and genetic mutations - infused with music throughout, to create a dreamlike tale unlike anything you''ve ever seen.', '/kuOGun9Nw5WZg5MWynKTQLm5qX4.jpg', '2012-05-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16207, 'Blue Money', 206312, NULL, '/3vr5OIaEIhmAYsbtIwE6H1fTxQf.jpg', 'Blue Money', 'Mobsters and the IRA chase a stagestruck London cabby (Tim Curry) who has found a briefcase full of cash.', '/dAtjqvWR8Kn8HuoYvCFo3epVTbm.jpg', '1985-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16208, 'The Voyages of Young Doctor Dolittle', 173843, NULL, '/8ff8KL6YULVVVxXCnSAvJyEccNH.jpg', 'The Voyages of Young Doctor Dolittle', 'John Dolittle loves animals just like his uncle, Doctor Dolittle. When John is warned that animals are in danger, he jumps into his uncle’s submarine to help. When he arrives at Dolittle Island, he learns that it has been taken over by Ramsey the Ram and his army of gorillas. With a little help from some new friends, John comes to the rescue and saves the island.', '/nG6ajXQMRv0xsKLYXKo37EwOKv1.jpg', '2011-11-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16209, 'The Wild Thornberrys: The Origin of Donnie', 106333, NULL, NULL, 'The Wild Thornberrys: The Origin of Donnie', 'Donnie goes missing and the rest of the Thornberry family have various adventures (broken bones, getting lost in a cave, and a forest fire) while looking for him. It has been screened as a TV movie and as four episodes in season 4 of the TV series.', '/e4Br3oF0lOyaVpZh415CxEFecb4.jpg', '2001-08-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16210, 'Saving Santa', 238302, NULL, '/qQvojaZWnRgepiPd5ohLRPDs4Vq.jpg', 'Saving Santa', 'A lowly stable elf finds that he is the only one who can stop an invasion of the North Pole by using the secret of Santa''s Sleigh, a TimeGlobe, to travel back in time to Save Santa - twice.', '/luIe2Qe7dYmlJ37CvDaLp2sKxc1.jpg', '2013-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16211, 'Pirates of the Plain', 218970, NULL, NULL, 'Pirates of the Plain', '"Pirates of the Plain" details the adventure of Jezebel Jack, a pirate with a heart of gold that is sent to the future where he meets Bobby, a young boy with an overactive imagination.', '/wrSoUM1ZiPnhfXoppNbij3YxjRb.jpg', '1999-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16212, 'Bruno the Kid: The Animated Movie', 1180681, NULL, NULL, 'Bruno the Kid: The Animated Movie', 'Bruno the Kid  faces a trio of world-class villains, just as his mentor, Jarlsburg, decides to retire.', '/GU6yIkzSmi23rZfR01N0ED3wgp.jpg', '1997-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16213, 'Creating a Myth... the Memories of ''Legend''', 249319, NULL, '/chM682DtvL2RxTHMJEWYyIHdnnG.jpg', 'Creating a Myth... the Memories of ''Legend''', 'This 51 minute documentary of the movie "Legend" can be found as an extra on the 2002 2-disc boxed-set ''Ultimate Edition'' DVD release of "Legend". The first part of the documentary deals with the fruition of the idea and the making of the movie. It includes interviews with almost all the main participants of the feature, with the exception of actor Tom Cruise, who was a no show. The second half is much more fascinating and deals with what went wrong with the movie and its marketing.', '/369kpKTKW5lJ9gb6lKD19FHj5lN.jpg', '2002-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16214, 'Lion of Oz', 146499, NULL, '/j8uA51TN0wUOEgZTuVwrL8dLVcJ.jpg', 'Lion of Oz', 'The Cowardly Lion, of the Omaha Circus and close friends with balloonist Oscar Diggs, is swept away to the Land of Oz, where he—and a number of new friends—cross paths with the Wicked Witch of the East, who seeks the mysterious Flower of Oz.', '/utXFBWyo4i4LaEZKblOG9viZx5N.jpg', '2000-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16215, 'I Love Muppets', 261728, NULL, '/p7uI1nQJ0wy2Hx7J6sPz3OvDkg.jpg', 'I Love Muppets', 'Gonzo the Great talks about the Muppets creator Jim Henson and what he did before the television show was made in 1976.', '/oZAt7E7UJINZIhaZ5hYtHSkjLcL.jpg', '2002-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16216, 'Abel''s Island', 265797, NULL, '/zrr17hCgcMq8aH6CJALw1cUPLS6.jpg', 'Abel''s Island', 'One summer afternoon in 1907, Abel and his wife (both mice) are picnicking, when they become separated during a violent rainstorm. After flying some distance, Abel discovers himself alone on a river island, unable to swim due to the powerful current. Abel periodically attempts to leave the island by various means: flying on a leaf, rowing a crudely fashioned boat, etc. Meanwhile, he tries to create a normal life of sorts, even learning to enjoy a new hobby: sculpture. Still, Abel''s goal is to escape the island and rejoin his wife in the city.', '/bQRtQz0A9fVk3lSvcq86wnlTDES.jpg', '1988-06-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16217, 'The Scoundrel''s Wife', 154119, NULL, '/jd2dSIr5W4aR144Pk1au8ahxVIS.jpg', 'The Scoundrel''s Wife', 'Already an outcast for crimes she did not commit, a woman struggling to raise her two children in a small village during World War II is suspected of being a saboteur.', '/a50lkybzGONv98LvYrVIMZoFUbK.jpg', '2002-03-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16218, 'Superhuman Samurai Syber-Squad: The Glitch That Stole Christmas', 1003946, NULL, NULL, 'Superhuman Samurai Syber-Squad: The Glitch That Stole Christmas', 'In this Christmas special, Malcolm and the evil Kilokahn have finally tracked down Servo. Kilokahn has ordered Malcolm to strand up Christmas lights to pin point him. When Kilokahn finds out that Sam Collins is Servo he tries to destroy him. Kilokahn turns on Malcolm and tries to destroy him as well. Now Sam and Malcolm have to work together after secretly being enemies all along. Servo now has to defeat Kilokahn in a finale battle.', '/a4Jxh5hqGevCRmaLNIyTNJ2CDLo.jpg', '1994-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16219, 'Who Done It: The Clue Documentary', 1026255, NULL, '/hSqRgbLJ1Q9if534Azhp2eekKdl.jpg', 'Who Done It: The Clue Documentary', 'Clue (1985) has become a cult classic film and is loved by multiple generations. Yet there has never been a documentary created to tell the behind the scenes stories...until now.', '/xQjFbRnCnSK6FExTkTWG4ypelKA.jpg', '2022-11-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16220, 'Lover''s Knot', 241058, NULL, '/tLBkJqflkjKpjdm4CZZw2Fw2E4v.jpg', 'Lover''s Knot', 'A pair of lovers have no idea that their affair is overseen and orchestrated by an angel sent by Cupid to see that they remain together in this romantic comedy.', '/tAisZeScQ5aMyD6iUwpLcXOs7Hl.jpg', '1996-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16221, 'Defenders of Dynatron City', 1033171, NULL, NULL, 'Defenders of Dynatron City', 'Made-for-TV special about a delivery man, his friends, and a talking ape mutating into quirky superheroes and fighting a mad scientist who wants to conquer their futuristic atomic city. Based on the eponymous NES video game.', '/uUz8qaqPKbVeUWjUGoZ1v2dWOc.jpg', '1992-02-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16222, 'Passed Away', 62383, NULL, '/4HYBjoT3IJW9dREApR1wizj2DMT.jpg', 'Passed Away', 'Thrown for a loop by the unexpected news that Dad has suddenly gone to his reward, the grieving eccentric Scanian clan are drawn together in a test of familial endurance that soon has them at each other''s throats.', '/kUBxt3YGBOg5Okpg6dUE7DBrRgR.jpg', '1992-04-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16223, 'The Story of Santa Claus', 81685, NULL, '/hGo1mvRe0PJ5BywKkUWEjw7AJBv.jpg', 'The Story of Santa Claus', 'An animated musical that explains how a toymaker named Nicholas Claus (voice of Edward Asner) started the tradition of delivering a toy to every child on Christmas. Other voices: Betty White (Mrs. Claus); Tim Curry (Nostros); Miko Hughes (Clement).', '/qAycltpHtCAdbhvjreUbWf3WXKm.jpg', '1996-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16224, 'Behind the Music: The Rocky Horror Picture Show', 1042169, NULL, NULL, 'Behind the Music: The Rocky Horror Picture Show', 'Identifying the legacy and status of the iconic 1975 cult classic film The Rocky Horror Picture Show.', '/cqCY81kjuo5ukzWIt1GUNkSYmRK.jpg', '1999-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16225, 'Starz Inside: Ladies or Gentlemen', 235737, NULL, NULL, 'Starz Inside: Ladies or Gentlemen', 'Why do movie audiences find men in skirts and women in pants anything but a drag? Discover the playful history of the most daring cross-sexual performances in Hollywood history, from Some Like it Hot to Big Momma''s House.', '/qc4VYtNTgmDKGNtbayZuCQdknV9.jpg', '2008-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16226, 'Curious George 2: Follow That Monkey!', 23903, NULL, '/7vdgvjjXPDtwtQ6aGE6f2PAmavA.jpg', 'Curious George 2: Follow That Monkey!', 'The film chronicles George''s adventures as he befriends Kayla, a baby elephant, at a magic circus show and helps her travel across the country to be reunited with her family.Accompanied by his friend, the Man with the Yellow Hat, George travels by foot, train, and truck to reach Kayla''s brother and sister in California, only to be accused of elephant-napping and brought all the way back to New York.', '/1jkSEqOvp3CnA3UzWrT56cu7yLR.jpg', '2009-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16227, 'Eloise Goes to School', 375603, NULL, NULL, 'Eloise Goes to School', 'After Eloise s tutor Philip quits, nanny enrolls her in the prestigious Hawthorne academy. Eloise can t wait to being real school, but soon finds out it isn t exactly what she was expecting. There are mean girls on the playground, very strict teachers and so many rules rules rules! Eloise decides it s time to make school fun again, she s teaching her new friends to stand up to bullies, helping her teacher understand there are a lot of different ways to learn and having tons of adventures. Can Eloise fit in at her new school? Will she be able to follow all the rules while remaining true to herself? Imagination runs wild and being bored is neer allowed in this fun filled animated adventure featuring the talented voices of Lynn Redgrave, Tim Curry, Neil Patrick Harris and Doris Roberts!', NULL, '2007-07-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16228, 'The Rocky Horror Picture Show: Let''s Do the Time Warp Again', 377448, NULL, '/6IZqrGf06xdaHCt3FmROZcJ7aeu.jpg', 'The Rocky Horror Picture Show: Let''s Do the Time Warp Again', 'After getting a flat tire in the middle of nowhere, newly engaged couple Brad and Janet encounter the eerie mansion of the flamboyant, seductive Dr. Frank-N-Furter and a variety of eccentric characters. Through elaborate dance and rock music, the mad scientist unveils his latest creation: a perfect, muscular man.', '/56KEpnJWe5KvpiPu5XmK14L7Wyr.jpg', '2016-10-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16229, 'Darkwing Duck: Darkly Dawns The Duck', 1301312, NULL, '/kVhUCvCqlPiaUZGfJxOmy0f2SB1.jpg', 'Darkwing Duck: Darkly Dawns The Duck', 'Hey Kids - Join me, Darkwiiiiing Duck, in my all-time favorite adventures chosen from zillions of fan letters. Along with my daughter Gosalyn and my sidekick, Launchpad, we''ll plucl the feathers of all who have gone afowl of the law. So c''mon crimebusters, lets''get dangerous!  Now you can own the original adventure that introduced the legendary masket avenger, Darkwing Duck" Discover how Darkwing first came to adopt Gosalyn, his mischievous daughter, and how Launchpad McQuack first became his loyal and trusty sidekick. Together, our herores battle the notorious Taurus Bulba, the bullish kingpin who steals the goverment''s top-secret weapon, the Ram Rod - then kidnaps Gosalyn because she''s the only who knows the arming code! Can Darkwing grab the bull by the horns in time to rescue her and save the city from ultimate destruction? Get dangerous and find out!', '/2ugzajtl0rHtCCBBra183RbHmds.jpg', '1991-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16230, 'Mucha Lucha: The Return of El Malefico', 410547, NULL, '/eACODw754FpdPP5cb46wis18WFU.jpg', 'Mucha Lucha: The Return of El Malefico', 'The hit TV series boldy goes bigger in an action-packed comedy/adventure starring everyone''s favorite luchadoras! When the greatest evil the world has ever knows -El Malefico -surfaces from the dark recesses of Earth, it''s up to Rikochet, Buena Girl & The Flea to mask-wrestle him back! Their challenge begins with a quest around the globe for the artifacts of bueno-ness & ends in Las Vegas', '/5rKLz9X8ZOT6CJtf4jNpWYSVNPK.jpg', '2005-01-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
