INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16238, 'Pennywise: The Story of ‘It’', 512356, NULL, '/fp7P88mD34Ie6yLyzuLC8qFjmRJ.jpg', 'Pennywise: The Story of ‘It’', 'Thirty-plus years after its release, the popular two-part miniseries "It" and its infamous villain Pennywise live on in the minds of horror fans around the world. This documentary captures not only the buzz the "It" saga generated in 1990 but also the lasting impact it has had on an entire generation and the horror genre at large. Several years in the making, the film features exclusive interviews with many of the cult classic''s key players, from cast members Richard Thomas, Seth Green, and Tim Curry, who portrayed the notorious monster clown Pennywise, to director Tommy Lee Wallace and special effects makeup artist Bart Mixon. The documentary also boasts a wealth of archival material and never-before-seen footage.', '/z6LfGKuA19tt0ckc8UN91rAmJF8.jpg', '2021-10-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
