INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16243, 'The More I Know', 442400, NULL, '/cH08Jzte0ooq21uHoAyqU9gLFrJ.jpg', 'Čím víc vím', 'A weary old man is getting ready to die. He has nothing more to fear and decides to share the secret of his life with us. While his relatives wait outside the door, eager to get a share from what was once his, he takes us on a journey through his memories. What will be the ultimate truth he chooses to pass on?', '/yd9HoMfKN6pcOepAMe62qa5Al2o.jpg', '2016-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
