INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16245, 'Video Stars', 672966, NULL, NULL, 'Video Stars', 'A new underground TV-Channel is set up. This comedy drama about the rise and fall of a cable TV channel. Vunderful Video chain owner Bob Surge gets the franchise for one of the new public access TV channels and wants it to rekindle his spirit of rebellion. He hires employee Max Loom to run the station and Max creates something wild, including presenter Teddy Whazz. It''s the wild west and edgy and exciting, but dark clouds are looming for Max and the gang when they draw the attention of right wing censorship group Cable Concern.', '/ljycG70asIkUw6h0QB5VvlOih8K.jpg', '1983-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16246, 'The Shout', 48131, NULL, '/vImleBhNfUQXxmWXivZsA2Bc4Lb.jpg', 'The Shout', 'A traveller by the name of Crossley forces himself upon a musician and his wife in a lonely part of Devon, and uses the aboriginal magic he has learned to displace his host.', '/89SfSiIgUjyxPDaRe5SedgVRggV.jpg', '1978-06-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16247, 'Lights! Camera! Annie! The Making of a Major Hollywood Musical', 823261, NULL, '/unJb7PJaEsnKIUNckgDP8dtTV44.jpg', 'Lights! Camera! Annie! The Making of a Major Hollywood Musical', 'An in-depth look into the making of the film Annie (1982). It covers the adaptation changes from the original Broadway musical, the hiring of director John Huston, the nationwide search to cast the title role, the production process, and the conception of several musical numbers, including a different version of the song "Easy Street" than the one that ended up in the film.', '/aI2Agbk4ve1J4tTvN0LZIaLQotg.jpg', '1982-03-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16248, 'The Titanic Chronicles', 1356717, NULL, NULL, 'The Titanic Chronicles', '"The Titanic Chronicles" is based on the 1912 Senate Hearings into the "Titanic" Disaster. The actual testimony is read by an international cast. This program is an enactment of the most striking and revealing moments from the actual hearings. The testimony you will hear comes closest to the truth as to why the R.M.S. "Titanic" now lies on the bottom of the North Atlantic.', '/59ag4JJjQz08RP12rLrxANzIesJ.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
