INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16251, 'The Not So Golden Calf: Commandments 1-2', 41906, NULL, NULL, 'The Not So Golden Calf: Commandments 1-2', 'The award-winning Kids'' Ten Commandments series includes great Bible lessons for kids! This 5-DVD K*10*C collection features state-of-the-art animation and inspirational music the entire family will enjoy. Through the adventures of Seth, an 11-year old boy, these captivating stories bring God''s Ten Commandments to life for children ages 6-11. Each of the five Bible videos teaches children how to apply the Ten Commandments to their daily lives. Featuring acclaimed Hollywood talent that includes Peter Strauss as Moses and other famous voices such as Tom Bosley, Jodi Benson, and Paul Winfield, your children will delight in learning about our great and awesome God!', '/bNgmakhghRw9waA0t5Iaf0JHbA9.jpg', '2003-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16252, 'Jimmy Neutron: The League of Villains', 1326553, NULL, NULL, 'Jimmy Neutron: The League of Villains', 'King Goobot gathers several of Jimmy''s enemies and they team up to defeat him once and for all. When Jimmy and Sheen are captured, it''s up to Carl, Cindy and Libby to rescue them.', '/hjHBoTc8SIljs9Rv7weOVnkmVYf.jpg', '2005-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:57', 0);
