INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16258, 'The United States of Leland', 13573, NULL, '/lIWbyPbnUUJPUvzwIN4BaeEGIgU.jpg', 'The United States of Leland', 'A withdrawn young man, Leland Fitzgerald is imprisoned for the murder of a mentally disabled boy, who also happened to be the brother of his girlfriend, Becky. As the community struggles to deal with the killing, Pearl Madison, a teacher at the prison, decides to write about Leland''s case. Meanwhile, others affected by the murder, including Becky and her sister, Julie, must contend with their own problems.', '/60B0kXNSy3isCSZtM3vl2GWeKdE.jpg', '2003-05-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16259, 'Seduced and Abandoned', 193645, NULL, '/spgZcy2k1SSjnvBGONXKMxQWXhC.jpg', 'Seduced and Abandoned', 'SEDUCED AND ABANDONED combines acting legend Alec Baldwin with director James Toback as they lead us on a troublesome and often hilarious journey of raising financing for their next feature film. Moving from director to financier to star actor, the two players provide us with a unique look behind the curtain at the world''s biggest and most glamourous film festival, shining a light on the bitter-sweet relationship filmmakers have with Cannes and the film business. Featuring insights from directors Martin Scorsese, ''Bernando Bertolucci'' and Roman Polanski; actors Ryan Gosling and Jessica Chastain and a host of film distribution luminaries.', '/gaXPdoGRurNLgfyRrUDKsa95fYa.jpg', '2013-05-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16260, 'NWR', 137923, NULL, '/nR56cXUagnENB60ASMmvVPnE0Xi.jpg', 'NWR', 'A documentary about Danish director Nicolas Winding Refn, winner of the Best Director award at the Cannes Festival in 2011 for Drive. From his childhood to the shooting of his next movie, Only God Forgives, in Thailand, discover the whole career of a truly visionary filmmaker. With Ryan Gosling, Mads Mikkelsen, Alejandro Jodorowsky, Gaspar Noé, Peter Peter and Zlatko Buric.', '/wAYFxiqH3SIGKxjOqdGAXAjNNz3.jpg', '2012-02-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16261, 'My Life Directed by Nicolas Winding Refn', 291868, NULL, '/p2qtXoAAPs5grMwxsZkDmUHv3Ra.jpg', 'My Life Directed by Nicolas Winding Refn', 'A documentary directed by Winding Refn''s wife, Liv Corfixen, and it follows the Danish-born filmmaker during the making of his 2013 film Only God Forgives.', '/tH83eBJ10SrhJhOPnl4mv0ofp23.jpg', '2015-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16262, 'Frankenstein and Me', 3119, NULL, '/tl8cFqGnsGnSqgHl2icsIMXAtgb.jpg', 'Frankenstein and Me', 'Earl Williams is a dreamer teenager obsessed with monsters, who fantasizes his life as if he were living in the world of the monsters of Universal Studios. Although being an excellent student, his intolerant and nasty school teacher Mrs. Perdue does not like him and punishes him for any minor fault. His supportive father Les Williams is also a dreamer, who has never been successful in life. When his father dies, his mother becomes lost with two boys, and tries to change the behavior of Earl. One day, the boy finds the "true Frankenstein" lost by a Carnival, and decides to bring the monster back to life.', '/4QWlmX69UAXlcySa9CJ5Q4Oqj7o.jpg', '1996-07-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16263, 'Nothing Too Good for a Cowboy', 118443, NULL, '/aOuAe3pTrJ4Xuy6hTZgkORrXGjb.jpg', 'Nothing Too Good for a Cowboy', 'A group of young adults struggle to run the biggest cattle ranch in the world amidst World War II.', '/8G4N7ZYvQiiCyDZEYm1nG4LMj7s.jpg', '1998-01-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16264, 'ReGeneration', 105942, NULL, NULL, 'ReGeneration', 'ReGeneration is a 2010 U.S. documentary film written and directed by Phillip Montgomery that looks at the issues facing today''s youth and young adults, and the influences that contribute to the U.S.''s current culture of apathy toward political and social causes.', '/enLq1u6ns4353kbz26gqez1ECOF.jpg', '2010-05-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16265, 'Goosebumps: Say Cheese and Die', 577414, NULL, '/lvtI3DRlhGMkf29C5yQ6duQBsRC.jpg', 'Goosebumps: Say Cheese and Die', 'Greg and his friends break into an old warehouse, where they find an unusual camera. However, the photographs Greg takes with it seem to predict disaster, and he becomes convinced the camera is cursed.', '/nBbpedXLqX2zqgEcMYjvewhKqhB.jpg', '1996-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16266, 'My Favorite Shapes by Julio Torres', 612392, NULL, '/dqXW5kXQeok9AOaAu6WzBW1DkB5.jpg', 'My Favorite Shapes by Julio Torres', 'In this multimedia comedy show, Torres explores his favorite shapes, which include a plexiglass square, a triangle, an oval that wishes he were a circle, a self-conscious cactus and a Ferrero Rocher chocolate that Julio is mad at because she left her little skirt at home. The objects are presented via an industrial conveyer belt and serve as a jumping-off point for fantastical stories, anecdotes and jokes.', '/v1Bx5clsiLnAmHPOqRIMOnFmKrY.jpg', '2019-08-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16267, 'I’m Still Here: Real Diaries of Young People Who Lived During the Holocaust', 630122, NULL, NULL, 'I’m Still Here: Real Diaries of Young People Who Lived During the Holocaust', 'Brings to life the diaries of young people who witnessed first-hand the horrors of the Holocaust. Through an emotional montage of archival footage, personal photos, and text from the diaries themselves, the film celebrates a group of brave, young writers who refused to quietly disappear.', '/pSYZIPgIlBaTQMiWrnIcpa3EKLa.jpg', '2005-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16268, 'The Blade Runner Phenomenon', 833898, NULL, '/iSDQjFsfmI1JUaI4Nzv1jRAb0Gc.jpg', 'Das Phänomen Blade Runner', 'Ridley Scott''s cult film Blade Runner, based on a novel by Philip K. Dick and released in 1982, is one of the most influential science fiction films ever made. Its depiction of Los Angeles in the year 2019 is oppressively prophetic: climate catastrophe, increasing public surveillance, powerful monopolistic corporations, highly evolved artificial intelligence; a fantastic vision of the future world that has become a frightening reality.', '/2ANJtUxqBlCLpV8CXv3BPLo0FV5.jpg', '2021-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16269, 'Misadventure', 1263014, NULL, NULL, 'Misadventure', 'In early development. In the vein of Crazy Stupid Love. Plot TBA.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
