INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16274, 'Megadoc', 1290369, NULL, '/95rvRmyXhHyErlg7kHZ10sxyVUc.jpg', 'Megadoc', 'Presenting a behind-the-scenes account of a visionary at work. From Oscar-nominated Mike Figgis, Megadoc gives audiences an unfiltered and intimate look at the making of Francis Ford Coppola’s epic sci-fi drama Megalopolis.', '/yjiqwnvgst3ntm25L5heBHjqny9.jpg', '2025-09-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
