INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16278, 'The Blood of Others', 4841, NULL, '/4CcD9akZavNAWpj6K8cGi9kR1NH.jpg', 'The Blood of Others', 'In the German-occupied Paris, Helene is torn between the love for her boyfriend Jean, working for the resistance and the German administrator Bergmann, who will do anything to gain her affection.', '/w1xtkJzKQjTeOkaZ16hTlxSITuw.jpg', '1984-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16279, 'Little Man Tate', 11521, NULL, '/lY1dSP8rtLxtnTPS1KM6ywYQK6Z.jpg', 'Little Man Tate', 'Dede is a sole parent trying to bring up her son Fred. When it is discovered that Fred is a genius, she is determined to ensure that Fred has all the opportunities that he needs, and that he is not taken advantage of by people who forget that his extremely powerful intellect is harboured in the body and emotions of a child.', '/eXf4xhJEc9c2NElBrExmiWFe4Pz.jpg', '1991-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
