INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16283, 'Stealing Home', 32331, NULL, '/hNKRqiXxDPhWCsJn5r2Q7hWRDfS.jpg', 'Stealing Home', 'Billy Wyatt, a former high school and minor-league baseball player, receives a telephone call from his mother revealing that his former child-sitter, and later in his teens, his first love, Katie Chandler, has died. Wyatt returns home to deal with this tragedy, reminiscing over his childhood growing up with his father, Katie, and best friend Alan Appleby.', '/pwl2DNSO4nnOYUTMubBC2DpMpOQ.jpg', '1988-08-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16284, 'Catchfire', 32924, NULL, '/jsL6WdEhvhEnYu9k1BiVhtI316v.jpg', 'Catchfire', 'A witness to a mob assassination flees for her life from town to town, switching identities, but cannot seem to elude Milo, the chief killer out to get her.', '/9cKFLrXTwzNO8NGfF1kf9nQcsNT.jpg', '1990-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16285, 'Beyond the Visible: The Story of the Very Large Array', 1097548, NULL, NULL, 'Beyond the Visible: The Story of the Very Large Array', 'Narrated by Academy Award-winning actress Jodie Foster (star of the film "Contact," which was based on the novel by Carl Sagan and filmed at the VLA), the program depicts many of the people whose diverse efforts enable the VLA to be a cutting-edge resource for astronomers and humanity worldwide.', '/yFZADhua734ZRxosNHyBYbHni9W.jpg', '2013-10-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16286, 'Siesta', 42014, NULL, '/bNVUGpdOn7mfxWJL86CWhWc3904.jpg', 'Siesta', 'American Claire wakes up blood-soaked and bruised at the end of a runway in Spain. As she tries to account for her state, she has flashbacks from the past few days. She thinks she''s killed someone, but isn''t sure, and now she''s wandering the Spanish streets without money or a clear memory.', '/qkBcoO3yHJC0WeAVdiZhw78kBem.jpg', '1987-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16287, 'Candleshoe', 14612, NULL, '/6NMedeS4pbfsPfhycL3XH3tCH8U.jpg', 'Candleshoe', 'When ex-con artist Harry claims that a secret treasure is hidden inside Candleshoe, an English estate, he creates an elaborate plan to find and steal the prize. By convincing a girl named Casey to impersonate the estate owner''s long-lost granddaughter, Harry hopes to uncover the treasure''s location. But when Casey has a change of heart, she must follow the clues and find the treasure, in order to save Candleshoe and stop Harry before it is too late.', '/6Rq9u5fnS6PzWz9dgPQmBhgDvRJ.jpg', '1977-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16288, 'Cinefile: Reel Women', 814416, NULL, '/j76KGrkZvCIC9x7pAd5qhKJ77I5.jpg', 'Cinefile: Reel Women', 'Interviews with women directors working in Hollywood and Europe in the early 1990s, exploring the opportunities and obstacles that face them. A program made to accompany a Channel 4 season of films directed and produced by women.', '/rlDVeHpKlm6GioUdNsxc5qcicfc.jpg', '1995-02-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16289, 'Freaky Friday', 16084, NULL, '/wsapbputwZHPNUy3fLnEjmc7QZw.jpg', 'Freaky Friday', 'School girl Annabel is hassled by her mother, and Mrs. Andrews is annoyed with her daughter, Annabel. They both think that the other has an easy life. On a normal Friday morning, both complain about each other and wish they could have the easy life of their daughter/mother for just one day and their wishes come true as a bit of magic puts Annabel in Mrs. Andrews'' body and vice versa. They both have a Freaky Friday.', '/ensFUbvS08uvG0xJze1MqhhjQJ1.jpg', '1976-12-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16290, 'One Little Indian', 45827, NULL, '/gZZi6cUl0M4zJBTw8dlXGQpNqBs.jpg', 'One Little Indian', 'An Army deserter flees by camel across the desert with a caucasian boy raised by Indians.', '/fPwJ82UoWF1NvC3prhlQ3WMNhKN.jpg', '1973-06-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16291, 'Everest: The Death Zone', 46285, NULL, NULL, 'Everest: The Death Zone', 'Get ready for a (literally) breathtaking trek up Mt. Everest, from Base Camp at 17,600 feet; through the chilling, corpse-strewn Death Zone; to the very pinnacle of the the Earth, five and a half miles above sea level. For those brave souls who survive the harrowing climb to the top of the world, it is a transformative experience. But can the excruciating ascent—through frigid cold, blasting wind, blinding sun, and severe lack of oxygen—cause permanent, damaging changes to the human brain and body? In the wake of the 1996 disaster that took eight climbers in a single day, scientists follow a team of hikers to measure, for the first time ever, the toll high-altitude climbing takes on the heart, lungs, blood, and brain. Why do seemingly rational people make poor, sometimes fatal decisions as they approach the peak? And the danger doesn’t end there—as NOVA discovers during the descent, when one climber''s respiratory illness takes a terrifying turn on the isolated mountainside.', '/yqOzDgoWnkPKFOIuM01OGYQt5aR.jpg', '1998-02-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16292, 'The Dangerous Lives of Altar Boys', 16857, NULL, '/kukeEqfKiybvnyppV1RilJrbSI9.jpg', 'The Dangerous Lives of Altar Boys', 'A group of Catholic school friends, after being caught drawing an obscene comic book, plan a heist that will outdo their previous prank and make them local legends.', '/4uTWXZ2Rvizl3ycMHtODfRjks4W.jpg', '2002-06-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16293, 'The Beaver', 50780, NULL, '/sCjTJ3R8UKmyd9dvMPLQ61nZIfY.jpg', 'The Beaver', 'Suffering from a severe case of depression, toy company CEO Walter Black begins using a beaver hand puppet to help him open up to his family. With his father seemingly going insane, adolescent son Porter pushes for his parents to get a divorce.', '/nlaWgS7iIb6MG3t0FitV1xdPqIV.jpg', '2011-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16294, 'The Little Girl Who Lives Down the Lane', 19971, NULL, '/kZPoR6PTQQDThvHDnmloXPa60bC.jpg', 'The Little Girl Who Lives Down the Lane', '13-year-old Rynn Jacobs lives in a New England beach town. Whenever the landlady inquires after Rynn''s father, she claims that he''s not available. But when the landlady''s son, Frank, won''t leave Rynn alone, she teams up with a neighbor Mario to maintain the dark family secret that she''s been keeping to herself.', '/qlH7atDoN2iOmq6pNsoFIlebhgA.jpg', '1976-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
