INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16303, 'It Was a Wonderful Life', 274320, NULL, NULL, 'It Was a Wonderful Life', 'They''re clean, educated, articulate and rarely receive public assistance. But following a divorce, job loss or a long illness, a growing number of middle-class women are forced to live out of their cars. Directed by Michèle Ohayon (Colors Straight Up) and narrated by Jodie Foster, It Was a Wonderful Life chronicles the hardships and triumphs of six "hidden homeless" women as they struggle to survive, one day at a time.', NULL, '1993-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
