INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16311, 'Three Gorges: The Biggest Dam in the World', 377429, NULL, NULL, 'Three Gorges: The Biggest Dam in the World', 'Explores the plans for the construction of the monumental dam on China''s Yangtze River, the structure that when completed in 2009 will become the Three Gorges Dam. It is slated to be 610 feet high, 1.3 miles across, creating a reservoir 400 miles and the largest power plant in the world.', NULL, '1998-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16312, 'Inside the Labyrinth: The Making of ''The Silence of the Lambs''', 401439, NULL, '/2vZFPGALsQ4YAlYPyycvVB3mbGE.jpg', 'Inside the Labyrinth: The Making of ''The Silence of the Lambs''', 'A behind-the-scenes look at the making of this Oscar winning thriller, prepared for its tenth anniversary. Includes interviews with star Anthony Hopkins, as well as other members of the cast and crew, giving their views on the experience of creating this masterpiece of terror and suspense.', '/2NMhqlNgzHnWgfJ15Yr2XFiDcYr.jpg', '2001-08-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
