INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16314, 'Movies Are My Life', 421029, NULL, '/lavfwiCiF7HfBC27fMzs8OKc45w.jpg', 'Movies Are My Life', 'The very first full-length documentary on Scorsese offers an invaluable look at how he was perceived by his colleagues, and himself, in 1977. Catching Scorsese while he was in post-production on New York, New York and editing The Last Waltz, British filmmaker Peter Hayden gets the manically hyper Scorsese to comment on his youth, his relation to his lead characters, the making of Mean Streets and most importantly, his approach to direction. The doc doesn’t quite move at the pace of Scorsese’s revved-up speed-talking, but it does offer some real insight into his productivity in the 1970s, thanks to an impressive array of talking heads. Included are Scorsese’s collaborators Jay Cocks, Mardik Martin, Brian De Palma, Steven Prince (who co-produced this doc), and his mentor John Cassavetes. Also the performers, who discuss his working methods in detail — Jodie Foster, Liza Minnelli, and, of course, Robert De Niro.', '/enYQT1PlCkV3zlTvyHsEaBKK41u.jpg', '1988-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16315, 'Menace on the Mountain', 103801, NULL, '/wcgOmUkoSyRaLaVW2XARCm9B5ta.jpg', 'Menace on the Mountain', 'A period piece about the McIver family trying to protect there home from Civil War deserters. Actor Jodie Foster, then approximately 8, plays Suellen McIver. Actor Mitch Vogel, Jamie, is their protector.', '/5K9Mw8ddb17wJxRZ7lNILrSC7lf.jpg', '1970-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16316, 'Disney Legends Awards Ceremony', 1329282, NULL, '/xtgUJ5Bqcd0xLC63lZuz0ajjsyI.jpg', 'Disney Legends Awards Ceremony', 'Since 1987, the Disney Legends Awards program has honored individuals for the significant impact they''ve had on the Disney legacy. See the 2024 honorees become Disney Legends.', '/r4FUMC48pRQW5X2d26BbAGnu0m5.jpg', '2024-08-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16317, 'Hinckley', 1317462, NULL, '/97a8fc0MdWqM8TxaV6CNcmfzBGS.jpg', 'Hinckley', 'In March 1981, inspired by a dangerous obsession with the film Taxi Driver and actress Jodie Foster, a man named John Hinckley tried to assassinate President Ronald Reagan. The attack shocked the world and forever changed American history. Found not guilty by reason of insanity, Hinckley spent thirty-five years in a psychiatric hospital. Nearly 40 years later, a judge granted him his unconditional release.  HINCKLEY presents an unsparing profile of a man whose shocking act of political violence forever changed a nation and still resonates today. It examines Hinckley''s troubled early life, his obsessions and other attempts at assassination, the leadup and aftermath of his attack on Reagan, and whether or not redemption is possible for one of America''s most infamous men, especially in a nation deeply divided by politics and gripped by gun violence.', '/lz5cp58GXqPuWYsikprI2sQJvSi.jpg', '2024-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16318, 'Hotel Artemis', 406761, NULL, '/9E4mLJY4ZiQDPi2KR8cWr7mHF8o.jpg', 'Hotel Artemis', 'Los Angeles, June 21st, 2028. While the streets are being torn apart by riots, the Nurse, who runs a clandestine hospital for criminals in the penthouse of the Artemis, a closed old hotel, has a rough night dealing with troublemaker clients: thieves, assassins, someone from the past and the one who owns the place and the whole city.', '/vaZMpZOhhkKOYz0MHCx4vDABwgP.jpg', '2018-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16319, 'Motherhood', 22805, NULL, '/8ic41TNDfkewNkN9lcZMbST1fdS.jpg', 'Motherhood', 'In Manhattan, a mother of two preparing for her daughter''s sixth birthday party has no idea of the challenges she''s about to face in order to pull off the event.', '/bzQCsmvPJU0L4tnPtQHlVliw2zn.jpg', '2009-01-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16320, '100 Films and a Funeral', 86074, NULL, NULL, '100 Films and a Funeral', 'A lively look at the history of the twice-risen, twice-fallen London-based Polygram Filmed Entertainment, which in its heyday produced such titles as Fargo, The Usual Suspects, and Four Weddings and a Funeral.', '/kZZaRmtogZpYj0vES7TKEXntX0o.jpg', '2007-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16321, 'Be Natural: The Untold Story of Alice Guy-Blaché', 520270, NULL, '/eLRuEg6wcJf6aFgy8UBrnN8DmN3.jpg', 'Be Natural: The Untold Story of Alice Guy-Blaché', 'The epic life story of Alice Guy-Blaché (1873–1968), a French screenwriter, director and producer, true pioneer of cinema, the first person who made a narrative fiction film; author of hundreds of movies, but banished from history books. Ignored and forgotten. At last remembered.', '/o5fz4qNgI5nfDirf6UcX0SpAG6T.jpg', '2018-12-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16322, 'Jonathan Demme & Jodie Foster', 526062, NULL, NULL, 'Jonathan Demme & Jodie Foster', 'Documentary about the making of "The Silence of the Lambs" (1991). Presented as three short documentaries on the collector''s edition DVD (MGM, January 2007), but first appeared in the 2005 European release.', '/8Dn1xcIRP4joqMuAeTOACyqupkz.jpg', '2005-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
