INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16324, 'Grease Day USA', 533039, NULL, NULL, 'Grease Day USA', 'The star-studded premiere party for "Grease," featuring numerous unrelated musical performances.', '/kC4wwspRSIpgXSt0a8FSLjUHhfN.jpg', '1978-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
