INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16328, 'Hollywood’s Children', 724336, NULL, NULL, 'Hollywood’s Children', 'A documentary about child actors, since the beginning of motion pictures (narrated by Roddy McDowell).', '/exM4LwDOub66LklnyVsSY8i6Xqc.jpg', '1982-02-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16329, 'The True Story of Hannibal', 747477, NULL, NULL, 'The True Story of Hannibal', 'Hannibal, one of the greatest military leaders in history, accompanied his father Amílcar Barca at the age of nine on the Carthaginian expedition to conquer Spain. Before embarking, the boy swore eternal hatred for Rome, the bitter rival of his people. Twenty years later, in 218 a. C., he left Nueva Cartago (now Cartagena, Spain) to wage war in "The Eternal City" with an army of about 40,000, including cavalry and elephants.', NULL, '2005-01-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16330, 'Reel Herstory: The Real Story of Reel Women', 551186, NULL, NULL, 'Reel Herstory: The Real Story of Reel Women', 'Using rare footage and exclusive interviews with filmmakers from all over the globe, "Reel Herstory" corrects the historic notion that women behind the scenes in motion pictures held peripheral careers compared with their male counterparts.', '/sCCp4mbAHUItaQoAKMOmW5YNChS.jpg', '2014-08-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16331, 'Inside Story - The Silence of the Lambs', 384189, NULL, '/A7CO0G2HH4PitAjpcUIMhkuLiYk.jpg', 'Inside Story - The Silence of the Lambs', 'With interviews from cast and crew, including stars Jodie Foster, Anthony Hopkins, and director Jonathan Demme, this feature-length documentary tells the story of how a film with a young director trained in B-movies and cheesy comedies managed to make one of the most chilling films in decades, and how a studio in the midst of collapse turned out a film that took the box office - and Oscars - by storm.', '/2krRKeQIpBbzihmJpVPevmVUwUu.jpg', '2010-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16332, 'Jodie Foster: Hollywood Under the Skin', 837550, NULL, '/x5GWEKfu1VKKlUWafaD5iT9ItzO.jpg', 'Jodie Foster - Hollywood dans la peau', 'From her precocious status as a sex symbol to her consecration as a filmmaker, Jodie Foster''s story is about a feminist struggle, albeit atypical, fought on and off the screen. This film sets out to retrace her remarkable journey within the Hollywood industry.', '/jebdlRpJ2pHTcjTNKP8IDrvXeVm.jpg', '2021-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16333, 'Sesame Street | All-Star 25th Birthday: Stars and Street Forever!', 519896, NULL, '/pEm58Bv3SkO6H1yfQKcfDq8pCL1.jpg', 'Sesame Street | All-Star 25th Birthday: Stars and Street Forever!', 'Sesame Street All-Star 25th Birthday: Stars and Street Forever! was a 1994 TV special that aired on ABC to celebrate Sesame Street''s 25th anniversary. It was originally broadcast on May 18, 1994.  The show featured Joe Pesci (as Ronald Grump), Corbin Bernsen (as real estate attorney, Arnie), Danny DeVito and Rhea Perlman (as a Worm TV hosts), John Goodman (as Tough Guy Helpline operator), Charles Grodin (as Chaz), Julia Louis-Dreyfus (as reporter Kathie Lee Kathie), Rosie O''Donnell (as the Good Hope Fairy), Susan Sarandon (as Bitsy), Barbara Walters (reporting for 25/25), and Regis Philbin and Kathie Lee Gifford (as themselves).', '/sywn5nLdKJ0W7hegEJcE9WAPraW.jpg', '1994-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16334, 'Scooby-Doo Meets The Addams Family', 1397947, NULL, '/ojy5hnmG2NmUI51TUDqnDrBWR3.jpg', 'Scooby-Doo Meets The Addams Family', 'With the Mystery Machine stuck in mud, Mystery Inc. ends up becoming housekeepers for the Addams Family while Gomez and Morticia go on vacation to the Okefenokee Swamp. A giant vulture like super villain known as the Vulture threatens the Addams house and Wednesday goes missing, so Scooby and the gang go to find her and stop the Vulture.', '/4WtNHKi8IC9emisqMoDuhG6gHWT.jpg', '1972-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16335, 'Early Directors on Directing', 1095257, NULL, NULL, 'Early Directors on Directing', 'There were more women directors before 1920 than at any other time in history. The first director to put a narrative story on celluloid was, Alice Guy Blaché in 1896. Few people know that Lillian Gish became a director in her own right in 1920. Ida Lupino directed over a hundred episodes of "Have Gun, Will Travel," "Thriller," "Gunsmoke," and many independent features.', '/yAQ4c7dU7sR0nuC2yBCBwIOp6hv.jpg', '2009-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16336, 'Henry Louis Gates Jr.: Uncovering America', 688875, NULL, NULL, 'Henry Louis Gates Jr.: Uncovering America', 'Actor Courtney B. Vance hosts this special celebrating Dr. Henry Louis Gates, Jr.''s work with focus on his five quintessential documentary series about American, African and African American history for PBS.', NULL, '2019-03-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16337, 'The Silence of the Lambs: The Beginning', 1473742, NULL, '/1QexeL8r63KfLW9adAdE9okZiX.jpg', 'The Silence of the Lambs: The Beginning', '"The Beginning" is one of three Johnathan Demme & Jodie Foster documentary features included in the physical release of "The Silence of the Lambs." This part focuses on the early beginnings of the script, story and how it came to unfold.', '/h4NGQZzaiw3LMXwDrVfmSTrEyrK.jpg', '2005-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16338, 'The Silence of the Lambs: Making Silence of the Lambs', 1473743, NULL, '/1QexeL8r63KfLW9adAdE9okZiX.jpg', 'The Silence of the Lambs: Making Silence of the Lambs', '"Making Silence of the Lambs" is one of three Johnathan Demme & Jodie Foster documentary features included in the physical release of "The Silence of the Lambs." This part discusses and showcases the different aspects that went into the making of the film.', '/ohZmRYXU8KmKrLMfUsEQcvhNS7M.jpg', '2005-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16339, 'The Silence of the Lambs: Breaking the Silence', 1473744, NULL, NULL, 'The Silence of the Lambs: Breaking the Silence', '"Breaking the Silence" is one of three Johnathan Demme & Jodie Foster documentary features included in the physical release of "The Silence of the Lambs." This part talks about film''s tone, impact, release and how it was received.', '/eiIRxgR65rlG1CODNhwEl3OwEsJ.jpg', '2005-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16340, 'Jodie Promo', 1485142, NULL, NULL, 'Jodie Promo', 'a chronological coming attractions overview of Jodie Foster’s career', NULL, '1995-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16341, 'A Look Back with Jodie Foster', 1558848, NULL, NULL, 'A Look Back with Jodie Foster', 'Jodie Foster reminisces about her time filming Freaky Friday and other Disney films.', '/ioe0XerN7psTP9i0xzN4otBUe4z.jpg', '2004-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16342, 'Breakdown: 1975', 1584125, NULL, '/lHSLTzz1rW3XcfJYTyCSdaPmosr.jpg', 'Breakdown: 1975', 'In 1975, as America faced social and political upheaval, filmmakers turned chaos into art.', '/6LirpQnBmBpAOa5Me1lBCBBy90e.jpg', '2025-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16343, 'The Making of ''...And God Spoke''', 41660, NULL, '/32DrtHSSw5kMaDxYErrQINRIeiA.jpg', 'The Making of ''...And God Spoke''', 'A documentary on the making of a big budget Bible picture. This is a spoof that shows the inside action on a film set where everything that could possibly go wrong goes wrong.', '/yRpHivmM03ziTnYTTqFNmKY9TfY.jpg', '1994-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16344, 'Henry Fonda for President', 1221622, NULL, '/rjcJsm1DWOZf776eKuZz59cgBZI.jpg', 'Henry Fonda for President', 'A personal essay about the United States viewed through the life and work of the late American film and stage actor Henry Fonda.', '/sIwhdJ2EqC292XD6L0H143HLhgL.jpg', '2025-01-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16345, 'Junkyard Dogs', 876487, NULL, '/1uF30AAoF6bajoZ7HwrDrGhhpCG.jpg', 'Junkyard Dogs', 'Follows a dog who is a master escape artist, who must team up with his puppy pals to prevent their block from being robbed.', '/7dy7qz736fvx3KBECpNKZNP6sRC.jpg', '2022-08-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16346, 'Blackwoods', 30779, NULL, '/eKgT1LT6LgKIqMYP5yceICei8W2.jpg', 'Blackwoods', 'Matt is haunted by the death of a girl from a car accident he caused years ago. Matt was drunk and as he reached for the car radio, he struck the girl as she crossed the road. The guilt that he feels has altered his sense of reality, making Matt''s life a mystery full of shadows and phantoms. Now, years later Matt goes away for weekend with his new girlfriend Dawn. After a wild session of lovemaking, Dawn goes for a walk. While she is away a strange man with an ax comes into the motel room and attacks Matt. After that incident Matt goes into the woods, looking for Dawn. There he encounters Dawn''s family who tie him down and put him on trail for the murder of the girl years before. They find him guilty and he is sent back into the forest to be hunted down by the family. The deeper Matt runs into the forest the farther his mind is lost to the Blackwoods.', '/hkrYVd2ivJBmeLTGs1TEPJ5Arjo.jpg', '2001-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16347, 'Deadlock', 718949, NULL, '/fm30gY7bWBYRlDMAy5deIb6wspK.jpg', 'Deadlock', 'Mack is a former soldier who, after the war, moved to a town with a nuclear power plant, where nearly everybody works. Life is peaceful for him there, until a gang of mercenaries led by Ron storm the reactor and take everybody hostage, including a group of children on a school trip. Now Mack is in a race against the clock and must use his military training to defeat Ron before he puts the reactor into meltdown. Along the way he discovers Ron’s motive, which unravels a greater secret Mack’s town is hiding.', '/nNZOJnWWaCnfst7LIU8dOuB9h8q.jpg', '2021-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16348, 'Christmas Town', 26381, NULL, '/aRYR8DSht5aVzaAQ2s31L4y0jK.jpg', 'Christmas Town', 'A week before Christmas Liza McCann visit her estranged father who strangely lives in a town decked out for the holidays and is full of Christmas spirit. Strange events immediately occur when they arrive challenging everything Liza had once believed in.', '/59lgpjWNZUSFTETgKYymPkROFFw.jpg', '2008-12-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16349, 'A Boyfriend for Christmas', 26463, NULL, '/wfeyDJiPpjTsLzPFaJkzBtMwXZa.jpg', 'A Boyfriend for Christmas', 'Holly Grant has learned a long time ago not to rely on Santa Claus leaving Mr. Right in her Christmas stocking. But Holly is in for a surprise when a handsome man arrives on her doorstep with a twinkle in his eye and Yuletide tree in tow.', '/nj4Dg2xsHzTpSvgwxRrs6uyHHjh.jpg', '2004-11-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16350, 'Point of Entry', 43530, NULL, '/1xg2yOw1ZkGeo6zVmHcNp70kdxG.jpg', 'Point of Entry', 'A young woman named Katherine Alden becomes the unwanted victim of her new handsome next door neighbor Caleb, after her and her husband and son moves to a new town for a fresh start from a robbery.', '/1giz7JTg4fscAzvzWbetmfyeDJy.jpg', '2007-11-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16351, 'Wicked', 44046, NULL, '/5PYuy6PWovZHDLA4FuREKkDFzeA.jpg', 'Wicked', 'A cul-de-sac in an oppressive suburb becomes a literal dead end for wife and mother Karen Christianson when she is brutally murdered in her own home. In the wake of the event, Karen''s teenage daughter Ellie begins to exhibit bizarre behaviors as she slowly acquires her mother''s demeanor and mannerisms. Meanwhile, Karen''s husband Ben nurtures a less-than-innocent interest in the family''s sultry live-in nanny, Lena.', '/13ix5ryXWE9l8UhtEKuJrkjmsTr.jpg', '1998-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16352, 'The 7 Adventures of Sinbad', 44773, NULL, '/89A9PHkGoNwW35te6tQitBvILGk.jpg', 'The 7 Adventures of Sinbad', 'Sinbad, the original Prince of Persia, must complete seven tasks in order to save the world from catastrophe.', '/c6jY8DaiumXg02CMUdcdwm7thXy.jpg', '2010-05-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16353, 'Rage and Honor II: Hostile Takeover', 66854, NULL, '/qDeKsnmJSinEUj1WN6cp3sFevWn.jpg', 'Rage and Honor II: Hostile Takeover', 'Kris and Preston team up once again to take on powerful gangster Buntao. But Buntao has problems of his own, dealing with Dazo, another gangster who is on a steady rise to power...', '/63tCJDbP5Ao0o7CmoWYAmvW71Yu.jpg', '1993-06-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16354, 'Military Intelligence and You!', 47521, NULL, NULL, 'Military Intelligence and You!', 'Major Nick Reed is an intrepid analyst for Army Intelligence. It''s his job to locate a secret enemy base whose fighters - the dreaded Ghost Squadron - attack our bombers. Complicating his efforts is a chance meeting with his former love, Lt. Monica Tasty, and her current beau, Major Mitch Dunning. Can Reed find the fighter base in time for the 4th Armoured to attack...', '/ufZ1pWlDoXVTgQ3UtTX4xmheK8X.jpg', '2006-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16355, 'Black Cat Run', 48170, NULL, '/muY5sFFZnI7A3KGG7Iqd3xyCY7m.jpg', 'Black Cat Run', 'A girl is in love with a gas station attendant and sees him against her father''s wishes. The father is the sheriff and shortly after a confrontation with the boy friend, he is killed by escaped convicts and the daughter is kidnapped. Everyone, including the deputy, is convinced that the boy friend committed the murder and ran away with the girl. This sets up a chase of the convicts by the boy friend and of the boy friend by the police.', '/mwc5GRwZCgbH3dEa4LDMMOnnUVa.jpg', '1998-09-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16356, 'Ice Spiders', 17306, NULL, '/cCjKoyRZKbDm1T2PaL1vkI9q7I.jpg', 'Ice Spiders', 'When a young ski team training for the Olympics arrives at the remote and isolated Lost Mountain Ski Resort to focus on training, they''re thrilled to find a retired Olympic skier is there to help them train. But their plans are halted when a scientist working at a nearby government lab arrives with the horrifying news that a top secret Government project has produced giant spiders and they have escaped, killing and eating everything in sight.', '/Asp7hjh1CfZoOxSJ3cr2RiVx3yt.jpg', '2007-06-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16357, 'Born to Ride', 68995, NULL, '/pfPuCQybXvacUgtHeFCZ03ouUzF.jpg', 'Born to Ride', 'Mike decides to hit the road on his refurbished classic motorcycle along with best buddy Alex, but their trek takes a surprising turn when they become involved in a plan involving political blackmail, corruption, and dirty money. Carrying evidence that could get them killed at any minute, the boys are chased on the open road but turn their skills to their own advantage.', '/qHlPQ9P6CYiOD8NlJ1wtntcvq88.jpg', '2011-06-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16358, 'The Second Arrival', 19154, NULL, '/xGS06Ur3Etqzjf5D0xqKU6WqfeG.jpg', 'The Second Arrival', 'After Zane Ziminski is found dead five people received envelopes with details of an alien invasion. This group of five includes 3 scientists, Zane''s brother Jack, and a reporter. Quickly, the group is down to three and then Jack and Bridget, the reporter. With a small piece of alien technology, they must escape from the aliens, who take human form, and try to convince others that aliens exist.', '/3mjqRwjs6KbmNuMHYIz2gualCZJ.jpg', '1998-11-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16359, 'Turbulent Skies', 70110, NULL, '/slQkyiStcYezBZyeK2LdWcfKELb.jpg', 'Turbulent Skies', 'When a new airplane that''s equipped with a new computer that can fly the plane on its own, is about to have its first flight. But the son of the owner decides to upload more software, he doesn''t bother to check if there are any viruses with it. And he also invites some potential investors to try it. So the plane appears to be working well but suddenly it veers off course and it can''t be shut down. When the military learns of this and fears what if something happens if it''s over a populated area; decides to shoot it down along with everyone on board. The man who built the computer whose wife is among the passengers thinks if he can get on board he might be able to shut it down and regain control of the plane. So the military using a new plane gets him on board. But what he didn''t know is that both pilots are incapacitated so there''s no one who can fly the plane.', '/i5Q6MTFIg58oCjPIE20kDbi4uyQ.jpg', '2010-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16360, 'Miracle Dogs Too', 73548, NULL, '/q715jy3uL80RYN5T6NieZdU4D4b.jpg', 'Miracle Dogs Too', 'Zack, a young boy, finds two Cocker Spaniels caged in the woods and takes them home. The animals, Sissy and Buddy, have magical healing powers that change the people of a small town.', '/8b2pNn3bWOQUlh2eEonvrn6w5kd.jpg', '2006-04-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16361, 'Project Viper', 54928, NULL, NULL, 'Project Viper', 'A space shuttle crashes containing a lethal prototype organism designed to survive in any environment. The only people who can stop the creature are the Secretary of Defense agent and the female scientist who created it.', '/pb3HUpfgiIbm075klZ4MRlMLUKJ.jpg', '2002-05-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16362, 'Chain of Command', 57219, NULL, '/eaVFrRU8xH5jLfEKrsK3yz7L1tz.jpg', 'Chain of Command', 'Secret Service agents must retrieve the briefcase allowing the President control of America''s nuclear arsenal before massive destruction ensues.', '/cFaOIywzc46tpWOzoSUTfQC0SXg.jpg', '2000-07-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
