INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16428, 'Aloft', 251321, NULL, '/61DzNcUduoqVDooSEhOHvkXOI7L.jpg', 'Aloft', 'As we follow a mother and her son, we delve into a past marred by an accident that tears them apart. She will become a renowned artist and healer, and he will grow into his own and a peculiar falconer who bears the marks of a double absence. In the present, a young journalist will bring about an encounter between the two that puts the very meaning of life and art into question, so that we may contemplate the possibility of living life to its fullest, despite the uncertainties littering our paths.', '/fxwJywCV6XLAFi0FcqVyduw0Fu.jpg', '2014-02-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
