INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16432, 'Far Harbor', 287881, NULL, '/itRr0tnDSEBrGDm0ocRvXJFNhwf.jpg', 'Far Harbor', 'A group of seven young people spend a weekend in the home of a wealthy yuppie on Long Island and live out their problems.', '/iFPzx2t0h0wVfbdxdOBVW0YVZUX.jpg', '1996-11-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16433, 'Sergio Leone: The Italian Who Invented America', 1005428, NULL, '/d67M27QMwFY8Kx7kC9ug3Xeiqou.jpg', 'Sergio Leone - L''italiano che inventò l''America', 'To mark the recent thirtieth anniversary of Sergio Leone’s death, this documentary sets out to pay tribute to one of the great legends of world cinema. The singular artistic vision of Sergio Leone has transcended national borders, creating the Spaghetti Western genre and transforming the international cinematic panorama forever with his innovative stylistic and narrative solutions, which have now become part of the language of the movies. The film, which is enriched with precious archive footage from the Cineteca di Bologna, including rare audio recordings and film clips shot behind the scenes, sees for the first time the direct participation of the Leone family and has interviews both with Leone’s longtime collaborators and with icons of Hollywood who have been profoundly influenced by his work.', '/aCKJgQ4pA68AadCzvGsngWQLHeV.jpg', '2022-10-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16434, 'Jim Henson Idea Man', 1273196, NULL, '/yfLAaxP3T0p08X0gxHm8zYdjnHC.jpg', 'Jim Henson Idea Man', 'Featuring unprecedented access to Jim Henson''s personal archives, filmmaker Ron Howard brings us a fascinating and insightful look at a complex man whose boundless imagination inspired the world.', '/w1IYhFVW2XyKfkIyZ65jZ2Uyn6Y.jpg', '2024-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16435, 'Rocketeer: Excitement in the Air', 367479, NULL, '/4j9Yhhp1QJ6jlI2XyA5JOaQoVNg.jpg', 'Rocketeer: Excitement in the Air', 'American TV-Special hosted by Bill Campbell, star of "The Rocketeer".  A sneak peak at the film "The Rocketeer" with behind the scenes interviews and meeting "real-life rocketeers".', '/jG400cA6JvrY1VoQFmT53b9qOjR.jpg', '1991-06-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16436, 'Out There', 345268, NULL, '/rylTDx17UNJ0CGhJW8TUMyNjchW.jpg', 'Out There', 'A Pulitzer Prize winning photographer is fired from his job for not being sensationalistic enough. After he purchases an old camera at a yard sale, he discovers some undeveloped film in it, including photos of an apparent alien abduction. When he goes public with the photos, he garners the attention of his former boss, the government and a woman who thinks her father was the abductee.', '/zHgdt0XILxGE3j1Up8j0mleMj6x.jpg', '1995-11-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16437, 'The World of Jim Henson', 168699, NULL, '/pvjUN2g5X3LTAnYQubtkDcFtXrB.jpg', 'The World of Jim Henson', 'In this episode of PBS'' Great Performances, the history and legacy of puppeteer Jim Henson is explored, from his six-second commercial beginnings to a five-season run on ABC of The Muppet Show to several theatrically released films, including five Muppet movies, The Dark Crystal, and Labyrinth.', '/asLSFe0r0JyGwzcHfVjpLJiJD59.jpg', '1994-11-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16438, 'Inside a Beautiful Mind', 692305, NULL, NULL, 'Inside a Beautiful Mind', '"Behind-the-scenes" documentary on the making of and public reaction to the Ron Howard/Brian Grazer film "A Beautiful Mind." Featuring rare interviews with Russell Crowe, Jennifer Connally and mathematician John Nash.', '/mn6v5WStNNJ2mUU3ejm3NSknKXp.jpg', '2002-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:58', 0);
