INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16442, 'The Plight of Clownana', 221290, NULL, NULL, 'The Plight of Clownana', 'Ishamel is the Clownana, a dancing half-clown, half-banana store mascot. Life is great until the nearby porn store gets its own mascot and Ishamel is left wondering what his life is all about - oh, that and there is a not-to-be-missed dance-off.', NULL, '2004-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16443, 'Batman: The Long Halloween Deluxe Edition', 1010830, NULL, '/ekdyrBffLhoFWkm5eUVAbIhDVh6.jpg', 'Batman: The Long Halloween Deluxe Edition', 'Atrocious serial killings on holidays in Gotham City send The World''s Greatest Detective into action - confronting both organized crime and a unified front of classic DC Super-Villains - while attempting to stop the mysterious murderer.', '/15erh7z92WBiW6z8Xpb8WLaWhbD.jpg', '2022-09-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16444, 'Buddy Games: Spring Awakening', 1017507, NULL, '/6IWAFezMXqgXDsPb2Y0w2Y2d5Ct.jpg', 'Buddy Games: Spring Awakening', 'Faced with their biggest challenge yet, the gang sets out to honor a lost friend only to find themselves in the middle of where it all began – Spring Break – where they learn their old school ways of partying hardly compete with today''s generation.', '/8Xye26gsr6MHWRzqolqz7y2u93g.jpg', '2023-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16445, 'Legion of Super-Heroes', 1003580, NULL, '/jhi3K0rN46SSu9wEu6zYVCOeVtH.jpg', 'Legion of Super-Heroes', 'Kara, devastated by the loss of Krypton, struggles to adjust to her new life on Earth. Her cousin, Superman, mentors her and suggests she leave their space-time to attend the Legion Academy in the 31st century, where she makes new friends and a new enemy: Brainiac 5. Meanwhile, she must contend with a mysterious group called the Dark Circle as it searches for a powerful weapon held in the Academy’s vault.', '/8M6bA5t2q5u1nWDTEIXuGDwvboW.jpg', '2023-02-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16446, 'Buddy Games', 472815, NULL, '/z1VcsfkSHhByeqloNnu7m0YRB9v.jpg', 'Buddy Games', 'After six lifelong friends have a five-year falling out, “The Bobfather”, reunites his pals for the Buddy Games, an insane competition of absurd physical and mental challenges with the chance to win a $150,000 pot. Now all bets are off, as the determined dudes'' fight, claw, and party for the big bucks.', '/uNCZh6YGg6r0GMyrctI14R0lHGL.jpg', '2019-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
