INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16448, 'Batman: The Long Halloween, Part One', 736073, NULL, '/uS9apevOgs2fuYghf9szOoK1u63.jpg', 'Batman: The Long Halloween, Part One', 'Following a brutal series of murders taking place on Halloween, Thanksgiving, and Christmas, Gotham City''s young vigilante known as the Batman sets out to pursue the mysterious serial killer alongside police officer James Gordon and district attorney Harvey Dent.', '/sR7gppb0YGjwLvE6Vnj6wYv5MnW.jpg', '2021-06-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16449, 'Batman: The Long Halloween, Part Two', 736074, NULL, '/j14Z0pP7tpuHZlVBSuUL7tq2SGb.jpg', 'Batman: The Long Halloween, Part Two', 'As Gotham City''s young vigilante, the Batman, struggles to pursue a brutal serial killer, district attorney Harvey Dent gets caught in a feud involving the criminal family of the Falcones.', '/5X1n5q08mZ7NpNpxehMFODxfNYq.jpg', '2021-07-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16450, 'Bury My Heart at Wounded Knee', 13470, NULL, '/rEovUFDH1BSNipOt5T80G8FDGs.jpg', 'Bury My Heart at Wounded Knee', 'Beginning just after the bloody Sioux victory over General Custer at Little Big Horn, the story is told through two unique perspectives: Charles Eastman, a young, white-educated Sioux doctor held up as living proof of the alleged success of assimilation, and Sitting Bull the proud Lakota chief whose tribe won the American Indians’ last major victory at Little Big Horn.', '/w8FeAVNxe17rQUqaBhKy5F0wpBf.jpg', '2007-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16451, 'The Sacred Sundance: The Transfer of a Ceremony', 1164530, NULL, '/99VFngin9MZrqHXcxJy0jXjKUYI.jpg', 'The Sacred Sundance: The Transfer of a Ceremony', 'This feature-length documentary chronicles the Sundance ceremony brought to Eastern Canada by William Nevin of the Elsipogtog First Nation of the Mi''kmaq. Nevin learned from Elder Keith Chiefmoon of the Blackfoot Confederacy in Alberta. Under the July sky, participants in the Sundance ceremony go four days without food or water. Then they will pierce the flesh of their chests in an offering to the Creator. This event marks a transmission of culture and a link to the warrior traditions of the past.', '/vN5H7QqYEKQq1Dy3odQTqHrpYSE.jpg', '2008-07-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16452, 'Three Times', 11554, NULL, '/nUUfagmcm9Bg2lRbaObfbMifkit.jpg', '最好的時光', 'In three separate segments, set respectively in 1966, 1911, and 2005, three love stories unfold between three sets of characters, under three different periods of Taiwanese history and governance.', '/Ajd6uUZchc9AR2PHDaAiI79fFUl.jpg', '2005-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
