INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16454, 'The Eye 2', 24674, NULL, '/blOO2Sj5aYt67K9a1ELP9DlBVUS.jpg', '見鬼2', 'Pregnant Joey teeters on the brink of madness after several fruitless suicide attempts. She''s the unwilling recipient of an influx of shadowy images that haunt her pervasively. In an attempt to quell this disturbing phenomenon, she looks up with her secretive ex-lover Sam, who may be able to shed some light upon the mysterious twilight world descending upon Joey.', '/oLzGWnLYBTdCVqaXooertbagQgn.jpg', '2004-03-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16455, 'Bishonen', 27060, NULL, '/joaSaeFsw8qgGi8eDY7g0PoCvhj.jpg', '美少年之戀', 'A hustler and a model policeman who is uneasy with his own secret homosexuality begin a secret relationship.', '/v1DGBfBzE9BpGK7vPq8QGezE7wx.jpg', '1998-08-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16456, 'Looking for Mr. Perfect', 40006, NULL, '/2UgRUELutSwk8Vx0AzpYPi1Lbgk.jpg', '奇逢敵手', 'A policewoman has always had the worst luck in love. On a trip to Malaysia, she finally meets the man of her dreams. However, her Perfect Man might not be all he appears to be.', '/ndKNS8unsl0eXObJAVlRrAhJk6s.jpg', '2003-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16457, 'Impermanence Is Eternity', 912180, NULL, '/1xNHk8nkpi614eN0jAndwJJk03A.jpg', '她的猜想', 'Short film for Vogue FILM by Huang Shi. In the dimly lit and dreamy scenes, Shu Qi shows a unique romantic poetry in three sets of different styles; Shu Qi, who shuttles between reality, dreams and imagination, exudes mysterious and unpredictable dramatic tension, communicates with oneself, and feels the impermanence of fate: "impermanence is the only eternity."', '/tmwKnxkwhruAY80LwEcj2pkBWy2.jpg', '2021-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16458, 'To Each His Own Cinema', 36108, NULL, '/20vIC3JXCFrsLwv0TpiBbK7IKh2.jpg', 'Chacun son cinema ou Ce petit coup au coeur quand la lumiere s''eteint et que le film commence', 'Commissioned to mark the 60th anniversary of the Cannes Film Festival, "To Each His Own Cinema" brought together 33 of the world''s pre-eminent filmmakers to produce short pieces exploring the multifarious facets of cinema and their perspective on the state of their chosen artform in the early 21st century.', '/1bTniamnmxv8TY3AUrxddrNy9rV.jpg', '2007-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16459, 'Beijing Rocks', 44677, NULL, '/7jD23ieDHP2Lvizq5GwLwEXXAX3.jpg', '北京樂與路', 'A rock and roll story that portrays the decay of political and cultural lacunae that have separated China and Hong Kong for so long.', '/huJPxWsWwwjDR2Cwsc04JEUhDWg.jpg', '2001-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16460, 'City Under Siege', 44263, NULL, '/asmHjYeTdLvMw9IZzNzvzGWFWXe.jpg', '全城戒備', 'Sunny is a naïve circus performer who dreams of inheriting his father''s knife-throwing skills. However, his hostile colleagues continue to bully him, relegating him to a lowly clown. On a tour to Malaysia, Cheung and other performers discover a cave occupied by the Japanese army during World War II. Instead of finding treasure, the performers - including Sunny - are sprayed with a mysterious chemical that turns them into superhuman mutants...', '/8FDwOGJT7OSE3Rho4qDoifMpOTW.jpg', '2010-08-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16461, 'Extreme Crisis', 45381, NULL, '/fQ9S5EhS2oRPMvwXhVE18kTZKwj.jpg', 'B計劃', 'Hot-headed Hong Kong cop Ken Cheung (Julian Cheung) teams with die-hard Japanese Interpol agent Takami (Kenya Sawada) to stop a ruthless gang of Japanese terrorists. The crime fighters must race to find a hidden time bomb filled with noxious gas that threatens the city -- but first they''ll have to survive attacks from vicious terrorist thugs. This action-packed adventure is a directorial debut for renowned action choreographer Bruce Law.', '/uyky2hmIYU5PJmOSq8KRGUAfe2Z.jpg', '1998-08-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16462, 'City of Glass', 45399, NULL, '/d1bJLkK9nDGqvg1qCK6e71AqNoc.jpg', '玻璃之城', 'The story of man and ex-girlfriend found dead after a car crash and how their children come together to retell the story.', '/2FcLcilrHUffu7Eu4qvHEcRsXDV.jpg', '1998-10-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16463, 'Martial Angels', 45414, NULL, '/dF2OxKaZeK4Si3e4FAdgWlsKBvW.jpg', '绝色神偷', 'Cat is a professional thief turned straight after leaving her lover, Chi Lam, two years before. But her past returns to haunt her as Chi Lam is kidnapped for the ransom of security software belonging to the company Cat works for. In order to rescue him, she calls on her old friends from her orphanage days, six other feisty women, to save the day...', '/7FYE2OvISR8cMD4fNiggJYxeN25.jpg', '2001-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16464, 'The Wesley''s Mysterious File', 45440, NULL, '/p76Ejy5tq0tOADGYvXB8YrYGRgP.jpg', '衛斯理：藍血人', 'Andy Lau is Wesley, investigating alien existence on this earth. He works outside of the MIB-influenced FBI operation, run by Shu Qi and Roy Cheung. They''re hot on the trail of the Blue-Blooded Alien (Rosamund Kwan). Two other aliens, the "Warlock Toxin Group," are gunning for her as well -- red maggoty swarming creatures that form into Mark Cheng and Almen Wong.', '/jFqqkvQ4EuWncXDwbFtgLw0kGqq.jpg', '2002-03-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16465, 'Blood Brothers', 45425, NULL, '/hPbxpNgmptuudgBQ0iaApiGH9kA.jpg', '天堂口', 'Three best friends who are barely getting by as fishermen seek their fate in 1930s Shanghai. Upon arriving in the bustling city, the naïve trio gradually find their innocence corrupted as they fall into the deepest depths of the criminal underworld.', '/4AbR965SBXlyuaE7lxuxnrINJ77.jpg', '2007-08-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16466, 'Love Me, Love My Money', 45473, NULL, '/tEpdUjqANEZHvYH5fQH9sQZfVJC.jpg', '有情飲水飽', 'Skinflint businessman Richard (Leung) doesn''t feel bad when he sacks his employees and secretary to cut unnecessary costs. He also doesn''t bat an eyelid when his gold-digging girlfriend leaves after he refuses to give her money. She gets her revenge by cancelling his credit cards and giving away his furniture. Suddenly destitute, he''s forced to rely on the generosity of Choi (Shu Qi), a good Samaritan who helps him out even though she thinks he''s a scumbag who makes a habit of cheating women out of money.', '/mT8WLXuei7EkaXmOKSWRWVALDHA.jpg', '2001-10-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16467, 'Visible Secret', 45480, NULL, '/pMhQ6kMXXU5vb2iZNcCnToMNm1e.jpg', '幽靈人間', 'A man develops a relationship with a woman who has mysterious supernatural abilities.', '/sUlsM23k8yzwNGWC0NWGzeNz1i4.jpg', '2001-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16468, 'Forest of Death', 45501, NULL, NULL, '森冤', 'In a mysterious forest in Thailand, many suicidal youths disappear and rescue teams can not find the way out even with compass. The ambitious reporter May is making sensationalist journalism exploring the deaths in the forest. Her boyfriend and botanist Shun Shu-hoi is developing a means of communication with plants. Meanwhile, Detective C. C. Ha is investigating the rape and death of a woman and the main suspect is Patrick Wong.', '/arD15dxhMqD5Ix1jexmwoybjbhU.jpg', '2007-03-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16469, 'The Fruit Is Swelling', 39998, NULL, '/yT9QRx9pGRtL2qEi2YHucKt1dyB.jpg', '蜜桃成熟時1997', 'An 8-year-old girl named Peach makes a wish and wakes up to find herself transformed into an 18-year-old woman.', '/4IbVhACQ6wyt6chFj1LUycIhMle.jpg', '1997-03-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16470, 'If You Are the One', 18232, NULL, '/sKGUTAtvGYT5e5fjIAI0egrjOZs.jpg', '非诚勿扰', 'Qin Fen, a funny, honest, single inventor, met a girl called Smiley, who was in agony of her boyfriend''s betrayal. They traveled to Hokkaido, tried to help Smiley cure her pain in heart, and both of them gradually found their true love and life redemption during the journey.', '/5EJ3WXtAV0itREDaFM4GRhFSTh8.jpg', '2008-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16471, 'Confession of Pain', 18877, NULL, '/oNofblVwO3VI3a7WqvuAd8UHv8h.jpg', '傷城', 'In a city of love and prosperity, a city of lost hope and premature death, veteran detective Hei feels it all: the hurt, the helplessness, the horror. When his father-in-law, the billionaire benefactor Kim, is gruesomely murdered in his palatial mansion, he enlists the assistance of his former partner turned private detective.', '/xzj1XnM3TIF3OQ95DC94Nsa5zdh.jpg', '2006-12-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16472, 'Iron Sister', 68799, NULL, '/gIX3P6SXb4dpeTW6UN7uPWPncoV.jpg', '悍婦崗', 'Manchuria 1941: Caught sleeping with his Japanese major''s mistress, Manchurian collaborator Tung Fei (Jackson Liu Hsiu-hsien) fatally shoots the man and flees for his life. Overcome by fatigue after hours of travel on horseback, Tung eventually awakens to find himself under the care of hunter Suen (Dick Wei) and his daughter, Ironic (Hsu).', '/efv38zlGDLRwZyZzyBYIAnX9CBd.jpg', '1997-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16473, 'Good Autumn, Mommy', 1133008, NULL, '/sKEtha4DUFEVGpTHYgqIQ8LiKwo.jpg', '寻她', 'A Southern sugar-cane village family''s peaceful wait for a new member is shattered by a sudden crisis, leading the matriarch, Chen Fengdi, on a journey of self-discovery and recovery.', '/iDjEKDN4M7SgeM3Qk1o2lVsvZAu.jpg', '2025-10-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16474, 'Sex and Zen II', 74887, NULL, '/kOJ9GdqGbun6JoMfpV2EvGzhgbh.jpg', '玉蒲團II玉女心經', 'Wealthy Sai Moon-Kin works hard to please as many women as he possibly can. When marrying off his mentally handicapped son, he finds himself attracted to his new daughter in law, so he takes her for his own, unaware that she is the evil Mirage Woman, who wields fantastical "sucking" abilities.', '/p1Omevox7vCu8KohiqIEhFgfJcT.jpg', '1996-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16475, 'Love', 95919, NULL, '/7uz6adVRXIo8xYuyO8feFb73FiU.jpg', '愛', 'Eight people try to end their loneliness by searching for that one person to love, who can make their life complete.', '/vDvYtfQYCw0BEVCzrd7yfOaLM4W.jpg', '2012-02-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16476, 'The Second Woman', 120880, NULL, '/7SwPRhwJEF7EQFBLBF5Qtne81DZ.jpg', '情谜', 'One suspects writer-director Carol Lai may have harboured some Black Swan ambitions with a tale that also centers around a stage practitioner who embarks on an unwitting destructive journey when playing a role to die for. The Second Woman, whose Chinese title Romance Riddle may hold better clues as to how this film developed, being more of a guessing game that threw constant clues rather than a overly romantic film about twins falling in love with a man who decided it''s perfectly OK to string both women along, until he discovers that this spells double trouble.', '/1dPv4QAh7kLs4JlZ85jH3MANr9l.jpg', '2012-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16477, 'My Loving Trouble 7', 136944, NULL, '/fCiUoUG5poyQSQVN9NYLeVQ39rr.jpg', '我愛777', 'Patrick Tam plays James, a director of TV commercials who becomes infatuated with Julia, a mysterious woman he happens to notice walking across the street one day (and since Julia is played by Shu Qi, who can blame him?). She is actually a high-tech industrial spy, and plans to quit the service after completing one more mission, with the help of her new partner Candy (Tien Hsin). When the women realize that they have been set up, James tries to help them and the initially hostile Julia begins warming up to him.', '/iNrGY8nBFbaZBn25FHRQqcbTc1B.jpg', '1999-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16478, 'Flyin'' Dance', 195720, NULL, NULL, '第一次的亲密接触', 'Tai and Choi are both fans of the internet, but they use it for different purposes. Tai uses it to chase women, while Choi uses it as to escape from reality, isolating himself from all those around him. While Tai is chasing after several girls, he meets Siu Yu. At the same time, Choi meets a girl named "Lightning Dancing Queen". As Choi''s virtual world becomes more passionate, self-confident, and humorous, his life in the real world becomes more and more remote.', '/tXQq6ORDLaqLFfjWlSksi2iob9e.jpg', '2000-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16479, 'The Island Tales', 255977, NULL, NULL, '有时跳舞', 'A group of disparate characters find themselves trapped overnight on a island somewhere off the coast of mainland China. The circumstances force them to overlook their preconceptions of one another, and they forge a kinship that goes to the heart their identities.', '/epDZxIyRuZDa5vcvlSGqkGI9aYo.jpg', '2000-02-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16480, 'Metade Fumaça', 36348, NULL, '/hYvXqRqi7z2Hy4Hoho9wrdCn11o.jpg', '半支煙', 'Former Hong Kong gangster Roy returns home after three decades of exile in Brazil, hoping to settle some unfinished business before he dies. Affected by Alzheimer''s disease, he hires young thug Smokey to act as his guide and helper as he searches for the man who put a bullet in him and stole the love of his life. Traveling through the Hong Kong underworld together, the two men form a close bond as they discuss their idealized loves and missed opportunities.', '/2scdW7azN25RS0mEBUCHP2fz5du.jpg', '1999-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16481, 'For Bad Boys Only', 45389, NULL, '/r4rv13CKGWhUoHvy6bwp4FGrZyk.jpg', 'BadBoy特攻', 'The Bad Boy Squad, a variety of private detective agency, is composed of King (Ekin Cheng Yi-kin), Queen (Kristy Yeung), and Jack (Louis Koo Tin-lok), whose primary source of business is the reuniting of clientèle with their first flames, and when the trio of young operatives returns to Hong Kong from an assignment in Thailand and the Squad''s next three customers supply photographs of lost loves, the women in the pictures appear to be the same individual.', '/83MsMvCiGdgSWfmLBeqHnY2BYVR.jpg', '2000-12-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16482, 'Love Is Not a Game, But a Joke', 256083, NULL, NULL, '飛一般愛情小說', 'Three friends begin a contest to find Karen, a particular girl they all like. The limits: one month, and no advertising or radio. The prize: the losers withdraw and the winner gets free reign to woo her.', '/uGXWHPiKFDCMkefdya8mucxTghw.jpg', '1997-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16483, 'Till Death Do Us Laugh', 256085, NULL, '/sLRwgJdGc4NI5vO70w6ZBGggAhT.jpg', '怪談協會', 'An investigative reporter has been invited to an exclusive annual dinner of the "Strange and Unbelievable Experiences Society," where three stories are told in the framing device of this horror anthology.', '/qDaTemCSP0cAKPeJJJZoJXKxqdv.jpg', '1996-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16484, 'Hidden Whisper', 258814, NULL, '/36SkKq0Or03peUDmQ71g3BVzzqd.jpg', '小百無禁忌', 'The film consists of three stories: One about a 5-year-old girl, one about a teenager, and still another about a 30 something woman involved in an affair with a married man. Without providing a definite answer whether the three leading actresses are playing the same person in different stages of life, the movie instead hovers on several consistent themes that keep on emerging in all the stories. For example, the image of drops of blood on the clothes, in the shape of maroon flowers.', '/87PDNPoflbweSwLkQaNXU9YyGSG.jpg', '2000-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16485, '10 Plus 10', 104194, NULL, '/iIxuCW2qIe37X87ZgZSgPmgT2vu.jpg', '10+10', '10+10 is a project initiated by the Taipei Golden Horse Film Festival to demonstrate the solidarity between Taiwanese film-makers. 20 directors are invited to make a 5-minute short film each on the theme of the “Uniqueness of Taiwan,” but allowed total freedom in all other aspects.', '/7jgTH8Qmu4SsoU7a3QV65I1joeI.jpg', '2011-12-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16486, 'The Foliage', 255691, NULL, NULL, '美人草', 'On her way back from a family visit, young female intellectual Xing-Yu meets the equally young and rebellious Si-Mong and the two fall in love. When Xing-Yu''s childhood friend and lover Yuan gets into a fight with Si-Mong, Xing-Yu tries to make peace between the two jealous rivals. Her attempts for truce further draw her into a forbidden and passionate relationship instead.', '/2IZkEkeNEhTtwdQmRRkUw3uTaj4.jpg', '2004-03-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16487, 'Women from Mars', 32524, NULL, NULL, '當男人變成女人', 'A hairdresser, a village leader and a veterinarian each have girlfriends but still insist on playing the field. One night, a demon spirit arrives to teach them a lesson by taking their "goods" away. To get their "goods" back, the trio must each have a woman tell them "I love you."', '/ppFvphkgiQaLAUfpPAZBcKxEYSW.jpg', '2002-05-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16488, 'Just One Look', 45471, NULL, NULL, '一碌蔗', 'Set in 70s Hong Kong, Just One Look actually tells of Fan (Shawn Yu), whose policeman father commits suicide in a cinema toilet, but Fan believes he was murdered by a gangster nicknamed ''Crazy'' (Anthony Wong). Ten years later Fan contemplates avenging his father''s death. Meanwhile, he and best friend Ming (Wong Yu Nam), who are movie fans and sell their family wares outside the local cinema, decide to enlist for kung fu lessons after spotting the master''s beautiful daughter (Charlene Choi). But Fan falls for a mysterious girl who lives in the countryside (Gillian Chung).', '/7Q6Tp23L0FJ176ayea9HpsIdcVf.jpg', '2002-09-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16489, 'My Name Is Nobody', 109051, NULL, '/dt1OlGt5OXwGlkEUpbtgA7n8s46.jpg', '賭聖3：無名小子', 'Nobody is a top gambler who falls for a blind model named Bitter. However, his buddy Chun sets him up and beats him, causing Nobody to lose his sight. Now, Nobody must seek revenge while managing his feelings for Bitter, who has regained her eyesight.', '/qKw5rSgiWJT0HRMEro2GjmsKyez.jpg', '2000-01-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16490, 'Home Sweet Home', 115960, NULL, '/lkiSWBpUPmXUu2gGp2S6cumPXb4.jpg', '怪物', 'May''s son has gone missing, and in order to win him back, the devoted mother is going to have to face her worst fears as she navigates a treacherous maze of incomprehensible evil. If she can make it out alive, she might just get a second chance at motherhood. If she falls prey to the darkness that surrounds her, however, she will suffer a fate worse than death as she is forced to confront every mother''s worst nightmare.', '/h93kEPPg16oI5RHrWox9NgaXnrL.jpg', '2005-10-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16491, 'Skyline Cruisers', 45573, NULL, '/yYejsYLGuYjCwkrQLZWe9kMGLe1.jpg', '神偷次世代', 'Action adventure in which the formula for a cancer-curing medicine is stolen, and a kung-fu fighting team must overcome rivals and doublecrosses in order to get it back.', '/wRhouVhfFXOhIiEQrqmklDC7O9o.jpg', '2000-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16492, 'Haunted Office', 182769, NULL, '/7idveFWTIYKZmWNXDuugS8XnGQf.jpg', 'Office有鬼', 'Employees working at a high rise building begin encountering a series of strange occurrences. Ken, a recent hire who attracts to the lovely, but spiritually harried Shan. Meanwhile, Pat is apparently terrorized by the evil demon who resides in the last stall of the woman''s bathroom. And Richard, a mean boss of another company in the same building, wants to get rid of his long-time employee Mary and begins to suspect that his entire staff has become ghosts.', '/gzCxws49eYaqgqU5XOunglnyFKo.jpg', '2002-09-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16493, 'A Queer Story', 124840, NULL, '/1WZG9xx4N3LTM0KlfbASnaeSKAj.jpg', '基佬40', 'From an unhappy childhood experience, Law Ka Sing decisively hides his homosexual identity. Sing''s partner of 8 years, young boyfriend Sunny is just the opposite, he has never minded publicly revealing his identity.', '/w9YcaBTVhXIa2r7aDuUBX3sGRQI.jpg', '1997-01-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16494, 'If You Are the One 3', 1211979, NULL, '/eVrj9EkJ2g0eHbP7i7JsvrfprFv.jpg', '非诚勿扰 3', 'In 2031, Qin retires alone on a small island, as his wife Xiaoxiao is away all year long. Fan, Qin''s friend, designs an android identical to Xiaoxiao to keep Qin company.', '/eMsP44KNK4jspZxvZj1E9GE6nk9.jpg', '2023-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16495, 'Growing Up', 315019, NULL, '/rDKWI5nmzTWwGBqkuqkv5OPtiMl.jpg', '人細鬼大之三個Handsup的少年', 'A group of friends are starting their senior year in a HK highschool. A new girl is the new student of the school and one of the friends from the group falls in love with her.', '/nlV3A18u1euFP25FBy8zBuOKAT7.jpg', '1996-09-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16496, 'Those Were the Days', 315026, NULL, '/fnbkryPYT2wtlAw1JyjIhYFUUJA.jpg', '精裝難兄難弟', '"Those Were the days" speculates on what would happen if a hot international art house director were transported back in time to the 1960s Hong Kong film industry. Highlights include: WKW meets Wong Jing as a child and profoundly influences career; WKW attempts to make his kind of films with the resources, talent, and expectations of 1960s HK filmmakers, and a lot of other Hong Kong /Wong Jing style zaniness.', '/7MYbQYCzCcZw8zp0Nyr8h5XYQT4.jpg', '1997-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16497, 'My Dad Is a Jerk', 315030, NULL, '/6aimzJ7HD33UV7arDwxIEgWoJ5P.jpg', '對不起，多謝你', 'Lee Lap Cheung is a immature slacker who is going nowhere. His ex-wife Yip Ting has become a powerful woman in the business world within a few years. Cheung in a moment of anger requests Yip Ting to allow him and his son Jason to spend some time together. Jason is an free, innocent and lovable child. Although he is a child, he is quite righteous. Under his influence, Cheung finally changes for the better to become someone with a true sense of responsibility...', '/gYWz5umwGfuTALkym59uD56KA0s.jpg', '1997-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16498, 'Gone with the Bullets', 312408, NULL, '/bnDTOgs8zmNjBllb9x0Nt4og0OH.jpg', '一步之遥', 'Set in 1920s Shanghai, Ma Zouri and Xiang Feitian establish a notorious beauty pageant called the Flowers Competition. All of the city''s elite attend the gala event, but when Wanyan Ying unexpectedly wins, it sets into motion a series of tragic events that change their destinies.', '/11cY7FN26dqTyYAQXLzclxg1mz8.jpg', '2014-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16499, 'Love: Amoeba Style', 315020, NULL, NULL, '愛情Amoeba', 'May Ching has three roommates. Tung is the career minded account executive with a business minded girlfriend. Long is the slacker chasing a blind date over the Internet. And ''Brad Pitt'' is the playboy who never sleeps with the same woman twice. When all four friends find themselves suddenly out of a job, they decide to open up a bar. In the course of setting up the business, the three boys reexamine their romantic life.', '/pQfkyJuQIz4Tra6ViM3qZUIgWAz.jpg', '1997-02-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16500, 'L-O-V-E...... Love', 315028, NULL, '/jnc6Pg107Oav40IDR4qiljzAZOK.jpg', '超級無敵追女仔', 'A super rich tycoon (Michael To) decides to become an ordinary person and joins a sushi bar. He and the other three people in the bar (Jerry Lamb, Natalis Chan, Eric Kot) go on a girl-hunting spree and meet up with girls participating in a beauty contest (Shu Qi, Angie Cheung, Vivian Hsu, Teresa Mak)', '/ecLXm3e6WC3hVyc3sDyBw9YNm7B.jpg', '1997-06-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16501, 'Dragon Heat', 315033, NULL, NULL, '龍火', 'An "experimental" film by Eric Kot, featuring an all-star cameo cast.', '/pCyL0B7NIriJKyW0JPaJq38lREo.jpg', '1999-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16502, 'Home in My Heart', 315034, NULL, NULL, '星語心願', 'Gun and Wai are two young ladies who grow up in a church during wartime. One day, an army passes by the church near the border, and the two young ladies volunteer to take them to the base of the hostile force. On the way there, they witness the hardship and cruelty that the war has brought to their peaceful, holy-land. The war has also given them a better vision of love and understanding of humanity. The war is now over, and they must decide whether to leave the church for new found love or stay living alone.', '/1rM0jrWu5KZ5Il7oL5eX9SiczbR.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16503, 'Love Generation Hong Kong', 315031, NULL, '/tcfMpX9MEfJN9jvc9CYR7zuZFOR.jpg', '新戀愛世紀', 'The film focuses on the protagonist Bill (played by Leon Lai) and his three emotional entanglements with Mei Sui (played by Carina Lau), Xue Er (played by Shu Qi), and the girl next door (played by Ann Lee). It narrates his growth journey from a career low to achieving success and fame. After Mei Sui breaks up with Bill due to her inability to endure an ordinary life, Bill goes to the United States to start a business and becomes successful. Years later, when they reunite, Mei Sui is already engaged to the gangland boss "Brother Heping". Bill attempts to win her back but fails, ultimately discovering that true love was by his side all along.', '/4K0TgW2ff6DsauM21EkH7GXMJsr.jpg', '1998-07-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16504, 'Unexpected Challenges', 315035, NULL, '/zjC4OREJ2gDZlNWUs6ypbrdepmA.jpg', '靈與慾', 'Retired Win Kao used to be reknowned as the "Prince of Golf" for over a decade, but now suffers from financial hardship when his golf facilities store hits hard times. Reluctant to seek help because of his pride, he finally approaches strong career girl Jenny Wu after his economic situation hits the headlines in the local newspaper. Win blames Zsa-zsa for the story, the journalist who is dating his son Charles, and begins a campaign to separate them. But his son''s relationship seems sincere and reminds him of his lost love with May, his childhood sweetheart who had committed suicide after she gets pregnant and her parents forbid their love.', '/xSeBjr0JGhPqkkqmxSBQ16YIely.jpg', '1995-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16505, 'When I Look Upon the Stars', 315032, NULL, '/qX4ZsOwE5D0HimX2zz5AQBuu4NL.jpg', '天旋地戀', 'Kei (Leo Koo) has just wrapped up a big contract for his company (though it''s never clear what kind of work he does). He decides to take a well deserved vacation, to go and visit his girlfriend June (Anita Chan) in Japan. He hasn''t seen her in a while.', '/x8WIT132wyWiT7o7f5YGUbcokXe.jpg', '1999-01-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
