INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16507, 'Decent Things', 1240544, NULL, NULL, '入型入格', 'In 1931, a famous person borrowed an ancient painting to appreciate, but he refused to return it. The owner of the painting was embarrassed to ask for it, so he entrusted an elementary school martial arts teacher to contact the celebrity''s bodyguard, Tie Backer, hoping to accommodate him. By means of painting, it shows the sophistication of martial arts practitioners.', '/zNKxdkGDdEo8pCHE8OUun8HBJbz.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16508, 'Shu Qi - Dreaming Naked Show', 1248311, NULL, NULL, '舒淇梦幻狂潮性感写真', 'This unique forty-minute montage features the lovely Shu Qi exhibiting her heavenly form in various settings. The first shoot takes place seaside, where she poses nude and seminude. In the next segment she models outdoors in lingerie. Cut to a bathroom, in which she strips, showers, and then bathes. She poses in lingerie some more and in a bedroom lies nude on a bed. The final sequence occurs on a catwalk, where she and other models strut their stuff in scanty undergarments. A mixed soundtrack plays all the while, from start to finish.', '/p9ZPbWEOujLXFRf5JffO98cwj5A.jpg', '1996-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16509, 'Shu Qi: Viva! Island Girl', 342168, NULL, '/ajoyAfoo6Kwy5IF6KcSYjO9Aw4w.jpg', '“春”回大地', 'Taiwan-born Shu Kei captivated audiences by storm with her naïve-yet-naughty performances in films like Sex and Zen Two and Viva Erotica. This bare-it-all portfolio, shot before her "retirement" from appearing nude in films for good, makes a perfect showcase for her famous come-hither persona and her devilish figure. Whether it''s bathing underneath a waterfall, posing on the catwalk in her revealing outfit, or brooding half-naked by the lakeside lodge, watching this now-classic portfolio will make you understand why Shu Kei is rightly regarded as the quintessential Hong Kong sex symbol for 1990''s.', '/i1AcVIOH9MNoOC56DmNMTXKAVAn.jpg', '1996-03-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16510, 'The Last Women Standing', 367877, NULL, '/vmTdqUQpAfe9jYJ3ifaqnoeJP0a.jpg', '剩者为王', 'For the thirtysomething Sheng Ruxi, whose surname unmistakably echoes the slang term "sheng nu" (leftover women), the wait for a perfect partner is growing more despairing by the day. With an ultra-anxious mother who would rather die than see her daughter stay single, Ruxi is further annoyed by the doctor she’s fixed up with. Could her new colleague, the dashing 25-year-old Ma Sai, offer last-minute salvation?', '/krp7jLzQDWGhwvMX1rKvsQfGvxT.jpg', '2015-11-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16511, 'All You Need Is Love', 374385, NULL, '/eO11O79TDCUeVv7ujmHe8av1eik.jpg', '落跑吧愛情', 'Tired of her family constantly nagging her to get married, spoiled heiress Yeh Fenfen (Shu Qi) books a stay at a beautiful villa on the Penghu Islands, which are the subject of a classic song on a tape left for her by her mother. When she arrives at her destination, she''s dismayed to find that the gorgeous villa is actually a rundown B&B owned by Wu (Richie Jen). It turns out that Wu''s friends, hoping to drum up some business for the B&B, falsified a few details about the state of the property on the internet. Angered by the deception, Fenfen packs her bags and leaves the next day. But, when she loses all of her luggage on the boat ride, Fenfen has no choice but to head back to the island.', '/6xEOwuCsxkjawHbZQMNFO9q8Ro1.jpg', '2015-09-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
