INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16525, '狄仁杰之三尸九虫', 1629215, NULL, NULL, '狄仁杰之三尸九虫', 'During the Tang Dynasty, a bizarre and mysterious case occurred in Bianzhou. Rumors spread that it was the work of evil spirits, sending the entire city into an uproar and spreading panic among the people. Di Renjie, a twenty-year-old prodigy, was specially promoted by the Ministry of Justice to investigate the case in Bianzhou by imperial order. He eventually uncovered the truth and brought the culprit to justice.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:42:59', 0);
