INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16560, 'I Don''t Understand You Anymore', 290958, NULL, '/pd2S9omOgt45r0cww8avmUjntlz.jpg', 'Non ti conosco più amore', 'On entering her bathroom, Luisa finds a naked man showering. She calls the police at once and the man is arrested. At the police station Alberto, a psychiatrist, recognizes the man: he is Paolo, Luisa''s husband. Alberto offers to help Paolo, but when the two men arrive at his home, Paolo still in his bathrobe, Luisa hugs Alberto and calls him Paolo. The two men try everything they think of to help Luisa regain her memory until the last (but not too unexpected) surprise.', '/1IyO5lvxIDliB7ONaatK6qMEM7N.jpg', '1980-10-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
