INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16563, 'Liebes Lager', 260558, NULL, '/2hT8F1B6oi8s7sKYhdPH7YsbVZB.jpg', 'Liebes Lager', 'In a Nazi concentration camp, German soldiers shamelessly abuse the inmates, mocking and brutalizing them. But the prisoners never give up on the violence they have suffered, convinced that they can rebel and take revenge.', '/zc5GysGArDSczAT1dgcpGw2G7Jl.jpg', '1976-12-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16564, 'Grog', 283951, NULL, '/7G6Go3L269wKnv3YSGozjf3VciQ.jpg', 'Grog', 'Two convicts escape from prison and evade the law by taking hostage the middle-class family of a doctor. One of the jailbirds calls the local television station, requesting that they broadcast his demand for a plane so they can escape the country. The television director and his crew show up to film the hostage crisis, and then things get progressively more bizarre and satirical. Not content with the living drama, he directs everyone''s actions to make the event more newsworthy.', '/aDuArmStpZ0gTTa7q9RQnLvyW3i.jpg', '1982-09-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16565, 'Caligula''s Hot Nights', 406420, NULL, '/1RhlIIOLc45y2380sfKyy3lDyLB.jpg', 'Le calde notti di Caligola', 'In Augusta the emperor Caligula has a serious problem: he must demonstrate his manliness "coram populo" on the occasion of the feast of Priapus. But the Imperial young man is powerless and threatens a fool in front of the people who arrive in droves to watch the battle. To avoid this conflict, he goes to the professor Barnardus and attempts to hide out in his clinic.', '/7dyTQr0ED6r5xCZweDj0HP5YrOX.jpg', '1977-08-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
