INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16568, 'Oh, Canada', 1113583, NULL, '/50ZSvrvnnIHobB8h2henqbBXqKH.jpg', 'Oh, Canada', 'Famed Canadian-American leftist documentary filmmaker Leonard Fife was one of sixty thousand draft evaders and deserters who fled to Canada to avoid serving in Vietnam. Now in his late seventies, Fife is dying of cancer in Montreal and has agreed to a final interview in which he is determined to bare all his secrets at last, to demythologize his mythologized life.', '/hKDR5AYXRTPb751oc7xK2Ay3PH0.jpg', '2024-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16569, 'Carpe Liam', 1203247, NULL, '/8mNWIpsxUZVhej5ueAmY2vbR500.jpg', 'Carpe Liam', 'Liam, a young man, who dreams of becoming a wildlife photographer is unlucky in life due to his over controlling mothers interfering. Liam against all odds manages to get to his once in a lifetime interview late and is forced to stand up to his mother if he is ever to get away from her.', '/9B67sbxUTjxiEVjy4IKGqnlW9Ej.jpg', '2015-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:00', 0);
