INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16596, 'Elena and the Secret of Avalor', 427143, NULL, '/xpQqhEytDLf7qDMLBNeQK8ruYfd.jpg', 'Elena and the Secret of Avalor', 'In the Kingdom of Avalor, Elena takes Naomi up a mountain to show her favorite view of the kingdom. Elena laments to Naomi how she was trapped in the Amulet of Avalor for forty-one years, and then presents to her a broken wand. She tells her that it was Shuriki''s wand and how she would still be trapped in the Amulet if it was not for a brave young Princess: Sofia. Elena then proceeds to tell Naomi the whole story ...', '/6dknXo3Ny4J97eBRs9XKVwQc8fH.jpg', '2016-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
