INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16598, 'Disney Parks Presents: A Descendants Magical Holiday Celebration', 509423, NULL, '/jIjhv1DilmZf1swzCzF3TTcfvuk.jpg', 'Disney Parks Presents: A Descendants Magical Holiday Celebration', 'Aside from taking a look inside Disney Parks during the holiday season, the show features musical performances from both Disney Channel stars and famous faces from “Descendants 2!”  Disney Channel stars Dove Cameron, Cameron Boyce, Sofia Carson and Booboo Stewart will perform “Jolly to the Core,” while star China Anne McClain will sing “This Christmas.”  Additional musical performances include:  “Silent Night,” performed by Hollywood Records and Republic Records recording artist Sofia Carson.  Kelly Clarkson performing a song from her 2013 holiday album “Wrapped in Red.”  Forever In Your Mind performing “Celebrate.”  Trisha Yearwood and Garth Brooks perform a holiday duet from their new album, “Christmas Together"', '/WFZJlEE0xyJmScvzCSu3Ow0aRd.jpg', '2016-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16599, 'Saving Flora', 570488, NULL, '/fvkEWfD5ZIHCcBnV9dPctsYNwVO.jpg', 'Saving Flora', 'Flora is a circus elephant who can no longer perform her tricks. The night before she''s scheduled to be euthanized, the circus owner''s 14-year old daughter, Dawn, sneaks Flora from the circus. All that stands between them and the safety of the elephant preserve is two hundred kilometers of woods, one raging river, two elephant hunters and the fear of not making it.', '/txFQFgjVQmQYFYvEFCbUlTJMYcs.jpg', '2019-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
