INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16602, 'Elena of Avalor: Realm of the Jaquins', 829155, NULL, NULL, 'Elena of Avalor: Realm of the Jaquins', 'Join crown princess Elena as she soars through a hidden gateway into Vallestrella, the mysterious, dazzling domain of the Jaquins. On the way there, she accidentally releases a mythical forest sprite that could endanger Avalor! Now Elena must find the Jaquins’ magical, legendary Sunbird Oracle to save the kingdom!', '/mC6v1l75pl55d3nyblEFV5WjaFz.jpg', '2017-08-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
