INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16604, 'Elena of Avalor: Ready to Rule', 1427159, NULL, NULL, 'Elena of Avalor: Ready to Rule', 'Loyal and brave, 16-year-old Elena must learn to reign with wisdom and compassion over Avalor -- a land bursting with magic and majesty. Fortunately, she''ll have plenty of help from her grandparents, her sister Isabel, wizard-in-training Mateo and more. With friends and family by her side, it''s a wild and daring ride! Experience the fun, action and adventure as Disney''s most inspiring new hero embarks on a bold quest to restore her kingdom to greatness and prove she''s READY TO RULE!', '/r8or8LYT7k2jCRMPorHyeEkgFSJ.jpg', '2016-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
