INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16699, 'Lady Next Door Penetrated Indiscriminately', 1286262, NULL, NULL, 'Lady Next Door Penetrated Indiscriminately', 'Scene 1. (Girl next door) A woman who lives next door recklessly enters a man’s house and starts hitting him. He is beaten without knowing why and tries to resist, and although he tries to resist, it’s not enough for her. In the end, the man had no choice but to do whatever she told him to do.  Scene 2. (Reunion) A man and a woman come to a motel after drinking. The woman asks the man if he remembers seeing her before, and as he thinks deeply, he then realizes that she was the woman who bullied him in the past. The man hurriedly tries to run away, but the woman does not let go, and they end up having sex according to her wishes.  Scene 3. (Hunting) A man gets out of the car and enters a convenience store to hunt down the woman he saw to see if she likes him. He was initially rejected, but he seduces her with all his might, and the woman eventually agrees to have a drink with him. However, the man is planning to get her drunk.', '/6suzorVSEwaez87sRKyIIk05tv4.jpg', '2024-03-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
