INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16703, 'Mistress', 1316057, NULL, NULL, '아씨마님', 'After finishing his long career as a government official in Hanyang, His Excellency returns home with his gisaeng lover. His mistress, who washed her identity as his foster daughter, can''t adjust to the boring country life and becomes lonely. On the other hand, His Excellency keeps paying attention to his female servant, a familiar face in his hometown full of memories, and becomes increasingly neglectful of his mistress. The mistress, who is saddened by His Excellency''s actions, receives comfort for her body and mind from his male servant. One day, an imperial scholar comes to visit and takes control of his mistress, but when His Excellency does not take any action, she becomes greatly disappointed. However, the male servant, who watched the scene, seeks revenge for her from the imperial scholar but is caught by His Excellency and beats him. At the end, his mistress decides to run away with the male servant in the middle of the night.', '/6sTeWsvRtWSEU4BA6CpNP1FVukc.jpg', '2024-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16704, 'Delicious Room Salon Service 2', 721164, NULL, '/le8trnuRlHjyOC1bL1oEV7WAHtD.jpg', '룸싸롱 : 맛있는 서비스2', 'Old friends Yoon-soo, Jong-gyoo, and Jin-gyoo reunite after a long time and share drinks while catching up on each other''s lives. Yoon-soo, who is married to Ji-soo, confides that he''s been struggling with issues in his sex life with his wife. Jin-gyoo reveals that he broke up with his girlfriend, Mi-kyeong, because their sexual desires didn''t align, and he now satisfies his needs at karaoke bars, massage parlors, and similar venues. As the three friends get tipsy, they decide to have a wild night at a room salon. Thanks to the tips he picks up there, Yoon-soo is able to improve his marital sex life. Encouraged by this, his friends begin visiting room salons more frequently.', '/mgvUkbQSXlGLqwQCmcIJi1fSM0h.jpg', '2019-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16705, '3 minutes Partner', 471819, NULL, '/lkqszozNjEDM4gOvjK0X8ABspNk.jpg', '3분 파트너', 'Dae-goo likes his sunbae Soo-kyeong, but she doesn''t like him back. One day he discovers 3-Minute Partners and passionately has Soo-kyeong as his partner. As he changes, will he be able to succeed in winning Soo-kyeong''s love?', '/yv5zLYEtc2B3cKy84ZP39bIsnKH.jpg', '2017-08-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
