INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16709, 'The Daughter-in-law', 574939, NULL, '/58wiUqlNbuc1Y4LzgkTm2AcAppj.jpg', '사돈처녀', 'Jang-hyeon is in the leasing business and he lives with his son Byeong-cheol. One day he gets a call from his daughter-in-law in the States that she''s coming to Korea for a while and will be staying at Jang-hyeon''s house.  Jang-hyeon goes to pick her up from the airport and Byeong-cheol calls his girlfriend for some mature fun, but the daughter-in-law walks in.', '/gUCKYaIQnkc3ZU0kPhHljt9yHKM.jpg', '2018-12-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
