INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16712, 'I Don''t Like Younger Men 4', 619433, NULL, '/t6dlEgoJFUfkoyLCLn0RBn44Twj.jpg', '딸의 친구 4', 'Thanks to her wealthy father, Yoo-jin runs a coffee shop. One day she runs into childhood friend Mi-ae on the streets and they have a good time catching up. Mi-ae is currently unemployed and helps Yoo-jin at the coffee shop.  Min-soo stops by the café to see his daughter, but realizes he feels rather too fond of Mi-ae, who welcomes him.', '/hA18oqd7vHLYV6iTIGVpjC8uFFy.jpg', '2019-07-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16713, 'Housekeeper - My Wife''s Friend', 647087, NULL, '/5XZSISEUXO0UEKkO1K05cXFajCc.jpg', '식모: 아내의 친구', 'Mi-jeong works in a company and she''s an elegant and formal elite career woman. Hyeon-seok, her husband, is proud of her and loves her, but he''s submissive to her at night, so some times he flinches when she even steps close to him. Hyeon-seok is close to his little brother, Hyeon-soo, and they start a useless talk about the housekeeper that moves in with them. Then one day the housekeeper, Se-hee, tells him to ''keep the secret or make up a secret...'' and he falls into confusion and indecisiveness.  Hyeon-seok and Hyeon-soo don''t dream for a second that his wife has plans up her sleeve and they end up in a very strange situation...', '/panJGgQg7H00xe0GYa6gMrI7T8F.jpg', '2019-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16714, 'Invitation Girl 2', 650273, NULL, '/vVRlCSosWwxaoLF5CrxukNOzNIs.jpg', '초대녀 2', 'A man prepares a surprise for his wife on their 5-year-anniversary. One day, a couple, a man in the middle of a divorce and his mistress, come to visit. An entangled romantic web ensues.', '/276j0ZVVcQglf9kbkW9Vwtf5x8s.jpg', '2019-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16715, 'Bad Detective: Reload', 652628, NULL, '/7DlYH4DEYMWdRHFAU8Klljcn0g9.jpg', '불량탐정 : 리로드', 'The first story of a former detective and current private inspector. Hye-sook and Yoo-jin are a lesbian couple that love each other. One day, Hye-sook finds out Yoo-jin is seeing another man and warns the man to stay away.However, the man ends up threatening her for her life. Hye-sook wants Yoo-jin back so she seeks a private eye, but a few days later, she goes off grid. The private suspects she’s been kidnapped and finds Yoo-jin to find out the whereabouts of Hye-sook.', '/343gVtbOIVPjGvyv4FlMr22TWNd.jpg', '2019-11-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16716, 'The Youngest Sister-in-law', 654374, NULL, '/7cra09dpSPto2jGZlK7OMbeO90O.jpg', '막내 처제', 'One day, her family gathers for an offering and they worry that she''s the only one without a boyfriend. Her brother-in-law, Ho-seok, sets her up on a blind date with his colleague, Min-soo, who has always been nice to him. The more she talks to Min-soo, the more Seo-ri realizes she is interested in her brother-in-law, Ho-seok. She then tries to meet up with him frequently.', '/hC9yqXygRNVDz2B9NfZocqmhczM.jpg', '2019-12-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16717, 'Chatting App Sister Taste', 652836, NULL, '/lIiqPqifLnUSMRH5xJrPlASW64H.jpg', '채팅앱 - 누나의 맛', 'Ye-sung and Seok-hun are senior juniors who have nothing to do. One day, Ye-seong, who found an app that relieves women''s discomfort, met Seo Hye-ji through a chat app and had a chance to see her. I ask you… Yeseong tells Seokhoon about the chat app as well as signing up for Seokhoon''s housework. .Seokhundo app will meet with women to have fun sex. After that, Seokhoon meets women through the chat app while working hard. As more and more Seokhoon than Yeseong is becoming more popular with women in the chat app, women are looking for Seokhun rather than Yeseong, and Yeseong is surprised by the popularity of Seokhun and is driven out of the house.', '/qLXTb41e9CNzXhvOkKArdWU5Jno.jpg', '2019-11-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16718, 'I Have Two Wives', 653122, NULL, '/gMfYQARMy3QESlGpCyAy8LarKM9.jpg', '내 아내는 둘이다', 'Min-ji is an ordinary housewife with a dark secret. Unlike the wishes of her husband, In-gyu, who has a business running resorts, they don''t have a child yet. They''ve tried test tubes and home remedies, but nothing has worked.  Her husband and her in-laws finally decide to get a surrogate mother, and Min-ji has no choice but to agree to it, as she is worn out from their pressure. Hometown friend Jeong-ah comes knocking on the door. Min-ji is uneasy with Jeong-ah around, as she knows her past secrets, including the time she lived with someone else and had an abortion. On the other hand, In-gyu has completely fallen for bold and sexy Jeong-ah. Like a crow that nests in another''s nest, Jeong-ah takes over Min-ji''s place slowly and gradually. Min-ji is driven into a corner, so she meets Jeong-ah''s husband, Joo-sik, to stop her. However, she falls for his trap and is used to replace his wife who ran away from home.', '/Aol6g6M4YlvE2GPPcmiP6zb9ZWT.jpg', '2019-12-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16719, 'Room Salon College Girls 2', 656958, NULL, NULL, '룸싸롱 여대생들 2', 'Soo-jin and Jeong-hee are university students who start looking for a high paying part time job during vacation. They end up in a room salon and fall for a high down payment. The owner notices how naive they are and tells them they have to go for second rounds if they want to make big money. Meanwhile, the ace host girl, Yoon-jeong, comes back after a hiatus due to being sick. These girls begin an ego battle for getting the most customers.', '/5VjzM7qsrNYzKJ456oouDUM0c6R.jpg', '2019-07-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16720, 'Friend''s Young Mom', 660653, NULL, '/7D8PhcRHUt2P8e5hAp3CBF0Wc4V.jpg', '젊은 친구엄마', 'Every day, Jung-woo goes to a friend''s house. In fact, he fell in love with Hyunsoo''s mother, Hyunsook. Jin-soo and his lover Nam-joo have to go to a love hotel to have sex in order to live in their parents'' homes, and the two people, who are starting to pay the hotel bill, ask Jung-woo to borrow a room for a while.  Jung-woo is in Jin-su''s room while the two enjoy sex in her room. Hyun-sook and Jung-woo, who are both under one roof, imagine this and that, and Hyun-sook, who notices their situation, tells Jung-woo that he will go to clean the room.  Hyunsuk came to Jungwoo''s room a few days later. I can see the gesture of temptation as she cleans.', '/9KumU7gLIDhbNBKOcGbDbXEAwh9.jpg', '2019-10-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16721, 'Dirty Wife', 660803, NULL, '/3VQcGBc6Eex8gGHWm8ctjzYj5l0.jpg', '더러운 아내', 'A husband named Cha Dae-seong turns into a vegetable after an accident. Yoo Soo-yeon, his wife, takes care of him with all her heart. One day, she meets Baek Goon while hiking on her own. As time passes, Soo-yeon starts leaning towards him... Baek Goon and Soo-yeon have an affair and she even boldly has sex in the room her stationary husband is lying in. The husband cries in his heart as he can''t do anything about it. Baek Goon''s sex partner, Hee-jin suspects something is going on and follows him to find out everything. Then she starts taking care of Soo-yeon''s husband. Dae-seong starts getting better and slowly starts to stir... However, he still pretends to be a vegetable and watches his wife and slowly, he starts getting revenge on his wife and Baek Goon.', '/gBzePyjRPPpcQCOxqPyVBOrVP3T.jpg', '2020-01-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16722, 'Bad Detective: Missing', 663172, NULL, '/2p6LxBSNPWn3bTcmTDs9XDmEQB4.jpg', '불량탐정 : 미씽', 'Mi-ri''s friends, who work in a private detective office, leave on a trip to South East Asia. But suddenly, Mi-ri loses contact with her friends, and their whereabouts are unknown. Mi-ri is sure they have been abducted and asks a detective for help... The detective looks into the case, but where will he find Mi-ri''s friends?', '/aAhCvyJZq5BPWTUPO74N9CouFvy.jpg', '2019-12-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
