INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16744, 'Room Salon College Girls 3', 698779, NULL, '/8Qok8peiW6TTU6VFAmdBiuaAuBW.jpg', '룸싸롱 여대생들 3', 'Hee-jung, a college student, uses up a lot of money on Bitcoin and so she can''t pay back her friend, Joo-yeong. Worried, she came to work at a room salon and pays off the money she borrowed. Seeing how Hee-jung is, Joo-yeong tells her she wants to work at the room salon, too. Eventually, they both became aces! Until the vacation ends, they are slowly getting money, their hot services are attracting more and more customers...', '/efzmOJME5zbmXsgLCjCINm1e7X2.jpg', '2020-04-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16745, 'Bosomy Elder Sister-in-law', 698746, NULL, NULL, '가슴 큰 형수', 'Jang-soo and Seong-yeon have been married for about 10 years, but they have an unspeakable secret; Jang-soo''s brother, Jae-cheol. Jae-cheol used to go out with Seong-yeon before she met Jang-soo. And although Jang-soo couldn''t help but marry Seong-yeon knowing her past, he himself had a young girlfriend named Eun-hye...  Jae-cheol was getting along fine with Eun-hye when one day she breaks up with him. The love story between two brothers in "Big Breasted Sister-In-Law" will soon come out.', '/fNCFOuODky0eqAzCcClJjVeJGL8.jpg', '2019-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16746, 'Handwashing Lady', 698782, NULL, NULL, '손빨래하는 여자', 'Chan-sung, a job seeker is fascinated by Haru, a woman living in the neighborhood. Haru opens her heart little by little to the tender Chan-sung, every time he helps her carry her suitcase.  With the promise to not look at any other woman, Chan-sung moves to her home, and Haru even takes care of the money as the live happily together.  That''s exactly for a month...  Haru who used to be fragrant suddenly turned foul and living with her suddenly felt like a bed of nails. Chan-sung is attracted to his friend, Eun-dong''s roommate, Min-ji, and Haru''s madness turns into a catastrophe.', '/6hK0ZaFskfhXOVOuFUAPXOzWc6G.jpg', '2020-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
