INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16752, 'My Student''s Mom 4', 700548, NULL, '/cFE7g8jvaNPrjzlGI4YeA8X17yv.jpg', '내 학생의 엄마 4', 'Yoon-yeong failed her university entrance exam twice. Her mother provides her an English tutor since her grades do not improve as expected.  However, the tutor goes to Yoon-yeong’s mother, Hee-jae, and then Hee-jae’s younger sibling, Yoon-joo, likes the youthful and handsome tutor.  Eventually, Yoon-joo plans to seduce the tutor, Yoon-seong by making her sister and Yoon-yeong leave the house.  The tutor knows how Yoon-joo feels, but he still keeps on thinking about seeking Hee-jae…', '/mYX7QmIizJKQAoiiJ9mjgb7m02b.jpg', '2019-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
