INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16755, 'Wet Dream: Prostitute Woman', 698963, NULL, '/wYRqbEQXGIcVsCR0XmfIReeLd8W.jpg', '몽정: 파는 여자', 'Sang-hee feels lonely whenever she sees her drunkard husband… Whenever her husband comes home late, she is being comforted by Min-gi, the character in the video. Then one day, she learns about a man named Lewis from a business card her friend Mi-yeon gave her, and strange things happen to Sang-hee’s life. Dong-seok, her husband, started to think weirdly about Sang-hee, and Min-gi worries about her because she’s been saying strange things. Unaware who’s telling the truth, Sang-hee is in denial with what’s real, saying that all of this is just a dream.  Louis seems to know the situation… Who’s telling the truth… It comes out one by one…', '/jpfYRUBbJnbxevN4QfeEzJ4rGpz.jpg', '2020-04-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16756, 'Neighborhood Oppas', 699134, NULL, '/9WWo3L8gu6D49iaRuIQKNOY3rCQ.jpg', '동네오빠들', 'Hee-joo, a high school student, meets the tutor that she likes and it made her push to study harder. Yeon-soo, upon seeing her best friend, Hee-joo change for the better, she felt hurt and asked her brothers to do unpleasant things to Hee-joo. She even let out rumors to make Hee-joo drop out of school.  After dropping out, even if she took the college entrance exam, Hee-joo couldn''t adjust, and so she got along with the neighborhood oppas from before and lived a pathetic life.  On the other hand, Yeon-soo found a man to marry. She pretends to be a woman who went to college with a job and talents, trying to hide her past. However, that man was Hee-joo''s former tutor....  Will Hee-joo''s life, destroyed by a friend, be able to find her place?', '/vNJHL9CwLbkgFjdEvbVIUmaBkWg.jpg', '2020-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16757, 'Intercourse: Special Sister-In-Law', 699172, NULL, '/2MAEzTg6uUUcaPNB3gmYb46NF0S.jpg', '관계 : 특별한 형수 무삭제', 'Joon-pyo is a troublemaker who just got out of prison, and moves in with his brother Joon-seok and his wife Eun-ha. On the first day of meeting his sister-in-law, she looks calm and quiet, but she actually used to be a member of a high school gang. She hands Joon-pyo some money in return for not talking about her past. A few days later, Eun-ha is furious to see her husband having an intimate moment with her sister. Joon-pyo sees this as his chance and approaches a drunken Eun-ha...', '/tg9teKVp1pXIj252yKfqgkH9U9b.jpg', '2019-11-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16758, 'Lonely Dad: 20s Sex Partners', 699169, NULL, '/3hYFdouDs18RKCGsrP60LBfyyjo.jpg', '기러기 아빠 : 20대 섹스 파트너들', 'Joon-gi who sends her wife and children to study abroad lives alone. But one day, he was surprised to find someone who came into his house, Mi-na. As it turns out, he got into a real estate fraud... Situation had been tight and it made her stay at home for a while.  Meanwhile, her stepdaughter, Yoo-kyeong, who lives in a different house also comes home. She promises not to tell her mom that her stepfather is living with a younger woman. However, when she accidentally found her stepfather and Mi-na having sex, she feels a strange excitement...', '/v5ASz0MxCBvoVsORM04QpqtdaFE.jpg', '2020-03-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:01', 0);
