INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16894, 'La importancia de llamarse Ernesto y la gilipollez de llamarse Eric', 1099400, NULL, '/7ab7E5BgKwMpGgIcnP8CV8ciIGM.jpg', 'La importancia de llamarse Ernesto y la gilipollez de llamarse Eric', 'He was born in Granada, the only city in the world with an explosive name. At the age of ten he joined the Falange because he wanted to play the drum. His biggest musical influences have been Holy Week and his first host, the one he was given at birth. It was produced at the age of sixteen. A little later he began using drugs to escape. he should have died before thirty. For forty years he has hit the drums as life has hit him, with all his might.', '/h6wpgSBkJFKc7y9rIbaR2eSbOSF.jpg', '2023-11-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16895, 'Enrique Morente: flamenco impuro', 921888, NULL, '/54LATyAcDRX7bW61z2LsQ6eOsI.jpg', 'Enrique Morente: flamenco impuro', 'Enrique Morente''s three sons tell the story of their father: the most revolutionary flamenco in history. Despite criticism from purists, he opened cante jondo to cultured poetry, brought it closer to young university students, explored its Arab roots and paired it with rock and other contemporary sounds. Much of the Spanish music of the last decades is heir to his findings.', '/gqyYkmxBPTpD8nbKQ3fBbiSFWeY.jpg', '2021-11-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
