INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16901, '¡Qué vienen los Beatles!', 1237904, NULL, '/xztSs8YF3RHupAjb4kZ8L5PQIv6.jpg', '¡Qué vienen los Beatles!', 'In July 1965, the Beatles visited Spain to give only two concerts: one at the Plaza de Toros de las Ventas, in Madrid, on June 2, and the other, the following day, at the Monumental in Barcelona. It was a quick and unexpected visit that the Franco regime did not take kindly to, and which gave rise to succulent anecdotes.', '/9YpUgzyzdfkJ1aBGlGgLMGLJFxV.jpg', '1995-07-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
