INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16914, 'Tivoli', 1256000, NULL, '/hJ8cQP2Wp4X6E0SKegCPgjQrkYw.jpg', 'Tivoli', 'In the 1970s, the Spanish dictatorship opened up to the outside world and allowed a group of Danes to build Tivoli World, the first amusement park on the Costa del Sol, a copy of Tivoli Garden in Copenhagen.', '/hSEQq82Rynt6ZxcE2hagZSg1R2T.jpg', '2024-06-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16915, 'Waldo', 1357351, NULL, '/hbwp1fFH1GZ78JoQdtWwlGphRJ2.jpg', 'Waldo', 'The morning of the 28th of March, 1977, the news broke out that the prestigious composer of "Ode to joy", Waldo de los Ríos, was found dead with two gunshots to the face. This documentary is a project trying to decipher all the secrets behind the public figure of the celebrated Argentinian musician, who lived in Spain since the 60s. During the investigation, we find a life of fame, luxury, passion, homophobia, dictatorship, esotericism, depression, solitud, an enigmatic suicide... and oblivion.  We try to understand how one of the biggest composers of universal history transformed his own life into a requiem. From home-movies, photographs, personal letters, audio tapes and other inedit material, the documentary presents the most intimate and hidden portrait of this revolutionary musical genius.', '/vOUDAMaaTHA9AEnCHEbrE1WF7fA.jpg', '2024-11-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16916, 'Madrid', 260803, NULL, '/sNLsGHCweNAvOd7TPz5vzIr8085.jpg', 'Madrid', 'Hans, a German director, is in Madrid to film a television production about the capital and the Civil War, 50 years after it occurred. Accompanied by Lucía, his editor, and Goyo, his cinematographer, he films shots of the modern city, searching for spaces and people related to its past. At the same time, he views materials related to the past. In this search, Hans questions the point of his project, and disagrees with his producers until he discovers a project that he is passionate about.', '/81LBbvvrqLFHKOjB7pk1syQtF21.jpg', '1987-03-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
