INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16919, 'Dobermann', 10347, NULL, '/caaLhZmZm6kQVAnYInjIPiNBIE8.jpg', 'Dobermann', 'The charismatic criminal Dobermann, who got his first gun when he was christened, leads a gang of brutal robbers. After a complex and brutal bank robbery, they are being hunted by the Paris police. The hunt is led by the sadistic cop Christini, who only has one goal: to catch Dobermann at any cost.', '/3rahpIHJBenGJKI1EfAHlGSfKEY.jpg', '1997-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16920, 'Manuale d''amore 2 (capitoli successivi)', 20069, NULL, '/asFQViBQ0LraXtFZOI1TwTCkSPB.jpg', 'Manuale d''amore 2 (capitoli successivi)', 'Paralyzed from a crash, Nicola falls for his physiotherapist Lucia. Franco and Manuela seek fertility treatment in Barcelona. Filippo and Fosco, a gay couple, plan their wedding. Ernesto, a waiter, has an affair with Spanish cook Cecilia.', '/2mDPqJ8HQNs9oyziI88EelJCzoO.jpg', '2007-01-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16921, 'She Hate Me', 20912, NULL, '/61TkJ1U9zBF6C7JczCswA8BQ3AT.jpg', 'She Hate Me', 'Fired from his job, a former executive turns to impregnating wealthy lesbians for profit.', '/jjfzD3AEABBuJRnCJAZhUuwQvPi.jpg', '2004-07-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16922, 'The Stone Council', 21775, NULL, '/vwL1iuYXJC8CNwKijazMRTCPA4P.jpg', 'Le Concile de Pierre', 'In France, the single translator Diane Siprien adopts an Asian baby named Liu-San in a foundation directed by Sybille Weber. Years later, a weird mark appears on the boy''s chest and Diane and Liu share their dreadful nightmares. Diane is assigned for a three-day job in Germany and she leaves Liu with her friend Sybille. However, while going to the airport, Diane finds Liu hidden in the backseat and startles with an eagle flying toward the windshield, crashing her car. Liu falls into a coma and his digital recorder records the boy speaking in an unknown dialect. When Diane searches the translation and the origins of Liu, she is surrounded by mysterious murders. She discovers that the dialect is from the mystic Mongolian Tseven tribe and that Liu is a powerful Observer; further, he is in danger, threatened by sorcerers that need the boy for their Council of the Stone..', '/9hFKhOI7bUnkXjE2gbG2bpFSVh9.jpg', '2006-11-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16923, 'Napoleon and Me', 24180, NULL, '/yQGE8e3YkQgVpCkWeidjXhzxOvt.jpg', 'N - Io e Napoleone', 'Elba island, 1814. Martino is a young teacher, idealist and strongly anti Napoleon, in love with the beautiful and noble Baroness Emily. The young man finds himself serving as librarian to the Great Emperor in exile, whom he deeply hates, yet soon begins recording Napoleon''s memoirs, getting to know and learning to value the man behind the myth. Among seductions and affairs, expectations and fears, he will craft a precise portrait that nevertheless will not manage to hide a final, inevitable, disappointment.', '/xPVy5Jp7Lwc9RSnYGlJHM2EoggK.jpg', '2006-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16924, 'The Man Who Loves', 24191, NULL, '/viSBFM8ItsbQbnvMe64Cs6HBy51.jpg', 'L''uomo che ama', 'A man is broken hearted at the loss of his lover, then later visits the same pain on the next woman with whom he becomes involved.', '/fR57w7pjj29ztH5rPltPWoEkrD1.jpg', '2008-10-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16925, 'The Apartment', 12531, NULL, '/3Q7gL6aLgxdIZY4gCLxtT53XfUS.jpg', 'L''Appartement', 'Max is a former playboy who has decided to settle down by marrying his current love, Muriel. However, when Max catches a glimpse of the great lost love of his life, he becomes obsessed with rekindling their relationship.', '/8EWKKGnAQPdTXhr2aRde1aLwPQn.jpg', '1996-07-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16926, 'Secret Agents', 12648, NULL, '/ux4HpKKilst54SDiw4DPQAdGT3R.jpg', 'Agents secrets', 'From his offices in Switzerland, Russian Igor Lipovsky is engaged in a vast and profitable gunrunning operation with Africa. The French government wants to hinder the activities of the arms dealer and sends a team to sink one of his ships heading for Angola with a load of illegal weaponry. Lisa, Brisseau, Loïc, Tony and Raymond are professionals: they carefully set up their cover, plan all their moves meticulously, and carry out orders without asking questions. Perhaps they should. The code-name of the mission is "Janus"; and just like with the ancient deity, there are two opposite faces for every aspect of the operation: the objective of the French government, the role of each team member, the presumed friend and the assumed foe...', '/5tzRPF8TUQ1XTz3UnABCLOhMug4.jpg', '2004-03-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16927, 'The Girl in the Fountain', 895999, NULL, '/xUVms9smUJFckjkUTEBoWzXw04B.jpg', 'The Girl in the Fountain', 'Alternating archive footage of Anita Ekberg with the story of a quintessential diva as Monica Bellucci who is offered the chance to play Anita in a movie, digging through this woman’s story, she retraces her exceptional life, frailties and chooses, reflecting on what it feels like to be an icon.  What key decisions a contemporary diva faces in order not to fall into oblivion?', '/hRdjASz9uJW2rdWCprgJo6T3uFY.jpg', '2021-11-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16928, 'Stressati', 444278, NULL, NULL, 'Stressati', 'Two thirtysomething friends on the verge of a nervous breakdown can no longer cope with the stress created by their wives, jobs, mobile phones, and struggle for survival.', '/3swdS52CrPc9wXmOwxov899V3fO.jpg', '1997-09-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16929, 'Wild Blood', 40052, NULL, '/nSlq0hO62II8nqJkeWGTPZl12f5.jpg', 'Sanguepazzo', 'The bad romance between Luisa Ferida and Osvaldo Valenti, two of the foremost movie stars in Fascist Italy, who were supporters of the regime to the bitter end, and shared its brutal downfall.', '/bSR2lYFZAg0KAp39RNOZ3fpWJKR.jpg', '2008-05-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16930, 'Satan', 13742, NULL, '/8RblQZM2gy2K8AQ2RXP7UzEW8jW.jpg', 'Sheitan', 'A group of young people leave a disco and bump into a shepherd who is ready to spend his night worshipping Satan.', '/f10fK5ELawYMG3VOLwD2I5MdMEF.jpg', '2006-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16931, 'Remember Me, My Love', 38970, NULL, '/qRpoH1NgnsskEwKM8yR7Dkxzd76.jpg', 'Ricordati di me', 'A middle-class Italian family is tore apart when the father meets an old flame, the mother—a frustrated onetime actress—auditions for a play, their insecure son tries to make friends through drugs, and their underaged daughter—who has already figured out how to use sex to her advantage—does what she does best to appear on TV.', '/3GcAGqAtaSfD8V2ULGV1v6CROPj.jpg', '2003-02-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16932, 'Diabolik: Who Are You?', 824003, NULL, '/hLYH6wbi3Mgscdv2KuYcTdWGlUV.jpg', 'Diabolik - Chi sei?', 'Captured by a ruthless gang of bank robbers, foes Diabolik and Ginko find themselves facing certain death. While Eva Kant and Altea forge an unlikely alliance to rescue their lovers, Diabolik reveals his mysterious past to the Inspector.', '/1DAXwi4y941ryPoGbzUlFEEiPAo.jpg', '2023-11-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16933, 'The Whistleblower', 65760, NULL, '/wSCuWifaI1WmM5iFI580xac98qP.jpg', 'The Whistleblower', 'Nebraska cop Kathryn Bolkovac discovers a deadly sex trafficking ring while serving as a U.N. peacekeeper in post-war Bosnia. Risking her own life to save the lives of others, she uncovers an international conspiracy that is determined to stop her, no matter the cost.', '/iIVcea2BHHi7RJgucGEmpt3zkED.jpg', '2010-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16934, 'Don''t Look Back', 18897, NULL, '/62V5KHpwLQPbzKd1NEIbfGQyACL.jpg', 'Ne te retourne pas', 'Panic attacks and memory loss signal the plight of a writer whose body is inexplicably being taken over by another woman.', '/pvbhKQMP4Vi2BLyA38MqUBRPZPM.jpg', '2009-06-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16935, 'Like a Fish Out of Water', 18922, NULL, '/apAH1WzS9urP0kOUzYZuJFVmVs4.jpg', 'Comme un poisson hors de l''eau', 'A seductive femme fatale (Monica Bellucci) and two con men -- one cool as ice, and one who just likes to "ice" his victims -- enlist a mild-mannered, unsuspecting man in their mission to steal a rare and valuable fish. They plan to sell it back to its grieving owner at an enormous profit (talk about "sleeping with the fishes!"). Tcheky Karyo, Michel Muller and Dominique Pinon co-star.', '/2UybnV2kxzTqSlwqXp9AAmK8wJa.jpg', '1999-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16936, 'A Burning Hot Summer', 80440, NULL, '/ipVJXwR3shQnwY7n9R43b18qDno.jpg', 'Un été brûlant', 'Paul reflects on the summer he met Angèle and Frédéric as he watches his friend being laid to rest.', '/4CUsoDkhrR85fFIT7EIsDFjimbx.jpg', '2011-09-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16937, 'The Last New Year''s Eve', 52676, NULL, '/2uxPfvSXD4ditHJUbhdwIeXTlIt.jpg', 'L''ultimo capodanno', 'New year''s eve at "The Islands" condos. An aging countess''s party is crashed by the soccer team from her gigolo''s town. While dressing for a dinner party, the wealthy Guilia discovers her husband''s affair with her best friend and vows revenge. Next door, a family prepares their vintage Dodge for a drive through the streets. A call girl ties up a lawyer while, unbeknownst to him, three men await the right moment to break into his office. Across the hall, a woman downs pills in a lonely suicide attempt. Two young men hide out in a bedroom smoking dope; one of them has some dynamite. As midnight approaches, each group draws closer to grotesque tragedy.', '/fKetwjFc7PNWgprnLfbD0JbLNsv.jpg', '1998-03-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16938, 'Franck Spadone', 52684, NULL, '/kh2lwMzOegkRVHST0Yt4SfpCTfJ.jpg', 'Franck Spadone', 'Professional pickpocket Franck Spadone and his co-horts rob a beautiful stripper (played by Monica Bellucci). But Spadone becomes infatuated with his victim, and soon finds himself in the midst of a gang war because of his affections for her.', '/2d7rHuoWpa75F9HZtJ5SzGm1Hwi.jpg', '2000-07-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16939, 'The Heroes', 82358, NULL, '/mkG5afzjnMImlMsCmV031McqW2X.jpg', 'I mitici - Colpo gobbo a Milano', 'Roman TV technicians Fabio and Enzo have been unable to find decent jobs. They decide to crack a safe at a jewelry in Milan. To get the layout of the store, they enlist a beautiful but unsophisticated young woman, Deborah. To find underground access to the store, they get help from a sewage worker. An obese trapeze artist is called for disarm the store alarms. The clever Mrs. Motta, old hotelier, is also involved. Will they succeed?', '/et2YAFGIpWRPhKx4oRSPwNmvXcj.jpg', '1994-02-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16940, 'Stubborn Fate', 74181, NULL, '/tFMMTpzz5O5dq9QBwLAdeC5wYjR.jpg', 'Ostinato destino', 'Carolina Rambaldi isn''t fulfilled by her three children: Marcello, a lazy do-nothing, Lucrezia, a bossy type who produces a TV show, and Cesare, homosexual and malicious, who''s a sociologist. When she writes her will, Carolina leaves her property to the one child who''s married and had a child in the past year and a half.', '/bhIpeb6sacnS8INaBYUJgtGMKqk.jpg', '1992-05-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16941, 'La folle histoire de Sophie Marceau', 940852, NULL, NULL, 'La folle histoire de Sophie Marceau', NULL, '/o7s3WEZ2vxe6XS0WFvrGRhZtP0E.jpg', '2016-01-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16942, 'The Second Wind', 59918, NULL, '/tCqvD2AzIJ3vakoSTlwCfj9rS6R.jpg', 'Le Deuxième Souffle', 'Gu, a famous gangster, has just escaped from jail. All french police is after him. Before leaving the country with Manouche, the woman he loves, Gu needs a final job to get some money. The job works, but a police''s scheming makes Gu appear as a traitor to his own accomplices. Gu will do whatever it takes to clean his honor...', '/auxgoI3jxk7S5ht0bq1wN135w9M.jpg', '2007-10-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16943, 'Bits & Pieces', 59147, NULL, '/9EwvsVwuu71uQeCAQ1LWdEWujyx.jpg', 'Il cielo è sempre più blu', 'Dive into the Eternal City – see Rome like you’ve never seen it before. Storefront robberies, bizarre murders, career dreamers, and cameos from Italy''s foremost directors and actors feature in this star-studded omnibus tale about life and love.', '/jSVZi2Xhd0ytmsLcpWC71itnMib.jpg', '1996-02-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16944, 'The Big Question', 120500, NULL, NULL, 'The Big Question', 'Although it was shot on the set of director Mel Gibson''s controversial epic The Passion of the Christ, this thought-provoking documentary is not about the making of the movie. Rather, filmmakers Francesco Cabras and Alberto Molinari delve into the nature of divinity and spiritual beliefs through revealing interviews with Gibson and members of his cast and crew -- including stars Jim Caviezel and Monica Bellucci.', '/xaWDtwbe2fCdKSesSY4xbb1SGn8.jpg', '2004-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16945, 'Unruly', 140811, NULL, '/5n4l0ArFqMzLxHsuMn3v4Shhfrh.jpg', 'Méditerranées', 'After many years spent in prison, Pitou returns back to his native town of Marseille. He couldn''t even imagine all the disappointments he would face there.', '/9DvUwbxWO0ZzglFMSXMcwdurt1m.jpg', '1999-10-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16946, 'Rhino Season', 110391, NULL, '/bDQh7oSpHoOeNbnPPvH2aXBBoF8.jpg', 'وەرزی کەرگەدەن', 'Kurdish-Iranian poet Sahel has just been released from a thirty-year prison sentence in Iran. Now the one thing keeping him going is the thought of finding his wife, who thinks he''s been dead for over twenty years.', '/1d7hDJnzEzrBjsWg3ad8Fq69j2O.jpg', '2012-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16947, 'Mafia Mamma', 809787, NULL, '/gGZxCy9keK0D6TxbmS8GJj85Ut4.jpg', 'Mafia Mamma', 'A suburban American woman inherits her grandfather’s Mafia empire and, guided by the Firm’s trusted consigliere, defies everyone’s expectations, including her own, as the new head of the family business.', '/hqFZqZFWWEDRCTtbTJqvrIitEKB.jpg', '2023-04-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16948, 'It Happened in Saint-Tropez', 184020, NULL, '/cJGRMvpgV6KxGLp26DqI7DSnrJU.jpg', 'Des gens qui s''embrassent', 'Zef’s stormy relationship with his brother Roni is further aggravated when Roni marries his daughter just as he is attending to his wife’s funeral. The two brothers have never got on with each other. One is faithful to his religion, the other lives only for the present. Between London, Paris, Saint-Tropez and New York, a series of confrontations and betrayals threatens to drive the family further apart, but out of this confusion will come a great love story, perhaps even two...', '/z1t9TdvgFyf0JWq7SE42xxCBKsO.jpg', '2013-01-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16949, 'Snowball', 167637, NULL, '/ht0LU1170TSZTc6XG9bwfcfMSI5.jpg', 'Palla di Neve', 'Snowball, a dolphin, gets into trouble when it swallows a bottle with the records of pension payments owed to Billy Bolla, an aged cruise ship entertainer. If the performer cannot quickly catch Snowball and induce him to produce the papers, he will have no retirement.', '/qi1GiFrojWslcIxJBVTkZJXN0qP.jpg', '1995-12-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16950, 'Bandits: Love and Liberty', 168922, NULL, '/aekulWh1xGVTHKBJCVOXJ3RiOeW.jpg', 'Briganti - Amore e Libertà', 'In 1838 in the kingdom of Naples and the Two Sicilies, Malacarne, gamekeeper of Baron San Germano, kills the bandit Caruso, whose widow gives birth to Giovanni and at the same time becomes the nurse of Costanza, San Germano’s orphaned daughter. Thirteen years later, Giovanni and Costanza fall in love to the jealousy of her uncle, who shuts her in a convent, ordering Giovanni to be killed by Malacarne who has meanwhile become a bandit. Barely alive, Giovanni is taken away by Bourbon soldiers. After Garibaldi’s arrival in Sicily and its union with Italy, Costanza is freed from the convent and returns to San Germano. She is visited by Giovanni and although still loves him, rejects him since she wishes to become a nun. In the meantime, Giovanni kills Malacarne and takes his place. Costanza marries the rich Lo Turco and the next day departs for Naples, but during the journey the carriage is attacked by Giovanni’s band. Costanza flees with him and they leave for America.', '/2j6Pej0q7eah7pUyeWFCehvGf7D.jpg', '1994-10-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16951, 'Mauvais Genre', 172961, NULL, '/8Yo6EvAf1zoJa45ImRl2t4uPqxN.jpg', 'Mauvais Genre', 'The film''s title is a pun, the double meaning referencing both the "wrong genre" and a person with distasteful motives. Insecure novelist Martial Bok promotes his new sexy novel La Fille de Dos ("Girl Observed From the Rear") with a round of book-signings and talk-shows. When beautiful hat designer Camille buys the book, Martial follows her and spies on her as she reads his book and removes her clothing. It''s the beginning of his obsession and also an inspiration. After Martial''s live-in girlfriend Lucie establishes contact with Camille for real, Martial is able to type out another sexy manuscript.', '/sVeKHSlwpvZv16y5EBEvqpa1Jpt.jpg', '1997-05-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16952, 'Dear Paris', 1119546, NULL, '/rZMTJ5Biql3vqjVTP0GjkSm5w6V.jpg', 'Paradis Paris', 'What makes life worth living? In a set of interconnected stories, several Paris residents see their lives turned upside down when death knocks at their door: a narcissistic Italian opera singer wakes up at the morgue only to realise her own passing came unnoticed; a British stuntman finds himself questioning his own profession when his son suffers an accident; an eccentric elderly Colombian woman makes a pact with death itself... While each character strives to reconnect with what matters most, the city of light, love and endless possibility shines brighter than ever.', '/AtlNewzoGpSVk1Udib4XmZjIF3x.jpg', '2024-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16953, 'Life with the Kids', 239067, NULL, '/8SbsBW13isNfoYWZcPXp99s6V0Z.jpg', 'Vita coi figli', 'The story of one man dealing with an unexpected series of events, discovering his youth once again in the relationship with a much younger woman and finally coming to grips with his age, and the fact that he hasn''t been there for his family like he should have.', '/uYak3OlVKeDTxRcaxqCJHzuPwsQ.jpg', '1990-02-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16954, 'Diabolik: Ginko Attacks!', 823999, NULL, '/jYbABnXml6XyQ7cfhZFkMRZvMQz.jpg', 'Diabolik - Ginko all''attacco!', 'Diabolik narrowly escapes Inspector Ginko''s latest trap, leaving his partner in crime Eva Kant behind. Furious, Eva offers Ginko her help in capturing him, but the former has to face first the return of an old flame of his, noblewoman Altea.', '/8QVbWBv94BAT9u1q9uJccwOxMzt.jpg', '2022-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16955, 'The Wonders', 265226, NULL, '/xjEEy1Ykrq0caDMUIQa2exiuEEI.jpg', 'Le meraviglie', 'In the Tuscan countryside, a family of traditional honey farmers struggles to make ends meet. The household consists of only daughters—four of them—led by the eldest, Gelsomina, who takes on the responsibilities of the family. When a small boy is sent to stay with them for rehabilitation, their routine is disrupted. As financial troubles threaten their home, Gelsomina sees an opportunity in a reality TV contest searching for ''Italy’s Most Traditional Family.'' Willing to expose their secluded life for the prize money, she clashes with her father’s rigid ways in a bid to secure their future.', '/u5Z23Rt9OKhQc61wPPwrDs4psdi.jpg', '2014-05-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16956, 'Rose, c''est Paris', 208467, NULL, '/lpjzS2XkoHvCLZSODgA8u8vylvW.jpg', 'Rose, c''est Paris', 'Bettina Rheims and Serge Bramly''s Rose, c''est Paris is both a photographic monograph and a feature-length film. This extraordinary work of art, in two different but interlocking and complementary formats, defies easy categorization. For in this multi-layered opus of poetic symbolism, photographer Bettina Rheims and writer Serge Bramly evoke the City of Light in a completely novel way: this is a Paris of surrealist visions, confused identities, artistic phantoms, unseen manipulation, obsession, fetish, and seething desire.', '/1xYeJ3gSHvRok61nzqaJzDi3FmS.jpg', '2010-05-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16957, 'Maria Callas: Letters and Memoirs', 1202640, NULL, '/xuGWMShAd2x2xVWFWoRrYIkEQsa.jpg', 'Maria Callas: Letters and Memoirs', 'An invaluable imprint of the world tour of the play Maria Callas: Letters and Memoirs, starring Monica Bellucci as the great opera diva. Through the chronicle of the tour, which lasted from November 2019 to January 2023, we observe and compare two different eras (the current one and the one in which Callas reached the apex of fame), while at the same time, we partake to and witness an essential dialogue between the great contemporary Italian actress and the voice that marked the 20th century: two women who, despite their different background, meet in retrospect due to their love of art.', '/itCohhfPmRJmJ75pDLRc3zMMEZc.jpg', '2025-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16958, 'Irréversible : à l''envers et contre tout', 1205486, NULL, NULL, 'Irréversible : à l''envers et contre tout', 'A documentary on the making of Irréversible', '/4oSbmD4QyflCdZPKetKEvShn2f9.jpg', '2021-05-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16959, 'Heartango', 280558, NULL, NULL, 'Heartango', 'Promotional short for Italian intimates company Intimissimi.', '/6Y0NAxcJb3QSBNK1B00JAqXPSA1.jpg', '2007-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16960, 'On the Milky Road', 255160, NULL, '/29O4XcNhzKvhLb4DiGQ934XXM5f.jpg', 'Na mlečnom putu', 'Spring in wartime. Each day a milkman crosses the frontline on a donkey, dodging bullets to bring his precious wares to the soldiers. Blessed with good fortune on his mission, loved by a beautiful villager, a peaceful future seems to await him… until the arrival of a mysterious Italian woman turns his life upside down. Thus begins a story of passionate, forbidden love that will plunge them both into a series of fantastic and dangerous adventures. They have been joined by fate, and nothing and no one seems able to stop them… Two-times Palme D''Or winner Emir Kusturica directs and stars in this story of love and war, rich in emotion, comedy and adventure.', '/okmLuoaeHOtcMK7UrBe1rYhBi0D.jpg', '2016-02-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16961, 'Cover Story - 20 anni di Vanity Fair', 1219535, NULL, '/dDKsJQvWAtiDZRwxO6Slaztrffs.jpg', 'Cover Story - 20 anni di Vanity Fair', NULL, '/s2DYQNbgNoApdK9d9vw6mFQJpWB.jpg', '2024-01-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16962, 'The Irreversible Odyssey', 1047240, NULL, NULL, 'The Irreversible Odyssey', 'The Irreversible Odyssey is a retrospective documentary featuring interviews with Gaspar Noé, actors Monica Bellucci, Vincent Cassel and Albert Dupontel.', '/ajtHkl49JnF6xZCjfAJ8gB1y37s.jpg', '2019-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16963, 'Baaria', 25846, NULL, '/lzSEhkipvwLLmL3PUIDreQCJdqs.jpg', 'Baarìa', 'In 1920s Bagheria, Giuseppe ''Peppino'' Torrenuova works as a shepherd to financially help his poor family. Over the next fifty years, Giuseppe''s life, as well as the life of the village, is observed. Giuseppe grows up, joins the Communist Party, marries a local girl, has children, and forges a political career for himself.', '/8gMju8daHITnaqjJFQfxJbVVtPJ.jpg', '2009-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16964, 'Those Who Love', 103704, NULL, '/Akq701BzW9EAb7bQ0NAJK0uWtdG.jpg', 'A los que aman', 'A secret and deep passion marks the life of a young doctor, and threatens the existence of those around him.', '/klPdZNwFLoeXsnZKv2MQlrInitn.jpg', '1998-10-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16965, 'Ville-Marie', 353463, NULL, '/vy6NUb6NC9HSm93hcF4yX2kz20O.jpg', 'Ville-Marie', 'Celebrated European actor Sophie Bernard is in Montreal shooting a movie, and she''s taking the opportunity to visit her gay son Thomas in the hope of bridging the rift that''s grown between them. But Thomas has his own agenda for their time together; he intends to finally get some answers as to the identity of his father. Meanwhile, at Ville-Marie Hospital, paramedic Pierre struggles with PTSD, and though he has support in Marie, a nurse who keeps the overflowing emergency room running, it''s uncertain whether he''ll remain able to cope with the high intensity of his work. Each of these four characters is dealing with emotional damage — and on one dark Montreal night, their lives will all intersect in a fateful occurrence at Ville-Marie.', '/e0saRPwVtw4FQmh9FmyaXsF7h11.jpg', '2015-10-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16966, 'Pleasure (And Its Little Inconveniences)', 45751, NULL, NULL, 'Le Plaisir (et ses petits tracas)', 'Seemingly unrelated events connect several people: a young wounded soldier, a nurse, a failed comedian, and a murderer.  The film starts literally with a bang and ends with a strangulation. In between there are numerous events both strange and unpredictable involving drugs and homosexuality, a deaf-mute and a potential suicide. The odd characters assembled in this movie are each in their own way in search of sexual gratification.', '/4HJwUHOtxAnLrUtBPNkJ8gF4ChH.jpg', '1998-08-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16967, 'A Beautiful Vacation', 374316, NULL, NULL, '"Una Bella Vacanza" Buon Compleanno Dino Risi!', 'This 2006 documentary was filmed on the occasion of director Dino Risi''s ninetieth birthday. It features interviews with his collaborators, friends, and family, as well as Risi himself, who talks candidly about his personal successes and the obstacles he has faced.', '/qUzHr7qsq4WMc45B8JrKOssEt8h.jpg', '2006-12-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16968, 'Na Quebrada', 297278, NULL, '/xblLMVyoua1ByLzX5y3WiooGY0K.jpg', 'Na Quebrada', 'In the ghettos of the greatest metropolis in Brazil, a midst flying bullets, love and any number of hurdles, young people''s stories mingle and collide in the search for dreams and choices. Inspired by true stories, the feature film ''Broken Town'' reveals the struggle faced and the choices made by teenagers who have always been surrounded by weapons, crime, and hardship.', '/6d6HIauSSQvybsmBkAXx0JPrqAG.jpg', '2014-10-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
