INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16972, 'As You Want Me', 409509, NULL, '/AkPv59MDiqPoMc9UtIyIvRlEiP1.jpg', 'Come mi vuoi', 'Pasquale is a policeman in Roma. During a roundup he meets Desideria. He/she is a transsexual, living together with other two trans , Gaia and Gioia. But overall Desideria is an old friend of Pasquale, they already been attending the same schools. Desideria immediately fall in love for Pasquale. But the policeman has a fiancé, Nellina, even if too far so they meet rarely. That''s why Pasquale could change idea about Desideria.', '/2JGdM4irWjHedORKLnBFVHoHEdM.jpg', '1997-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16973, 'The Best Years of a Life', 582887, NULL, '/ylob1axAunw2NW06Drd5jfjMASK.jpg', 'Les plus belles années d''une vie', 'They knew each other long ago: a man and a woman whose dazzling and unexpected romance captured in the now-iconic film revolutionized our understanding of love. Today, the former race car driver seems lost in the pathways of his memory. In order to help him, his son seeks out the woman his father wasn’t able to cherish but whom he constantly revisits in his thoughts and dreams. Anne reunites with Jean-Louis and their story picks up where they left it…', '/41jZAOJvZRj4e1jshl3sFzKqHnR.jpg', '2019-05-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
