INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16981, 'Dry', 797840, NULL, '/YN9QF1ktsd0Wjia3Hn2ylXMuWK.jpg', 'Siccità', 'In Rome it hasn’t rained for three years and the lack of water is overturning rules and habits. Through the city dying of thirst and prohibitions moves a chorus of people, young and old, marginalised and successful, victims and profiteers. Their lives are linked in a single design, while each seeks his or her deliverance.', '/2pl2qRaUvJ9iKiNROyKi5a9l31E.jpg', '2022-09-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (16982, 'The Legend of the Christmas Witch: The Origins', 811050, NULL, '/gE1AlXZWgUTj4rRCImsvuLXVa59.jpg', 'La befana vien di notte 2 - Le origini', '18th century. Paola, a young, reckless street urchin inadvertently gets in the way of the plans of terrifying Baron De Michelis, a small and mean hunchback always escorted by his trusted (and abused) minion Marmotta, with an unquenchable thirst for power and an unmeasurable hate for witches. The intervention of the sweet and powerful Dolores, a good witch who has devoted her life to children, saves Paola from being burned at the stake. Through a magical apprenticeship, breakneck pursuits, incredible transformations and a whole lot of trouble, Paola will discover that fate has something really special in store for her… And so the legend begins.', '/b2Yv544mACPTcp8ZrfIaLOcQXj6.jpg', '2021-12-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
