INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17014, 'The Reckoning', 25935, NULL, '/njUgaQiMubIqErfN0Ken7BoXEKC.jpg', 'The Reckoning', 'In 14th Century England, this tale of murder and mystery follows a fugitive priest who falls in with a troupe of actors. As they arrive in a small town, the actors encounter a woman being sentenced to death for practicing witchcraft and murder. Discarding the expected bible stories, the actors now stage a performance based on the crime. Through the performance of the play, they discover a mystery.', '/pv2ocoAR3b4TJ4oGQMIy1CJx2wQ.jpg', '2004-02-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
