INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17016, 'WΔZ', 15069, NULL, '/6oJiTcSBra0w1DDonE9kn4zw9cN.jpg', 'WΔZ', 'There is something horribly wrong with the bodies found in the dark city streets. Some are mutilated while others have the Price equation (wΔz = Cov (w,z) = βwzVz) carved into their flesh. Detective Eddie Argo and his new partner Helen Westcott unearth the meaning of the odd equation and realise each victim is being offered a gruesome choice: kill your loved ones, or be killed. Before long it becomes clear that the perpetrator has suffered a similar fate and is now coping by seeking a way to solve this philosophical dilemma.', '/bf11TuyZCWUnSDaGxsmq4jBrmwx.jpg', '2007-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17017, 'LD 50 Lethal Dose', 15473, NULL, NULL, 'LD 50 Lethal Dose', 'Re-formed by a coded message to their web site, a group of animal rights activists set off to free an imprisoned colleague from a terrifying ordeal. Their rescue mission leads them to a disused lab, but what should have been a simple raid turns into a series of twisted and mind bending incidents where the free and the caged switch places, in this tormented psychological horror.', '/m0OAj6Bb5HtNPQBEMBJyqVSYqgd.jpg', '2003-02-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17018, 'Sweeney Todd', 37924, NULL, '/d118NiMInfjuMRGmEmfF5qif9Wf.jpg', 'Sweeney Todd', 'A BBC adaptation of the Victorian "penny dreadful" tale of 19th century "demon barber" Sweeney Todd, of Fleet Street, who cuts the throats of unsuspecting clients in his London shop.', '/40ntPvTqjqEJlME1AtBEzwVUPHC.jpg', '2006-01-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17019, 'A for Andromeda', 45158, NULL, '/ysqAOKXpCLSWRNPbLLJOiSYI7pO.jpg', 'A for Andromeda', 'In the Yorkshire Dales, a mysterious signal from space arrives with instructions to build a powerful super-computer. Once completed, the evice''s motives provokes discourse between scientists John Fleming and Madeleine Dawnay as further instructions are to create a living organism, which Dawnay develops. The entity compels lab assistant Christine to commit suicide, and, upon manifestation, adopts her form, now known as Andromeda.', '/dgZUv8xbs3IjzRrDY5g8nYegBWE.jpg', '2006-03-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17020, 'Deserter', 63971, NULL, '/s3Q8PL6P9ZPQFhwHEN7Kt4MFbHf.jpg', 'Simon: An English Legionnaire', 'Unlikely friends in a melting pot of confusion. Simon Murray fights for the French Foreign Legion. Pascal Dupont fights for himself. War torn men question honour, hope, morality...because you can desert everything...except yourself.', '/nb7fYnVnWeTRYNxvKFLDbcRV87f.jpg', '2002-04-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17021, 'Scenes of a Sexual Nature', 18558, NULL, '/aGISpdwLN94fR6fs6xinYsk2FQC.jpg', 'Scenes of a Sexual Nature', 'Sex and love. Some seek it, some need it, some spurn it and some pay for it, but we''re all involved in it. Set on one afternoon on Hampstead Heath in north-west  London, the film investigates the minutiae of seven couples. What makes us tick?', '/gyDQY4mileMV4C1O1T4Ux6Mtuwn.jpg', '2006-11-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17022, 'Minotaur', 18870, NULL, '/ig5nkwRi0AbPTYxl6zMb8u6dqkQ.jpg', 'Minotaur', 'Long ago in the Iron Age, a shadow loomed over a lonely village. For generations, the village youths are stolen from their families and delivered as sacrifice to a mythical beast - the Minotaur, that dwells beneath a great palace. Theo, haunted by the loss of his love in an earlier sacrifice is convinced that the beast isn''t real and that his girl still lives as a slave within the palace.', '/nwSYtZNc42WaqOzkMpSuZ4NElJr.jpg', '2006-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
