INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17025, 'Heroes and Demons', 155776, NULL, '/OKR5JJmayeCQ2kAFyGdCfdtVQb.jpg', 'Heroes and Demons', 'Gripping thriller drama with fantastic all-star cast: Six different stories about crooks, misfits, heroes and their determination to overcome the destiny. Stories about intolerance, hopelessness, betrayal, despair, and the unpredictable.', '/bGwEuV6u91naC6g3c1983rDI5uW.jpg', '2011-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
