INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17027, 'London Road', 328483, NULL, '/ohp0ZrioXFTe3v9HyqSiN510DAP.jpg', 'London Road', 'London Road is a musical drama that documents the events of 2006, when the quiet rural town of Ipswich was shattered by the discovery of the bodies of five women. The residents of London Road had struggled for years with frequent soliciting and kerb-crawling on their street. When a local resident was charged and then convicted of the murders, the community grappled with what it meant to be at the epicentre of this tragedy.', '/skZ2ZokJLkjJi98T82fzCQYTDRY.jpg', '2015-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17028, 'Sucker Punch', 54185, NULL, '/zV6KITjBKNj3Gy0AZBBN2KGmTdQ.jpg', 'Sucker Punch', 'Ray ''Harley'' Davidson is a hustler. With flash clothes and a fast mouth, Harley lives life in the fast lane. With his passion for all things gambling, money runs like water through Harley''s hands and as quickly as he makes a killing he takes a beating, normally at the poker table. Nominally an illegal prize-fight manager, Harley hasn''t produced a live one in months, until Charles Buchinsky literally wanders into his life. Charles Buchinsky, street fighter extraordinaire. He''s from out of town looking for a fight and the chance to tie up a few loose ends. Keeps himself to himself, lets his fists do the talking and his word is his bond. Victor Maitland, top illegal fight promoter and porn baron. Hates losing and loves the prestige of managing the best hitter in town. Harley dreams of bringing Maitland down and after seeing Buchinsky at work, engineers a fragile partnership. The duo soon becomes a hot ticket...', '/qyR5sKqwUkPCsv0Ru53IceiQdBe.jpg', '2008-08-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17029, 'Dot the I', 18538, NULL, '/cNGpwYkko2GvU6sDDkoSwefN0Zm.jpg', 'Dot the I', 'A fiery Spanish woman is about to marry a kind British man when she meets a Brazilian actor who ignites in her a flame of lust she can''t ignore.', '/2Gq1e0OC7r6L4V5dJaLgANk09xl.jpg', '2003-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17030, 'Flood', 6309, NULL, '/8RHqeBwgHIZnNeswqLJdm0pz05Y.jpg', 'Flood', 'Timely yet terrifying, The Flood predicts the unthinkable. When a raging storm coincides with high seas it unleashes a colossal tidal surge, which travels mercilessly down England''s East Coast and into the Thames Estuary. Overwhelming the Barrier, torrents of water pour into the city. The lives of millions of Londoners are at stake.', '/s0F2iDMtj6uYQPqbjwCPlwug2O4.jpg', '2007-08-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17031, 'Perfect', 340984, NULL, NULL, 'Perfect', 'A sometimes fantastical love story set in Notting Hill, Perfect tells the story of what happens when Adam and Liberty''s paths cross and how their worlds impact on each other.', '/qiUxV2xxmVW0qMb7bC65Xu6zVLP.jpg', '2009-06-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17032, 'Gideon''s Daughter', 59958, NULL, '/iYzeI1DxZliyYv4Xab06MIaDwLf.jpg', 'Gideon''s Daughter', 'Bill Nighy and Miranda Richardson star in a story of grief and celebrity, set in the intense spring and summer of New Labour''s election victory and Diana''s death. Nighy is a PR guru who has to stop and re-evaluate his world when his daughter threatens to leave his life, perhaps as revenge for his serial infidelities. Richardson plays a mother trying to bury her grief in an unconventional way after the loss of her young son.', '/7QNYM2gCTBEWuW5KqOJ8wS2dABb.jpg', '2005-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:03', 0);
