INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17049, 'Johnson Family Vacation', 19084, NULL, '/jDOHPRqgsEHojHnB0FfZsU9KP7v.jpg', 'Johnson Family Vacation', 'Nate Johnson, a Los Angeles man estranged from his wife and three children, decides to reconnect with his family by taking them with him on a road trip to Missouri for a big family reunion.', '/3F6bmetJSJvqLCB9PMxpNz1sngB.jpg', '2004-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
