INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17052, 'DJ SWB Volume 6 | This Is How We Do', 56349, NULL, NULL, 'DJ SWB Volume 6 | This Is How We Do', 'DJ SWB is back at it again with his crazyyyy video mixes, and this time YUNG JOC and LUPE FIASCO lend a helping hand by hosting over 107 minutes of the strongest video blends in the market. With over 40 new video mixes, bonus interviews (including TI, Lupe and Young Joc), and a live performance by the Clipse, "How We Do Vol 6" is action packed from start to finish! This DVD is a must have for any hip-hop fan and a great edition to DJ SWB''s always highly anticipated "How We Do" series. And If you don''t believe our word, just check out the trailer and see the excitement for yourself!', NULL, '2009-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17053, 'Allegiance', 141999, NULL, '/ju9tIaYSbRRJugyyxTvpNVUSM6U.jpg', 'Allegiance', 'After being granted a questionable transfer that will keep him stateside as his National Guard unit deploys for Iraq, Lieutenant Danny Sefton becomes embroiled in a last minute AWOL attempt by one of his soldiers — forcing him to choose between his loyalties to the fleeing soldier, his unit and his fiancé.', '/xN8A0wslH0bkEM4Ie0GbK0Dszrj.jpg', '2012-12-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
