INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17055, 'All About the Benjamins', 13950, NULL, '/3Z9n1DjfYzvknQvoLLkMCvQsSxz.jpg', 'All About the Benjamins', 'Bounty hunter Bucum Jackson teams with the small-time con artist, Reggie Wright, that he is pursuing, in an attempt to locate a missing stash of diamonds and a lottery ticket worth millions of dollars. Bucum and Reggie find themselves in a race to the finish as they embark on an unlikely partnership that should -- when all is said and done -- prove beneficial to them both.', '/sO7IpJHjZBGLevi8Ozj9EsAUw5h.jpg', '2002-03-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17056, 'In Broad Daylight', 616187, NULL, '/52hAx1G8Y4qctvWTIOQe0z2xScx.jpg', 'In Broad Daylight', 'Jordan is kidnapped and held hostage by her estranged boyfriend Steve. Her family and community rally together to find her before it''s too late. He cousin Malik makes it his personal mission to find and bring her home safely.', '/OBtC6WTQWIuWBSPDYIMDINNBDy.jpg', '2019-07-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17057, 'Hurricane Season', 32007, NULL, '/ySdpEXCGAoKwHD5m3NjGeKyfVSI.jpg', 'Hurricane Season', 'Based on true events amid the wreckage and chaos dealt by Hurricane Katrina; one basketball coach in Marrero, Louisiana just will not give up. Coach Al Collins, gathers other players from hard-hit schools and builds a team actually worthy enough to go to the state playoffs.', '/axzk9UTvnV68brpqmmVNp4z2kj5.jpg', '2010-02-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17058, 'Christina Aguilera: My Reflection', 83604, NULL, '/p8KwaHWqGgC3NuTaFZUHWmm0LGj.jpg', 'Christina Aguilera: My Reflection', 'Aguilera''s first concert video, a repackaging of a slick special that aired on ABC-TV in 2000, shows what this "girl" really wants is to move beyond the bouncy R&B-flavored pop she''s known for. Her cheeky hits ("Genie in a Bottle," "Come On Over, Baby," "What a Girl Wants") are followed by songs from Mi Reflejo, her Spanish-language album, and My Kind of Christmas, her holiday release. She has sweet duets with R&B legend Dr. John on "Merry Christmas, Baby" and balladeer Brian McKnight on "Have Yourself a Merry Little Christmas," and shares the stage with rapper Lil'' Bow Wow (weird, but it works) on "So Emotional" and "Christmas Time."', '/w4BoyTeVDhB217YYpncyXb6TAlr.jpg', '2001-06-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17059, 'Stuck on You', 1792, NULL, '/bj4VHJFQOWXKgnvFrlHoBeOLU3M.jpg', 'Stuck on You', 'In Martha''s Vineyard, Mass., conjoined twins Walt and Bob Tenor make the best of their handicap by being the fastest grill cooks in town. While outgoing Walt hopes to one day become a famous actor, shy Bob prefers to stay out of the spotlight. When a fading Hollywood actress, Cher, decides to get her show "Honey and the Beaze" cancelled, she hires Walt -- and his brotherly appendage -- as her costars. But their addition surprisingly achieves the opposite.', '/5TmPGPsOP4EgMo8X14pyywxB1j2.jpg', '2003-12-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
