INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17061, 'The Third Wheel', 37270, NULL, '/fMMdGBMNFt1KFydmHY3MjXkqH0x.jpg', 'The Third Wheel', 'The clumsy and shy Stanley is a nice fellow, beloved by his colleagues in the office. He has a crush on the gorgeous new-hire Diana, but he has difficulties to get close to her. When Stanley finally invites Diana for a date, he hits the homeless Phil with his Taurus, and his planned night turns upside down.', '/tP2wOztb1FW3JlyHMDzlyeZRjBS.jpg', '2002-05-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17062, 'Mystic Pizza', 11191, NULL, '/qMLXgZM0MtlZ0tFSTVfNY6v64ln.jpg', 'Mystic Pizza', 'Three teenage girls come of age while working at a pizza parlor in Mystic, Connecticut.', '/2wqMKLJEMjenT7U8UqnuI070cUC.jpg', '1988-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17063, 'All the Pretty Horses', 21355, NULL, '/7U6WJ0qri2sACtcGa0wEpM9eAM1.jpg', 'All the Pretty Horses', 'The year is 1949. A young Texan named John Grady finds himself without a home after his mother sells the ranch where he has spent his entire life. Lured south of the border by the romance of cowboy life and the promise of a fresh start, Cole and his pal embark on an adventure that will test their resilience, define their maturity, and change their lives forever.', '/6E4E7wYXw1DE2321F2hVNryLSk7.jpg', '2000-12-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17064, 'The Informant!', 11323, NULL, '/gDgSTQfkDG4y3SyGE2XVRBX80gy.jpg', 'The Informant!', 'A rising star at agri-industry giant Archer Daniels Midland (ADM), Mark Whitacre suddenly turns whistleblower. Even as he exposes his company’s multi-national price-fixing conspiracy to the FBI, Whitacre envisions himself being hailed as a hero of the common man and handed a promotion.', '/eV8u5crNe4QYWcu0zjKxFVq2Qem.jpg', '2009-09-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17065, 'Youth Without Youth', 7797, NULL, '/nZJhuZMSlL21rm5HrrLWWIV6drP.jpg', 'Youth Without Youth', 'Professor of language and philosophy Dominic Matei is struck by lightning and  ages backwards from 70 to 40 in a week, attracting the world and the Nazis. While on the run, the professor meets a young woman who has her own experience with a lightning storm. Not only does Dominic find love again, but her new abilities hold the key to his research.', '/yG902RF45xC0IsPZkjuJZMmB5C5.jpg', '2007-10-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17066, 'The Making of the Last Duel', 1089625, NULL, NULL, 'The Making of the Last Duel', 'Get unprecedented access to renowned director Ridley Scott as he collaborates with the cast and crew to make critical decisions about location, cinematography and performances.', '/8sJhjZFNwuX18yieuNSAjUwPs9J.jpg', '2021-11-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
