INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17068, 'Margaret', 44754, NULL, '/ugDpO1cu2RxL1URucxPLkT31KG3.jpg', 'Margaret', '17-year-old Lisa feels certain that she inadvertently played a role in causing a traffic accident that claimed a woman''s life. In her attempts to set things right, she meets with opposition at every step. Torn apart with frustration, she begins emotionally brutalizing her family, her friends, her teachers, and, most of all, herself. She has been confronted quite unexpectedly with a basic truth: that her youthful ideals are on a collision course with the realities and compromises of the adult world.', '/zqBao8uRH6TQAJd13tqC22vPB76.jpg', '2011-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
