INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17078, 'After Frank', 1182551, NULL, NULL, 'After Frank', 'Filmmaker, Walter Forsyth sets out on a journey to make a tribute film about photographer/filmmaker, Robert Frank, deconstructing the documentary form along the way. With appearances by Albert Maysles, Nick Broomfield, ex-Rolling Stone Mick Taylor, Alfred Leslie and Matt Damon. "He pulled a sad poem right out of America, taking his place among the great poets of our time" - Jack Karoac.', NULL, '2005-09-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17079, 'Marvel Studios Assembled: The Making of Thor: Love and Thunder', 1015595, NULL, '/3UBlm2N094EFPWuBn3v2EGtHr95.jpg', 'Marvel Studios Assembled: The Making of Thor: Love and Thunder', 'Settle in with the likes of Taika Waititi, Chris Hemsworth, Natalie Portman, Christian Bale, and Tessa Thompson, and as they divulge the secrets behind the creation of Thor: Love and Thunder. Through in-depth interviews with cast and crew, along with raw, unseen footage from the set and beyond, this documentary special pulls back the curtain on the God of Thunder’s fourth feature film.', '/eb7GP3cttApzilOOM52L129Eaaj.jpg', '2022-09-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
