INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17084, '2007 Boston Red Sox: The Official World Series Film', 58021, NULL, '/vaOtxeAa0jZBhIZAxyhjHBX3zBy.jpg', '2007 Boston Red Sox: The Official World Series Film', 'Red Sox Nation rejoiced as its beloved team reached the World Series in dramatic fashion, having just overcome a three-games-to-one deficit in the ALCS by outscoring the Cleveland Indians 30-5 in the final three contests. There they met the sizzling Colorado Rockies -victors in 21 of their last 22 games and just the second team ever to win their first seven in the postseason. But while both teams came into the World Series on fire, only one continued that torrid pace. The Red Sox briskly swept the Rockies aside to capture their second title of the decade and their second straight Fall Classic sweep.', '/nLwcuZP8uMFIHboOfsoqnl4KRo5.jpg', '2007-11-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17085, 'Prince: 21 Nights in London', 446610, NULL, '/rEvm0Fb6L4kcB4bBfc96KLlxDCC.jpg', 'Prince: 21 Nights in London', 'A documentary film about Prince''s 21 Night Stand at the O2 Arena in London. England.', '/nRCdeO80jRxaeDWOUhlpv6RjJvI.jpg', '2008-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17086, 'Glory Daze', 26626, NULL, '/mPSqoeQObPuoT616wz3v5EtifhC.jpg', 'Glory Daze', 'Jack, a soon-to-be graduate, finds he''s having a difficult time letting go of the college life -- and decides maybe he doesn''t have to. Also questioning whether there''s life after college are Jack''s roommates: Rob, who fears domestication; comic-strip artist Mickey, who''s shy around girls; intellectual party animal Slosh; and perpetual student Dennis.', '/mosH3RnC5wjcThd0DZq4ZqWkTPQ.jpg', '1995-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17087, 'Howard Zinn: You Can''t Be Neutral on a Moving Train', 33150, NULL, '/x5F4SgHIX5wZFkAjFRxR4Evs5G6.jpg', 'Howard Zinn: You Can''t Be Neutral on a Moving Train', 'You Can''t Be Neutral documents the life and times of the historian, activist and author of the best selling classic "A People''s History of the United States". Featuring rare archival materials, interviews with Howard Zinn as well as colleagues and friends including Noam Chomsky, Marian Wright Edelman, Daniel Ellsberg, Tom Hayden and Alice Walker.', '/haeDX5PjOYpI0xsbwcKjsQvAyNY.jpg', '2004-06-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
