INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17089, 'The Man Who Saved the World', 214137, NULL, '/Da000jQtBctswxgMgRqjg3RT29.jpg', 'The Man Who Saved the World', 'A documentary film about Stanislav Petrov, a former lieutenant colonel of the Soviet Air Defence Forces.', '/6IyL7p8BiCBO5yme5bvEuCu41EY.jpg', '2014-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17090, 'Rising Son', 293399, NULL, '/kW701TJsOhhDygO3irZw7qMcbMA.jpg', 'Rising Son', 'Gus Robinson loves three things: his job, family, and country; but suddenly he''s losing all three. When his factory shuts down, Gus faces unemployment. It''s a time of change for his wife Martha and son Charlie as they reassess a world Gus barely recognizes. But through the nightmare, one dream they cannot take away from him; the reason he will continue to fight: his son, Charlie.', '/11f1hCoLSvRhGNUWL9fnJv1puW9.jpg', '1990-07-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17091, 'Teenage Paparazzo', 54994, NULL, '/1KXxNTawX5cYuutpKkypJhShU0u.jpg', 'Teenage Paparazzo', 'A documentary that examines the relationship between celebrity and society.', '/8bFVNIfo70z5HZMW3nya2QBtS2n.jpg', '2010-08-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17092, 'Plan B', 489417, NULL, '/kQSoaGwqAzGsJb5Pyeu8klNuHkv.jpg', 'Plan B', 'Narrated by Matt Damon, Plan B is a 90 minute documentary based on the book by environmental visionary Lester Brown. Shot on location around the world, the film''s message is clear and unflinching -- either confront the realities of climate change or suffer the consequences of lost civilizations and failed states. Ultimately Plan B provides audiences with a glimpse into a new and emerging economy based upon renewable resources as well as strategies to avoid the growing threat of global warming. Appearing with Lester Brown are Nobel Laureate Paul Krugman, Pulitzer Prize winner Tom Friedman, former Governor and Secretary of the Interior Bruce Babbitt, along with other scholars and scientists. Locations include: China, Japan, South Korea, India, Italy, Turkey, Bangladesh, Zambia, Haiti, and the U.S.', '/2xJVGbHhP68KhItAdlFtJ3QO4wP.jpg', '2011-03-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17093, 'The Long Way Home: Making ''The Martian''', 603459, NULL, '/nionfsRokOX4CGXN1o8iNlz3EQg.jpg', 'The Long Way Home: Making ''The Martian''', 'A long form documentary on the making of Ridley Scott''s film, "The Martian," featuring interviews with its cast and crew.', '/jo4bpujR5acfcJrLkH0TZ3MumjG.jpg', '2016-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17094, 'Jay and Silent Bob Reboot', 440762, NULL, '/z7U3MXCHsnIBiYOMXnXZSiapmyc.jpg', 'Jay and Silent Bob Reboot', 'Jay and Silent Bob embark on a cross-country mission to stop Hollywood from rebooting a film based on their comic book characters Bluntman and Chronic.', '/5uGl5lbcpGLTvtLwBMnfRC0Az5u.jpg', '2019-10-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17095, 'American Teacher', 75760, NULL, NULL, 'American Teacher', 'As the debate over the state of America''s public school system rages on, one thing everyone agrees on is the need for great teachers. Yet, while research proves that teachers are the most important school factor in a child''s future success, America''s teachers are so woefully underpaid that almost a third must divide their time between a second job in order to make a living. Chronicling the stories of four teachers in different areas of the country, American Teacher reveals the frustrating realities of today''s educators, the difficulty of attracting talented new teachers, and why so many of our best teachers feel forced to leave the profession altogether. But this wake-up call to our system''s failings also looks at possibilities for reform. Can we re-value teaching in the United States and turn it into a prestigious, financially attractive and competitive profession? With almost half of American teachers leaving the field in the next five years, now is the time to find out.', '/AapxrTEfa8zMAwQWzDx2RpTJpus.jpg', '2011-05-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17096, 'The Good Old Boys', 277388, NULL, '/ftC6OY9ySSHAWIet22OfLf9piGp.jpg', 'The Good Old Boys', 'An aging cowboy must choose between his desire to remain free and the responsibilities of maintaining a family.', '/iMbkbVfocibpao6YoLqH87ExGA2.jpg', '1995-03-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17097, 'Oh, What a Lovely Tea Party', 285278, NULL, '/k0X42PwXKcHwQON5pMs9INVXSuF.jpg', 'Oh, What a Lovely Tea Party', 'Directed by the wife of ''That Kevin Smith'', Jennifer Schwalbach Smith, a feature length documentary looking at the behind the scenes making of JAY AND SILENT BOB STRIKE BACK.', '/yK5FAZ1Suqntdn44AagoRauKra4.jpg', '2004-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17098, 'Stuck Together: Bringing Stuck on You to the Screen', 687754, NULL, NULL, 'Stuck Together: Bringing Stuck on You to the Screen', 'Comments from the Farrellys, Thomas, Wessler, Damon, Kinnear, and actors Ray “Rocket” Valliere, Wen Yan Shih, Lawyer Milloy and Tom Brady. They chat about the origins of the film and its slow path to the screen, casting, the story and character development, disabilities in the film, and their use of athletes in cameos.', '/4R9iul2tTNLlOBk0iW4hThta7bj.jpg', '2004-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17099, 'Making It Stick: The Makeup Effects of Stuck on You', 687771, NULL, NULL, 'Making It Stick: The Makeup Effects of Stuck on You', 'We find notes from the Farrellys, Damon, Kinnear, Thomas, Wessler and special make-up designer Tony Gardner. The latter participant dominates the show as he lets us know about the design of the conjoined rig, the various challenges and its execution. We also learn about general issues and the way the actors related to each other.', '/4R9iul2tTNLlOBk0iW4hThta7bj.jpg', '2004-04-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:04', 0);
