INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17120, 'Playing with Beethoven', 903856, NULL, '/vMzaMRPI2s7BzUFjZhj4ETszq8h.jpg', 'Playing with Beethoven', 'Josh, a classical piano student focused on winning the biggest competition of his life, encounters Charlotte, a free-spirited jazz pianist who distracts him to better her chances of winning. She lures him away from the practice room for a magical night and ends up teaching Josh that life, like his music, is about taking risks.', '/iaEEYxbun9lNbzvRR5DRnM6Oy04.jpg', '2021-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
