INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17122, 'Confessions of an American Bride', 62379, NULL, NULL, 'Confessions of an American Bride', 'Young career woman Samantha ''Sam'' Hoyt gets swept off her feet by Benjamin ''Ben'' Rosen, who romances her better then anyone before, so she jumps at the offer of becoming his fiancée. If Ben thought a girls typical obsession with the perfect wedding was testing, she soon proves a particularly bad case, and before he gets used to that meeting each-others parents complicates things gravely, as Jewish and church wedding traditions don''t exactly mix easily. They take their time preparing while living together. Then fate strikes again: the key man from the client of her firms advertising campaign is Luke Stinson, the perfect gay at college whom she could never date because of a rather serious fall just when they could have kissed. Luke proves still as irresistible, gorgeous, charming, easy-going and simply too sexy for any female not to lust for at first sight, and...', '/3BUHJBVB3UsIRrIQPvyJzHCUXrN.jpg', '2007-08-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17123, 'Why on Earth', 1012087, NULL, '/3pwQd6jr32Fq71iZLpsQ3bNNVCT.jpg', 'Why on Earth', 'Travel the globe to experience the vital connection between humans, animals, and our planet through stunning, rarely before seen footage which exposes the effects that deforestation and the illegal trade of threatened and endangered species have on elephants, lions, sharks, orangutans, and more. By caring for these beautiful animals, we begin a healing process that will eventually help us all.', '/1INhokxB7jstSKCN0VL7JSHXxXM.jpg', '2022-08-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17124, 'The Crooked E: The Unshredded Truth About Enron', 70207, NULL, NULL, 'The Crooked E: The Unshredded Truth About Enron', 'Brian Cruver, an ambitious 26-year-old lands a job at Enron. As he assimilates to the company''s get-rich-quick mantra, spending sprees and wild corporate "gatherings" become the norm. But when Enron files for bankruptcy, Cruver discovers he''s just a pawn in a failing game of corporate greed--one that made the rich richer...while the rest lost everything.', '/xOcDA4SzbZTngyicEQKFcFWek7k.jpg', '2003-01-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17125, 'Golden Winter', 134671, NULL, '/NloDMzB5loWauj7Ztzw4yjMNDC.jpg', 'Golden Winter', 'A runaway boy befriends a pack of homeless puppies. Together, they stop a bank robbery and find a family to adopt them all.', '/klVFo0I3ByvL73YzPEmm9FsFfdp.jpg', '2012-09-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17126, 'A Green Story', 185351, NULL, NULL, 'A Green Story', 'Van Vlahakis left Greece five decades ago with 22 dollars in his pocket. He arrived in the US hoping for a better future for him and his family. Eftichios as is his Greek name not only managed to live the American dream for himself, but also created Earth Friendly Products, a US giant for environmentally friendly cleaning products. His story is not only about transforming his life but also the lives of the ones around him as the owner and CEO of Earth Friendly Products. The story centers on the modern day Vlahakis, who is diagnosed with cancer and given only few months to live. During this time, he reflects on his early life as an immigrant during the 1950''s and ultimately decides to push himself to the limit by closing one final business deal that will concretize his company''s success, even if it means taking on a large corporation that is trying to take over his company.', '/gno3aAwcfeliwmtbIpwJ6qdps2h.jpg', '2013-05-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17127, 'Seamless', 213553, NULL, NULL, 'Seamless', 'While J.B.''s main occupation is running a trendy clothes store, he has also taken a group of street kids under his wing. When he meets a beautiful fashion designer, however, he abandons the kids and succumbs to his lusty desires.', '/vnUexMQDJqr4Adjmu4aN1hV1yRy.jpg', '1999-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17128, 'Catch a Christmas Star', 238304, NULL, '/2QL65MG9LKDgLPep34SXjvJPSYZ.jpg', 'Catch a Christmas Star', 'Nikki Crandon is one of the biggest pop stars on the planet. Whether she''s singing the National Anthem or promoting her latest album, everyone knows who she is—none more so than New Jersey high school basketball coach and widower Chris Mitchell, who was Nikki''s first love in high school. When Chris'' 10-year-old daughter Sophie finds out her dad still has feelings for the singer, she takes matters into her own hands. With her 8-year-old brother Jackson in tow, Sophie succeeds in reuniting the two. But when a misunderstanding and the growing glare of the public spotlight threaten Chris and Nikki''s happiness, one can only wonder: will fame get in the way of a Merry Christmas?', '/40nMble3uFagwJ7ffagvefbcKCJ.jpg', '2013-11-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17129, 'The Outsider', 241765, NULL, '/nxWUUSYOTEAjARGUI9EcTBSMo2u.jpg', 'The Outsider', 'Revolves around a British military contractor Lex Walker who is told his daughter has died. When he arrives in Los Angeles and discovers the body is not hers, he begins an investigation.', '/iYRFAxQpB0VVVO17cPC8nEyZiLN.jpg', '2015-06-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17130, 'Death on the Border', 1186052, NULL, '/8bfts544SQzWK1UuJBV5wrwEGEh.jpg', 'Death on the Border', 'Two determined women vie to escape their abusive relationships with a dirty Detective at rock bottom, determined to move sex trafficked girls over the Mexican border.', '/sPr1hZmowPggNQZWyH3AQhAJpTr.jpg', '2023-11-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17131, 'Plan B', 1193620, NULL, '/3aWxViFH5OgsCyhkaCFYbFJL5T0.jpg', 'Plan B', 'When a one night stand with her awkward neighbor leaves her pregnant, a young woman decides to quickly sleep with a successful businessman and tell him he''s the father of her unborn baby.', '/82WqjaYmmOkZprX1ST7b00WJn6n.jpg', '2024-09-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17132, 'The Kid & I', 64972, NULL, '/5atneVsCkiSLEtkFZPkqjEEGAVC.jpg', 'The Kid & I', 'Aaron Roman is a teenager with cerebral palsy who dreams of starring in a big-time action movie. When his father grants Aaron his wish for his eighteenth birthday, he experiences the reality a bit hard to manage.', '/nr5k1hesGiVEyjlAldEGbXyL0Ba.jpg', '2005-12-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17133, 'A Home for the Holidays', 953981, NULL, '/1kgNHwZtt3TekjeG4o3UhJm8sXx.jpg', 'A Home for the Holidays', 'A local hardware store owner who purchases a run-down house in a small Colorado town, only for the heir of the original owner to show up with his 10-year-old son to reclaim it.', '/1K0fJWR8gK6Nr4KeeH5ztCRHKRl.jpg', '2023-11-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17134, 'Marshall''s Miracle', 348898, NULL, '/phwfJWLQnsDAkkeDMP6ncFBRQQT.jpg', 'Marshall''s Miracle', 'A 13-year-old boy becomes the target of bullies at his new school and is feeling hopeless, until he finds Marshall being caged up by a dog-hoarder in deplorable conditions. Finn knows he must rescue Marshall, but he has been abused by the other dogs and needs to see the vet right away. The bond of friendship is immediate.', '/dXOWIURPHNtRogxmv44oTE9zVa8.jpg', '2015-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17135, 'Blast', 243856, NULL, '/7TNqLr09aHfBxr67Dm7hLSQvLKq.jpg', 'Blast', 'A deadly team of terrorists mounts a precision attack on a swimming complex, which holds the world''s finest women''s swimming team hostage, and unknowingly traps a janitor inside.', '/tSIHQJWX6AfPkS84js1j0A2GoAp.jpg', '1997-03-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17136, 'The Grand', 15378, NULL, '/wl9oqSfAcufBsrKSUMwsEZNCVUl.jpg', 'The Grand', 'The Grand is in the tradition of improvisational comedies like Best In Show and This Is Spinal Tap. The story is set in the world of professional poker and follows six players who reach the final table of the world’s second most famous high stakes tournament, the Grand Championship of Poker.', '/3H4QTgFxt1lJps8U2tKfSTbsMl7.jpg', '2007-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
