INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17138, 'You Belong to Me', 278670, NULL, '/evw3ZwVSAgwlb2r9FIm4tRThzlo.jpg', 'You Belong to Me', 'After a messy divorce, Alex Wilson isn''t interested in the advances of her colleague, Michael. But when Michael''s interest takes a morbid turn and someone ends up dead, Alex becomes trapped in a supernatural struggle to save her son from a scorned (and deceased) suitor.', '/giAVt2AkWZ2JHabqfSUMhQK7Myo.jpg', '2008-12-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17139, 'A Novel Romance', 141274, NULL, '/oNBBBybzHR3ZtBPMu0l3JGGVr3S.jpg', 'A Novel Romance', 'Nate Shepherd, late 40''s, and Jenny Sparks, early 30''s, meet in a fancy New York eatery. Complete strangers who have had a rotten day, waiting for their better halves, they reveal to one another that they are going to meet new people tonight. They quickly realize they are waiting for each other. When Nate loses his girlfriend (after getting fired from his cushy job at an ad agency) and Jenny loses her boyfriend to a drug overdose, Nate''s girlfriend suggests that they should move in together as friends to split the rent and ease each others pain. As their friendship grows into something more, their relationship becomes a loving but complicated experience.', '/kavYtS6y6PGPPtZ6ZVdxR3URLrx.jpg', '2011-11-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17140, 'Gibby', 411545, NULL, '/wSNFMC7aBXE7X4DaM78wh1YKKBt.jpg', 'Gibby', 'A young teenage girl, Katie, can not snap out of her depression after losing her mother. Katie has lost interest in school, her friends, and gymnastics. All that changes in the summer when she is asked to monkeysit Gibby, her science teacher''s Capuchin monkey. Taking care of the monkey changes her life in a big way. Gibby''s happy-go-lucky personality renews Katie''s zest for life. Gibby helps her with gymnastics, renewing friendships (including finding a potential boyfriend) and overcoming her nemesis, a mean girl who is out to beat Katie at everything.', '/sE18ZQ2mciDp8lEqcYE5XI1eNV5.jpg', '2016-08-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
