INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17143, 'Swing Away', 477906, NULL, '/2944ysMF8TVQXY2xjfBqHdcQGNz.jpg', 'Swing Away', 'Following a meltdown that leads to a suspension, professional golfer Zoe Papadopoulos travels to her grandparents'' village in Greece to escape the harsh spotlight of the international sports world. Between baking bread and eating baklava, she meets and mentors a ten-year-old girl who is determined - against all odds - to become the next golf sensation. Along the way, Zoe rediscovers her Greek heritage, her love of the game, and the hidden strength within herself as she inspires the townspeople in an epic showdown against a greedy American developer.', '/armSkPfOpBRgp1joorUm6Pc5TbB.jpg', '2017-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17144, 'KDOC First Night 2013', 517847, NULL, NULL, 'KDOC First Night 2013', 'First Night 2013 with Jamie Kennedy is a New Year''s Eve television special that was hosted by comedian and television producer Jamie Kennedy. Broadcast live on December 31, 2012 from outside Grauman''s Chinese Theatre in Hollywood, California, the special included comedy sketches, interviews with celebrities and others in attendance, and live musical performances by Macy Gray and Bone Thugs-n-Harmony. The special was aired locally on the Orange County-based independent station KDOC-TV, and was also broadcast by the Sacramento MyNetworkTV affiliate KQCA.  Clips from this special became a popular viral video due to the many technical gaffes and accidental profanity that occurred during the live broadcast.', '/Cg10cnYZKOoG9ZYkuI6gGMGiLe.jpg', '2012-12-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17145, 'Night of the Demons', 27646, NULL, '/ol2FlTsW52tBqIGLBlFH3R0O1sg.jpg', 'Night of the Demons', 'Angela is throwing a decadent Halloween party at New Orleans'' infamous Broussard Mansion. But after the police break up the festivities, Maddie and a few friends stay behind. Trapped inside the locked mansion gates, the remaining guests uncover a horrifying secret and soon fall victim to seven vicious, blood-thirsty demons.', '/zm6pIvRM91rtJgQb3BlUczLr4qd.jpg', '2009-08-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
