INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17147, 'Skin: A History of Nudity in the Movies', 722926, NULL, '/ddJcIY7jO6qipzvrlBzLXR2APcA.jpg', 'Skin: A History of Nudity in the Movies', 'The definitive documentary on the history of nudity in feature films from the early silent days to the present, studying the changes in morality that led to the use of nudity in films while emphasizing the political, sociological and artistic changes that shaped that history. Skin will also study the gender inequality in presenting nude images in motion pictures and will follow the revolution that has created nude gender equality in feature films today.', '/zjQNcvUianPh2qx98hYttIVaeYa.jpg', '2020-08-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17148, 'Blade Squad', 343992, NULL, '/jaTJSeDQ8n0wGt1M2UhzaP2HAYP.jpg', 'Blade Squad', 'This futuristic action-thriller is set in a world in which police officers wear heavy body armor and get around on especially designed in-line skates. The story centers on the cop''s attempts to take down a murderous crime lord.', '/5x5qJVzJjsdv7qlp0khvBOulxrz.jpg', '1998-08-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
