INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17180, 'Cristian Castro: En Primera Fila', 225260, NULL, NULL, 'Cristian Castro En Primera Fila Dia 1', 'En Primera Fila Day 1 The successful formula of Sony Music continues its legacy with Cristian Castro. The series "Primera Fila", this idea of ​​recording style and already tested Unplugged artists like Thalia, Franco de Vita and Miguel Mateos, returns with the successes of the Mexican and some new tracks. This production is published in two volumes, classified as "Day 1" and "Day 2", each on CD and DVD. It was recorded in November 2012 in Los Angeles, California, before hundreds of fans and a team of over 200 people. "En Primera Fila: Day 1" contains classics like "Vuelveme a Querer", "Azul", "No Podras" and "Lloran las Rosas" and duets with haash, Reik and Leonel Garcia. Also highlights the participation of his mother, Veronica Castro, who of course could not miss an event of such magnitude.', NULL, '2013-04-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:05', 0);
