INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17218, 'Shake It Up: Made in Japan', 1444720, NULL, '/yCdNd5CraRGbbPhzBBEnfBAdUKZ.jpg', 'Shake It Up: Made in Japan', 'After facing off against crews from across the country in an epic dance battle, Rocky and CeCe win a once-in-a-lifetime trip to Japan to star in a new interactive dance video game. While there, Rocky plans to explore Japan and soak in the culture, but CeCe is convinced that they need to seize the chance to live their dreams and take their shot at becoming real global superstars.', '/swmCoSFDSn99Y7Wd9ifJcNZIyOc.jpg', '2012-08-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
