INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17220, 'Team Darryl', 505945, NULL, '/wL56346BF1eMElIGtqWLiILcfbU.jpg', 'Team Darryl', 'Fresh off being unseated as the ruler of Sakaar, the Grandmaster makes his way to Earth to start a new life. It''s been over a year since Thor left Australia and Darryl has been struggling to pay his rent. Now Darryl needs a new roommate to help make the monthly payments. Unfortunately for Darryl, the Grandmaster was the only one who answered Darryl''s "Roommate Needed" ad and with no viable options, the Grandmaster moves in.', '/edroTAeTEM9ILyAnumA0ALxRSne.jpg', '2018-02-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17221, 'Ca$h', 27004, NULL, '/td9f8E6W8Z2HnmmU69tT7ZHwK5F.jpg', 'Ca$h', 'A stroke of good luck turns lethal for Sam Phelan and his wife Leslie when they are faced with a life-changing decision that brings strange and sinister Pyke Kubic to their doorstep. As Pyke leads Sam and Leslie on a tumultuous adventure through the streets of Chicago, each are pulled deeper and deeper into a desperate spiral of deception and violence – all in the name of money.', '/e5B7nG6xREL6lNnS34ZoAvXbB9l.jpg', '2010-03-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
