INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17223, 'Ollie Klublershturf vs. the Nazis', 45920, NULL, '/tsy2hFiffYUXNOE5tGZK4skW7fo.jpg', 'Ollie Klublershturf vs. the Nazis', 'An off-the-wall comedy set around the dinner table. What at first glance seems like an awkward ''meet the parents'' situation for Dade Klublershturf quickly turns into a game of cat and mouse between Nazis, his boy genius younger brother, Ollie, and a time machine (disguised as an Atari joy stick) the Nazis are trying to capture from him.', '/rwddRZOmykkxknyY5sVtv77sz8x.jpg', '2010-09-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
