INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17226, 'A Brothers'' Journey: Thor & Loki', 580798, NULL, NULL, 'A Brothers'' Journey: Thor & Loki', 'This Marvel Cinematic Universe documentary delves into the development, casting, character arcs and performances of Hemsworth''s Thor and Hiddleston''s Loki. Part 1 begins by focusing on the original Thor (2011) and Joss Whedon''s Avengers, but soon ropes in Thor: The Dark World. Part 2 offers a more sequel-specific overview of the Asgardian brothers that features plenty of interview segments with key members of the cast and crew.', '/pZPk9wvO8HGH7TNJxkyT6BUMy1l.jpg', '2014-02-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17227, 'Kath & Kim: Our Effluent Life', 1049624, NULL, '/celbtOROMAt3ndBgD8ENWBGUGVW.jpg', 'Kath & Kim: Our Effluent Life', 'Featuring freshly minted scenes with the whole gang as well as some never-before-seen moments and too many bloopers and blunders to count on a washing glove-covered hand.', '/414LzsWWG5hiXMZbXRuhYT5kTO1.jpg', '2022-11-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
