INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17233, 'Shark Beach with Chris Hemsworth', 836691, NULL, '/gSpADcISuvwNnFBaVkg95OARMq1.jpg', 'Shark Beach with Chris Hemsworth', 'Chris Hemsworth has a real passion for sharks. The Hollywood star talks to experts to find out more about the apex predators of the oceans.', '/lnx1DMYg4hUU16rH9kOmMQECBeE.jpg', '2021-07-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17234, 'Subversion', 1473270, NULL, NULL, 'Subversion', 'A once-promising Naval commander is blackmailed by a cartel-like operation into piloting a dangerous submarine carrying illegal cargo across international waters. Thrust into a high-stakes game of cat and mouse, the man must outmaneuver blockades and navigate perilous threats both in and outside of the submarine.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17235, 'Chris Hemsworth: A Road Trip to Remember', 1563925, NULL, '/t2NdxB5kIscjsmK4ZKTWBf7XpY4.jpg', 'Chris Hemsworth: A Road Trip to Remember', 'In his most personal documentary yet, Chris Hemsworth turns the camera on his own family after his dad’s recent Alzheimer’s diagnosis. They embark on a road trip into their past, exploring the science of social connection and how it can support memory function. They revisit meaningful places and faces, capturing it all as a home movie, and reviving treasured recollections.', '/uRvBvxOmqaCMeZNJGducuh2WsgE.jpg', '2025-11-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
