INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17237, 'Tourism Australia | Dundee: The Son of a Legend Returns Home', 1317475, NULL, '/eKR7CSvdIm1H62OWNhanFt8eSDm.jpg', 'Tourism Australia | Dundee: The Son of a Legend Returns Home', 'Crocodile Dundee is back. Well, actually, he''s missing in the Outback. And the only person who might be able to find him is the loudmouthed American son no-one knew he had. Introducing Danny McBride as Brian Dundee. This son of a legend is forced to channel his Aussie roots as he embarks on the ultimate adventure in the land down under. It''s time to live up to the family name.', '/tkQuvGTFV3Xp1O31HtSMkf1yGy6.jpg', '2018-02-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17238, 'Forces of Nature', 1641, NULL, '/lZYsPT5WzDMgHe4tZzO9GHVN9ei.jpg', 'Forces of Nature', 'Ben Holmes, a professional book-jacket blurbologist, is trying to get to Savannah for his wedding. He just barely catches the last plane, but a seagull flies into the engine as the plane is taking off. All later flights are cancelled because of an approaching hurricane, so he is forced to hitch a ride in a Geo Metro with an attractive but eccentric woman named Sara.', '/etmjiee84g6G9WALmLkJ1DhenAu.jpg', '1999-03-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17239, '28 Days', 10468, NULL, '/gXahs8xwiF2VMZJK7JgtSZSgTDt.jpg', '28 Days', 'After getting into a car accident while drunk on the day of her sister''s wedding, Gwen Cummings is given a choice between prison or a rehab center. She chooses rehab, but is extremely resistant to taking part in any of the treatment programs they have to offer, refusing to admit that she has an alcohol addiction.', '/tlgz7Shx0UavR5pyITeJ2mUHKFI.jpg', '2000-04-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17240, 'All About Steve', 23706, NULL, '/7qdeWU6XNrMFuemM2TAHD6Rc6NS.jpg', 'All About Steve', 'After one short blind date, Mary Horowitz, a brilliant and eccentric crossword constructor, is convinced that Steve, a CCN cameraman, is her soul mate. Because his job takes him hither and yon, she crisscrosses the country following Steve, with the encouragement of a reporter, turning up at media events he''s at to convince him they are perfect for each other. Along the way, she befriends an assortment of misfits who accept her for who she is, leading her to reassess her reasons for this strange journey.', '/k7lmf0OeOpQLUoTRLG7e5JZ7H4B.jpg', '2009-08-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17241, 'Love Potion No. 9', 26255, NULL, '/dXGECXMTs0SEJGg4qwuisHbe2vc.jpg', 'Love Potion No. 9', 'Unlucky in love, chemist Paul Matthews visits gypsy Madame Rosa for help. Quickly realizing he is a hopeless nerd, she gifts him with Love Potion No. 8, which makes anyone who wears it irresistible to the opposite sex for four hours. Paul and animal psychologist coworker Diane Farrow decide to test it on themselves. The awkward pair suddenly find themselves alluring to anyone they approach, but soon realize they are most attracted to each other.', '/n0DYahGGueR96mhajPGGgZpFL4k.jpg', '1992-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17242, 'Hope Floats', 9715, NULL, '/9zgnuwIK6JAc6giVsscq9H82li1.jpg', 'Hope Floats', 'Birdee Pruitt has been humiliated on live television by her best friend, Connie, who''s been sleeping with Birdee''s husband, Bill. Birdee tries starting over with her daughter, Bernice, by returning to her small Texas hometown, but she''s faced with petty old acquaintances who are thrilled to see Birdee unhappy -- except for her friend Justin. As he helps Birdee get back on her feet, love begins to blossom.', '/6PRFM09xjGSWpXObW87CT5JELGJ.jpg', '1998-05-29', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17243, 'In Love and War', 26949, NULL, '/hTofqSo4o05UOlpU79WfBAoCM9U.jpg', 'In Love and War', 'After teenage ambulance driver Ernest Hemingway takes shrapnel in the leg during World War I, he falls in love with Agnes von Kurowsky, a beautiful older nurse at the hospital where he''s sent to recover. Their affair slowly blossoms, until Hemingway boldly asks Agnes to be his wife and journey to America with him.', '/rjRu7HOjXNVflUrR40eMKhvmQps.jpg', '1996-12-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17244, 'Divine Secrets of the Ya-Ya Sisterhood', 9583, NULL, '/nTB7rsZ1JTCrolj91bRBFgi9G4x.jpg', 'Divine Secrets of the Ya-Ya Sisterhood', 'In a sleepy Louisiana parish, a group of lifelong friends stage a rather unorthodox intervention to help a young playwright unravel the truth about her complicated mother and let go of her painful past.', '/hI05FJ8wgPROHQgLtfJ4ZuH3l4b.jpg', '2002-06-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17245, 'Infamous', 9672, NULL, '/kA28hzGAais4Rlk0RG6PsQzTqU4.jpg', 'Infamous', 'While researching his book In Cold Blood, writer Truman Capote develops a close relationship with convicted murderers Dick Hickock and Perry Smith.', '/cIQUn20lUQpi70W0Z7ixezQJ7gj.jpg', '2006-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17246, 'The Thing Called Love', 27804, NULL, '/5U9tWqwaLREc6cnXPOVSVIDzYpl.jpg', 'The Thing Called Love', 'A group of newcomers to the country music business seek love and stardom.', '/xsxkXRFDYeGGMGkdvotCIhMJFPl.jpg', '1993-08-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17247, 'Wrestling Ernest Hemingway', 40509, NULL, '/mmJLL4PyHhTuiUdjKowHuni2aEb.jpg', 'Wrestling Ernest Hemingway', 'Frank, a retired Irish seaman, and Walter, a retired Cuban barber, are two lonely old men trapped in the emptiness of their own lives. When they meet in a park Frank is able to start a conversation after several attempts. They begin to spend time together and become friends. But because of their different characters they often quarrel with each other and finally seperate after Frank misbehaves to Walter''s friend Elaine.', '/aMWkpitaM33HgDv25RzeMy9ZNFQ.jpg', '1993-12-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17248, 'Fire on the Amazon', 28983, NULL, '/p19YGO5l7W4kVNpd0RXvS5MOaH7.jpg', 'Fire on the Amazon', 'When a well-known environmental researcher is murdered in the Amazon jungle, an arrogant photojournalist joins forces with a beautiful young activist to find out who is responsible. Along they way, they fall in love as they discover the men responsible for the killing would be more than willing to murder again if it will keep them quiet.', '/9OUU14KPIhRTEjAFcUi4MN52nHV.jpg', '1993-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17249, 'Gun Shy', 29076, NULL, '/4bAq4bkYgLrg2b36uDucxbFf8cl.jpg', 'Gun Shy', 'Legendary undercover DEA agent Charlie Mayough has suddenly lost his nerves of steel. On the verge of a career-induced mental breakdown, and in complete fear of trigger-happy Mafia leader Fulvio Nesstra, Charlie seeks psychiatric help and finds himself relying on the support of an unstable therapy group and nurse Judy just to get through his work.', '/iMCuGjQu5LsS6hyr5KmRDNqcomy.jpg', '2000-02-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17250, 'Hangmen', 47749, NULL, '/pS3cYrmSXiGPFQa5zfQxsJ0JqSN.jpg', 'Hangmen', 'Rob Greene has information about an undercover terror team inside the CIA led by Joe Connelly. To stay alive with the knowledge, he is advised to stay undercover by his supervisor Andrews. Connelly''s men try to kill Greene, but he can escape and warns his son Danny that he also may be in danger and that he should look for Dog Thompson.', '/gtSD18nFsPjOz2AnFVOoiUWHTf6.jpg', '1987-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17251, 'Two If by Sea', 19760, NULL, '/9YTwzhG4HcZICyWcwSGO3O9JBgw.jpg', 'Two If by Sea', 'Frank O''Brien, a petty thief, and his 7-year-long girlfriend Roz want to put an end to their unsteady lifestyle and just do that last job, which involves stealing a valuable painting. Frank takes Roz to an island on the coast of New England, where he wants to sell the painting and also hopes that their sagging relationship will get a positive push back up. Not everything goes as planned.', '/xSfqAMYqrTtDeAjPtYo0S8nc5Zz.jpg', '1996-01-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17252, 'Who Do I Gotta Kill?', 54052, NULL, '/5Cr5s35gfjQvQl4ISDqeIFnyfBD.jpg', 'Who Do I Gotta Kill?', 'A struggling writer takes a job for his mobster uncle in order to obtain first-hand material for a book on conspiracy plots and the JFK assassination.  They often say that a good writer lives what he writes, but what happens when the life that the writer is living could likely get him killed?', '/eQw4tC4onERymDQ6kESTqI9DC7t.jpg', '1994-09-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
