INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17254, 'A Fool and His Money', 59864, NULL, NULL, 'A Fool and His Money', 'New York advertising executive Morris Codman seems to have it all - lots of talent and a beautiful girlfriend, Debbie. When he loses his job he decides to use his advertising expertise to create, package and market a shady product that will make him millions. Debbie tries to convince him that money isn''t everything and she loves him just the way he is. Morris'' bizarre antics in promoting his product surprisingly lead to a fortune, but can love survive his quest for the almighty dollar?', '/xclRdJ9x6VlfQxwsHoDXbS3EQLf.jpg', '1989-11-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
