INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17256, 'When the Party''s Over', 102408, NULL, '/73E34ld2wYZ1BmznSLnIHwX3mf0.jpg', 'When the Party''s Over', 'Three women and a gay man in their 20s share a house in Los Angeles;  try to find love and happiness - often at the expense of their well-being and friendships. Artist Amanda is trying to make it on the gallery scene, while aspiring actor Banks attempts to hit it big in Hollywood. Meanwhile, Frankie has an emotionally draining yet rewarding job as a social worker, but would be shattered to know that her roommate M.J. is sleeping with her boyfriend.', '/xQf4udmAXaKklmnj6EkbeIkKdtu.jpg', '1993-03-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17257, 'Lisa Picard Is Famous', 206412, NULL, NULL, 'Lisa Picard Is Famous', 'A documentarian decides to follow the career of New York actress Lisa Picard, believing she is on the brink of fame. Instead, he bears witness to Lisa''s continued, humorous, struggles as an actress, as well as the conflict that arises when Lisa''s best friend Tate hits it big with an off-Broadway one-man show.', '/cVC2chP5nJxAOs5FIBeZJ6KfDfm.jpg', '2000-05-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
