INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17260, 'The Prime Ministers: The Pioneers', 227962, NULL, NULL, 'The Prime Ministers: The Pioneers', 'Based on the best-selling book by Ambassador Yehuda Avner, The Prime Ministers: The Pioneers takes the audience inside the offices of Israel''s Prime Ministers through the eyes of an insider, Yehuda Avner, who served as a chief aide, English language note-taker and speechwriter to Levi Eshkol, Golda Meir, Yitzhak Rabin, Menachem Begin, and Shimon Peres. The first of two parts, The Prime Ministers: The Pioneers focuses on Ambassador Avner''s years working with Prime Ministers Levi Eshkol and Golda Meir and then US Ambassador Yitzhak Rabin and reveals new details about the Six-Day War, the development of Israel''s close strategic relationship with the United States, the fight against terrorism, the Yom Kippur War and its aftermath.', '/oiY4UJlPwVSAixNJD98CccskunK.jpg', '2013-10-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
