INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17273, 'Z for Zachariah', 193687, NULL, '/muAlT7ip6t7DhsVjOJiFuPQHNU1.jpg', 'Z for Zachariah', 'In the wake of a nuclear war, a young woman survives on her own, fearing she may actually be the proverbial last woman on earth, until she discovers the most astonishing sight of her life: another human being. A distraught scientist, he’s nearly been driven mad by radiation exposure and his desperate search for others. A fragile, imperative strand of trust connects them. But when a stranger enters the valley, their precarious bond begins to unravel.', '/c7rdpZlviWAcOOx5bnzfqPPPNvq.jpg', '2015-08-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
