INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17276, 'Hollywood''s Hard Hitters: Women in Action', 1266284, NULL, NULL, 'Hollywood''s Hard Hitters: Women in Action', 'This all female feature film documentary that explores the world of Hollywood stunt performers and journey for equality and recognition from The Academy. This part 2 sequel picks up where part one, 2nd Unit: invisible action stars leaves off. Join us on this journey where the Hollywood stars put their stunt performers first, show their support like never seen before. Director Jason Strickland says "Without our stunt performers, action films could never be made".. It''s about time they get recognized at the Academy Awards!', '/yOdeX38fj7vHmiHnma5XrJYCywu.jpg', '2023-02-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:07', 0);
