INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17321, 'W.C. Fields and Me', 49914, NULL, NULL, 'W.C. Fields and Me', 'In 1920s New York City, W. C. Fields is a successful headlining entertainer, but when his girlfriend leaves him and his broker loses his money, Fields begins anew in California. Working at a wax museum, Fields eventually lands a film role that ascends him to stardom. Back in the limelight and palling around with John Barrymore and the like, Fields meets an aspiring actress Carlotta Monti at a party, with whom he forms a rocky relationship.', '/5pVWpLDdjC4T8Ae2VKbDCCVO0vh.jpg', '1976-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17322, 'Water', 19127, NULL, '/fz3JoREbHzUdwjlfiUq0BU9ibpM.jpg', 'Water', 'The British governor of a tiny island nation in the Caribbean Commonwealth finds his idyllic existence thrown into chaos when an American drilling company finds a huge source of natural mineral water there.', '/iBwZRLoNjvzplQ5bForJ2dEC0QH.jpg', '1985-01-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17323, 'The Californians', 73511, NULL, '/i8dyHahIY3jMaVkgItVAObaYFV7.jpg', 'The Californians', 'When real estate mogul Gavin Ransom announces his plan to cover California''s northern coast with scores of mini-mansions, his environmentalist sister, Olive, launches a protest to stop him. But there''s trouble ahead when Gavin begins falling for the pretty folk singer who''s helping Olive''s cause.', '/94w3CM4V8AG9OEgtPQSwDfFd6Vw.jpg', '2005-10-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17324, 'Steambath', 90970, NULL, '/tJ1DYULfUBFd5LpZnXfpG4XJztc.jpg', 'Steambath', 'Tandy, Merideth and assorted others unexpectedly wake up in a steambath with no easy exit. After spending some time there, it becomes clear that the steambath is a sort of Afterlife, where indifferent souls come to tell their stories to God who happens to be the attendant picking up the towels.', '/9mFGZCpvRx6pvqIU7QriPD5rWZP.jpg', '1973-05-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17325, 'Sweet Bird of Youth', 90994, NULL, '/k7xIyu0DuAGmtQ4LJbBLERhzLZW.jpg', 'Sweet Bird of Youth', 'Tennessee William’s masterful melodrama about an aging movie star who, appalled by her own image on the screen, flees from her movie premiere and goes into seclusion, becoming entangled with a much younger hotel masseur and resident gigolo.', '/uNx3J2DcM3V0MuHEUy0bETUXXsD.jpg', '1989-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17326, 'Bright Angel', 95590, NULL, '/cfG6wV1ckM4RJkh29t5vzuo7jXN.jpg', 'Bright Angel', 'In Montana, naive teenager George longs to escape from his broken home before his dysfunctional parents push him over the edge. When George meets pretty drifter Lucy, she easily convinces him and his friend Claude to join her on a road trip to Montana in hopes of breaking her brother out of jail.', '/354LhIvDd2rCG0EBUZF0YNVaWov.jpg', '1990-11-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
