INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17330, 'My Girlfriend''s Boyfriend', 195000, NULL, '/n0CsCgI0XQRafWCEawQSYxQmQin.jpg', 'My Girlfriend''s Boyfriend', 'Jake can only think of one thing after being dragged to the wedding of his girlfriend''s best friend. How can he get out of it? On the advice of Wes, the out-and-proud best man, he pretends to be gay and gets caught kissing Wes. Little does Jake realize he''s about to get caught up in a circle of jealousy and lies. Cliff, the groom, is getting married to help solidify his hunky, soap opera star image... and to stay closeted. Yep, he s gay. And his longtime boyfriend is none other than his best man. When Cliff and Wes get pictures taken of them in a compromising position (several, in fact) it looks as though his cover might be blown. Thrown into the mix is the bride''s sex crazy mother and the nosy reporter-turned-wedding photographer with a sock puppet (pop icon Deborah Gibson). What ensues is a fun, quirky and modern comedy of errors that is sure to tickle your funny bone.', '/kqFEsXHz3L8HW3fU3lVLpPJSyzf.jpg', '1999-02-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17331, 'Mountain of Diamonds', 201931, NULL, '/kSrSkdPdCT76npGxJIiFGQAg33g.jpg', 'La montagna dei diamanti', 'France, 1915. Young and radiantly beautiful Centaine de Thiry is the happiest woman in the world: in a few more hours she will be married to pilot Michael Courteney, the love of her life. But fate has it otherwise: Michael is shot down in a reconnaissance plane shortly before his wedding. Life has lost its meaning for Centaine. When the young woman realizes soon afterwards that she is expecting a baby, her zest for live is revived. She decides to give birth to the child in South Africa, the home country of her deceased fiancé.', '/ujpT5y1K7jXYLnYmW6e1QAAZlPi.jpg', '1991-10-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17332, 'The Magician of Lublin', 87121, NULL, NULL, 'The Magician of Lublin', 'Yasha is a Jewish stage magician who tours through eastern Europe while destroying his career through personal problems. He has one more chance at theatrical success, but he needs to do a brand new trick in a Warsaw theater.', '/zWKPlZZ8llxKzLh95QqI5AevXR7.jpg', '1979-11-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17333, 'Marian Rose White', 358200, NULL, NULL, 'Marian Rose White', 'Marian Rose White is placed in a State Home for the feeble-minded by her uncaring mother when her father dies. She is a young teenager and there is nothing wrong with her except for some clumsiness, mostly caused by poor vision. State law (in 1934) requires sterilization of all inmates. Sympathetic nurse, Bonnie McNeil, befriends Marian and protests her treatment.', '/cgCNK0LbrSgJURbfhcRwfjbCW6y.jpg', '1982-01-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17334, 'Ziegfeld: The Man and His Women', 359363, NULL, NULL, 'Ziegfeld: The Man and His Women', 'The life and times of the flamboyant showman who built his legendary Follies around beautiful women -- as told by the women in his life.', '/lstM8GtBUyjPfP6jyWPAVIzGGYj.jpg', '1978-05-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17335, 'Mask of Murder', 104621, NULL, '/oegT02SSvE4vhvP9Mqi9vo8Rzcm.jpg', 'Mask of Murder', 'In a Canadian village are women being killed by a psychopath. Chief Rich and Inspector McLane have no clue until McLane shoots a suspicious man. Now the killing seems to have ended, but the killer picks yet another victim...', '/uBudILyexCCQuPRV0Fw0JFKmmQR.jpg', '1985-10-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
