INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17337, 'When Your Lover Leaves', 368353, NULL, NULL, 'When Your Lover Leaves', 'Comedy about a woman dumped by her married boyfriend who gets involved in a short-lived relationship with a neighbor. When that also doesn''t work out, she decides she must first do something to please herself.', '/r7z0K91nBSpQ7gr0lcdCznwFsN5.jpg', '1983-10-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17338, 'A Place Called Truth', 407349, NULL, '/9qweJsWvk6kU9hIanWN8PMM8Ck1.jpg', 'A Place Called Truth', 'Love, pride and jealousy are aroused when a ranch owner''s daughter, called Lizzie, has an affair with a cowboy. Meanwhile a mysterious woman seduces the various lovers of Lizzie, who has fled to New Orleans to escape her arranged marriage.', '/rzycymXhY4Eqd0ayMGLpQDb0hcW.jpg', '1998-07-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17339, 'The Making of ''Superman: The Movie''', 457825, NULL, NULL, 'The Making of ''Superman: The Movie''', 'Ernie Anderson narrates this look at the making of Richard Donner''s blockbuster 1978 film. Behind-the-scenes footage, as well as scenes from the film, reveal just how audiences were able to "believe a man can fly." This program features interviews with key cast and crew.', '/64dBPF3v7KcxfG3V1zCIHxJcNqS.jpg', '1982-01-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17340, 'Malibu', 411774, NULL, '/e3sRdMYVpPURupFBoM1xfm8LlBb.jpg', 'Malibu', 'A young couple from Milwaukee moves into the fabled, high-society Malibu beach community and becomes involved with the lives of the various people living in the community.', '/klFo8jJqX9LD2cX3si4AOYom8au.jpg', '1983-01-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17341, 'Superman II: The Richard Donner Cut', 624479, NULL, '/rRo1EzVd0E8GAOAeCulPpekKwjP.jpg', 'Superman II: The Richard Donner Cut', 'Superman agrees to sacrifice his powers to start a relationship with Lois Lane, unaware that three Kryptonian criminals he inadvertently released are conquering Earth.', '/dkLplIwss7Jleh82NawyGyFNMgJ.jpg', '2006-11-02', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17342, 'The Amateurs', 17035, NULL, '/A7wROeDATxR28m6oyCYMh4IUKV.jpg', 'The Amateurs', 'Sex sells in America and these guys know it. The Amateurs follows a small town band of loveable losers who hit upon an idea that can make their dreams and fantasies come true. Thinking they''ve found the road to riches and fame they decide to make the world''s most innocent adult film. Everyman''s fantasy turns into a hilarious misadventure when they find they''re in way over their heads.', '/kj4ZZpyP95ltT4ZF2c6aiyEH5N9.jpg', '2006-04-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17343, 'The Couple Takes a Wife', 252964, NULL, '/kjrNMuqnHoe7LDqi0AcInmUUguh.jpg', 'The Couple Takes a Wife', 'Complications ensue when an overworked couple decides to hire a "wife" — someone who can run the household for them with complete autonomy — but she''s a little too attractive for comfort.', '/aFhIZN0PZs2T4kyKBIPYBLfUZFy.jpg', '1972-12-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17344, 'Brown''s Requiem', 64166, NULL, NULL, 'Brown''s Requiem', 'Fritz Brown is an ex-LAPD, recovering alcoholic who now splits his time repossessing cars for a used car lot and staffing his one-man private detective agency. When a filthy caddie named Freddy "Fat Dog" Baker wanders into Fritz''s office one day, flashing a wad of cash, Fritz is hired to follow Fat Dog''s kid sister Jane, who is holed up with a Beverly Hills sugar daddy named Sol Kupferman. Kupferman is a 70 year-old bag man for the mob, and Fat Dog claims that "Solly K" is up to something evil that may harm Jane. The trail leads Fritz to an encounter with his dark past in the person of Haywood Cathcart, current head of LAPD internal affairs and the person who kicked Fritz off the police force.', '/hhshoH9MZM9cB9lfArRtZ0mf9Gv.jpg', '1998-11-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17345, 'Valerie', 743679, NULL, '/grdfcBwIx0AdYDTFGJJ7y7FsBfk.jpg', 'Valerie', 'A documentary of the incredible life of actress Valerie Perrine and her battle with Parkinson''s.', '/40EC3bR4UTJfm58438TApmPVh8i.jpg', '2019-08-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17346, 'The Muppets Go Hollywood', 114671, NULL, '/hiw4elYT1Iu1zZMAqiifutSnlkO.jpg', 'The Muppets Go Hollywood', 'Kermit the Frog throws a glamorous party at the Cocoanut Grove nightclub to celebrate the premiere of the Muppets'' first feature film, The Muppet Movie. Hosts Dick van Dyke and Rita Moreno interview the wide array of celebrities and Muppets who attend the event. Gary Owens serves as off-camera announcer, and appears on-screen to introduce Miss Piggy.', '/ytdirqn3SxUdnIePMfdKUfTONNl.jpg', '1979-05-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17347, 'Curtain Call', 48689, NULL, '/k21lrYDmrcROWUI4PVzPtKK1x1S.jpg', 'Curtain Call', 'A bachelor afraid of marriage angers his long-time girlfriend by buying a splendid townhouse just for himself, only to find it haunted by the ghosts of a famous theatrical couple, who teach him about love and commitment.', '/bZmI4sd3KHxjujVAjzSu9huWHCJ.jpg', '1998-12-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17348, 'The Fabulous Allan Carr', 456599, NULL, '/zKpGdP8DBtWkKAOScKmsmD4o1gB.jpg', 'The Fabulous Allan Carr', 'Armed with a limitless Rolodex and a Benedict Canyon enclave with its own disco, Allan Carr threw the Hollywood parties that defined the 1970s. A producer, manager, and marketing genius, Carr built his bombastic reputation amid a series of successes including the mega-hit musical film "Grease," until it all came crashing down after he produced the 1989 Academy Awards, a notorious debacle.', '/bCRiYgxxt82r7Rpo1gNlkoJRuNB.jpg', '2017-05-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17349, 'Reflections in a Dark Sky', 847421, NULL, NULL, 'Riflessi in un cielo scuro', 'In a sordid account of mutual charity, an alcoholic doctor tries to make a captive heroin addict kick her self-destructive behavior — and vice-versa.', '/2aev1Bo0zUAFQt56KYtlA5xJ76M.jpg', '1991-12-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17350, 'Re-Directing Eddie', 733090, NULL, NULL, 'Re-Directing Eddie', 'Making an indie film is murder under the best of circumstances, but first-time director Eddie Vassick''s scenario is chaotic. Halfway through filming his main investor croaks. He has to tangle with the investor''s widow who not only demands a plum role in the film when she''s never acted a day in her life, but sells the film''s rights to none other than Eddie''s domineering older brother Warren. Warren is a B-movie mogul, king of commercial flicks, who has cast a shadow over Eddie his entire life. Eddie is forced to bend to Warren''s will, and Warren immediately issues an impossible ultimatum, true to form. Eddie must re-shoot the entire film in costly 35mm format in four weeks time, or control of the entire project will revert to Warren. Meanwhile, Warren, who has always been secretly jealous of his little brother''s inherent talents, has gotten his hands on a copy of Eddie''s script and views this project as his one shot to catapult himself from the "B" leagues into the majors.', '/pd2ahTXm9sk8ODMgOzsoN4ELPiw.jpg', '2008-10-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
