INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17353, 'Magic Night', 1422113, NULL, NULL, 'Magic Night', 'This one hour TV special promoting the release of Can''t Stop the Music featured the film''s stars (The Village People, Valerie Perrine, Steve Guttenberg and Bruce Jenner) with guest appearances by Cher, Hugh Hefner and others.', '/gX1GCNII3ChfZAj6uOxHoiFKnQc.jpg', '1980-05-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17354, 'Breaking and Entering', 1253, NULL, '/qpeCN9X4QHxPh8yWF5gRp1wxfct.jpg', 'Breaking and Entering', 'Set in a blighted, inner-city neighbourhood of London, Breaking and Entering examines an affair which unfolds between a successful British landscape architect and Amira, a Bosnian woman – the mother of a troubled teen son – who was widowed by the war in Bosnia and Herzegovina.', '/4VZWsOQGbxfPuqMBcLaQLxNvLzR.jpg', '2006-12-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
