INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17357, 'All the King''s Men', 1717, NULL, '/xp5cZAZC9jcdaIr10Md47CgPHbF.jpg', 'All the King''s Men', 'The story of an idealist''s rise to power in the world of Louisiana politics and the corruption that leads to his ultimate downfall. Based on the 1946 Pulitzer Prize-winning novel written by Robert Penn Warren, loosely based on the story of real-life politician Huey Long.', '/r3Yu6JdufxUSqy6PJgT887UpSMt.jpg', '2006-09-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17358, 'Sleuth', 4520, NULL, '/7wazgiTbygqijaduEiapT43YxTJ.jpg', 'Sleuth', 'Locked in a high-tech English manor, bound in a deadly duel of wits, Andrew Wyke and Milo Tindle come together as English gentlemen to discuss the matter of Wyke''s wife: the woman both are sleeping with.', '/y70r13kOHp7pcYToG25uwMYm562.jpg', '2007-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17359, 'Midnight in the Garden of Good and Evil', 8197, NULL, '/zDtIIaPdcRvZnvpD1qnI8v4nHOR.jpg', 'Midnight in the Garden of Good and Evil', 'A visiting city reporter''s assignment suddenly revolves around the murder trial of a local millionaire, whom he befriends.', '/cXS5o6RIp8m1epBm5I7cX49bfFd.jpg', '1997-11-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17360, 'Firebrand', 848439, NULL, '/fGJ3XKgnmA8xvl1VUjYAUWNhTRv.jpg', 'Firebrand', 'Katherine Parr, the sixth wife of King Henry VIII, is named regent while the tyrant battles abroad. When the king returns, increasingly ill and paranoid, Katherine finds herself fighting for her own survival.', '/kXAc1LaxL64udWr9SOAHQwOBEG0.jpg', '2024-03-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17361, 'Rage', 26738, NULL, '/sJ1wBKCkQX9bRk6DnZxOVn51NwT.jpg', 'Rage', 'A schoolboy uses his cellphone camera to shoot intimate interviews with people working at a New York fashion house and secretly posts them on the internet. Result: a bitterly funny expose of an industry in crisis, during a week in which an accident on the runway becomes a murder investigation, and denial leads to devastation.', '/atqccoctqnvjj9yepJMxytbRvqf.jpg', '2009-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17362, 'Shopping', 45549, NULL, '/zW3guydPMAnqEcia0PJGZnDuWJm.jpg', 'Shopping', 'A dark, hip, urban story of a barren and anonymous city where the underclass'' sport of choice is ram-raiding. An exciting game in which stolen cars are driven through shop windows to aid large-scale looting before the police arrive. For Tommy, it''s a business, but for Billy and Jo, it''s a labour of love. As the competition between Tommy and Billy grows more fierce, the stakes become higher and the "shopping" trips increasingly risky.', '/jiIQO8UWyvVkdJEujb6VWKUBzaz.jpg', '1994-12-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17363, 'I Love You, I Love You Not', 45565, NULL, '/rJDEAyYkKKSIrGETkbRUTNqvV0L.jpg', 'I Love You, I Love You Not', 'A school student and her European-born grandmother share sad stories of their lives.', '/aesZ94JtQFiVdvNFNbO5CSeWms2.jpg', '1996-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17364, 'Love, Honour and Obey', 18002, NULL, '/vDeOTyvAnOSjeqmjm9X5Z0tMlP5.jpg', 'Love, Honour and Obey', 'Jonny dreams of leaving his dead-end job as a courier. Through his childhood best friend, nephew of the notorious crime lord Ray Kreed, he wins his way into the toughest gang in North London. Hungry for action, Jonny sparks a feud between Ray''s gang and a rival firm in South London headed by drug kingpin Sean and his lieutenant Matthew.', '/xVJ3ZLCHfWUMkV1sIhnJXDGbJUW.jpg', '2000-04-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17365, 'Music from Another Room', 39424, NULL, '/tDFCGTkLT40Q6ySAzXPxjCwpgyX.jpg', 'Music from Another Room', 'Music From Another Room is a romantic comedy that follows the exploits of Danny, a young man who grew up believing he was destined to marry the girl he helped deliver as a five year old boy when his neighbor went into emergency labor. Twenty-five years later, Danny returns to his hometown and finds the irresistible Anna Swann but she finds it easy to resist him since she is already engaged to dreamboat Eric, a very practical match. In pursuit of Anna, Danny finds himself entangled with each of the eccentric Swanns including blind, sheltered Nina, cynical sister Karen, big brother Bill and dramatic mother Grace as he fights to prove that fate should never be messed with and passion should never be practical.', '/zamhRB4bKVeRUW568lVSFeEbqVg.jpg', '1998-04-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17366, 'Final Cut', 47072, NULL, '/xlrwGUVkIWwJqoLGkgeLV5tUsbm.jpg', 'Final Cut', 'A group of friends gather for a wake, and are shown a video shot by Jude and starring them before he dies. Things go rapidly downhill.', '/ckeyOoyGjcnsEoCXdMPOFW5Rzd7.jpg', '1998-11-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17367, 'Bent', 19601, NULL, '/zrc9EoqrKOGy3QBDr6keuqH32wd.jpg', 'Bent', 'Max is a handsome young man who, after a fateful tryst with a German soldier, is forced to run for his life. Eventually Max is placed in a concentration camp where he pretends to be Jewish because in the eyes of the Nazis, gays are the lowest form of human being. But it takes a relationship with an openly gay prisoner to teach Max that without the love of another, life is not worth living.', '/mTRIVPmRK01rgLlE6XJPGbbRdXb.jpg', '1997-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17368, 'The Day After Peace', 57352, NULL, NULL, 'The Day After Peace', 'Against all the odds an individual manages to create an annual global ''Peace Day''; but can he inspire an actual ceasefire and silence the cynics by proving the day can actually save lives?', NULL, '2009-04-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17369, 'Presence of Mind', 79080, NULL, '/ptxrvJXr5Yoc2gcDMYF2MQ60Stc.jpg', 'El celo', 'A governess, caring for two children at a remote estate, becomes convinced that the grounds are haunted and the children are under an evil influence.', '/v0DDI1Fjk8jFmWMjLfaNRbmCQky.jpg', '2000-09-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17370, '360', 89455, NULL, '/npIWAwSta6hOpU9BOJzvCD1qwf4.jpg', '360', 'A disparate group of characters unknowingly bond by the sexual choices they make. Consumed by loneliness, a British businessman ponders a rendezvous with a prostitute. The businessman''s wife prepares to call it quits with her younger lover. A Brazilian student breaks up with her boyfriend in London. A recovering alcoholic travels to Phoenix in search of his missing daughter. A paroled sex offender struggles to stay composed when propositioned in a Denver airport. A widower''s religious devotion is put to a difficult test.', '/xzI3p0c2oFRMx5fYQg2BoQzYCE0.jpg', '2012-07-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17371, 'Dom Hemingway', 192134, NULL, '/kBenhxySFb2NhRJjCVLRCiTqYPr.jpg', 'Dom Hemingway', 'After spending 12 years in prison for keeping his mouth shut, notorious safe-cracker Dom Hemingway is back on the streets of London looking to collect what he''s owed.', '/hvrUPdZUDlSn1S4KCW5IdIMGS5D.jpg', '2013-11-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17372, 'Black Sea', 246080, NULL, '/goccXjwwNyDhrwQiP77T71pfFb7.jpg', 'Black Sea', 'A rogue submarine captain pulls together a misfit crew to go after a sunken treasure rumored to be lost in the depths of the Black Sea. As greed and desperation take control on-board their claustrophobic vessel, the increasing uncertainty of the mission causes the men to turn on each other to fight for their own survival.', '/oqOXFP35a2DjxjdpmEaOTIfI5TS.jpg', '2014-12-05', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17373, 'Harold Pinter:  A Celebration', 442063, NULL, NULL, 'Harold Pinter:  A Celebration', 'In June 2009, a group Britain''s leading actors gathered for one night only to perform a celebration of the work of Harold Pinter at the National Theatre, directed by Ian Rickson. The team who made the acclaimed  Harold Pinter documentaries for BBC''s Arena was there to record this unique performance.', '/b9f73ltBOI8iGU5u9hWmWbJQLbK.jpg', '2010-01-24', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17374, 'The Tailor of Gloucester', 1243739, NULL, NULL, 'The Tailor of Gloucester', 'An ill tailor is trying to finish a coat for a wealthy man. He is hindered by his cat and helped by some grateful mice.', '/kufmAGkzQYjlUgSxC930LUf35Pr.jpg', '1989-12-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17375, 'The Vote', 338984, NULL, '/dllVbdK0oFaRJmAETcptbEz6gqu.jpg', 'The Vote', 'On 7 May, churches, school halls, and back rooms of community centres will be turned into polling stations, staffed by council workers and volunteers. A church polling station is the backdrop for a real-time play for theatre and TV, called The Vote, staged at the exact moment in which the action is set - the last 90 minutes before polls close.', '/kLmBhgALdq1JUTNvmcWsXw4kjFt.jpg', '2015-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17376, 'Connection', 381933, NULL, NULL, 'Connection', 'A celebrity meets a person at the airport. All is fine until the person finds out that if they return home, they will be arrested.', '/2HGJTra9yTiVY27uwV4R5BIrZlV.jpg', '2013-09-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17377, 'The Roof', 410671, NULL, NULL, 'The Roof', 'A brief comedy about a visit from a legendary theatre maker and his legion of fans.', '/kA9X5gM4LId88OuK0MoCX3lvzZD.jpg', '2016-03-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17378, 'Vox Lux', 429202, NULL, '/qXzqEcHs9YcEgkjoNdWvxM2kIqZ.jpg', 'Vox Lux', 'In 1999, teenage sisters Celeste and Eleanor survive a seismic, violent tragedy. The sisters compose and perform a song about their experience, making something lovely and cathartic out of catastrophe — while also catapulting Celeste to stardom. By 2017, the now 31-year-old Celeste is mother to a teenage daughter of her own and struggling to navigate a career fraught with scandals when another act of terrifying violence demands her attention.', '/xmFOjB5bGvFqNzsX5TbIWzdvpGd.jpg', '2018-09-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17379, 'Muse of Fire', 232599, NULL, '/7YNEh7VI5NZu6lzavkS7HfeyLct.jpg', 'Muse of Fire', 'This unique feature documentary follows two actors, Giles Terera and Dan Poole, as they travel the world to find out everything they can about tackling the greatest writer of them all. Together they have directed and produced an inspiring film that aims to demystify and illuminate Shakespeare’s work for everyone: from actors, directors and students of all disciplines, right through to the "man on the street".  Think Shakespeare is boring? Think again!', '/864e2GelmOGK5YQhOiM47yzNgkh.jpg', '2013-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17380, 'National Theatre Live: Obsession', 444453, NULL, '/8TWk4GpTttdIaeSY3sRsSStEjK5.jpg', 'National Theatre Live: Obsession', 'Gino is a drifter, down-at-heel and magnetically handsome. At a road side restaurant he encounters husband and wife, Joseph and Hanna. Irresistibly attracted to each other, Gino and Hanna begin a fiery affair and plot to murder her husband. But, in this chilling tale of passion and destruction, the crime only serves to tear them apart.', '/6cqAe4W19UV60mRPCmys2UMQ50N.jpg', '2017-05-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17381, 'The Rhythm Section', 466622, NULL, '/ivEOcnP78Xbp8jwd7O5jazfeKwK.jpg', 'The Rhythm Section', 'When she discovers the plane crash that claimed the lives of her family was no accident, Stephanie Patrick enters the dark, complex world of international espionage seeking vengeance. With nothing left to lose, Stephanie transforms from victim to assassin and discovers that neither revenge nor the truth are what they appear.', '/spTr0VYyRtl36Lkk6nCnnbFXhus.jpg', '2020-01-31', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17382, 'Free Speech Fear Free', 459163, NULL, '/eYtZ8N6smzGJWx4VyF2qFJPdOmQ.jpg', 'Free Speech Fear Free', 'Can we really be fully human without Free Speech? Is free speech the oxygen of our society? Without it we crumble. Free Speech Fear Free get''s to the core of what free speech really is, and the impact it has on our day to day lives. It compares the UK with Belarus and shows what life is really like without Free Speech. It tells chilling stories of a dictatorship that destroys people''s standard of living.', '/dBjSUWF1B4pT65n6sLs6H9wfzGj.jpg', '2017-06-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17383, 'The Nest', 545237, NULL, '/pbvsoMOOgzqJCpUCnHWwbZqw98D.jpg', 'The Nest', 'Rory is an ambitious entrepreneur who brings his American wife and kids to his native country, England, to explore new business opportunities. After abandoning the sanctuary of their safe American suburban surroundings, the family is plunged into the despair of an archaic ''80s Britain and their unaffordable new life in an English manor house threatens to destroy the family.', '/mSTrRgXGzu2t1jVhTexIqwSHlk7.jpg', '2020-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17384, 'The Crane', 563935, NULL, NULL, 'The Crane', 'An enigmatic fragment of a bigger story, showing events leading up to a pivotal moment in the life of a strange, troubled young man. After losing his home, fiancée and job, he finds a moment of hopefulness.', '/AaRkA1m4ZP189VzVGq8GR4zIMdG.jpg', '1993-01-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17385, 'Frame by Frame: The Invisible Art of Production Designer Carol Spier', 620496, NULL, NULL, 'Frame by Frame: The Invisible Art of Production Designer Carol Spier', 'The invisible art of production designer Carol Spier. The relationship between director and production designer is a special one. FRAME BY FRAME is a documentary that goes behind the scenes of David Cronenberg''s sci-fi film, eXistenZ, for a rare and fascinating look at the art of production designer, Carol Spier.', '/qvKwIKSWpLwjlYGBknojKv73HjM.jpg', '2000-05-08', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17386, 'Skywatch', 643022, NULL, '/vUqVLheTiiq7cbk8M9dsULPV6CJ.jpg', 'Skywatch', 'When two outcast teens hack into a drone to pull a prank on their neighbor, they accidentally find themselves on the run from the delivery corporation.', '/64B4iGhwFB72QJpRPggi2aCciOK.jpg', '2019-10-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17387, 'Sherlock Holmes: Reinvented', 683258, NULL, NULL, 'Sherlock Holmes: Reinvented', 'Making of featurette for Sherlock Holmes (2009).', '/ubZ5EY63SpH6NYc8BRNdgLBlpZi.jpg', '2010-03-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17388, 'Sherlock Holmes and Dr. Watson: A Perfect Chemistry', 683262, NULL, NULL, 'Sherlock Holmes and Dr. Watson: A Perfect Chemistry', 'The ever-budding relationship between Holmes and Watson, as well as the bonding duo who portray them.', NULL, '2012-06-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17389, 'The Third Day: Autumn', 749418, NULL, '/yNlk3UUr7XOWwPL6jNaMPQ2mh0F.jpg', 'The Third Day: Autumn', 'The Third Day: Autumn invites viewers deeper into the suspenseful world of The Third Day. Featuring members of The Third Day cast including Jude Law, viewers will follow the events of a single day in a real time 12 hour broadcast as live from the island. In one continuous and cinematic take, the rituals and traditions of the islanders are further revealed as the line between what is real and what is not increasingly blurs.', '/hkBgdgne69pjyDDF0QQ2yS8F8vC.jpg', '2020-10-03', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17390, 'The Hat', 758907, NULL, NULL, 'The Hat', 'A young man wanders into the middle of a barren field, and just as he’s enjoying the peace of it all, a mystery assailant comes running out of the trees towards him. But some things you can’t outrun.', '/4JdSMak2Sjqtfi4eCT2wrJa7X4O.jpg', '2020-10-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17391, 'Letters Live from the Archive: Freemasons’ Hall', 806492, NULL, '/tnuqijCU0VBWC8y0nWBDj6lyWIq.jpg', 'Letters Live from the Archive: Freemasons’ Hall', 'Inspired by "Letters of Note", the bestselling anthology compiled by Shaun Usher, and "To the Letter" by Simon Garfield, Letters Live is a series of curated, live events that celebrate the enduring power of literary correspondence.  Performed by a remarkable and surprise cast each night, Letters Live is a unique event that is heartbreaking, euphoric, hilarious and inspiring in equal measure.  Those who have previously attended Letters Live will know how memorable these evenings are. In addition, a portion of the proceeds from each show are channeled towards a number of carefully selected literacy charities to support the important work they do.', '/pyqzh3RB6CM3l5rBjoRRSFNsjM0.jpg', '2021-03-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17392, 'Happy M’Gee', 1392816, NULL, NULL, 'Happy M’Gee', 'In the near future a neurodiverse man causes a fatal accident with deadly repercussions for his brother.', NULL, '2000-01-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17393, 'Ladies & Gentlemen... 50 Years of SNL Music', 1421461, NULL, '/bq9JVp1Bt7paCXWbDwLntQBHAKP.jpg', 'Ladies & Gentlemen... 50 Years of SNL Music', 'Untold stories behind the culture-defining and newsmaking musical performances, sketches and cameos of the past 50 years.', '/wiIfy2MXau1VPdi6z0Z0oYYT7ne.jpg', '2025-01-27', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17394, 'Saturday Night Live: The Best of ''09/''10', 1453218, NULL, NULL, 'Saturday Night Live: The Best of ''09/''10', 'Enjoy some of the bet sketches from SNL''s 35th season including Will Forte as MacGruber, Kenan Thompson''s Deandre Cole in What Up With That?, Fred Armisen as Barack Obama, Bill Hader as Vincent Price and Andy Samberg in two SNL Digital Shorts - Shy Ronnie and On The Ground.  Also join host Betty White and SNL alums Molly Shannon and Ana Gasteyer for another episode of NPR''s Delicious Dish.  Speacial Guests include Alec Baldwin, Charles Barkley, Gerard Butler, Tina Fey, James Franco, Zach Galifianakis, Jon Hamm, Jude Law, Blake Lively, Gabourey Sidibe, and Taylor Swift.', '/9AAL2pwM4JdBAn9B9tFWJlQxsHy.jpg', '2011-03-13', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
