INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17399, 'Frederick Douglass: In Five Speeches', 933721, NULL, '/dX81WoYtYyWSQHzw2IBjOFTgPSO.jpg', 'Frederick Douglass: In Five Speeches', 'Acclaimed actors draw from five of Douglass’ legendary speeches, to represent a different moment in the tumultuous history of 19th century America as well as a different stage of Douglass’ long and celebrated life, while famed scholars provide context for the speeches, and remind us that Frederick Douglass’ words about racial injustice still resonate deeply today.', '/2mi0TQcdtIWGlwAGU5kwXNJq09k.jpg', '2022-02-23', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17400, 'Newlyweeds', 158870, NULL, '/bxszeSJ4e0NAJSJPMkIgBbeOFW7.jpg', 'Newlyweeds', 'A match made in stoner heaven turns into a love triangle gone awry when Lyle can''t decide which matters most, Nina or Mary Jane.', '/pUmgwa0gjrFQoEfBkB28YfMl0S3.jpg', '2013-09-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17401, 'North Star', 977233, NULL, NULL, 'North Star', 'A rural rancher sacrifices everything to care for his dying husband as his sister-in-law and a pair of televangelists peddle in shame, fear, and division.', '/hSlcDz3OeTmf9WtipYKS7vKYNHS.jpg', '2022-01-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17402, 'New Moon', 989988, NULL, '/kZIgUWz6iUIgZO4Qdsb6kcrsoyA.jpg', 'New Moon', 'An imaginative surrealist journey of young Jay Jay and his mother Edie. Their inner city dreams are illuminated by the New Moon accompanied by magic of Aretha Franklin playing on a summer''s eve on a transistor radio in a backyard in West Philadelphia.', '/3fPmU1SXHGt5DQfgQOVVkkQovXw.jpg', '2022-07-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17403, 'When My Sleeping Dragon Woke', 1025920, NULL, NULL, 'When My Sleeping Dragon Woke', 'A little girl lives in a custodian apartment inside a New York Public Library, where her father stokes its coal furnace 24/7. Decades later, actor Sharon Washington chooses the theater to write her modern-day fairytale filled with real and imagined dragons, family secrets, forgiveness, and a world of books.', '/iVtZxcPCLqmixRSpm8FwHGBhrcE.jpg', '2022-10-12', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17404, 'A Long Walk', 308648, NULL, NULL, 'A Long Walk', 'A father humiliates his son by parading him through the neighborhood in women''s clothing in front of all the other kids on a summer day. The impact of that decision ripples through his family and best friend''s lives for years to come. This story is based on true events.', '/mOKOAscYLNS09ImxWtX8Xzqu5XZ.jpg', '2014-03-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17405, 'Unforgettable', 1236125, NULL, NULL, 'Unforgettable', 'The movie will chart Cole’s journey as musician and quiet revolutionary, navigating racial injustice, Hollywood sabotage and self doubt to ensure his legacy and help pave the way for future generations of artists and Black men and women.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17406, 'Oprah & The Color Purple Journey', 1218168, NULL, '/uaElBG0jYMFLoTIsFrJ1L0ld5dp.jpg', 'Oprah & The Color Purple Journey', 'A behind-the-scenes look into the making of the new feature film “The Color Purple,” and the impact the story has had on our culture. Oprah Winfrey takes viewers inside the four-decade phenomenon, exploring the importance of the novel, films and musical, and the ever-evolving conversation around this seminal work.', '/Ap07nfF2bmHsMKNAmLRGU56xlmG.jpg', '2023-12-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17407, 'The Birth of a Nation', 339408, NULL, '/gTo9VPjYsP6FD89HdzAKfjA7qH4.jpg', 'The Birth of a Nation', 'Nat Turner, a former slave in America, leads a liberation movement in 1831 to free African-Americans in Virginia that results in a violent retaliation from whites.', '/vlbvPL3uXem7JaVWM2mVHJLkRqW.jpg', '2016-09-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
