INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17409, 'Beautiful Something', 349087, NULL, '/wOlNKlBeTUbWAJAbeXtq6VWai9v.jpg', 'Beautiful Something', 'Four diverse gay men navigate art, sex and love in one sublime night.', '/1q9PlHdGpQSJeO5wEZnGSKL8Xa3.jpg', '2015-04-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17410, 'Red Hook Summer', 84328, NULL, '/ziTYJXcrxgYOYcpsgbcS7xXWmQ1.jpg', 'Red Hook Summer', 'When his mom deposits him at the Red Hook housing project in Brooklyn to spend the summer with the grandfather he’s never met, young Flik may as well have landed on Mars. Fresh from his cushy life in Atlanta, he’s bored and friendless, and his strict grandfather, Enoch, a firebrand preacher, is bent on getting him to accept Jesus Christ as his personal savior. Only Chazz, the feisty girl from church, provides a diversion from the drudgery. As hot summer simmers and Sunday mornings brim with Enoch’s operatic sermons, things turn anything but dull as people’s conflicting agendas collide.', '/qxAc0F0zzGj0YROOOr6OQIEOvq1.jpg', '2012-08-10', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17411, 'Assassination Nation', 446101, NULL, '/kDlwxlCzJmmJra99LlIwr4o9nbZ.jpg', 'Assassination Nation', 'After an anonymous hacker begins leaking the private data of thousands living in a small American town, the townspeople spiral into madness, with four high school seniors at the center of the maelstrom.', '/dMg1wPakqPx54yMzm0OuHn1jl42.jpg', '2018-09-21', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
