INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17413, 'True Crime', 10354, NULL, '/891kxjT04dJNMhbsyMOlycO5wAN.jpg', 'True Crime', 'Boozer, skirt chaser, careless father. You could create your own list of reporter Steve Everett''s faults but there''s no time. A San Quentin Death Row prisoner is slated to die at midnight – a man Everett has suddenly realized is innocent.', '/ozrV1xtwU3Y5XOFuVn9T00ZYoiV.jpg', '1999-03-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
