INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17415, 'Lucy in the Sky', 340104, NULL, '/zYNHAnh6455uFW6lDHCTtWrQyjA.jpg', 'Lucy in the Sky', 'Astronaut Lucy Cola returns to Earth after a transcendent experience during a mission to space – and begins to lose touch with reality in a world that now seems too small.', '/ofhOB6EGSBqzGHA0MStMx9zWnML.jpg', '2019-09-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
