INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17417, 'Zola', 539565, NULL, '/zL7CozbpAbGSdhBsuTI847tu5Fo.jpg', 'Zola', 'A waitress agrees to accompany an exotic dancer, her put-upon boyfriend, and her mysterious and domineering roommate on a road trip to Florida to seek their fortune at a high-end strip club.', '/bJLCPROp9bmNndurwZpVnOioVpB.jpg', '2021-06-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17418, 'Hairbrained', 239056, NULL, '/auORL6gbhGIqN7SaiMw3wevFtZm.jpg', 'Hairbrained', 'A fourteen-year-old genius gets rejected by Harvard and ends up at a much lower ranked school where he makes friends with a mature student.', '/ifLjWZ40nf5urj5socB2OMOZglE.jpg', '2013-11-25', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17419, 'King of the Bingo Game', 667077, NULL, NULL, 'King of the Bingo Game', 'Harlem, 1943. Sonny is a struggling African American who frequents the bingo parlor in a desperate attempt to provide for his family in post-Depression era New York.', '/4qwav2FhOPoeiz4xkKFXAa3144Z.jpg', '1999-01-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17420, 'Kung Phooey!', 58255, NULL, '/6Cx59irjtesx5GjQrq8oZ6SIj0k.jpg', 'Kung Phooey!', 'The plot follows Art Chew''s (a pun of the sound one makes when sneezing) quest to retrieve the ancient peach. The movie starts with Art Chew traveling to America, as well as showing Art''s training at the Shur-li temple (a play on words with the child actor Shirley Temple), showing many kung-fu clichés such as grabbing the pebble from the masters hand (which Art succeeds without effort), fighting on trees in this case small potted palms and "listing" for elements (Earth, Wind and Fire play a funky tune). After the montage is shown Art meets up with his cousin Wayman (A parody on the way Chinese pronounce r as w) a Chinese adult who tries to act American so he isn''t embarrassed by stereotypes and foster cousin Roy Lee, an African American who sincerely believes he is a reincarnation of Bruce Lee.', '/gpjbRGteCRu5FyIfbXp6fnvN6M6.jpg', '2003-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17421, 'Miracle at St. Anna', 12412, NULL, '/hY3O9tTA6xlk5l7xamO4uVNxEN2.jpg', 'Miracle at St. Anna', 'Miracle at St. Anna chronicles the story of four American soldiers who are members of the all-black 92nd "Buffalo Soldier" Division stationed in Tuscany, Italy during World War II.', '/7PqmgaQBuD0Zp9pDIkkEjkhCJUj.jpg', '2008-09-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17422, 'Around the Fire', 18592, NULL, '/dZh9ReokmLpaeN04rmEcacVb7NW.jpg', 'Around the Fire', 'Simon is an intelligent and privileged young man whose family expects him to become a Princeton graduate. Crying out for attention from his reserved and cool hearted family, Simon commits numerous petty crimes and is soon sent away to boarding school where he befriends a "Deadhead," adopts the "hippie" lifestyle and dabbles in many drugs in his search for acceptance.', '/gn7LxcbCk5bvdtpHeXupLWGuIbD.jpg', '1998-09-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17423, 'Desi''s Looking for a New Girl', 278788, NULL, '/lv6jMZnowcl5L8ORCKKEdGOQGMZ.jpg', 'Desi''s Looking for a New Girl', 'After her live-in lover leaves her for another woman, Desi, a young artist, gets incredibly depressed. Her well-meaning friends try to set her up with a number of women, all of whom Desi finds less than inspiring. Meanwhile, teen skateboarder J.T. harbors wild dreams of meeting her idol, comic Marga Gomez. This film, set in San Francisco''s Latina lesbian culture, premiered at the 2000 San Francisco Lesbian and Gay Film Festival.', '/6sLefSlhsDc6amSpV1mvaagU0i9.jpg', '2000-06-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
