INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17461, 'Kickboxer: Vengeance', 308529, NULL, '/mZT5eXy9Tapf85LV62hkfaVp2Of.jpg', 'Kickboxer: Vengeance', 'Eric and Kurt Sloane are the descendants of a well-known Venice, California-based family of martial artists. Kurt has always been in older brother, Eric''s shadow, as he lacks the instincts needed to become a champion. Against Kurt''s concerns, Eric accepts a paid offer and travels to Thailand to challenge the Muay Thai champion Tong Po and fails with dire consequences. Kurt sets out for revenge. He trains with his brother''s mentor, Master Durand, for a Muay Thai fight against the merciless champion, Tong Po. Durand first thinks Kurt is impossible to train, but through a series of spiritual exercises and tests, Durand discovers that Kurt has a deeper strength that will carry him through his final showdown with Tong Po.', '/9suFyXDE1MhZ8I8tuhmTd0fJ7G8.jpg', '2016-07-14', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17462, 'Pound of Flesh', 326284, NULL, '/5KqLlBfhkS58MVQ9ir4ttyGk2i6.jpg', 'Pound of Flesh', 'In China to donate his kidney to his dying niece, former black-ops agent Deacon awakes the day before the operation to find he is the latest victim of organ theft. Stitched up and pissed-off, Deacon descends from his opulent hotel in search of his stolen kidney and carves a blood-soaked path through the darkest corners of the city. The clock is ticking for his niece and with each step he loses blood.', '/lLxgyIuENnjPLeNIoqwIg3XBwJ1.jpg', '2015-05-07', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17463, 'Silent Kill', 1042653, NULL, NULL, 'Silent Kill', 'A hidden treasure in the Congo has been found by a group of mercenaries. They will bury it and all agree to meet back at the same spot in three years and split the fortune evenly, however things take a different turn.', NULL, NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
