INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17466, 'Narco', 20200, NULL, '/yfOZnKb77EOLGewJcvSCb5fZ2a2.jpg', 'Narco', 'Gustave Klopp suffers from narcolepsy, he can fall asleep everwhere at anytime whithout warning. Living a simple life with his wife Pam and his best friend Lenny Bar, Gus decides to undergo therapy sessions and finds out that he can make incredible comics from his dreams.', '/w4Ea1P4Ig5B48hZl9owRshUepVs.jpg', '2004-12-01', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17467, 'Albert Pyun: King of Cult Movies', 1257969, NULL, NULL, 'Albert Pyun: King of Cult Movies', 'Albert Pyun: King of Cult Movies tells the story of a true renegade and his love for filmmaking, a free spirit who always did Hollywood his way despite the odds. The documentary follows Albert after his diagnosis of multiple sclerosis and dementia. Fighting rapidly declining health, hallucinations, and memory loss, he is on a mission to make his final film, Cyborg Overture - Bad Ass Angels and Demons, the prequel to one of his most famous films, the post-apocalyptic classic Cyborg.', '/tcSYxicDPmNgEpEzIaLoakR9tgU.jpg', '2023-11-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17468, 'Beur sur la ville', 77460, NULL, '/3qX5VHxvum3bYMmm9o4b40CbdXd.jpg', 'Beur sur la ville', '25-year-old Khalid Belkacem has failed at everything: college education, summer camp instructor''s permit, driver''s license, and even his BCG. He never expected to become the first "positive discrimination" member of the police force. But as his mother says: "That''s France for you! A country where everyone has a chance."', '/m6tfj24kfVRp1ahHBPApK7nAcXZ.jpg', '2011-10-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17469, 'Heist School', 27959, NULL, '/jkcxKC43syOKHh9roYLb3UMFcuQ.jpg', 'Sınav', 'Five high school students plans to steal University Entrance Exam booklets.', '/t53xz110VXSYtBciCuRkYvZsw9Z.jpg', '2006-10-20', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17470, 'Kickboxer: Retaliation', 447665, NULL, '/kU4EafCWSksRo8Lnno91mzOURgN.jpg', 'Kickboxer: Retaliation', 'One year after the events of "Kickboxer: Vengeance", Kurt Sloan has vowed never to return to Thailand. However, while gearing up for a MMA title shot, he finds himself sedated and forced back into Thailand, this time in prison. He is there because the ones responsible want him to face a 6''8" 400 lbs. beast named Mongkut and in return for the fight, Kurt will get two million dollars and his freedom back. Kurt at first refuses, in which a bounty is placed on his head as a way to force him to face Mongkut. Kurt soon learns he will have no other choice and will undergo his most rigorous training yet under some unexpected mentors in order to face Mongkut in hopes to regain his freedom.', '/oMWP4cAoy8WBauuKZAVTIfuY3Fw.jpg', '2018-01-26', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17471, 'Woman Between Wolf and Dog', 198508, NULL, NULL, 'Een vrouw tussen hond en wolf', 'Lieve is a Belgian woman who marries just as World War II is beginning. When the Germans invade, her husband goes off to fight them, but he swiftly returns home after the invasion succeeds. Later, he decides that the Germans are on the right side of things, and goes off to fight for them on the Eastern Front. Soon afterward, a resistance fighter is stranded on her doorway, and she hides him. The two of them fall in love, and the conflicts and joys of this relationship cause Lieve continued grief well after the end of the war.', '/5kDt9NtklxyJe21rC6zP95Ft5oA.jpg', '1979-06-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17472, 'Street of the Damned', 76217, NULL, '/46y3rvkRx0FlZDfRWX2BrNHcolE.jpg', 'Rue Barbare', 'In a desolate Paris suburb, no one dares challenge crime boss Hagen, who rules his turf with an iron fist. That includes his former friend Chet, who vows to keep to himself in order to protect his loved ones. But Hagen keeps pushing his buttons… and Chet can only stand for so much before he explodes.', '/8rfFhkNAGNl5WTUpsdg8dRqjEGq.jpg', '1984-01-04', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17473, 'Kill ''em All', 449503, NULL, '/hINq9R7bPiGpLOXRA4pl6toh5f3.jpg', 'Kill ''em All', 'After a massive shootout, a mysterious stranger arrives at a local hospital on the brink of death. Then, a foreign gang brazenly comes to the hospital to hunt him down. His nurse, the sole surviving witness to the follow-up shootout, must face an FBI interrogation that unlocks a plot of international intrigue and revenge.', '/cWkZQqS2IxMcvH7UZSHFR8YYRfk.jpg', '2017-06-06', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17474, 'Black Water', 454615, NULL, '/noNMHp461qETqftTGRC4xJtJ8Pf.jpg', 'Black Water', 'A deep cover operative awakens to find himself imprisoned on a submarine. With the help of a fellow prisoner and an amateur agent, he must race against the clock to escape the vessel and expose who set him up.', '/tIcZAB5AmRN8fIDXfDZ2aUok9qa.jpg', '2018-05-18', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17475, 'The Go-Go Boys: The Inside Story of Cannon Films', 295099, NULL, '/Rbz276DvQ1l0ung6HvJ7xfrBeB.jpg', 'The Go-Go Boys: The Inside Story of Cannon Films', 'Cousins Menahem Golan and Yoram Globus relive the creation, rise and fall of their independent film company, Cannon Films. This documentary recounts their many successes and discusses their eventual downfall.', '/fpc5p8NyADSsZyZAcn7qdsWuvsU.jpg', '2014-10-22', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17476, 'Jian Bing Man', 348595, NULL, '/y1AV6vVB2bhHfMyBU1C32yc7mg0.jpg', '煎饼侠', 'Beijing, the present day. Popular TV personality Da Peng is invited by gangster businessman Wang Hai to make a film in which he will invest. Wang insists that Da Peng''s co-star is TV drama actress Du Xiaoxiao. However, after a nightclub scandal involving Da Peng goes viral, he''s blackballed by a powerful internet executive and finds himself unable to attract any male co-star. Wang also wants his investment back. Da Peng decides to make his own movie on the cheap, using a script he has about an alien, A Li, who arrives on Earth and has various adventures as a superhero.', '/sN6WqOcalzLEiHXkgDFVIAXHYhH.jpg', '2015-07-17', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
