INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17478, 'We Die Young', 538207, NULL, '/srEsK6LPJSMd0LndDIzxtBEiKNS.jpg', 'We Die Young', 'Lucas, a 14-year-old boy inducted into the gang life in Washington D.C., is determined that his 10-year-old brother won''t follow the same path. When an Afghanistan war veteran comes into the neighborhood, an opportunity arises.', '/dB0Dl2nDRmvplaJLeHSfkppJXHs.jpg', '2019-05-09', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17479, 'The Making of Double Impact, Parts 1 & 2', 619880, NULL, NULL, 'The Making of Double Impact, Parts 1 & 2', 'Jean-Claude van Damme, Sheldon Lettich and more discuss the 1991 film "Double Impact" from inception to reception.', NULL, '2019-05-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17480, 'Universal Soldier: A Tale of Two Titans', 684421, NULL, NULL, 'Universal Soldier: A Tale of Two Titans', 'Biography style segment that gives us some interesting background information on Van Damme and Lundgren. Though they come from different parts of Europe, they followed a similar path on their respective trips to Hollywood stardom. The mini documentary follows them from their early days in Europe through to their current careers in America and uses lots of personal archive photos and footage to tell its tale.', '/968aWHliMK9nQ4ZVNmTZq7Q6DS7.jpg', '2004-10-19', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
