INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17483, 'The Last Mercenary', 729720, NULL, '/fZ4hrFacm5yow9gT64rS6YMNyHz.jpg', 'Le Dernier Mercenaire', 'A legendary secret service agent comes out of hiding and returns to France to help the son he''s never met get out of trouble.', '/ttpKJ7XQxDZV252KNEHXtykYT41.jpg', '2021-07-30', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17484, 'Monsieur Jean-Claude', 794863, NULL, NULL, 'Monsieur Jean-Claude', 'Jean-Claude Van Damme is back, and this time it''s personal. Seventy-two photograms constructed from a 35mm trailer of JCVD''s opus The Quest (1996). Re-examining conceptions of masculinity by deconstructing some of the images I watched repeatedly as a child.', '/92k5qwtJDpPFmRsnxVMbinNCM4f.jpg', '2021-07-15', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17485, 'All the Love You Cannes!', 99368, NULL, '/nLe1qkpAuuUibw0zdi1UEfFgb0N.jpg', 'All the Love You Cannes!', 'Known for what must be the cheapest and cheesiest of the indie film world, Troma films takes on Cannes with gallons of fake blood, the Tronettes, and numerous hijinks by an uncontrollable group of volunteer Troma fans, costumed, naked, and did I mention covered with blood? While any publicity is good publicity, the low budget Troma films must wonder what this will do to their reputation. And I think they''re thinking, woohoo!', '/rnShktOr0ErzRffCfclknD7NcTk.jpg', '2002-05-16', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
