INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17487, 'Slinger', 1446634, NULL, '/hLhcQrvreQfDePcgJxonN6QMO17.jpg', 'Slinger', 'Set in a post-apocalyptic future where starvation and disease are plaguing the few remaining inhabitants of Earth. Scientists are close to discovering a cure for the plague that is sweeping the country. Gibson Rickenbacker is a strong fighter who leads a group to Atlanta to gain information needed for the cure, along the way attempting to avoid the villains.', '/yrmK34vzCl2E9oXuVJtZPo0V45x.jpg', '2011-03-11', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17488, 'Sensation: Cruise', 1517174, NULL, '/wWhr87zZ0JJTN0q6PYBVUvs4Rmu.jpg', 'Круїзна Сенсація', 'Mykola Kuńko works as an unlucky TV reporter in early 2000s Ukraine. Together with his trusty camerawoman, Jenya, he is wandering aimlessly through life, from one boring news story to another. One morning, when they are about to go to the premiere of a new rip-off action film, they stumble upon their biggest sensation yet.', '/pYB1DzQKSw8oyTgsSNKmZg4tZLn.jpg', '2025-06-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17489, 'Ultrarêve', 1524212, NULL, '/fHLTgLnvYGRMaK1wwjfGTYEUdVp.jpg', 'Ultrarêve', 'Jean-Claude Van Damme drives a car into an empty out-of-the-way parking lot. As the song Ultrarêve begins to play, JCVD gets out of the car and begins to mildly dance--as if becoming attuned with nature.', '/5AUuHLB6LxeMt0Wosudbf2KMkLf.jpg', '2020-08-28', NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO movies (id, title, tmdb_id, imdb_id, backdrop_path, original_title, overview, poster_path, release_date, runtime, tagline, director, wins, nominations, last_modified, is_deleted) VALUES (17490, 'Chinese Hercules: The Bolo Yeung Story', 1403690, NULL, '/rMAA8r6AxfaJuXCkxrQqU7NxRfP.jpg', 'Chinese Hercules: The Bolo Yeung Story', 'This is the story of the bodybuilder, Martial Artist and actor who wrote his own destiny and walked his own path. A legendary tale that''s never been told on-screen before.', '/skQeMDPobckWwBoAGY1VDXR60LA.jpg', NULL, NULL, NULL, NULL, 0, 0, '2026-04-29 22:43:08', 0);
