INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (4525, 'Emma Stone', 54693, 'nm1297015', 'Emily Jean "Emma" Stone (born November 6, 1988) is an American actress and film producer. Her accolades include two Academy Awards, two British Academy Film Awards, two Golden Globe Awards and a Volpi Cup. In 2017, she was the world''s highest-paid actress and was named by Time magazine as one of the 100 most influential people in the world.

As a child in Arizona, Stone started acting in local theatre productions before relocating to Los Angeles to pursue a career in the film industry. As a teenager, she made her television debut in the reality show In Search of the New Partridge Family (2004). After small television roles, she appeared in a string of successful comedy films, including Superbad (2007), Zombieland (2009), and Easy A (2010), which marked Stone''s first leading role. Following this breakthrough, she starred in the romantic comedy Crazy, Stupid, Love (2011) and the period drama The Help (2011). She gained wider recognition as Gwen Stacy in Marc Webb''s Spider-Man films (2012–2014).

Stone cemented her status as a leading lady by taking on more eclectic and dramatic roles. She earned nominations for the Academy Award for Best Supporting Actress for portraying a recovering drug addict in the surrealist dark comedy Birdman (2014) and Abigail Hill in the absurdist period film The Favourite (2018); the latter marked her first of many collaborations with Yorgos Lanthimos. She won two Academy Awards for Best Actress for portraying an aspiring actress in the romantic musical La La Land (2016) and a resurrected suicide victim in Lanthimos''s Poor Things (2023); she was also nominated for the Academy Award for Best Picture for the latter. Stone also earned recognition for portraying tennis player Billie Jean King in Battle of the Sexes (2017) and the titular role in Cruella (2021). She has since collaborated twice more with Lanthimos, starring in the anthology film Kinds of Kindness (2024) and the dark comedy Bugonia (2025); the latter earned her further nominations for the Academy Award for Best Actress and Best Picture, making her the first woman to be nominated as both a producer and an actress in two different films.

On Broadway, Stone starred as Sally Bowles in a revival of the musical Cabaret (2014–2015). On television, she has led the dark comedy miniseries Maniac (2018) and The Curse (2023). She and her husband, Dave McCary, founded the production company Fruit Tree in 2020.

Description above from the Wikipedia article Emma Stone, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1988-11-06', NULL, 1, 'Acting', 'Scottsdale, Arizona, USA', '/cZ8a3QvAnj2cgcgVL6g4XaqPzpL.jpg', 2, 5, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (4823, 'Florence Pugh', 1373737, 'nm6073955', 'Florence Pugh (/pjuː/ PEW; born 3 January 1996) is an English actress. Her accolades include a British Independent Film Award, as well as nominations for an Academy Award and three BAFTA Awards.

After making her acting debut in the drama film The Falling (2014), Pugh gained praise for starring in the independent drama Lady Macbeth (2016) and the miniseries The Little Drummer Girl (2018). Her international breakthrough came in 2019 with her portrayals of professional wrestler Paige in the sports film Fighting with My Family, a despondent American woman in the horror film Midsommar, and Amy March in the period drama Little Women. For the last of these, she was nominated for the Academy Award for Best Supporting Actress.

Pugh has played Yelena Belova in the Marvel Cinematic Universe, starring in the films Black Widow (2021), Thunderbolts* (2025), Avengers: Doomsday (2026) and Avengers: Secret Wars, as well as the Disney+ miniseries Hawkeye (2021). In her highest-grossing releases, she voiced Goldilocks in Puss in Boots: The Last Wish (2022), and portrayed Jean Tatlock in Oppenheimer (2023) and Princess Irulan in Dune: Part Two (2024); she also continued to gain praise for her performances in dramas such as We Live in Time (2024).

Description above from the Wikipedia article Florence Pugh, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1996-01-03', NULL, 1, 'Acting', 'Oxford, Oxfordshire, England UK', '/1Uvfh7xL4U2evkhs0M3C7BbBYFf.jpg', 0, 1, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5074, 'Colman Domingo', 91671, 'nm0231458', 'Colman Jason Domingo (born November 28, 1969) is an American actor, playwright, and director. Prominent on both screen and stage since the 2010s, Domingo has received various accolades, including a Primetime Emmy Award, and nominations for an Academy Award and two Tony Awards. Time magazine named him one of the 100 most influential people in the world in 2024.

Domingo''s early Broadway roles include the 2005 play Well and the 2008 musical Passing Strange. He gained acclaim for his role as Mr. Bones in the Broadway musical The Scottsboro Boys (2011), for which he was nominated for the Tony Award for Best Featured Actor in a Musical. He reprised the role in the 2014 West End production, receiving a nomination for the Laurence Olivier Award for Best Performance in a Supporting Role in a Musical. In 2018, he wrote the book for the Broadway musical Summer: The Donna Summer Musical.

After early roles in various incarnations of the Law & Order series and as part of the main cast for The Big Gay Sketch Show, Domingo had his breakthrough playing Victor Strand in the AMC series Fear the Walking Dead (2015–2023). He gained wider acclaim for his recurring role as the recovering drug addict Ali on the HBO series Euphoria (2019–present), winning the Primetime Emmy Award for Outstanding Guest Actor in a Drama Series in 2022.

Domingo received consecutive nominations in 2024 and 2025 for the Academy Award for Best Actor for his portrayals of civil rights activist Bayard Rustin in the biopic Rustin and a prison inmate in the drama Sing Sing. His other notable film appearances include roles in Lincoln (2012), The Butler (2013), Selma (2014), If Beale Street Could Talk (2018), Ma Rainey''s Black Bottom (2020), Zola (2021), and The Color Purple (2023).  Description above from the Wikipedia article Colman Domingo, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1969-11-28', NULL, 2, 'Acting', 'Philadelphia, Pennsylvania, USA', '/t0cgfvtA7Thxnrtj5baRi656zlc.jpg', 0, 2, '2026-04-29 22:43:08', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5080, 'Emily Blunt', 5081, 'nm1289434', 'Emily Olivia Laura Blunt (born 23 February 1983) is a British actress. She has received several accolades, including a Golden Globe Award and two Screen Actors Guild Awards, in addition to nominations for an Academy Award and four British Academy Film Awards. Forbes ranked her as one of the highest-paid actresses in the world in 2020.

Blunt made her acting debut in the 2001 drama production of The Royal Family and portrayed Catherine Howard in the television miniseries Henry VIII (2003). She made her feature film debut in the drama My Summer of Love (2004). Blunt''s breakthrough came in 2006 with her starring roles in the television film Gideon''s Daughter and the comedy-drama  The Devil Wears Prada. The former won her a Golden Globe Award for Best Supporting Actress. Her profile continued to grow with leading roles in the period film The Young Victoria (2009), the romantic comedy Salmon Fishing in the Yemen (2011), the science fiction films The Adjustment Bureau (2011), Looper(2012) and Edge of Tomorrow (2014), and the musical Into the Woods (2014).

Blunt received critical acclaim for playing an idealistic FBI agent in the crime film Sicario (2015), an alcoholic in the psychological thriller The Girl on the Train (2016), and a survivalist mother in her husband John Krasinski''s horror film A Quiet Place (2018), for which she won a SAG Award for Best Supporting Actress. She has since starred in the sequels Mary Poppins Returns (2018) and A Quiet Place Part II (2021), the fantasy adventure Jungle Cruise (2021), and the revisionist Western television miniseries The English (2022). Her portrayal of Katherine Oppenheimer in Christopher Nolan''s biographical thriller film Oppenheimer (2023) earned her a nomination for the Academy Award for Best Supporting Actress.

Blunt has been working with the American Institute for Stuttering since 2006 to help children overcome stuttering through educational resources and raise awareness of the realities of the condition. She is on the institute''s board of directors and hosts a gala to raise funds for speech therapy scholarships for children and adults.

Description above from the Wikipedia article Emily Blunt, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1983-02-23', NULL, 1, 'Acting', 'Wandsworth, London, England, UK', '/zpJ7pupuNF3W0zTxm6yioGIoxbd.jpg', 0, 1, '2026-04-29 22:43:07', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5210, 'Jacob Elordi', 2034418, 'nm8624059', 'Jacob Nathaniel Elordi (born 26 June 1997) is an Australian actor. After moving to Los Angeles in 2017 to pursue an acting career, he gained prominence with his role as Noah Flynn, the bad boy love interest, in Netflix''s The Kissing Booth film series (2018–2021). He also became known for his role as troubled high school football player Nate Jacobs in HBO''s teen drama series Euphoria (2019–present). In 2023, he starred as Elvis Presley in the biographical film Priscilla and as a wealthy university student in Saltburn, which earned him a nomination for the BAFTA Award for Best Actor in a Supporting Role.', '1997-06-26', NULL, 2, 'Acting', 'Brisbane, Queensland, Australia', '/lC9pK3ADyPpH4dRo2BKZBaTZPfu.jpg', 0, 1, '2026-04-29 22:43:00', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5272, 'Sydney Sweeney', 115440, 'nm2858875', 'Sydney Bernice Sweeney (born September 12, 1997) is an American actress. She gained early recognition for her roles in Everything Sucks!, The Handmaid''s Tale and Sharp Objects in 2018. She received wider acclaim for her performances in the drama series Euphoria (2019–present) and the first season of the anthology series The White Lotus (2021), both of which earned her nominations for Primetime Emmy Awards.

In film, Sweeney garnered critical acclaim for her performances in the drama film Reality (2023) and for her portrayal of professional boxer Christy Martin in the biopic Christy (2025), and has also appeared in the box office hits Anyone but You (2023) and The Housemaid (2025). Her other film credits include Once Upon a Time in Hollywood (2019), Madame Web (2024), and Immaculate (2024).

Description above from the Wikipedia article Sydney Sweeney, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1997-09-12', NULL, 1, 'Acting', 'Spokane, Washington, USA', '/lkEC9xM133h2f8wmp8CpyLr3JNq.jpg', 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5273, 'Hannah Cheramy', 1562430, 'nm7344528', 'Hannah was born in Vancouver, BC. She began acting in local children''s theatre productions by the age of 7. Hannah found her agent when she was 11 years old and in the first year she was booked in numerous commercials and was cast as a lead in a horror feature film. Since then, she has been cast in TV movies, TV series, feature films and is now a series regular on the TV series "From".', '2003-07-13', NULL, 1, 'Acting', 'Vancouver, Canada', '/bVNJpvLKWwzxvLPFFmhsoMsR5qu.jpg', 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5293, 'Keanu Reeves', 6384, 'nm0000206', 'Keanu Charles Reeves is a Canadian actor. Reeves is known for his roles in Bill & Ted''s Excellent Adventure, Speed, Point Break, and The Matrix franchise as Neo.

He has collaborated with major directors such as Stephen Frears (in the 1988 period drama Dangerous Liaisons); Gus Van Sant (in the 1991 independent film My Own Private Idaho); and Bernardo Bertolucci (in the 1993 film Little Buddha). Referring to his 1991 film releases, The New York Times'' critic, Janet Maslin, praised Reeves'' versatility, saying that he "displays considerable discipline and range. He moves easily between the buttoned-down demeanor that suits a police procedural story and the loose-jointed manner of his comic roles." A repeated theme in roles he has portrayed is that of saving the world, including the characters of Ted Logan, Buddha, Neo, Johnny Mnemonic, John Constantine and Klaatu.', '1964-09-02', NULL, 2, 'Acting', 'Beirut, Lebanon', '/kEoUZKEG7dzbCESDjd0CKAN1r0n.jpg', 0, 0, '2026-04-29 22:42:53', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5308, 'Chris Hemsworth', 74568, 'nm1165110', 'Christopher Hemsworth AM (born 11 August 1983) is an Australian actor and film producer. Born and raised in Melbourne, Victoria, and Bulman, Northern Territory, he rose to prominence playing Kim Hyde in the Australian television series Home and Away (2004–2007) before beginning a film career in Hollywood. In the Marvel Cinematic Universe, Hemsworth starred as Thor in the 2011 film of the same name and reprised the role in several subsequent instalments, which established him among the world''s highest-paid actors.

His other film roles include the action films Star Trek (2009), Snow White and the Huntsman (2012) and its sequel The Huntsman: Winter''s War(2016), Red Dawn (2012), Blackhat (2015), Men in Black: International (2019), Extraction (2020) and its 2023 sequel, the thriller A Perfect Getaway(2009), and the comedy Ghostbusters (2016). Hemsworth''s most critically acclaimed films include the comedy horror The Cabin in the Woods (2012), the biographical sports film Rush (2013) in which he portrayed James Hunt, the action film Furiosa: A Mad Max Saga (2024)—which earned him a nomination for the AACTA Award for Best Actor in a Supporting Role—and the animated film Transformers One (2024) in which he voiced Optimus Prime.

Description above from the Wikipedia article Chris Hemsworth, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1983-08-11', NULL, 2, 'Acting', 'Melbourne, Victoria, Australia', '/piQGdoIQOF3C1EI5cbYZLAW1gfj.jpg', 0, 0, '2026-04-29 22:43:06', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5337, 'Hitoe Ootake', 1487683, 'nm0652714', NULL, '1972-02-05', NULL, 1, 'Acting', 'Tokyo, Japan', '/44pPj6GmPInI9q6BAKMIygp9yN6.jpg', 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5387, 'Hunter Schafer', 2340180, 'nm9476408', 'Hunter Schafer (born December 31, 1998) is an American actress, model and transgender rights activist. Born in Trenton, New Jersey, and raised in Raleigh, North Carolina, Schafer was assigned male at birth and transitioned as a child. She came to public attention after joining a 2016 lawsuit against North Carolina''s Public Facilities Privacy & Security Act, a so-called "bathroom bill" which prevented transgender people from using public bathrooms corresponding to their gender identity. For her activism, she was named to Teen Vogue''s "21 Under 21" list in 2017.

Schafer has studied watercolour painting and clothing design. In 2017, she began work as a fashion model for various brands. Schafer initially planned to attend an arts college to further her studies in clothing design, but instead decided to transition to acting after being cast in the HBO teen drama series Euphoria (2019–present). Her role as transgender high school student Jules Vaughn, and her co-writing credit on an episode of the series, garnered her critical praise.

Schafer has since starred in the films The Hunger Games: The Ballad of Songbirds & Snakes (2023) and Cuckoo (2024), and had minor roles in Kinds of Kindness (2024) and the English dub of the Japanese film Belle (2021). Schafer has continued to model after entering the acting industry, serving as a brand ambassador for Shiseido Makeup, Prada, and Mugler.

Description above from the Wikipedia article Hunter Schafer, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1998-12-31', NULL, 1, 'Acting', 'Trenton, New Jersey, USA', '/6ZDieLlbm2m3jbYaxsHFo7cWWzJ.jpg', 0, 0, '2026-04-29 22:43:00', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (5472, 'Ashley Lopez', 5420126, 'nm17002888', NULL, NULL, NULL, 1, 'Acting', NULL, '/pRIF389pP8fCmkp7wlOusY9AlMQ.jpg', 0, 0, '2026-04-29 22:42:55', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (28285, 'Nathalie Baye', 136761, 'nm0000882', 'Nathalie Marie Andrée Baye (July 6, 1948 – April 17, 2026) was a French film, television, and stage actress. She began her career in 1970 and has appeared in more than 80 films. A ten-time César Award nominee, her four wins were for Every Man for Himself (1980), Strange Affair (1981), La Balance (1982), and The Young Lieutenant (2005). Her other films include Day for Night (1973), Catch Me If You Can (2002), Tell No One (2006), and The Assistant (2015). In 2009, she was appointed a Chevalier of the Legion of Honour.

Baye was born in Mainneville, Eure, Normandy to Claude Baye and Denise Coustet, two painters. At 14, she joined a school of dance in Monaco. Three years later she went to the United States. On returning to France, she continued with dance but also registered for the Simon Course and was admitted to the Conservatoire, from where she graduated in 1972 with a second prize in comedy, dramatic comedy, and foreign theatre.

Her second cinema appearance was in Two People (1973), directed by Robert Wise. She became better known as the script girl in Day for Night (La Nuit américaine, 1973) by François Truffaut. Throughout the 1970s, she played the good girlfriend or nice provincial girl in film and television.

She won her first César, as best supporting artist, for Every Man for Himself (Sauve qui peut (la vie), 1980) directed by Jean-Luc Godard. There then followed The Return of Martin Guerre (Le Retour de Martin Guerre, 1982) and La Balance (also 1982).

Baye won two more César Awards, Best Supporting Actress, for Strange Affair (Une étrange affaire, 1981), and Best Actress for La Balance, 1982). Her four-year relationship with Johnny Hallyday made them a celebrity couple and their daughter is Laura Smet, now an actress.

After changing her image by playing a streetwalker in La Balance, she widened her scope with more obscure characters in J''ai épousé une ombre (1983) and En toute innocence (1988). In 1986, she returned to the theatre with an interpretation of Adriana Monti.

In 1999, she was voted Best Supporting Actress at Venice Film Festival for Une liaison pornographique and starred in Vénus Beauté (Institut) (2000) by Tonie Marshall which won multiple César Awards including Best Film.

She has worked with Claude Chabrol and Steven Spielberg.

Source: Article "Nathalie Baye" from Wikipedia in English, licensed under CC-BY-SA.', '1948-07-06', '2026-04-17', 1, 'Acting', 'Mainneville, Eure, France', '/9WZnFcyqdixlOfqHKBXq0l0Rc4L.jpg', 0, 0, '2026-04-29 22:42:45', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (47341, 'Patrick Muldoon', 41687, 'nm0005258', 'William Patrick Muldoon III (September 27, 1968 — April 19, 2026) was an American actor of Irish and Croatian ancestry. His parents'' artistic backgrounds, in painting, writing, and music, induced the same appetites in their son, as well as athletics. He played college football for the U.S.C. Trojans and has two Rose Bowl rings.', '1968-09-27', '2026-04-19', 2, 'Acting', 'Los Angeles, California, USA', '/nuqKElpRossYTwh9BIymHLA5G6e.jpg', 0, 0, '2026-04-29 22:42:58', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (85627, 'Nelia Da Costa', 4090658, 'nm9177527', NULL, NULL, NULL, 1, 'Acting', NULL, '/ceAaf4Mw8J0f3v2Dzpg1PaIWvqZ.jpg', 0, 0, '2026-04-29 22:43:05', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (86515, 'Jaafar Jackson', 3898497, 'nm4170484', 'Jaafar Jeremiah Jackson (born July 25, 1996) is an American singer, dancer, and actor. He is the son of Jermaine Jackson. Jackson released his debut song, "Got Me Singing", in 2019. He made his acting debut portraying his uncle, Michael Jackson, in Michael (2026).', '1996-07-25', NULL, 2, 'Acting', 'Los Angeles, California, USA', '/tVSzFjQxOrLOcvnzFto0772Q9Bw.jpg', 0, 0, '2026-04-29 22:42:54', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (86522, 'KeiLyn Durrel Jones', 1990676, 'nm3252039', NULL, NULL, NULL, 2, 'Acting', NULL, '/4wDO3Zt9KJg9CARCEgjuVdhWa8x.jpg', 0, 0, '2026-04-29 22:42:50', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (106833, 'Nadia Farès', 34627, 'nm0268626', 'Nadia Farès, born on December 20, 1968, in Marrakech, Morocco, and died on April 17, 2026, in Paris, was a French actress.

Nadia Farès made her screen debut in the 1991 television film "L''Exil", then her film debut in 1992 in the comedy "Les Amis de ma femme" by Didier Van Cauwelaert. However, it was in Christopher Frank''s "Elles n''oublient jamais" that Nadia Farès gained wider public attention in 1994. She played the venomous Angela, who harasses Thierry Lhermitte.

The following year, the young actress starred in the Italian drama "Poliziotti", then worked with Alexandre Arcady on "Dis-moi oui". Moving effortlessly between dramatic roles and lighter appearances, Nadia Farès joined the prestigious cast of Claude Lelouch''s "Hommes, femmes : mode d''emploi". In 1997, she starred in Bernie Bonvoisin''s "Les Démons de Jesus, where she cemented her tough-girl image as Marie, the family''s daughter. Two years later, the director called upon the actress again for "Les Grandes Bouches".

Nadia Farès would revisit this strong character after a foray into the animated film "Le Château des singes", for which she provided a voice. In 2000, she played the enigmatic Fanny in Mathieu Kassovitz''s thriller "Les Rivières Pourpres". Strong and determined, she established herself as a woman of action, a tendency confirmed in "Nid de guêpes". In 2004, Nadia Farès played a manipulative wife fascinated by crime in the dark comedy "Pour le plaisir". She remained in the comedy genre with "L''Ex femme de ma vie", in which she portrayed a dynamic press agent who thrives alongside Thierry Lhermitte.

On April 11, 2026, Nadia Farès was involved in a serious accident at the Blanche gym''s swimming pool in the 9th arrondissement of Paris. She was found unconscious at the bottom of the pool. Pulled from the water by other swimmers, she was resuscitated by firefighters and then rushed to the Pitié-Salpêtrière Hospital in critical condition and placed in an induced coma. She died on April 17, 2026, at the age of 57. Her daughters, Cylia and Shana Chasman, announced her death in a statement to AFP.', '1968-12-20', '2026-04-17', 1, 'Acting', 'Marrakech, Morocco', '/uvomxwk2CfO8scOsR60CxHGM2J3.jpg', 0, 0, '2026-04-29 22:42:44', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (127120, 'Daniella Wang', 1320544, 'nm5275869', 'Daniella Wang (王李丹妮) is a Chinese actress of Mongolian ethnicity. She is a graduate from Beijing Zhongbei King Art School (北京中北英皇艺术学校).', '1989-08-06', NULL, 1, 'Acting', 'Nanyang, Henan, China', '/Afh0SE4hnXY0eiKu3uyB1R0XKZL.jpg', 0, 0, '2026-04-29 22:42:40', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (217189, 'Verónica Castro', 975043, 'nm0145708', 'Verónica Judith Sáinz Castro (born 19 October 1951), better known as Verónica Castro, is a Mexican actress, singer, producer, former model and presenter. She is the mother of singer Cristian Castro and filmmaker Michel Castro.

One of the most important figures on Mexican television who revolutionized the world of romantic novels and films is the beautiful and sensual Verónica Castro, the so-called "Diva of Mexico" who achieved her goals with her charm, charisma, and, above all, perseverance. biggest dreams regarding television, becoming a celebrity recognized not only throughout Latin America, but also in much of the entire world.

She was recognized in 2005 with the Emmy Award for her contribution to Mexican television.', '1952-10-19', NULL, 1, 'Acting', 'Mexico City, Distrito Federal, Mexico', '/wm2Rdj6YdNbfsLoxVU1qlaclBY6.jpg', 0, 0, '2026-04-29 22:43:05', 0);
