INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265449, 'Ginger Lynn', 44936, 'nm0000259', 'Born in Rockford, Illinois, on December 14, 1962, Ginger Lynn Allen went to California in 1982 to visit her ill grandfather. She decided to stay and found employment as a manager at a Musicland record store in Redlands. She had lived in a trailer in one of the worst parts of the city for almost a year when she answered an ad for figure models. This led to employment the same day and a layout in Penthouse magazine.

Work in the adult-film industry soon followed. She worked in the industry from December 1983 through February 1986, making a total of 69 films (plus countless re-issues and compilations). She retired, partially because the work was no longer fun and she had very little time off. That same year, she was approached by the FBI to testify on behalf of Traci Lords, who had just been exposed as having been underage during her years in the adult-film industry. She refused and was eventually arrested for tax evasion.

Following her years in adult movies, she appeared in many "legit" films throughout the late 1980s and 1990s-- most notably the "Vice Academy" films. She also starred in Metallica''s music video "Turn the Page." She has a son, whom she gave birth to on March 24, 1996. She tours gentlemen''s clubs around the country, and signed a comeback deal with VCA Pictures in 1999. She has starred in four new adult movies so far: Torn (1999), White Lightning (2000), New Wave Hookers 6 (2000) and Taken (2005).', '1962-12-14', NULL, 1, 'Acting', 'Rockford, Illinois, USA', '/m6wD4bQAw0ApIjCnHOyYWMbhkfW.jpg', 0, 0, '2026-04-29 22:25:44', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265450, 'Lisa Ann', 108562, 'nm0030217', 'Lisa Ann is known to most of the world by her 20 plus years of success in the Adult Industry. During that time, she covered all bases from being the most searched adult star, to feature dancing, producing, directing, running a talent agency, hosting a radio show on Playboy/Spice radio on Sirius XM. A career highlight was her staring role in the Eminem Video "We Made You" where she appeared in another well known scenario, playing Sarah Palin which was derived from her claim to her fame in the infamous Hustler Series "Who''s Nailin Palin?"

Lisa Ann shocked the world in December of 2014 with her retirement, which was announced by a handwritten letter on her Facebook Page. What the world didn''t know was there were other secret passions yet to be uncovered. Her retirement was inspired by her new found success with SiriusXM Fantasy Sports Radio where she landed her first show, Lisa Ann Does Fantasy, covering fantasy sports. In that first year Lisa Ann claimed her first Fantasy Football trophy winning the SiriusXM Celebrity Host League. Lisa Ann had a well known mantra when secretly planning her retirement from the adult industry, she would say "it''s time to get out of bed and put some clothes on!" Literally!

After 1 full year of retirement, filled with endless hours of writing Lisa Ann released her autobiography The Life. The Life is a tell all, about what it was like to live in the clear heels of an adult star. The release of The Life was the first step in the exploration of the her love of writing, while opening the doors for endless opportunity.

She measures 38DD-20-34.', '1972-05-09', NULL, 1, 'Acting', 'Easton, Pennsylvania, USA', '/dyE3nuFUcMXIkjbub36NOVLzVv2.jpg', 0, 0, '2026-04-29 22:25:45', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265451, 'Janine Lindemulder', 75926, 'nm0511576', 'Janine, an enormously popular superstar, returned to the Vivid Entertainment Group in 2004. The classic beauty with fabulous eyes and trademark luxurious blonde hair also had a major announcement: she would begin performing with men. Upon returning to Vivid, Janine stated, "I feel peaceful and at ease with myself. I had a mental roadblock about working with men on film, but that is gone and I feel totally liberated and as excited as a schoolgirl at the thought. I''ve watched the business change over the years and hope that adult will never lose its edge. I love being a little naughty." A self-described tomboy, she chose modeling rather than attend college on an athletic scholarship. She was offered a Penthouse centerfold on the basis of a test shoot and her Penthouse magazine and video appearances launched her career in adult films. She was invited by the celebrated Andrew Blake to do her first XXX film, "Hidden Obsessions" in 1993, a huge success. Janine signed with Vivid and starred in best selling films such as "Blondage" and the popular "Where The Boys Aren''t" series. Additionally, she has won numerous AVN awards.', '1968-11-14', NULL, 1, 'Acting', 'La Mirada, California, USA', '/zw7KkEDx71rGhpIXREk1Q1q7X4r.jpg', 0, 0, '2026-04-29 22:25:45', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265452, 'Chasey Lain', 544069, 'nm0481815', 'Chasey Lain (born December 7, 1971 in Cocoa Beach, Florida) is an American pornographic actress. She became a stripper as a young adult. She pursued a career in California, starring in many erotic movies and making appearances in some mainstream movies. Lain was on AVN magazine''s list of top 50 porn stars of all time in 2002.

Lain acted in her first adult film in 1991. In 1997 she appeared in Orgazmo, a non-pornographic mainstream movie directed by Trey Parker. She had her own line of lesbian videos, the Chasin'' Pink series. In 2002, she filmed her last film with Vivid Entertainment, Chasin'' Pink 6, and took a break from the industry. In 2004, after 2 years on hiatus, Lain returned to adult films. On February 10, 2007, Chasey Lain launched a new company, "Forbidden Cinema", to produce Chasey Reloaded.', '1971-12-07', NULL, 1, 'Acting', 'Newport, North Carolina, USA', '/zA9ujFFefeyEbk4I5Mcg2xZtva1.jpg', 0, 0, '2026-04-29 22:25:45', 0);
