INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265465, 'Gary Orona', 236036, 'nm0650381', 'A native Californian, Gary Orona was born in 1964. His photographic talents landed him a a job as photographer for the Ventura (California) Star Free Press at age 18. By age 22 he had his degree in film production from Columbia and was rapidly becoming a director/cameraman of note. A world traveler and extreme outdoor enthusiast, Orona was picked by EMI Records in Tokyo, Japan, to produce/direct/photograph over 100 music videos for the Karaoke market. By his mid-20s he was producing and directing music videos and commercials, and at age 26 was hired as Director of Photography for Imperial Entertainment''s The Bikini Carwash Company (1992). The following year he directed the sequel, The Bikini Carwash Company II (1993), and his movie career was rolling.

Orona has produced and directed 65 episodes of erotic shows for HBO/Cinemax, 15 feature length films for HBO/Cinemax, 4 mainstream independent feature films including the New York International Film Festival "Best Picture" "Trance", over 200 "special event erotic shows" for Directv, Pay TV, Pay Cable, and Home Video/DVD Worldwide, over 100 music videos for EMI Records, Tokyo, Japan, and as a photographer has been published in more than 20 Major publications.

He is married to adult actress Tabitha Stevens and was previously married to model and actress Lauren Hays.', '1964-09-07', NULL, 2, 'Directing', 'Kern County, California, USA', '/aeduDDYbH0FX0DBhIfXAOQJovIh.jpg', 0, 0, '2026-04-29 22:25:47', 0);
