INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265467, 'Danny D', 1356419, 'nm3504991', 'This successful and talented European American adult film actor hails from Britain, where he has been kicking up a storm with stellar performances across the UK. His performances have not only been with the very best names and top brands in the industry, but have resulted in internationally renowned nominations and awards. His nomination for Best Foreign Male Performer with AVN was only topped by winning Best Male Performer in the UK version of the Adult Grammy Awards, the Shaftas. His ability to act transcends his preferred genre, and he has also had appearances on BBC comedy series. He has been featured in Whitezilla in the UK , for Playboy TV in North America, in various scenes with Harmony Films and Television X, and in large names such as Bluebird, Killergram, Wicked, and of course, Brazzers. Danny is not only a highly sought performer. His unusually large and endlessly attentive physical attributes are jaw dropping and quite a rare find. He has a 12 in well endowed (BWC) member.', '1987-08-11', NULL, 2, 'Acting', 'Maidstone, Kent, England, UK', '/8Hj4gorfLXOjICHiBOEpDrAaUHJ.jpg', 0, 0, '2026-04-29 22:25:47', 0);
