INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265522, 'Lea Müller', 1184243, 'nm2782889', 'Lea Müller is a German actress.  Lea Müller made her film debut in 2007 in the TV movie 12 is called: I love you as the film daughter of Devid Striesow. In the same year she appeared in the Christmas comedy Meine schöne Bescherung alongside Martina Gedeck and Heino Ferch. Between 2008 and 2010 she appeared as Paula Fabian in five episodes of the ZDF television series Unser Charly. In 2010 she appeared with a small role in the production Die Grenze, directed by Roland Suso Richter and broadcast on Sat.1. In the summer of 2012 she played the young Wilhelmine in the musical Friedrich - Mythos und Tragödie in Potsdam''s Metropolis-Halle[1] For the television adaptation Das Mädchen mit den Schwefelhölzer (The Girl with the Sulfur Woods), which was shown in the Christmas Program 2013 as part of the film series Six at One Stroke, she took on a title role for the first time. In the adaptation of the fairy tale by Hans Christian Andersen with Nina Kunzendorf, Oliver Korittke and Jörg Hartmann she impersonated the orphan Inga.

Since August 2012 Lea Müller has been attending a grammar school in her home town of Potsdam.', '1999-11-08', NULL, 1, 'Acting', 'Berlin, Germany', '/1AW1eISrNCIN7QS3UR6fKRodOHL.jpg', 0, 0, '2026-04-29 22:25:57', 0);
