INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265610, 'Adam Dunn', 3430988, 'nm4350784', 'Adam Dunn is an Australian actor and writer.  After graduating from the Stella Adler Acting Studios in New York, Adam has appeared across stage and screen for the last 15 years. His first foray into writing produced Status Update. A modern day fairytale where everything a man types into his Facebook status comes true.', '1979-11-09', NULL, 2, 'Acting', 'Sydney, New South Wales, Australia', '/evIYbZYGzodkaVmniiYe2nhoSAD.jpg', 0, 0, '2026-04-29 22:26:12', 0);
