INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265685, 'Cherie DeVille', 1041370, 'nm4882092', 'Cherie DeVille was born on August 30, 1978 in Durham, North Carolina. She''s of Franco-Canadian descent. DeVille grew up in Washington, DC and Cape Cod, Massachusetts. Cherie rode horses, did ballet, played in the band, and even was a cheerleader for a few years while growing up. DeVille was also on the swim team and was a lifeguard at age sixteen. Cherie worked as a physical therapist prior to starting out in the adult industry as a model in 2011. DeVille first began performing in explicit hardcore movies in her mid 30''s in 2012. DeVille plays drums and teaches swing dancing in her spare time. She lives in Tennessee.', '1978-08-30', NULL, 1, 'Acting', 'North Carolina, USA', '/1Z0p3l5xKL3lhLIsiisfTHsMgae.jpg', 0, 0, '2026-04-29 22:26:24', 0);
