INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265688, 'Gwen Adora', 3970051, 'nm8197254', 'Gwen Adora is a performer, host, internet personality and pure joy based in Toronto, Canada. Known for her unapologetic approach to self-expression, body positivity, and queer representation, she is a standout presence in the digital space. Gwen has successfully merged her passion for fashion, drag, and self-love into engaging and relatable storytelling. In 2023, she starred as a subject in Netflix''s MoneyShot documentary. Gwen''s bubbly personality has lead to her co-hosting Siri Dahl''s Corn Telethon (2024), bar tending on Watch What Happens Live with Andy Cohen (2023), and as an interviewee on Crave TV''s 1 Queen, 5 Queers (2022). In addition to her mainstream pursuits, she is a multi-award winner in the adult industry.', '1995-07-16', NULL, 1, 'Acting', 'Canada', NULL, 0, 0, '2026-04-29 22:26:25', 0);
