INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265713, 'Antonio Hernández Fimia', 4105611, NULL, 'Antonio Hernández Fimia (Madrid, Spain, 09/30/1997) is an actor and poet with a degree in Acting from the Real Escuela Superior de Arte Dramático. Currently, he is a member of the Compañía Nacional de Teatro Clásico (CNTC). He has participated in various theater productions, including notable works such as “La discreta enamorada” by Lope de Vega, directed by Lluis Homar, “El monstruo de los jardines” by Calderón de la Barca, directed by Iñaki Rikarte, “Todas hieren y una mata” by Álvaro Tato and “Mestiza” by Julieta Soria, among others. He has also appeared in television series such as “+ de 100 mentiras” and “Cuéntame”, and films such as “Casa de fieras”, “Código 10.36” and “Culpa mía”. Trained in fencing, karate, and acrobatics, he works as a specialist and choreographer in action scenes for both theater and audiovisual productions. He has contributed to the anthology “Puro teatro: homenaje a un oficio” (Daniel Migueláñez ed.), which brings together various professionals in the theatrical field. His first poetry book, “Del Purgatorio”, was published by Valparaíso Ediciones. He has written, directed, and starred in his first theatrical monologue, “Poética del Naufragio”. He is the founder and director of Ayer, a weekly poetry recital in Madrid, which eventually gave its name to his audiovisual production company: Ayer Producciones. He combines cultural promotion on social media with his work as an actor and visual artist (theater posters, video art, illustrations, etc.). In 2021, he debuted as an audiovisual producer with “Ayer: especial fin de año”, an arts event he directed and hosted, inviting numerous representatives of contemporary theater and poetry. In December 2022, he directed and produced a second edition of the event. In 2023, he produced the miniseries Rapport. “Upon the Sky” is his first film as a director.', '1997-09-30', NULL, 2, 'Acting', 'Madrid, Madrid, Spain', '/u2jjeMbQthFMVPH6ozbPWiGsAph.jpg', 0, 0, '2026-04-29 22:26:29', 0);
