INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265727, 'Sonam Kapoor Ahuja', 85040, 'nm2128238', 'Sonam Kapoor is an Indian actress who appears in Bollywood films and daughter of actor Anil Kapoor. Kapoor studied theatre and arts at the United World College of South East Asia in Singapore. She was an assistant director to Sanjay Leela Bhansali on the 2005 film Black.

Kapoor made her acting debut in Bhansali''s romantic drama Saawariya (2007), which earned her a nomination for the Filmfare Award for Best Female Debut. After a series of commercial failures, the sleeper hit Raanjhanaa (2013) marked a turning point in her career, earning her several Best Actress nominations.', '1985-06-09', NULL, 1, 'Acting', 'Mumbai, Maharashtra, India', '/p5A2rzbCs9ZlgxVgJ6zGtHNUzaq.jpg', 0, 0, '2026-04-29 22:26:31', 0);
