INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265735, 'Cedric Gegel', 2730819, NULL, 'The third of four children, Cedric Gegel grew up in Wapakoneta, Ohio. A performer from a young age, Cedric graduated from Wapakoneta High School in 2013 and from Capital University, where he studied theatre, public relations, and English literature, in 2017.

Cedric co-founded Just a Skosh Productions and, under that company''s banner, wrote and directed his debut feature film, the indie family fantasy "Cadia: The World Within," starring Corbin Bernsen and James Phelps. Additionally, he wrote the screenplay for the cancer drama "Forbearance," starring Vernon Wells, and also appears in a supporting role in the film. He stars as the titular character in the ASTRA-nominated indie series "The Coroner''s Assistant," for which he was nominated for Best Leading Actor - Comedy and the 2024 Indie Series Awards. Award-nominated stage roles include Robert F. Kennedy (Kennedy: Bobby''s Last Crusade), the Beast (Beauty and the Beast), Pippin (Pippin), and Link Larkin (Hairspray). In 2024, he appeared in the play "Butterflies Are Free" alongside Morgan Fairchild.

Cedric also runs a YouTube channel where he analyzes music videos and live performances to educate thousands of viewers on storytelling, cinematography, editing, acting, production design, and vocal technique.

He continues to travel the country working on indie films and in various stage roles.', NULL, NULL, 2, 'Acting', NULL, '/1MNXDrWiTnnH9Kw44gkMNl0llPM.jpg', 0, 0, '2026-04-29 22:26:33', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265736, 'Johnny Vivash', 1160330, 'nm3131573', 'Johnny Vivash is originally from Dublin but trained in London were he is now based. He has strong theatre background, having toured nationally for a number of years working with various theatre companies in the U.K. He has worked on numerous award winning short films and Independent features in the UK, Europe & the U.S. He is an on going collaborator with numerous directors both as an actor and script developer.', NULL, NULL, 2, 'Acting', 'Dublin, Ireland', '/vVpZRUvnYht0GE9rpyHuVJnAOCQ.jpg', 0, 0, '2026-04-29 22:26:33', 0);
