INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265740, 'Scot Scurlock', 2715017, NULL, 'Scot is a resident of Saint Augustine, Florida. Prior to relocating to Florida, he was extremely active in the New Mexico Independent Film community having worked in several films selected by Festivals and received a Best Actor''s nomination for his role in the film Bad Situation. He was selected as one of 15 actors invited to participate in the Nashville Film Festival''s first-ever Actor''s Challenge and was a finalist in both the 2018 and 2019 New Mexico Film Foundations - Actors Showcase. In addition to acting, Scot has directed, produced, and completed his first film script.', NULL, NULL, 2, 'Acting', NULL, '/k5vSAtpFxeaMIN7ZFucHgKJHLnD.jpg', 0, 0, '2026-04-29 22:26:34', 0);
