INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265798, 'Julanne Johnston', 29981, 'nm0426710', 'From Wikipedia, the free encyclopedia.

Julanne Johnston (May 1, 1900 - December 26, 1988) was an American silent film actress born in Indianapolis, Indiana.

Johnston is known for being on William Randolph Hearst''s yacht The Oneida during the weekend in November 1924 when film director and producer Thomas Ince later died of heart failure. She was also the female lead in the Douglas Fairbanks film The Thief of Bagdad, with Anna May Wong, that same year.

She died in Grosse Pointe, Michigan, at the age of 88. Her remains were buried at Woodlawn Cemetery in Detroit.

Description above from the Wikipedia article Julanne Johnston, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1900-04-30', '1988-12-26', 1, 'Acting', 'Indianapolis, Indiana, USA', '/5CJdV1WKw9E0mPs8hWeC2bYV9m9.jpg', 0, 0, '2026-04-29 22:42:41', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265799, 'Edward Grover', 197486, 'nm0344013', 'Edward D. Grover (October 23, 1932 – November 22, 2016) was an American film, stage and television actor. He was perhaps best known for playing Tony Baretta''s supervisor Lieutenant Hal Brubaker in the American detective television series Baretta. Grover also played as Inspector Lombardo in the 1973 film Serpico.', '1932-10-23', '2016-11-22', 2, 'Acting', 'Los Angeles, California, USA', '/mIzpFgp9hMZCccLvoA6lRNrwJfe.jpg', 0, 0, '2026-04-29 22:42:42', 0);
