INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265803, 'Robert Reich', 1209117, 'nm1049185', 'Robert Bernard Reich (born June 24, 1946) is an American professor, author, lawyer, and political commentator. He worked in the administrations of Presidents Gerald Ford and Jimmy Carter, and served as Secretary of Labor from 1993 to 1997 in the cabinet of President Bill Clinton. He was also a member of President Barack Obama''s economic transition advisory board.

Reich has been the Chancellor''s Professor of Public Policy at the Goldman School of Public Policy at UC Berkeley since January 2006. He was formerly a lecturer at Harvard University''s John F. Kennedy School of Government and a professor of social and economic policy at the Heller School for Social Policy and Management of Brandeis University. In 2008, Time magazine named him one of the Ten Best Cabinet Members of the century, and in the same year The Wall Street Journal placed him sixth on its list of Most Influential Business Thinkers.

He has published 18 books which have been translated into 22 languages, including the best-sellers The Work of Nations, Reason, Saving Capitalism, Supercapitalism, Aftershock: The Next Economy and America''s Future, and a best-selling e-book, Beyond Outrage. He is also board chair emeritus of Common Cause and writes his own blog about the political economy at Robertreich.org. The Robert Reich–Jacob Kornbluth film Saving Capitalism was selected to be a Netflix Original, and debuted in November 2017, and their film Inequality for All won a U.S. Documentary Special Jury Award for Achievement in Filmmaking at the 2013 Sundance Film Festival in Utah.

In 2015, Reich and Kornbluth founded Inequality Media, a nonprofit digital media company. Inequality Media''s videos feature Reich discussing topics relating to inequality and power primarily in the United States, including universal basic income, labor rights protection, the racial wealth gap, affordable housing, and gerrymandering.', '1946-06-24', NULL, 2, 'Acting', 'Scranton, Pennsylvania, USA', '/f9Pbe4ULNEzrKeNZKn2GWJZ4mE.jpg', 0, 0, '2026-04-29 22:42:46', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265804, 'Massimo Cagnina', 1496177, 'nm2373664', NULL, NULL, NULL, 0, 'Acting', NULL, '/ubD8neHTvpY7CL2AK5djGMEGovO.jpg', 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265805, 'Francis X. Bushman Jr.', 1670560, 'nm0124287', 'From Wikipedia, the free encyclopedia

Ralph Everly Bushman (May 1, 1903 – April 16, 1978), was an American actor. He appeared in fifty-five films between 1920 and 1943. In his early film career, he was often credited as Francis X. Bushman Jr.

The son of notable silent film star Francis X. Bushman and Josephine Fladung Duval, he was born in Baltimore, Maryland and died in Los Angeles, California at age 74.

He was a maternal uncle of Pat Conway (1931–1981), star of the ABC western television series Tombstone Territory (1957–1960). He and his wife Beatrice were married for 54 years at the time of his death.', '1903-05-01', '1978-04-16', 2, 'Acting', 'Baltimore, Maryland, USA', '/eEFnfSZ1LjSazkdBxVcy0F2ahed.jpg', 0, 0, '2026-04-29 22:42:49', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265806, 'Nina van Pallandt', 41732, 'nm0887684', 'Nina van Pallandt (born Nina Magdelena; 15 July 1932) is a Danish retired actress. She was first a celebrated folk singer in Europe, together with her husband, Baron Frederik van Pallandt. They split up in 1969 and after a brief solo carrier as singer she ended up in Hollywood, appearing in several Robert Altman movies, as well as various TV series. She is also famous as the mistress of hoaxer Clifford Irving, who went to jail when his biography of Howard Hughes proved to be a fake.', '1932-07-15', NULL, 1, 'Acting', 'Copenhagen, Denmark', '/8eUeOcWHczbpFGYyYtYTgZC7WES.jpg', 0, 0, '2026-04-29 22:42:51', 0);
INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265807, 'Trixie Friganza', 150637, 'nm0295688', 'Trixie Friganza (November 29, 1870 – February 27, 1955), born Delia O’Callaghan, began her career as an operetta soubrette working her way from the chorus to starring in musical comedies to having her own feature act on the vaudeville circuit.

She transitioned to film in the early 1920s mostly playing small characters that were quirky and comedic and retired from the stage in 1940 due to health concerns. She spent her last years teaching drama to young women in a convent school and when she died she left everything to the convent. She became a highly sought after comic actress after the success of The Chaperons (played "Aramanthe Dedincourt") and is most well-known for her stage roles of Caroline Vokes (or Vokins?) in The Orchid, Mrs. Radcliffe in The Sweetest Girl in Paris, for multiple roles in The Passing Show of 1912, and of course her unforgettable run as a vaudeville headliner. During the height of her career, she used her fame to promote social, civic, and political issues of importance, such as self-love and the Suffragist movement.

Description above from the Wikipedia article Trixie Friganza, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1870-11-29', '1955-02-27', 1, 'Acting', 'Grenola, Kansas, USA', '/4BDX5PJ9LFpPC02fBn25Nm7qLc0.jpg', 0, 0, '2026-04-29 22:42:52', 0);
