INSERT OR REPLACE INTO people (id, name, tmdb_id, imdb_id, biography, birthday, deathday, gender, known_for_department, place_of_birth, profile_path, wins, nominations, last_modified, is_deleted) VALUES (265810, 'Nathan Lee Chasing Horse', 7871, 'nm0496724', 'Nathan Lee Chasing His Horse (born April 28, 1976), also known as Nathan Chasing Horse and Nathan Chases His Horse, is a Sicangu Lakota actor.

Chasing Horse portrayed the young Lakota character Smiles a Lot in Kevin Costner''s 1990 film Dances with Wolves. He has appeared in three TNT telefilms with First Nations actor Eric Schweig: The Broken Chain, Into the West, and Bury My Heart at Wounded Knee.', '1976-04-28', NULL, 2, 'Acting', 'Rosebud Reservation, South Dakota, USA', NULL, 0, 0, '2026-04-29 22:42:59', 0);
